INSERT INTO `activities` (`id`, `vendor_id`, `name`, `activity_type`, `activity_type_id`, `duration_minutes`, `benefits`, `descriptions`, `contract_price`, `adult_contract_rate`, `adult_markup_type`, `adult_markup`, `child_contract_rate`, `child_markup_type`, `child_markup`, `adult_publish_rate`, `child_publish_rate`, `capacity_min`, `capacity_max`, `includes`, `excludes`, `cancellation_policy`, `notes`, `gallery_images`, `is_active`, `created_at`, `updated_at`, `deleted_at`, `created_by`, `updated_by`) VALUES
(11, 7, 'Rafting Ayung River', 'Water Activity', 1, 120, NULL, '<p class=\"n2-font-25d19f8e927c5443bc632d974cfc42aa-paragraph   \" style=\"box-sizing: content-box; -webkit-font-smoothing: antialiased; --bdt-inverse: initial; padding: 0px; border-style: initial; border-color: initial; border-image: initial; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 18px; line-height: 1.6; font-family: Poppins; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-language-override: inherit; vertical-align: baseline; height: auto; width: auto; box-shadow: none; hyphens: manual; color: rgb(0, 0, 0); text-shadow: none; text-align: justify; background-attachment: scroll !important;\">Experience Rafting Ayung with Bali Sobek a classic two hour, visually spectacular rafting trip on the Ayung River. This unforgettable adventure combines excitement, fun, and breathtaking scenery. Carving through Bali’s most stunning landscapes, Class II and III rapids flow past deep valleys, cascading waterfalls, dense tropical rainforests, and towering cliffs.</p><p class=\"n2-font-25d19f8e927c5443bc632d974cfc42aa-paragraph   \" style=\"box-sizing: content-box; -webkit-font-smoothing: antialiased; --bdt-inverse: initial; padding: 0px; border-style: initial; border-color: initial; border-image: initial; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 18px; line-height: 1.6; font-family: Poppins; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; font-language-override: inherit; vertical-align: baseline; height: auto; width: auto; box-shadow: none; hyphens: manual; color: rgb(0, 0, 0); text-shadow: none; text-align: justify; background-attachment: scroll !important;\">Our professional Sobek guides are experts in water safety and skilled in white-water rafting techniques, ensuring an exhilarating yet safe journey. After your adventure, enjoy a delicious lunch served at our unique riverside garden restaurant.</p>', 900000, 900000, 'fixed', 300000, 600000, 'fixed', 200000, 1200000, 800000, 4, 30, '<ul><li>Insurance</li></ul>', NULL, NULL, NULL, '[\"activities\\/i5H3YjzTakdv71bRGuwFjS3BDHZm6pqFTCPpZCuD.jpg\",\"activities\\/ajgy3MchkQZAd1h2MQrgtMAVKL2qPjtCaEtcvZ3w.jpg\"]', 1, '2026-03-23 21:57:47', '2026-03-23 23:16:11', NULL, 1, 1),
(12, 7, 'Rafting Telagawaja', 'Water Activity', 1, 120, NULL, '<span style=\"color: rgb(0, 0, 0); font-family: Poppins; font-size: 18px; text-align: justify;\">Step up to a greater white water challenge with Rafting Telagawaja an adrenaline filled adventure through Bali’s most thrilling river. Conquer Class III+ rapids as you rush past riverbanks lined with ancient hanging trees, winding through lush rainforests and steep rock gorges. Rafting Telagawaja promises nonstop excitement and breathtaking scenery from start to finish. After your adventure, relax and enjoy a delicious lunch at our riverside restaurant before heading back to your hotel.</span>', 900000, 900000, 'fixed', 300000, 600000, 'fixed', 200000, 1200000, 800000, 3, 30, NULL, NULL, NULL, NULL, '[\"activities\\/ICJMw90Aduky86xM7PHqGPoQti3kNfiG7YsaFOlm.jpg\",\"activities\\/nofSgte9BGaQ2yP46IkQTxGDgJkH0LvMken9r72K.jpg\",\"activities\\/exDpwQgfeR9FtIt1BX97eOlMJdek4UKbUQSehtFi.jpg\"]', 1, '2026-03-23 23:21:26', '2026-03-23 23:21:26', NULL, 1, 1),
(13, 7, 'Cycling Ubud', 'Adventure', 2, 120, NULL, '<span style=\"color: rgb(0, 0, 0); font-family: Poppins, -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Oxygen-Sans, Ubuntu, Cantarell, &quot;Helvetica Neue&quot;, sans-serif; font-size: 17px; text-align: justify; background-color: rgb(255, 245, 247);\">Discover the breathtaking beauty of Bali’s nature and culture with an unforgettable cycling adventure through Ubud, one of the island’s most iconic destinations. Our cycling tours offer a unique opportunity to explore scenic routes surrounded by lush green rice fields, dense tropical forests, and charming traditional villages.</span>', 300000, 300000, 'fixed', 50000, 200000, 'fixed', 100000, 350000, 300000, 2, 20, NULL, NULL, NULL, NULL, '[\"activities\\/90lh7zZGaH3JHSWYQ28Wbc5aw33zrdMWcRVVE7ml.jpg\",\"activities\\/CeHFTE3uVGnn46PhXwHNo8n5UcaFSwb3mmkkvUTJ.jpg\"]', 1, '2026-03-23 23:25:27', '2026-03-23 23:25:27', NULL, 1, 1),
(14, 7, 'Cycling Batur', 'Adventure', 2, 120, NULL, '<span style=\"color: rgb(0, 0, 0); font-family: Poppins, -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Oxygen-Sans, Ubuntu, Cantarell, &quot;Helvetica Neue&quot;, sans-serif; font-size: 17px; text-align: justify; background-color: rgb(255, 245, 247);\">Escape from the tourist center to the cooler climate of Batur Volcano. Using our well maintained mountain bikes the downhill route from Pludu village will lead you through sleepy villages along little-used roads and tracks, past ancient temples and along leafy lanes through the rainforest that grace the hills slope. Stopping on the way to experience traditional bali life, the 2,5-hours ride concludes with lunch in the town of Ubud in the mountain foothillls.</span>', 300000, 300000, 'fixed', 50000, 200000, 'fixed', 50000, 350000, 250000, 2, 20, NULL, NULL, NULL, NULL, '[\"activities\\/X4K5EQVxdmz1naLKMoyznK9FTYYZ8hzc85wi7Mgm.jpg\",\"activities\\/P4oUUF1fPdYCRhd2uPHiGyHiGigWdahfnRPSEo8h.jpg\",\"activities\\/7sWNImT8lgJqEKdhiiLZ6yg5vEn1jV8ZOWWtUR18.jpg\"]', 1, '2026-03-23 23:27:47', '2026-03-23 23:27:47', NULL, 1, 1),
(15, 6, 'Flyfish', 'Water Activity', 1, 30, NULL, '<span style=\"color: rgb(68, 68, 68); font-family: Inter, sans-serif;\">Try the latest water sport craze where you wear a special device that propels you into the air, allowing you to perform aerial maneuvers above the water</span>', 120000, 120000, 'fixed', 35000, NULL, 'fixed', 0, 155000, NULL, 2, 30, NULL, NULL, NULL, NULL, '[\"activities\\/whGWAvFrBbsFGlObvLmBM3Z6tJZYjnnxDgDFLmRJ.jpg\"]', 1, '2026-03-23 23:36:19', '2026-03-23 23:40:52', NULL, 1, 1),
(16, 6, 'Fly Board', 'Water Activity', 1, 30, NULL, '<span style=\"color: rgb(68, 68, 68); font-family: Inter, sans-serif; font-size: 16px;\">Flyboarding: Try the latest water sport craze where you wear a special device that propels you into the air, allowing you to perform aerial maneuvers above the water.</span>', 350000, 350000, 'fixed', 100000, NULL, 'fixed', 0, 450000, NULL, 1, 20, NULL, NULL, NULL, NULL, '[\"activities\\/TPFemUWKzNdNAnnRROD9OS3bhF3AzqjMKcI0YHlh.jpg\"]', 1, '2026-03-23 23:38:13', '2026-03-23 23:38:13', NULL, 1, 1),
(17, 6, 'Diving', 'Water Activity', 1, 60, NULL, '<span style=\"color: rgb(68, 68, 68); font-family: Inter, sans-serif;\">Discover the rich marine biodiversity by participating in scuba diving sessions. Tanjung Benoa offers various dive spots suitable for both beginners and experienced divers.</span>', 250000, 250000, 'fixed', 25000, NULL, 'fixed', 0, 275000, NULL, 2, 30, NULL, NULL, NULL, NULL, '[\"activities\\/hg0P3eoMht7KA6qOty6l1NJUswcUhVmxQrZySTwt.jpg\"]', 1, '2026-03-23 23:39:40', '2026-03-23 23:39:40', NULL, 1, 1),
(18, 6, 'Sea Walker', 'Water Activity', 1, 60, NULL, '<span style=\"color: rgb(68, 68, 68); font-family: Inter, sans-serif;\">Try the latest water sport craze where you wear a special device that propels you into the air, allowing you to perform aerial maneuvers above the water</span>', 200000, 200000, 'fixed', 75000, NULL, 'fixed', 0, 275000, NULL, 4, 20, NULL, NULL, NULL, NULL, '[\"activities\\/4c1Tbp4lFLnDNRCk3S63KlCf08kQAvLN9G8k2foK.jpg\"]', 1, '2026-03-23 23:42:31', '2026-03-23 23:42:31', NULL, 1, 1),
(19, 10, 'Sip and Sight Package', 'Nature Tour', 3, 60, NULL, '<span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">A coffee tour in Alas Harum Bali offers unique and enriching experience for coffee enthusiasts and travelers. In this activities you will explain how the luwak coffee being processed which closely connected to the history of coffee production in Indonesia</span>', 200000, 200000, 'fixed', 93000, NULL, 'fixed', 0, 293000, NULL, 2, 50, '<ul><li>1x Entrance to Alas Harum Bali Area</li><li>1x Coffee Tour</li><li>1x Coffee and Tea Combination set</li></ul>', NULL, NULL, NULL, '[\"activities\\/3TEI2ftRGyzzHCHrrUKql7kqplZiiBmRunG2Fq12.jpg\"]', 1, '2026-03-23 23:54:10', '2026-03-23 23:54:10', NULL, 1, 1),
(20, 10, 'Thrill and Chill Experience', 'Nature Tour', 3, 60, NULL, '<span style=\"color: rgb(0, 0, 0); font-family: Poppins-Regular; background-color: rgba(0, 102, 102, 0.05);\">Enjoy the Thrill &amp; Chill Experience at Alas Harum Bali, including entrance access, one extreme activity, and a relaxing tea time - perfect for an unforgettable day in nature.</span>', 350000, 350000, 'fixed', 130000, NULL, 'fixed', 0, 480000, NULL, 1, 50, '<ul><li><span style=\"color: rgb(0, 0, 0); font-family: Poppins-Regular; font-size: 0.875rem;\">1x Entrance to Alas Harum Bali area</span></li><li><span style=\"color: rgb(0, 0, 0); font-family: Poppins-Regular; font-size: 0.875rem;\">1x Activity (Super Extreme Swing / Flying Fox / Sky Bike)</span></li><li><span style=\"color: rgb(0, 0, 0); font-family: Poppins-Regular; font-size: 0.875rem;\">1x Tea Time Package</span></li></ul>', NULL, '<font color=\"#000000\" face=\"Poppins-Regular\"><div style=\"\"><ul style=\"\"><li style=\"\">Reservations must be made at least one day in advance, no later than 5:00 PM.<br>- For reservations, please contact us at +62-361-958-5999 / reservation@alasharum.com<br>- All tickets, activities, and entrance access at Alas Harum Bali exclude access to Cretya Ubud.<br>- Separate admission is required.</li><li style=\"\">Operating Hours:<br>- 07:00 – 10:00: Only the Swing activities are available.<br>- 10:00 – 18:00: All activities are available.</li><li style=\"\">Cancelation:<br>- Any cancellation is non-refundable.</li><li style=\"\">Restriction:<br>- Pregnant women, children under 7 years old, and individuals with heart disease or congenital disorders are prohibited from participating in extreme activities.</li><li style=\"\">Weight &amp; Height Requirements:<br>- Swing Activities: Minimum weight 35 kg, maximum 150 kg (single) / 200 kg (couple)<br>- Bed Swing: Maximum weight 350 kg (4 pax)<br>- Sky Bike: Minimum weight 35 kg, maximum 90 kg (single) / 150 kg (couple), minimum height 165 cm<br>- Flying Fox: Minimum weight 35 kg, maximum 90 kg (single). For tandem (couple), the combined weight must not exceed 100 kg.<br>- Couple Face to Face Swing: Maximum combined weight 150 kg (couple).</li><li style=\"\">Insurance covered.</li><li style=\"\">Using full safety attributes is a must.</li><li style=\"\">Prices are in IDR and subjected to 17.25% tax and service.</li></ul></div></font>', NULL, '[\"activities\\/kNGnEogy3wieuASZf9O5c6MrbhxijXKbnbs5lKn3.jpg\",\"activities\\/kRXXSpjXZd9S3rObW7dJsCygUSGQO9UhjA8rEq2Q.jpg\",\"activities\\/2pMvIh0RISag5Du6jopqMSrYFcvcTgDkoKM5SCk5.jpg\"]', 1, '2026-03-24 00:02:31', '2026-03-24 00:26:36', NULL, 1, 7),
(21, 11, 'Boat Trip Packages', 'Marine Tour', 6, 30, NULL, 'Experience an incredible aquatic journey with our Boat Trip Package', 150000, 150000, 'fixed', 50000, NULL, 'fixed', 0, 200000, NULL, 1, 20, '<div><ul><li>Boat</li><li>Mineral water</li><li>Snorkeling Equipments</li><li>Towels</li><li>Go Pro Camera Available for Rent IDR 200k</li><li>Shower Place</li><li>Bread For The Fish</li></ul></div>', NULL, NULL, NULL, '[\"activities\\/wXPnnYFixx3vuYyKth1s9bcpc1fE8zp9Ill9eu1P.jpg\"]', 1, '2026-03-24 00:47:01', '2026-03-24 00:47:01', NULL, 7, 7),
(22, 11, 'Snorkeling Amed', 'Water Activity', 1, 120, NULL, '<span style=\"color: rgb(0, 0, 0); font-family: Montserrat; text-align: center;\">Enjoy all the best Snorkeling spots in amed</span>', 150000, 150000, 'fixed', 100000, NULL, 'fixed', 0, 250000, NULL, 1, 50, NULL, NULL, NULL, 'Destination:<br><div><ul><li>Japanese Shipwreck</li><li>Pyramid Starfish Point &amp; Turtle</li><li>Vienna Beach (Coral Garden &amp; Turtle Point)</li><li>Underwater Temple ( Jemeluk Bay).</li><li>Selang Beach</li></ul></div>', '[\"activities\\/5EbA5gxGAEPFaQwXFXD5INZtQNryTZy3O7tRK2rq.jpg\"]', 1, '2026-03-24 00:50:54', '2026-03-24 00:50:54', NULL, 7, 7),
(30, 36, 'Jungle Hopper Legend', 'Adventure', 2, 120, NULL, 'The Jungle Hopper package is our number one selling ticket! This popular Safari package embarks you on an adventure in the wildlife to encounter a wide variety of animals, even endangered species.', 200000, 200000, 'fixed', 50000, 150000, 'fixed', 50000, 250000, 200000, 2, 100, '<div><ul><li>Safari Journey (1x)</li><li>Bali Agung Show (Tuesday to Sunday)</li><li>Animals Educational Presentation</li><li>Tiger Educational Presentation</li><li>Elephant Educational Presentation</li><li>Tax included</li></ul></div>', NULL, 'The activities schedules are subject to change or cancellation due to weather circumstances and on the condition of our animals.', NULL, '[\"activities\\/evwEiTMIpXJwilink2UTibWb8CRQGHiQzxf54n35.jpg\",\"activities\\/GpQ8WsxTzcLSvkDeB86DDIHpFEMvuuPKY32yAC9g.jpg\",\"activities\\/dQy4qa1av7OonygDdmeZHvuMSz5WlcSP1FTaB0K5.jpg\",\"activities\\/lTMkTi6HZ5SRX06IHWdwpbobjUvQN9iJqqnzDin8.jpg\"]', 1, '2026-04-13 07:28:35', '2026-04-14 09:17:37', NULL, 1, 2),
(31, 36, 'Night Safari', 'Adventure', 2, 120, NULL, '<div>Satisfy your senses with the unforgettable experience of a nighttime adventure in the wilderness.</div><div>A specially designed caged tram will take you on a journey where you will get to witness and hand-feed animals at a close range!</div><div>See our Fire Show, and enjoy a BBQ dinner, with our unique shows included, you will experience a true natural wildlife encounter.</div>', 0, 0, 'fixed', 0, 0, 'fixed', 0, 0, 0, 2, 100, '<div><ul><li>Walking Safari</li><li>Welcome Drink</li><li>Night Safari Journey (1x)</li><li>Dinner</li><li>The Rhythm of African</li><li>Fire Dance Show</li><li>Animal Encounter</li><li>Tax included</li><li>Valid after 6 PM</li></ul></div>', NULL, NULL, 'The activities schedules are subject to change or cancellation due to weather circumstances and on the condition of our animals.', '[\"activities\\/lqI0EdeL4lAB52Fz1r25HoAYJGB38Al1xn2sOpqG.jpg\",\"activities\\/RXOm2nwxrn8H4emXATNnIcIJwPdonrhgtaWb1DXx.jpg\",\"activities\\/2wMh2JQukwUJMHSRWn7iTy3ZzmCV41rPFlJCym3p.jpg\"]', 1, '2026-04-13 07:32:48', '2026-04-14 09:15:34', NULL, 1, 2),
(32, 36, 'Varuna Show', 'Entertainment', 7, 60, NULL, '<div>Step into the realm of The Varuna Show, Indonesia’s first underwater theatrical dining experience, set in the mesmerizing backdrop of Bali. Witness a world where the depths of the ocean reveal their secrets, intertwining gastronomy with a journey of fantasy and flavor.</div><div><br></div><div><b>The Legend Beneath The Waves</b></div><div>In Bali’s enchanting underwater world, The Varuna Show unfolds a captivating story. Follow the extraordinary journey of a young prince, a child of land and sea, discovering his inner strength and royal destiny. Amidst majestic sea creatures and armed with a mystical royal necklace, his adventure beneath the waves is an odyssey like no other.</div><div><br></div><div><b>A Spectacle of Storytelling and Culinary Art</b></div><div>Crafted by the visionary Creative Director Peter Wilson, The Varuna Show is more than just a performance; it’s an immersive experience. Audiences are not mere spectators but integral parts of this underwater odyssey, where each scene is a mesmerizing fusion of awe-inspiring performances and heartfelt storytelling.</div><div>Are you ready to dive into the heart of Indonesia’s underwater magic? Book your journey now and be part of The Varuna Show, where each moment is a discovery of fantasy and flavors.</div>', 1200000, 1200000, 'fixed', 200000, 1000000, 'fixed', 200000, 1400000, 1200000, 2, 100, '<ul><li>Wine (red/white)</li><li>3-course lunch</li><li>preferential seating</li><li>VIP waiting lounge with free canape &amp; mocktail/cocktail</li></ul>', NULL, NULL, NULL, '[\"activities\\/BIvKVkBUtNoRn0nZgL66uSPb9DvcetJHcvBkvRMp.jpg\",\"activities\\/uPjj6ny2HWnCS8atgQFZwELNOxthKrXuSuqrNKqR.jpg\",\"activities\\/X0PCUkSn5NBDP2NC3oduJh3agM8uOBRnMJZAR4KQ.jpg\",\"activities\\/qDhjw1rBWaiw4GhESvVMGvDp6s9HkdD3Mn53JsxJ.jpg\"]', 1, '2026-04-13 07:45:31', '2026-04-14 08:05:43', NULL, 1, 2);
INSERT INTO `activity_logs` (`id`, `user_id`, `module`, `action`, `subject_id`, `subject_type`, `properties`, `created_at`, `updated_at`) VALUES
(9, 2, 'Hotel', 'updated', 6, 'App\\Models\\Hotel', '{\"changed\":[\"address\",\"status\",\"map\",\"latitude\",\"longitude\",\"updated_at\"],\"before\":{\"address\":\"Jl. Belimbing Sari Tambiyak, Pecatu, South Kuta, Badung Regency, Bali 80364\",\"status\":\"Active\",\"map\":\"https:\\/\\/g.page\\/alilavillasuluwatu?share\",\"latitude\":null,\"longitude\":null,\"updated_at\":\"2025-06-24T04:05:11.000000Z\"},\"after\":{\"address\":\"Jalan Temu Dewi, Pecatu, Bali, Indonesia\",\"status\":\"active\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Alila+Villas+Uluwatu\\/@-8.8442372,115.1381182,1083m\\/data=!3m1!1e3!4m20!1m10!3m9!1s0x2dd25add7437e1c1:0xb608f145222330a6!2sAlila+Villas+Uluwatu!5m2!4m1!1i2!8m2!3d-8.8442372!4d115.1381182!16s%2Fg%2F1v2gb4_0!3m8!1s0x2dd25add7437e1c1:0xb608f145222330a6!5m2!4m1!1i2!8m2!3d-8.8442372!4d115.1381182!16s%2Fg%2F1v2gb4_0?entry=ttu&g_ep=EgoyMDI2MDMxOC4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.8442372\",\"longitude\":\"115.1381182\",\"updated_at\":\"2026-03-23 09:48:02\"}}', '2026-03-23 01:48:02', '2026-03-23 01:48:02'),
(10, 7, 'Hotel', 'updated', 142, 'App\\Models\\Hotel', '{\"changed\":[\"address\",\"status\",\"check_in_time\",\"check_out_time\",\"map\",\"latitude\",\"longitude\",\"updated_at\"],\"before\":{\"address\":\"Jl. Raya Keliki No.123, Keliki, Kec. Tegallalang, Kabupaten Gianyar, Bali 80561\",\"status\":\"Active\",\"check_in_time\":null,\"check_out_time\":null,\"map\":\"https:\\/\\/maps.app.goo.gl\\/4fMcWTs2Ryc7s5VR9\",\"latitude\":null,\"longitude\":null,\"updated_at\":\"2025-07-16T03:15:22.000000Z\"},\"after\":{\"address\":\"Keliki, Bali, Indonesia\",\"status\":\"active\",\"check_in_time\":\"11:00\",\"check_out_time\":\"13:00\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Abisena+Wellness+and+Resort+Ubud\\/@-8.4600015,115.2567105,17z\\/data=!4m9!3m8!1s0x2dd22300d43f11b1:0xdd8e485a87028f24!5m2!4m1!1i2!8m2!3d-8.4600068!4d115.2592854!16s%2Fg%2F11qnldxs1t?entry=ttu&g_ep=EgoyMDI2MDMxOC4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.4600015\",\"longitude\":\"115.2567105\",\"updated_at\":\"2026-03-24 09:38:47\"}}', '2026-03-24 01:38:47', '2026-03-24 01:38:47'),
(11, 7, 'Hotel', 'updated', 54, 'App\\Models\\Hotel', '{\"changed\":[\"address\",\"description\",\"status\",\"map\",\"latitude\",\"longitude\",\"updated_at\"],\"before\":{\"address\":\"Monkey Forest, Street Jalan Wenara Wana, Ubud, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571\",\"description\":\"The Monkey Forest area has always been referred to as the beating heart of Ubud. It captures the essence of Tri Hita Karana that believes that in order to reach the ultimate well-being, one must live harmoniously with other people, with nature, and with God. Strategically located within the area, Adiwana Monkey Forest offers the perfect Bali getaway. The 21 suites are beautifully designed to showcase the artistic Balinese craftsmanship while maintaining a contemporary feel.&nbsp;\",\"status\":\"Active\",\"map\":\"https:\\/\\/goo.gl\\/maps\\/3651dBsUHYmEF7GP9\",\"latitude\":null,\"longitude\":null,\"updated_at\":\"2025-06-30T03:08:23.000000Z\"},\"after\":{\"address\":\"Jalan Bisma, Ubud, Bali, Indonesia\",\"description\":\"The Monkey Forest area has always been referred to as the beating heart of Ubud. It captures the essence of Tri Hita Karana that believes that in order to reach the ultimate well-being, one must live harmoniously with other people, with nature, and with God. Strategically located within the area, Adiwana Monkey Forest offers the perfect Bali getaway. The 21 suites are beautifully designed to showcase the artistic Balinese craftsmanship while maintaining a contemporary feel.&amp;nbsp;\",\"status\":\"active\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Adiwana+Monkey+Forest\\/@-8.5131354,115.2583127,17z\\/data=!3m1!4b1!4m9!3m8!1s0x2dd23d6d262dc895:0x8c375cb7eb34329e!5m2!4m1!1i2!8m2!3d-8.5131407!4d115.2608876!16s%2Fg%2F11f5bp4m65?entry=ttu&g_ep=EgoyMDI2MDMxOC4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.5131354\",\"longitude\":\"115.2583127\",\"updated_at\":\"2026-03-24 09:47:11\"}}', '2026-03-24 01:47:11', '2026-03-24 01:47:11'),
(12, 2, 'Hotel', 'updated', 51, 'App\\Models\\Hotel', '{\"changed\":[\"address\",\"description\",\"status\",\"map\",\"latitude\",\"longitude\",\"updated_at\"],\"before\":{\"address\":\"Jl. Jembawan, Ubud, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571\",\"description\":\"Adiwana Resort Jembawan is a boutique wellness retreat in the heart of Ubud that focuses on body, mind and spirit of rejuvenation. With its team of onsite experts, including an Ayurvedic practitioner and yoga instructor, the resort offers lifestyle programs that are tailored to address any specific health concerns you may have. Designed by Ground Kent Architect, based in Perth, the spacious rooms and suites are built with contemporary Bali in mind.&nbsp;These 41 rooms property are a healing sanctuary for personal renewal with affordable solutions to many of the issues caused by trying to exist in today\\u2019s fast paced world. It is a place where guests are encouraged to slow down, eat nutritious food and return to the basics of simply living well.\",\"status\":\"Active\",\"map\":\"https:\\/\\/g.page\\/hideawayvillasbali?share\",\"latitude\":null,\"longitude\":null,\"updated_at\":\"2025-06-30T02:47:41.000000Z\"},\"after\":{\"address\":\"Jalan Dalem Suargan, Bongkasa, Bali, Indonesia\",\"description\":\"Adiwana Resort Jembawan is a boutique wellness retreat in the heart of Ubud that focuses on body, mind and spirit of rejuvenation. With its team of onsite experts, including an Ayurvedic practitioner and yoga instructor, the resort offers lifestyle programs that are tailored to address any specific health concerns you may have. Designed by Ground Kent Architect, based in Perth, the spacious rooms and suites are built with contemporary Bali in mind.&amp;nbsp;These 41 rooms property are a healing sanctuary for personal renewal with affordable solutions to many of the issues caused by trying to exist in today\\u2019s fast paced world. It is a place where guests are encouraged to slow down, eat nutritious food and return to the basics of simply living well.\",\"status\":\"active\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Adiwana+Resort+Jembawan\\/@-8.5198623,115.2289771,13.25z\\/data=!4m9!3m8!1s0x2dd23d694d2ffaed:0x791a0d66f8ecc581!5m2!4m1!1i2!8m2!3d-8.5100961!4d115.2668279!16s%2Fg%2F11c3109rn1?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.5198623\",\"longitude\":\"115.2289771\",\"updated_at\":\"2026-03-25 01:49:27\"}}', '2026-03-24 17:49:27', '2026-03-24 17:49:27'),
