(18, 2, 'Hotel', 'updated', 96, 'App\\Models\\Hotel', '{\"changed\":[\"address\",\"description\",\"facility\",\"status\",\"cover\",\"web\",\"check_in_time\",\"check_out_time\",\"map\",\"latitude\",\"longitude\",\"updated_at\"],\"before\":{\"address\":\"Jl. Raya Legian 123B Kuta\",\"description\":\"<p>Steeped in romance, Alaya Dedaun Kuta brings affordable luxury and understated Indonesian elegance to Bali&rsquo;s favourite beachside playground. Designed to embrace the spirit of a traditional village, the property features a collection of just 12 private villas in a concept attuned to the attributes of outdoor living.<\\/p><p>Each villa is a tropical retreat secluded within a native garden compound featuring a generous sized swimming pool and ample space to unwind. Bedroom suites are styled to evoke a sense of privacy with canopied beds and indulging bathroom facilities. Attentive butler service ensures that all needs are effortlessly taken care of with a warm Balinese smile.<\\/p>\",\"facility\":\"<ul><li>Private swimming pool set within a tropical garden compound<\\/li><li>Fully equipped gourmet kitchen<\\/li><li>Stylish living environment<\\/li><li>Separate shower and bathtub<\\/li><li>Signature bathroom amenities<\\/li><li>Air &ndash; Conditioner<\\/li><li>IDD Telephone<\\/li><li>Cable TV ( International and local&nbsp; channels)<\\/li><li>Surround sound home entertainment system<\\/li><li>Espresso coffee and tea making facilities<\\/li><li>Minibar<\\/li><li>Safety deposit box<\\/li><li>Slippers &amp; Kimonos<\\/li><li>Hair Dryer<\\/li><li>Iron ( on request )<\\/li><li>Baby cot on request<\\/li><li>Turn down service<\\/li><li>Laundry, dry cleaning and pressing service<\\/li><\\/ul>\",\"status\":\"Active\",\"cover\":\"1700195476_Alaya-Dedaun-Kuta.webp\",\"web\":\"www.alayahotels.com\",\"check_in_time\":null,\"check_out_time\":null,\"map\":\"https:\\/\\/goo.gl\\/maps\\/HrWNm7AMdSW7V54k7\",\"latitude\":null,\"longitude\":null,\"updated_at\":\"2024-11-04T09:06:26.000000Z\"},\"after\":{\"address\":\"Gang Nakula, Kuta, Bali, Indonesia\",\"description\":\"<p>Steeped in romance, Alaya Dedaun Kuta brings affordable luxury and understated Indonesian elegance to Bali\\u2019s favourite beachside playground. Designed to embrace the spirit of a traditional village, the property features a collection of just 12 private villas in a concept attuned to the attributes of outdoor living.<\\/p><p>Each villa is a tropical retreat secluded within a native garden compound featuring a generous sized swimming pool and ample space to unwind. Bedroom suites are styled to evoke a sense of privacy with canopied beds and indulging bathroom facilities. Attentive butler service ensures that all needs are effortlessly taken care of with a warm Balinese smile.<\\/p>\",\"facility\":\"<ul><li>Private swimming pool set within a tropical garden compound<\\/li><li>Fully equipped gourmet kitchen<\\/li><li>Stylish living environment<\\/li><li>Separate shower and bathtub<\\/li><li>Signature bathroom amenities<\\/li><li>Air \\u2013 Conditioner<\\/li><li>IDD Telephone<\\/li><li>Cable TV ( International and local&nbsp; channels)<\\/li><li>Surround sound home entertainment system<\\/li><li>Espresso coffee and tea making facilities<\\/li><li>Minibar<\\/li><li>Safety deposit box<\\/li><li>Slippers &amp; Kimonos<\\/li><li>Hair Dryer<\\/li><li>Iron ( on request )<\\/li><li>Baby cot on request<\\/li><li>Turn down service<\\/li><li>Laundry, dry cleaning and pressing service<\\/li><\\/ul>\",\"status\":\"active\",\"cover\":\"hotels\\/covers\\/1700195476_Alaya-Dedaun-Kuta.webp\",\"web\":\"https:\\/\\/alayahotels.com\\/alaya-dedaun-kuta\",\"check_in_time\":\"11:00\",\"check_out_time\":\"13:00\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Alaya+Dedaun+Kuta\\/@-8.7132313,115.1709377,17z\\/data=!4m10!3m9!1s0x2dd24702420401f1:0x3179d5feabe35c2b!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.7132366!4d115.1735126!16s%2Fg%2F11h81hd1zd?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.7132313\",\"longitude\":\"115.1709377\",\"updated_at\":\"2026-03-25 03:05:51\"}}', '2026-03-24 19:05:51', '2026-03-24 19:05:51'),
