(39, 2, 'Hotel', 'updated', 55, 'App\\Models\\Hotel', '{\"changed\":[\"additional_info\",\"cover\",\"map\",\"updated_at\"],\"before\":{\"additional_info\":\"<p><strong>Children Policy :<\\/strong>&nbsp;<\\/p><ul><li>The river tents and Keliki Valley tents are not suitable for families with infants and children below the age of 10<\\/li><li>The child and 1 infant can stay free of charge with the parents using the tent&rsquo;s existing bedding configuration according to maximum bedding capacity stated below, breakfast included<\\/li><li>A cot for infants is provided with our compliments.<\\/li><li>A child is defined as a person between the ages of 4-12 years&rsquo; old, whereas an infant is defined as a person below the age of 4 years&rsquo; old.&nbsp;<\\/li><\\/ul><p><strong>Honeymoon Amenity :&nbsp;<\\/strong><\\/p><p>Honeymoon cake, one flower bath and one bouquet of flowers await the couple - once during their stay&nbsp;<\\/p><p><strong>Anniversary Amenity :&nbsp;<\\/strong><\\/p><p>Two Tridatu bracelets and one anniversary cake await the couple - once during the guest&#39;s stay&nbsp;<\\/p><p><strong>Birthday Amenity :&nbsp;<\\/strong><\\/p><p>One birthday cake and a special surprise await the guset - once during the guest&#39;s stay&nbsp;<\\/p>\",\"cover\":\"1700191668_Capella-Ubud.webp\",\"map\":\"https:\\/\\/g.page\\/CapellaUbud?share\",\"updated_at\":\"2026-03-25T02:26:55.000000Z\"},\"after\":{\"additional_info\":\"<p><strong>Children Policy :<\\/strong>&nbsp;<\\/p><ul><li>The river tents and Keliki Valley tents are not suitable for families with infants and children below the age of 10<\\/li><li>The child and 1 infant can stay free of charge with the parents using the tent\\u2019s existing bedding configuration according to maximum bedding capacity stated below, breakfast included<\\/li><li>A cot for infants is provided with our compliments.<\\/li><li>A child is defined as a person between the ages of 4-12 years\\u2019 old, whereas an infant is defined as a person below the age of 4 years\\u2019 old.&nbsp;<\\/li><\\/ul><p><strong>Honeymoon Amenity :&nbsp;<\\/strong><\\/p><p>Honeymoon cake, one flower bath and one bouquet of flowers await the couple - once during their stay&nbsp;<\\/p><p><strong>Anniversary Amenity :&nbsp;<\\/strong><\\/p><p>Two Tridatu bracelets and one anniversary cake await the couple - once during the guest\'s stay&nbsp;<\\/p><p><strong>Birthday Amenity :&nbsp;<\\/strong><\\/p><p>One birthday cake and a special surprise await the guset - once during the guest\'s stay&nbsp;<\\/p>\",\"cover\":\"hotels\\/covers\\/1700191668_Capella-Ubud.webp\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Capella+Ubud,+Bali\\/@-8.4482038,115.2655368,17z\\/data=!4m10!3m9!1s0x2dd2232a33674863:0x25093ef92f99017c!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.4482091!4d115.2681117!16s%2Fg%2F11g0h_r0wd?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"updated_at\":\"2026-03-25 03:51:09\"}}', '2026-03-24 19:51:09', '2026-03-24 19:51:09'),
(40, 2, 'Hotel', 'updated', 72, 'App\\Models\\Hotel', '{\"changed\":[\"address\",\"description\",\"cover\",\"web\",\"map\",\"latitude\",\"longitude\",\"updated_at\"],\"before\":{\"address\":\"Jl. Raya Bilukan, Sebatu, Kec. Tegallalang, Kabupaten Gianyar, Bali 80561\",\"description\":\"Cicada Resort Bali Ubud, Autograph Collection sits just 10 minutes away from the renowned Tegalalang Rice Fields and a mere 25-minute drive from the breathtaking vistas of Kintamani. Thanks to our secluded location away from the bustling crowds, we ensure a peaceful and rejuvenating experience for all of our guests.Perfect for a romantic trip or honeymoon, the resort offers a charming and unique blend&nbsp;of Balinese and modern designs. Within, it contains 20 suites with valley views and 10 heated pool villas that have each been tailored to provide a wellness-focused experience. During your stay, you can enjoy a culinary journey at Tangelo Restaurant, which offers a concept of casual fine dining with international cuisine. Elsewhere, the resort also includes the Verdant Pool Lounge &amp; Bar, a casual dining concept serving Asian, international, and healthy options. For relaxation, visit Pravi SPA, which provides a range of therapeutic treatments. Alternatively, work on your fitness routine at the fitness centre.\",\"cover\":\"1744771254_Cover.jpg\",\"web\":\"marriott.com\",\"map\":\"https:\\/\\/goo.gl\\/maps\\/SQqo4irvLf1uBmfWA\",\"latitude\":null,\"longitude\":null,\"updated_at\":\"2026-03-25T02:26:55.000000Z\"},\"after\":{\"address\":\"Sebatu, Bali, Indonesia\",\"description\":\"Cicada Resort Bali Ubud, Autograph Collection sits just 10 minutes away from the renowned Tegalalang Rice Fields and a mere 25-minute drive from the breathtaking vistas of Kintamani. Thanks to our secluded location away from the bustling crowds, we ensure a peaceful and rejuvenating experience for all of our guests.Perfect for a romantic trip or honeymoon, the resort offers a charming and unique blend&amp;nbsp;of Balinese and modern designs. Within, it contains 20 suites with valley views and 10 heated pool villas that have each been tailored to provide a wellness-focused experience. During your stay, you can enjoy a culinary journey at Tangelo Restaurant, which offers a concept of casual fine dining with international cuisine. Elsewhere, the resort also includes the Verdant Pool Lounge &amp;amp; Bar, a casual dining concept serving Asian, international, and healthy options. For relaxation, visit Pravi SPA, which provides a range of therapeutic treatments. Alternatively, work on your fitness routine at the fitness centre.\",\"cover\":\"hotels\\/covers\\/1744771254_Cover.jpg\",\"web\":\"https:\\/\\/www.marriott.com\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Cicada+Resort+Bali+Ubud,+Autograph+Collection\\/@-8.3895893,115.2937091,17z\\/data=!4m10!3m9!1s0x2dd21f452f6e050b:0xeaa2ef07d03d74e8!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.3895946!4d115.296284!16s%2Fg%2F11g02yv714?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.3873628\",\"longitude\":\"115.2971130\",\"updated_at\":\"2026-03-25 03:55:50\"}}', '2026-03-24 19:55:50', '2026-03-24 19:55:50'),
