(45, 2, 'Hotel', 'updated', 54, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"description\",\"latitude\",\"longitude\",\"updated_at\",\"updated_by\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"description\":\"The Monkey Forest area has always been referred to as the beating heart of Ubud. It captures the essence of Tri Hita Karana that believes that in order to reach the ultimate well-being, one must live harmoniously with other people, with nature, and with God. Strategically located within the area, Adiwana Monkey Forest offers the perfect Bali getaway. The 21 suites are beautifully designed to showcase the artistic Balinese craftsmanship while maintaining a contemporary feel.&amp;amp;nbsp;\",\"latitude\":-8.5132254,\"longitude\":115.2609125,\"updated_at\":\"2026-03-25T03:14:56.000000Z\",\"updated_by\":1},\"after\":{\"city\":\"Ubud\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"description\":\"The Monkey Forest area has always been referred to as the beating heart of Ubud. It captures the essence of Tri Hita Karana that believes that in order to reach the ultimate well-being, one must live harmoniously with other people, with nature, and with God. Strategically located within the area, Adiwana Monkey Forest offers the perfect Bali getaway. The 21 suites are beautifully designed to showcase the artistic Balinese craftsmanship while maintaining a contemporary feel.&amp;amp;amp;nbsp;\",\"latitude\":\"-8.5133734\",\"longitude\":\"115.2608718\",\"updated_at\":\"2026-03-26 02:57:33\",\"updated_by\":2}}', '2026-03-25 18:57:33', '2026-03-25 18:57:33'),
(46, 2, 'Hotel', 'updated', 51, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"address\",\"description\",\"map\",\"latitude\",\"longitude\",\"updated_at\",\"updated_by\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"address\":\"Jalan Dalem Suargan, Bongkasa, Bali, Indonesia\",\"description\":\"Adiwana Resort Jembawan is a boutique wellness retreat in the heart of Ubud that focuses on body, mind and spirit of rejuvenation. With its team of onsite experts, including an Ayurvedic practitioner and yoga instructor, the resort offers lifestyle programs that are tailored to address any specific health concerns you may have. Designed by Ground Kent Architect, based in Perth, the spacious rooms and suites are built with contemporary Bali in mind.&amp;amp;amp;amp;nbsp;These 41 rooms property are a healing sanctuary for personal renewal with affordable solutions to many of the issues caused by trying to exist in today\\u2019s fast paced world. It is a place where guests are encouraged to slow down, eat nutritious food and return to the basics of simply living well.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Adiwana+Resort+Jembawan\\/@-8.5198623,115.2289771,13.25z\\/data=!4m9!3m8!1s0x2dd23d694d2ffaed:0x791a0d66f8ecc581!5m2!4m1!1i2!8m2!3d-8.5100961!4d115.2668279!16s%2Fg%2F11c3109rn1?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":-8.5101191,\"longitude\":115.2668479,\"updated_at\":\"2026-03-25T03:00:28.000000Z\",\"updated_by\":1},\"after\":{\"city\":\"Ubud\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"address\":\"Jalan Jembawan, Ubud, Bali, Indonesia\",\"description\":\"Adiwana Resort Jembawan is a boutique wellness retreat in the heart of Ubud that focuses on body, mind and spirit of rejuvenation. With its team of onsite experts, including an Ayurvedic practitioner and yoga instructor, the resort offers lifestyle programs that are tailored to address any specific health concerns you may have. Designed by Ground Kent Architect, based in Perth, the spacious rooms and suites are built with contemporary Bali in mind.&amp;amp;amp;amp;amp;nbsp;These 41 rooms property are a healing sanctuary for personal renewal with affordable solutions to many of the issues caused by trying to exist in today\\u2019s fast paced world. It is a place where guests are encouraged to slow down, eat nutritious food and return to the basics of simply living well.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Adiwana+Resort+Jembawan\\/@-8.5097384,115.2665512,19.5z\\/data=!4m9!3m8!1s0x2dd23d694d2ffaed:0x791a0d66f8ecc581!5m2!4m1!1i2!8m2!3d-8.5100961!4d115.2668279!16s%2Fg%2F11c3109rn1?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.5104106\",\"longitude\":\"115.2676824\",\"updated_at\":\"2026-03-26 03:00:25\",\"updated_by\":2}}', '2026-03-25 19:00:25', '2026-03-25 19:00:25'),
