(54, 2, 'Hotel', 'updated', 78, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"description\",\"additional_info\",\"map\",\"latitude\",\"longitude\",\"updated_at\",\"updated_by\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"description\":\"Nestled in the heart of Tegallalang, the AnandaDara Ubud Resort &amp;amp; Spa is a testament to the seamless integration of classy design and the natural beauty of Bali. Expertly crafted by acclaimed Balinese architect, Miyoga, the resort is a harmonious blend of traditional Balinese elements and modern comforts. Surrounded by lush rice paddies and meticulously manicured gardens, AnandaDara invites guests to a serene retreat that captures the essence of Bali\\u2019s charm.\",\"additional_info\":\"No check in and no check out on - seclusion day (Nyepi Day)&amp;nbsp;\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/AnandaDara+Ubud+Resort+%26+Spa\\/@-8.4678317,115.2669621,17z\\/data=!4m10!3m9!1s0x2dd2235d54eadbab:0x58721c2a9d4514b2!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.467837!4d115.269537!16s%2Fg%2F11vq6k7r72?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":-8.467719,\"longitude\":115.2695114,\"updated_at\":\"2026-03-25T03:29:27.000000Z\",\"updated_by\":1},\"after\":{\"city\":\"Kenderan\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"description\":\"Nestled in the heart of Tegallalang, the AnandaDara Ubud Resort &amp;amp;amp; Spa is a testament to the seamless integration of classy design and the natural beauty of Bali. Expertly crafted by acclaimed Balinese architect, Miyoga, the resort is a harmonious blend of traditional Balinese elements and modern comforts. Surrounded by lush rice paddies and meticulously manicured gardens, AnandaDara invites guests to a serene retreat that captures the essence of Bali\\u2019s charm.\",\"additional_info\":\"No check in and no check out on - seclusion day (Nyep