(61, 2, 'Hotel', 'updated', 144, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"address\",\"description\",\"map\",\"latitude\",\"longitude\",\"updated_at\",\"updated_by\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"address\":\"Jalan Ritz Carlton, Jimbaran, Bali, Indonesia\",\"description\":\"On Bali\'s heights, traditions bloom, modern forms kissed by ocean\\u2019s plume. Vibrant blooms greet dawn\'s embrace, welcoming travelers to this sacred place. A realm of rest, discovery\\u2019s door, ancient roots and dreams explore.&nbsp;On this hilltop where breezes sing, eternal dance of time&nbsp;they bring.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/AYANA+Segara+Bali\\/@-8.7874822,115.1378222,17z\\/data=!4m10!3m9!1s0x2dd24591e9ebebd3:0x8ab63d8b6077342a!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.7874875!4d115.1403971!16s%2Fg%2F11sbdh4gms?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":-8.7874001,\"longitude\":115.1406866,\"updated_at\":\"2026-03-25T03:40:59.000000Z\",\"updated_by\":1},\"after\":{\"city\":\"Balangan\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"address\":\"Jalan Ritz Carlton, Balangan, Bali, Indonesia\",\"description\":\"On Bali\'s heights, traditions bloom, modern forms kissed by ocean\\u2019s plume. Vibrant blooms greet dawn\'s embrace, welcoming travelers to this sacred place. A realm of rest, discovery\\u2019s door, ancient roots and dreams explore.&amp;nbsp;On this hilltop where breezes sing, eternal dance of time&amp;nbsp;they bring.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/AYANA+Segara+Bali\\/@-8.7874822,115.1378222,17z\\/data=!3m1!4b1!4m9!3m8!1s0x2dd24591e9ebebd3:0x8ab63d8b6077342a!5m2!4m1!1i2!8m2!3d-8.7874875!4d115.1403971!16s%2Fg%2F11sbdh4gms?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.7871764\",\"longitude\":\"115.1405254\",\"updated_at\":\"2026-03-26 03:18:52\",\"updated_by\":2}}', '2026-03-25 19:18:52', '2026-03-25 19:18:52'),
(62, 2, 'Hotel', 'updated', 146, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"description\",\"map\",\"latitude\",\"longitude\",\"updated_at\",\"updated_by\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"description\":\"Perched atop the cliff\'s edge, overlooking the Jimbaran sea, a distinctive Balinese villa awaits. The rooms are spacious and grand, with a butler ready to lend a hand, offering attentive service tailored to your plan. The freedom to do anything, or nothing at all. Surrounded by graceful silence and nature\'s embrace,&nbsp;take an extraordinary escape in this secluded space.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/AYANA+Villas+Bali\\/@-8.7879957,115.1340515,17z\\/data=!4m10!3m9!1s0x2dd24502e260697b:0x826f7997cd0bff97!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.788001!4d115.1366264!16s%2Fg%2F11xk3wd3c?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":-8.7880256,\"longitude\":115.1365347,\"updated_at\":\"2026-03-25T03:42:03.000000Z\",\"updated_by\":1},\"after\":{\"city\":\"Jimbaran\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"description\":\"Perched atop the cliff\'s edge, overlooking the Jimbaran sea, a distinctive Balinese villa awaits. The rooms are spacious and grand, with a butler ready to lend a hand, offering attentive service tailored to your plan. The freedom to do anything, or nothing at all. Surrounded by graceful silence and nature\'s embrace,&amp;nbsp;take an extraordinary escape in this secluded space.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/AYANA+Villas+Bali\\/@-8.7879957,115.1340515,17z\\/data=!3m1!4b1!4m9!3m8!1s0x2dd24502e260697b:0x826f7997cd0bff97!5m2!4m1!1i2!8m2!3d-8.788001!4d115.1366264!16s%2Fg%2F11xk3wd3c?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.7879398\",\"longitude\":\"115.1365879\",\"updated_at\":\"2026-03-26 03:20:02\",\"updated_by\":2}}', 