(69, 2, 'Hotel', 'updated', 72, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"description\",\"map\",\"latitude\",\"longitude\",\"updated_at\",\"updated_by\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"description\":\"Cicada Resort Bali Ubud, Autograph Collection sits just 10 minutes away from the renowned Tegalalang Rice Fields and a mere 25-minute drive from the breathtaking vistas of Kintamani. Thanks to our secluded location away from the bustling crowds, we ensure a peaceful and rejuvenating experience for all of our guests.Perfect for a romantic trip or honeymoon, the resort offers a charming and unique blend&amp;nbsp;of Balinese and modern designs. Within, it contains 20 suites with valley views and 10 heated pool villas that have each been tailored to provide a wellness-focused experience. During your stay, you can enjoy a culinary journey at Tangelo Restaurant, which offers a concept of casual fine dining with international cuisine. Elsewhere, the resort also includes the Verdant Pool Lounge &amp;amp; Bar, a casual dining concept serving Asian, international, and healthy options. For relaxation, visit Pravi SPA, which provides a range of therapeutic treatments. Alternatively, work on your fitness routine at the fitness centre.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Cicada+Resort+Bali+Ubud,+Autograph+Collection\\/@-8.3895893,115.2937091,17z\\/data=!4m10!3m9!1s0x2dd21f452f6e050b:0xeaa2ef07d03d74e8!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.3895946!4d115.296284!16s%2Fg%2F11g02yv714?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D\",\"latitude\":-8.3873628,\"longitude\":115.297113,\"updated_at\":\"2026-03-25T03:55:50.000000Z\",\"updated_by\":1},\"after\":{\"city\":\"Sebatu\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"description\":\"Cicada Resort Bali Ubud, Autograph Collection sits just 10 minutes away from the renowned Tegalalang Rice Fields and a mere 25-minute drive from the breathtaking vistas of Kintamani. Thanks to our secluded location away from the bustling crowds, we ensure a peaceful and rejuvenating experience for all of our guests.Perfect for a romantic trip or honeymoon, the resort offers a charming and unique blend&amp;amp;nbsp;of Balinese and modern designs. Within, it contains 20 suites with valley views and 10 heated pool villas that have each been tailored to provide a wellness-focused experience. During your stay, you can enjoy a culinary journey at Tangelo Restaurant, which offers a concept of casual fine dining with international cuisine. Elsewhere, the resort also includes the Verdant Pool Lounge &amp;amp;amp; Bar, a casual dining concept serving Asian, international, and healthy options. For relaxation, visit Pravi SPA, which provides a range of therapeutic treatments. Alternatively, work on your fitness routine at the fitness centre.\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Cicada+Resort+Bali+Ubud,+Autograph+Collection\\/@-8.3895893,115.2937091,17z\\/data=!3m1!4b1!4m9!3m8!1s0x2dd21f452f6e050b:0xeaa2ef07d03d74e8!5m2!4m1!1i2!8m2!3d-8.3895946!4d115.296284!16s%2Fg%2F11g02yv714?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.3895893\",\"longitude\":\"115.2937091\",\"updated_at\":\"2026-03-26 03:28:10\",\"updated_by\":2}}', '2026-03-25 19:28:10', '2026-03-25 19:28:10'),
