(73, 2, 'Hotel', 'updated', 27, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"address\",\"description\",\"additional_info\",\"cover\",\"map\",\"latitude\",\"longitude\",\"updated_at\",\"updated_by\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"address\":\"Kawasan Pariwisata Lot Sw1, Jl. Nusa Dua, Benoa, Bali, Kabupaten Badung\\t,Bali, Indonesia\",\"description\":\"<p>Discover the relaxed comfort and exceptional service awaiting you at Courtyard Bali Nusa Dua Resort. Our award-winning hotel is a few miles from the airport via our shuttle service. Unwind in our Nusa Dua five-star resort accommodations with amenities like complimentary Wi-Fi and a flat-screen TV, a marble bathroom and a private balcony with scenic views of the resort and Nusa Dua beach. Stop by one of our inviting dining outlets to enjoy all-day cuisine, to-go snacks or poolside refreshments. There&#39;s no better way to bask in the Bali sunshine than at our resort&#39;s lagoon pool. Our youngest guests can have fun at the Kids&#39; Club or at the children&#39;s pool and lazy river. Pamper yourself with a luxury treatment at the resort spa, challenge yourself in the gym or take the complimentary shuttle to our Beach Club and spend the day relaxing on Nusa Dua Beach. Those hosting an event in Bali can explore our hotel&#39;s versatile indoor and outdoor venues as well. Plan your getaway to our Nusa Dua, Bali, resort today<\\/p>\",\"additional_info\":\"<p>Daily breakfast<\\/p><p>Minimum of 4 continuous stay is required during Peak Season (23 December 2022 &ndash; 5 January 2023)<\\/p><p>No Check Out is permitted on December 31st<\\/p>\",\"cover\":\"1700189085_Courtyard.webp\",\"map\":\"https:\\/\\/g.page\\/CourtyardBali?share\",\"latitude\":null,\"longitude\":null,\"updated_at\":\"2026-03-25T02:26:55.000000Z\",\"updated_by\":1},\"after\":{\"city\":\"Nusa Dua\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"address\":\"Nusa Dua, Bali, Indonesia\",\"description\":\"<p>Discover the relaxed comfort and exceptional service awaiting you at Courtyard Bali Nusa Dua Resort. Our award-winning hotel is a few miles from the airport via our shuttle service. Unwind in our Nusa Dua five-star resort accommodations with amenities like complimentary Wi-Fi and a flat-screen TV, a marble bathroom and a private balcony with scenic views of the resort and Nusa Dua beach. Stop by one of our inviting dining outlets to enjoy all-day cuisine, to-go snacks or poolside refreshments. There\'s no better way to bask in the Bali sunshine than at our resort\'s lagoon pool. Our youngest guests can have fun at the Kids\' Club or at the children\'s pool and lazy river. Pamper yourself with a luxury treatment at the resort spa, challenge yourself in the gym or take the complimentary shuttle to our Beach Club and spend the day relaxing on Nusa Dua Beach. Those hosting an event in Bali can explore our hotel\'s versatile indoor and outdoor venues as well. Plan your getaway to our Nusa Dua, Bali, resort today<\\/p>\",\"additional_info\":\"<p>Daily breakfast<\\/p><p>Minimum of 4 continuous stay is required during Peak Season (23 December 2022 \\u2013 5 January 2023)<\\/p><p>No Check Out is permitted on December 31st<\\/p>\",\"cover\":\"hotels\\/covers\\/1700189085_Courtyard.webp\",\"map\":\"https:\\/\\/www.google.com\\/maps\\/place\\/Courtyard+by+Marriott+Bali+Nusa+Dua+Resort\\/@-8.8069575,115.2227605,17z\\/data=!3m1!4b1!4m9!3m8!1s0x2dd2432632a802d9:0x9d0ae67d948c37f3!5m2!4m1!1i2!8m2!3d-8.8069628!4d115.2253354!16s%2Fg%2F1tk3w7gc?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D\",\"latitude\":\"-8.8071719\",\"longitude\":\"115.2252921\",\"updated_at\":\"2026-03-26 03:34:58\",\"updated_by\":2}}', '2026-03-25 19:34:58', '2026-03-25 19:34:58'),
