(1429, 7, 'Itinerary', 'created', 391, 'App\\Models\\Itinerary', '{\"changes\":[{\"field\":\"title\",\"label\":\"Title\",\"from\":null,\"to\":\"2D1N Bali Family Tour Package\"},{\"field\":\"destination\",\"label\":\"Destination\",\"from\":null,\"to\":\"Bali\"},{\"field\":\"inquiry_id\",\"label\":\"Inquiry Id\",\"from\":null,\"to\":\"5\"},{\"field\":\"duration_days\",\"label\":\"Duration Days\",\"from\":null,\"to\":\"2\"},{\"field\":\"duration_nights\",\"label\":\"Duration Nights\",\"from\":null,\"to\":\"1\"},{\"field\":\"description\",\"label\":\"Description\",\"from\":null,\"to\":\"<strong data-start=\\\"0\\\" data-end=\\\"25\\\" data-is-only-node=\\\"\\\">2D1N Bali Family Tour<\\/strong> is a 2-day, 1-night getaway designed for families who want to enjoy quality time while exploring the beauty of Bali. Visit popular attractions, scenic spots, and family-friendly destinations with a relaxed and enjoyable pace. With comfortable accommodation, private transportation, and a well-arranged itinerary, this tour ensures a memorable and stress-free family holiday.&nbsp;\"},{\"field\":\"is_active\",\"label\":\"Is Active\",\"from\":null,\"to\":true},{\"field\":\"created_by\",\"label\":\"Created By\",\"from\":null,\"to\":7},{\"field\":\"status\",\"label\":\"Status\",\"from\":null,\"to\":\"draft\"},{\"field\":\"destination_id\",\"label\":\"Destination Id\",\"from\":null,\"to\":17},{\"field\":\"updated_by\",\"label\":\"Updated By\",\"from\":null,\"to\":7},{\"field\":\"id\",\"label\":\"Id\",\"from\":null,\"to\":391}]}', '2026-04-06 00:15:53', '2026-04-06 00:15:53');
