(1539, 1, 'Hotel', 'updated', 46, 'App\\Models\\Hotel', '{\"changed\":[\"city\",\"province\",\"country\",\"destination_id\",\"address\",\"description\",\"cover\",\"map\",\"latitude\",\"longitude\",\"cancellation_policy\"],\"before\":{\"city\":null,\"province\":null,\"country\":null,\"destination_id\":null,\"address\":\"Jl. Petitenget, Kerobokan Kelod, Kec. Kuta Utara, Kabupaten Badung, Bali\",\"description\":\"Trade in ordinary for extraordinary at W Bali - Seminyak. Our Green Key certified luxury hotel in Seminyak plays by a different set of rules, located at the heart of Bali\\u2019s vibrant fashion, nightlife, and restaurant scene. This five-star Bali family resort embodies the archipelago with a rice field-inspired WET\\u00ae pool. Visit our 24-hour AWAY\\u00ae Spa and FIT gym. Experience two of our world-class restaurants\\u00a0with the most popular brunch on the island, Starfish Bloo and FIRE. Join the nightlife at Woobar Bali, a beachfront spot with a magnetic social scene. Enjoy garden and panoramic views of the Indian Ocean in your hotel rooms and suites, or the privacy of your private pool in your villa. Soak in a terrazzo bathtub, slip into a robe, order in-room dining, and sleep peacefully under 350-thread-count cotton linens. Before you know it, hit the alarm, head out, and hit repeat.\",\"cover\":\"1744164273_439237188.jpg\",\"map\":\"https:\\/\\/g.page\\/hyattregencybali?share\",\"latitude\":null,\"longitude\":null,\"cancellation_policy\":\"<b>Regular Season (Low Season):\\u00a0<\\/b><br><ul><li>Cancellation within 7 days of arrival : 1 night penalty\\u00a0<\\/li><li>Cancellation within 3 days of arrival : 100% penalty charged\\u00a0<br><\\/li><\\/ul><b>High Season<\\/b> <i>(14 Jun - 31 Aug):\\u00a0<\\/i><br><ul><li>Cancellation within 21 days of arrival : 1 night penalty\\u00a0<\\/li><li>Cancellation within 14 days of arrival : 100% penalty charged\\u00a0<\\/li><\\/ul><b>Peak Season:<\\/b><br><ul><li>Cancellation within 45 days of arrival : 100% penalty charged\\u00a0\\u00a0<\\/li><\\/ul><b>No Show:\\u00a0<br><\\/b><ul><li>Clients who do not show will be charged for the entire length of stay.<\\/li><\\/ul>\"},\"after\":{\"city\":\"Kuta Utara\",\"province\":\"Bali\",\"country\":\"Indonesia\",\"destination_id\":\"17\",\"address\":\"Jalan W Retreat, Kerobokan Kelod, Kuta Utara, Bali, Indonesia\",\"description\":\"Trade in ordinary for extraordinary at W Bali - Seminyak. Our Green Key certified luxury hotel in Seminyak plays by a different set of rules, located at the heart of Bali\\u2019s vibrant fashion, nightlife, and restaurant scene. This five-star Bali family resort embodies the archipelago with a rice field-inspired WET\\u00ae pool. Visit our 24-hour AWAY\\u00ae Spa and FIT gym. Experience two of our world-class restaurants&nbsp;with the most popular brunch on the island, Starfish Bloo and FIRE. Join the nightlife at Woobar Bali, a beachfront spot with a magnetic social scene. Enjoy garden and panoramic views of the Indian Ocean in your hotel rooms and suites, or the privacy of your private pool in your villa. Soak in a terrazzo bathtub, slip into a robe, order in-room dining, and sleep peacefully under 350-thread-count cotton linens. Before you know it, hit the alarm, head out, and hit repeat.\",\"cover\":\"hotels\\/covers\\/1744164273_439237188.jpg\",\"map\":\"https:\\/\\/maps.google.com\\/?q=-8.6773270,115.1492582\",\"latitude\":-8.677327,\"longitude\":115.1492582,\"cancellation_policy\":\"<b>Regular Season (Low Season):&nbsp;<\\/b><br><ul><li>Cancellation within 7 days of arrival : 1 night penalty&nbsp;<\\/li><li>Cancellation within 3 days of arrival : 100% penalty charged&nbsp;<br><\\/li><\\/ul><b>High Season<\\/b> <i>(14 Jun - 31 Aug):&nbsp;<\\/i><br><ul><li>Cancellation within 21 days of arrival : 1 night penalty&nbsp;<\\/li><li>Cancellation within 14 days of arrival : 100% penalty charged&nbsp;<\\/li><\\/ul><b>Peak Season:<\\/b><br><ul><li>Cancellation within 45 days of arrival : 100% penalty charged