(1553, 1, 'Activity', 'created', 30, 'App\\Models\\Activity', '{\"changes\":[{\"field\":\"vendor_id\",\"label\":\"Vendor Id\",\"from\":null,\"to\":\"36\"},{\"field\":\"name\",\"label\":\"Name\",\"from\":null,\"to\":\"Jungle Hopper Legend\"},{\"field\":\"duration_minutes\",\"label\":\"Duration Minutes\",\"from\":null,\"to\":\"120\"},{\"field\":\"benefits\",\"label\":\"Benefits\",\"from\":null,\"to\":null},{\"field\":\"descriptions\",\"label\":\"Descriptions\",\"from\":null,\"to\":\"The Jungle Hopper package is our number one selling ticket! This popular Safari package embarks you on an adventure in the wildlife to encounter a wide variety of animals, even endangered species.\"},{\"field\":\"adult_contract_rate\",\"label\":\"Adult Contract Rate\",\"from\":null,\"to\":200000},{\"field\":\"child_contract_rate\",\"label\":\"Child Contract Rate\",\"from\":null,\"to\":150000},{\"field\":\"adult_markup_type\",\"label\":\"Adult Markup Type\",\"from\":null,\"to\":\"fixed\"},{\"field\":\"adult_markup\",\"label\":\"Adult Markup\",\"from\":null,\"to\":50000},{\"field\":\"child_markup_type\",\"label\":\"Child Markup Type\",\"from\":null,\"to\":\"fixed\"},{\"field\":\"child_markup\",\"label\":\"Child Markup\",\"from\":null,\"to\":50000},{\"field\":\"adult_publish_rate\",\"label\":\"Adult Publish Rate\",\"from\":null,\"to\":250000},{\"field\":\"child_publish_rate\",\"label\":\"Child Publish Rate\",\"from\":null,\"to\":200000},{\"field\":\"capacity_min\",\"label\":\"Capacity Min\",\"from\":null,\"to\":\"2\"},{\"field\":\"capacity_max\",\"label\":\"Capacity Max\",\"from\":null,\"to\":\"100\"},{\"field\":\"includes\",\"label\":\"Includes\",\"from\":null,\"to\":\"<div><ul><li>Safari Journey (1x)<\\/li><li>Bali Agung Show (Tuesday to Sunday)<\\/li><li>Animals Educational Presentation<\\/li><li>Tiger Educational Presentation<\\/li><li>Elephant Educational Presentation<\\/li><li>Tax included<\\/li><\\/ul><\\/div>\"},{\"field\":\"excludes\",\"label\":\"Excludes\",\"from\":null,\"to\":null},{\"field\":\"cancellation_policy\",\"label\":\"Cancellation Policy\",\"from\":null,\"to\":\"The activities schedules are subject to change or cancellation due to weather circumstances and on the condition of our animals.\"},{\"field\":\"notes\",\"label\":\"Notes\",\"from\":null,\"to\":null},{\"field\":\"is_active\",\"label\":\"Is Active\",\"from\":null,\"to\":true},{\"field\":\"activity_type_id\",\"label\":\"Activity Type Id\",\"from\":null,\"to\":2},{\"field\":\"activity_type\",\"label\":\"Activity Type\",\"from\":null,\"to\":\"Adventure\"},{\"field\":\"contract_price\",\"label\":\"Contract Price\",\"from\":null,\"to\":200000},{\"field\":\"gallery_images\",\"label\":\"Gallery Images\",\"from\":null,\"to\":\"[]\"},{\"field\":\"created_by\",\"label\":\"Created By\",\"from\":null,\"to\":1},{\"field\":\"updated_by\",\"label\":\"Updated By\",\"from\":null,\"to\":1},{\"field\":\"id\",\"label\":\"Id\",\"from\":null,\"to\":30}]}', '2026-04-13 07:28:35', '2026-04-13 07:28:35');
