INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(3, 'The Apurva Kempinski', '17', NULL, NULL, NULL, 'DwYDSP55ndP9zvonhCNMAWvSno', '17', NULL, 'Jl. Raya Nusa Dua Selatan, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali', 2, 16, 'Dewi Sartika', '03612092288', 'Standing atop the majestic cliff of Nusa Dua, with breathtaking views of the Indian Ocean and tropical garden, The Apurva Kempinski Bali offers the epitome of beachfront luxury. This five-star hotel in Bali presents itself as a majestic open-air theatre, an embodiment of Indonesian elegance.A collection of 475 iconic rooms, suites and villas are showcased, with 60% of the accommodation featuring its own private plunge pools. From a unique culinary journey and indigenous spa treatments, to the spacious meeting rooms and alluring chapels, The Apurva Kempinski Bali is a spectacular stage where curated experiences are brought to life.', NULL, NULL, '<ul><li>High-Speed Internet Access</li><li>Experiential Concierge</li><li>Lady In Red</li><li>Swimming Pool and Kids Pool</li><li>Cliff Lounge</li><li>Villa Lounge</li><li>Asha Curated Boutique & Gallery</li><li>Jalak Family Club</li><li>In-Room Dining</li><li>Idyllic Beach</li><li>Business Centre</li><li>Parking & Valet</li><li>Airport Pick-Up Service</li></ul>', NULL, NULL, '<b>Children Policy:</b><ul><li>Children 0-5 years old share their parent\'s room at no extra charge</li><li>Babycot is complimentary</li><li>Breakfast is complimentary for children under 6 years old</li></ul><span><b>Honeymoon Benefit (Min 2 night stay):</b><br></span><ul><li>Welcome drink, nice petal flowers of in-room arrangement, variety of in-room fruit bowl, honeymooner’s cake and romantic turn down service amenities on day of arrival.</li></ul>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1731986971_1686212602_Apurva_kempinsky_cover.webp', 14, 'https://www.kempinski.com/en/bali/the-apurva-kempinski-bali/dining/', '2', '360', NULL, NULL, 'https://g.page/KempinskiBali?share', NULL, NULL, NULL, NULL, '<b>Normal Season:</b><ul><li>Cancellation 7 days prior to arrival: No cancellation fee</li><li>Cancellation within 7 days prior to arrival: 100% night cancellation fee </li><li>Reduce in length of stay within 7 days: 100% night cancellation fee </li><li>No-show or Early Departure: 100% cancellation fee </li></ul><b>High Season:</b><ul><li>Cancellation 21 days prior to arrival: No cancellation fee </li><li>Cancellation within 20 days prior to arrival: 1 night cancellation fee </li><li>Cancellation within 14 days or Early Departure/No-Show: 100% cancellation fee </li></ul><b>Peak Season: </b><ul><li>Cancellation 45 days prior to arrival: No cancellation fee </li><li>Cancellation within 30 days prior to arrival: 1 night cancellation fee </li><li>Cancellation within 21 days prior to arrival: 50% cancellation fee </li><li>Cancellation within 14 days or Early Departure/No-Show: 100% cancellation fee </li></ul>', NULL, NULL, NULL, '2022-10-26 00:28:36', '2026-03-24 18:21:00', 1, 1),
(5, 'Merusaka', '17', NULL, NULL, NULL, 'PBMDDwhKa4xXTxEDNxYmwJIZAL', '17', NULL, 'Kawasan Wisata Nusa Dua Lot S-3, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80363', 1, 1, 'Ayu Wanindia', '03612002900', '<p>Located at the heart of the secure gated, exclusive compound of ITDC Nusa Dua area,&nbsp;<a href=\"https://merusaka.com/\">merusaka</a>&nbsp;is awash with tropical natural beauty. Turquoise waters lap at white-sand shores of Mengiat Beach and swaying palm trees, the stunning landscape is exquisitely complemented with the vibrant culture of Bali.</p>', NULL, NULL, '<ul><li>Free Internet Access</li><li>Free Parking&nbsp;</li><li>Restaurant On-Site&nbsp;</li><li>Room&nbsp;Service&nbsp;</li><li>Fitness&nbsp;Center&nbsp;</li><li>Pool</li><li>SPA&nbsp;</li><li>Concierge&nbsp;</li><li>Beach&nbsp;Front</li><li>Laundry&nbsp;</li><li>Meeting&nbsp;Facilities&nbsp;</li><li>Business&nbsp;Center</li></ul>', NULL, NULL, '<p><strong>Children Policy:&nbsp;</strong></p><p>Children under 6 years old sharing existing bedding with parents will be free of charge for breakfast or meal plans.</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1731987303_nusa-dua-7-1030x687.webp', 2, 'https://merusaka.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/czckeDJMaedjtDH56', NULL, NULL, NULL, NULL, '<ul></ul><p><strong>Low Season</strong> <em>(01 Apr - 30 Jun, 01 Sep - 23 Dec, 04 Jan - 31 Mar):</em>&nbsp;Cancellation 7 days, Full Charge</p><p><strong>High Season</strong> <em>(01 Jul - 31 Aug): </em>Cancellation 30 days, Full Charge</p><p><strong>Peak Season</strong><em> (24 Dec - 03 Jan): </em>Cancellation 45 days, Full Charge&nbsp;</p><p><strong>No show or Early Check Out</strong> considered as cancellation and will be applied full charge&nbsp;</p><p><strong>Seasonal Policy:&nbsp;</strong></p><ol><li>Minimum stay 3 nights valid for booking on the period of 24 December 2024 - 03 January 2025&nbsp;</li><li>Compulsory New Year Eve Dinner on 31 December 2024 at USD 106 net/person&nbsp;</li></ol>', NULL, NULL, NULL, '2022-10-26 02:38:34', '2026-03-24 18:26:55', 2, 1),
(6, 'Alila Villas Uluwatu', '17', 'Pecatu', 'Bali', 'Indonesia', 'pwdaAR3PKvShVefAJRvKyWXeN8', '17', 17, 'Jalan Temu Dewi, Pecatu, Bali, Indonesia', 2, 20, 'Miu Miu Chang', '03618482166', 'Set atop dramatic cliffs overlooking the Indian Ocean, in a setting that feels as if you’re at the edge of the world, is Alila Villas Uluwatu. Here, you’ll find a profound connection to place and self in ways unknown.', '座落於俯瞰印度洋的壯麗懸崖之上，彷彿身處世界盡頭的地方，這裡是 Alila Villas Uluwatu。在這裡，您將以前所未有的方式，與這片土地以及自我建立深刻的聯繫。', '坐落于俯瞰印度洋的壮丽悬崖之上，仿佛置身世界尽头的地方，这里是 Alila Villas Uluwatu。在这里，您将以前所未有的方式，与这片土地以及内心深处建立深刻的连接。', '<ul><li>Wi-Fi internet access throughout the resort</li><li>Morning Yoga classes everyday from 7.30am - 8.30am</li><li>Host (butler) service</li><li>Use of 24-hour gym</li><li>Bicycles available for guests\' use at the resort</li><li>Alila Living bath amenities</li></ul>', '<ul><li><li>度假村全區提供 Wi-Fi 無線網路</li><li>每天早上 7:30 - 8:30 提供晨間瑜伽課程</li><li>管家服務</li><li>24 小時健身房開放使用</li><li>度假村內提供賓客使用的自行車</li><li>Alila Living 沐浴用品</li></li></ul>', '<ul><li><li>度假村全区域提供 Wi-Fi 无线网络</li><li>每天早上 7:30 - 8:30 提供晨间瑜伽课程</li><li>管家服务</li><li>24 小时健身房开放使用</li><li>度假村内提供宾客使用的自行车</li><li>Alila Living 沐浴用品</li></li></ul>', '<b>Seasonal Policy :</b><ul><li>Minimum 3 nights stay for Peak Season</li><li>The following special conditions to be applied during Peak Season (24 Dec&nbsp;- 05 Jan): No check – out on 31 December, no set dinner is available on 24, 25 &amp; 31 December &amp; 1 January</li></ul><b>Couple Celebration :&nbsp;</b><br><ul><li>(Honeymoon Benefits): Romantic drawn bath and scented candles, a special selection of Alila room amenities placed in the villa prior to arrival</li></ul>', '季節性政策：\r\n<ul>\r\n<li>\r\n節假高峰期（12月24日 - 次年1月5日）需至少入住3晚。\r\n</li>\r\n<li>\r\n節假高峰期間適用以下特別條款：12月31日不可辦理退房，12月24日、25日、31日及1月1日不提供套餐晚餐服務。\r\n</li>\r\n</ul>\r\n<span>情侶慶典：<br></span><ul><li>（蜜月禮遇）：浪漫泡澡與香氛蠟燭，精選 Alila 房間備品將在客人抵達前特別布置於別墅內。</li></ul>', '季节性政策：\r\n<ul>\r\n<li>\r\n节假高峰期（12月24日 - 次年1月5日）需至少入住3晚。\r\n</li>\r\n<li>\r\n节假高峰期间适用以下特别条款：12月31日不可办理退房，12月24日、25日、31日及1月1日不提供套餐晚餐服务。\r\n</li>\r\n</ul>\r\n<span>情侣庆典：<br></span><ul><li>\r\n（蜜月礼遇）：浪漫泡泡浴及香薰蜡烛，别致的 Alila 房间礼品将于客人抵达前精心布置于别墅内。</li></ul>', '<p><strong>早上&amp;中午 - 婚礼的早餐</strong></p><p>如果要点早餐送到房间只能点2位新人的早餐份量。不允许点给工作人员，亲友，朋友们的份量。如果被酒店发现酒店会强制罚款或者另外收几位的早餐费用。请告知新人。</p><p><strong>早上&amp;中午 &ndash; 花材 可2选1</strong></p><p>4个兰花 + 10把白玫瑰 或者 20把白玫瑰</p>', NULL, NULL, 'active', 'hotels/covers/1700186622_Alila-Villa-Uluwatu.webp', 14, 'https://www.alilahotels.com/uluwatu', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Alila+Villas+Uluwatu/@-8.8442319,115.1355433,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd25add7437e1c1:0xb608f145222330a6!5m2!4m1!1i2!8m2!3d-8.8442372!4d115.1381182!16s%2Fg%2F1v2gb4_0?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.8440253, 115.1380157, NULL, NULL, '<span><b>Normal Season</b> <i>(01 Apr - 14 Jul, 16 Sep - 23 Dec, 06 Jan - 31 March) :</i></span><ul><li>a cancellation fee equivalent to one night of the room charge for each room cancelled less than 7&nbsp;days prior to arrival</li><li>a no-show fee equivalent to one night will be charged for each room whereby booking will be canceled immediately</li></ul><span><b>High Season</b> <i>(15 Jul - 15 Sep) :</i></span><ul><li>a cancellation fee equivalent to one night of the room charge for each room cancelled less than 14 days prior to arrival</li><li>a no-show fee equivalent to 50% of the total room nights will be charged for each room whereby booking will be canceled immediately</li></ul><span><b>Peak Season</b> <i>(24 Dec - 05 Jan) :</i></span><ul><li>a cancellation fee equivalent to 100% of the total night per room reserved for each room cancelled less than 30 days prior to arrival</li><li>a no-show fee equivalent to the entire stay will be charged for each room whereby booking will be canceled immediately</li></ul>', '平季（4月1日 - 7月14日、9月16日 - 12月23日、次年1月6日 - 3月31日）：\r\n<br>\r\n<ul><li>若於抵達日前 少於7天取消，每間客房將收取相當於 1晚房費的取消費用。</li><li>若未如期入住（No-show），每間客房將收取 1晚房費作為未入住費用，並立即取消預訂。</li></ul>\r\n旺季（7月15日 - 9月15日）：\r\n<ul>\r\n<li>\r\n若於抵達日前 少於14天取消，每間客房將收取相當於 1晚房費的取消費用。\r\n</li>\r\n<li>\r\n若未如期入住（No-show），每間客房將收取 總房晚數的50%作為未入住費用，並立即取消預訂。\r\n</li>\r\n</ul>\r\n節假高峰期（12月24日 - 次年1月5日）：\r\n<ul>\r\n<li>\r\n若於抵達日前 少於30天取消，每間客房將收取相當於 整個預訂期間100%房費的取消費用。\r\n</li>\r\n<li>\r\n若未如期入住（No-show），每間客房將收取 整段住宿期間的全額費用，並立即取消預訂。</li></ul>', '平季（4月1日 - 7月14日、9月16日 - 12月23日、次年1月6日 - 3月31日）：\r\n<ul>\r\n<li>\r\n若在抵达日前 不足7天取消，每间客房将收取相当于 1晚房费的取消费用。\r\n</li>\r\n<li>\r\n若未按时入住（No-show），每间客房将收取 1晚房费作为未入住费用，并立即取消预订。\r\n</li>\r\n</ul>\r\n旺季（7月15日 - 9月15日）：\r\n<ul>\r\n<li>\r\n若在抵达日前 不足14天取消，每间客房将收取相当于 1晚房费的取消费用。\r\n</li>\r\n<li>\r\n若未按时入住（No-show），每间客房将收取 总房晚数的50%作为未入住费用，并立即取消预订。\r\n</li>\r\n</ul>\r\n节假高峰期（12月24日 - 次年1月5日）：\r\n<ul>\r\n<li>\r\n若在抵达日前 不足30天取消，每间客房将收取相当于 全期预订房晚的100%作为取消费用。\r\n</li>\r\n<li>\r\n若未按时入住（No-show），每间客房将收取 整个住宿期间的全额费用，并立即取消预订。</li></ul>', NULL, '2022-10-26 04:23:21', '2026-03-25 19:08:17', 1, 2),
(9, 'The Anvaya Beach Resort Bali', '17', NULL, NULL, NULL, 'mKsQuepwqJPBI0cYqwer2rEnEZ', '17', NULL, 'Jl. Kartika Plaza, Tuban, Kec. Kuta, Kabupaten Badung, Bali 80361', 1, 4, 'Riska Chintya', '03612090477', 'A hidden sanctuary in southern Bali has been reborn as the brand new The ANVAYA Beach Resort. ANVAYA derives from Sanskrit language and means connection. Drawing from this, we focus on building strong connections with our guests by providing not just an experience but also the luxury of providing you with a home away from home.', '位於峇里島南部的一處隱密天堂，現已重生為全新的 The ANVAYA 海灘度假村。<br>\r\n“ANVAYA”一詞源自梵文，意為「連結」。秉持此理念，我們致力於與賓客建立深厚的聯繫，不僅提供難忘的體驗，更為您帶來一種遠離塵囂卻如家般溫暖與奢華的享受。', '位于巴厘岛南部的一处隐秘圣地，焕然新生为全新的 The ANVAYA 海滩度假村。<br>\r\n“ANVAYA”一词源自梵语，意为“连接”。基于这一理念，我们致力于与宾客建立深厚的联系，带给您不仅是一次难忘的体验，更是一种如家般舒适与奢华的享受。', '<ul><li>Free Internet Access </li><li>Free Parking – Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilitie</li></ul>', '<ul><li><li>免費上網</li><li>免費停車（餐廳專用）</li><li>健身中心</li><li>游泳池</li><li>水療中心</li><li>數位房卡</li><li>線上入住</li><li>度假型飯店</li><li>洗衣服務</li><li>禮賓服務</li><li>會議設施</li></li></ul>', '<ul><li><li>免费上网</li><li>免费停车（餐厅专用）</li><li>健身中心</li><li>游泳池</li><li>水疗中心</li><li>数字房卡</li><li>在线入住</li><li>度假型酒店</li><li>洗衣服务</li><li>礼宾服务</li><li>会议设施</li></li></ul>', '<b>Seasonal Policy : </b><ul><li>Minimum 3N stay is required during peak season period 23 Dec - 05 Jan</li><li>No check in and check out on 30 &  31 December </li></ul>', '季節性政策：\r\n<ul>\r\n<li>\r\n高峰期間（12月23日 – 次年1月5日）需至少入住 3 晚。\r\n</li>\r\n<li>\r\n12月30日與31日不提供入住與退房服務。</li></ul>', '季节性政策：\r\n<ul>\r\n<li>\r\n高峰期（12月23日 – 次年1月5日）需至少入住 3 晚。\r\n</li>\r\n<li>\r\n12月30日和31日不办理入住与退房手续。</li></ul>', NULL, NULL, NULL, 'inactive', '1700186832_Anvaya.webp', 14, 'https://www.theanvayabali.com/', '2', '360', NULL, NULL, 'https://g.page/TheANVAYABali?share', NULL, NULL, NULL, NULL, '<p><span style=\"font-size: 14px;\"><b>Normal Season (06 Jan - 31 May\'26, 01 Oct - 22 Dec\'26, 06 Jan - 31 Mar\'27) : </b></span></p><ol><li><span style=\"font-size: 14px;\">\r\nCancellation 14 - 21 days : 1 night charge </span></li><li><span style=\"font-size: 14px;\">\r\nCancellation less than 14 days, no show & early departure & amendments : 100% of Full Stay\r\n</span></li></ol><p><span style=\"font-size: 14px;\"><b>Shoulder / High / Peak Season (01 - 30 Jun\'26, 01 - 30 Sep\'26 / 01 Jul - 31 Aug\'26 / 01 - 05 Jan26, 23 - 31 Dec\'26, 01 - 05 Jan\'27) :\r\n</b></span></p><ol><li><span style=\"font-size: 14px;\">Cancellation 30 - 45 days : 1 night charge </span></li><li><span style=\"font-size: 14px;\">\r\nCancellation less than 30 days, no show & early departure & amendments : 100% of Full Stay</span></li></ol>', '<p data-start=\"178\" data-end=\"354\"><strong data-start=\"178\" data-end=\"199\">平季（Normal Season）</strong><br data-start=\"199\" data-end=\"202\">\r\n（2026年1月6日–5月31日、2026年10月1日–12月22日、2027年1月6日–3月31日）<br data-start=\"253\" data-end=\"256\">\r\n• 於入住前 <strong data-start=\"263\" data-end=\"274\">14–21 天</strong> 取消：收取 <strong data-start=\"281\" data-end=\"290\">1 晚房費</strong><br data-start=\"290\" data-end=\"293\">\r\n• 於入住前 <strong data-start=\"300\" data-end=\"309\">少於14天</strong> 取消、未入住（No Show）、提前退房或修改預訂：收取 <strong data-start=\"339\" data-end=\"354\">全程住宿費用的100%</strong></p>\r\n<p data-start=\"356\" data-end=\"595\"><strong data-start=\"356\" data-end=\"400\">肩季／旺季／高峰季（Shoulder / High / Peak Season）</strong><br data-start=\"400\" data-end=\"403\">\r\n（2026年6月1日–6月30日、2026年9月1日–9月30日／2026年7月1日–8月31日／2026年1月1日–5日、2026年12月23日–31日、2027年1月1日–5日）<br data-start=\"494\" data-end=\"497\">\r\n• 於入住前 <strong data-start=\"504\" data-end=\"515\">30–45 天</strong> 取消：收取 <strong data-start=\"522\" data-end=\"531\">1 晚房費</strong><br data-start=\"531\" data-end=\"534\">\r\n• 於入住前 <strong data-start=\"541\" data-end=\"550\">少於30天</strong> 取消、未入住（No Show）、提前退房或修改預訂：收取 <strong data-start=\"580\" data-end=\"595\">全程住宿費用的100%</strong></p><ul>\r\n</ul>', '<p data-start=\"636\" data-end=\"808\"><strong data-start=\"636\" data-end=\"657\">平季（Normal Season）</strong><br data-start=\"657\" data-end=\"660\">\r\n（2026年1月6日–5月31日、2026年10月1日–12月22日、2027年1月6日–3月31日）<br data-start=\"711\" data-end=\"714\">\r\n• 入住前 <strong data-start=\"720\" data-end=\"730\">14–21天</strong> 取消：收取 <strong data-start=\"737\" data-end=\"745\">1晚房费</strong><br data-start=\"745\" data-end=\"748\">\r\n• 入住前 <strong data-start=\"754\" data-end=\"763\">少于14天</strong> 取消、未入住（No Show）、提前退房或修改预订：收取 <strong data-start=\"793\" data-end=\"808\">全程住宿费用的100%</strong></p>\r\n<p data-start=\"810\" data-end=\"1046\"><strong data-start=\"810\" data-end=\"855\">次旺季／旺季／高峰季（Shoulder / High / Peak Season）</strong><br data-start=\"855\" data-end=\"858\">\r\n（2026年6月1日–6月30日、2026年9月1日–9月30日／2026年7月1日–8月31日／2026年1月1日–5日、2026年12月23日–31日、2027年1月1日–5日）<br data-start=\"949\" data-end=\"952\">\r\n• 入住前 <strong data-start=\"958\" data-end=\"968\">30–45天</strong> 取消：收取 <strong data-start=\"975\" data-end=\"983\">1晚房费</strong><br data-start=\"983\" data-end=\"986\">\r\n• 入住前 <strong data-start=\"992\" data-end=\"1001\">少于30天</strong> 取消、未入住（No Show）、提前退房或修改预订：收取 <strong data-start=\"1031\" data-end=\"1046\">全程住宿费用的100%</strong></p>', NULL, '2022-10-29 02:44:28', '2026-03-24 18:21:00', 1, 1),
(10, 'Ayodya Resort Bali', '17', 'Nusa Dua', 'Bali', 'Indonesia', 'WRWwZ0VlLk9QFJVy1gnxtZ0iU8', '17', 17, 'Nusa Dua, Bali, Indonesia', 1, 13, 'Ade Wahyudiarta', '0361771102', 'Welcome to Ayodya Resort Bali, the best hotel in Nusa Dua Bali, where the allure of the ancient epic of Ramayana and the enchanting water palaces of Bali converge to create an unforgettable retreat in paradise.Inspired by the legendary kingdom of Ayodhya, as depicted in the Ramayana, our resort pays homage to the epic tale through its architectural design and cultural motifs. From the moment you arrive, you’ll be transported back in time, greeted by towering statues of mythical creatures and intricate carvings that tell the story of gods and demons.Wandering through our expansive grounds, you’ll encounter echoes of Bali’s famed water palaces, where tranquil ponds and cascading fountains create a sense of serenity and harmony with nature. Our own interpretation of these majestic structures can be found in the layout of our gardens and the design of our swimming pool, which evokes the feeling of bathing in a royal oasis.Each corner of our resort is imbued with the spirit of the Ramayana, from the grandeur of our lobby, reminiscent of a royal court, to the intimate courtyards and pavilions where guests can relax and unwind. Even our accommodations pay homage to the epic, with names and décor inspired by characters and scenes from the ancient tale.But it’s not just the physical architecture that reflects our inspiration from the Ramayana; it’s also the spirit of hospitality and reverence for tradition that permeates every aspect of our resort. Just as Lord Rama and his allies were welcomed with open arms on their journey, so too do we welcome our guests with warmth and graciousness, ensuring that their stay with us is nothing short of extraordinary.', '<span>歡迎來到 Ayodya Resort Bali —— 峇里島努沙杜瓦最頂級的度假飯店。在這裡，古老史詩《羅摩衍那》的神話魅力，與峇里島迷人的水宮意象交匯融合，為您打造一場難以忘懷的天堂之旅。<br>\r\n本度假村靈感源自《羅摩衍那》中傳奇的阿逾陀王國，透過建築設計與文化元素，向這部史詩致上崇高敬意。從您抵達的那一刻起，彷彿時光倒流，迎接您的是神話生物的宏偉雕像與細膩浮雕，述說著神與魔的傳奇故事。</span>\r\n穿梭於我們遼闊的園區，您將感受到峇里著名水宮的氛圍，靜謐的水池與潺潺流水，營造出與自然和諧共處的寧靜氛圍。我們對這些壯麗水宮的詮釋體現在花園的布局與泳池的設計中，讓人彷彿沐浴在皇族綠洲中。\r\n度假村每一角落皆蘊含《羅摩衍那》的精神：從宏偉如皇家宮廷的大廳，到私密靜謐的庭院與涼亭，讓賓客得以放鬆身心、沉澱心靈。甚至我們的客房命名與裝潢，也取材自史詩中的角色與場景。\r\n然而，真正體現《羅摩衍那》精神的，並非僅是建築本身，更是我們對傳統的尊重與對賓客的熱忱款待。正如羅摩王子與其盟友在旅途中受到熱情迎接，我們亦以誠摯與溫暖歡迎每一位賓客，確保您在此的每一刻都精彩非凡。', '<span>欢迎来到 Ayodya Resort Bali —— 巴厘岛努沙杜瓦最好的度假酒店。在这里，古老的史诗《罗摩衍那》的魅力与巴厘岛迷人的水宫景致交织，为您打造一段难忘的天堂之旅。<br>\r\n度假村的灵感源自史诗《罗摩衍那》中传奇的阿逾陀王国，我们通过建筑设计与文化元素向这部不朽的史诗致敬。从您踏入度假村的那一刻起，便仿佛穿越时空，迎接您的是神话生物的高大雕像与精致的石雕，诉说着神祇与恶魔的故事。</span>\r\n漫步于我们广阔的园区，您将处处感受到巴厘著名水宫的气息，宁静的水池与潺潺的喷泉营造出自然和谐的氛围。我们对水宫的诠释体现在花园布局和泳池设计中，让您仿佛沐浴于皇家绿洲。\r\n度假村的每一个角落都蕴含着《罗摩衍那》的精神：从气势恢宏、宛如皇家宫廷的大堂，到私密宁静的庭院与凉亭，为宾客提供放松与沉淀的空间。就连我们的客房命名与装潢，也取材于史诗中的人物与场景。\r\n然而，不仅仅是建筑反映了《罗摩衍那》的灵感，更重要的是我们对传统的敬意与好客之道贯穿于度假村的每个细节。正如罗摩王子与其盟友在旅途中受到热情接待，我们也以真诚与温暖欢迎每一位宾客，确保您在此度过非凡的旅程。', '<ul><li>Gym</li><li>Ayodya Swing</li><li>Infinity Pool</li><li>Sutowo Mini Golf&nbsp;</li><li>The Kids Water Slides &amp; Splash Pad&nbsp;</li><li>Camp Ananda Kids Club&nbsp;</li><li>Water Sport&nbsp;</li><li>Trampoline&nbsp;</li><li>Balinese Theater&nbsp;</li><li>Tour Desk&nbsp;</li><li>Main Pool</li></ul>', '<ul><li><li>健身房</li><li>Ayodya 鞦韆</li><li>無邊泳池</li><li>Sutowo 迷你高爾夫</li><li>兒童滑水道與戲水噴泉區</li><li>Camp Ananda 兒童俱樂部</li><li>水上活動</li><li>彈跳床</li><li>峇里島劇場</li><li>旅遊諮詢櫃檯</li><li>主泳池</li></li></ul>', '<ul><li><li>健身房</li><li>Ayodya 秋千</li><li>无边泳池</li><li>Sutowo 迷你高尔夫</li><li>儿童滑水道与喷水乐园</li><li>Camp Ananda 儿童俱乐部</li><li>水上运动</li><li>蹦床</li><li>巴厘岛剧场</li><li>旅游咨询台</li><li>主泳池</li></li></ul>', '<b>Seasonal Policy:&nbsp;</b><br><ul><li>A minimum stay of 4 nights is required during the peak season&nbsp;<i>(23 Dec - 03 Jan)</i>&nbsp;with no check out on December 31&nbsp;</li><li>A compulsory New Year’s Eve party will be applied with the rate to be advised on closer date&nbsp;</li></ul>', '季節性政策：\r\n<ul>\r\n<li>\r\n高峰期間（12月23日 – 次年1月3日）需至少入住4晚，12月31日不可辦理退房。\r\n</li>\r\n<li>\r\n跨年夜將舉辦強制性派對，相關費用將於接近日期時另行公告。</li></ul>', '季节性政策：\r\n<ul>\r\n<li>\r\n高峰季期间（12月23日 – 次年1月3日）需至少入住4晚，12月31日不可退房。\r\n</li>\r\n<li>\r\n跨年夜将安排强制性派对，相关费用将于临近日期另行通知。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1731987491_Ayodya Resort.webp', 14, 'https://www.ayodyaresortbali.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Ayodya+Resort+Bali/@-8.8080987,115.2257024,17z/data=!4m20!1m10!3m9!1s0x2dd25cc40c1925fb:0xe5030588f503aab5!2sAyodya+Resort+Bali!5m2!4m1!1i2!8m2!3d-8.808104!4d115.2282773!16s%2Fg%2F1w6ws56z!3m8!1s0x2dd25cc40c1925fb:0xe5030588f503aab5!5m2!4m1!1i2!8m2!3d-8.808104!4d115.2282773!16s%2Fg%2F1w6ws56z?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.8085937, 115.2293710, NULL, NULL, '<span><b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 22 Dec, 04 Jan - 31 Mar):&nbsp;</i></span><ul><li>7 days or more prior to arrival: No cancellation fee&nbsp;</li><li>6 days prior to arrival: One-night cancellation fee</li><li>5-0 days prior to arrival (incl. no show): 100% of the full stay&nbsp;</li><li>Early departure: 100% of the full stay&nbsp;</li><li>No Show: 100% of the full stay&nbsp;</li></ul><span><b>High Season </b><i>(01 Jul - 31 Aug):</i>&nbsp;</span><ul><li>14 days or more prior to arrival: No cancellation fee&nbsp;</li><li>13 days prior to arrival: One-night cancellation fee&nbsp;</li><li>12-0 days prior to arrival (incl. no chow): 100% of the full stay&nbsp;</li><li>Early departure: 100% of the full stay&nbsp;</li><li>No Show: 100% of the full stay&nbsp;</li></ul><span><b>Peak Season</b> <i>(23 Dec - 03 Jan):</i>&nbsp;</span><ul><li>30 days or more prior to arrival: No cancellation&nbsp;</li><li>29 days prior to arrival: One-night cancellation fee&nbsp;</li><li>28 - 0 days prior to arrival (incl. no show): 100% of the full stay&nbsp;</li><li>Early departure: 100% of the full stay&nbsp;&nbsp;</li><li>No Show: 100% of the full stay&nbsp;</li></ul>', '淡季（4月1日 – 6月30日、9月1日 – 12月22日、次年1月4日 – 3月31日）：\r\n<ul>\r\n<li>\r\n抵達前 7天或以上取消：不收取取消費用\r\n</li>\r\n<li>\r\n抵達前 6天取消：收取1晚房費作為取消費用\r\n</li>\r\n<li>\r\n抵達前 5至0天取消（含未入住）：收取全額房費（100%）\r\n</li>\r\n<li>\r\n提前退房：收取全額房費（100%）\r\n</li>\r\n<li>\r\n未入住（No Show）：收取全額房費（100%）\r\n</li>\r\n</ul>\r\n旺季（7月1日 – 8月31日）：\r\n<ul>\r\n<li>\r\n抵達前 14天或以上取消：不收取取消費用\r\n</li>\r\n<li>\r\n抵達前 13天取消：收取1晚房費作為取消費用\r\n</li>\r\n<li>\r\n抵達前 12至0天取消（含未入住）：收取全額房費（100%）\r\n</li>\r\n<li>\r\n提前退房：收取全額房費（100%）\r\n</li>\r\n<li>\r\n未入住（No Show）：收取全額房費（100%）\r\n</li>\r\n</ul>\r\n旺季高峰（12月23日 – 次年1月3日）：\r\n<ul>\r\n<li>\r\n抵達前 30天或以上取消：不收取取消費用\r\n</li>\r\n<li>\r\n抵達前 29天取消：收取1晚房費作為取消費用\r\n</li>\r\n<li>\r\n抵達前 28至0天取消（含未入住）：收取全額房費（100%）\r\n</li>\r\n<li>\r\n提前退房：收取全額房費（100%）\r\n</li>\r\n<li>\r\n未入住（No Show）：收取全額房費（100%）</li></ul>', '淡季（4月1日 – 6月30日、9月1日 – 12月22日、次年1月4日 – 3月31日）：\r\n<ul>\r\n<li>\r\n抵达前 7天或以上取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前 6天取消：收取1晚房费作为取消费用\r\n</li>\r\n<li>\r\n抵达前 5至0天取消（含未入住）：收取全额房费（100%）\r\n</li>\r\n<li>\r\n提前退房：收取全额房费（100%）\r\n</li>\r\n<li>\r\n未入住（No Show）：收取全额房费（100%）\r\n</li>\r\n</ul>\r\n旺季（7月1日 – 8月31日）：\r\n<ul>\r\n<li>\r\n抵达前 14天或以上取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前 13天取消：收取1晚房费作为取消费用\r\n</li>\r\n<li>\r\n抵达前 12至0天取消（含未入住）：收取全额房费（100%）\r\n</li>\r\n<li>\r\n提前退房：收取全额房费（100%）\r\n</li>\r\n<li>\r\n未入住（No Show）：收取全额房费（100%）\r\n</li>\r\n</ul>\r\n高峰季（12月23日 – 次年1月3日）：\r\n<ul>\r\n<li>\r\n抵达前 30天或以上取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前 29天取消：收取1晚房费作为取消费用\r\n</li>\r\n<li>\r\n抵达前 28至0天取消（含未入住）：收取全额房费（100%）\r\n</li>\r\n<li>\r\n提前退房：收取全额房费（100%）\r\n</li>\r\n<li>\r\n未入住（No Show）：收取全额房费（100%）</li></ul>', NULL, '2022-10-29 03:53:03', '2026-03-25 19:21:07', 1, 2),
(11, 'Umana Bali, LXR Hotels & Resorts', '17', NULL, NULL, NULL, 'pfzsdDaw4ycZ1aLm4tlQE7JU1O', '17', NULL, 'Jl. Melasti, Ungasan, Kec. Kuta Sel., Kabupaten Badung, Bali 80364', 1, 21, 'Nita Rizky', '03613007000', 'Escape to our clifftop resort with direct access to Melasti Beach. Every villa has a private infinity pool and whirlpool with ocean or garden views. Find a living and dining area inside, and another outside. Rinse off in the indoor or outdoor rain shower. Spend a day on the green at Bali National Golf Club and New Kuta Golf. Shop at Bali Collection, or immerse yourself in culture at Uluwatu Temple.', '入住我們懸崖頂的度假村，直通梅拉斯蒂海灘。每棟別墅均配備私人無邊泳池和漩渦浴池，可欣賞海景或花園景緻。別墅內外均設有起居和用餐區。您可在室內或室外雨淋花灑下沐浴煥新。前往峇里國家高爾夫俱樂部或新庫塔高爾夫度過悠閒的一天。也可前往峇里購物中心購物，或在烏魯瓦圖寺沉浸於文化之中。', '入住我们悬崖顶的度假村，直通梅拉斯蒂海滩。每栋别墅均配备私人无边泳池和漩涡浴池，可欣赏海景或花园景致。别墅内外均设有起居和用餐区。您可在室内或室外雨淋花洒下沐浴焕新。前往巴厘国家高尔夫俱乐部或新库塔高尔夫度过悠闲的一天。也可前往巴厘购物中心购物，或在乌鲁瓦图寺沉浸于文化之中。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1756457632_Resort_Aerial_Night1.webp', 14, 'https://www.hilton.com/en/hotels/dpsolol-umana-bali-resort/?SEO_id=GMB-APAC-OL-DPSOLOL', '2', '45', NULL, NULL, 'https://goo.gl/maps/J1ui5kF9oMnPeU6i9', NULL, NULL, NULL, NULL, '<b>Low Season (01 Sep - 21 Dec, 05 Jan - 30 Jun):</b><br><ul><li>14 days: 1 night charge&nbsp;</li><li>7 days / no show / shorten stay: 100% full night charge&nbsp;</li></ul><b>High Season (21 Dec - 04 Jan):&nbsp;</b><br><ul><li>30 days: 1 night charge&nbsp;</li><li>21 days / no show / shorten stay: 100% full night charge&nbsp;</li></ul>', '淡季（9月1日 - 12月21日，1月5日 - 6月30日）：\r\n<ul>\r\n<li>\r\n14天前取消：收取1晚房費\r\n</li>\r\n<li>\r\n7天內 / 未到店 / 縮短入住：收取全額房費\r\n</li>\r\n</ul>\r\n旺季（12月21日 - 1月4日）：\r\n<ul>\r\n<li>\r\n30天前取消：收取1晚房費\r\n</li>\r\n<li>\r\n21天內 / 未到店 / 縮短入住：收取全額房費</li></ul>', '淡季（9月1日 - 12月21日，1月5日 - 6月30日）：\r\n<ul>\r\n<li>\r\n14天前取消：收取1晚房费\r\n</li>\r\n<li>\r\n7天内 / 未到店 / 缩短入住：收取全额房费\r\n</li>\r\n</ul>\r\n旺季（12月21日 - 1月4日）：\r\n<ul>\r\n<li>\r\n30天前取消：收取1晚房费\r\n</li>\r\n<li>\r\n21天内 / 未到店 / 缩短入住：收取全额房费</li></ul>', NULL, '2022-11-01 12:11:37', '2026-03-24 18:21:00', 1, 1),
(12, 'Maca Villas & Spa Bali', '17', NULL, NULL, NULL, '09mEA3seXZJ5HhAcPGZ2lB3k5g', '17', NULL, 'Jl. Lb. Sari Jl. Petitenget No.7, Seminyak, Kec. Kuta Utara, Kabupaten Badung, Bali 80361', 1, 13, 'Putu Sariasih', '0361739090', 'Where luxury meets privacy in your own villa for two. Located in Seminyak, it\'s perfect for island life. Start with a personalized breakfast, relax by your private pool, and enjoy a rejuvenating spa at SOHAM Wellness. End the day with cocktails and an unforgettable dinner.', '在專屬於兩人的私人別墅中，奢華與隱私完美交匯。<br>\r\n別墅位於水明漾，適合享受悠閒的海島生活。<br>\r\n以量身打造的早餐展開一天，在您的專屬泳池旁放鬆，並於 SOHAM Wellness 體驗身心療癒的水療服務。<br>\r\n夜晚，品一杯雞尾酒，享用一頓難忘的晚餐，為一天畫下完美句點。', '<span>在属于您两人的私人别墅中，奢华与私密完美融合。<br>\r\n别墅坐落于水明漾，尽享惬意海岛生活。<br>\r\n以个性化早餐开启美好一天，在专属泳池边放松身心，随后前往 SOHAM Wellness 享受焕活身心的水疗护理。<br>\r\n夜晚则以精致鸡尾酒和难忘晚餐圆满落幕。</span>', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>A minimum of a 3-night stay is required during the high season period&nbsp;(16 Jul - 15 Sep, 22 Dec - 04 Jan, 13 - 20 Feb), and a minimum of a 4-night stay is required for bookings during the New Year period for arrivals between December 28 and January 2</li><li>A compulsory New Year’s Eve Dinner will be held on December 31 Price at Additional Charge&nbsp;</li></ul><b>Honeymoon Benefit:&nbsp;</b><br><ul><li>Flower decorated room upon arrival&nbsp;</li><li>Flower bath upon arrival&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n在旺季期間（7 月 16 日至 9 月 15 日、12 月 22 日至 1 月 4 日、2 月 13 日至 2 月 20 日）需至少入住 3 晚；而跨年期間（12 月 28 日至 1 月 2 日）則需至少入住 4 晚。</li><li>\r\n12 月 31 日將舉辦跨年晚宴，需額外收費。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時提供花卉佈置的房間</li><li>\r\n抵達時提供花瓣浴</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n在旺季期间（7 月 16 日至 9 月 15 日、12 月 22 日至 1 月 4 日、2 月 13 日至 2 月 20 日）需至少入住 3 晚；而跨年期间（12 月 28 日至 1 月 2 日）需至少入住 4 晚。</li><li>\r\n12 月 31 日将举办跨年晚宴，需额外收费。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时提供鲜花装饰的房间</li><li>\r\n抵达时提供花瓣浴</li></ul>', NULL, NULL, NULL, 'Active', '1759194862_maca-villas-spa.jpg', 2, 'http://www.macavillas.com/', '2', '45', NULL, NULL, 'https://g.page/alilaseminyak?share', NULL, NULL, NULL, NULL, '<b>Low Season </b><i>(01 Apr - 15 Jul, 16 Sep - 21 Dec, 05 Jan - 12 Feb, 21 Feb - 31 Mar):</i><br><ul><li>In the event of cancellation within 8 - 14 (eight to fourteen) days prior to arrival \r\ndate, the reservation will be subject to a cancellation fee equivalent to the \r\nvalue of 1 (one) night accommodation. </li></ul><ul><li>In the event of cancellation within 2 - 7 (two to seven) days prior to arrival date, \r\nthe reservation will be subject to a cancellation fee equivalent to the value of \r\n50% from the total room night reserved. </li></ul><ul><li>In the event of cancellation within 1 (one) day prior to arrival date, No show as \r\nwell as Early departure will be subject to full room night reserved.&nbsp;</li></ul><b>High Season </b><i>(16 Jul - 15 Sep, 22 Dec - 04 Jan, 13 - 20 Feb):&nbsp;</i><br><ul><li>In the event of cancellation within 15-30 (fifteen to thirty) days prior to arrival \r\ndate, the reservation will be subject to a cancellation fee equivalent to the \r\nvalue of 1 (one) night accommodation. </li></ul><ul><li>In the event of cancellation within 2-14 (two to fourteen) days prior to arrival \r\ndate, the reservation will be subject to a cancellation fee equivalent to the \r\nvalue of 50% from the total room night reserved. </li></ul><ul><li>In the event of cancellation within 1 (one) day prior to arrival date, No show as \r\nwell as Early Departure will be subject to full room night reserved&nbsp;</li></ul>', '淡季（4月1日 – 7月15日、9月16日 – 12月21日、1月5日 – 2月12日、2月21日 – 3月31日）：\r\n<ul>\r\n<li>\r\n若於抵達前8至14天內取消預訂，將收取1晚房費作為取消費用。\r\n</li>\r\n<li>\r\n若於抵達前2至7天內取消預訂，將收取**總預訂房晚費用的50%**作為取消費用。\r\n</li>\r\n<li>\r\n若於抵達前1天內取消，或未入住（No Show）、提前退房，將收取全部預訂房晚費用（100%）。\r\n</li>\r\n</ul>\r\n旺季（7月16日 – 9月15日、12月22日 – 次年1月4日、2月13日 – 2月20日）：\r\n<ul>\r\n<li>\r\n若於抵達前15至30天內取消預訂，將收取1晚房費作為取消費用。\r\n</li>\r\n<li>\r\n若於抵達前2至14天內取消預訂，將收取**總預訂房晚費用的50%**作為取消費用。\r\n</li>\r\n<li>\r\n若於抵達前1天內取消，或未入住（No Show）、提前退房，將收取全部預訂房晚費用（100%）。</li></ul>', '淡季（4月1日 – 7月15日、9月16日 – 12月21日、1月5日 – 2月12日、2月21日 – 3月31日）：\r\n<ul>\r\n<li>\r\n若在抵达前8至14天内取消，将收取1晚房费作为取消费用。\r\n</li>\r\n<li>\r\n若在抵达前2至7天内取消，将收取**总预订房晚费用的50%**作为取消费用。\r\n</li>\r\n<li>\r\n若在抵达前1天内取消，或未入住（No Show）、提前退房，将收取全部预订房晚费用（100%）。\r\n</li>\r\n</ul>\r\n旺季（7月16日 – 9月15日、12月22日 – 次年1月4日、2月13日 – 2月20日）：\r\n<ul>\r\n<li>\r\n若在抵达前15至30天内取消，将收取1晚房费作为取消费用。\r\n</li>\r\n<li>\r\n若在抵达前2至14天内取消，将收取**总预订房晚费用的50%**作为取消费用。\r\n</li>\r\n<li>\r\n若在抵达前1天内取消，或未入住（No Show）、提前退房，将收取全部预订房晚费用（100%）。</li></ul>', NULL, '2022-11-01 12:37:24', '2025-09-29 17:14:22', 2, 1),
(13, 'The Samaya Ubud', '17', NULL, NULL, NULL, 'Jvjb4FyAZRWu8kyGx2kM1MssnS', '17', NULL, 'Jl. Baung, Sayan, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 37, 'Ayu Suliani', '0361973606', 'Hidden in the hills of Sayan village of Ubud, the cultural center of Bali, The Samaya Ubud is the ideal sanctuary for those who seek for the balance of mind, body, and soul. One cannot help but feel at peace within the comfort of modern luxury while still enjoying the classic Balinese touches at every corner.', '隱藏在峇里島文化重鎮烏布的 Sayan 山丘中，The Samaya Ubud 是尋求身心靈平衡旅人的理想靜謐之所。置身於現代奢華的舒適之中，同時感受每一處經典峇里島風情，令人不禁感到平靜與安心。', '隐匿于乌布文化中心——Sayan 村的群山之间，The Samaya Ubud 是理想的静修圣地，适合追求身心灵平衡的旅人。在现代奢华的舒适中，处处融合经典巴厘岛元素，让人不禁心生宁静与安逸。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1743665342_lobby-4-1545102265.jpg', 14, 'https://thesamayabali.com/ubud/', '2', '45', NULL, NULL, 'https://goo.gl/maps/6jm1sGMDtBvEi8Jt7', NULL, NULL, NULL, NULL, '<b>Low Season:</b> <br><ul><li>In the event of cancellation within 7 (seven) days to 3 (three) days prior to \r\narrival date, the reservation will be subject to a cancellation fee equivalent to \r\nthe value of 1 (one) night accommodation</li><li>Cancellation within 2 (two) days prior to arrival to the date of arrival, no Show \r\nas well as Early Departure, the reservation will be subject to a cancellation fee \r\nequivalent to the value of full room night charge</li></ul><b>High Season:</b> <br><ul><li>In the event of cancellation within 21 (twenty one) days prior to arrival date, \r\nthe reservation will be subject to a cancellation fee equivalent to the value of \r\n1 (one) night accommodation.</li><li>In the event of cancellation within 14 (fourteen) days  to 3 (three) days prior to \r\narrival date, the reservation will be subject to a cancellation fee equivalent to \r\nthe value of 50% from the total room night charge.</li><li>Cancellation within 2 (two) days prior to arrival to the date of arrival, no show \r\nas well as Early departure will be subject to full room night charge.</li></ul>', '淡季：\r\n<ul>\r\n<li>\r\n若於抵達日前 7 天至 3 天內取消預訂，將收取 相當於 1 晚房費 的取消費用。\r\n</li>\r\n<li>\r\n若於抵達日前 2 天內取消、當日未入住（No Show）或提前退房，將收取 全額房晚費用 作為取消費。\r\n</li>\r\n</ul>\r\n旺季：\r\n<ul>\r\n<li>\r\n若於抵達日前 21 天內取消預訂，將收取 相當於 1 晚房費 的取消費用。\r\n</li>\r\n<li>\r\n若於抵達日前 14 天至 3 天內取消預訂，將收取 總房晚費用的 50% 作為取消費。\r\n</li>\r\n<li>\r\n若於抵達日前 2 天內取消、當日未入住（No Show）或提前退房，將收取 全額房晚費用 作為取消費。</li></ul>', '淡季：\r\n<ul>\r\n<li>\r\n如在抵达日前 7 天至 3 天内取消预订，将收取 相当于 1 晚房费的取消费用。\r\n</li>\r\n<li>\r\n如在抵达日前 2 天内取消、当天未入住（No Show）或提前退房，将收取 全额房晚费用 作为取消费用。\r\n</li>\r\n</ul>\r\n旺季：\r\n<ul>\r\n<li>\r\n如在抵达日前 21 天内取消预订，将收取 相当于 1 晚房费的取消费用。\r\n</li>\r\n<li>\r\n如在抵达日前 14 天至 3 天内取消预订，将收取 相当于总房晚费用的 50% 作为取消费用。\r\n</li>\r\n<li>\r\n如在抵达日前 2 天内取消、当天未入住（No Show）或提前退房，将收取 全额房晚费用 作为取消费用。</li></ul>', NULL, '2022-11-01 12:45:11', '2025-06-24 18:40:17', 1, 1),
(14, 'Grand Kuta Hotel & Residence', '17', NULL, NULL, NULL, 'VhoI6MtSuxBCMKWCVqnLQj0CAA', '17', NULL, 'Jl. Dewi Sri No.8, Legian, Kec. Kuta, Bali, 80361', 1, 8, 'I Nyoman Candra', '03613000888', 'Grand Kuta Hotel and Residence is a modern and trendy condotel conceptualized for vacationing couples and families looking for good value with best rates, ideal for either short holiday breaks or long stay assignments. The charming property offers a calm inner courtyard sanctuary with three (3) swimming pools, meeting rooms, free Wi-Fi, free parking space. Offer you 77 well appointed studios in one, two and three bedroom configurations offer pantry, a living room and private balconies complimented by amenities and services befitting an international full service hotel. Our enjoyable coffee shop offers an interesting array of local and imported delicacies where you can relax and take pleasure in the innovative cuisine and calm atmosphere.', 'Grand Kuta Hotel and Residence 是一間現代時尚的公寓式飯店，專為尋求高性價比的度假情侶與家庭所設計，無論是短期假期或長期住宿任務都非常適合。這間迷人的飯店擁有寧靜的內部庭院、三座游泳池、會議室、免費無線上網和免費停車空間。\r\n我們提供77間設計完善的套房，有一房、兩房及三房格局可供選擇，配有簡易廚房、客廳及私人陽台，並提供媲美國際全方位服務飯店的設施與服務。\r\n我們令人愉悅的咖啡廳提供各式本地與進口美食，讓您在悠閒的氛圍中享受創意料理與放鬆時光。', 'Grand Kuta Hotel and Residence 是一家现代时尚的公寓式酒店，为寻求高性价比的度假情侣和家庭打造，无论是短期假期还是长期住宿都非常理想。这家迷人的酒店提供宁静的内院环境、三座游泳池、会议室、免费无线网络和免费停车位。\r\n我们提供77间设施齐全的套房，设有一居室、两居室和三居室配置，配备小厨房、客厅和私人阳台，并提供符合国际全方位服务酒店标准的设施与服务。\r\n我们舒适的咖啡厅供应多样的本地及进口美食，让您在宁静的氛围中尽情享受创意料理和惬意时光。', '<ul><li>3 outdoor Swimming Pools</li><li>Pool Bar&nbsp;</li><li>Spacious lobby&nbsp;</li><li>24 Hour Room Service&nbsp;</li><li>Lobby Lounge&nbsp;</li><li>Laundry &amp; Dry Cleaning&nbsp;</li><li>Airport transfer service (On Request)&nbsp;</li><li>Concierge Services&nbsp;</li><li>WI-FI Internet Access&nbsp;</li><li>24 Hour Doctor Service (On Call)&nbsp;</li><li>Car rental service&nbsp;</li><li>Mail &amp; Postage Service&nbsp;</li><li>24 Hour Covered Car Park&nbsp;</li><li>Meeting Room</li></ul>', '<ul><li>3座戶外游泳池</li><li>\r\n池畔酒吧</li><li>\r\n寬敞大廳</li><li>\r\n24小時客房服務</li><li>\r\n大廳酒廊</li><li>\r\n洗衣與乾洗服務</li><li>\r\n機場接送服務（需預約）</li><li>\r\n禮賓服務</li><li>\r\n無線網路連線</li><li>\r\n24小時醫生服務（隨叫隨到）</li><li>\r\n汽車租賃服務</li><li>\r\n郵寄與收信服務</li><li>\r\n24小時室內停車場</li><li>\r\n會議室</li></ul>', '<ul><li>3座户外游泳池</li><li>\r\n池畔酒吧</li><li>\r\n宽敞大堂</li><li>\r\n24小时客房服务</li><li>\r\n大堂酒廊</li><li>\r\n洗衣和干洗服务</li><li>\r\n机场接送服务（需预约）</li><li>\r\n礼宾服务</li><li>\r\n无线网络连接</li><li>\r\n24小时医生服务（随叫随到）</li><li>\r\n汽车租赁服务</li><li>\r\n邮寄与收信服务</li><li>\r\n24小时室内停车场</li><li>\r\n会议室</li></ul>', 'Child Policy:&nbsp;Children under 5 years old will get free of charge breakfast, sharing the existing bedding with parent and above 12 years old at full charge required extra bed', '兒童政策：5歲以下兒童與父母共用現有床鋪可免費享用早餐；12歲以上兒童需加床並全額收費。', '儿童政策：5岁以下儿童与父母共用现有床铺可免费享用早餐；12岁以上儿童需加床并全额收费。', NULL, NULL, NULL, 'active', '1732067854_Cover.jpg', 2, 'https://www.grandkuta.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/FevPiwpDbzGF5qNT9', NULL, NULL, NULL, NULL, '<ul><li>Any cancellation made within 07 days in Low Season and 14 days in High/Peak Season (12 - 20 Feb 2026, 23 Dec 2025 - 05 Jan 2026)&nbsp;prior to guest arrival, will result in the forfeiting 1 (one) night accommodation cancellation penalty.&nbsp;</li><li>Any cancellation made within 03 days prior to arrival, or in case of no show, a full night booking charge will be applied&nbsp;</li></ul>', '<ul><li>如於淡季入住前7天內或旺季／巔峰季（2026年2月12日至20日，2025年12月23日至2026年1月5日）入住前14天內取消預訂，將收取1晚房費作為取消罰金。</li><li>如於入住前3天內取消預訂，或未出現（No Show），將收取全額住宿費用。</li></ul>', '<ul><li>如在淡季入住前7天内或旺季／高峰季（2026年2月12日至20日，2025年12月23日至2026年1月5日）入住前14天内取消预订，将收取1晚房费作为取消罚金。</li><li>如在入住前3天内取消预订，或未出现（No Show），将收取全额住宿费用。</li></ul>', NULL, '2022-11-01 12:55:09', '2026-03-24 18:26:55', 2, 1),
(15, 'Ametis Villa Canggu', '17', 'Canggu', 'Bali', 'Indonesia', 'OblGAYHFnhfLUgz41W2DrLQy8O', '17', 17, 'Canggu, Bali, Indonesia', 2, 21, 'Akiko Yoshioka', '03618445557', '<p>While the passage of time has wrought certain changes, the true essence of Bali remains the same and Ametis Villa is the place for you experience the very soul of this heavenly island.</p><p>Located in Canggu, Ametis Villa is about 35 minutes from Kuta. This area maintains its cultural roots and is dotted with productive rice terraces that extend to a rugged stretch of coastline. Canggu is popular within surfing and expatriate circles, sought out for its laidback lifestyle qualities away from the crowds and concrete jungle of Seminyak.</p><p>Ametis Villa is a luxury lifestyle villa with a home-style concept that will make you feel like you truly belong. During your stay, you will be assigned a personal butler, who excels in the singular ability to anticipate your every need, and to exceed your every expectation.</p><p>Conceived, built and managed with integrity, Ametis Villa is respectful of Bali\'s unique cultural heritage, seeks to interact with the local community and shows sensitivity towards the immediate environment</p>', NULL, NULL, '<p>- Cruising/Sailing/Scuba Diving/Snorkelling<br>- Surfing<br>- White Water Rafting<br>- Golf and Tennis<br>- Fishing<br>- Horse Riding<br>- Elephant Safari Park<br>- Water Sports<br>- Surfing and Body Boarding<br>- Waterbom Park<br>- Bali Bird Park Safari<br>- Bali Safari &amp; Marine Park<br>- RUBY SPA<br>- Private Villa</p>', NULL, NULL, '<p><strong>Standard benefit :</strong></p><p>Daily breakfast, Personal butler service, personalized villa check in&amp;out, 30Mins relaxing massage, daily sunset cocktail and canapes 18.00-20.00, daily afternoon tea 15.00-18.00, daily restocked minibar (soft drink, beer), daily restocked coffee, ea and homemade snack in villa, daily replenished fresh fruit in villa</p><p>Add value for stay in Imperial Villa : upgrade 1x30mins into 60mins body massage at Ruby Spa, daily laundry up to 8 pieces/day/villa</p><p><strong>Children policy :</strong></p><p>·&nbsp;&nbsp;&nbsp;&nbsp; Accommodation at Ametis Villa is available only for guest aged 12 years and above</p><p>·&nbsp;&nbsp;&nbsp;&nbsp; Children aged between 12 years and 16 years old have alternative to stay with their parents in the same villa on existing sofa bed in Imperial Villa and Grand Villa</p><p>·&nbsp;&nbsp;&nbsp;&nbsp; Eternal home-style dining and Ametis Lounge is available for children under 12 years old who should be accompanied by parents or guardian.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp; In case Ametis Villa receives guest check-in with children under 12 years old without any advance notice, Ametis Villa has full authority to relocate guest to another hotel.</p><p><strong>Honeymoon benefit :</strong></p><p>• Honeymoon flower and cake upon arrival</p><p>• Departure gift</p><p><strong>Seasonal policy :</strong></p><p>No Check-in nor Check-out is allowed on 31st December 2022</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1700187515_Ametis.webp', 2, 'https://www.ametisvilla.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Ametis+Villa/@-8.6569645,115.1289464,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd2387c49d72c23:0x963f451148ce5cbb!5m2!4m1!1i2!8m2!3d-8.6569698!4d115.1315213!16s%2Fg%2F11xxm9hzj?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.6567942, 115.1314128, NULL, NULL, '<p><strong>Regular Season:</strong></p><p>• 14 days before arrival: one night cancellation fee per villa</p><p>• 7 days before arrival: full night’s cancellation fee per villa</p><p>• No shows and early departures will be charged in full for the total number of nights per room reserved</p><p><strong>High Season:</strong></p><p>• 21 days before arrival: one night cancellation fee per villa</p><p>• 14 days before arrival: full night’s cancellation fee per villa</p><p>• No shows and early departures will be charged in full for the total number of nights per room reserved</p><p><strong>Peak Season:</strong></p><p>• 30 days before arrival: one night cancellation fee per villa</p><p>• 21 days before arrival: full night’s cancellation fee per villa</p><p>• No shows and early departures will be charged in full for the total number of nights per room reserved</p>', NULL, NULL, NULL, '2022-11-01 13:10:22', '2026-03-25 19:09:22', 2, 2),
(16, 'Peppers Seminyak', '17', NULL, NULL, NULL, 'PERXJY3kqZptq5hrmGJK0FuNvL', '17', NULL, 'Jl. Pura Telaga Waja Jl. Petitenget, Seminyak, Kec. Kuta Utara, Kabupaten Badung, Bali', 1, 13, 'Sapta Dewi Ari', '0361730333', '<div>Enjoy the amenities of a classy beach resort and the privacy of a luxury villa at Peppers Seminyak, Bali. Amidst tropical greenery and tranquil pools, discover a choice of one- to five-bedroom villas, each with its own private pool and lush garden area, making it ideal for everyone from honeymooners to families. This trendy hotel in Seminyak Bali is tranquil, close to white-sand beaches and fine shopping and dining.</div><div><br></div><div>Unwind at our tranquil Seminyak resort spa. Pamper yourself with a full-day package, or choose from treatments ranging from massages, body scrubs and facials. You can also book personalized wellness activities, from yoga to personal training. Dine at The Laneway Restaurant in an elegant and relaxed setting. Overlooking the stone-lined pool, this relaxed restaurant combines traditional and modern cuisine, including Balinese and Italian, with fresh ingredients.</div>', '在峇里島 Peppers Seminyak，盡情享受高級海灘渡假村的設施與奢華別墅的隱私空間。置身於熱帶綠意與寧靜泳池之間，可選擇一至五臥室的別墅，每間皆配有私人泳池與綠意盎然的花園空間，無論是蜜月夫妻還是家庭旅客，皆是理想選擇。這間時尚的水明漾飯店環境靜謐，鄰近白沙海灘，並可輕鬆前往購物與高級餐飲地點。\r\n<span>在我們靜謐的水明漾渡假村 SPA 中放鬆身心。您可享受全天的呵護療程，或從按摩、身體去角質、臉部護理等多種療程中選擇。亦可預訂量身打造的健康活動，如瑜伽或私人健身訓練。<br>\r\n於 The Laneway 餐廳享用美食，優雅放鬆的氛圍環繞四周。餐廳俯瞰石砌泳池，將傳統與現代料理完美融合，提供包括峇里島與義大利料理在內的新鮮食材佳餚。</span>', '在巴厘岛 Peppers Seminyak，尽情享受高级海滩度假村的设施与豪华别墅的私密空间。置身于热带绿意与宁静泳池之间，可选择一至五卧室的别墅，每间都配有私人泳池和郁郁葱葱的花园区域，无论是蜜月旅行还是家庭出游，都是理想之选。这家时尚的水明漾酒店环境宁静，靠近白沙海滩，并邻近购物与精致餐饮场所。\r\n<span>在我们宁静的水明漾度假村水疗中心放松身心。您可以享受全天呵护的护理套餐，或从按摩、身体去角质、面部护理等疗程中选择。还可以预约个性化健康活动，如瑜伽或私人健身训练。<br>\r\n在 The Laneway 餐厅用餐，享受优雅而轻松的用餐氛围。餐厅俯瞰石质泳池，将传统与现代料理完美结合，包括巴厘岛和意大利美食，精选新鲜食材制作。</span>', '<ul><li>Swimming pool</li><li>Restaurant</li><li>Air conditioner</li><li>Bar</li><li>Room service</li><li>Shuttle</li><li>Wi-Fi</li><li>Meeting room</li></ul>', '<ul><li>游泳池</li><li>\r\n餐廳</li><li>\r\n空調</li><li>\r\n酒吧</li><li>\r\n客房服務</li><li>\r\n接駁服務</li><li>\r\n無線網路</li><li>\r\n會議室</li></ul>', '<ul><li>游泳池</li><li>\r\n餐厅</li><li>\r\n空调</li><li>\r\n酒吧</li><li>\r\n客房服务</li><li>\r\n接驳服务</li><li>\r\n无线网络</li><li>\r\n会议室</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1743652551_cover.jpg', 14, 'https://all.accor.com/lien_externe.svlt?goto=fiche_hotel&code_hotel=B3U5&merchantid=seo-maps-ID-B3U5&sourceid=aw-cen&utm_medium=seo%20maps&utm_source=google%20Maps&utm_campaign=seo%20maps', '2', '45', NULL, NULL, 'https://g.page/andazbali?share', NULL, NULL, NULL, NULL, '<b>Low Seasons:</b><br><ul><li>1 (one) night cancellation fee is chargeable for cancellation made 14 days or more prior to arrival.</li></ul><ul><li>50% of entire stay cancellation fee chargeable for cancellation made 7 to 3 days prior to arrival.&nbsp;</li></ul><ul><li>100% of entire stay cancellation fee chargeable for cancellation made 2 days or less prior to arrival for “No Shows” and “early departure”&nbsp;</li></ul><b>High Seasons</b> <i>(01 June - 30 September 2025):</i><br><ul><li>1 (one) night cancellation fee is chargeable for cancellation made 30 days prior to arrival.</li></ul><ul><li>50% of entire stay cancellation fee chargeable for cancellation made between 21 to 15 days prior to arrival. </li></ul><ul><li>100% of entire stay cancellation fee chargeable for cancellation made within 14 days or less prior to arrival for “No Shows” and “early departure.\r\n</li></ul><div><b>Peak Seasons</b> <i>(22 Dec 2025 - 06 Jan 2026):</i></div><ul><li>50% of entire stay cancellation fee chargeable for cancellation made 45 days prior to arrival. </li></ul><ul><li>100% of entire stay cancellation fee chargeable for cancellation made 30 days or less prior to arrival for “No Shows” and “early departure</li></ul><b>NO SHOW POLICY</b> <br>In case of a no show where the guest does not arrive, the hotel will apply a charge equivalent to 100% of the entire stay.', '淡季：\r\n<ul>\r\n<li>\r\n若於入住日前14天或更早取消預訂，將收取1晚取消費用。\r\n</li>\r\n<li>\r\n若於入住日前7至3天內取消預訂，將收取50%總住宿費作為取消費用。\r\n</li>\r\n<li>\r\n若於入住日前2天內取消預訂，或未出現（No Show）或提前退房，將收取100%總住宿費作為取消費用。\r\n</li>\r\n</ul>\r\n旺季（2025年6月1日至9月30日）：\r\n<ul>\r\n<li>\r\n若於入住日前30天內取消預訂，將收取1晚取消費用。\r\n</li>\r\n<li>\r\n若於入住日前21至15天內取消預訂，將收取50%總住宿費作為取消費用。\r\n</li>\r\n<li>\r\n若於入住日前14天內取消預訂，或未出現或提前退房，將收取100%總住宿費作為取消費用。\r\n</li>\r\n</ul>\r\n巔峰季節（2025年12月22日至2026年1月6日）：\r\n<ul>\r\n<li>\r\n若於入住日前45天內取消預訂，將收取50%總住宿費作為取消費用。\r\n</li>\r\n<li>\r\n若於入住日前30天內取消預訂，或未出現或提前退房，將收取100%總住宿費作為取消費用。\r\n</li>\r\n</ul>\r\n<span>未出現政策（No Show Policy）：<br>\r\n如旅客未到達酒店，將收取整段住宿期間的100%費用。</span>', '淡季：\r\n<ul>\r\n<li>\r\n若在入住日前14天或更早取消预订，将收取1晚取消费用。\r\n</li>\r\n<li>\r\n若在入住日前7至3天内取消预订，将收取50%的总住宿费用作为取消费用。\r\n</li>\r\n<li>\r\n若在入住日前2天内取消预订，或未出现（No Show）或提前退房，将收取100%的总住宿费用作为取消费用。\r\n</li>\r\n</ul>\r\n旺季（2025年6月1日至9月30日）：\r\n<ul>\r\n<li>\r\n若在入住日前30天内取消预订，将收取1晚取消费用。\r\n</li>\r\n<li>\r\n若在入住日前21至15天内取消预订，将收取50%的总住宿费用作为取消费用。\r\n</li>\r\n<li>\r\n若在入住日前14天内取消预订，或未出现或提前退房，将收取100%的总住宿费用作为取消费用。\r\n</li>\r\n</ul>\r\n高峰季节（2025年12月22日至2026年1月6日）：\r\n<ul>\r\n<li>\r\n若在入住日前45天内取消预订，将收取50%的总住宿费用作为取消费用。\r\n</li>\r\n<li>\r\n若在入住日前30天内取消预订，或未出现或提前退房，将收取100%的总住宿费用作为取消费用。\r\n</li>\r\n</ul>\r\n<span>未出现政策（No Show Policy）：<br>\r\n如客人未到达酒店，将收取整段住宿期间的100%费用。</span>', NULL, '2022-11-01 13:21:22', '2025-06-24 19:35:49', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(17, 'Maca Villas & Residence Umalas', '17', NULL, NULL, NULL, 'KICqjCZMn5sW6gCi8BrRtfhBJn', '17', NULL, 'Jalan Umalas Klecung Gang Panilla, Kerobokan Kelod, Kuta Utara, Badung Regency, Bali 80361', 1, 45, 'Putu Sariasih', '03614741445', 'Enjoy the serenity of Bali’s Umalas region from the tranquil Maca Villas &amp; Residence Umalas, ideally located between the lively Canggu and trendy Seminyak. Surrounded by lush tropical gardens, our private pool villas seamlessly combine traditional Balinese elements with modern elegance. Choose from 13 one- and two-bedroom villas or 5 spacious estates with two- or three-bedrooms, perfect for couples or families seeking luxury. Each villa features a fully-equipped kitchenette, expansive living areas, and private garages. Indulge in the on-site Mase Uma Kitchen &amp; Bar, rejuvenate with in-villa spa services, or unwind by the communal pool. At Maca Villas &amp; Residence Umalas, every moment is a peaceful escape, offering the ultimate in comfort and relaxation.', '在寧靜的 Maca Villas &amp; Residence Umalas，感受峇里島 Umalas 地區的靜謐氛圍。地理位置絕佳，位於熱鬧的 Canggu 和時尚的 Seminyak 之間。私密泳池別墅被茂密的熱帶花園環繞，巧妙融合傳統峇里島元素與現代優雅設計。\r\n您可選擇13間一臥或兩臥室的別墅，或5間寬敞的雙臥至三臥室豪華宅邸，非常適合情侶或家庭尋求奢華體驗。每棟別墅皆配備完善的簡易廚房、寬敞的起居空間與私人車庫。\r\n<span>在館內的 Mase Uma Kitchen &amp; Bar 享用美饌、預訂別墅內SPA服務放鬆身心，或在公共泳池畔悠閒度日。<br>\r\n於 Maca Villas &amp; Residence Umalas，每一刻皆是寧靜的逃逸旅程，為您帶來極致的舒適與放鬆體驗。</span>', '在宁静的 Maca Villas &amp; Residence Umalas，感受巴厘岛 Umalas 地区的宁谧氛围。地理位置优越，位于热闹的 Canggu 和时尚的 Seminyak 之间。私人泳池别墅被郁郁葱葱的热带花园环绕，完美融合传统巴厘岛元素与现代优雅风格。\r\n您可选择13间一居或两居室别墅，或5间宽敞的双居至三居室豪华宅邸，非常适合情侣或家庭寻求奢华体验。每栋别墅都配备齐全的简易厨房、宽敞的起居空间和私人车库。\r\n<span>在馆内的 Mase Uma Kitchen &amp; Bar 享受美食，预约别墅内的水疗服务焕发活力，或在公共泳池边放松休憩。<br>\r\n在 Maca Villas &amp; Residence Umalas，每一刻都是宁静的度假时光，带来极致的舒适与放松体验。</span>', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>A minimum of a 3-night stay is required during the high season period&nbsp;(16 Jul - 15 Sep, 22 Dec - 04 Jan, 13 - 20 Feb), and a minimum of a 4-night stay is required for bookings during the New Year period for arrivals between December 28 and January 2</li><li>A compulsory New Year’s Eve Dinner will be held on December 31 at Additional Charge&nbsp;</li></ul><b>Honeymoon Benefit:&nbsp;</b><br><ul><li>Flower decorated room upon arrival&nbsp;</li><li>Flower bath upon arrival</li></ul>', '<span>季節性政策：<br></span><ul><li>在旺季期間（7 月 16 日至 9 月 15 日、12 月 22 日至 1 月 4 日、2 月 13 日至 2 月 20 日）需至少入住 3 晚；而跨年期間（12 月 28 日至 1 月 2 日）則需至少入住 4 晚。</li><li>12 月 31 日將舉辦跨年晚宴，需額外收費。</li></ul><span>蜜月禮遇：<br></span><ul><li>抵達時提供花卉佈置的房間</li><li>抵達時提供花瓣浴</li></ul><ul>\r\n</ul>', '<span>季节性政策：<br></span><ul><li>在旺季期间（7 月 16 日至 9 月 15 日、12 月 22 日至 1 月 4 日、2 月 13 日至 2 月 20 日）需至少入住 3 晚；而跨年期间（12 月 28 日至 1 月 2 日）需至少入住 4 晚。</li><li>12 月 31 日将举办跨年晚宴，需额外收费。</li></ul><span>蜜月礼遇：<br></span><ul><li>抵达时提供鲜花装饰的房间</li><li>抵达时提供花瓣浴</li></ul>', NULL, NULL, NULL, 'Active', '1759194979_518115425.jpg', 2, 'http://www.macaumalas.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/if722YzNKMBHSkUT9', NULL, NULL, NULL, NULL, '<b>Low Season&nbsp;</b><i>(01 Apr - 15 Jul, 16 Sep - 21 Dec, 05 Jan - 12 Feb, 21 Feb - 31 Mar):</i><br><ul><li>In the event of cancellation within 8 - 14 (eight to fourteen) days prior to arrival date, the reservation will be subject to a cancellation fee equivalent to the value of 1 (one) night accommodation.</li></ul><ul><li>In the event of cancellation within 2 - 7 (two to seven) days prior to arrival date, the reservation will be subject to a cancellation fee equivalent to the value of 50% from the total room night reserved.</li></ul><ul><li>In the event of cancellation within 1 (one) day prior to arrival date, No show as well as Early departure will be subject to full room night reserved.&nbsp;</li></ul><b>High Season&nbsp;</b><i>(16 Jul - 15 Sep, 22 Dec - 04 Jan, 13 - 20 Feb):&nbsp;</i><br><ul><li>In the event of cancellation within 15-30 (fifteen to thirty) days prior to arrival date, the reservation will be subject to a cancellation fee equivalent to the value of 1 (one) night accommodation.</li></ul><ul><li>In the event of cancellation within 2-14 (two to fourteen) days prior to arrival date, the reservation will be subject to a cancellation fee equivalent to the value of 50% from the total room night reserved.</li></ul><ul><li>In the event of cancellation within 1 (one) day prior to arrival date, No show as well as Early Departure will be subject to full room night reserved&nbsp;</li></ul>', '淡季（4月1日－7月15日、9月16日－12月21日、1月5日－2月12日、2月21日－3月31日）：\r\n<ul>\r\n<li>\r\n若於入住日前8至14天內取消預訂，將收取相當於1晚房費的取消費用。\r\n</li>\r\n<li>\r\n若於入住日前2至7天內取消預訂，將收取總住宿晚數50%的取消費用。\r\n</li>\r\n<li>\r\n若於入住前1天內取消預訂、未出現（No Show）或提前退房，將收取全部預訂住宿晚數的房費作為取消費用。\r\n</li>\r\n</ul>\r\n旺季（7月16日－9月15日、12月22日－1月4日、2月13日－2月20日）：\r\n<ul>\r\n<li>\r\n若於入住日前15至30天內取消預訂，將收取相當於1晚房費的取消費用。\r\n</li>\r\n<li>\r\n若於入住日前2至14天內取消預訂，將收取總住宿晚數50%的取消費用。\r\n</li>\r\n<li>\r\n若於入住前1天內取消預訂、未出現或提前退房，將收取全部預訂住宿晚數的房費作為取消費用。</li></ul>', '淡季（4月1日－7月15日、9月16日－12月21日、1月5日－2月12日、2月21日－3月31日）：\r\n<ul>\r\n<li>\r\n若在入住日前8至14天内取消预订，将收取相当于1晚房费的取消费用。\r\n</li>\r\n<li>\r\n若在入住日前2至7天内取消预订，将收取总住宿晚数50%的取消费用。\r\n</li>\r\n<li>\r\n若在入住前1天内取消预订、未出现（No Show）或提前退房，将收取全部预订住宿晚数的房费作为取消费用。\r\n</li>\r\n</ul>\r\n旺季（7月16日－9月15日、12月22日－1月4日、2月13日－2月20日）：\r\n<ul>\r\n<li>\r\n若在入住日前15至30天内取消预订，将收取相当于1晚房费的取消费用。\r\n</li>\r\n<li>\r\n若在入住日前2至14天内取消预订，将收取总住宿晚数50%的取消费用。\r\n</li>\r\n<li>\r\n若在入住前1天内取消预订、未出现或提前退房，将收取全部预订住宿晚数的房费作为取消费用。</li></ul>', NULL, '2022-11-01 13:37:26', '2025-09-29 17:16:19', 2, 1),
(18, 'Jumeirah Bali', '17', NULL, NULL, NULL, 'eJnIvMbtJi6PGwKNp33itM9hen', '17', NULL, 'Pecatu Indah Resort, Jl. Raya Uluwatu Street, South Kuta, Badung Regency	,Bali, Indonesia', 2, 20, 'Timotius Ajawaila', '03612015000', '<p>An elegant haven inspired by a tranquil Javanese-Hindu water palace</p>', '<p>靈感源自寧靜的爪哇—印度教水宮殿的優雅靜謐之所</p>', '<p>灵感源自宁静的爪哇—印度教水宫殿的优雅静谧之所</p>', '<ol><li>Luxury Airport Transfers</li><li>Personal Butler Service</li><li>Peafowl Pavilion Kids Club</li><li>Holistic Wellness Experiences</li><li>Beach Boot Camp</li><li>Blessings of Bali</li><li>Sunrise to Sunset Meditation</li></ol>', '<p>豪華機場接送服務<br data-start=\"136\" data-end=\"139\">\r\n專屬私人管家服務<br data-start=\"147\" data-end=\"150\">\r\n孔雀亭兒童俱樂部<br data-start=\"158\" data-end=\"161\">\r\n全方位身心靈療癒體驗<br data-start=\"171\" data-end=\"174\">\r\n海灘體能訓練營<br data-start=\"181\" data-end=\"184\">\r\n峇里島祝福儀式<br data-start=\"191\" data-end=\"194\">\r\n日出至日落冥想體驗</p>', '<p>豪华机场接送服务<br data-start=\"253\" data-end=\"256\">\r\n专属私人管家服务<br data-start=\"264\" data-end=\"267\">\r\n孔雀亭儿童俱乐部<br data-start=\"275\" data-end=\"278\">\r\n全方位身心灵疗愈体验<br data-start=\"288\" data-end=\"291\">\r\n海滩体能训练营<br data-start=\"298\" data-end=\"301\">\r\n巴厘岛祝福仪式<br data-start=\"308\" data-end=\"311\">\r\n日出至日落冥想体验</p>', NULL, NULL, NULL, '<ul><li>December 24-26・December 29-03, 2024, March 10-13, 2024</li><li>Dates when Jumeirah Hotel was booked</li><li>Currently - reservations and weddings are held on March 31, 2025. Exclusive to Jiamei - Complimentary 5-course candlelight dinner for 2 to the newlyweds at SEGARAN restaurant</li><li>Low consumption at the dinner venue (excluding tax rate and service charge, currently 21%)</li></ul>', NULL, NULL, 'inactive', '1731988017_IMG-20230414-WA0038.webp', 14, 'https://www.jumeirah.com/en', '2', '360', NULL, NULL, 'https://g.page/jumeirahbali?share', NULL, NULL, NULL, NULL, '<p><strong>Shoulder Season</strong> (01 - 04 Apr, 15 Apr - 30 Jun, 01 Sep - 19 Dec, 06 - 23 Jan, 03 Feb - 31 Mar):&nbsp;</p><p>Within 7 days or less prior to arrival at 15:00 hours, 100% charge on total booking.&nbsp;</p><p><strong>High Season</strong> (05 - 14 Apr, 01 Jul - 31 Aug, 24 Jan - 02 Feb):&nbsp;</p><p>Within 14 days or less prior to arrival at 15:00 hours, 100% charge on total booking.&nbsp;</p><p><strong>Peak Season</strong> (20 Dec - 05 Jan):&nbsp;</p><p>Within 21 days or less prior to arrival at 15:00 hours, 100% charge on total booking.&nbsp;</p><p><strong>No Show</strong>: 100% charge on total booking&nbsp;</p>', '<p data-start=\"131\" data-end=\"243\"><strong data-start=\"131\" data-end=\"194\">平季（01–04 4月、15 4月–30 6月、01 9月–19 12月、06–23 1月、03 2月–31 3月）：</strong><br data-start=\"194\" data-end=\"197\">\r\n於抵達日前 7 天（含）或更晚，且於下午 15:00 前取消，將收取訂單總金額的 100%。</p><p data-start=\"245\" data-end=\"336\"><strong data-start=\"245\" data-end=\"286\">旺季（05–14 4月、01 7月–31 8月、24 1月–02 2月）：</strong><br data-start=\"286\" data-end=\"289\">\r\n於抵達日前 14 天（含）或更晚，且於下午 15:00 前取消，將收取訂單總金額的 100%。</p><p data-start=\"338\" data-end=\"410\"><strong data-start=\"338\" data-end=\"360\">高峰季（20 12月–05 1月）：</strong><br data-start=\"360\" data-end=\"363\">\r\n於抵達日前 21 天（含）或更晚，且於下午 15:00 前取消，將收取訂單總金額的 100%。</p><p>\r\n\r\n\r\n</p><p data-start=\"412\" data-end=\"447\"><strong data-start=\"412\" data-end=\"429\">未入住（No Show）：</strong><br data-start=\"429\" data-end=\"432\">\r\n將收取訂單總金額的 100%。</p>', '<p data-start=\"487\" data-end=\"599\"><strong data-start=\"487\" data-end=\"550\">平季（01–04 4月、15 4月–30 6月、01 9月–19 12月、06–23 1月、03 2月–31 3月）：</strong><br data-start=\"550\" data-end=\"553\">\r\n于抵达日前 7 天（含）或更晚，且在下午 15:00 前取消，将收取订单总金额的 100%。</p><p data-start=\"601\" data-end=\"692\"><strong data-start=\"601\" data-end=\"642\">旺季（05–14 4月、01 7月–31 8月、24 1月–02 2月）：</strong><br data-start=\"642\" data-end=\"645\">\r\n于抵达日前 14 天（含）或更晚，且在下午 15:00 前取消，将收取订单总金额的 100%。</p><p data-start=\"694\" data-end=\"766\"><strong data-start=\"694\" data-end=\"716\">高峰季（20 12月–05 1月）：</strong><br data-start=\"716\" data-end=\"719\">\r\n于抵达日前 21 天（含）或更晚，且在下午 15:00 前取消，将收取订单总金额的 100%。</p><p>\r\n\r\n\r\n</p><p data-start=\"768\" data-end=\"803\" data-is-last-node=\"\" data-is-only-node=\"\"><strong data-start=\"768\" data-end=\"785\">未入住（No Show）：</strong><br data-start=\"785\" data-end=\"788\">\r\n将收取订单总金额的 100%。</p>', NULL, '2022-11-01 13:49:40', '2026-03-24 18:26:55', 1, 1),
(19, 'Hotel Indigo', '17', NULL, NULL, NULL, '0iEsCUInXr9R44V3Ll1GBSNp0P', '17', NULL, 'Jl. Camplung Tanduk No.10, Seminyak, Bali, Kabupaten Badung, Bali 80361', 1, 9, 'Pingkan Kereh', '03612099999', '<p>Hotel Indigo Bali Seminyak Beach is situated in the heart of one of Bali&rsquo;s most vibrant districts, a place where centuries of tradition and culture are blended with an atmosphere of casual sophistication.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1713775583_cover.webp', 14, 'https://www.ihg.com/hotelindigo/hotels/us/en//bali/dpsin/hoteldetail', '2', '45', NULL, NULL, 'https://g.page/sheratonkuta?share', NULL, NULL, NULL, NULL, '<p><strong>Normal Season</strong> <em>(01 Apr - 17 Jun, 01 Sep - 19 Dec, 06 Jan - 31 Mar):</em></p><ol><li>Cancellation or change in length of stay within 72 hours prior to arrival: 1 night&nbsp;penalty&nbsp;</li><li>Cancellation within 24 hours prior to arrival: 100% penalty, equivalent to the entire length of stay&nbsp;</li></ol><p><strong>High &amp; Peak Season:</strong></p><ol><li>Cancellation or change in length of stay within 14 days prior to arrival: 1 night penalty&nbsp;</li><li>Cancellation, no show or early check out within 7 days prior to arrival: 100% penalty, equivalent to the entire length of stay&nbsp;</li></ol><p><strong>No Show:</strong>&nbsp;Client who does not show will be charged for the entire length of stay</p>', NULL, NULL, NULL, '2022-11-05 06:48:14', '2026-03-24 18:26:55', 1, 1),
(20, 'InterContinetal Bali Resort', '17', NULL, NULL, NULL, 'GKPKEF6FDEpkTfVIcBNhQhR7jI', '17', NULL, 'Uluwatu St No.45, Jimbaran, South Kuta, Badung Regency, Bali 80361', 1, 8, 'Thalia Susanti', '0361701888', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1759197722_intercontinental-hotels-bali-resort-jimbaran-e7abd83b.jpg', 2, 'https://www.ihg.com/intercontinental', '2', '45', NULL, NULL, 'https://goo.gl/maps/vZqwp21Z48YLstxp9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-12 08:15:57', '2026-03-24 18:26:55', 2, 1),
(21, 'Padma Legian', '17', NULL, NULL, NULL, 'xdobOFg5SOZkV9BVhq01o8S0Vb', '17', NULL, 'Jl. Padma No. 1 Legian - Bali 80361 Indonesia', 1, 10, 'Yuliaty Lawandra', '0361752111', '<p>Situated in 6.8 hectares of beautifully manicured gardens filled with lush tropical greenery, water features, swimming pools and stunning public art, Padma Resort Legian is a warm and welcoming luxury five-star resort immersed in the rich heritage, arts and culture of Bali.</p><p>With a prime beachfront location in the heart of Legian, an area renowned for its beautiful sunsets, entertainment, night life, restaurants and boutique shopping, Padma Resort Legian offers a choice of stylish contemporary and Balinese-inspired accommodation backed by world-class facilities, event spaces and the celebrated Balinese hospitality and charm.</p>', NULL, NULL, '<ul><li>Swimming Pool</li><li>Fitness Center</li><li>Spa</li><li>Tennis Court</li><li>Kids Club</li><li>Shop</li><li>Guest Services</li><li>Transportation</li></ul>', NULL, NULL, '<p><strong>Honeymoon/Anniversary Benefit :</strong></p><p>Flower and fruits upon arrival and 1x Honeymoon cake (advance booking is required)</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1700188376_Padma-Legian.webp', 14, 'https://padmaresortlegian.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/search/padma+legian/@-8.7041474,115.1651316,17z/data=!3m1!4b1', NULL, NULL, NULL, NULL, '<p><strong>Regular Season&nbsp;</strong><em>(01 Apr - 30 Jun, 01 Sep - 23 Dec, 05 - 24 Jan, 03 Feb - 31 Mar) :</em></p><ul><li>Cancellation within 7 days : Full Night Charge</li></ul><p><strong>High Season/CNY&nbsp;</strong><em>(01 July - 31 Aug &amp; 25 Jan - 02 Feb) :&nbsp;</em></p><ul><li>Cancellation within 14 days&nbsp;: Full Night Charge</li></ul><p><strong>Peak Season </strong><em>(24 Dec - 04 Jan) :&nbsp;</em></p><ul><li>Cancellation within 21 days : Full Night Charge</li></ul><p><strong>No Show</strong>&nbsp;: Full payment applies&nbsp;</p><p><strong>Seasonal Policy :</strong></p><ul><li>No check out on 31 December&nbsp;</li><li>No check in &ndash; check out on Nyepi Day of 2025</li><li>No compulsory dinner on Christmas Eve and New Year Eve</li></ul>', NULL, NULL, NULL, '2022-11-12 09:27:38', '2026-03-24 18:26:55', 1, 1),
(22, 'Villa Jerami', '17', NULL, NULL, NULL, 'Lx8wprWbvicj94kpktkXHriudL', '17', NULL, 'Jl. Bali Deli No.1, Seminyak, Kec. Kuta, Kabupaten Badung, Bali 80361', 1, 10, 'Ni Nyoman Sukarini', '03618475970', 'Villa Jerami is a luxurious private villa complex of 19 luxurious homes superbly located in the heart of Seminyak, Bali. Carefully designed to combine serene Balinese touches with a modern minimalist style, Villa Jerami is understated and elegant with a fantastic sense of privacy.<br>This tropical sanctuary offers you a unique experience while on holiday in Bali; from culinary delights from our restaurant or in your villa to total body and soul pampering in our Spa.<br>Located in one of Bali`s most sought after areas, Villa Jerami covers almost one hectare of land in the cosmopolitan neighborhood of Seminyak.<br>Close to world class boutiques, designer shops and food choices from around the world, we are wonderfully positioned to allow you to enjoy the very best of what Bali has to offer while retaining the original charm that Bali is so famous for.', 'Villa Jerami 是一座豪華的私人別墅群，共有19棟奢華住宅，坐落於峇里島水明漾核心地段的黃金位置。別墅設計巧妙，融合了寧靜的峇里島風格與現代極簡美學，展現低調優雅的氛圍，同時擁有絕佳的私密性。\r\n這片熱帶綠洲讓您在峇里度假時享有獨特體驗：從餐廳或私人別墅中享用美味佳餚，到在 SPA 中徹底放鬆身心靈。\r\nVilla Jerami 坐落於峇里島最受歡迎的地段之一——時尚的水明漾，占地近一公頃。\r\n鄰近世界級精品店、設計師商店與來自世界各地的美食餐廳，我們的位置極佳，讓您能盡情體驗峇里最精彩的部分，同時保留了峇里島聞名於世的原始魅力。', 'Villa Jerami 是一座豪华的私人别墅区，共有19栋奢华住宅，绝佳地坐落于巴厘岛水明漾的核心地带。别墅精心设计，融合了宁静的巴厘岛元素与现代极简风格，低调而优雅，同时拥有出色的私密性。\r\n这片热带天堂为您在巴厘度假时提供独特体验：无论是在餐厅或您的别墅内享用美食，还是在我们的水疗中心享受身心灵的全面呵护。\r\nVilla Jerami 坐落于巴厘岛最受欢迎的地区之一——时尚的水明漾，占地近一公顷。\r\n临近世界级精品店、设计师品牌与来自世界各地的美食餐厅，我们的位置优越，让您尽情享受巴厘岛所能提供的最佳体验，同时保留巴厘最原始迷人的魅力。', NULL, NULL, NULL, '<b>Seasonal Policy :&nbsp;</b><ul><li>Contract Rate is Valid for a minimum of 3 Nights consecutive stay during high season&nbsp;(1 Jul - 31 Aug)</li><li>Bookings made in Peak Season, for arrivals within 21 December – 5 January must be for a minimum of 5 nights stay with no check-in and no check-out on 31 December and 1 January</li><li>Compulsory New Year\'s Eve Dinner on 31 Dec (Price at additional charge)&nbsp;</li></ul><b>Child Policy:&nbsp;</b><ul><li>Child 0-4 years old sharing existing bedding with parents, breakfast free of charge</li></ul><b>Honeymoon Benefits:&nbsp;</b><ul><li>Honeymoon decoration in the villa</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n合約價格於旺季（7月1日至8月31日）期間，需連續入住至少3晚方可適用。</li><li>巔峰季節（12月21日至1月5日）之預訂，需入住至少5晚，且12月31日與1月1日不可辦理入住與退房。</li><li>12月31日需參加強制性的新年前夕晚宴（需額外收費）。</li></ul><span>兒童政策：<br></span><ul><li>\r\n0–4歲兒童與父母共用現有床鋪可免費享用早餐。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n別墅內提供蜜月佈置。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n合约价格在旺季（7月1日至8月31日）期间，需连续入住至少3晚才可适用。</li><li>在高峰季节（12月21日至1月5日）期间的预订，需至少入住5晚，且12月31日和1月1日不可办理入住和退房手续。</li><li>12月31日须参加强制性的新年前夜晚宴（需额外收费）。</li></ul><span>儿童政策：<br></span><ul><li>\r\n0–4岁儿童与父母共用现有床铺可免费享用早餐。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n别墅内提供蜜月布置。</li></ul>', NULL, NULL, NULL, 'Active', '1700188460_Villa-Jerami.webp', 14, 'https://www.villajerami.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/3NvZ9VxRLAWoiVfC6', NULL, NULL, NULL, NULL, '<b>Low Season</b>&nbsp;<i>(01 Apr - 30 Jun, 01 Sep - 20 Dec, 06 Jan - 31 Mar):&nbsp;</i><ul><li>Cancellation 21 days : 1 room night charge&nbsp;</li><li>Cancellation 7 days&nbsp;: 50% charges of total room night reserved&nbsp;</li><li>Cancellation 24 hrs/no show : 100% charges of total room night reserved&nbsp;</li><li>Early departure : 100% charges of total room night reserved&nbsp;</li></ul><b>High Season</b> <i>(15 Jul - 31 Aug) :</i><ul><li>Cancellation 30 days :&nbsp;1 room night charge&nbsp;</li><li>Cancellation 14 days : 50% charges of total room night reserved&nbsp;</li><li>Cancellation&nbsp;7 days/no show&nbsp;: 100% charges of total room night reserved&nbsp;</li><li>Early departure : 100% charges of total room night reserved&nbsp;</li></ul><b>Peak Season</b> <i>(21 Dec - 05 Jan) :&nbsp;</i><ul><li>Cancellation 45 days : 1 room night charge</li><li>Cancellation 21 days : 50% charges of total room night reserved&nbsp;</li><li>Cancellation 14 days/no show : 100% charges of total room night reserved&nbsp;</li><li>Early departure : 100% charges of total room night reserved&nbsp;</li></ul>', '淡季（4月1日－6月30日、9月1日－12月20日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n取消預訂在入住日前21天內：收取1晚房費\r\n</li>\r\n<li>\r\n取消預訂在入住日前7天內：收取總住宿晚數50%的費用\r\n</li>\r\n<li>\r\n取消預訂在入住前24小時內／未出現（No Show）：收取總住宿晚數100%的費用\r\n</li>\r\n<li>\r\n提前退房：收取總住宿晚數100%的費用\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日）：\r\n<ul>\r\n<li>\r\n取消預訂在入住日前30天內：收取1晚房費\r\n</li>\r\n<li>\r\n取消預訂在入住日前14天內：收取總住宿晚數50%的費用\r\n</li>\r\n<li>\r\n取消預訂在入住日前7天內／未出現：收取總住宿晚數100%的費用\r\n</li>\r\n<li>\r\n提前退房：收取總住宿晚數100%的費用\r\n</li>\r\n</ul>\r\n巔峰季節（12月21日－1月5日）：\r\n<ul>\r\n<li>\r\n取消預訂在入住日前45天內：收取1晚房費\r\n</li>\r\n<li>\r\n取消預訂在入住日前21天內：收取總住宿晚數50%的費用\r\n</li>\r\n<li>\r\n取消預訂在入住日前14天內／未出現：收取總住宿晚數100%的費用\r\n</li>\r\n<li>\r\n提前退房：收取總住宿晚數100%的費用</li></ul>', '淡季（4月1日－6月30日、9月1日－12月20日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n在入住日前21天取消预订：收取1晚房费\r\n</li>\r\n<li>\r\n在入住日前7天取消预订：收取总住宿晚数50%的费用\r\n</li>\r\n<li>\r\n在入住前24小时内取消／未出现（No Show）：收取总住宿晚数100%的费用\r\n</li>\r\n<li>\r\n提前退房：收取总住宿晚数100%的费用\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日）：\r\n<ul>\r\n<li>\r\n在入住日前30天取消预订：收取1晚房费\r\n</li>\r\n<li>\r\n在入住日前14天取消预订：收取总住宿晚数50%的费用\r\n</li>\r\n<li>\r\n在入住日前7天内取消／未出现：收取总住宿晚数100%的费用\r\n</li>\r\n<li>\r\n提前退房：收取总住宿晚数100%的费用\r\n</li>\r\n</ul>\r\n高峰季节（12月21日－1月5日）：\r\n<ul>\r\n<li>\r\n在入住日前45天取消预订：收取1晚房费\r\n</li>\r\n<li>\r\n在入住日前21天取消预订：收取总住宿晚数50%的费用\r\n</li>\r\n<li>\r\n在入住日前14天内取消／未出现：收取总住宿晚数100%的费用\r\n</li>\r\n<li>\r\n提前退房：收取总住宿晚数100%的费用</li></ul>', NULL, '2022-11-13 09:28:37', '2025-09-23 17:25:33', 1, 1),
(23, 'The Lovina Bali', '17', NULL, NULL, NULL, 'hyi7Bs7d6WjlJwXmqjqtPfsSAX', '17', NULL, 'Lovina, Jl. Mas Lovina, Kalibukbuk, Kec. Buleleng, Kabupaten Buleleng, Bali 81151', 3, 100, 'Dwi Dharmawijaya', '03623435800', 'The Lovina Bali Resort is located in one of the most beautiful places on earth, North Bali. Nestled between the Bedugul mountains and the Bali Sea, it really is a slice of paradise. Enjoying 200 metres of absolute beachfront only a short stroll from the centre of town, The Lovina really is perfection.<br>From superb accommodation, to wonderful, friendly staff, The Lovina really does have it all.<br>Finish your day at our famous Sunset Bar with a signature cocktail, followed by our authentic local and international cuisine, before retiring to your private suite or villa.', 'The Lovina Bali Resort 位於峇里島北部——這片被譽為地球上最美麗的地方之一。度假村坐落於貝都古山脈與峇里海之間，彷彿人間仙境。擁有200公尺絕美海濱，步行即可抵達鎮中心，The Lovina 無疑是完美的選擇。\r\n從頂級的住宿到親切友善的服務團隊，The Lovina 擁有您所需要的一切。\r\n結束一天行程後，您可以在我們著名的 Sunset Bar 享用招牌調酒，接著品嚐地道的本地與國際美食，最後回到您的私人套房或別墅，悠然入睡。', 'The Lovina Bali Resort 坐落于巴厘岛北部——这片被誉为地球上最美的地方之一。度假村位于贝都古山脉与巴厘海之间，宛如人间天堂。拥有200米的绝美海滩，步行即可到达市中心，The Lovina 可谓尽善尽美。\r\n从卓越的住宿条件到热情友好的员工，The Lovina 一应俱全。\r\n结束一天的行程后，您可以在我们著名的 Sunset Bar（落日酒吧）享用招牌鸡尾酒，接着品味地道的本地与国际美食，最后返回私人套房或别墅安然休憩。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1744249579_Photo-63.jpg', 14, 'http://www.thelovinabali.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/2K5fdYynLLeKQMbk9', NULL, NULL, NULL, NULL, '<b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Oct - 31 Mar):&nbsp;</i><br><ul><li>14 days prior to arrival, one night penalty.&nbsp;</li><li>7 days prior to arrival, 50% penalty.&nbsp;</li><li>3 days prior to arrival or no show, 100% penalty.&nbsp;</li></ul><b>High Season</b> <i>(01 - 31 May):&nbsp;<br></i><ul><li>30 days prior to arrival, one night penalty.&nbsp;</li><li>21 days prior to arrival, 50% penalty.&nbsp;</li><li>14 days prior to arrival or no show, 100% penalty.&nbsp;</li></ul>', '淡季（4月1日－6月30日、10月1日－3月31日）：\r\n<ul>\r\n<li>\r\n入住前14天取消，將收取1晚房費作為違約金。\r\n</li>\r\n<li>\r\n入住前7天取消，將收取50%房費作為違約金。\r\n</li>\r\n<li>\r\n入住前3天內取消或未出現（No Show），將收取100%房費作為違約金。\r\n</li>\r\n</ul>\r\n旺季（5月1日－5月31日）：\r\n<ul>\r\n<li>\r\n入住前30天取消，將收取1晚房費作為違約金。\r\n</li>\r\n<li>\r\n入住前21天取消，將收取50%房費作為違約金。\r\n</li>\r\n<li>\r\n入住前14天內取消或未出現，將收取100%房費作為違約金。</li></ul>', '淡季（4月1日－6月30日、10月1日－3月31日）：\r\n<ul>\r\n<li>\r\n入住前14天取消，将收取1晚房费作为违约金。\r\n</li>\r\n<li>\r\n入住前7天取消，将收取50%房费作为违约金。\r\n</li>\r\n<li>\r\n入住前3天内取消或未出现（No Show），将收取100%房费作为违约金。\r\n</li>\r\n</ul>\r\n旺季（5月1日－5月31日）：\r\n<ul>\r\n<li>\r\n入住前30天取消，将收取1晚房费作为违约金。\r\n</li>\r\n<li>\r\n入住前21天取消，将收取50%房费作为违约金。\r\n</li>\r\n<li>\r\n入住前14天内取消或未出现，将收取100%房费作为违约金。</li></ul>', NULL, '2022-11-14 11:53:39', '2025-06-24 21:38:35', 1, 1),
(24, 'Renaissance Uluwatu', '17', NULL, NULL, NULL, '6Q6DRtlNawkASiiVSRlLYcqYvC', '17', NULL, 'Jalan Pantai Balangan 1 no. 1, Ungasan, Bali, Indonesia, 80361', 2, 15, 'Augustina Tandun', '03612003588', '<p>At Renaissance Bali Uluwatu Resort &amp; Spa, we offer a five-star resort experience amidst the tranquility of the sand and ocean. Surrounded by pristine Bali beaches, our family-friendly Uluwatu resort inspires you to relax in hotel rooms and suites featuring floating baths, plush beds, complimentary Wi-Fi and views from your private balcony. Savor Indonesian cuisine while you take in the live music and activities at Roosterfish Beach Club. Enjoy resort-style amenities like our outdoor pools, free breakfast, 24-hour gym, valet parking and on-site restaurants and bars, including our pool bar. Visit popular Bali sites, including GWK Cultural Park, Uluwatu Temple and Bali Nusa Dua Convention Center. Balance your mind and body with massages, beauty and wellness therapies at our hotel spa. Our five-star resort overlooks miles of beaches and offers an authentic Indonesian experience in Uluwatu. Unforgettable stays in Bali begin at Renaissance Bali Uluwatu Resort &amp; Spa.</p>', NULL, NULL, '<ul><li>Restaurant</li><li>Fitness Center</li><li>Spa</li><li>Outdool pool</li><li>Meeting space</li><li>Room Service</li></ul>', NULL, NULL, '<p><strong>Standard Benefit :&nbsp;</strong></p><ul><li>Daily buffet breakfast for 2 people at the Clay Craft Restaurant&nbsp;</li><li>Pottery Class based on hotel&rsquo; schedule&nbsp;</li><li>Daily shuttle service to Roosterfish Beach Club at Pandawa Beach based on hotel&rsquo; schedule&nbsp;</li><li>Other house activities based on hotel schedule such as Bike Tour, Aquarobic, yoga class, Fit Boxing and&nbsp;Balinese Experience</li></ul><p><strong>Extra Person Policy:</strong></p><ul><li>Maximum occupancy for Deluxe, Deluxe Ocean and Deluxe Terrace Ocean for adults is two (2) people and one (1) child under 12 years old based on sharing in existing bed</li><li>Maximum occupancy for Junior Suite and Executive Suite using existing bed two adults and one child below 12 using existing bed including the existing sofa bed</li><li>Due to the unique rooms design and interior, we do not accommodate extra bed in deluxe room categories</li></ul><p><strong>Children Policy :&nbsp;</strong></p><p>Children below 6 years old when sharing room with parents using existing bed will be free of charge including breakfast</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1700188633_Renaissance.webp', 2, 'https://www.marriott.com/en-us/hotels/dpsuw-renaissance-bali-uluwatu-resort-and-spa/overview/', '2', '45', NULL, NULL, 'https://g.page/RenaissanceUluwatu?share', NULL, NULL, NULL, NULL, '<p><strong>Normal Season :&nbsp;</strong></p><ul><li>Cancellation occurs within 7 days of arrival or if a no-show occurs : 1 night cancellation fee including room and tax, will be assessed.</li></ul><p><strong>High Season :&nbsp;</strong></p><ul><li>Cancellation occurs within 14 days of arrival or if a no-show occurs : 1 night cancellation fee including room and tax, will be assessed.</li></ul><p><strong>Peak Season :&nbsp;</strong></p><ul><li>Cancellation occurs within 21 days of arrival or if a no-show occurs : 1 night cancellation fee including room and tax, will be assessed.&nbsp;</li></ul><p><strong>Seasonal Policy :</strong>&nbsp;</p><ul><li>Minimum 3-night (consecutive) is required for stay period arrival from 27th Dec - 2nd Jan</li><li>No check-out on 31st December</li><li>Any lunch or/dinner benefits included in the campaign will not be valid for redemption during festive events such as Christmas&#39; Eve, Christmas Day, New Year&#39;s Eve and New Year&#39;s Day</li></ul>', NULL, NULL, NULL, '2022-11-15 09:22:15', '2026-03-24 18:26:55', 2, 1),
(25, 'Puri Sebali Resort', '17', NULL, NULL, NULL, 'WYQMVtoxw2jRGDw60QMkGD3HI9', '17', NULL, 'Jl. Raya Sebali, Kelusa, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 44, 'Sudas', '03614792644', 'Puri Sebali is an ideal hideaway resort for you to relax, unwind, and enjoy the beautiful emerald-green rice terraces of Sebali Village in Ubud.<br><br>Specifically designed for those who want to capture the precious moments of your honeymoon on the island of paradise. Make the romantic moments with your beloved partner you will never forget. The beauty of your love blending with the beauty of nature will make your special day even more spectacular.<br><br>The resort offers three categories of intimate suites and pool villas, each with attentive, discreet service. An on-site restaurant serving international cuisines and a spa with state-of-the-art facilities are readily available to enhance your stay at Sebali.The culture and art centers of Ubud are located only 15 minutes away, easily accessible with our shuttle service.<span><br>Excellent service and superior facilities make for an unforgettable stay. Free Wi-Fi, 24-hour security, daily housekeeping, private check-in and check-out, and free breakfast round up the amazing experience you will have in Puri Sebali. We can’t wait to welcome you home.</span>', 'Puri Sebali 是一處理想的世外桃源度假村，讓您放鬆身心，盡情享受烏布 Sebali 村壯麗的翠綠梯田美景。\r\n度假村專為希望在這片天堂島嶼上，捕捉珍貴蜜月時光的情侶所設計。與摯愛伴侶共度浪漫時光，締造難以忘懷的回憶。當愛情之美與大自然之美交織，將使您的特別日子更加絢麗動人。\r\n度假村提供三種親密的套房與泳池別墅選擇，每間均配有細緻周到的服務。館內設有供應國際美食的餐廳與先進設施的水療中心，為您在 Sebali 的旅程增添舒適與奢華。距離烏布的文化與藝術中心僅15分鐘車程，並提供接駁服務，交通便利。\r\n卓越的服務與頂級設施，為您帶來難忘的住宿體驗。免費無線網路、24小時保全、每日客房清潔、私人入住／退房服務，以及免費早餐，讓您在 Puri Sebali 的每一刻都倍感尊寵。我們期待歡迎您回家。', 'Puri Sebali 是一个理想的度假胜地，适合您放松身心，沉浸于乌布 Sebali 村翠绿稻田的迷人美景中。\r\n度假村专为想在这座天堂岛屿上捕捉蜜月珍贵时刻的情侣而设计。与挚爱一起度过浪漫时光，创造一生难忘的回忆。爱与自然的美丽交融，将使您的特别日子更加耀眼动人。\r\n度假村提供三种温馨舒适的套房和泳池别墅，每间均配有贴心周到的服务。馆内设有提供国际美食的餐厅及先进设施的水疗中心，为您的 Sebali 之旅增添非凡体验。乌布的文化与艺术中心仅需15分钟车程，酒店亦提供接驳服务，方便前往。\r\n优质的服务与卓越的设施，带来难以忘怀的住宿体验。免费无线网络、24小时安保、每日客房清洁、私人入住与退房服务、免费早餐，让您在 Puri Sebali 的每一刻都倍感尊贵。我们迫不及待欢迎您回家。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>No check out on 31 December (New Year Eve)</li></ul><b>Child Policy:&nbsp;</b><ul><li>Free of charge for a baby cot.</li><li>Maximum1 child under 10 years old may stay free of charge by sharing existing bed with parents.</li></ul><b>Honeymoon Benefit:&nbsp;</b><ul><li>Fruit basket in room upon arrival&nbsp;</li><li>Flower arrangement in room upon arrival&nbsp;</li><li>Homemade Honeymoon Cake&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月31日（新年前夕）不接受退房。</li></ul><span>兒童政策：<br></span><ul><li>\r\n嬰兒床免費提供。</li><li>最多1位10歲以下兒童可與父母共用現有床鋪免費入住。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時房內提供水果籃</li><li>抵達時房內提供鮮花佈置</li><li>自製蜜月蛋糕</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n12月31日（新年前夜）不可办理退房。</li></ul>\r\n<span>儿童政策：<br></span><ul><li>\r\n婴儿床免费提供。</li><li>最多1位10岁以下儿童可与父母共用现有床铺免费入住。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时房内提供水果篮</li><li>抵达时房内提供鲜花装饰</li><li>自制蜜月蛋糕</li></ul>', NULL, NULL, NULL, 'Active', '1731988460_DJI_0018.webp', 14, 'https://www.purisebaliresort.com/', '2', '45', NULL, NULL, 'https://g.page/aman-villas-at-nusa-dua?share', NULL, NULL, NULL, NULL, '<b>Low Season:</b><ul><li>1 (one) night charge of all night reserved will be applied for any cancellation made within 7 days prior to arrival.</li><li>Full charge will be applied in the case of no show</li></ul><span><b>High Season and Peak Season</b> <i>(01 July – 31 August and 20 December – 10 January) :</i></span><ul><li>A full charge of all night reserved will be applied for any cancellation made within 14 days prior to arrival and 1 (one) night charge of all night reserved will be applied for any cancellation made within 30 days.</li><li>Full charge will be applied in the case of no show</li><li>Cancellation notification should be made in writing and then acknowledged by the hotel</li></ul>', '<span>淡季：<br></span><ul><li>\r\n若於入住日前7天內取消預訂，將收取整體預訂晚數中1晚的費用。</li><li>若未出現（No Show），將收取全數住宿費用。</li></ul><span>旺季與巔峰季節（7月1日－8月31日 及 12月20日－1月10日）：<br></span><ul><li>\r\n若於入住日前14天內取消預訂，將收取全部預訂晚數的費用。</li><li>若於入住日前30天內取消預訂，將收取全部預訂晚數中1晚的費用。</li><li>若未出現，將收取全數住宿費用。\r\n取消通知需以書面形式提出，並經由飯店確認。</li></ul>', '<span>淡季：<br></span><ul><li>\r\n如在入住日前7天内取消预订，将收取所预订总晚数中的1晚费用。</li><li>如未出现（No Show），将收取全部住宿费用。</li></ul><span>旺季与高峰季节（7月1日－8月31日 和 12月20日－1月10日）：<br></span><ul><li>\r\n如在入住日前14天内取消预订，将收取全部预订晚数的费用。</li><li>如在入住日前30天内取消预订，将收取所预订总晚数中1晚的费用。</li><li>如未出现，将收取全部住宿费用。\r\n取消通知需以书面形式提交，并由酒店确认。</li></ul>', NULL, '2022-11-15 09:37:30', '2025-06-24 21:57:48', 1, 1),
(26, 'The Sebali Resort', '17', NULL, NULL, NULL, 'FBGclJKzMYQls5kP9nbcYMS83d', '17', NULL, 'Br. Kepitu, Kecamatan Ubud, Bali 80571', 2, 45, 'I Wayan Yudianta', '0361975333', 'The Sebali Resort, Ubud, is a luxury, boutique resort with personalized service for all its villas. It is exclusively reserved for single, couple and family with children above 15 years old', 'The Sebali Resort，烏布，是一家提供個人化服務的豪華精品度假村。所有別墅僅限單人、情侶以及攜帶15歲以上兒童的家庭入住。', 'The Sebali Resort，乌布，是一家提供个性化服务的豪华精品度假村。所有别墅仅限单人、情侣以及携带15岁以上儿童的家庭入住。', NULL, NULL, NULL, '<b>Seasonal Policy: </b><ul><li>No check out on 31 December (New Year Eve) </li></ul><b>Honeymoon Benefit: </b><ul><li>Flower arrangement in the room upon arrival </li><li>Homemade Honeymoon cake </li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月31日（新年前夕）不接受退房。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時房內提供鮮花佈置</li><li>自製蜜月蛋糕</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n12月31日（新年前夜）不可办理退房。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时房内提供鲜花装饰</li><li>自制蜜月蛋糕</li></ul>', NULL, NULL, NULL, 'Active', '1759990563_372928043.jpg', 2, 'http://www.thesebali.com/', '2', '60', NULL, NULL, 'https://g.page/amandari-resort?share', NULL, NULL, NULL, NULL, '<b>Low season:</b><ul><li>1 (one) night charge of all night reserved will be applied for any cancellation made within 7 days prior to arrival.</li><li>Full charge will be applied in the case of no show</li></ul><span><b>High Season and Peak Season</b> <i>(01 July – 31 August and 20 December – 10 January):</i></span><ul><li>A full charge of all night reserved will be applied for any cancellation made within 14 days prior to arrival and 1 (one) night charge of all night reserved will be applied for any cancellation made within 30 days.</li><li>Full charge will be applied in the case of no show</li><li>Cancellation notification should be made in writing and then acknowledged by the hotel</li></ul>', '<span>淡季：<br></span><ul><li>\r\n若於入住日前7天內取消預訂，將收取整體預訂晚數中1晚的費用。</li><li>若未出現（No Show），將收取全數住宿費用。</li></ul><span>旺季與巔峰季節（7月1日－8月31日 及 12月20日－1月10日）：<br></span><ul><li>若於入住日前14天內取消預訂，將收取全部預訂晚數的費用。</li><li>若於入住日前30天內取消預訂，將收取整體預訂晚數中1晚的費用。</li><li>若未出現，將收取全數住宿費用。\r\n取消通知須以書面形式提出，並經由飯店確認。</li></ul>', '<span>淡季：<br></span><ul><li>\r\n如在入住日前7天内取消预订，将收取所预订总晚数中1晚的费用。</li><li>如未出现（No Show），将收取全部住宿费用。</li></ul>\r\n<span>旺季与高峰季节（7月1日－8月31日 和 12月20日－1月10日）：<br></span><ul><li>\r\n如在入住日前14天内取消预订，将收取全部预订晚数的费用。</li><li>如在入住日前30天内取消预订，将收取所预订总晚数中1晚的费用。</li><li>如未出现，将收取全部住宿费用。\r\n取消通知需以书面形式提交，并由酒店确认。</li></ul>', NULL, '2022-11-15 09:51:56', '2025-10-08 22:16:03', 2, 1),
(27, 'Courtyard by Marriott Bali Nusa Dua Resort', '17', 'Nusa Dua', 'Bali', 'Indonesia', 'GaStu1WLOLRQd90CQsjRzp5YPf', '17', 17, 'Nusa Dua, Bali, Indonesia', 1, 14, 'Putu Widyawati', '03613003888', '<p>Discover the relaxed comfort and exceptional service awaiting you at Courtyard Bali Nusa Dua Resort. Our award-winning hotel is a few miles from the airport via our shuttle service. Unwind in our Nusa Dua five-star resort accommodations with amenities like complimentary Wi-Fi and a flat-screen TV, a marble bathroom and a private balcony with scenic views of the resort and Nusa Dua beach. Stop by one of our inviting dining outlets to enjoy all-day cuisine, to-go snacks or poolside refreshments. There\'s no better way to bask in the Bali sunshine than at our resort\'s lagoon pool. Our youngest guests can have fun at the Kids\' Club or at the children\'s pool and lazy river. Pamper yourself with a luxury treatment at the resort spa, challenge yourself in the gym or take the complimentary shuttle to our Beach Club and spend the day relaxing on Nusa Dua Beach. Those hosting an event in Bali can explore our hotel\'s versatile indoor and outdoor venues as well. Plan your getaway to our Nusa Dua, Bali, resort today</p>', NULL, NULL, '<p>- Complimentary&nbsp;</p><p>- Wi-Fi</p><p>- Swimming pool Adult &amp; Kid</p><p>- Whirlpool</p><p>- Beach Club</p><p>- Gym</p><p>- Spa</p><p>- Yoga</p><p>- In Room Dining</p><p>- Meeting room</p><p>- Restaurants and bars</p>', NULL, NULL, '<p>Daily breakfast</p><p>Minimum of 4 continuous stay is required during Peak Season (23 December 2022 – 5 January 2023)</p><p>No Check Out is permitted on December 31st</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1700189085_Courtyard.webp', 2, 'https://www.marriott.com/en-us/hotels/dpscy-courtyard-bali-nusa-dua-resort/overview/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Courtyard+by+Marriott+Bali+Nusa+Dua+Resort/@-8.8069575,115.2227605,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd2432632a802d9:0x9d0ae67d948c37f3!5m2!4m1!1i2!8m2!3d-8.8069628!4d115.2253354!16s%2Fg%2F1tk3w7gc?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.8071719, 115.2252921, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-15 11:11:17', '2026-03-25 19:34:58', 2, 2),
(28, 'VOUK Hotel & Suites', '17', NULL, NULL, NULL, 'LwgtSVMkinI2Yx9I2N8Gdz9aW5', '17', NULL, 'Jl. Raya Nusa Dua Selatan, Sawangan, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 25, 'Frederick Nelson', '03618465750', 'Capturing the beauty of Nusa Dua where guests can enjoy the serenity of Indian Ocean Views from the Seaview Terrace, VOUK Hotel &amp; Suites sets its 5-star standard with strong commitment to deliver top-notch services with facilities such as swimming pools for adults and kids, fully equipped gymnasium, Chakra Spa, 7 spacious multi-function and meeting rooms, New Bangle Restaurant for Indian cuisine enthusiasts, the impeccable pool-view Rasa Restaurant and Splash Bar where you can sip one or two drinks before the night’s out. Guests can also take advantage of the complete luxurious amenities provided in the rooms as well as the 24 hours in-room dining facility. We are thrilled to have assembled an extraordinary team of hospitality professional, inspiring leadership and innovative approach to guide the hotel’s team as we prepare to welcome guests and create one-of-a-kind living experience for which VOUK Hotel &amp; Suites Nusa Dua is known for.<br>', '展現努沙杜瓦的迷人風采，賓客可於海景露台欣賞寧靜的印度洋美景，VOUK Hotel &amp; Suites 堅守五星級標準，致力於提供卓越服務與設施，包括成人與兒童專用游泳池、設備齊全的健身房、Chakra Spa 七脈輪水療中心、七間寬敞的多功能與會議室，專為印度料理愛好者設立的 New Bangle 餐廳、可欣賞泳池景觀的 Rasa 餐廳，以及在夜晚來臨前小酌一兩杯的 Splash Bar。\r\n賓客亦可盡情享受客房內所提供的完整豪華設施與24小時客房餐飲服務。我們很榮幸能夠匯聚一支卓越的酒店專業團隊，配合充滿啟發性的領導力與創新服務精神，引領團隊邁向更高標準，準備迎接每一位賓客，打造 VOUK Hotel &amp; Suites Nusa Dua 引以為傲的獨一無二住宿體驗。', '展现努沙杜瓦的迷人风采，宾客可于海景露台欣赏宁静的印度洋美景，VOUK Hotel &amp; Suites 坚守五星级标准，致力于提供卓越服务与设施，包括成人与儿童专用游泳池、设备齐全的健身房、Chakra Spa 七脉轮水疗中心、七间宽敞的多功能与会议室，专为印度料理爱好者设立的 New Bangle 餐厅、可欣赏泳池景观的 Rasa 餐厅，以及在夜晚到来前小酌一两杯的 Splash Bar。\r\n宾客亦可尽情享受客房内所提供的完整豪华设施与24小时客房送餐服务。我们很荣幸能够汇聚一支卓越的酒店专业团队，配合充满启发性的领导力与创新服务精神，引领团队迈向更高标准，准备迎接每一位宾客，打造 VOUK Hotel &amp; Suites Nusa Dua 引以为傲的独特住宿体验。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>No check out at 31 Dec 2025&nbsp;</li><li>Compulsory New Years Eve Dinner (Price: TBA)&nbsp;</li><li>19 March 2026 No check in and check out - Silent Day&nbsp;</li></ul><b>Children Policy:</b>&nbsp;<br><ul><li>Children are considered 12 years of age and below&nbsp;</li><li>Breakfast for child 0 - 5 years old sharing bed with parents are free&nbsp;</li><li>1 baby cot per room is provided free of charge, based on availability&nbsp;&nbsp;</li><li>Maximum number of extra bed or baby cot in a room is 1 (one), based on availability</li></ul><b>Honeymoon/Anniversary Benefit:&nbsp;</b><br><ul><li>Minimum 3N Stay: Welcome honeymoon/Swan Towel&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2025年12月31日不可退房。</li><li>12月31日需參加強制性新年前夕晚宴（價格：待通知）。</li><li>2026年3月19日為靜居日（Nyepi），當天不可辦理入住與退房。</li></ul><span>兒童政策：<br></span><ul><li>\r\n12歲及以下視為兒童。</li><li>0至5歲兒童與父母共床可免費享用早餐。</li><li>每間房可免費提供1張嬰兒床（需視供應情況而定）。</li><li>每間房最多可加1張加床或嬰兒床（需視供應情況而定）。</li></ul><span>蜜月／週年紀念禮遇：<br></span><ul><li>\r\n最低入住3晚：提供歡迎蜜月／天鵝毛巾佈置。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2025年12月31日不可退房。</li><li>12月31日需参加强制性新年前夜晚宴（价格：待通知）。</li><li>2026年3月19日为宁静日（Nyepi），当天不可办理入住与退房。</li></ul><span>儿童政策：<br></span><ul><li>\r\n12岁及以下视为儿童。</li><li>0至5岁儿童与父母同床可免费享用早餐。</li><li>每间房可免费提供1张婴儿床（视供应情况而定）。</li><li>每间房最多可加1张加床或婴儿床（视供应情况而定）。</li></ul><span>蜜月／纪念日礼遇：<br></span><ul><li>\r\n最少入住3晚：提供欢迎蜜月／天鹅毛巾装饰。</li></ul>', NULL, NULL, NULL, 'Active', '1747962663_revato-2622-66456-056982.jpg', 14, 'https://voukbali.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/cJV4kumAbb7pivcd6', NULL, NULL, NULL, NULL, '<b>Normal Season&nbsp;</b><i>(07 Apr - 30 Jun, 01 - 30 Sep, 08 Oct - 21 Dec, 05 Jan - 13 Feb, 23 Feb - 17 Mar) :</i><br><ul><li>Minimum notice 7 - 4 days : 1 night charge&nbsp;</li><li>Minimum notice 3 - 1 days, no show, early departure and amendments : Full stay charge&nbsp;</li></ul><b>High Season&nbsp;</b><i>(01 - 06 Apr, 01 Jul - 31 Aug, 01 - 07 Oct, 14 - 22 Feb, 18 - 31 Mar) :&nbsp;</i><br><ul><li>Minimum notice 21 - 8 days : 1 night charge&nbsp;</li><li>Minimum notice 7 - 1 days, no show, early departure and amendments : Full stay charge&nbsp;</li></ul><b>Peak Season</b> <i>(22 Dec - 04 Jan) :</i><br><ul><li>Minimum notice 30 - 15 days : 1 night charge&nbsp;</li><li>Minimum notice 14 - 1 days, no show, early departure and amendments : Full stay charge&nbsp;</li></ul>', '平季（4月7日－6月30日、9月1日－9月30日、10月8日－12月21日、1月5日－2月13日、2月23日－3月17日）：<br><ul><li>\r\n提前通知7－4天取消：收取1晚房費</li><li>提前通知3－1天取消、未出現、提前退房或更改預訂：收取全額住宿費用&nbsp;</li></ul>旺季（4月1日－4月6日、7月1日－8月31日、10月1日－10月7日、2月14日－2月22日、3月18日－3月31日）：<br><ul><li>\r\n提前通知21－8天取消：收取1晚房費</li><li>提前通知7－1天取消、未出現、提前退房或更改預訂：收取全額住宿費用</li></ul><span>巔峰季節（12月22日－1月4日）：<br></span><ul><li>\r\n提前通知30－15天取消：收取1晚房費</li><li>提前通知14－1天取消、未出現、提前退房或更改預訂：收取全額住宿費用</li></ul>', '<span>平季（4月7日－6月30日、9月1日－9月30日、10月8日－12月21日、1月5日－2月13日、2月23日－3月17日）：<br></span><ul><li>\r\n提前通知7－4天取消：收取1晚房费</li><li>提前通知3－1天取消、未出现、提前退房或修改预订：收取全额住宿费用</li></ul>旺季（4月1日－4月6日、7月1日－8月31日、10月1日－10月7日、2月14日－2月22日、3月18日－3月31日）：<br><ul><li>\r\n提前通知21－8天取消：收取1晚房费</li><li>提前通知7－1天取消、未出现、提前退房或修改预订：收取全额住宿费用&nbsp;</li></ul>高峰季节（12月22日－1月4日）：<br><ul><li>\r\n提前通知30－15天取消：收取1晚房费</li><li>提前通知14－1天取消、未出现、提前退房或修改预订：收取全额住宿费用</li></ul>', NULL, '2022-11-15 11:19:42', '2025-06-24 22:12:23', 1, 1),
(29, 'VOCO Bali Seminyak', '17', NULL, NULL, NULL, 'i1e0SzegcDAx69QJ4sW2Jvgps5', '17', NULL, 'Jl. Raya Kerobokan No.128 C, Banjar Taman, Kerobokan Kelod, Kec. Kuta Utara, Kabupaten Badung, Bali 80361', 1, 11, 'Maria Febyola', '03612099180', 'voco Bali Seminyak, located in the heart of Bali’s vibrant Seminyak district is just a 16-minute drive from downtown Denpasar and a 20-minute drive from Ngurah Rai International Airport. Offering a blissful blend of relaxation, adventure, and authentic Balinese hospitality, our hotel is the perfect destination for those looking to experience the vibrant culture and stunning scenery of Bali, while enjoying the contemporary conveniences and our warm voco hospitality.Guests can indulge in the spaciously appointed sophisticated rooms with plush bedding along with a variety of amenities that are designed to make your stay comfortable and enjoyable. Take a refreshing dip in one of our outdoor pools, surrounded by lush tropical gardens.When it comes to dining, our restaurant serves a delightful selection of international and local cuisine, while our poolside bar offers refreshing cocktails and light bites.Beyond the hotel, the central location in Seminyak makes it an ideal base for exploring the area’s beaches, nightlife, and cultural attractions.', 'voco Bali Seminyak 位於峇里島熱鬧的水明漾地區中心，距離登巴薩市中心僅 16 分鐘車程，距離伍拉·賴國際機場也僅 20 分鐘車程。飯店結合了放鬆、冒險與地道的峇里式熱情款待，為想要探索峇里島繽紛文化與壯麗景色的旅客提供完美的下榻地點，同時享受現代便利與溫暖的 voco 待客之道。\r\n賓客可盡情享受空間寬敞、設計雅緻的客房，配備柔軟舒適的寢具及多項設施，讓您的住宿更加愜意愉快。可於戶外泳池中暢泳，四周環繞熱帶花園，讓您在自然中徹底放鬆。\r\n在餐飲方面，飯店餐廳供應各式美味的國際與在地料理，而池畔酒吧則提供清涼雞尾酒與輕食。\r\n飯店地處水明漾市中心，地理位置絕佳，是探索當地海灘、夜生活與文化景點的理想據點。', 'voco Bali Seminyak 坐落于巴厘岛充满活力的水明漾核心地带，距离登巴萨市中心仅 16 分钟车程，距离伍拉·赖国际机场仅 20 分钟车程。酒店完美融合了放松、探险与地道的巴厘岛式热情款待，是想要体验巴厘文化与迷人风光的旅客的理想之选，同时也能享受到现代便利与 voco 独特温暖的待客之道。\r\n宾客可以在宽敞且精致的客房中放松休憩，配有舒适柔软的床品及多种贴心设施，让您的住宿轻松愉快。您还可在绿意环绕的户外泳池畅游，尽享热带自然之美。\r\n在餐饮方面，酒店餐厅供应各类国际与本地佳肴，池畔酒吧则提供清爽鸡尾酒与精致小食。\r\n酒店位于水明漾的核心位置，是探索当地海滩、夜生活与文化景点的理想起点。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1748401618_voco-bali-9192034603-2x1.jfif', 14, 'https://www.ihg.com/voco/hotels', '2', '45', NULL, NULL, 'https://goo.gl/maps/9JyvTRoGGRGwFXqf8', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-15 11:31:50', '2026-03-24 18:26:55', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(30, 'Como Uma Canggu', '17', 'Canggu', 'Bali', 'Indonesia', 'CirqBrabnZeg5Mw3vW0IozWBK7', '17', 17, 'Jalan Munduk Kedungu, Canggu, Bali, Indonesia', 2, 23, 'Yuli Rahmayanti', '03616202209', 'COMO Uma Canggu is situated on Bali\'s south coast — a beachfront destination offering panoramic views of the soft volcanic sand and rolling waves. This luxury resort in Canggu — an area liked for its laid-back café scene and surf waves — offers stylish accommodation, exceptional cuisine, meaningful wellness and the same impeccable service COMO is known for across the globe. Guests can nurture their wellbeing at the resort’s COMO Shambhala Retreat, with daily fitness classes, hands-on healing and holistic therapies. Friends and family can gather at the buzzing COMO Beach Club, where an eclectic global menu can be enjoyed to the sounds of live acoustic musicians and DJs, with some of the best sunset views on the island.', 'COMO Uma Canggu 坐落於峇里島南岸，是一處海濱度假勝地，可飽覽柔軟火山沙灘與層層波浪的壯麗景致。這家位於 Canggu 的奢華度假村，以悠閒的咖啡文化與衝浪氛圍聞名，提供時尚的住宿空間、精緻的料理、有意義的養生體驗，以及 COMO 品牌一貫的世界級卓越服務。\r\n賓客可在度假村的 COMO Shambhala Retreat 養生中心滋養身心，參加每日健身課程、親身療癒體驗與整體療法。\r\n親友們可齊聚熱鬧非凡的 COMO Beach Club，享受多元的國際料理，同時欣賞現場原聲音樂與 DJ 表演，坐擁島上最迷人的日落景致之一。', 'COMO Uma Canggu 坐落于巴厘岛南海岸，是一处海滨度假胜地，可俯瞰柔软的火山沙滩和起伏的海浪。位于 Canggu 的这家奢华度假村，以悠闲的咖啡文化和冲浪氛围深受喜爱，提供时尚住宿、精致餐饮、深度健康疗愈体验，以及 COMO 品牌在全球广受好评的无瑕服务。\r\n宾客可在度假村的 COMO Shambhala Retreat 健康中心滋养身心，参与每日健身课程、亲身疗愈及整体疗法。\r\n亲朋好友可在热闹的 COMO Beach Club 齐聚一堂，享用多元的国际美食，伴随原声音乐人及 DJ 表演，尽览岛上最美的日落美景之一。', '<ul><li>Fitness Centre</li><li>115m lagoon pool</li><li>COMO the Shop</li><li>Glow</li><li>Seven treatment rooms (five singles and -two doubles)</li><li>Gym (250sq m)</li><li>Two Pilates studios (51sq m and 36sq m)</li><li>Two yoga studios (56sq m and 46sq m)</li><li>25m lap pool at the COMO Beach Club</li><li>COMO Beach Club</li><li>Play by COMO Space</li></ul>', '<ul><li>健身中心</li><li>\r\n115 公尺環礁泳池</li><li>\r\nCOMO 精品店</li><li>\r\nGlow 餐廳</li><li>\r\n七間療程室（五間單人房與兩間雙人房）</li><li>\r\n健身房（250 平方公尺）</li><li>\r\n兩間彼拉提斯教室（51 平方公尺與 36 平方公尺）</li><li>\r\n兩間瑜伽教室（56 平方公尺與 46 平方公尺）</li><li>\r\nCOMO 海灘俱樂部設有 25 公尺標準泳池</li><li>\r\nCOMO 海灘俱樂部</li><li>\r\nPlay by COMO 兒童空間</li></ul>', '<ul><li>健身中心</li><li>\r\n115米环礁泳池</li><li>\r\nCOMO 精品店</li><li>\r\nGlow 餐厅</li><li>\r\n七间理疗室（五间单人房和两间双人房）</li><li>\r\n健身房（250平方米）</li><li>\r\n两间普拉提教室（51平方米和36平方米）</li><li>\r\n两间瑜伽教室（56平方米和46平方米）</li><li>\r\nCOMO 海滩俱乐部设有25米标准泳池</li><li>\r\nCOMO 海滩俱乐部</li><li>\r\nPlay by COMO 儿童空间</li></ul>', '<b>Seasonal Policy:&nbsp; &nbsp;</b><ul><li>Check out on 31st December is not permitted.&nbsp;</li><li>Check-in and check out is not permitted due to Balinese silent day – Nyepi Day: between 6:00am on 19th March 2026 and 6:00am on 20th March 2026&nbsp;</li></ul><b>Honeymoon Amenities (Min 2 nights stay) :&nbsp;</b><br><ul><li>Honeymoon set up in the room upon arrival&nbsp;</li><li>Sunset cocktail for two&nbsp;</li><li>Home-made local treats&nbsp;</li></ul>Proof of marriage within last 6 months must be presented at the time of reservation or at the time of arrival<br><br><b>Child Policy:&nbsp;</b><br><ul><li>For children of 12 years and below one extra bed can be provided on complimentary basis, including breakfast&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2025年12月31日不可辦理退房。</li><li>因峇里島靜居日（Nyepi Day），2026年3月19日早上6:00至3月20日早上6:00期間不可辦理入住與退房。</li></ul><span>蜜月禮遇（至少入住2晚）：<br></span><ul><li>\r\n抵達時房內提供蜜月佈置</li><li>雙人日落雞尾酒</li><li>自製在地甜點</li></ul>\r\n須於預訂或入住時出示6個月內的結婚證明\r\n<br><span>兒童政策：<br></span><ul><li>\r\n12歲及以下兒童可免費加床，並包含早餐</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2025年12月31日不可办理退房。</li><li>\r\n因巴厘岛静居日（Nyepi Day），2026年3月19日早上6:00至3月20日早上6:00期间不可办理入住与退房。</li></ul><span>蜜月礼遇（至少入住2晚）：<br></span><ul><li>\r\n抵达时房内提供蜜月布置</li><li>\r\n双人日落鸡尾酒</li><li>\r\n自制本地甜点</li><li>\r\n预订或入住时需出示6个月内的结婚证明</li></ul><span>儿童政策：<br></span><ul><li>\r\n12岁及以下儿童可免费提供一张加床，并包含早餐</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1700189380_Como-Uma-Canggu.webp', 14, 'https://www.comohotels.com/en/umacanggu', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/COMO+Uma+Canggu/@-8.6546436,115.1232893,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd2387638e81509:0xb617027d13f7963f!5m2!4m1!1i2!8m2!3d-8.6546489!4d115.1258642!16s%2Fg%2F11h9xnty4b?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.6552529, 115.1266526, NULL, NULL, '<span><b>Season 1 and 2</b>&nbsp;<i>(21 Oct - 20 Dec, 07 Jan - 31 Mar and 01 Apr - 24 Jun, 01 Sep - 20 Oct):&nbsp;</i></span><ul><li>Bookings cancelled between 7 days and 4 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 3 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.&nbsp;</li></ul><span><b>Season 3</b><i> (25 Jun - 31 Aug):</i></span><ul><li>Bookings cancelled between 14 days and 8 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 7 days of the date of arrival will incur cancellation charges equal to 100% of the total booking</li></ul><span><b>Season 4</b> <i>(21 Dec - 06 Jan):&nbsp;</i></span><ul><li>Bookings cancelled between 45 days and 31 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 30 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.</li></ul>', '<span>第1與第2季（10月21日－12月20日、1月7日－3月31日、4月1日－6月24日、9月1日－10月20日）：<br></span><ul><li>\r\n於入住日前7至4天取消預訂，將收取等同於1晚住宿費用的取消費用。</li><li>\r\n於入住日前3天內取消預訂，將收取全部預訂金額的100%。</li></ul><span>第3季（6月25日－8月31日）：<br></span><ul><li>\r\n於入住日前14至8天取消預訂，將收取等同於1晚住宿費用的取消費用。</li><li>\r\n於入住日前7天內取消預訂，將收取全部預訂金額的100%。</li></ul><span>第4季（12月21日－1月6日）：<br></span><ul><li>\r\n於入住日前45至31天取消預訂，將收取等同於1晚住宿費用的取消費用。</li><li>\r\n於入住日前30天內取消預訂，將收取全部預訂金額的100%。</li></ul>', '<span>第1和第2季（10月21日－12月20日、1月7日－3月31日、4月1日－6月24日、9月1日－10月20日）：<br></span><ul><li>\r\n如在入住日前7至4天取消预订，将收取等同1晚住宿费用的取消费用。</li><li>\r\n如在入住日前3天内取消预订，将收取100%的总预订金额。</li></ul><span>第3季（6月25日－8月31日）：<br></span><ul><li>\r\n如在入住日前14至8天取消预订，将收取等同1晚住宿费用的取消费用。</li><li>\r\n如在入住日前7天内取消预订，将收取100%的总预订金额。</li></ul><span>第4季（12月21日－1月6日）：<br></span><ul><li>\r\n如在入住日前45至31天取消预订，将收取等同1晚住宿费用的取消费用。</li><li>\r\n如在入住日前30天内取消预订，将收取100%的总预订金额。</li></ul>', NULL, '2022-11-15 12:16:20', '2026-03-25 19:30:47', 1, 2),
(31, 'Como Shambala Estate', '17', 'Melinggih Kelod', 'Bali', 'Indonesia', 'jFi6k9LEW1GV3TwGhUiivryhoU', '17', 17, 'Melinggih Kelod, Bali, Indonesia', 2, 45, 'Yuli Rahmayanti', '0361978888', 'COMO Shambhala Estate is a residential retreat combining holistic wellness with exceptional villa accommodation. The location is unique, a spiritual enclave of jungle, river and sun-rich clearings just north of Ubud. Specialists in yoga and Pilates provide inspiration and nurture, working in harmony with guides for mountain biking, hiking, climbing, white-water rafting and outdoor circuit training. For lasting commitment and actionable change to take home, guests can embark on our Integrated Wellness Programme, which is tailored to individual wellness needs.', 'COMO Shambhala Estate 是一座結合整體健康療癒與頂級別墅住宿的養生型度假村。地點獨特，坐落於烏布以北的靜謐靈性聖地，四周環繞著叢林、河流與陽光普照的空地。\r\n瑜伽與彼拉提斯專家提供靈感與滋養，並與登山車、健行、攀岩、泛舟與戶外循環訓練的教練協作，達到身心平衡。\r\n賓客可參加我們量身打造的「整合式健康計畫」，根據個人健康需求進行定制，讓您在回家後持續實踐轉變，邁向長久的健康承諾。', 'COMO Shambhala Estate 是一家结合整体健康疗愈与高端别墅住宿的养生型度假村。其地理位置独特，位于乌布以北的灵性秘境之中，周围环绕着丛林、河流与阳光充沛的空地。\r\n瑜伽与普拉提专家提供启发与滋养，并与山地骑行、徒步、攀岩、漂流及户外体能训练的教练密切合作，促进身心协调。\r\n宾客可参与我们专为个人健康需求量身定制的「整合健康计划」，实现可持续的改变与疗愈体验，将健康的承诺带回家。', '<ul><li>Nine treatment rooms (three for couples)</li><li>Three treatment pavilions</li><li>Outdoor hydrotherapy area with vitality pool</li><li>Male/female sauna and steam room</li><li>Yoga pavilion and Yoga bale</li><li>Pilates studio Consultation rooms</li><li>25-metre swimming pool</li><li>Chemical-free natural spring water pools</li><li>Gym with weights and cardio equipment</li><li>Outdoor jungle gym</li></ul>', '<ul><li>九間療程室（其中三間為雙人房）</li><li>\r\n三座療癒亭</li><li>\r\n設有活力池的戶外水療區</li><li>\r\n男女分開的桑拿與蒸氣室</li><li>\r\n瑜伽亭與瑜伽草亭</li><li>\r\n彼拉提斯教室</li><li>\r\n諮詢室</li><li>\r\n25米游泳池</li><li>\r\n無化學添加的天然山泉水泳池</li><li>\r\n設有重量訓練與心肺器材的健身房</li><li>\r\n戶外叢林健身區</li></ul>', '<ul><li>九间理疗室（三间为双人使用）</li><li>\r\n三座理疗亭</li><li>\r\n带活力池的户外水疗区</li><li>\r\n男女分开的桑拿房和蒸汽房</li><li>\r\n瑜伽馆和瑜伽草亭</li><li>\r\n普拉提教室</li><li>\r\n咨询室</li><li>\r\n25米游泳池</li><li>\r\n无化学添加的天然山泉水泳池</li><li>\r\n配备力量训练与有氧设备的健身房</li><li>\r\n户外丛林健身区</li></ul>', '<b>Seasonal Policy:&nbsp;</b><br><ul><li>Check-in and check out is not permitted due to Balinese silent day – Nyepi Day: between 6:00am on 19th March 2026 and 6:00am on 20th March 2026</li></ul><b>Honeymoon Amenities:</b><br>All honeymoon guests staying for minimum 3 consecutive nights will receive with our compliments:&nbsp;<br><ul><li>Special welcome amenity and a honeymoon set up in the room upon arrival&nbsp;</li></ul>Honeymoon amenities are valid throughout the contracting period and are combinable with all rates and promotions. Proof of marriage within last 6 months must be presented at the time of reservations or at the time of arrival.&nbsp;<br><br><b>Child Policy:&nbsp;</b><br><ul><li>For children of 12 years and below one extra bed can be provided on complimentary basis, including breakfast&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n因峇里島靜居日（Nyepi Day），2026年3月19日早上6:00至3月20日早上6:00期間不可辦理入住與退房。</li></ul>蜜月禮遇：<br>\r\n所有連續入住至少3晚的蜜月賓客，將獲贈以下禮遇：<br><ul><li>\r\n特別迎賓禮品與房內蜜月佈置</li><li>\r\n蜜月禮遇適用於整個合約期間，且可與所有房價與優惠活動併用。</li><li>\r\n需於預訂時或入住時出示6個月內的結婚證明。</li></ul><span>兒童政策：<br></span><ul><li>\r\n12歲及以下兒童可免費提供一張加床，並包含早餐。</li></ul>', '季节性政策：<br><ul><li>因巴厘岛静居日（Nyepi Day），2026年3月19日早上6:00至3月20日早上6:00期间不可办理入住与退房。</li></ul>蜜月礼遇：<br>所有连续入住至少3晚的蜜月宾客，将免费获赠以下礼遇：<br><ul><li>\r\n特别欢迎礼品及房内蜜月布置</li><li>蜜月礼遇适用于整个合同期间，并可与所有房价及促销活动同时使用。</li><li>需在预订时或入住时出示6个月内的结婚证明。</li></ul>儿童政策：<br><ul><li>\r\n12岁及以下儿童可免费提供一张加床，并包含早餐。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1745906896_f1abb5d5b3f69ffe3285cc3a42a4ab47.jpg', 14, 'https://www.comohotels.com/en/comoshambhalaestate', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/COMO+Shambhala+Estate/@-8.4507779,115.2328758,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd223aaaf09c597:0xd9697a3af62777ad!5m2!4m1!1i2!8m2!3d-8.4507832!4d115.2354507!16s%2Fg%2F1tcy_05x?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.4507285, 115.2353635, NULL, NULL, '<span><b>Season 1 and 2 </b><i>(21 Oct - 20 Dec, 07 Jan - 31 Mar and 01 Apr - 24 Jun, 01 Sep - 20 Oct) :&nbsp;</i></span><ul><li>Bookings cancelled between 7 days and 4 days prior to arrival date will incur cancellation charges equal to one night accommodation cost.</li><li>Bookings cancelled within 3 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.&nbsp;</li></ul><span><b>Season 3 (For Individual Rooms and Suites Reservations Only, except COMO Suite)</b> <i>(25 Jun - 31 Aug) :</i></span><ul><li>Bookings cancelled between 14 days and 8 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 7 days of the date of arrival will incur cancellation charges equal to 100% of the total booking. &nbsp;&nbsp;</li></ul><span><b>Season 3 (For Residence/Villa/COMO Suite&nbsp;Reservations Only)</b>&nbsp;<i>(25 Jun - 31 Aug) :</i></span><ul><li>Bookings cancelled between 60 days and 45 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 44 days of the date of arrival will incur cancellation charges equal to 100% of the total booking. &nbsp;&nbsp;</li></ul><span><b>Season 4</b> <b>(For Individual Rooms and Suites Reservations Only, except COMO Suite) </b><i>(21 Dec - 06 Jan) :&nbsp;</i></span><ul><li>Bookings cancelled between 45 days and 31 days prior to arrival date will incur cancellation charges equal to one night accommodation cost.</li><li>Bookings cancelled within 30 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.</li></ul><span><b>Season 4 (For Residence/Villa/COMO Suite Reservations Only)</b>&nbsp;<i>(21 Dec - 06 Jan) :&nbsp;</i></span><ul><li>Bookings cancelled between 60 days and 45 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 44 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.&nbsp;&nbsp;</li></ul>', '<span>第1與第2季（10月21日－12月20日、1月7日－3月31日、4月1日－6月24日、9月1日－10月20日）：<br></span><ul><li>\r\n在入住日前7至4天取消預訂，將收取等同於1晚住宿費的取消費用。</li><li>\r\n在入住日前3天內取消預訂，將收取全部預訂金額的100%。</li></ul><span>第3季（僅適用於個別客房與套房預訂，COMO 套房除外）（6月25日－8月31日）：<br></span><ul><li>\r\n在入住日前14至8天取消預訂，將收取等同於1晚住宿費的取消費用。</li><li>\r\n在入住日前7天內取消預訂，將收取全部預訂金額的100%。</li></ul><span>第3季（僅適用於住宅／別墅／COMO 套房預訂）（6月25日－8月31日）：<br></span><ul><li>\r\n在入住日前60至45天取消預訂，將收取等同於1晚住宿費的取消費用。</li><li>\r\n在入住日前44天內取消預訂，將收取全部預訂金額的100%。</li></ul><span>第4季（僅適用於個別客房與套房預訂，COMO 套房除外）（12月21日－1月6日）：<br></span><ul><li>\r\n在入住日前45至31天取消預訂，將收取等同於1晚住宿費的取消費用。</li><li>\r\n在入住日前30天內取消預訂，將收取全部預訂金額的100%。</li></ul><span>第4季（僅適用於住宅／別墅／COMO 套房預訂）（12月21日－1月6日）：<br></span><ul><li>\r\n在入住日前60至45天取消預訂，將收取等同於1晚住宿費的取消費用。</li><li>\r\n在入住日前44天內取消預訂，將收取全部預訂金額的100%。</li></ul>', '<span>第1和第2季（10月21日－12月20日、1月7日－3月31日、4月1日－6月24日、9月1日－10月20日）：<br></span><ul><li>\r\n如在入住日前7至4天取消预订，将收取等同1晚房费的取消费用。</li><li>\r\n如在入住日前3天内取消预订，将收取100%的预订总金额。</li></ul><span>第3季（仅适用于个人客房和套房预订，COMO 套房除外）（6月25日－8月31日）：<br></span><ul><li>\r\n如在入住日前14至8天取消预订，将收取等同1晚房费的取消费用。</li><li>\r\n如在入住日前7天内取消预订，将收取100%的预订总金额。</li></ul><span>第3季（仅适用于住宅／别墅／COMO 套房预订）（6月25日－8月31日）：<br></span><ul><li>\r\n如在入住日前60至45天取消预订，将收取等同1晚房费的取消费用。</li><li>\r\n如在入住日前44天内取消预订，将收取100%的预订总金额。</li></ul><span>第4季（仅适用于个人客房和套房预订，COMO 套房除外）（12月21日－1月6日）：<br></span><ul><li>\r\n如在入住日前45至31天取消预订，将收取等同1晚房费的取消费用。</li><li>\r\n如在入住日前30天内取消预订，将收取100%的预订总金额。</li></ul><span>第4季（仅适用于住宅／别墅／COMO 套房预订）（12月21日－1月6日）：<br></span><ul><li>\r\n如在入住日前60至45天取消预订，将收取等同1晚房费的取消费用。</li><li>\r\n如在入住日前44天内取消预订，将收取100%的预订总金额。</li></ul>', NULL, '2022-11-15 12:56:05', '2026-03-25 19:29:43', 1, 2),
(32, 'Como Uma Ubud', '17', 'Ubud', 'Bali', 'Indonesia', 'VCYvC220wmvdB8dDsnkWvWpOW1', '17', 17, 'Raya Sanggingan, Ubud, Bali, Indonesia', 2, 41, 'Yuli Rahmayanti', '0361972448', 'COMO Uma Ubud is a luxury resort in the heart of Ubud. The contemporary Asian design of our 46 rooms, suites and villas are relaxed, sunshine-filled spaces. Our restaurants, Kemiri and Uma Cucina, boast world-class cuisine while COMO Shambhala Retreat at Uma Ubud focuses on holistic wellness, with active pursuits including temple visits, biking and trekking.', 'COMO Uma Ubud 是位於烏布中心的奢華度假村。我們的 46 間客房、套房與別墅採用現代亞洲風格設計，空間舒適悠閒、陽光充足。餐廳 Kemiri 與 Uma Cucina 提供世界級的美食，而 Uma Ubud 的 COMO Shambhala Retreat 則專注於整體健康療癒，並提供參觀寺廟、騎行與健行等戶外活動。', 'COMO Uma Ubud 是位于乌布中心的奢华度假村。我们拥有 46 间客房、套房和别墅，采用现代亚洲设计风格，空间舒适惬意、阳光充足。餐厅 Kemiri 和 Uma Cucina 提供世界级的美食，而 Uma Ubud 的 COMO Shambhala Retreat 则专注于整体健康疗愈，并提供寺庙参观、骑行和徒步等户外活动。', '<ul><li>Como shambhala retreat wellness facilities: yoga studio, yoga pavilion, pool, gym, four treatment rooms</li><li>Room services: daily housekeeping, laundry</li><li>Complimentary scheduled shuttle to and from ubud town</li><li>Services upon request: personal shopping, babysitting</li><li>Como the shop retail boutique</li><li>Concierge service to arrange airport transfers, daily tours and more</li><li>Restaurants and bar: uma cucina, kemiri, uma bar</li><li>Daily scheduled activities and guided walks to join</li><li>Meeting room facilities and catering service for event</li></ul>', '<ul><li>COMO Shambhala Retreat 健康設施：瑜伽教室、瑜伽亭、泳池、健身房、四間療程室</li><li>客房服務：每日客房清潔服務、洗衣服務</li><li>免費定時接駁服務：提供定時免費接駁車往返烏布市區</li><li>應要求提供的服務：個人購物協助、保母服務</li><li>COMO The Shop 精品店</li><li>禮賓服務：協助安排機場接送、每日觀光行程等</li><li>餐廳與酒吧：Uma Cucina、Kemiri、Uma Bar</li><li>每日定時活動與導覽步行行程</li><li>會議設施與活動餐飲服務</li></ul>', '<ul><li>COMO Shambhala Retreat 健康设施：瑜伽教室、瑜伽亭、泳池、健身房、四间理疗室</li><li>客房服务：每日客房清洁服务、洗衣服务</li><li>免费定时接驳服务：提供定时免费接驳车往返乌布市区</li><li>应要求提供的服务：个人购物协助、婴儿看护服务</li><li>COMO The Shop 精品店</li><li>礼宾服务：协助安排机场接送、每日旅游行程等</li><li>餐厅与酒吧：Uma Cucina、Kemiri、Uma Bar</li><li>每日定时活动及导览步行行程</li><li>会议室设施及活动餐饮服务</li></ul>', '<span><b>Seasonal Policy:</b>&nbsp;</span><ul><li>Check-in and check out is not permitted due to&nbsp;Balinese silent day - Nyepi Day: between 6:00am on 19 Mar 2026 and 6:00am on 20 Mar 2026&nbsp;</li></ul><b>Children Policy :&nbsp;</b><ul><li>Baby cot will be provided on complimentary basis</li><li>For childreen of 12 years and below one extra bed can be provided on complimentary basis, including breakfast</li></ul><b>Honeymoon Amenities :</b><br>All honeymoon guests staying for minimum 2 consecutive nights will receive with our compliments:&nbsp;<ul><li>Bottle of wine&nbsp;</li><li>A box of home-made chocolates&nbsp;</li><li>Honeymoon set up in the room upon arrival&nbsp;</li><li>Proof of marriage within last 6 months must be presented at the time of reservation or at the time of arrival&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n由於峇里島寧靜日（Nyepi Day），2026年3月19日上午6:00 至 2026年3月20日上午6:00 期間，禁止辦理入住與退房。</li></ul><span>兒童政策：<br></span><ul><li>\r\n嬰兒床可免費提供。</li><li>\r\n12歲及以下兒童可免費加床，並包含早餐。</li></ul><span>蜜月禮遇：<br>\r\n所有連續入住至少2晚的蜜月賓客，將免費獲得以下禮遇：<br></span><ul><li>\r\n一瓶紅酒</li><li>\r\n一盒手工巧克力</li><li>\r\n房內蜜月佈置（入住時提供）</li><li>\r\n須於預訂或入住時出示6個月內的結婚證明。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n由于巴厘岛静居日（Nyepi Day），2026年3月19日早上6:00至2026年3月20日早上6:00期间，禁止办理入住和退房。</li></ul><span>儿童政策：<br></span><ul><li>\r\n婴儿床可免费提供。</li><li>\r\n12岁及以下儿童可免费加床，含早餐。</li></ul><span>蜜月礼遇：<br>\r\n所有连续入住至少2晚的蜜月宾客，将免费获赠以下礼遇：<br></span><ul><li>\r\n一瓶葡萄酒</li><li>\r\n一盒手工巧克力</li><li>\r\n房内蜜月布置（抵达时提供）</li><li>\r\n需在预订时或入住时出示6个月内的结婚证明。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1700189555_Como-Uma-Ubud.webp', 14, 'https://www.comohotels.com/en/umaubud', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/COMO+Uma+Ubud/@-8.4916565,115.2514792,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd23d313678b90f:0x7afc320e57f5b318!5m2!4m1!1i2!8m2!3d-8.4916618!4d115.2540541!16s%2Fg%2F1ttrv3fp?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.4920908, 115.2536060, NULL, NULL, '<span><b>Season 1 and 2</b> <i>(21 Oct - 20 Dec, 07 Jan - 31 Mar and 01 Apr - 24 Jun, 01 - 20 Oct):&nbsp;</i></span><ul><li>Bookings cancelled between 7 days and 4 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 3 days of the date of arrival will incur cancellation charges equal to 100% of the total booking. &nbsp;&nbsp;</li></ul><span><b>Season 3</b> <i>(25 Jun - 30 Sep):&nbsp;</i></span><ul><li>Bookings cancelled between 14 days and 8 days prior to arrival date will incur cancellation charges equal to one night accommodation cost. &nbsp;</li><li>Bookings cancelled within 7 days of the date of arrival will incur cancellation charges equal to 100% of the total booking. &nbsp;&nbsp;</li></ul><span><b>Season 4</b> <i>(21 Dec - 06 Jan):&nbsp;</i></span><ul><li>Bookings cancelled between 45 days and 31 days prior to arrival date will incur cancellation charges equal to one night accommodation cost.</li><li>Bookings cancelled within 30 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.&nbsp;</li></ul>', '<span>第1與第2季（10月21日－12月20日、1月7日－3月31日、4月1日－6月24日、10月1日－10月20日）：<br></span><ul><li>\r\n於入住日前7至4天取消預訂，將收取1晚房費作為取消費用。</li><li>\r\n於入住日前3天內取消預訂，將收取預訂總金額的100%作為取消費用。</li></ul><span>第3季（6月25日－9月30日）：<br></span><ul><li>\r\n於入住日前14至8天取消預訂，將收取1晚房費作為取消費用。</li><li>\r\n於入住日前7天內取消預訂，將收取預訂總金額的100%作為取消費用。</li></ul><span>第4季（12月21日－1月6日）：<br></span><ul><li>\r\n於入住日前45至31天取消預訂，將收取1晚房費作為取消費用。</li><li>\r\n於入住日前30天內取消預訂，將收取預訂總金額的100%作為取消費用。</li></ul>', '<span>第1和第2季（10月21日－12月20日、1月7日－3月31日、4月1日－6月24日、10月1日－10月20日）：<br></span><ul><li>\r\n在入住日前7至4天取消预订，将收取1晚房费作为取消费用。</li><li>\r\n在入住日前3天内取消预订，将收取预订总金额的100%作为取消费用。</li></ul><span>第3季（6月25日－9月30日）：<br></span><ul><li>\r\n在入住日前14至8天取消预订，将收取1晚房费作为取消费用。</li><li>\r\n在入住日前7天内取消预订，将收取预订总金额的100%作为取消费用。</li></ul><span>第4季（12月21日－1月6日）：<br></span><ul><li>\r\n在入住日前45至31天取消预订，将收取1晚房费作为取消费用。</li><li>\r\n在入住日前30天内取消预订，将收取预订总金额的100%作为取消费用。</li></ul>', NULL, '2022-11-15 13:29:20', '2026-03-25 19:33:37', 1, 2),
(33, 'Movenpick Resort', '17', NULL, NULL, NULL, 'pHBsgVWtjQ7lRkmtl8VmZa2T3V', '17', NULL, 'Jl. Wanagiri No.1, Jimbaran, Kec. Kuta Sel., Kabupaten Badung ,Bali, Indonesia', 1, 10, 'Thalia Susanti', '03614725777', 'Immerse yourself in island living, a vibrant culinary scene and Balinese wellness at Mövenpick Resort & Spa Jimbaran Bali, a 5-star family resort less than 5 minutes walk from Jimbaran Beach. Relax at the pool with swim-up hammocks or unwind with a massage at our traditional Arkipela Spa.Shop at Samasta Lifestyle Village while your children are having fun in our pirate-themed Meera Kids Club.', '沉浸於島嶼生活、充滿活力的美食場景與峇里島式養生體驗，盡在五星級家庭渡假村——峇里島金巴蘭瑞享渡假村及水療中心（Mövenpick Resort & Spa Jimbaran Bali），距離金巴蘭海灘步行不到 5 分鐘。您可在設有吊床的泳池中放鬆身心，或於傳統的 Arkipela Spa 體驗舒緩按摩。在 Samasta 生活村享受購物樂趣的同時，小朋友們也能在以海盜為主題的 Meera 兒童俱樂部中開心玩耍。', '<div><div><div><div><div><div><div><div>沉浸于岛屿生活、充满活力的美食体验和巴厘岛式健康疗愈，在金巴兰瑞享度假村及水疗中心（Mövenpick Resort & Spa Jimbaran Bali）尽享五星级家庭度假体验，距离金巴兰海滩步行不到5分钟。您可以在泳池中使用吊床放松身心，或在传统的 Arkipela Spa 享受按摩疗程。在 Samasta 生活村购物的同时，孩子们也可以在以海盗为主题的 Meera 儿童俱乐部中尽情玩乐。</div></div></div></div><div><div><div></div></div></div><div><div></div></div></div><div><div></div></div></div></div></div><div></div>', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities</li></ul>', '<ul><li>免費網路</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位房卡</li><li>\r\n線上辦理入住</li><li>\r\n度假型酒店</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费上网</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字钥匙</li><li>\r\n数字入住</li><li>\r\n度假型酒店</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1700189655_Movenpick.webp', 14, 'https://www.movenpick.com/en/asia/indonesia/bali/jimbaran-bali.html', '2', '360', NULL, NULL, 'https://g.page/movenpick-bali?share', NULL, NULL, NULL, NULL, '<span><b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 19 Dec, 06 Jan - 31 Mar) :</i><br></span><ul><li>Cancellation within 7 days prior to arrival : 100% charge </li></ul><span><b>High Season </b><i>(01 Jul - 31 Aug) : </i><br></span><ul><li>Cancellation within 14 days prior to arrival : 100% charge </li></ul><p><b><span style=\"font-size: 14px;\">Peak Season</span></b><i><span style=\"font-size: 14px;\"> (20 Dec - 05 Jan) :</span></i></p><ul><li><span style=\"font-size: 14px;\">Cancellation within 21 days prior to arrival : 100% charge </span></li></ul>', '<p data-start=\"34\" data-end=\"106\"><strong data-start=\"34\" data-end=\"76\">淡季（4月1日－6月30日、9月1日－12月19日、1月6日－3月31日）：</strong><br data-start=\"76\" data-end=\"79\">\r\n於入住日前 7 天內取消，將收取 100% 費用。</p>\r\n<p data-start=\"108\" data-end=\"158\"><strong data-start=\"108\" data-end=\"127\">旺季（7月1日－8月31日）：</strong><br data-start=\"127\" data-end=\"130\">\r\n於入住日前 14 天內取消，將收取 100% 費用。</p>\r\n<p data-start=\"160\" data-end=\"212\"><strong data-start=\"160\" data-end=\"181\">高峰季（12月20日－1月5日）：</strong><br data-start=\"181\" data-end=\"184\">\r\n於入住日前 21 天內取消，將收取 100% 費用。</p>', '<p data-start=\"252\" data-end=\"324\"><strong data-start=\"252\" data-end=\"294\">淡季（4月1日－6月30日、9月1日－12月19日、1月6日－3月31日）：</strong><br data-start=\"294\" data-end=\"297\">\r\n于入住日前 7 天内取消，将收取 100% 费用。</p>\r\n<p data-start=\"326\" data-end=\"376\"><strong data-start=\"326\" data-end=\"345\">旺季（7月1日－8月31日）：</strong><br data-start=\"345\" data-end=\"348\">\r\n于入住日前 14 天内取消，将收取 100% 费用。</p>\r\n<p data-start=\"378\" data-end=\"428\" data-is-last-node=\"\" data-is-only-node=\"\"><strong data-start=\"378\" data-end=\"399\">高峰季（12月20日－1月5日）：</strong><br data-start=\"399\" data-end=\"402\">\r\n于入住日前 21 天内取消，将收取 100% 费用。</p><div><div><div></div></div></div><div><div></div></div><div><div></div></div><div></div>', NULL, '2022-11-15 13:45:24', '2026-03-24 18:21:00', 1, 1),
(35, 'Bali Beach Hotel', '17', 'Denpasar', 'Bali', 'Indonesia', '7VRlceqe4DrZ2YeatHZhG7neWv', '17', 17, 'Jalan Bypass Ngurah Rai, Sanur Kaja, Denpasar, Bali, Indonesia', 1, 14, 'Kurnia Sommario', '03612012000', 'Embark on a transformative journey of rediscovery at our sanctuary, where each moment reveals a treasure waiting to be uncovered. Immerse yourself in a realm of enchantment and embrace the extraordinary at Bali Beach Hotel Sanur.', '踏上重新探索自我的蛻變之旅，在我們的心靈聖地中，每一刻都將揭示等待發現的珍寶。沉浸於迷人的國度，擁抱非凡體驗，盡在峇里沙努爾海灘酒店（Bali Beach Hotel Sanur）。', '踏上重新发现自我的蜕变之旅，在我们的心灵圣地中，每一刻都将揭示等待发现的珍宝。沉浸于迷人的世界，拥抱非凡体验，尽在巴厘沙努尔海滩酒店（Bali Beach Hotel Sanur）。', NULL, NULL, NULL, '<span><b>Seasonal Policy:&nbsp;</b><br></span><ul><li>Compulsory Dinner applied on 31 December 2025. Price at Additional Charge&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n2025年12月31日需參加強制性晚宴，費用另計。</li></ul>', '季节性政策：<br><ul><li>\r\n2025年12月31日须参加强制性晚宴，费用另计。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1713493187_Cover.webp', 14, 'https://balibeachsanur.com/experience/', '2', '360', NULL, NULL, 'https://www.google.com/maps/place/Bali+Beach+Hotel+-+Sanur/@-8.6773979,115.2611364,17z/data=!4m9!3m8!1s0x2dd240376f0de05f:0x4566ce0914d2ed8a!5m2!4m1!1i2!8m2!3d-8.6774032!4d115.2637113!16s%2Fg%2F1tcy1f55?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.6780353, 115.2635851, NULL, NULL, '<span><b>Normal Season</b> <i>(01 Apr - 14 Jul, 16 Sep - 19 Dec, 06 Jan - 31 Mar):&nbsp;</i></span><ul><li>Cancellation or change in length of stay within 72 hours / 3 days prior to arrival: 1-night penalty&nbsp;</li><li>Cancellation within 48 hours / 2 days prior to arrival: 100% penalty, equivalent to the entire length of stay&nbsp;</li></ul><span><b>High Season</b> <i>(15 Jul - 15 Sep):&nbsp;</i></span><ul><li>Cancellation or change in length of stay within 14 days prior to arrival: 1-night penalty&nbsp;</li><li>Cancellation or change in length of stay within 7 days prior to arrival: 100% penalty, equivalent to the entire length of stay&nbsp;</li></ul><span><b>Peak Season</b><span> <i>(20 Dec - 05 Jan):&nbsp;</i></span></span><ul><li>Cancellation or change in length of stay within 30&nbsp;days prior to arrival: 1-night penalty&nbsp;</li><li>Cancellation or change in length of stay within 21&nbsp;days prior to arrival: 100% penalty, equivalent to the entire length of stay&nbsp;</li></ul>No show or Early Check Out considered as cancellation and will be applied full charge.', '<span>一般季節（4月1日－7月14日、9月16日－12月19日、1月6日－3月31日）：<br></span><ul><li>\r\n於抵達前72小時／3天內取消或更改住宿天數：收取1晚房費作為違約金</li><li>\r\n於抵達前48小時／2天內取消：收取全額住宿費用</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n於抵達前14天內取消或更改住宿天數：收取1晚房費作為違約金</li><li>\r\n於抵達前7天內取消或更改住宿天數：收取全額住宿費用</li></ul><span>巔峰季節（12月20日－1月5日）：<br></span><ul><li>\r\n於抵達前30天內取消或更改住宿天數：收取1晚房費作為違約金</li><li>\r\n於抵達前21天內取消或更改住宿天數：收取全額住宿費用</li></ul>未如期入住（No Show）或提前退房視為取消，將收取全額費用。', '<span>普通季节（4月1日－7月14日、9月16日－12月19日、1月6日－3月31日）：<br></span><ul><li>\r\n在抵达前72小时／3天内取消或更改住宿天数：收取1晚房费作为违约金</li><li>\r\n在抵达前48小时／2天内取消：收取全额住宿费用</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n在抵达前14天内取消或更改住宿天数：收取1晚房费作为违约金</li><li>\r\n在抵达前7天内取消或更改住宿天数：收取全额住宿费用</li></ul><span>高峰季节（12月20日－1月5日）：<br></span><ul><li>\r\n在抵达前30天内取消或更改住宿天数：收取1晚房费作为违约金</li><li>\r\n在抵达前21天内取消或更改住宿天数：收取全额住宿费用</li></ul>未如期入住（No Show）或提前退房将视为取消，并收取全额费用。', NULL, '2022-11-16 08:16:51', '2026-03-25 19:22:29', 1, 2),
(36, 'The Meru Sanur', '17', NULL, NULL, NULL, 'iYCuv63Ny52Gnl0DYLLVLMrqoy', '17', NULL, 'Jl. Hang Tuah, Sanur Kaja, Denpasar Selatan, Kota Denpasar, Bali 80227', 1, 14, 'Kurnia Sommario', '03612012000', 'Welcome to our tranquil haven, dedicated to nurturing the harmony of mind, body, and spirit.<br>Join us on a transformative wellness voyage, where our locally inspired services engage all five senses—sound,<br>sight, scent, taste, and touch—ensuring a holistic and revitalizing journey.', '<span>歡迎來到我們靜謐的心靈殿堂，致力於滋養身、心、靈的和諧。<br>\r\n加入我們的療癒旅程，在這段蛻變的健康之旅中，體驗本地靈感啟發的服務，喚醒聽覺、視覺、嗅覺、味覺與觸覺五感，帶來全方位且煥然一新的體驗。</span>', '欢迎来到我们宁静的心灵殿堂，致力于滋养身、心、灵的和谐。<br>\r\n加入我们的健康转化之旅，在这段疗愈旅程中，体验本地灵感启发的服务，唤醒听觉、视觉、嗅觉、味觉与触觉五感，带来全方位且焕然一新的体验。', '<ul><li>Resort Swimming Pool </li><li>Kids Club </li><li>Fitness Center</li><li>Sarinah</li><li>Sanur Beach </li></ul>', '<ul><li>度假村游泳池</li><li>\r\n兒童俱樂部</li><li>\r\n健身中心</li><li>\r\nSarinah 購物中心</li><li>\r\n沙努爾海灘</li></ul>', '<ul><li>度假村游泳池</li><li>\r\n儿童俱乐部</li><li>\r\n健身中心</li><li>\r\nSarinah 购物中心</li><li>\r\n沙努尔海滩</li></ul>', '<span><b>Seasonal Policy: </b><br></span><ul><li>Compulsory Dinner applied on 31 December 2025. Price at Additional Charge </li></ul>', '季節性政策：<br><ul><li>\r\n2025年12月31日需參加強制性晚宴，費用另計。</li></ul>', '季节性政策：<br><ul><li>\r\n2025年12月31日须参加强制性晚宴，费用另计。</li></ul>', NULL, NULL, NULL, 'Active', '1759195076_The-Meru-Sanur-Featured-Image.jpg', 14, 'http://themerusanur.com/', '2', '360', NULL, NULL, 'https://goo.gl/maps/PzDDxSW6h8cNYxFc7', NULL, NULL, NULL, NULL, '<span><b>Normal Season</b> <i>(01 Apr - 14 Jul, 16 Sep - 19 Dec, 06 Jan - 31 Mar): </i></span><ul><li>Cancellation or change in length of stay within 72 hours / 3 days prior to arrival: 1-night penalty </li><li>Cancellation within 48 hours / 2 days prior to arrival: 100% penalty, equivalent to the entire length of stay </li></ul><span><b>High Season</b> <i>(15 Jul - 15 Sep): </i></span><ul><li>Cancellation or change in length of stay within 14 days prior to arrival: 1-night penalty </li><li>Cancellation or change in length of stay within 7 days prior to arrival: 100% penalty, equivalent to the entire length of stay </li></ul><span><b>Peak Season</b><i> (20 Dec - 05 Jan): </i></span><ul><li>Cancellation or change in length of stay within 30 days prior to arrival: 1-night penalty </li><li>Cancellation or change in length of stay within 21 days prior to arrival: 100% penalty, equivalent to the entire length of stay </li></ul>No show or Early Check Out considered as cancellation and will be applied full charge.', '<span>一般季節（4月1日－7月14日、9月16日－12月19日、1月6日－3月31日）：<br></span><ul><li>\r\n在抵達日前72小時／3天內取消或更改住宿長度：收取1晚房費作為違約金</li><li>\r\n在抵達日前48小時／2天內取消：收取全額住宿費用</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n在抵達日前14天內取消或更改住宿長度：收取1晚房費作為違約金</li><li>\r\n在抵達日前7天內取消或更改住宿長度：收取全額住宿費用</li></ul><span>巔峰季節（12月20日－1月5日）：<br></span><ul><li>\r\n在抵達日前30天內取消或更改住宿長度：收取1晚房費作為違約金</li><li>\r\n在抵達日前21天內取消或更改住宿長度：收取全額住宿費用</li></ul>未如期入住（No Show）或提前退房視為取消，將收取全額費用。', '<span>普通季节（4月1日－7月14日、9月16日－12月19日、1月6日－3月31日）：<br></span><ul><li>\r\n在抵达日前72小时／3天内取消或更改住宿长度：收取1晚房费作为违约金</li><li>\r\n在抵达日前48小时／2天内取消：收取全部住宿费用</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n在抵达日前14天内取消或更改住宿长度：收取1晚房费作为违约金</li><li>\r\n在抵达日前7天内取消或更改住宿长度：收取全部住宿费用</li></ul><span>高峰季节（12月20日－1月5日）：<br></span><ul><li>\r\n在抵达日前30天内取消或更改住宿长度：收取1晚房费作为违约金</li><li>\r\n在抵达日前21天内取消或更改住宿长度：收取全部住宿费用</li></ul>未如期入住（No Show）或提前退房视为取消，将收取全额费用。', NULL, '2022-11-16 08:38:21', '2026-01-28 21:59:23', 1, 1),
(37, 'Mayaloka Villa', '17', NULL, NULL, NULL, '60jtYgRkHOUJUKBIHrgNEBxfqJ', '17', NULL, 'Jl. Cendrawasih Jl. Petitenget No.88, Seminyak, Kec. Kuta Utara, Kabupaten Badung	,Bali, Indonesia', 1, 14, '(Ms) Ayu', '03614736436', '<p>An awarded certificate of excellent and travel choice 2020 by Tripadvisor, Mayaloka offers open air concept Boutique Villas with authentic Balinese architecture design experience.</p><p>Our villa offers complete privacy with its own private entrance, whilst having the added benefit of a 24-hour front office for anything you may need.</p>', NULL, NULL, '<p>- Free Internet Access</p><p>- Free Parking</p><p>- Restaurant</p><p>- Fitness Center</p><p>- Pool</p><p>- Spa</p><p>- Digital Key</p><p>- Digital Check-In</p><p>- Resort Property</p><p>- Laundry</p><p>- Concierge</p><p>- Meeting Facilities</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Special bookings made in Peak Season, for arrivals between 20 December and 5 January should be for minimum of 3 night&rsquo;s stay.</li></ul>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1700189950_Mayaloka-Villa.webp', 2, 'https://mayaresorts.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/7TZ1CdN5V91Xm674A', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-16 08:42:52', '2026-03-24 18:26:55', 2, 1),
(38, 'Aston Canggu Beach Resort', '17', 'Canggu', 'Bali', 'Indonesia', 'g4qWS0UeWfkupi37Qqv5Wu1bYr', '17', 17, 'Canggu, Bali, Indonesia', 2, 23, '(Ms) Yuni', '03613023333', '<p>ASTON Canggu Beach Resort is a perfect home in Canggu &nbsp;located just a walk away from the famous surfing point at Batu Bolong Beach. Our Hotel feature a rooftop dining venue, UpZscale Sky Dining &amp; Bar, which lies by the poolside, overlooks the majestic ocean view and spectacular sunset.&nbsp;</p>', NULL, NULL, '<p>- Restaurant</p><p>- Coffee Shop</p><p>- Room Service</p><p>- Swimming Pool</p><p>- Kids Pool</p><p>- Carpark</p><p>- Wifi Area</p><p>- Spa</p><p>- Gym/Fitness Center</p><p>- Non Smoking Room</p><p>- Connecting Rooms</p><p>- Rooftop Terrace</p><p>- Safety Deposit Box</p><p>- WheelChair Access</p><p>- 24 Hour Front Desk</p><p>- 24 Hour Security</p><p>- Airport Transfer</p><p>- Laundry Service</p><p>- Luggage Storage</p>', NULL, NULL, '<p>Daily breakfast</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1700190067_Aston-Canggu.webp', 2, 'https://www.astonhotelsinternational.com/en/hotel/view/57/aston-canggu-beach-resort', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Aston+Canggu+Beach+Resort/@-8.658201,115.1281144,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd24787cc86bd4d:0x4f2ddeec2b272bc9!5m2!4m1!1i2!8m2!3d-8.6582063!4d115.1306893!16s%2Fg%2F11c5sx00p2?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.6584913, 115.1303615, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-16 11:17:34', '2026-03-25 19:15:23', 2, 2),
(39, 'ASAI Village Jimbaran', '17', 'Jimbaran', 'Bali', 'Indonesia', 'TaE7vlxGwxd8WZkKkiRLnryLVP', '17', 17, 'Jimbaran, Bali, Indonesia', 60, 10, 'Novia Dewi', '082144434214', NULL, NULL, NULL, NULL, NULL, NULL, '<span><b>Seasonal Policy:&nbsp;</b><br></span><ul><li>Minimum stay 2 nights during high season (01 Jul - 31 Aug)&nbsp;</li><li>Minimum stay 3 nights during peak season (20 Dec - 05 Jan)&nbsp;</li><li>Strictly no check in and check out during New Year Eve 31 December 2025&nbsp;</li><li>New Year Eve Dinner on 31 December 2025 (rates to be reconfirm soonest - not compulsory)&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n旺季期間（7月1日至8月31日）最少入住2晚</li><li>\r\n巔峰季節（12月20日至1月5日）最少入住3晚</li><li>\r\n2025年12月31日跨年夜嚴禁辦理入住與退房</li><li>\r\n2025年12月31日跨年晚宴（價格將儘快確認－非強制性）</li></ul>', '季节性政策：<br><ul><li>\r\n旺季期间（7月1日至8月31日）最少入住2晚</li><li>\r\n高峰季节（12月20日至1月5日）最少入住3晚</li><li>\r\n2025年12月31日跨年夜严禁办理入住与退房</li><li>\r\n2025年12月31日跨年晚宴（价格将尽快确认－非强制性）</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1750059064_Blossom_Pool_1.jpg.webp', 14, 'https://asaivillage.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/ASAI+Village/@-8.7850954,115.1541513,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd2458baac4326f:0xc6c9da76c57a4a51!5m2!4m1!1i2!8m2!3d-8.7851007!4d115.1567262!16s%2Fg%2F11p3nmrm9h?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.7852573, 115.1568761, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-16 11:25:47', '2026-03-25 19:14:13', 1, 2),
(40, 'Lumbini Luxury Villas & Spa', '17', NULL, NULL, NULL, 'rL5oVBpwwnzwlpBJQ9I8vojFHv', '17', NULL, 'Uluwatu St No.38, Jimbaran, South Kuta, Badung Regency, Bali 80361', 1, 6, 'Saryati Ayu', '0361704338', 'Warmest greetings from Lumbini Luxury Villas and Spa “An Oasis of peace Jimbaran” Bali.', '來自 Lumbini Luxury Villas and Spa「金巴蘭的和平綠洲」峇里島的最溫馨問候。', '来自 Lumbini Luxury Villas and Spa“金巴兰的和平绿洲”巴厘岛的最温馨问候。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>Minimum stay during peak season (23 Dec - 05 Jan) is 5 Night</li><li>No check in/out on 31st December</li><li>Compulsory New Year Dinner (Price at additional charge)</li></ul>', '季節性政策：<br><ul><li>\r\n巔峰季節（12月23日至1月5日）最少入住5晚</li><li>\r\n12月31日不可辦理入住與退房</li><li>\r\n跨年晚宴為強制性活動（費用另計）</li></ul>', '季节性政策：<br><ul><li>\r\n高峰季节（12月23日至1月5日）最少入住5晚</li><li>\r\n12月31日不可办理入住与退房</li><li>\r\n跨年晚宴为强制性活动（费用另计）</li></ul>', NULL, NULL, NULL, 'Active', '1731989213_421072170.webp', 14, 'http://www.lumbinivillas.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/58SDRS62feQtmeca8', NULL, NULL, NULL, NULL, '<ul><li>A full charge (of all night reserved) will be applied for any cancellation made within 7 days prior to arrival and 50% charge will be applied for any cancellation made within 14 days</li><li>Automatic full charge (of all nights reserved) will be applied for no-show guest</li></ul>', '<ul><li>如於抵達日前7天內取消預訂，將收取全部預訂夜數的全額費用；如於抵達日前14天內取消，將收取50%的費用。</li><li>\r\n如未出現（No-show），將自動收取全部預訂夜數的全額費用。</li></ul>', '<ul><li>如在抵达日前7天内取消预订，将收取所有预订夜晚的全额费用；如在抵达日前14天内取消，将收取50%的费用。</li><li>\r\n如未入住（No-show），将自动收取所有预订夜晚的全额费用。</li></ul>', NULL, '2022-11-16 11:35:38', '2025-06-25 20:00:40', 1, 1),
(41, 'Six Senses Uluwatu', '17', NULL, NULL, NULL, 'ywRQbbtyr6l0qSmyldkBynbo3f', '17', NULL, 'Jl. Goa Lempeh, Uluwatu, Kec. Kuta Sel., Kabupaten Badung ,Bali, Indonesia', 2, 20, 'Nurullita Suhandini', '03612090300', 'Discover us on top of the cliffs at the southernmost tip of Bali where the site of Pura Uluwatu is located, the sacred temple considered one of the island’s core spiritual pillars. Here at our Uluwatu resort, tradition mixes with beautiful beaches, great surf breaks and an eclectic wellness and dining scene. Oh, and did we mention the uninterrupted ocean views from every aspect', '探索我們坐落於峇里島最南端懸崖頂端的度假勝地，這裡正是著名的烏魯瓦圖寺（Pura Uluwatu）所在地，這座神聖的寺廟被視為島上最重要的精神支柱之一。在我們的烏魯瓦圖度假村，傳統文化與美麗海灘、絕佳衝浪點以及多元的健康與美食體驗完美交融。對了，我們還擁有每個角度都能欣賞到的無遮蔽海景哦！', '探索我们位于巴厘岛最南端悬崖之上的度假胜地，这里正是乌鲁瓦图寺（Pura Uluwatu）所在的地方，这座神圣的庙宇被认为是岛上最重要的精神支柱之一。在我们的乌鲁瓦图度假村，传统文化与美丽海滩、绝佳冲浪点以及多元的健康与美食体验相融合。对了，这里每一处都能欣赏到无障碍的海景哦！', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities&nbsp;&nbsp; &nbsp;</li></ul>', '<ul><li>免費網路</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位鑰匙</li><li>\r\n數位入住</li><li>\r\n度假村設施</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费网络</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字钥匙</li><li>\r\n数字入住</li><li>\r\n度假村设施</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>Peak 23 Dec - 05 Jan inclusive - Minimum stay 3 nights during peak season</li><li>No check-out on 31st December &amp; 01st January</li><li>Gala Dinner - December 31st (Non- compulsory)&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n巔峰季為 12 月 23 日至 1 月 5 日（含）——巔峰季期間最少需入住 3 晚</li><li>\r\n12 月 31 日及 1 月 1 日不可辦理退房手續</li><li>\r\n12 月 31 日設有慶祝晚宴（非強制參加）</li></ul>', '季节性政策：<br><ul><li>\r\n高峰期为 12 月 23 日至 1 月 5 日（含）——高峰期期间最低入住 3 晚</li><li>\r\n12 月 31 日及 1 月 1 日不可办理退房手续</li><li>\r\n12 月 31 日设有庆祝晚宴（非强制参加）</li></ul>', NULL, NULL, NULL, 'inactive', '1758159728_505113246.jpg', 14, 'https://www.sixsenses.com/en/resorts/uluwatu-bali', '2', '45', NULL, NULL, 'https://goo.gl/maps/ngHJyQbt89ZSMcp87', NULL, NULL, NULL, NULL, '<b>Low Season</b> <i>(01 Apr - 14 Jul, 01 Sep - 23 Dec) :</i><ul><li>Cancellation &gt;=8&nbsp;days prior to arrival or less : No charge&nbsp;</li><li>Cancellation 7&nbsp;days prior to arrival or less : Full charge for the whole stay&nbsp;</li><li>No show and early departure : Full charge for the whole stay</li></ul><b>High Season</b> <i>(15 Jul - 31 Aug) :</i><ul><li>Cancellation &gt;=15&nbsp;days prior to arrival or less : No charge&nbsp;</li><li>Cancellation 14&nbsp;days prior to arrival or less : Full charge for the whole stay&nbsp;</li><li>No show and early departure : Full charge for the whole stay</li></ul><b>Peak Season</b><i> (24 - 31 Dec) :&nbsp;</i><ul><li>Cancellation &gt;=23&nbsp;days prior to arrival or less : no charge&nbsp;</li><li>Cancellation 22&nbsp;days prior to arrival or less : Full charge for the whole stay&nbsp;</li><li>No show and early departure : Full charge for the whole stay</li></ul>', '<span>淡季（4月1日－7月14日、9月1日－12月23日）：<br></span><ul><li>\r\n抵達前 ≥8 天取消：不收取費用</li><li>\r\n抵達前 7 天內取消：收取全額住宿費用</li><li>\r\n未入住或提前退房：收取全額住宿費用</li></ul><span>旺季（7月15日－8月31日）：<br></span><ul><li>\r\n抵達前 ≥15 天取消：不收取費用</li><li>\r\n抵達前 14 天內取消：收取全額住宿費用</li><li>\r\n未入住或提前退房：收取全額住宿費用</li></ul><span>巔峰季（12月24日－12月31日）：<br></span><ul><li>\r\n抵達前 ≥23 天取消：不收取費用</li><li>\r\n抵達前 22 天內取消：收取全額住宿費用</li><li>\r\n未入住或提前退房：收取全額住宿費用</li></ul>', '<span>淡季（4月1日－7月14日、9月1日－12月23日）：<br></span><ul><li>\r\n抵达前 ≥8 天取消：不收取费用</li><li>\r\n抵达前 7 天内取消：收取全额住宿费用</li><li>\r\n未入住或提前退房：收取全额住宿费用</li></ul><span>旺季（7月15日－8月31日）：<br></span><ul><li>\r\n抵达前 ≥15 天取消：不收取费用</li><li>\r\n抵达前 14 天内取消：收取全额住宿费用</li><li>\r\n未入住或提前退房：收取全额住宿费用</li></ul><span>巅峰季（12月24日－12月31日）：<br></span><ul><li>\r\n抵达前 ≥23 天取消：不收取费用</li><li>\r\n抵达前 22 天内取消：收取全额住宿费用</li><li>\r\n未入住或提前退房：收取全额住宿费用</li></ul>', NULL, '2022-11-16 11:52:23', '2026-03-24 18:26:55', 1, 1),
(42, 'Renaissance Bali Nusa Dua', '17', NULL, NULL, NULL, '7qwMR9kzrS2AhZmKfm0CVJrtoV', '17', NULL, 'Kawasan Pariwisata Lot SW 4 & 5, Nusa Dua Bali, Bali 80363', 1, 14, 'Satya Adiguna', '03612092888', '<p>Perched on the hilly area of Indonesia&#39;s Southern Bali Peninsula, Renaissance Bali Nusa Dua Resort enjoys a bird-eye view of the Nusa Dua enclave and sparkling sea. Inspired by Balinese theater, our resort is fashioned for all senses in theatrical lifestyle and design elements. All rooms and suites boast spacious areas with plush bedding, private balconies, fashionable living areas and bathrooms with soaking tubs. Delight your palate at our distinctive restaurants, including a beach club and an authentic Indonesian restaurant, Nusantara by Locavore. Our resort houses modern meeting rooms, including a grand ballroom that is ideal for your unconventional gala. Pamper your senses with an indulgent spa treatment after a day of island discovery and beach hopping. Little ones will love the Lava Land Kids Club with kids pool, next to resort&rsquo;s outdoor pools with pool bar. Explore Indonesia from Renaissance Bali Nusa Dua Resort with your R Navigator, where unforgettable adventure awaits.</p>', NULL, NULL, '<ul><li>Cocktail during Punch Bowl Ritual at R Bar based on Hotel Schedule&nbsp;</li><li>Daily Shuttle service to Renaissance Bali Beach Club at ITDC</li><li>Free access to use outdoor sundeck at Renaissance Bali Beach Club subject to availability&nbsp;</li><li>Free to join daily activities (Adult &amp; Kids) based on hotel schedule such as Sunlight Cycling tour, Aqua aerobic, Yoga class, Boxing class, Balinese experience and many more&nbsp;</li><li>Free access to steam, sauna and Jacuzzi at The Spa&nbsp;</li><li>Free 24 hours access to Gym&nbsp;</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1700190471_Renaissance-Nusa-Dua.webp', 14, 'https://www.marriott.com/en-us/hotels/dpsnd-renaissance-bali-nusa-dua-resort/overview', '2', '45', NULL, NULL, 'https://goo.gl/maps/WgHGHbSmiE3WbEFCA', NULL, NULL, NULL, NULL, '<p><strong>Low Season</strong> - Room reservation may be cancelled up to 7 days prior to arrival via a mutually agreed documented method. If cancellation occurs within 7 days of arrival, a one night cancellation fee including room and tax, will be assessed.&nbsp;</p><p><strong>High Season and Peak Season</strong> - Room reservation may be cancelled up to 21 days prior to arrival via a mutually agreed documented method. If cancellation occurs within 21 days of arrival, a one night cancellation fee including room and tax, will be assessed.</p><p><strong>No Show </strong>- Full Charge, Date changes inside of the cancellation policy are considered a cancellation and re-booking, and as such, are subject to cancellation damages. The daily cancellation fee will not be contingent on Hotel&#39;s occupancy for the nights for which rooms are cancelled&nbsp;</p>', NULL, NULL, NULL, '2022-11-19 09:13:20', '2026-03-24 18:26:55', 1, 1),
(43, 'Villa Bulan Bali', '17', NULL, NULL, NULL, 'tuVJaAXP4TPjNIsO1CjC4si1ZD', '17', NULL, 'Jl. Petasikan Gang Lemu No.1, Jimbaran, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 2, 'Budi Susanta', '081338963097', 'Villa Bulan Bali is located steps away from the famous Jimbaran bay, Melasti beach, GWK and the airport. Featuring 12 spacious beautiful villas, one and two bedrooms, each with a private pool, kitchen and living room, with service that is impressive for the price you pay.<span><br>With its minimalist mix of Japanese and Balinese elements throughout the property, Villa Bulan Bali is a resort that offers private luxe villas with splendid private pools, in the heart of Jimbaran’s bustling authentic fisherman village.</span><span><br>Suitable for intimate couples and family friendly, experience a perfect romantic ambience or spend quality time with your family. It’s time to reconnect with yourself, your loved ones and nature, so you can unwind completely on the island of the Gods.</span>', 'Villa Bulan Bali 距離著名的金巴蘭灣、Melasti 海灘、GWK 文化公園及機場僅數步之遙。度假村擁有 12 間寬敞雅緻的一臥與兩臥別墅，每間皆設有私人泳池、廚房與客廳，服務水準令人驚艷，物超所值。<br>\r\n整個園區融合日式與峇里島元素的極簡風格，Villa Bulan Bali 是一處位於金巴蘭熱鬧的傳統漁村中心的私人奢華別墅度假村，配備令人讚嘆的私人泳池。<br>\r\n無論是情侶私密度假，或是親子家庭皆相當適合，讓您享受浪漫氛圍或珍貴的家庭時光。現在正是時候重新連結自己、摯愛與大自然，徹底放鬆於這座眾神之島。', 'Villa Bulan Bali 距离著名的金巴兰湾、Melasti 海滩、GWK 公园和机场仅数步之遥。度假村拥有 12 间宽敞漂亮的一卧和两卧别墅，每间都配有私人泳池、厨房和客厅，提供超出价格预期的服务体验。<br>\r\n整个园区采用日式与巴厘岛风格相结合的极简设计，Villa Bulan Bali 是一家位于金巴兰热闹的传统渔村中心的奢华私人别墅度假村，配有令人惊叹的私人泳池。<br>\r\n无论是情侣私密度假，还是亲子家庭出游都非常合适，尽享浪漫氛围或与家人共度美好时光。是时候重新连接自己、挚爱与大自然，在这座众神之岛尽情放松身心。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;<br></b><ul><li>Not a compulsory Chirstmas Eve Dinner and New Year\'s Eve Gala Dinner&nbsp;</li></ul><span><b>Honeymoon Benefits</b> - all honeymooners receive upon arrival on complimentary:&nbsp;</span><ul><li>Flower arrangement on the bed upon arrival&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n不強制參加平安夜晚宴與跨年晚宴</li></ul><span>蜜月禮遇 — 所有蜜月客人將於抵達時免費獲得：<br></span><ul><li>\r\n抵達時床上花卉擺設</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n不强制参加平安夜晚宴和跨年晚宴</li></ul><span>蜜月礼遇 — 所有蜜月客人将在抵达时免费获得：<br></span><ul><li>\r\n抵达时床上花艺摆设</li></ul>', NULL, NULL, NULL, 'Active', '1731989386_bali-bulan-villa-gianyar-bali-pic-1.webp', 14, 'http://www.villabulanbali.com/', '2', '45', NULL, NULL, 'https://g.page/revivoresorts?share', NULL, NULL, NULL, NULL, '<span><b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 19 Dec, 06 Jan - 27 Mar):&nbsp;</i></span><ul><li>3 Days prior to arrival : One night&nbsp;stay&nbsp;</li><li>Same day or No-show : 100% for full length of stay&nbsp;</li></ul><span><b>High &amp; Peak Season </b><i>(01 Jul - 31 Aug, 20 Dec - 05 Jan, 28 Mar - 02 Apr, 16 - 22 Mar):</i>&nbsp;</span><ul><li>21 Days prior to arrival : 50% of full length of stay&nbsp;</li><li>14 Days prior to arrival : full length of stay&nbsp;</li></ul>', '淡季（4月1日－6月30日、9月1日－12月19日、1月6日－3月27日）：\r\n<ul>\r\n<li>\r\n抵達日前 3 天內取消：收取 1 晚房費\r\n</li>\r\n<li>\r\n當天取消或未入住（No-show）：收取整段住宿期間的 100% 房費\r\n</li>\r\n</ul>\r\n旺季與巔峰季（7月1日－8月31日、12月20日－1月5日、3月28日－4月2日、3月16日－22日）：\r\n<ul>\r\n<li>\r\n抵達日前 21 天內取消：收取整段住宿費用的 50%\r\n</li>\r\n<li>\r\n抵達日前 14 天內取消：收取整段住宿期間的全額房費\r\n</li>\r\n</ul>', '淡季（4月1日－6月30日、9月1日－12月19日、1月6日－3月27日）：\r\n<ul>\r\n<li>\r\n抵达日前 3 天内取消：收取 1 晚房费\r\n</li>\r\n<li>\r\n当天取消或未入住（No-show）：收取全程住宿的 100% 房费\r\n</li>\r\n</ul>\r\n旺季与高峰季（7月1日－8月31日、12月20日－1月5日、3月28日－4月2日、3月16日－22日）：\r\n<ul>\r\n<li>\r\n抵达日前 21 天内取消：收取全程住宿费用的 50%\r\n</li>\r\n<li>\r\n抵达日前 14 天内取消：收取全程住宿的全额房费</li></ul>', NULL, '2022-11-19 09:30:13', '2025-06-29 17:49:11', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(44, 'The Ritz-Carlton, Bali', '17', NULL, NULL, NULL, 'JDzVfZvcsf0Eijx2YRyqJGr1mB', '17', NULL, 'Jl. Raya Nusa Dua Selatan, Lot Iii, Sawangan, Nusa Dua ,Bali, Indonesia', 1, 17, 'Bagus Pramana', '03618498988', 'Every detail of The Ritz-Carlton, Bali experience is inspired by the beauty and allure of the ocean. Overlooking the beach in Nusa Dua, this luxury resort celebrates its Bali surroundings at every moment. Luxury resort villas feature private pools, lush gardens and breathtaking views. The hotel\'s glass-enclosed wedding chapel is a modern interpretation of a classic structure. Meals at the resort are accompanied by an ocean breeze.', '巴厘島麗思卡爾頓酒店的每一個細節，皆取材自海洋的美麗與魅力。這間奢華度假村坐落於努沙杜瓦的海灘之上，隨時展現著對巴厘島自然環境的禮讚。奢華別墅設有私人泳池、茂密花園以及令人屏息的壯麗景觀。酒店的玻璃婚禮教堂是經典建築的現代詮釋。在度假村用餐時，更能感受到海風拂面，增添難忘體驗。', '巴厘岛丽思卡尔顿酒店的每一个细节，都源自海洋的美丽与魅力。这家奢华度假村坐落于努沙杜瓦海滩之上，时时刻刻展现着对巴厘岛自然环境的致敬。奢华别墅配有私人泳池、郁郁葱葱的花园和令人惊叹的景观。酒店的玻璃婚礼教堂是对经典建筑的现代诠释。用餐时更有海风拂面，为体验增添一抹惬意。', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities&nbsp;&nbsp; &nbsp;</li></ul>', '<ul><li>免費網路</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位鑰匙</li><li>\r\n數位入住</li><li>\r\n度假村設施</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费网络</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字钥匙</li><li>\r\n数字入住</li><li>\r\n度假村设施</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy :&nbsp;</b><br><ul><li>Minimum stay of 4-night for arrivals between 29&nbsp;December - 1 January</li><li>No check out allowed on 31 December</li><li>No compulsory New Year’s Eve dinner apply</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月29日至1月1日期間入住，須至少入住4晚</li><li>\r\n12月31日不允許退房</li><li>\r\n不強制參加跨年晚宴</li></ul>', '季节性政策：<br><ul><li>12月29日至1月1日期间入住，须至少入住4晚</li><li>12月31日不允许退房</li><li>不强制参加跨年晚宴</li></ul>', NULL, NULL, NULL, 'Active', '1700190637_The-Ritz-Carlton.webp', 14, 'https://www.ritzcarlton.com/en/hotels/indonesia/bali', '2', '45', NULL, NULL, 'https://g.page/ritzcarltonbali?share', NULL, NULL, NULL, NULL, '<span><b>Regular Season</b> <i>(01 Apr - 30 June, 01 Sep - 19 Dec, 04 Jan - 31 Mar) :</i>&nbsp;<br></span><ul><li>Cancellation within 7 days of arrival : 1 night penalty</li></ul><span><b>High Season</b> <i>(01 July - 31 Aug, 20 - 26 Dec, 14 - 21 Feb) :&nbsp;</i><br></span><ul><li>Cancellation within 14 days of arrival : 1 night penalty</li></ul><span><b>Peak Season</b> <i>(27 Dec - 03 Jan) :</i><br></span><ul><li>Full cost of stay in the event of cancellations within 45 days to arrival date</li></ul><span><b>No Show :</b> 100% charge&nbsp;</span><br>', '<span>平季（4月1日 - 6月30日、9月1日 - 12月19日、1月4日 - 3月31日）：<br></span><ul><li>\r\n抵達日前7天內取消預訂：收取1晚房費作為違約金。</li></ul><span>旺季（7月1日 - 8月31日、12月20日 - 12月26日、2月14日 - 2月21日）：<br></span><ul><li>\r\n抵達日前14天內取消預訂：收取1晚房費作為違約金。</li></ul><span>巔峰季節（12月27日 - 1月3日）：<br></span><ul><li>\r\n抵達日前45天內取消預訂：收取整個住宿期間全額費用。</li></ul>未如期入住（No Show）：收取全額費用。<br>', '<span>平季（4月1日 - 6月30日、9月1日 - 12月19日、1月4日 - 3月31日）：<br></span><ul><li>\r\n在抵达前7天内取消：收取1晚房费作为取消费用。</li></ul><span>旺季（7月1日 - 8月31日、12月20日 - 12月26日、2月14日 - 2月21日）：<br></span><ul><li>\r\n在抵达前14天内取消：收取1晚房费作为取消费用。</li></ul><span>高峰季节（12月27日 - 1月3日）：<br></span><ul><li>\r\n在抵达前45天内取消：收取整个住宿期间的全额费用。</li></ul>未入住（No Show）：收取全额费用。', NULL, '2022-11-19 12:32:04', '2025-06-25 23:42:14', 1, 1),
(45, 'Prasana by Arjani Resorts', '17', NULL, NULL, NULL, '2xourj1tcneyUFQa7npoGmtL10', '17', NULL, 'Jl. Harjani No.1, Ungasan, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 16, 'Eka Ariawan', '03614725488', 'Raised on the land of limitless seclusion, Prasana by Arjani Resorts is contrived to present the haven of bliss through the exquisite simplicity of its elements, utmost purity of its bearer’s culture and unfeigned sincerity of its indulgence.', 'Prasana by Arjani Resorts 座落於遺世獨立之地，旨在透過精緻而簡約的元素、承載者文化的純粹本質，以及款待中的真誠無偽，呈現一處幸福的世外桃源。', 'Prasana by Arjani Resorts 坐落于远离尘嚣的土地上，旨在通过精致而简约的元素、承载者文化的纯粹本质，以及款待中的真诚无伪，呈现一处幸福的世外桃源。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Compulsory Christmas Dinner on 25 Dec (Price: Tba)</li><li>Compulsory New Year Dinner on 31 Jan (Price: Tba)</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2025年12月25日需強制參加聖誕晚宴（價格待定）</li><li>\r\n2026年1月31日需強制參加跨年晚宴（價格待定）</li></ul>', '季节性政策：<br><ul><li>\r\n2025年12月25日需强制参加圣诞晚宴（价格待定）</li><li>\r\n2026年1月31日需强制参加跨年晚宴（价格待定）</li></ul>', NULL, NULL, NULL, 'Active', '1731989671_468210717.webp', 14, 'https://prasanabyarjaniresorts.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/Uo6LvyrMjYdJGetE9', NULL, NULL, NULL, NULL, '<b>Regular Season </b><i>(01 Apr - 31 Jul, 01 Sep - 19 Dec, 06 Jan - 31 Mar):&nbsp;</i><ul><li>1 night at the full contracted rate if canceled within 14 days of the guest\'s arrival&nbsp;</li><li>2 nights of full contracted rate if canceled within 7 days of the guest\'s arrival&nbsp;</li><li>Full contracted rate for all night\'s in case of a no-show&nbsp;</li></ul><span><span><b>High Season</b>&nbsp;</span><i>(01 - 31 Aug):&nbsp;</i></span><ul><li>1 night at the full contracted rate if canceled within 30 days of the guest\'s arrival&nbsp;</li><li>2 nights at the full contracted rate if canceled within 14 days of the guest\'s arrival&nbsp;</li><li>Full contracted rate for all nights in case of a no-show&nbsp;</li></ul><span><b>Peak Season</b> <i>(20 Dec - 05 Jan):&nbsp;</i></span><ul><li>All nights at the full contracted rate if canceled within 30 days of the guest\'s arrival or in the case of a No-Show&nbsp;</li></ul>', '平季（4月1日－7月31日、9月1日－12月19日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n若於抵達日前 14 天內取消：收取 1 晚房費（依合約價）\r\n</li>\r\n<li>\r\n若於抵達日前 7 天內取消：收取 2 晚房費（依合約價）\r\n</li>\r\n<li>\r\n若未入住（No-Show）：收取全段住宿費用（依合約價）\r\n</li>\r\n</ul>\r\n旺季（8月1日－8月31日）：\r\n<ul>\r\n<li>\r\n若於抵達日前 30 天內取消：收取 1 晚房費（依合約價）\r\n</li>\r\n<li>\r\n若於抵達日前 14 天內取消：收取 2 晚房費（依合約價）\r\n</li>\r\n<li>\r\n若未入住（No-Show）：收取全段住宿費用（依合約價）\r\n</li>\r\n</ul>\r\n巔峰季（12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n若於抵達日前 30 天內取消或未入住（No-Show）：收取全段住宿費用（依合約價）</li></ul>', '平季（4月1日－7月31日、9月1日－12月19日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n若在抵达日前 14 天内取消：收取 1 晚房费（按合同价）\r\n</li>\r\n<li>\r\n若在抵达日前 7 天内取消：收取 2 晚房费（按合同价）\r\n</li>\r\n<li>\r\n若未入住（No-Show）：收取全程住宿费用（按合同价）\r\n</li>\r\n</ul>\r\n旺季（8月1日－8月31日）：\r\n<ul>\r\n<li>\r\n若在抵达日前 30 天内取消：收取 1 晚房费（按合同价）\r\n</li>\r\n<li>\r\n若在抵达日前 14 天内取消：收取 2 晚房费（按合同价）\r\n</li>\r\n<li>\r\n若未入住（No-Show）：收取全程住宿费用（按合同价）\r\n</li>\r\n</ul>\r\n高峰季（12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n若在抵达日前 30 天内取消或未入住（No-Show）：收取全程住宿费用（按合同价）</li></ul>', NULL, '2022-11-19 13:22:48', '2025-06-29 17:54:56', 1, 1),
(46, 'W Bali Seminyak', '17', 'Kuta Utara', 'Bali', 'Indonesia', 'R5oh6SOgMxhTNYNXDVCDtOkiFV', '17', 17, 'Jalan W Retreat, Kerobokan Kelod, Kuta Utara, Bali, Indonesia', 1, 14, 'Sri Andani', '03613000106', 'Trade in ordinary for extraordinary at W Bali - Seminyak. Our Green Key certified luxury hotel in Seminyak plays by a different set of rules, located at the heart of Bali’s vibrant fashion, nightlife, and restaurant scene. This five-star Bali family resort embodies the archipelago with a rice field-inspired WET® pool. Visit our 24-hour AWAY® Spa and FIT gym. Experience two of our world-class restaurants&amp;nbsp;with the most popular brunch on the island, Starfish Bloo and FIRE. Join the nightlife at Woobar Bali, a beachfront spot with a magnetic social scene. Enjoy garden and panoramic views of the Indian Ocean in your hotel rooms and suites, or the privacy of your private pool in your villa. Soak in a terrazzo bathtub, slip into a robe, order in-room dining, and sleep peacefully under 350-thread-count cotton linens. Before you know it, hit the alarm, head out, and hit repeat.', '在 W Bali - Seminyak，讓平凡蛻變為非凡。我們位於峇里島水明漾、獲得 Green Key 認證的奢華飯店，跳脫傳統規則，座落於峇里最活躍的時尚、夜生活與餐飲中心。這間五星級親子度假飯店，以稻田為靈感打造獨特的 WET® 泳池，完美呈現群島風情。造訪我們 24 小時營運的 AWAY® Spa 與 FIT 健身房，並體驗我們兩間世界級餐廳——島上最受歡迎的早午餐地點 Starfish Bloo 和 FIRE。晚上來到海灘旁的 Woobar Bali，加入充滿魅力的社交夜生活。客房與套房享有花園景觀與印度洋全景，也可選擇帶有私人泳池的別墅，享受極致私密空間。浸泡在水磨石浴缸中，披上浴袍，點選客房餐飲，沉睡於 350 針數的純棉床單中。眨眼之間，鬧鐘響起，再次啟程，重新開始。', '在 W Bali - Seminyak，让平凡变得非凡。我们位于巴厘岛水明漾，获得 Green Key 认证的奢华酒店，不走寻常路，坐落于巴厘最热闹的时尚、夜生活和餐饮中心。这家五星级亲子度假酒店，以稻田为灵感打造的 WET® 泳池，完美呈现群岛风貌。欢迎光临全天候营业的 AWAY® Spa 和 FIT 健身房。尽情享用我们两间世界级餐厅——岛上最受欢迎的早午餐地点 Starfish Bloo 和 FIRE。晚上加入 Woobar Bali 的海滩派对，感受迷人的社交氛围。酒店客房和套房享有花园和印度洋的全景，也可选择带私人泳池的别墅，尽享私密空间。泡在水磨石浴缸中，披上浴袍，享受客房送餐服务，在 350 针数的纯棉床单下安然入睡。眨眼之间，闹钟响起，整装出发，精彩再续。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1744164273_439237188.jpg', 14, 'https://www.marriott.com/en-us/hotels/dpswh-w-bali-seminyak/overview/?scid=f2ae0541-1279-4f24-b197-a979c79310b0', '2', '360', '13:00', '11:00', 'https://maps.google.com/?q=-8.6773270,115.1492582', -8.6773270, 115.1492582, NULL, NULL, '<b>Regular Season (Low Season):&nbsp;</b><br><ul><li>Cancellation within 7 days of arrival : 1 night penalty&nbsp;</li><li>Cancellation within 3 days of arrival : 100% penalty charged&nbsp;<br></li></ul><b>High Season</b> <i>(14 Jun - 31 Aug):&nbsp;</i><br><ul><li>Cancellation within 21 days of arrival : 1 night penalty&nbsp;</li><li>Cancellation within 14 days of arrival : 100% penalty charged&nbsp;</li></ul><b>Peak Season:</b><br><ul><li>Cancellation within 45 days of arrival : 100% penalty charged&nbsp;&nbsp;</li></ul><b>No Show:&nbsp;<br></b><ul><li>Clients who do not show will be charged for the entire length of stay.</li></ul>', '平季（淡季）：\r\n<ul>\r\n<li>\r\n入住前 7 天內取消：收取 1 晚房費作為罰金\r\n</li>\r\n<li>\r\n入住前 3 天內取消：收取 100% 房費作為罰金\r\n</li>\r\n</ul>\r\n旺季（6 月 14 日 – 8 月 31 日）：\r\n<ul>\r\n<li>\r\n入住前 21 天內取消：收取 1 晚房費作為罰金\r\n</li>\r\n<li>\r\n入住前 14 天內取消：收取 100% 房費作為罰金\r\n</li>\r\n</ul>\r\n高峰季：\r\n<ul>\r\n<li>\r\n入住前 45 天內取消：收取 100% 房費作為罰金\r\n</li>\r\n</ul>\r\n未入住（No Show）：\r\n<ul>\r\n<li>\r\n未按預訂入住的房客，將收取全額住宿費用。</li></ul>', '平季（淡季）：\r\n<ul>\r\n<li>\r\n入住前 7 天内取消：收取 1 晚房费作为罚金\r\n</li>\r\n<li>\r\n入住前 3 天内取消：收取 100% 房费作为罚金\r\n</li>\r\n</ul>\r\n旺季（6 月 14 日 – 8 月 31 日）：\r\n<ul>\r\n<li>\r\n入住前 21 天内取消：收取 1 晚房费作为罚金\r\n</li>\r\n<li>\r\n入住前 14 天内取消：收取 100% 房费作为罚金\r\n</li>\r\n</ul>\r\n高峰季：\r\n<ul>\r\n<li>\r\n入住前 45 天内取消：收取 100% 房费作为罚金\r\n</li>\r\n</ul>\r\n未入住（No Show）：\r\n<ul>\r\n<li>\r\n未按预订入住的客人，将收取全额住宿费用。</li></ul>', NULL, '2022-11-21 09:25:23', '2026-04-13 05:50:19', 1, 1),
(47, 'La Berceuse', '17', NULL, NULL, NULL, 'QR1PCpUOq8Bh5IAJrUaERo2YeC', '17', NULL, 'Jl. Desa Sawangan Jl. Nusa Dua, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 16, 'Rina Damayanti', '03614771325', 'Nusa Dua is known for the beauty of its pristine white sandy beaches, home for cultural heritage sites, destination for numerous watersport activities and a place for world-class conferences. The resort is located 25minutes’ drive away from Ngurah Rai International Airport and within short distance away from attractions', '努沙杜瓦以潔白無瑕的沙灘之美而聞名，是文化遺產地的所在、各種水上活動的目的地，也是世界級會議的舉辦地。度假村距離伍拉·賴國際機場僅25分鐘車程，並鄰近多個旅遊景點。', '努沙杜瓦以洁白无瑕的沙滩之美而闻名，是文化遗产地的所在、各种水上活动的目的地，也是世界级会议的举办地。度假村距离伍拉·赖国际机场仅25分钟车程，并邻近多个旅游景点。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1751861309_laberceuse_geger_beach_nusa_dua_covid_1.jpg', 14, 'http://www.laberceusebali.com/', '2', '45', NULL, NULL, 'https://g.page/mayasanur?share', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-21 11:47:06', '2025-07-06 21:44:09', 1, 1),
(48, 'Adiwana Warnakali', '17', 'Toyapakeh', 'Bali', 'Indonesia', 'FwFJV6ScppTqHvlD4HLHMpM5Uh', '17', 17, 'Toyapakeh, Bali, Indonesia', 3, 36, 'Aldi Andika', '0361620700', 'Perched 20 meters above the tropical beach of Nusa Penida, Adiwana Warnakali is ready to welcome its guests with unparalleled beauty, ultimate relaxation and endless adventure. Explore the legendary underwater beauty of Nusa Penida right from our beachfront. For the diving enthusiast, we have the Dune Dive Center that offers PADI courses and Scuba Diving Safari. As it sits on a tall cliff, the hotel was built following nature’s contour. Each room is layered and overlooks the gorgeous ocean as well as its neighboring island of Nusa Ceningan. Enjoy a day by the pool facing the ocean or another option is to spend the day exploring Nusa Penida’s finest attractions, such as Angel Billabong, Atuh Beach and many more. Afterwards, unwind and discover pure bliss at the renowned Tejas Spa.', 'Adiwana Warnakali 坐落於努沙佩尼達熱帶海灘上方 20 公尺的懸崖之上，準備好以無與倫比的美景、極致的放鬆體驗與無盡的冒險，迎接每一位賓客。從我們的海濱地點出發，即可探索努沙佩尼達傳說中的海底奇景。對於潛水愛好者，我們設有 Dune 潛水中心，提供 PADI 課程與水肺潛水之旅。<br>\r\n飯店順應自然地勢而建，坐落於高懸崖之上，每間客房皆呈層疊式設計，擁有壯麗的海景以及可遠眺鄰近的努沙切寧安島。您可以選擇在面向海洋的泳池畔悠閒度日，或是展開一日冒險，造訪努沙佩尼達最迷人的景點，如天使的蕩漾（Angel Billabong）、Atuh 海灘等。結束一天行程後，前往知名的 Tejas Spa，享受身心靈的極致療癒與純粹幸福。', 'Adiwana Warnakali 坐落在努沙佩尼达热带海滩上方 20 米的悬崖之上，准备以无与伦比的美景、极致的放松体验与无限的冒险欢迎宾客。从我们的海滨出发，即可探索努沙佩尼达传奇般的海底世界。对于潜水爱好者，我们拥有 Dune 潜水中心，提供 PADI 课程和水肺潜水之旅。<br>\r\n酒店依照自然地形建造，层层错落地坐落于高耸的悬崖上，每间客房都可俯瞰壮丽海景及邻近的努沙切宁安岛。您可以选择在面朝大海的泳池旁度过悠闲时光，或出发探索努沙佩尼达最受欢迎的景点，例如天使的荡漾（Angel Billabong）、Atuh 海滩等。一天的行程结束后，不妨前往知名的 Tejas Spa，尽情放松，感受纯粹的幸福。', '<ul><li>Tejas Spa Warnakali&nbsp;</li><li>Swimming Pool&nbsp;</li><li>Warnakali Restaurant&nbsp;</li><li>Dune Dive Center&nbsp;</li></ul>', '<ul><li>Tejas Spa Warnakali 泰加斯水療中心（Warnakali）</li><li>\r\n游泳池</li><li>\r\nWarnakali 餐廳</li><li>\r\nDune 潛水中心</li></ul>', '<ul><li>Tejas Spa Warnakali 泰加斯水疗中心（Warnakali）</li><li>\r\n游泳池</li><li>\r\nWarnakali 餐厅</li><li>\r\nDune 潜水中心</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>No check In and Check Out on - seclusion day (Nyepi Day)</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n靜居日（Nyepi Day）當天不接受入住與退房</li></ul>', '季节性政策：<br><ul><li>\r\n静居日（Nyepi Day）当天不接受入住和退房</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1731990146_Adiwana-Warnakali-Bali-Indonesia-3.webp', 14, 'https://adiwanahotels.com/warnakali-resort-nusa-penida-bali/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Adiwana+Warnakali+Resort+-+Nusa+Penida/@-8.6842963,115.480362,17z/data=!4m10!3m9!1s0x2dd273c370889485:0xeb300ce6041c8687!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.6843016!4d115.4829369!16s%2Fg%2F11h3l00hsz?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D', -8.6842272, 115.4831067, NULL, NULL, '<b>High Season:</b> 01 Jul - 31 Aug&nbsp;<br><b>Peak Season:</b> 24 Dec - 05 Jan&nbsp;<ul><li>Prior to 14 days for the normal season and 21 days for high and 30 days for peak season, no penalty fee&nbsp;</li><li>Within 14 days for the normal season and 21 days for high and 30 days for peak season any cancellation is subject to the first night of accommodation at your daily contracted room rate for each room booked&nbsp;</li><li>Any amendment after check in will be 100% charged according to the initial reservation amount&nbsp;</li></ul>', '<span>旺季：7月1日－8月31日<br>\r\n巔峰季：12月24日－1月5日</span>\r\n<br><ul><li>在一般季節抵達日前 14 天前、旺季抵達日前 21 天前、巔峰季抵達日前 30 天前取消，將不收取任何取消費用。</li><li>\r\n若於一般季節抵達日前 14 天內、旺季抵達日前 21 天內、巔峰季抵達日前 30 天內取消，將收取每間已預訂客房每日合約房價的第一晚作為取消費用。</li><li>\r\n入住後若有任何修改（如縮短住宿），將依照原始預訂總金額收取 100% 費用。</li></ul>', '<span>旺季：7月1日－8月31日<br>\r\n高峰季：12月24日－1月5日</span>\r\n<br><ul><li>在普通季节抵达日前14天前、旺季前21天前、高峰季前30天前取消，均不收取任何取消费用。</li><li>\r\n若在普通季节抵达日前14天内、旺季前21天内、高峰季前30天内取消，则每间已预订客房将收取每日合同价的首晚房费作为取消费用。</li><li>\r\n入住后如有任何更改（如缩短住宿天数），将按原始预订金额收取100%费用。</li></ul>', NULL, '2022-11-22 07:02:44', '2026-03-25 19:01:17', 1, 2),
(49, 'Komaneka at Keramas Beach', '17', NULL, NULL, NULL, 'r9dqZdRo0AYu8gfeE1yWMi6PLU', '17', NULL, 'Jalan Prof. Ida Bagus Mantra, Keramas 80581	,Bali, Indonesia', 2, 36, 'Putri Dharmasanti', '0361705777', 'Komaneka Resorts is founded, designed, and run by young Balinese couple from Ubud, Koman W. Suteja and Mansri Trisniawati. Firstly introduced as an art gallery specializing in high-end Balinese and Indonesian contemporary art, Komaneka is a collection of boutique resorts - each carefully created to fulfill travelers\' expectations of upscale luxury lifestyle, surrounded by Ubud\'s natural beauty or the dramatic seaside of Keramas. Designed to reflect a contemporary interpretation of traditional Balinese style and architecture, you will also be looked after by our gracious professional staff, with utmost attention to details for your ultimate Bali experience. Experience the excitement of Bali\'s cultural heritage. Choose a Komaneka resort for your home address in Bali', '<span>Komaneka Resorts 是由來自烏布的一對年輕峇里島夫妻 Koman W. Suteja 和 Mansri Trisniawati 所創立、設計並經營的。Komaneka 最初是一間專門展出高端峇里與印尼當代藝術的畫廊，如今已發展為一系列精品度假村——每一處皆精心打造，旨在實現旅人對高端奢華生活方式的期待，坐落於烏布的自然美景或克拉瑪斯壯麗海濱之間。<br>\r\n度假村設計風格融合現代詮釋的峇里傳統建築美學，並由我們親切且專業的團隊細心照料每個細節，為您打造極致的峇里島體驗。親身感受峇里豐富的文化遺產，選擇 Komaneka 度假村，作為您在峇里的理想居所。</span>', 'Komaneka Resorts 是由来自乌布的一对年轻巴厘岛夫妻 Koman W. Suteja 和 Mansri Trisniawati 创立、设计并经营的。Komaneka 最初是一个专门展示高端巴厘和印尼当代艺术的画廊，如今发展为一系列精品度假村——每一家都精心打造，旨在满足旅行者对高端奢华生活方式的期待，坐落于乌布的自然美景或克拉玛斯壮丽的海岸。<br>\r\n度假村的设计风格融合了现代诠释的传统巴厘建筑风格，由我们亲切且专业的员工用心服务，注重每一个细节，为您呈现极致的巴厘岛体验。亲身感受巴厘岛丰富的文化遗产，选择 Komaneka 度假村作为您在巴厘岛的家。', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>On-Site Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities</li></ul>', '<ul><li>免費網路</li><li>\r\n免費停車</li><li>\r\n館內餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位房卡</li><li>\r\n線上入住登記</li><li>\r\n度假型飯店</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费网络</li><li>\r\n免费停车</li><li>\r\n馆内餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字房卡</li><li>\r\n线上入住登记</li><li>\r\n度假型酒店</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>No check-in/check-out on Nyepi Day, 19 Mar 2026</li><li>No check-in/check-out on Nyepi Day, 08 March 2027</li></ul><b>Honeymoon Benefit:&nbsp;</b><ul><li>Honeymoon cake&nbsp;</li><li>In-room honeymoon flower set-up&nbsp;</li></ul><b>Children Policy:&nbsp;</b><br><ul><li>0-2 year old baby cot is free</li><li>3-5 year old sharing bed with parent inclusive of breakfast is free of charge</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2026年3月19日靜居日（Nyepi Day）當天不接受入住與退房</li><li><span style=\"color: rgb(128, 128, 128); font-size: 14.4px;\">2027 年 3 月 8 日靜居日（Nyepi Day）當天不接受入住與退房</span></li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n蜜月蛋糕</li><li>\r\n客房內蜜月花藝佈置</li></ul><span>兒童政策：<br></span><ul><li>\r\n0-2 歲嬰兒可免費提供嬰兒床</li><li>\r\n3-5 歲兒童與父母同床且包含早餐，免費入住</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2026年3月19日静居日（Nyepi Day）当天不接受入住和退房</li><li><span style=\"color: rgb(128, 128, 128); font-size: 14.4px;\">2027 年 3 月 8 日静居日（Nyepi Day）当天不接受入住和退房</span></li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n蜜月蛋糕</li><li>\r\n客房内蜜月花艺布置</li></ul><span>儿童政策：<br></span><ul><li>\r\n0-2 岁婴儿可免费提供婴儿床</li><li>\r\n3-5 岁儿童与父母同床并含早餐，免费入住</li></ul>', NULL, NULL, NULL, 'Active', '1700191186_Komaneka-Keramas.webp', 14, 'https://www.komaneka.com/keramas', '2', '360', NULL, NULL, 'https://g.page/komanekaatkeramasbeach?share', NULL, NULL, NULL, NULL, '<b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 23 Dec, 07 Jan - 31 Mar): </i><ul><li>During low season, if cancellation occurs within 14 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 7 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><b>High Season</b> <i>(01 Jul - 31 Aug, 24 Dec - 06 Jan): </i><ul><li>During high season, if cancellation occurs within 35 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 30 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><b>No Show:</b> 100% room charge will be applied for the No Show.<br>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n若於抵達日前 14 天內取消，將收取 1 晚取消費。\r\n</li>\r\n<li>\r\n若於抵達日前 7 天內取消，將收取整段住宿的全額房費。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n若於抵達日前 35 天內取消，將收取 1 晚取消費。\r\n</li>\r\n<li>\r\n若於抵達日前 30 天內取消，將收取整段住宿的全額房費。\r\n</li>\r\n</ul>\r\n未出現（No Show）：\r\n<ul>\r\n<li>\r\n將收取整段住宿的 100% 房費。</li></ul>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n若在抵达日前14天内取消，将收取1晚取消费用。\r\n</li>\r\n<li>\r\n若在抵达日前7天内取消，将收取全程住宿的房费。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n若在抵达日前35天内取消，将收取1晚取消费用。\r\n</li>\r\n<li>\r\n若在抵达日前30天内取消，将收取全程住宿的房费。\r\n</li>\r\n</ul>\r\n未出现（No Show）：\r\n<ul>\r\n<li>\r\n将收取全程住宿的100%房费。</li></ul>', NULL, '2022-11-22 07:54:50', '2026-02-04 17:49:30', 1, 1),
(50, 'Komaneka at Monkey Forest', '17', NULL, NULL, NULL, 'TTnlUlFLCweLK9XvKeJq41SAei', '17', NULL, 'Jl. Monkey Forest, Ubud, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 43, 'Putri Dharmasanti', '03614792518', '<span>Komaneka at Monkey Forest began as a residence for artists behind the prestigious Komaneka Gallery, specializing in fine contemporary Indonesian and Balinese art. Now recently renovated with luxurious suites, an infinity pool, open-air restaurant, spa, and pool villas, all in a lush garden with mature shade trees, this is a very special oasis.<br>The resort\'s location on the Monkey Forest Road gives immediate access to the Ubud market and all the cultural activities of the Ubud palace, Puri Ubud, residence of Ubud\'s ruling family. At the other end of this bustling street, lined with restaurants and boutiques, is a sacred monkey forest.</span>', 'Komaneka at Monkey Forest 最初是為藝術家打造的住所，背後是享有盛譽的 Komaneka 畫廊，專門展示印尼與峇里當代藝術精品。如今，度假村經翻新後擁有豪華套房、無邊際泳池、露天餐廳、水療中心與泳池別墅，座落於綠意盎然、樹木成蔭的花園中，是一處獨具魅力的世外桃源。<br>\r\n度假村位於猴林路（Monkey Forest Road），可即刻前往烏布市集及烏布王宮（Puri Ubud）等文化活動場所，該王宮是烏布王室的居所。這條熱鬧街道的盡頭，有著神聖的猴子森林，沿路遍布餐廳與精品店。', 'Komaneka at Monkey Forest 最初是为艺术家打造的住所，背后是享有盛誉的 Komaneka 画廊，专注于印尼与巴厘岛的当代艺术精品。如今，度假村已焕然一新，拥有豪华套房、无边泳池、露天餐厅、水疗中心和泳池别墅，坐落于绿意盎然、古树参天的花园中，是一片极为特别的静谧绿洲。<br>\r\n度假村位于猴林路（Monkey Forest Road），可便捷前往乌布市场以及乌布王宫（Puri Ubud）等文化活动中心，乌布王宫是乌布王室的居所。而这条热闹街道的另一端，则是神圣的猴子森林，街道两旁遍布餐厅与精品店。', '<ul><li>Dining</li><li>Garden Terrace Kitchen</li><li>Spa</li></ul>', '<ul><li>餐飲</li><li>\r\n花園露台廚房</li><li>\r\n水療中心</li></ul>', '<ul><li>餐饮</li><li>\r\n花园露台厨房</li><li>\r\n水疗中心</li></ul>', '<b>Seasonal Policy: </b><ul><li>No check-in/check-out on Nyepi Day, 19 Mar 2026<br>No check-in/check-out on Nyepi Day, 08 March 2027</li></ul><b>Honeymoon Benefit: </b><ul><li>Honeymoon cake </li><li>In-room honeymoon flower set-up </li></ul><b>Children Policy: </b><br><ul><li>0-2 year old baby cot is free</li><li>3-5 year old sharing bed with parent inclusive of breakfast is free of charge</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2026 年 3 月 19 日靜居日（Nyepi Day）當天不接受入住與退房</li><li>2027 年 3 月 8 日靜居日（Nyepi Day）當天不接受入住與退房</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n蜜月蛋糕</li><li>\r\n客房內蜜月花藝佈置</li></ul><span>兒童政策：<br></span><ul><li>\r\n0－2 歲嬰兒可免費提供嬰兒床</li><li>\r\n3－5 歲兒童與父母同床且含早餐，可免費入住</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2026 年 3 月 19 日静居日（Nyepi Day）当天不接受入住和退房</li><li>2027 年 3 月 8 日静居日（Nyepi Day）当天不接受入住和退房</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n蜜月蛋糕</li><li>\r\n客房内蜜月花艺布置</li></ul><span>儿童政策：<br></span><ul><li>\r\n0－2 岁婴儿可免费提供婴儿床</li><li>\r\n3－5 岁儿童与父母同床并含早餐，可免费入住</li></ul>', NULL, NULL, NULL, 'Active', '1700191264_Komaneka-Monkey-Forest.webp', 14, 'https://www.komaneka.com/monkeyforest', '2', '360', NULL, NULL, 'https://goo.gl/maps/Trh8fbh5W86jQ7gr6', NULL, NULL, NULL, NULL, '<span><b>Low Season </b><i>(01 Apr - 30 Jun, 01 Sep - 23 Dec, 07 Jan - 31 Mar): </i></span><ul><li>During low season, if cancellation occurs within 14 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 7 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>High Season</b><i> (01 Jul - 31 Aug, 24 Dec - 06 Jan): </i></span><ul><li>During high season, if cancellation occurs within 35 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 30 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>No Show:</b> 100% room charge will be applied for the No Show.</span><br>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n若於抵達日前14天內取消，將收取1晚房費作為取消費用。\r\n</li>\r\n<li>\r\n若於抵達日前7天內取消，將收取全段住宿的費用。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n若於抵達日前35天內取消，將收取1晚房費作為取消費用。\r\n</li>\r\n<li>\r\n若於抵達日前30天內取消，將收取全段住宿的費用。\r\n</li>\r\n</ul>\r\n未出現（No Show）：\r\n<ul>\r\n<li>\r\n將收取全段住宿的100%房費。</li></ul>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n若在抵达日前14天内取消，将收取1晚房费作为取消费用。\r\n</li>\r\n<li>\r\n若在抵达日前7天内取消，将收取全程住宿费用。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n若在抵达日前35天内取消，将收取1晚房费作为取消费用。\r\n</li>\r\n<li>\r\n若在抵达日前30天内取消，将收取全程住宿费用。\r\n</li>\r\n</ul>\r\n未出现（No Show）：\r\n<ul>\r\n<li>\r\n将收取全程住宿的100%房费。</li></ul>', NULL, '2022-11-22 08:06:11', '2026-02-03 00:05:07', 1, 1),
(51, 'Adiwana Resort Jembawan', '17', 'Ubud', 'Bali', 'Indonesia', 'AE3HvMFJHlJXr4Xid1F9FnCTrY', '17', 17, 'Jalan Jembawan, Ubud, Bali, Indonesia', 2, 40, 'Ira Kusumadewi', '03619083289', 'Adiwana Resort Jembawan is a boutique wellness retreat in the heart of Ubud that focuses on body, mind and spirit of rejuvenation. With its team of onsite experts, including an Ayurvedic practitioner and yoga instructor, the resort offers lifestyle programs that are tailored to address any specific health concerns you may have. Designed by Ground Kent Architect, based in Perth, the spacious rooms and suites are built with contemporary Bali in mind.&amp;amp;amp;amp;amp;nbsp;These 41 rooms property are a healing sanctuary for personal renewal with affordable solutions to many of the issues caused by trying to exist in today’s fast paced world. It is a place where guests are encouraged to slow down, eat nutritious food and return to the basics of simply living well.', 'Adiwana Resort Jembawan 是一間位於烏布心臟地帶的精品養生度假村，專注於身、心、靈的全面修復與療癒。在這裡，駐村專家團隊包含阿育吠陀醫師與瑜珈導師，度假村提供的生活方式療癒課程可依照個人健康需求量身打造。<br>\r\n由澳洲伯斯的 Ground Kent 建築事務所設計，寬敞的客房與套房展現現代峇里島風格。這家擁有 41 間客房的度假村，是一處為身心更新打造的療癒聖地，為在現今快節奏生活中感到疲憊的人們提供平價且有效的療癒方案。這裡鼓勵賓客放慢腳步，享用營養美食，回歸簡單且健康的生活本質。', 'Adiwana Resort Jembawan 是一家位于乌布中心的精品养生度假村，专注于身心灵的全面焕活与疗愈。度假村拥有专业团队，包括阿育吠陀医生和瑜伽导师，提供根据个人健康需求量身定制的生活方式疗程。<br>\r\n由位于澳大利亚珀斯的 Ground Kent 建筑事务所设计，宽敞的客房与套房融合现代巴厘岛风格。度假村拥有 41 间客房，是一个为个人更新身心而打造的疗愈圣地，提供实惠而有效的方案，帮助人们应对现代快节奏生活带来的各种问题。<br>\r\n在这里，宾客被鼓励放慢脚步，享用营养饮食，回归简单且健康的生活方式。', '<ul><li>Infinity Pool&nbsp;</li><li>Yoga Pavillion&nbsp;</li><li>Tejas Spa Jembawan&nbsp;</li><li>Herb Library&nbsp;</li><li>GYM Center&nbsp;</li></ul>', '<ul><li>無邊際泳池</li><li>\r\n瑜珈亭</li><li>\r\nTejas Spa Jembawan 水療中心</li><li>\r\nHerb Library 香草圖書館</li><li>\r\n健身中心</li></ul>', '<ul><li>无边际泳池</li><li>\r\n瑜伽亭</li><li>\r\nTejas Spa Jembawan 水疗中心</li><li>\r\nHerb Library 香草图书馆</li><li>\r\n健身中心</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>No Check in and out - seclusion day 19 March 2026 (Nyepi Day)&nbsp;</li></ul><b>Child Policy:&nbsp;</b><ul><li>Baby cots shall be supplied free of charge and must be requested at the time of reservation</li></ul><b>Honeymoon Benefits:&nbsp;</b><ul><li>Flower decoration on the bed &amp; cake&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2026 年 3 月 19 日靜居日（Nyepi Day）不接受入住與退房</li></ul><span>兒童政策：<br></span><ul><li>\r\n嬰兒床可免費提供，須於預訂時提出需求</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n床上花藝裝飾與蜜月蛋糕</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2026 年 3 月 19 日静居日（Nyepi Day）当天不接受入住和退房</li></ul><span>儿童政策：<br></span><ul><li>\r\n婴儿床可免费提供，须在预订时提出申请</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n床上花艺装饰及蜜月蛋糕</li></ul>', NULL, NULL, NULL, 'inactive', 'hotels/covers/1731990334_183732265.webp', 14, 'https://adiwanahotels.com/jembawan-resort-ubud-bali/', '2', '45', '11:00', '13:00', 'https://www.google.com/maps/place/Adiwana+Resort+Jembawan/@-8.5097384,115.2665512,19.5z/data=!4m9!3m8!1s0x2dd23d694d2ffaed:0x791a0d66f8ecc581!5m2!4m1!1i2!8m2!3d-8.5100961!4d115.2668279!16s%2Fg%2F11c3109rn1?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.5104106, 115.2676824, NULL, NULL, '<b>High Season:</b> <i>(01 Jul - 31 Aug)</i><br><b>Peak Season:</b> <i>(24 Dec - 05 Jan)&nbsp;</i><br><ul><li>Prior to 14 days for the normal season and 21 days for the high and peak season, no penalty fee</li><li>Within 14 days for the normal season and 21 days for the high and peak season, any cancellation is subject to the first night of accommodation at your daily contracted room rate for each room booked</li><li>Any amendment after check in will be 100% charged according to the initial reservation amount</li></ul>', '<span>旺季： 7月1日－8月31日<br>\r\n巔峰季： 12月24日－1月5日</span>\r\n<br><ul><li>若在平季抵達日前14天前，或在旺季與巔峰季抵達日前21天前取消，則不收取任何取消費用。</li><li>\r\n若於平季抵達日前14天內，或於旺季與巔峰季抵達日前21天內取消，則每間已預訂客房將收取1晚房費（依每日合約房價）作為取消費用。</li><li>\r\n入住後若有任何更動（如縮短住宿），將依原始預訂金額收取100%費用。</li></ul>', '<span>旺季： 7月1日－8月31日<br>\r\n高峰季： 12月24日－1月5日</span>\r\n<br><ul><li>若在普通季节抵达日前14天前，或在旺季与高峰季抵达日前21天前取消，不收取任何取消费用。</li><li>\r\n若在普通季节抵达日前14天内，或在旺季与高峰季抵达日前21天内取消，则每间已预订客房将收取1晚房费（按每日合同价）作为取消费用。</li><li>\r\n入住后如有任何更改（如缩短住宿），将按原始预订金额收取100%费用。</li></ul>', NULL, '2022-11-26 08:45:49', '2026-03-25 19:00:25', 1, 2),
(52, 'Sthala Ubud Bali', '17', NULL, NULL, NULL, 'xEIPy4hpf4CFhuMs4YAQvqQCDM', '17', NULL, 'Jalan A.A Gede Rai, Jl. Raya Mawang Kelod, Lodtunduh, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 30, 'Dwi Janana', '03613018700', 'Enjoy rich cultural experiences and authentic Indonesian hospitality at Sthala, a Tribute Portfolio Hotel, Ubud Bali. Tucked among the lush hills and dense forests along the Wos River, our Ubud hotel offers boutique luxury accommodations showcasing a beautiful, locally inspired design, Balinese art, and complimentary Wi-Fi. Visit our hotel spa for a restorative massage or facial, and take a dip in&nbsp;our infinity pool. Stay active with riverside yoga or a Balinese dance class. Enjoy Balinese and Western cuisine in our open-air restaurant overlooking the Ubud forest or sip cocktails in our hotel\'s rooftop bar with panoramic views of Lodtunduh. Our hotel in Ubud, Bali, offers light-filled venues as well as scenic, outdoor spaces for your next event. Discover Bali\'s many wonders near our hotel, from Ubud Monkey Forest to Bali Zoo and the historic Ubud Palace.', '在 Sthala, a Tribute Portfolio Hotel, Ubud Bali 體驗豐富的文化活動與正宗的印尼式待客之道。這家位於烏布的飯店隱身於 Wos 河沿岸鬱鬱蔥蔥的山丘與茂密森林之中，提供兼具精品奢華與在地靈感設計的住宿空間，融合峇里藝術風格，並提供免費無線上網服務。<br>\r\n造訪飯店水療中心，享受放鬆的按摩或臉部護理，或在無邊際泳池中暢泳。您也可參加河畔瑜珈或峇里舞蹈課程保持活力。在我們的露天餐廳享用峇里與西式料理，欣賞烏布森林景觀，或在飯店屋頂酒吧啜飲雞尾酒，眺望 Lodtunduh 的壯麗全景。<br>\r\n我們的飯店設有採光良好的會議空間及美麗的戶外場地，是舉辦活動的理想選擇。從烏布猴林、峇里動物園到歷史悠久的烏布皇宮，探索飯店周邊的峇里島魅力。', '在 Sthala, a Tribute Portfolio Hotel, Ubud Bali 享受丰富的文化体验和正宗的印尼式热情款待。我们的乌布酒店坐落在 Wos 河沿岸郁郁葱葱的山丘与茂密森林之间，提供精品奢华的住宿空间，展现本地灵感设计和峇里艺术，并提供免费无线网络。<br>\r\n欢迎前往酒店水疗中心享受舒缓按摩或面部护理，也可以在无边泳池中畅游。您还可以通过河畔瑜伽或峇里传统舞蹈课程保持活力。在我们开放式餐厅中品尝峇里与西式美食，俯瞰乌布森林，或在酒店屋顶酒吧中，边啜饮鸡尾酒边欣赏 Lodtunduh 的全景美景。<br>\r\n我们位于乌布的酒店提供采光良好的会议空间与风景如画的户外场地，非常适合举办各类活动。从乌布猴林、峇里岛动物园到历史悠久的乌布皇宫，探索我们酒店周边的众多巴厘岛魅力。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>No compulsory dinner or lunch on Christmas Eve/Day or New Year\'s Eve/Day&nbsp;</li><li>No check out on the date of 31 December.&nbsp;</li><li>Check in 31 December is allowed&nbsp;</li></ul><b>Child Policy:&nbsp;</b><br><ul><li>No charge for children under 12 years when occupying same room as adult(s) &amp; using existing beds in rooms.</li><li>Buffet Breakfast for children under 12 years is free.</li><li>1 baby cot is provided free of charge (including breakfast) for a maximum of 1 infant.</li></ul><b>Honeymoon Benefits:&nbsp;<br></b><ul><li>Towel art, room decoration with flower and honeymoon cake</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n平安夜／聖誕節或跨年夜／元旦當天無需參加強制性午餐或晚餐</li><li>\r\n12月31日當天不可退房，但可辦理入住</li></ul><span>兒童政策：<br></span><ul><li>\r\n12歲以下兒童與成人同住且使用現有床位者，免收住宿費</li><li>\r\n12歲以下兒童享用自助早餐免費</li><li>\r\n最多提供1張嬰兒床（含早餐），免費供1名嬰兒使用</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n毛巾藝術、客房花藝佈置與蜜月蛋糕</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n平安夜／圣诞节或跨年夜／元旦当天无须参加强制性午餐或晚餐</li><li>\r\n12月31日当天不可退房，但可办理入住</li></ul><span>儿童政策：<br></span><ul><li>\r\n12岁以下儿童与成人同住且使用现有床位者，免收住宿费</li><li>\r\n12岁以下儿童享用自助早餐免费</li><li>\r\n最多提供1张婴儿床（含早餐），免费供1名婴儿使用</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n毛巾艺术、客房鲜花布置与蜜月蛋糕</li></ul>', NULL, NULL, NULL, 'Active', '1759195237_caption.jpg', 2, 'https://www.marriott.com/en-us/hotels/dpstp-sthala-a-tribute-portfolio-hotel-ubud-bali/overview/?scid=f2ae0541-1279-4f24-b197-a979c79310b0', '2', '45', NULL, NULL, 'https://goo.gl/maps/HsVYfNgctqsFFFqm7', NULL, NULL, NULL, NULL, '<ul><li>During regular season, if cancellation occurs within 72 hours of arrival, a one-night cancellation fee will be assessed. If cancellation occurs within 24 hours of arrival, a full charge for the entire length of stay will be assessed.</li></ul><ul><li>During high season <i>(01 Jul - 31 Aug)</i>, if cancellation occurs within 14 days of arrival, a one-night cancellation fee will be assessed. If cancellation occurs within 7 days of arrival, a full charge for the entire length of stay will be assessed.</li></ul><ul><li>During peak season <i>(23 Dec - 05 Jan)</i>, if cancellation occurs within 30 days of arrival, a full charge for the entire length of stay will be assessed.</li></ul><b>No Show:</b> If a no-show occurs, a full charge for the entire length of stay will be assessed.<br>', '<ul><li>在平季期間，若於抵達前72小時內取消，將收取1晚房費作為取消費用；若於抵達前24小時內取消，將收取全段住宿的費用。</li></ul><ul><li>\r\n在旺季期間（7月1日－8月31日），若於抵達前14天內取消，將收取1晚房費；若於抵達前7天內取消，將收取全段住宿的費用。</li></ul><ul><li>\r\n在巔峰季期間（12月23日－1月5日），若於抵達前30天內取消，將收取全段住宿的費用。</li></ul>\r\n若未入住（No Show），將收取全段住宿的費用。', '<ul><li>在平季期间，若在抵达前72小时内取消，将收取1晚房费作为取消费用；若在抵达前24小时内取消，将收取全程住宿费用。</li><li>\r\n在旺季期间（7月1日－8月31日），若在抵达前14天内取消，将收取1晚房费；若在抵达前7天内取消，将收取全程住宿费用。</li><li>\r\n在高峰季期间（12月23日－1月5日），若在抵达前30天内取消，将收取全程住宿费用。</li></ul>\r\n若未入住（No Show），将收取全程住宿费用。', NULL, '2022-11-26 09:29:16', '2025-09-29 17:20:37', 2, 1),
(53, 'The Club Villas Seminyak', '17', NULL, NULL, NULL, '3vuMEEc1odi7VcI9tPkXwM3ZJp', '17', NULL, 'Jln. Kayu Aya (Oberoi),  Seminyak, Bali', 1, 12, 'Mardian Putra', '62361736260', 'The Club Villas Seminyak provides a luxurious and private escape in the vibrant area of Seminyak, Bali. With beautifully designed villas, modern amenities, and exceptional service, it promises an unforgettable stay whether you are visiting for a romantic getaway, a family vacation, or a wellness retreat.', 'The Club Villas Seminyak 坐落於峇里島熱鬧的水明漾區，提供豪華且私密的度假體驗。擁有設計優雅的別墅、現代化的設施，以及卓越的服務，無論您是為了浪漫之旅、家庭度假或養生靜修而來，都將享有一段難忘的時光。', 'The Club Villas Seminyak 坐落于巴厘岛热闹的水明漾区，提供豪华而私密的度假体验。配备精美设计的别墅、现代化设施以及卓越的服务，无论您是来享受浪漫之旅、家庭假期或健康养生之旅，都能收获一段难忘的时光。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Minimum stay 3 nights during peak season NY Eve (27 Dec - 05 Jan)</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n跨年巔峰季期間（12月27日－1月5日）最少需入住 3 晚</li></ul>', '<span>季节性政策：<br></span><ul><li>跨年高峰季期间（12月27日－1月5日）最少需入住 3 晚</li></ul><div><div></div></div><div><div><div></div></div></div><div><div></div></div><div><div></div></div>', NULL, NULL, NULL, 'Active', '1737015437_WhatsApp Image 2025-01-16 at 15.45.52.jpeg', 14, 'https://theclubvillaseminyak.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/SaxkVaCx362vdvuEA', NULL, NULL, NULL, NULL, '<span><b>Regular Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 22 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 30% from the total booking or 1 night charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 30% from the total booking or 1 night charge</li><li>Cancellation made within 14 - 8 days to arrival : 50% from the total booking or full charge for booking 1 night&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>High Season</b> <i>(01 Jul - 31 Aug, 23 - 26 Dec) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 01 night charge</li><li>Cancellation made within 21 - 15 days to arrival : 50% of total length of stay</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>Peak Season</b> <i>(27 Dec - 05 Jan) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul>', '平季（4月1日－6月30日、9月1日－12月22日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達前 60－22 天取消：收取總預訂金額的 30% 或 1 晚房費（以較高者為準）\r\n</li>\r\n<li>\r\n抵達前 21－15 天取消：收取總預訂金額的 30% 或 1 晚房費（以較高者為準）\r\n</li>\r\n<li>\r\n抵達前 14－8 天取消：收取總預訂金額的 50% 或如預訂僅 1 晚則收取全額\r\n</li>\r\n<li>\r\n抵達前 7－1 天取消：收取總預訂金額的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的 100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月23日－26日）：\r\n<ul>\r\n<li>\r\n抵達前 60－22 天取消：收取 1 晚房費\r\n</li>\r\n<li>\r\n抵達前 21－15 天取消：收取整段住宿費用的 50%\r\n</li>\r\n<li>\r\n抵達前 14－8 天取消：收取總預訂金額的 100%\r\n</li>\r\n<li>\r\n抵達前 7－1 天取消：收取總預訂金額的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的 100%\r\n</li>\r\n</ul>\r\n巔峰季（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達前 60－22 天取消：收取總預訂金額的 100%\r\n</li>\r\n<li>\r\n抵達前 21－15 天取消：收取總預訂金額的 100%\r\n</li>\r\n<li>\r\n抵達前 14－8 天取消：收取總預訂金額的 100%\r\n</li>\r\n<li>\r\n抵達前 7－1 天取消：收取總預訂金額的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的 100%\r\n</li>\r\n</ul>', '平季（4月1日－6月30日、9月1日－12月22日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达前 60－22 天取消：收取总预订金额的 30% 或 1 晚房费（以较高者为准）\r\n</li>\r\n<li>\r\n抵达前 21－15 天取消：收取总预订金额的 30% 或 1 晚房费（以较高者为准）\r\n</li>\r\n<li>\r\n抵达前 14－8 天取消：收取总预订金额的 50% 或如仅预订 1 晚则收取全额\r\n</li>\r\n<li>\r\n抵达前 7－1 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的 100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月23日－26日）：\r\n<ul>\r\n<li>\r\n抵达前 60－22 天取消：收取 1 晚房费\r\n</li>\r\n<li>\r\n抵达前 21－15 天取消：收取全程住宿费用的 50%\r\n</li>\r\n<li>\r\n抵达前 14－8 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 7－1 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的 100%\r\n</li>\r\n</ul>\r\n高峰季（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达前 60－22 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 21－15 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 14－8 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 7－1 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的 100%</li></ul>', NULL, '2022-11-26 09:52:03', '2025-06-29 19:00:58', 1, 1),
(54, 'Adiwana Monkey Forest', '17', 'Ubud', 'Bali', 'Indonesia', 'iVSvH97DCVKPGPiOCVcbOJ9vfl', '17', 17, 'Jalan Bisma, Ubud, Bali, Indonesia', 2, 43, 'Mr. Bayu', '0361975231', 'The Monkey Forest area has always been referred to as the beating heart of Ubud. It captures the essence of Tri Hita Karana that believes that in order to reach the ultimate well-being, one must live harmoniously with other people, with nature, and with God. Strategically located within the area, Adiwana Monkey Forest offers the perfect Bali getaway. The 21 suites are beautifully designed to showcase the artistic Balinese craftsmanship while maintaining a contemporary feel.&amp;amp;amp;nbsp;', '猴林地區一直被譽為烏布的心臟地帶。它完美體現了「三和諧」（Tri Hita Karana）的精神，這一理念認為，唯有與他人、與自然以及與神保持和諧共處，才能達到真正的身心安頓。Adiwana Monkey Forest 座落於該地區的絕佳位置，是前往峇里島度假的理想選擇。<br>\r\n這裡擁有 21 間套房，設計精美，展現峇里島精緻的傳統工藝，同時保有現代感的設計風格。', '猴林地区一直被誉为乌布的心脏地带。它完美体现了“三和谐”（Tri Hita Karana）的理念，该理念认为，唯有与他人、与自然以及与神保持和谐共处，才能实现真正的身心安宁。Adiwana Monkey Forest 地理位置优越，是理想的巴厘岛度假选择。<br>\r\n酒店拥有 21 间设计精美的套房，既展现了巴厘岛传统工艺的艺术之美，又融合了现代感。', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities&nbsp;&nbsp; &nbsp;</li></ul>', '<ul><li>免費網路</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位房卡</li><li>\r\n線上入住</li><li>\r\n度假型物業</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费网络</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字房卡</li><li>\r\n线上入住</li><li>\r\n度假型物业</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>No Check In and Check Out on – seclusion day 19 March 2026 (Nyepi Day)</li></ul>', '季節性政策：<br><ul><li>\r\n2026年3月19日靜居日（Nyepi Day）當天不接受入住與退房</li></ul>', '季节性政策：<br><ul><li>\r\n2026年3月19日静居日（Nyepi Day）当天不接受入住和退房</li></ul>', NULL, NULL, NULL, 'inactive', 'hotels/covers/1700191570_Adiwana-Monkey-Forest.webp', 14, 'https://adiwanahotels.com/monkey-forest-resort-ubud-bali/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Adiwana+Monkey+Forest/@-8.5131354,115.2583127,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd23d6d262dc895:0x8c375cb7eb34329e!5m2!4m1!1i2!8m2!3d-8.5131407!4d115.2608876!16s%2Fg%2F11f5bp4m65?entry=ttu&g_ep=EgoyMDI2MDMxOC4xIKXMDSoASAFQAw%3D%3D', -8.5133734, 115.2608718, NULL, NULL, '<b>High Season:</b>&nbsp;(<i>01 Jul - 31 Aug)</i><br><b>Peak Season:</b>&nbsp;(<i>24 Dec - 05 Jan)&nbsp;</i><ul><li>Prior to 7 days for the normal season and 14 days for high and peak season, no penalty fee&nbsp;</li><li>Within 7 days for the normal season and 14 days for high and peak season any cancellation is subject to the first night of accommodation at your daily contracted room rate for each room booked</li><li>Post-check-in/No Show Post check-in, early check-out, or no-show will incur a full cancellation fee equaling to the total accommodation charge for the intended duration of stay for each room canceled&nbsp;&nbsp;</li></ul>', '<span>旺季： 7月1日－8月31日<br>\r\n巔峰季： 12月24日－1月5日</span>\r\n<br><ul><li>若於平季抵達日前 7 天前、或於旺季與巔峰季抵達日前 14 天前取消預訂，將不收取任何取消費用。</li><li>\r\n若於平季抵達日前 7 天內、或於旺季與巔峰季抵達日前 14 天內取消預訂，則每間已預訂客房將收取一晚房費（依每日合約房價）作為取消費用。</li><li>入住後修改／未入住：若於入住後修改、提前退房，或未入住（No Show），將收取每間房間原定住宿期間的全額費用作為取消費。</li></ul>', '<span>旺季： 7月1日－8月31日<br>\r\n高峰季： 12月24日－1月5日</span>\r\n<br><ul><li>若在普通季节抵达日前 7 天前，或在旺季与高峰季抵达日前 14 天前取消预订，则不收取任何取消费用。</li><li>\r\n若在普通季节抵达日前 7 天内，或在旺季与高峰季抵达日前 14 天内取消预订，则每间已预订客房将收取一晚房费（按每日合同价）作为取消费用。</li><li>入住后修改／未入住：如在入住后修改、提前退房或未入住（No Show），将收取每间房原定入住期间的全额房费作为取消费用。</li></ul>', NULL, '2022-11-26 10:17:33', '2026-03-25 18:57:33', 1, 2),
(55, 'Capella Ubud', '17', 'Keliki', 'Bali', 'Indonesia', 'wDof2qHDqUZjNRs5KN14VtMy0t', '17', 17, 'Jalan Raya Dalem, Keliki, Bali, Indonesia', 2, 49, 'Isma Suryani', '03612091888', '<p>Nestled in the heart of lush green forests, our unique tented camp sits in harmony with the surrounding nature. Inspired by the early European settlers from the 1800s, architect Bill Bensley designed Capella Ubud, Bali as a tribute to their spirit of adventure.</p>', NULL, NULL, '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities</li></ul>', NULL, NULL, '<p><strong>Children Policy :</strong>&nbsp;</p><ul><li>The river tents and Keliki Valley tents are not suitable for families with infants and children below the age of 10</li><li>The child and 1 infant can stay free of charge with the parents using the tent’s existing bedding configuration according to maximum bedding capacity stated below, breakfast included</li><li>A cot for infants is provided with our compliments.</li><li>A child is defined as a person between the ages of 4-12 years’ old, whereas an infant is defined as a person below the age of 4 years’ old.&nbsp;</li></ul><p><strong>Honeymoon Amenity :&nbsp;</strong></p><p>Honeymoon cake, one flower bath and one bouquet of flowers await the couple - once during their stay&nbsp;</p><p><strong>Anniversary Amenity :&nbsp;</strong></p><p>Two Tridatu bracelets and one anniversary cake await the couple - once during the guest\'s stay&nbsp;</p><p><strong>Birthday Amenity :&nbsp;</strong></p><p>One birthday cake and a special surprise await the guset - once during the guest\'s stay&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1700191668_Capella-Ubud.webp', 14, 'https://capellahotels.com/en/capella-ubud', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Capella+Ubud,+Bali/@-8.4482038,115.2655368,17z/data=!4m20!1m10!3m9!1s0x2dd2232a33674863:0x25093ef92f99017c!2sCapella+Ubud,+Bali!5m2!4m1!1i2!8m2!3d-8.4482091!4d115.2681117!16s%2Fg%2F11g0h_r0wd!3m8!1s0x2dd2232a33674863:0x25093ef92f99017c!5m2!4m1!1i2!8m2!3d-8.4482091!4d115.2681117!16s%2Fg%2F11g0h_r0wd?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.4488974, 115.2687674, NULL, NULL, '<p><strong>Low Season:</strong></p><ul><li>Cancellation within 15 days prior to the arrival : no charge&nbsp;</li><li>Cancellation between&nbsp;14 &amp; 8 days prior to the arrival : 1 night charge</li><li>Cancellation within 7 days prior to the arrival&nbsp;: 100% charge&nbsp;</li></ul><p><strong>Shoulder Season:</strong></p><ul><li>Cancellation within 22 days prior to the arrival : No charge&nbsp;</li><li>Cancellation between 21 &amp; 15 days prior to the arrival : 1 night charge</li><li>Cancellation within 14 days prior to the arrival : 100% charge&nbsp;</li></ul><p><strong>High / Peak Season:</strong></p><ul><li>Cancellation within 46 days prior to the arrival : No charge&nbsp;</li><li>Cancellation between 45 &amp; 31 days prior to the arrival : 1 night&nbsp;charge&nbsp;</li><li>Cancellation within 30 days prior to the arrival : 100% charge&nbsp;</li></ul><p><strong>No Show:&nbsp;</strong>100% charge&nbsp;</p>', NULL, NULL, NULL, '2022-11-26 12:12:00', '2026-03-25 19:27:08', 1, 2);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(56, 'Kappa Senses Ubud', '17', NULL, NULL, NULL, 'Ou4g8w4yeMzlCP27UtutEO5uOr', '17', NULL, 'Banjar Tanggayuda, Jalan Taman Sari, Kedewatan, Ubud, Gianyar Bali 80571, Indonesia', 2, 45, 'Santi Triana', '03612013888', 'At Kappa Senses Ubud, experience divine moments in the land of the gods, in an upscale, environmentally and socially responsible setting. Travel to one of the most coveted islands of the planet and immerse yourself amidst verdant rice fields, whose charm and beauty unfailingly astonish you. Dive into the romantic and passionate world of Rama and Shinta, the Balinese Romeo and Juliet. Whether you are looking for a place to reclaim your inner peace, or a hideaway haven in the midst of a lush jungle, come with an open heart and return forever changed by this enchanting destination and meaningful experiences.', '在 Kappa Senses Ubud，於眾神之島體驗神聖的時刻，享受高端、環保且社會責任感十足的氛圍。踏上全球最令人嚮往的島嶼之一，沉浸於翠綠稻田之中，其迷人與美麗總能令人驚嘆不已。探索羅摩與悉多（Rama 與 Shinta）的浪漫愛情故事——峇里島版的羅密歐與茱麗葉。無論您是在尋找重拾內心平靜的地方，還是在鬱鬱蔥蔥的叢林中尋覓一處靜謐天堂，請帶著一顆敞開的心前來，讓這個迷人的目的地與充滿意義的體驗，永遠改變您的生命旅程。', '在 Kappa Senses Ubud，于众神之岛体验神圣时刻，享受高端、环保且具社会责任感的环境。踏上全球最令人向往的岛屿之一，沉浸在郁郁葱葱的稻田之间，其魅力与美丽总是令人惊艳不已。探索罗摩与悉多（Rama 与 Shinta）的浪漫世界——巴厘岛的罗密欧与朱丽叶。无论您是想找回内心的宁静，还是在茂密丛林中寻找一处世外桃源，请带着一颗敞开的心前来，让这个迷人的目的地与意义非凡的体验，永远改变您的生命旅程。', '<ul><li>Daily Kappa Senses’ instant as per resort’s schedule</li><li>Shuttle service to a designated area in Ubud town based on the resort’s schedule</li><li>Wi-Fi in rooms and throughout the resort</li><li>Use of the gym and two resort’s swimming pool</li></ul>', '<ul><li>每日依照度假村行程安排的 Kappa Senses 活動體驗</li><li>\r\n依度假村固定時刻表提供接駁服務，往返烏布市區指定地點</li><li>\r\n客房及整個度假村範圍內皆提供無線網路</li><li>\r\n可使用健身房及度假村內兩座游泳池</li></ul>', '<ul><li>每日根据度假村行程安排的 Kappa Senses 活动体验</li><li>\r\n根据度假村固定时间表提供前往乌布镇指定区域的接驳服务</li><li>\r\n客房及整个度假村范围内提供无线网络</li><li>\r\n可使用健身房及度假村内两座游泳池</li></ul>', '<b>Seasonal Policy:&nbsp;<br></b><ul><li>Check-in and check-out is not permitted on Balinese silent day – Nyepi: between 6.00am on Thursday, 19th March \r\n2026 to 6.00am on Friday, 20th March 2026.&nbsp;</li><li>Check out on 31st December is not permitted.&nbsp;</li><li>Departure on 31st December is not permitted.&nbsp;</li><li>There is a compulsory gala dinner on New Year’s eve – 31st December (Price at additional charge)</li></ul><b>Children Policy:&nbsp;</b><br><ul><li>Baby cot/crib will be provided on complimentary basis. Baby cot is limited and will be subject to availability at time of \r\nbooking.&nbsp;&nbsp;</li></ul><b>Honeymoon Amenities:</b><br>All honeymoon guests will receive complimentary amenities as following:<br><ul><li>A box of home-made treats.&nbsp;</li></ul><ul><li>Honeymoon decoration in the room upon arrival.&nbsp;</li></ul>Honeymoon amenities are valid throughout the contracting period and are combinable with all rates and promotions. <br>Proof of marriage within 6 months must be presented at the time of booking.<br>', '<span>季節性政策：<br></span><ul><li>\r\n於峇里島靜居日（Nyepi）期間，2026 年 3 月 19 日（星期四）上午 6:00 至 3 月 20 日（星期五）上午 6:00，不允許辦理入住與退房。</li><li>12 月 31 日當天不允許退房與離店。</li><li>12 月 31 日需參加強制性跨年晚宴（需額外收費）。</li></ul><span>兒童政策：<br></span><ul><li>\r\n可免費提供嬰兒床／嬰兒搖籃。數量有限，需視預訂時可用情況而定。</li></ul><span>蜜月禮遇：<br>\r\n所有蜜月賓客可享以下免費禮遇：</span>\r\n<br>\r\n<ul><li>一盒手工點心</li><li>入住當日客房蜜月佈置</li></ul><div>蜜月禮遇適用於整個合約期間，並可與所有房價及促銷活動合併使用。</div>\r\n預訂時需出示六個月內的結婚證明。<br>', '<span>季节性政策：<br></span><ul><li>\r\n在巴厘岛静居日（Nyepi）期间，2026 年 3 月 19 日（星期四）上午 6:00 至 3 月 20 日（星期五）上午 6:00，不允许办理入住与退房。</li><li>12 月 31 日当天不允许退房和离店。</li><li>12 月 31 日须参加强制性的跨年晚宴（需额外收费）。</li></ul><span>儿童政策：<br></span><ul><li>\r\n婴儿床／婴儿摇篮可免费提供，数量有限，须视预订时供应情况而定。</li></ul><span>蜜月礼遇：<br>\r\n所有蜜月宾客可享受以下免费礼遇：</span>\r\n<br>\r\n<ul><li>一盒手工甜点</li><li>入住当天房间蜜月装饰</li></ul>\r\n<span>\r\n蜜月礼遇在整个合约期间有效，可与所有房价和促销活动同时使用。<br>\r\n预订时需提供六个月内的结婚证明。</span><br>', NULL, NULL, NULL, 'Active', '1700191741_Kappa-Senses-Ubud.webp', 14, 'https://www.kappasenses.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/rdKiL45N5Rcyoin2A', NULL, NULL, NULL, NULL, '<span><b>Season 1 (Low / Shoulder Season)</b><i>&nbsp;(01 Apr - 14 Jul, 16 Sep - 20 Dec, 09 Jan - 31 Mar):&nbsp;&nbsp;</i></span><ul><li>Bookings cancelled between 14 days and 8 days prior to arrival date will incur cancellation charges equal to one-night accommodation.</li><li>Bookings cancelled within 7 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.&nbsp;</li></ul><span><b>Season 2 &amp; 3 (High &amp; Peak Season)</b>&nbsp;<i>(15 Jul - 15 Sep, 21 Dec - 08 Jan):&nbsp;</i></span><ul><li><b></b>Bookings cancelled between 45 days and 31 days prior to arrival date will incur cancellation charges equal to onenight accommodation.</li><li>Bookings cancelled within 30 days of the date of arrival will incur cancellation charges equal to 100% of the total booking.&nbsp;</li></ul>', '<span>第1季（淡季／肩季）：<br>\r\n（4月1日－7月14日、9月16日－12月20日、1月9日－3月31日）</span>\r\n<ul>\r\n<li>\r\n於抵達日前14日至8日內取消預訂，將收取相當於一晚住宿費用的取消費。\r\n</li>\r\n<li>\r\n於抵達日前7日內取消預訂，將收取總預訂金額100%的取消費。\r\n</li>\r\n</ul>\r\n<span>第2與第3季（旺季與巔峰季）：<br>\r\n（7月15日－9月15日、12月21日－1月8日）</span>\r\n<ul>\r\n<li>\r\n於抵達日前45日至31日內取消預訂，將收取相當於一晚住宿費用的取消費。\r\n</li>\r\n<li>\r\n於抵達日前30日內取消預訂，將收取總預訂金額100%的取消費。</li></ul>', '<span>第1季（淡季／肩季）：<br>\r\n（4月1日－7月14日、9月16日－12月20日、1月9日－3月31日）</span>\r\n<ul>\r\n<li>\r\n在抵达日前14日至8日内取消预订，将收取相当于一晚房费的取消费用。\r\n</li>\r\n<li>\r\n在抵达日前7日内取消预订，将收取总预订金额100%的取消费用。\r\n</li>\r\n</ul>\r\n<span>第2与第3季（旺季与高峰季）：<br>\r\n（7月15日－9月15日、12月21日－1月8日）</span>\r\n<ul>\r\n<li>\r\n在抵达日前45日至31日内取消预订，将收取相当于一晚房费的取消费用。\r\n</li>\r\n<li>\r\n在抵达日前30日内取消预订，将收取总预订金额100%的取消费用。</li></ul>', NULL, '2022-11-26 13:10:19', '2025-09-23 22:52:54', 1, 1),
(57, 'Komaneka at Tanggayuda', '17', NULL, NULL, NULL, 'ocGzcbYCyCQgpPjaPfpK7dhnoD', '17', NULL, 'Br. Tanggayuda, Kedewatan, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 44, 'Putri Dharmasanti', '03610978123', 'Komaneka at Tanggayuda, established in 2001, is a quiet resort of almost 2 hectares, beautifully situated amidst tropical forest at the edge of a neighboring village, with views to the sacred volcano, Mount Batukaru, and the Oos River. At a slightly higher elevation than Ubud, the air is fresh and invigorating.', 'Komaneka at Tanggayuda 成立於 2001 年，是一處佔地近 2 公頃的靜謐度假村，優雅地座落於鄰近村莊邊緣的熱帶森林中，可遠眺神聖的峇都卡魯山（Mount Batukaru）與烏斯河（Oos River）。<br>\r\n度假村位於比烏布稍高的海拔，因此空氣更加清新宜人、令人精神振奮。', 'Komaneka at Tanggayuda 成立于 2001 年，是一个占地近 2 公顷的宁静度假村，坐落于邻近村庄边缘的热带森林中，优美地俯瞰神圣的巴图卡鲁山（Mount Batukaru）和乌斯河（Oos River）。<br>\r\n度假村海拔略高于乌布，空气清新怡人，令人精神焕发。', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities    </li></ul>', '<ul><li>免費無線上網</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位房卡</li><li>\r\n線上入住</li><li>\r\n度假型物業</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费无线网络</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字房卡</li><li>\r\n线上入住</li><li>\r\n度假型物业</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy: </b><ul><li>No check-in/check-out on Nyepi Day,19 Mar 2026</li><li>No check-in/check-out on Nyepi Day, 08 March 2027</li></ul><b>Honeymoon Benefit: </b><ul><li>Honeymoon cake </li><li>In-room honeymoon flower set-up </li></ul><b>Children Policy: </b><br><ul><li>0-2 year old baby cot is free</li><li>3-5 year old sharing bed with parent inclusive of breakfast is free of charge</li></ul>', '<p><span>季節性政策：<br>\r\n2026年3月19日靜居日（Nyepi Day）當天不接受入住與退房</span></p><p><span style=\"color: rgb(40, 40, 40); font-size: 1rem;\">2027 年 3 月 8 日靜居日（Nyepi Day）當天不接受入住與退房</span></p><p>蜜月禮遇：\r\n</p><ul>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n<li>\r\n客房內蜜月花藝佈置\r\n</li>\r\n</ul><p>\r\n兒童政策：\r\n</p><ul>\r\n<li>\r\n0－2歲嬰兒可免費提供嬰兒床\r\n</li>\r\n<li>\r\n3－5歲兒童與父母同床，含早餐免費\r\n</li>\r\n</ul>', '<p><span>季节性政策：<br>\r\n2026年3月19日静居日（Nyepi Day）当天不接受入住和退房</span></p><p><span style=\"color: rgb(40, 40, 40); font-size: 1rem;\">2027 年 3 月 8 日静居日（Nyepi Day）当天不接受入住和退房</span></p><p>蜜月礼遇：\r\n</p><ul>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n<li>\r\n客房内蜜月鲜花布置\r\n</li>\r\n</ul><p>\r\n儿童政策：\r\n</p><ul>\r\n<li>\r\n0－2岁婴儿可免费提供婴儿床\r\n</li>\r\n<li>\r\n3－5岁儿童与父母同床，含早餐免费</li></ul>', NULL, NULL, NULL, 'Active', '1700191808_Komaneka-Tanggayuda.webp', 14, 'https://tanggayuda.komaneka.com/', '2', '360', NULL, NULL, 'https://goo.gl/maps/3RFD6Bi1bCnRs4Kf9', NULL, NULL, NULL, NULL, '<span><b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 23 Dec, 07 Jan - 31 Mar): </i></span><ul><li>During low season, if cancellation occurs within 14 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 7 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>High Season</b> <i>(01 Jul - 31 Aug, 24 Dec - 06 Jan): </i></span><ul><li>During high season, if cancellation occurs within 35 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 30 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>No Show:</b> 100% room charge will be applied for the No Show.</span><br>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n若於抵達日前14天內取消，將收取一晚取消費用。\r\n</li>\r\n<li>\r\n若於抵達日前7天內取消，將收取全段住宿費用。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n若於抵達日前35天內取消，將收取一晚取消費用。\r\n</li>\r\n<li>\r\n若於抵達日前30天內取消，將收取全段住宿費用。\r\n</li>\r\n</ul>\r\n未入住（No Show）：\r\n<ul>\r\n<li>\r\n將收取100%全額房費作為違約金。</li></ul>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n若在抵达日前14天内取消，将收取一晚取消费用。\r\n</li>\r\n<li>\r\n若在抵达日前7天内取消，将收取全程住宿费用。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n若在抵达日前35天内取消，将收取一晚取消费用。\r\n</li>\r\n<li>\r\n若在抵达日前30天内取消，将收取全程住宿费用。\r\n</li>\r\n</ul>\r\n未入住（No Show）：\r\n<ul>\r\n<li>\r\n将收取100%全额房费作为违约金。</li></ul>', NULL, '2022-11-27 07:36:27', '2026-02-02 19:45:40', 1, 1),
(58, 'Komaneka at Bisma', '17', NULL, NULL, NULL, 'DiVFq9W5lqwbM7BFTPmBorZGVK', '17', NULL, 'Jl. Bisma, Ubud, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 43, 'Putri Dharmasanti', '0361971933', 'This five-hectare resort built in 2008 was the first luxury boutique resort in the up-and-coming area on Bisma Lane near the center of Ubud. Set on a slope overlooking the Campuhan river valley, the suites and villas have splendid views of a tropical forest valley and the resort\'s own rice fields. A sophisticated Ubud getaway near the center of town.', '這座佔地五公頃的度假村建於2008年，是位於烏布市中心附近 Bisma 巷新興地區的第一家奢華精品度假村。度假村座落於俯瞰 Campuhan 河谷的山坡上，套房與別墅擁有熱帶雨林山谷以及度假村自家稻田的壯麗景觀，是一處極具品味的烏布市中心近郊靜謐度假地。', '这座占地五公顷的度假村建于2008年，是位于乌布市中心附近 Bisma 巷新兴区域的第一家奢华精品度假村。度假村坐落于俯瞰 Campuhan 河谷的山坡上，套房和别墅可欣赏热带雨林山谷以及度假村自有稻田的壮丽景观，是靠近市中心的高品质乌布度假胜地。', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities    </li></ul>', '<ul><li>免費無線上網</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位房卡</li><li>\r\n線上入住</li><li>\r\n度假型物業</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费无线网络</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字房卡</li><li>\r\n线上入住</li><li>\r\n度假型物业</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>No check-in/check-out on Nyepi Day,19 Mar 2026</li><li>No check-in/check-out on Nyepi Day, 08 March 2027</li></ul><b>Honeymoon Benefit:&nbsp;</b><ul><li>Honeymoon cake&nbsp;</li><li>In-room honeymoon flower set-up&nbsp;</li></ul><b>Children Policy:&nbsp;</b><br><ul><li>0-2 year old baby cot is free</li><li>3-5 year old sharing bed with parent inclusive of breakfast is free of charge</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2026年3月19日靜居日（Nyepi Day）當天不接受入住與退房。</li><li>2027 年 3 月 8 日靜居日（Nyepi Day）當天不接受入住與退房</li></ul>蜜月禮遇：\r\n<ul>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n<li>\r\n客房內蜜月花藝佈置\r\n</li>\r\n</ul>\r\n兒童政策：\r\n<ul>\r\n<li>\r\n0－2歲嬰兒可免費提供嬰兒床\r\n</li>\r\n<li>\r\n3－5歲兒童與父母同床並含早餐，可免費入住\r\n</li>\r\n</ul>', '<span>季节性政策：<br></span><ul><li>\r\n2026年3月19日静居日（Nyepi Day）当天不接受入住与退房。</li><li>2027 年 3 月 8 日静居日（Nyepi Day）当天不接受入住和退房</li></ul>蜜月礼遇：\r\n<ul>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n<li>\r\n客房内蜜月花艺布置\r\n</li>\r\n</ul>\r\n儿童政策：\r\n<ul>\r\n<li>\r\n0－2岁婴儿可免费提供婴儿床\r\n</li>\r\n<li>\r\n3－5岁儿童与父母同床并含早餐，可免费入住</li></ul>', NULL, NULL, NULL, 'Active', '1700191883_Komaneka-Bisma.webp', 14, 'https://www.komaneka.com/bisma', '2', '360', NULL, NULL, 'https://goo.gl/maps/yz7DMScZmasSxwTp9', NULL, NULL, NULL, NULL, '<span><b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 23 Dec, 07 Jan - 31 Mar): </i></span><ul><li>During low season, if cancellation occurs within 14 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 7 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>High Season </b><i>(01 Jul - 31 Aug, 24 Dec - 06 Jan): </i></span><ul><li>During high season, if cancellation occurs within 35 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 30 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>No Show:</b> 100% room charge will be applied for the No Show.</span>', '<span>淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：<br></span><ul><li>\r\n若於抵達日前14天內取消，將收取1晚房費作為取消費用。</li><li>\r\n若於抵達日前7天內取消，將收取全段住宿費用。</li></ul><span>旺季（7月1日－8月31日、12月24日－1月6日）：<br></span><ul><li>\r\n若於抵達日前35天內取消，將收取1晚房費作為取消費用。</li><li>\r\n若於抵達日前30天內取消，將收取全段住宿費用。</li></ul>未入住（No Show）：將收取全額房費（100%）作為違約金。', '<span>淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：<br></span><ul><li>\r\n如在抵达日前14天内取消，将收取1晚房费作为取消费用。</li><li>\r\n如在抵达日前7天内取消，将收取全程住宿费用。</li></ul><span>旺季（7月1日－8月31日、12月24日－1月6日）：<br></span><ul><li>\r\n如在抵达日前35天内取消，将收取1晚房费作为取消费用。</li><li>\r\n如在抵达日前30天内取消，将收取全程住宿费用。</li></ul>未入住（No Show）：将收取100%的房费作为违约金。', NULL, '2022-11-27 07:54:16', '2026-02-03 00:03:46', 1, 1),
(59, 'Komaneka at Rasa Sayang', '17', NULL, NULL, NULL, 'D9oW7gwgp5F23a2nT6Xwzd8HkR', '17', NULL, 'Jl. Monkey Forest, Ubud, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 40, 'Putri Dharmasanti', '0361975491', 'Unveiled in 2011, this stylish urban-style hotel is nestled in an oasis on the Monkey Forest road, with immediate access to cultural and lifestyle activities in the center of Ubud. The architecture of this urban-style hotel is modern and stylish, with an extensive use of wood, and interiors furnished with fine Indonesian art.', '這間時尚的城市風格飯店於2011年開幕，坐落於猴林路上的一處綠洲，步行即可前往烏布市中心的文化與生活活動場所。飯店建築採現代且時尚的設計風格，廣泛運用木材，並搭配精緻的印尼藝術作品裝潢其室內空間。', '这家时尚的城市风格酒店于2011年揭幕，坐落在猴林路的一处绿洲中，距离乌布中心的文化与生活活动场所仅几步之遥。酒店的建筑设计现代且富有时尚感，广泛采用木材，室内陈设则融合了精美的印尼艺术作品。', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities</li></ul>', '<ul><li>免費無線上網</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位房卡</li><li>\r\n線上入住</li><li>\r\n度假型物業</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>免费无线网络</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字房卡</li><li>\r\n线上入住</li><li>\r\n度假型物业</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy: </b><ul><li>No check-in/check-out on Nyepi Day, 08 March 2027</li><li>No check-in/check-out on Nyepi Day,19 Mar 2026<br></li></ul><b>Honeymoon Benefit: </b><ul><li>Honeymoon cake </li><li>In-room honeymoon flower set-up </li></ul><b>Children Policy: </b><br><ul><li>0-2 year old baby cot is free</li><li>3-5 year old sharing bed with parent inclusive of breakfast is free of charge</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2026年3月19日靜居日（Nyepi Day）當天不接受入住與退房。</li><li><span style=\"color: rgb(128, 128, 128); font-size: 14.4px;\">2027 年 3 月 8 日靜居日（Nyepi Day）當天不接受入住與退房</span></li></ul>蜜月禮遇：\r\n<ul>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n<li>\r\n客房內蜜月花藝佈置\r\n</li>\r\n</ul>\r\n兒童政策：\r\n<ul>\r\n<li>\r\n0－2歲嬰兒可免費提供嬰兒床\r\n</li>\r\n<li>\r\n3－5歲兒童與父母同床並含早餐，可免費入住</li></ul>', '<span>季节性政策：<br></span><ul><li><span>\r\n2026年3月19日静居日（Nyepi Day）当天不接受入住与退房。</span></li><li><span><span style=\"color: rgb(128, 128, 128); font-size: 14.4px;\">2027 年 3 月 8 日静居日（Nyepi Day）当天不接受入住和退房</span></span></li><li><span><b></b></span></li></ul>蜜月礼遇：\r\n<ul>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n<li>\r\n客房内蜜月花艺布置\r\n</li>\r\n</ul>\r\n儿童政策：\r\n<ul>\r\n<li>\r\n0－2岁婴儿可免费提供婴儿床\r\n</li>\r\n<li>\r\n3－5岁儿童与父母同床并含早餐，可免费入住</li></ul>', NULL, NULL, NULL, 'Active', '1700191962_Komaneka-Rasa-Sayang.webp', 14, 'https://www.komaneka.com/rasasayang', '2', '360', NULL, NULL, 'https://g.page/komanekaatrasasayang?share', NULL, NULL, NULL, NULL, '<span><b>Low Season</b><i> (01 Apr - 30 Jun, 01 Sep - 23 Dec, 07 Jan - 31 Mar): </i></span><ul><li>During low season, if cancellation occurs within 14 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 7 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>High Season</b> <i>(01 Jul - 31 Aug, 24 Dec - 06 Jan): </i></span><ul><li>During high season, if cancellation occurs within 35 days of arrival, a one-night cancellation fee will be assessed.</li><li>If cancellation occurs within 30 days of arrival, a full charge for the entire length of stay will be assessed. </li></ul><span><b>No Show:</b> 100% room charge will be applied for the No Show.</span><br>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n若於抵達日前14天內取消，將收取一晚房費作為取消費。\r\n</li>\r\n<li>\r\n若於抵達日前7天內取消，將收取整段住宿的全額費用。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n若於抵達日前35天內取消，將收取一晚房費作為取消費。\r\n</li>\r\n<li>\r\n若於抵達日前30天內取消，將收取整段住宿的全額費用。\r\n</li>\r\n</ul>\r\n未入住（No Show）：\r\n<ul>\r\n<li>\r\n將收取全額房費（100%）作為違約金。</li></ul>', '淡季（4月1日－6月30日、9月1日－12月23日、1月7日－3月31日）：\r\n<ul>\r\n<li>\r\n如在抵达日前14天内取消，将收取一晚房费作为取消费用。\r\n</li>\r\n<li>\r\n如在抵达日前7天内取消，将收取整个住宿期间的全额费用。\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日、12月24日－1月6日）：\r\n<ul>\r\n<li>\r\n如在抵达日前35天内取消，将收取一晚房费作为取消费用。\r\n</li>\r\n<li>\r\n如在抵达日前30天内取消，将收取整个住宿期间的全额费用。\r\n</li>\r\n</ul>\r\n未入住（No Show）：\r\n<ul>\r\n<li>\r\n将收取100%房费作为违约金。</li></ul>', NULL, '2022-11-27 08:31:19', '2026-02-03 23:21:15', 1, 1),
(60, 'Vije Boutique Resort & Spa', '17', NULL, NULL, NULL, '8CSSf1bYLXfs0WNr9iio1hBTEB', '17', NULL, 'Jl. Suweta, Ubud, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 45, 'Dayu Mirah', '081138117614', 'Located right in the heart of Ubud, we are a familyowned boutique resort. Bali is our home and Ubud is where our heart it. Ubud comes from the word “ubad,” which means medicine. And just like medicine, this place heals and soothes. Come and visit our boutique resort, join us in your home away from home. We will do our best to represent Ubud, Bali.', '<span>我們是一家位於烏布心臟地帶的家族經營精品度假村。峇里島是我們的家，而烏布是我們的心之所繫。<br>\r\n「烏布」（Ubud）一詞源自「ubad」，意指藥物。正如藥物一般，這片土地具有療癒與安撫人心的力量。<br>\r\n歡迎蒞臨我們的精品度假村，在這個遠離家鄉卻如家的地方與我們相聚。我們將盡最大努力呈現烏布與峇里島的美好。</span>', '我们是一家位于乌布核心地带的家族经营精品度假村。巴厘岛是我们的家，而乌布是我们的心之所向。<br>\r\n“乌布”（Ubud）一词来源于“ubad”，意为药物。就像药物一样，这片土地能够疗愈和抚慰人心。<br>\r\n欢迎您来我们的精品度假村做客，在这处远方的家中与我们相遇。我们将尽力展现乌布和巴厘岛的魅力。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>Compulsory New Year\'s Eve Dinner on 31 December (Price at additional charge)</li></ul>', '季節性政策：<br><ul><li>\r\n12月31日須參加強制性跨年晚宴（需另行收費）</li></ul>', '季节性政策：<br><ul><li>\r\n12月31日需参加强制性跨年晚宴（需额外收费）</li></ul>', NULL, NULL, NULL, 'Active', '1744871848_1.-Pool.jpg', 14, 'https://vijeboutiqueresort.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/Fe3xRRUgiWMCxqXeA', NULL, NULL, NULL, NULL, '<b>Low Season</b> <i>(01 Apr - 14 Jul, 01 Sep - 24 Dec, 08 Jan - 31 Mar):&nbsp;<br></i><ul><li>7 Days prior to arrival: One night\'s stay</li><li>Same day or No-show: 100% for full length of stay</li></ul><b>High &amp; Peak Season</b> <i>(15 Jul - 31 Aug, 25 Dec - 07 Jan):&nbsp;<br></i><ul><li>21 Days prior to arrival: 50% of full length of stay<i></i></li><li>14 Days prior to arrival: full length of stay&nbsp;</li></ul>', '淡季（4月1日－7月14日、9月1日－12月24日、1月8日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達日前7天內取消：收取1晚房費\r\n</li>\r\n<li>\r\n當日取消或未入住（No-show）：收取全段住宿費用的100%\r\n</li>\r\n</ul>\r\n旺季與巔峰季（7月15日－8月31日、12月25日－1月7日）：\r\n<ul>\r\n<li>\r\n抵達日前21天內取消：收取全段住宿費用的50%\r\n</li>\r\n<li>\r\n抵達日前14天內取消：收取全段住宿費用的100%</li></ul>', '淡季（4月1日－7月14日、9月1日－12月24日、1月8日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达日前7天内取消：收取1晚房费\r\n</li>\r\n<li>\r\n当日取消或未入住（No-show）：收取整个住宿期间100%的费用\r\n</li>\r\n</ul>\r\n旺季及高峰季（7月15日－8月31日、12月25日－1月7日）：\r\n<ul>\r\n<li>\r\n抵达日前21天内取消：收取整个住宿期间费用的50%\r\n</li>\r\n<li>\r\n抵达日前14天内取消：收取整个住宿期间费用的100%</li></ul>', NULL, '2022-11-27 08:53:15', '2025-06-29 22:10:52', 1, 1),
(61, 'Mandapa, a Ritz-Carlton Reserve', '17', NULL, NULL, NULL, 'jk3gc6tnjIRT2ZBYpyaK5mzrX1', '17', NULL, 'Jl. Raya Kedewatan, Banjar, Kedewatan, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 41, 'Arik Mahardika', '03614792777', 'Befitting its name, which means \"temple\" in Sanskrit, Mandapa, a Ritz-Carlton Reserve offers hotel guests a “temple” to call their own, a luxury sanctuary for inner discovery and serenity. Nestled within Bali\'s cultural heart of Ubud, with the Ayung River floating peacefully alongside, the hotel offers butler-serviced villas and suites; vintage VW convertible tours of villages, rice fields and temples; and dining including the signature Kubu, featuring Mediterranean-European cuisine and private cocoons', '如同其梵文名稱 “Mandapa” 所代表的「神殿」意涵，Mandapa 麗思卡爾頓隱世精品度假酒店為賓客打造一座專屬的「聖殿」，是一處探索內在與尋求平靜的奢華靜修天堂。<br>\r\n酒店靜謐地坐落於峇里島文化核心——烏布，阿勇河靜靜流淌於一側。酒店提供配有私人管家的別墅與套房；安排復古 VW 敞篷車之旅，探索當地村莊、稻田與寺廟；餐飲方面包括標誌性餐廳 Kubu，主打地中海與歐洲料理，並設有私密繭型用餐空間。', '正如其梵语名称“Mandapa”所代表的“庙宇”之意，Mandapa 丽思卡尔顿隐世精品度假酒店为宾客打造专属的“圣殿”，一处奢华的心灵净土，让人得以探索内在与寻求宁静。<br>\r\n酒店坐落于巴厘岛文化中心乌布，静谧的阿勇河从旁流淌，环境宁静祥和。酒店提供配有管家服务的别墅与套房；可乘坐复古大众敞篷车游览村庄、稻田与庙宇；餐饮方面则包括主打地中海与欧洲风味的标志性餐厅 Kubu，设有私密的“茧型”用餐空间。', '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities</li></ul>', '<li>免費網路\r\n</li>\r\n<li>\r\n免費停車\r\n</li>\r\n<li>\r\n餐廳\r\n</li>\r\n<li>\r\n健身中心\r\n</li>\r\n<li>\r\n游泳池\r\n</li>\r\n<li>\r\n水療中心\r\n</li>\r\n<li>\r\n數位房卡\r\n</li>\r\n<li>\r\n線上辦理入住\r\n</li>\r\n<li>\r\n渡假村設施\r\n</li>\r\n<li>\r\n洗衣服務\r\n</li>\r\n<li>\r\n禮賓服務\r\n</li>\r\n<li>\r\n會議設施</li>', '<li>免费网络\r\n</li>\r\n<li>\r\n免费停车\r\n</li>\r\n<li>\r\n餐厅\r\n</li>\r\n<li>\r\n健身中心\r\n</li>\r\n<li>\r\n游泳池\r\n</li>\r\n<li>\r\n水疗中心\r\n</li>\r\n<li>\r\n数字房卡\r\n</li>\r\n<li>\r\n在线办理入住\r\n</li>\r\n<li>\r\n度假村物业\r\n</li>\r\n<li>\r\n洗衣服务\r\n</li>\r\n<li>\r\n礼宾服务\r\n</li>\r\n<li>\r\n会议设施</li>', '<b>Seasonal Policy:&nbsp;</b><br><ul><li>Please note that during NYEPI (Silence Day), some services will be available throughout the resort and our guest are expected to respect local customs.</li></ul><ul><li>Guest movement for arrival and departure are not allowed during Nyepi Days on the period of 19 March 2026.</li></ul><b>Children Policy :&nbsp;</b><br><ul><li>Below 5 years old complimentary baby crib &amp; breakfast&nbsp;</li></ul><span><b>HONEYMOON OFFER (PROMO CODE: HNM)</b> -&nbsp;Min. 3 nights stay is required to avail this offer (Applicable on all room categories except 2 Bedroom and 3 Bedroom Pool Villa)&nbsp;</span><ul><li>Flower bath &amp; bed turndown</li><li>Celebration miniature honeymoon / anniversary cake on arrival</li><li>One-time Couple’s treatment of 60 minutes Mepijet massage for two guests</li><li>One-time Afternoon Tea at Ambar for two guests</li></ul><span><b>FAMILY OFFER (PROMO CODE: FAM) </b>-&nbsp;Min. 3 nights stay is required to avail this offer (Applicable on all room categories)</span><ul><li>Daily breakfast for 1 child below 12 years old (per bedroom), following each room category maximum occupancy policy</li><li>Extra bed setup for 1 child below 12 years old (per bedroom), following each room category maximum occupancy policy</li></ul>', '<span>季節性政策：<br>\r\n請注意，在「靜居日」（Nyepi）期間，度假村內部分設施將維持開放，敬請賓客尊重當地文化習俗。<br>\r\n2026年3月19日靜居日當天，禁止賓客進出飯店，無法辦理入住或退房。</span>\r\n<span>兒童政策：<br>\r\n5歲以下兒童可免費提供嬰兒床與早餐。</span>\r\n蜜月專案（優惠碼：HNM）\r\n<ul>\r\n<li>\r\n最少需入住3晚方可使用本優惠（適用於除兩臥與三臥泳池別墅以外的所有房型）\r\n</li>\r\n<li>\r\n花浴與夜間床鋪佈置\r\n</li>\r\n<li>\r\n入住當日贈送迷你蜜月／週年蛋糕\r\n</li>\r\n<li>\r\n一次60分鐘雙人Mepijet按摩療程\r\n</li>\r\n<li>\r\n一次Ambar雙人下午茶體驗\r\n</li>\r\n</ul>\r\n家庭專案（優惠碼：FAM）\r\n<ul>\r\n<li>\r\n最少需入住3晚方可使用本優惠（適用於所有房型）\r\n</li>\r\n<li>\r\n每間房每日為一位12歲以下兒童提供早餐（依各房型最大入住人數政策）\r\n</li>\r\n<li>\r\n每間房為一位12歲以下兒童提供加床服務（依各房型最大入住人數政策）</li></ul>', '<span>季节性政策：<br>\r\n请注意，在“宁静日”（Nyepi）期间，度假村内部分服务仍将开放，敬请宾客尊重当地风俗文化。<br>\r\n2026年3月19日宁静日当天，宾客禁止进出及移动，无法办理入住或退房手续。</span>\r\n<span>儿童政策：<br>\r\n5岁以下儿童可免费提供婴儿床及早餐。</span>\r\n蜜月优惠（优惠码：HNM）\r\n<ul>\r\n<li>\r\n最少需入住3晚方可享此优惠（适用于除两卧室及三卧室泳池别墅以外的所有房型）\r\n</li>\r\n<li>\r\n鲜花浴与床铺夜间布置\r\n</li>\r\n<li>\r\n抵达时赠送迷你蜜月／周年蛋糕\r\n</li>\r\n<li>\r\n一次60分钟双人Mepijet按摩疗程\r\n</li>\r\n<li>\r\n一次Ambar双人下午茶体验\r\n</li>\r\n</ul>\r\n家庭优惠（优惠码：FAM）\r\n<ul>\r\n<li>\r\n最少需入住3晚方可享此优惠（适用于所有房型）\r\n</li>\r\n<li>\r\n每间卧室每日为一位12岁以下儿童提供早餐（根据房型最大入住政策）\r\n</li>\r\n<li>\r\n每间卧室为一位12岁以下儿童提供加床服务（根据房型最大入住政策）</li></ul>', NULL, NULL, NULL, 'Active', '1750384121_rz-dpsub-mandapa-camp-42045_Classic-Hor.jfif', 2, 'https://www.ritzcarlton.com/en/hotels/indonesia/mandapa', '2', '45', NULL, NULL, 'https://g.page/mandapareserve?share', NULL, NULL, NULL, NULL, '<span><b>Low Season</b>&nbsp;<i>(01 - 14 Apr, 05 May - 30 Jun, 01 - 28 Sep, 07 Oct - 19 Dec, 11 Jan - 09 Feb, 22 Feb - 31 Mar) :</i><br></span><ul><li>Cancellation less than 14 days prior to arrival or no show, a cancellation fee equal to entire stay will be levied.&nbsp;</li></ul><span><b>High Season</b><i> (15 Apr - 04 May, 01 Jul - 31 Aug, 29 Sep - 06 Oct, 20 Dec - 10 Jan, 10 - 21 Feb) :</i><br></span><ul><li>Cancellation less than 30 days prior to arrival or no show, a cancellation fee equal to entire stay will be levied.</li></ul>', '<span>淡季（4月1日 – 4月14日，5月5日 – 6月30日，9月1日 – 9月28日，10月7日 – 12月19日，1月11日 – 2月9日，2月22日 – 3月31日）：<br>\r\n若於入住前14天內取消預訂或未如期入住，將收取全額住宿費用作為取消罰金。</span>\r\n<span>旺季（4月15日 – 5月4日，7月1日 – 8月31日，9月29日 – 10月6日，12月20日 – 1月10日，2月10日 – 2月21日）：<br>\r\n若於入住前30天內取消預訂或未如期入住，將收取全額住宿費用作為取消罰金。</span>', '<span>淡季（4月1日 – 4月14日，5月5日 – 6月30日，9月1日 – 9月28日，10月7日 – 12月19日，1月11日 – 2月9日，2月22日 – 3月31日）：<br>\r\n若在入住前14天内取消预订或未如期入住，将收取全额住宿费用作为取消罚金。</span>\r\n<span>旺季（4月15日 – 5月4日，7月1日 – 8月31日，9月29日 – 10月6日，12月20日 – 1月10日，2月10日 – 2月21日）：<br>\r\n若在入住前30天内取消预订或未如期入住，将收取全额住宿费用作为取消罚金。</span>', NULL, '2022-11-27 09:19:00', '2025-06-23 17:52:50', 2, 1),
(62, 'Grand Mirage Resort & Thalasso Bali', '17', NULL, NULL, NULL, 'CwspbSvdEQXTzaGzub4vjJnUSE', '17', NULL, 'Jl. Pratama No 74, Tanjung Benoa 80363 Nusa Dua - Bali, Indonesia', 1, 15, 'Ade Ditayanti', '0361771888', 'Set on the southern part of Bali, Tanjung Benoa – Nusa Dua resort area, Grand Mirage Resort and Thalasso Bali spa is blessed with a hypnotizing view of Indian Ocean. This Bali resort is 25 minutes away from Ngurah Rai International Airport. The resort is also within walking distance of numerous shopping outlets, convenience stores and merchandise shops to choose from. With its pristine private beach, this 5 star beachfront Bali resort offers wonderful experiences of spending leisure time in a luxury hotel. With all the luxury inclusions, Grand Mirage Resort and Thalasso Bali Spa is definitely worth listing on every Bali itinerary!', '位於峇里島南部的丹絨貝諾亞－努沙杜瓦度假區，Grand Mirage Resort and Thalasso Bali Spa 擁有令人著迷的印度洋景致。這間峇里島度假村距離伍拉·賴國際機場僅25分鐘車程，步行即可抵達多家購物商店、便利商店及紀念品店。<br>\r\n擁有潔白私人的沙灘，這家五星級海濱度假村為賓客提供在奢華酒店中享受悠閒時光的絕佳體驗。結合各種奢華設施與服務，Grand Mirage Resort and Thalasso Bali Spa 絕對值得列入您的峇里島行程！', '位于巴厘岛南部的丹戎贝诺亚－努沙杜瓦度假区，Grand Mirage Resort and Thalasso Bali Spa 拥有令人着迷的印度洋景色。这家巴厘岛度假村距离伍拉·赖国际机场仅25分钟车程，步行即可到达多个购物商场、便利店和纪念品店。<br>\r\n度假村配有洁白的私人海滩，这家五星级海滨度假村为您带来在豪华酒店中度过悠闲时光的美妙体验。拥有众多奢华配套设施，Grand Mirage Resort and Thalasso Bali Spa 绝对值得列入每一个巴厘岛行程中！', '<ul><li>Beach Volley Ball</li><li>Main Swimming Pool</li><li>Pool at Family Paradise</li><li>Infinity Pool (Adult Only)</li><li>Motorized Water Sport</li><li>Non-Motorized Water Sport</li><li>Sea Walker</li><li>Fitness Center</li><li>Games Lounge</li><li>Yoga Class</li><li>Bicycle Tour Rental</li><li>Table Tennis</li><li>Mahjong Room</li><li>Karaoke Room</li><li>Cooking Demo</li></ul>', '<ul><li>沙灘排球</li><li>\r\n主游泳池</li><li>\r\n家庭天堂區游泳池</li><li>\r\n無邊際泳池（僅限成人）</li><li>\r\n機動水上活動</li><li>\r\n非機動水上活動</li><li>\r\n海底漫步</li><li>\r\n健身中心</li><li>\r\n遊戲休閒室</li><li>\r\n瑜珈課程</li><li>\r\n腳踏車導覽租借</li><li>\r\n桌上乒乓球</li><li>\r\n麻將室</li><li>\r\n卡拉OK包廂</li><li>\r\n烹飪示範</li></ul>', '<ul><li>沙滩排球</li><li>\r\n主游泳池</li><li>\r\n家庭天堂区游泳池</li><li>\r\n无边际泳池（仅限成人）</li><li>\r\n机动水上活动</li><li>\r\n非机动水上活动</li><li>\r\n海底漫步</li><li>\r\n健身中心</li><li>\r\n游戏休闲室</li><li>\r\n瑜伽课程</li><li>\r\n自行车导览租赁</li><li>\r\n乒乓球</li><li>\r\n麻将室</li><li>\r\n卡拉OK包间</li><li>\r\n烹饪示范</li></ul>', '<b>Seasonal Policy :&nbsp;</b><ul><li>No check in and check out on 31 December&nbsp;&amp; 01 January</li><li>Minimum 3 nights stay during Peak Season Period (24 Dec -&nbsp; 4 Jan)&nbsp;</li><li>Compulsory New Years Eve Gala Dinner 31 December 2025 (Price at additional charge)&nbsp;</li></ul><b>Nursery Room and Shared Pantry :</b><ul><li>For families with children below 4&nbsp;years old, complimentary shared Nursery room for 2 hours 45 minutes (equipped with 1 single bed, 1 baby cot, TV, and private bathroom), subject to availability&nbsp;</li><li>Free use of adjoining&nbsp;shared-pantry (equipped with sterilizer, microwave, kitchen sink, drinking water and tea coffee) for early check in or late check out, subject to availability</li></ul><b>Honeymooner</b> - Courtesy from the hotel will include (to be placed in the room upon arrival):&nbsp;<br><ul><li>Honeymoon Cake, Fruit Arrangement, Flowers&nbsp;Wedding Anniversary and Birthdays - Courtesy from the hotel for which the Agent or Guest will notify the hotel:Anniversary / Birthday cake, Fruit arrangement, Flowers</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月31日與1月1日不可辦理入住與退房</li><li>\r\n巔峰季期間（12月24日至1月4日）需至少入住3晚</li><li>\r\n2025年12月31日需參加強制性跨年晚宴（需額外收費）</li></ul><span>育嬰室與共用茶水間：<br></span><ul><li>\r\n針對4歲以下兒童的家庭，提供免費使用共用育嬰室2小時45分鐘（配備1張單人床、1張嬰兒床、電視及私人浴室），需視供應情況而定</li><li>\r\n若提早入住或延遲退房，可免費使用鄰近共用茶水間（配備消毒器、微波爐、洗滌槽、飲用水與茶/咖啡），亦需視供應情況而定</li></ul><span>蜜月禮遇（由飯店提供，將於抵達時擺放於房內）：<br></span><ul><li>\r\n蜜月蛋糕、水果擺設、鮮花</li></ul><span>結婚紀念日與生日禮遇（需由代理或賓客提前通知飯店）：<br></span><ul><li>\r\n紀念日／生日蛋糕、水果擺設、鮮花</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n12月31日和1月1日不可办理入住与退房</li><li>\r\n高峰季期间（12月24日至1月4日）需至少入住3晚</li><li>\r\n2025年12月31日需参加强制性跨年晚宴（需额外收费）</li></ul><span>育婴室与共享茶水间：<br></span><ul><li>\r\n针对4岁以下儿童的家庭，提供免费使用共享育婴室2小时45分钟（配备1张单人床、1张婴儿床、电视及独立卫浴），视供应情况而定</li><li>\r\n若提前入住或延迟退房，可免费使用邻近共享茶水间（配有消毒器、微波炉、水槽、饮用水和茶/咖啡），同样视供应情况而定</li></ul><span>蜜月礼遇（由酒店提供，将于抵达时放置于房间内）：<br></span><ul><li>\r\n蜜月蛋糕、水果摆设、鲜花</li></ul><span>结婚纪念日与生日礼遇（需由代理或客人提前通知酒店）：<br></span><ul><li>\r\n纪念日／生日蛋糕、水果摆设、鲜花</li></ul>', NULL, NULL, NULL, 'Active', '1759195449_225523060.jpg', 2, 'https://www.grandmirage.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/LAcvHEKqXuhr1muk6', NULL, NULL, NULL, NULL, '<b>Low Season :</b><ul><li>&nbsp;if cancelled before 3 days prior to arrival, no charge applies, if cancelled within 3 days,1 night cancellation policy applies.&nbsp;</li></ul><span><b>High Season</b> <i>(01 July - 31 Aug) :&nbsp;</i></span><ul><li>if cancelled before 14 days prior to arrival, no charge applies, if cancelled within 14 days,1 night cancellation policy applies.&nbsp;</li></ul><span><b>Peak Season</b> <i>(24 Dec - 04 Jan) :&nbsp;</i></span><ul><li>if cancelled before 21 days prior to arrival, no charge applies, if cancelled within 21 days,1 night cancellation policy applies. If cancelled within 14 days, 2 nights cancellation policy applies. If cancelled within 7 days will be charge 75% from total stay.&nbsp;</li></ul><span><b>Early check out and no show :</b> 100% full charge&nbsp;</span><br>', '<span>淡季：<br></span><ul><li>\r\n如於抵達日前3天前取消，無需收費；如於抵達日前3天內取消，將收取1晚取消費。</li></ul><span>旺季（7月1日－8月31日）：<br></span><ul><li>\r\n如於抵達日前14天前取消，無需收費；如於抵達日前14天內取消，將收取1晚取消費。</li></ul>巔峰季（12月24日－1月4日）：<br><ul><li>\r\n如於抵達日前21天前取消，無需收費；</li><li>\r\n如於抵達日前21天內取消，將收取1晚取消費；</li><li>\r\n如於抵達日前14天內取消，將收取2晚取消費；</li><li>\r\n如於抵達日前7天內取消，將收取總住宿費用的75%。</li></ul>提前退房與未入住（No Show）：將收取總住宿費用的100%。', '<span>淡季：<br></span><ul><li>\r\n如在抵达日前3天前取消，免费；如在抵达日前3天内取消，将收取1晚取消费用。</li></ul><span>旺季（7月1日－8月31日）：<br></span><ul><li>\r\n如在抵达日前14天前取消，免费；如在抵达日前14天内取消，将收取1晚取消费用。</li></ul><span>高峰季（12月24日－1月4日）：<br></span><ul><li>\r\n如在抵达日前21天前取消，免费；</li><li>\r\n如在抵达日前21天内取消，将收取1晚取消费用；</li><li>\r\n如在抵达日前14天内取消，将收取2晚取消费用；</li><li>\r\n如在抵达日前7天内取消，将收取总住宿费用的75%。</li></ul>提前退房与未入住（No Show）：将收取100%全额费用。', NULL, '2022-11-27 12:40:51', '2025-09-29 17:24:09', 2, 1),
(63, 'Samabe Bali Suite and Villa', '17', NULL, NULL, NULL, 'Mvh6lI939Fvlrm309BuMgycSN7', '17', NULL, 'Barong - Barong Sawangan, Jl. Pura, Jl. Raya Nusa Dua Selatan, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80363', 1, 17, 'Ade Ditayanti', '03618468633', 'Situated in the secluded part of Bali, Nusa Dua, Samabe Bali Suites &amp; Villas epitomises the tranquility of a beach resort in a lavish style. The Bali luxury resort sits on 8 hectare land with 81 suites &amp; villas, 2 restaurants, and 2 bars.', '位於峇里島幽靜的努沙杜瓦地區，Samabe Bali 套房與別墅以奢華風格完美詮釋海濱度假村的寧靜氛圍。這間奢華度假村佔地8公頃，擁有81間套房與別墅、2間餐廳及2間酒吧。', '位于巴厘岛幽静的努沙杜瓦地区，Samabe Bali 套房与别墅以奢华风格完美诠释海滨度假村的宁静氛围。这家奢华度假村占地8公顷，拥有81间套房与别墅、2间餐厅和2间酒吧。', '<ul><li>Infinity Pool</li><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities</li></ul>', '<ul><li>無邊際泳池</li><li>\r\n免費無線上網</li><li>\r\n免費停車</li><li>\r\n餐廳</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水療中心</li><li>\r\n數位房卡</li><li>\r\n線上入住</li><li>\r\n度假型物業</li><li>\r\n洗衣服務</li><li>\r\n禮賓服務</li><li>\r\n會議設施</li></ul>', '<ul><li>无边际泳池</li><li>\r\n免费无线网络</li><li>\r\n免费停车</li><li>\r\n餐厅</li><li>\r\n健身中心</li><li>\r\n游泳池</li><li>\r\n水疗中心</li><li>\r\n数字房卡</li><li>\r\n线上入住</li><li>\r\n度假型物业</li><li>\r\n洗衣服务</li><li>\r\n礼宾服务</li><li>\r\n会议设施</li></ul>', '<b>Seasonal Policy :&nbsp;</b><ul><li>Minimum stay 3 nights required (24 Dec 2024&nbsp;- 05 Jan 2025&nbsp;&amp; 20 Dec 2025 - 05 Jan 2026)&nbsp;</li><li>Compulsory Year End&nbsp;Dinner(Gala Dinner) on 31 Dec (Price : TBA)&nbsp;</li></ul><b>Honeymoon, Birthday, Anniversary Included :&nbsp;</b><br>Choose one from 9 complimentary options to give your special day a sweet little touch. Minimum stay 2 nights :&nbsp;<ol><li>One bottle of sparkling wine in your suite or villa upon arrival / Birthday. This is a refreshing way to ignite the night of celebration with your loved one. And then, an in-suite dinner to follow?.</li><li>Love swan with flowers on the bed upon arrival/birthday. A love swan will greet you as you step into your bedroom. A typical yet sensual touch to set a special atmosphere to mark your romantic getaway with.</li><li>Romantic surprise flower decoration in your suite or villa upon arrival/birthday You can arrange to have a flower decoration prepared prior to your check in to give your partner a lovely surprise.</li><li>Aroma flower candle bath upon arrival an intimate moment is created as soon as you begin your romantic journey at Samabe with an inviting aroma candle bath on your arrival/birthday</li><li>Samabe signature chocolate and canapés Are you sweet-toothed? We have something sweet for you with a wish that your entire holiday experience will be as sweet as the moment.</li><li>Chocolate fondue prepared by your butler at requested day and time Chocolate fondue for two is a heartwarming way to wish a happy day for more happy years to come.</li><li>Honeymoon Cake to Be delivered to your room or suite at the time and day you choose&nbsp;</li><li>Birthday Cake with Samabe Parade To Be delivered to your room or suite or at your dinner table by a group waiter/tress/butler together with a flower chain and some other surprises. Have your camera ready. Good for children and adult &nbsp;</li><li>Indonesian Rijstaffel Dinner experience at Rempah Rempah&nbsp;restaurant/Wantilan&nbsp;</li></ol>', '<span>季節性政策：<br>\r\n2024年12月24日至2025年1月5日，以及2025年12月20日至2026年1月5日，最低入住晚數為3晚。<br>\r\n2025年12月31日需參加強制性跨年晚宴（價格待公告）。</span>\r\n<span>蜜月、生日、結婚紀念日禮遇包含如下：<br>\r\n凡入住2晚或以上，可從9項免費禮遇中擇一，為您的特別日子增添甜蜜驚喜：</span>\r\n<ul>\r\n<li>\r\n抵達當日／生日：套房或別墅贈送一瓶氣泡酒——這是與摯愛共度歡慶夜晚的清新開場，接著可選擇享用客房內晚餐。\r\n</li>\r\n<li>\r\n抵達當日／生日：床上愛心天鵝搭配鮮花裝飾——踏入房間，浪漫天鵝為您營造典型而感性的氛圍，點綴您的浪漫假期。\r\n</li>\r\n<li>\r\n抵達當日／生日：客房或別墅內浪漫鮮花驚喜佈置——可預先安排，為伴侶帶來一份驚喜。\r\n</li>\r\n<li>\r\n抵達當日／生日：香氛花瓣蠟燭浴——於抵達時享受一場香氣迷人的蠟燭浴，開啟浪漫之旅。\r\n</li>\r\n<li>\r\nSamabe 精選巧克力與小點心——喜歡甜食的您，這將是我們祝願您整趟旅程如同這一刻般甜蜜的心意。\r\n</li>\r\n<li>\r\n由私人管家於指定日期時間準備巧克力火鍋——為兩人準備的溫馨巧克力火鍋，是為未來更多美好日子送上的祝福。\r\n</li>\r\n<li>\r\n蜜月蛋糕——可指定時間與地點，送至您的房間或套房。\r\n</li>\r\n<li>\r\n生日蛋糕與 Samabe 專屬遊行——由服務員／管家於房內或餐桌送上蛋糕、花圈與其他驚喜，記得準備好相機！適合兒童與成人。\r\n</li>\r\n<li>\r\n在 Rempah Rempah 餐廳／Wantilan 餐廳享用印尼傳統 Rijsttafel 晚餐體驗。</li></ul>', '<span>季节性政策：<br>\r\n2024年12月24日至2025年1月5日，以及2025年12月20日至2026年1月5日，需至少入住3晚。<br>\r\n2025年12月31日需参加强制性的跨年晚宴（价格待定）。</span>\r\n<span>蜜月、生日、纪念日礼遇包含如下：<br>\r\n凡入住2晚及以上，可从9项免费选项中任选一项，为您的特别日子增添温馨仪式感：</span>\r\n<ul>\r\n<li>\r\n抵达当天／生日：套房或别墅赠送一瓶起泡酒——为与爱人共度的庆祝夜拉开清新序幕，随后可安排客房内浪漫晚餐。\r\n</li>\r\n<li>\r\n抵达当天／生日：床上天鹅造型配鲜花布置——浪漫天鹅迎接您的入住，为旅途营造甜蜜氛围。\r\n</li>\r\n<li>\r\n抵达当天／生日：客房或别墅内浪漫鲜花惊喜布置——可提前安排，为伴侣送上惊喜。\r\n</li>\r\n<li>\r\n抵达当天／生日：香薰花瓣蜡烛浴——抵达即享的香氛蜡烛浴，开启浪漫之旅。\r\n</li>\r\n<li>\r\nSamabe 特色巧克力与小吃——为甜食爱好者准备的小点，希望您的假期如同这一刻般甜蜜。\r\n</li>\r\n<li>\r\n由您的私人管家在指定日期时间准备巧克力火锅——二人共享的甜蜜巧克力火锅，为未来的幸福生活送上祝福。\r\n</li>\r\n<li>\r\n蜜月蛋糕——可根据您的时间安排送至房间或套房。\r\n</li>\r\n<li>\r\n生日蛋糕与 Samabe 游行——由服务员／管家将蛋糕、花环及其他惊喜送至房间或餐桌，请准备好拍照！适合儿童和成人。\r\n</li>\r\n<li>\r\n在 Rempah Rempah 餐厅／Wantilan 餐厅享用印尼特色 Rijsttafel 晚餐体验。</li></ul>', NULL, NULL, NULL, 'Active', '1700192258_Samabe-Bali.webp', 14, 'https://www.samabe.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/s9Tb3R46Tmi5LEMQ8', NULL, NULL, NULL, NULL, '<ul><li><span>FIT booking will require a minimum cancellation notice period of 14 days prior to guest arrival during the Normal season while for Peak season <i>(24 Dec – 04 Jan)</i>, a minimum cancellation notice period of 30 days is required prior to guest arrival. while for High season <i>(15 Jul – 31 Aug)</i>, a minimum cancellation notice period of 14 days is required prior to guest arrival. Cancellation received less than the required notice period is subject to one night cancellation charge.</span></li></ul><ul><li>In the event of “NO SHOW”, the Operator shall be responsible for payment computed on the equivalent of the full length of stay. Royal Samabe Residence will be required 100% non-refundable booking due only1 unit available and high demand.</li></ul>', 'FIT 預訂在一般季節須於賓客抵達前至少14天提出取消通知；而在巔峰季（12月24日至1月4日）則須至少提前30天通知取消；旺季期間（7月15日至8月31日）則須提前14天通知。若在規定通知期限內取消，將收取1晚房費作為取消費用。\r\n若發生「未出現」（No Show）情況，業者須支付等同於整段住宿天數的全額費用。\r\nRoyal Samabe Residence 僅有1間房型且需求極高，所有預訂皆須100%預付且不可退款。', 'FIT 预订在普通季节须在客人抵达前至少14天通知取消；而在高峰季节（12月24日至1月4日）则需至少提前30天通知；旺季期间（7月15日至8月31日）则需提前14天通知取消。如未在规定的通知期限内取消，将收取一晚房费作为取消费用。\r\n若发生“未入住”（No Show）情况，运营商需支付相当于整个住宿期间的全额费用。\r\nRoyal Samabe Residence 仅有1间房型且需求量大，所有预订需100%预付且不可退款。', NULL, '2022-11-27 13:06:06', '2025-06-29 23:06:34', 1, 1),
(64, 'Kupu Kupu Barong Villas & Tree Spa by L\'OCCITANE', '17', NULL, NULL, NULL, 'miXOTaXeYCNcVFEzjNBQtZB6Bl', '17', NULL, 'Jl. Raya Kedewatan, Kedewatan, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 37, 'Uly Mardiani', '0361975478', '<div>“Kupu Kupu” is the Balinese name for Butterfly, as our hotel brand originates from Indonesia - the Butterfly is the symbol of beauty, culture, art and design.”<br><br></div><div>We believe in welcoming and treating everyone the way we would like to be treated ourselves. Stay with us, live with us, discover with us and enjoy one of the most luxurious and beautiful five-star hotels in Ubud.&nbsp;You can take time out to have a refreshing swim in our overflowing pool, enjoy a private access to the river, for the most charming sunrise of the jungle, or a relaxing moment in our Mango Tree Spa for a soothing balinese massage with natural L’Occitane body care.&nbsp;We intend to make your stay at Kupu Kupu Barong the most extraordinary of your traveler life.</div>', '「Kupu Kupu」在峇里語中是「蝴蝶」的意思，作為源自印尼的飯店品牌，蝴蝶象徵著美麗、文化、藝術與設計。\r\n我們相信，應以我們希望被對待的方式來歡迎與對待每一位賓客。入住我們的飯店，與我們一同生活、探索，並享受烏布最奢華且最美麗的五星級酒店之一。您可以在無邊際泳池中暢泳放鬆，享受通往河流的私人通道，迎接迷人的叢林日出，或前往 Mango Tree Spa 體驗舒緩的巴厘式按摩，搭配天然 L’Occitane 護膚品。我們致力於讓您在 Kupu Kupu Barong 的每一刻，成為您旅途中最非凡的回憶。', '“Kupu Kupu”在巴厘语中意为“蝴蝶”，作为起源于印尼的酒店品牌，蝴蝶象征着美丽、文化、艺术与设计。\r\n我们相信，应该以我们希望被对待的方式去欢迎和对待每一位宾客。入住我们酒店，与我们一同生活、探索，尽情享受乌布最奢华、最美丽的五星级酒店之一。您可以在我们的无边泳池中畅游放松，享受通往河流的私人通道，在丛林中迎接最迷人的日出，或在 Mango Tree Spa 享受使用天然 L’Occitane 护肤品的舒缓巴厘式按摩。我们致力于让您在 Kupu Kupu Barong 的每一段旅程，都成为您人生中最非凡的旅行体验。', NULL, NULL, NULL, '<b>Honeymoon Benfits:&nbsp;</b><br><ul><li>Special honeymoon cake served on the second day of guest stay</li><li>One glass of in-house wine per person per stay&nbsp;</li><li>Special flower arrangement and flower petals in the bathtub except Pool View Suite&nbsp;</li></ul>', '蜜月禮遇：\r\n<ul>\r\n<li>\r\n於入住第二天提供特製蜜月蛋糕\r\n</li>\r\n<li>\r\n每人每次入住贈送一杯館內葡萄酒\r\n</li>\r\n<li>\r\n特別花藝擺設與浴缸花瓣裝飾（泳池景套房除外）</li></ul>', '蜜月礼遇：\r\n<ul>\r\n<li>\r\n入住第二天赠送特别蜜月蛋糕\r\n</li>\r\n<li>\r\n每人每次入住赠送一杯酒店自制葡萄酒\r\n</li>\r\n<li>\r\n特别花艺布置及浴缸花瓣装饰（不适用于泳池景套房）</li></ul>', NULL, NULL, NULL, 'Active', '1749541071_KKB-AI-Expanded-3.webp', 14, 'https://kupubarongubud.com/', '2', '45', NULL, NULL, 'https://g.page/mayaubud?share', NULL, NULL, NULL, NULL, '<ul><li>In case of any cancellation made less than 14 days prior to arrival date during low season and 21 days prior to arrival \r\ndate during high season, one night cancellation fee will be charged. \r\nIn case of any cancellation less than 7 days on low season and 14 days on high season or no show, full cancellation \r\nfee of the total room nights will be charged.</li></ul>', '若於淡季抵達日前少於14天取消預訂，或於旺季抵達日前少於21天取消預訂，將收取一晚房費作為取消費。<br>\r\n若於淡季抵達日前少於7天或旺季抵達日前少於14天取消，或未出現（No Show），將收取全數房晚費用作為取消費。', '如在淡季抵达日前少于14天取消预订，或在旺季抵达日前少于21天取消预订，将收取一晚房费作为取消费用。<br>\r\n如在淡季抵达日前少于7天或旺季抵达日前少于14天取消，或未入住（No Show），将收取全部房晚的费用作为取消费用。', NULL, '2022-11-27 13:20:30', '2025-06-29 23:15:56', 1, 1),
(65, 'Kupu Kupu Jimbaran - Beach Club & Spa by L\'OCCITANE', '17', NULL, NULL, NULL, 'VHaV7jbQN2QT7fmI01A823DnSC', '17', NULL, '6588+JFW, Uluwatu St, Jimbaran, South Kuta, Badung Regency, Bali 80361', 1, 9, 'Uly Mardiani', '0361703342', '<div>“Kupu Kupu” is the Balinese name for Butterfly, symbol of the beauty of Balinese culture, art and decoration.</div><div><br>Enjoy our suites in a luxury hotel in Bali. Have a refreshing swim in our rooftop pool.&nbsp;Enjoy a private access to the beach, where sunbeds and parasols are waiting for you. Our Jimbaran Beach Club is near from our hotel. Lunch, snacks and dinner served on the beach.&nbsp;Relax in our Bamboo Spa by L’Occitane, for a real Bali massage with natural L’Occitane ingredients and oils.&nbsp;Choose from the many dining options: Indian tandoor and seafood at the Beach Club&nbsp;</div>', '「Kupu Kupu」是峇里語中「蝴蝶」的意思，象徵峇里文化、藝術與裝飾之美。\r\n歡迎入住我們位於峇里的奢華飯店套房。您可以在頂樓泳池暢游，享受清涼一刻。飯店提供專屬海灘通道，沙灘躺椅與遮陽傘早已為您準備妥當。我們的金巴蘭海灘俱樂部距飯店不遠，於沙灘上提供午餐、小吃與晚餐。前往 L’Occitane 竹之水療中心放鬆身心，享受採用天然 L’Occitane 成分與精油的正宗峇里式按摩。飯店亦提供多樣化的用餐選擇，包括海灘俱樂部的印度坦都烤爐料理與海鮮美食。', '“Kupu Kupu”是巴厘语中“蝴蝶”的意思，象征着巴厘文化、艺术与装饰之美。\r\n欢迎入住我们位于巴厘岛的豪华酒店套房。您可以在屋顶泳池中畅游，清爽消暑。酒店提供专属通道直达海滩，沙滩躺椅与遮阳伞已为您准备好。我们的金巴兰海滩俱乐部距离酒店不远，您可在海滩上享用午餐、小吃与晚餐。在 L’Occitane 竹子水疗中心放松，享受使用天然 L’Occitane 成分与精油的正宗巴厘按摩。酒店还提供多种餐饮选择，包括海滩俱乐部的印度坦度炉料理和海鲜佳肴。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;<br></b><ul><li>No Check out on 31 December 2025&nbsp;</li><li>Compulsory New Year Eve Dinner on 31 December 2025 Price at Additional Charge&nbsp;</li></ul><b>Honeymoon Benefits:&nbsp;</b><br><ul><li>Special honeymoon cake served on the second day&nbsp;</li><li>Special flower arrangement and flower petals in the bathtub</li></ul><ul></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2025年12月31日不可退房</li><li>\r\n2025年12月31日需參加強制性跨年晚宴，價格需另行支付</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n蜜月蛋糕將於入住第二天提供</li><li>\r\n浴缸內特別花瓣佈置與鮮花擺設</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2025年12月31日不可退房</li><li>\r\n2025年12月31日需参加强制性跨年晚宴，价格需另行支付</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n蜜月蛋糕将于入住第二天赠送</li><li>\r\n浴缸内特别花瓣装饰及鲜花摆设</li></ul>', NULL, NULL, NULL, 'Active', '1749546038_rooftop-pool-red-2-1536x862.jpg', 14, 'https://www.kupujimbaran.com/', '2', '45', NULL, NULL, 'https://g.page/padmaresortubud?share', NULL, NULL, NULL, NULL, '<ul><li>In case of any cancellation made less than 14 days prior to arrival date during low season and 21days prior to \r\narrival date during high season, one night cancellation fee will be charged.&nbsp;</li><li>In case of any cancellation less than 7 days on low season and 14 days on high season or no show, full \r\ncancellation fee of the total room nights will be charged.&nbsp;</li></ul>', '<span>若於淡季入住日前少於14天取消訂房，或於旺季入住日前少於21天取消，將收取一晚房費作為取消費用。<br>\r\n若於淡季入住日前少於7天，或旺季入住日前少於14天取消，或未如期入住（No Show），將收取全數住宿晚數的取消費用。</span>', '如在淡季入住日前少于14天取消预订，或在旺季入住日前少于21天取消，将收取一晚房费作为取消费用。<br>\r\n如在淡季入住日前少于7天，或旺季入住日前少于14天取消，或未如期入住（No Show），将收取全部住宿晚数的取消费用。', NULL, '2022-11-27 13:35:47', '2025-06-29 23:20:44', 1, 1),
(66, 'Mara River Safari Lodge', '17', NULL, NULL, NULL, 'yyu41OmIEbvCPZiZ9MJOaDkqXu', '17', NULL, 'The Amazing Taman Safari Bali, Jl. Prof. Dr. Ida Bagus Mantra No.Km. 19, Serongga, Kec. Gianyar, Kabupaten Gianyar, Bali 80551', 2, 36, 'Pradnya Swari', '03614791800', 'The first African-themed hotel in Bali. This themed safari resort in Bali gives a unique holiday experience with Safari-inspired ambiance and accommodations. Located within the grounds of&nbsp;<a target=\"_blank\" rel=\"nofollow\" href=\"https://www.balisafarimarinepark.com/\">Taman Safari Bali</a>, all lodges feature an open-air terrace. Mara River Safari Lodge Hotel is one of the best family-friendly retreats in Bali with 45 fully-equipped rooms and overwhelming facilities that reflect the rustic charm of the African Safari.', '峇里島首家非洲主題飯店。這間主題野生動物園度假村為您帶來獨特的假期體驗，擁有非洲野生動物園風格的氛圍與住宿環境。飯店座落於峇里島野生動物園（Taman Safari Bali）園區內，所有小屋皆配有露天陽台。Mara River Safari Lodge Hotel 是峇里島最適合家庭入住的度假場所之一，擁有 45 間設備齊全的客房與豐富設施，展現出非洲野生動物園的質樸魅力。', '巴厘岛首家非洲主题酒店。这家主题野生动物园度假村带来独特的假期体验，拥有非洲野生动物园风格的氛围与住宿环境。酒店位于巴厘岛野生动物园（Taman Safari Bali）园区内，所有小屋均设有露天露台。Mara River Safari Lodge Hotel 是巴厘岛最适合家庭入住的度假胜地之一，配备 45 间设施齐全的客房和丰富的设施，展现出非洲野生动物园的质朴魅力。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1759195547_50054922.jpg', 2, 'http://www.marariversafarilodge.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/3a52mXk4udzuwLSB6', NULL, NULL, NULL, NULL, '<b>Regular Season:&nbsp;</b><br><ul><li>Cancellation above 14 days prior to arrival: No Penalty&nbsp;</li><li>Cancellation within 14 days prior to arrival: 1 Night charge&nbsp;</li></ul><b>High Season (15 Jun - 31 Aug, 15 - 22 Feb):</b><br><ul><li>Cancellation above 21 days prior to arrival: No Penalty&nbsp;</li><li>Cancellation within 21 days prior to arrival: 1 Night charge&nbsp;</li></ul><b>Peak Season (15 Dec - 05 Jan):</b><br><ul><li>Cancellation above 45 days prior to arrival: No Penalty&nbsp;</li><li>Cancellation within 45 days prior to arrival: 1 Night charge&nbsp;</li></ul><b>No Show:</b> 100% of booking value&nbsp;', '一般季節：\r\n<ul>\r\n<li>\r\n抵達前超過14天取消：不收取任何費用\r\n</li>\r\n<li>\r\n抵達前14天內取消：收取1晚房費\r\n</li>\r\n</ul>\r\n旺季（6月15日－8月31日、2月15日－2月22日）：\r\n<ul>\r\n<li>\r\n抵達前超過21天取消：不收取任何費用\r\n</li>\r\n<li>\r\n抵達前21天內取消：收取1晚房費\r\n</li>\r\n</ul>\r\n尖峰季節（12月15日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達前超過45天取消：不收取任何費用\r\n</li>\r\n<li>\r\n抵達前45天內取消：收取1晚房費<br></li></ul>未出現（No Show）：將收取預訂總金額的100%。<br>', '常规季节：\r\n<ul>\r\n<li>\r\n抵达前超过14天取消：不收取任何费用\r\n</li>\r\n<li>\r\n抵达前14天内取消：收取1晚房费\r\n</li>\r\n</ul>\r\n旺季（6月15日－8月31日、2月15日－2月22日）：\r\n<ul>\r\n<li>\r\n抵达前超过21天取消：不收取任何费用\r\n</li>\r\n<li>\r\n抵达前21天内取消：收取1晚房费\r\n</li>\r\n</ul>\r\n巅峰季节（12月15日－1月5日）：\r\n<br><ul><li>抵达前超过45天取消：不收取任何费用</li><li>\r\n\r\n抵达前45天内取消：收取1晚房费</li></ul>未出现（No Show）：将收取预订总金额的100%。<br><br>', NULL, '2022-11-28 06:49:01', '2025-09-29 17:25:47', 2, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(67, 'Four Points by Sheraton Bali Ungasan', '17', NULL, NULL, NULL, 'HanW6GDMd1k8ptUKpXM3lZcndV', '17', NULL, 'Uluwatu St Banjar Giri Dharma, Ungasan, South Kuta, Badung Regency, Bali 80364', 1, 11, 'Andrew Grahitandaru MONGKOL', '03618498000', '<p>Four Points by Sheraton Bali, Ungasan welcomes travelers to Kuta Selatan, Indonesia with a stylish, comfortable and affordable experience. Located near the beach and overlooking the bright blue water of Jimbaran Bay, our hotel features modern rooms with free Wi-Fi and large workspaces. Spacious suites provide a separate living room and dining table. For those planning an event in Bali, we offer over 19,000 square feet of space, including one of Ungasan\'s largest pillarless ballrooms; exchange your wedding vows in a glass-enclosed chapel overlooking Jimbaran Bay and Garuda Wisnu Kencana Cultural Park. Our hotel is also close to the Uluwatu Temple, only moments away. Wellness is a focus here; hotel guests have access to a 24-hour fitness center, massage services and an outdoor infinity pool with views of Jimbaran Bay. Dining includes an indoor-outdoor restaurant showcasing local and international cuisines. We look forward to seeing you in Kuta Selatan at Four Points by Sheraton Bali, Ungasan. </p>', '<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&:has([data-writing-block])>*]:pointer-events-auto [content-visibility:auto] supports-[content-visibility:auto]:[contain-intrinsic-size:auto_100lvh] scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" tabindex=\"-1\" dir=\"auto\" data-turn-id=\"request-686768ed-857c-8002-a267-cfcc31ed1cbe-3\" data-testid=\"conversation-turn-392\" data-scroll-anchor=\"true\" data-turn=\"assistant\"><div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] thread-sm:[--thread-content-margin:--spacing(6)] thread-lg:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] thread-lg:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col grow\"><div data-message-author-role=\"assistant\" data-message-id=\"f343800a-43ef-48ba-9737-7f4fc0171ee2\" dir=\"auto\" class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&]:mt-1\" data-message-model-slug=\"gpt-5\"><div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\"><div class=\"markdown prose dark:prose-invert w-full break-words light markdown-new-styling\"><p data-start=\"548\" data-end=\"903\" data-is-last-node=\"\" data-is-only-node=\"\">峇里島烏加山福朋喜來登酒店（Four Points by Sheraton Bali, Ungasan）以時尚、舒適且實惠的住宿體驗，歡迎來自印尼南庫塔的旅客。酒店鄰近海灘，俯瞰金巴蘭灣湛藍海景，客房設計現代，配備免費無線網絡與寬敞工作空間。寬敞套房設有獨立客廳及餐桌。<br data-start=\"683\" data-end=\"686\">\r\n若您計劃在峇里島舉辦活動，我們提供超過19,000平方英尺的場地，包括烏加山其中一個最大的無柱宴會廳；您亦可於玻璃禮堂內舉行婚禮，俯瞰金巴蘭灣與加魯達·維斯努·肯卡納文化公園。酒店位置便利，距離烏魯瓦圖寺僅需數分鐘車程。<br data-start=\"796\" data-end=\"799\">\r\n我們重視身心健康，賓客可享受24小時健身中心、按摩服務，以及可欣賞金巴蘭灣景致的戶外無邊際泳池。餐飲方面，酒店設有室內外餐廳，提供在地與國際佳餚。我們誠摯期待在南庫塔的峇里島烏加山福朋喜來登酒店迎接您的蒞臨。</p></div></div></div></div><div class=\"z-0 flex min-h-[46px] justify-start\"></div><div class=\"mt-3 w-full empty:hidden\"><div class=\"text-center\"></div></div></div></div></article><div aria-hidden=\"true\" data-edge=\"true\" class=\"pointer-events-none h-px w-px\"></div>', '巴厘岛乌加山福朋喜来登酒店（Four Points by Sheraton Bali, Ungasan）以时尚、舒适且实惠的住宿体验，欢迎来自印度尼西亚南库塔的旅客。酒店坐落于海滩附近，俯瞰金巴兰湾湛蓝的海水，客房现代宽敞，配备免费无线网络和大型办公空间。宽敞的套房设有独立的起居室和餐桌。<br data-start=\"279\" data-end=\"282\">\r\n若您计划在巴厘岛举办活动，我们提供超过19,000平方英尺的会议空间，其中包括乌加山最大无柱宴会厅之一；您可在俯瞰金巴兰湾和加鲁达·维斯努·肯卡纳文化公园的玻璃礼堂中交换婚礼誓言。酒店地理位置优越，距离乌鲁瓦图寺也仅数分钟车程。<br data-start=\"396\" data-end=\"399\">\r\n我们注重身心健康，宾客可享受24小时健身中心、按摩服务，以及可欣赏金巴兰湾美景的无边泳池。餐饮方面，酒店设有室内外餐厅，提供本地与国际美食。我们期待在南库塔的巴厘岛乌加山福朋喜来登酒店恭候您的光临。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1720662157_dpsfg-exterior-1749-hor-wide.webp', 14, 'https://www.marriott.com/en-us/hotels/dpsfg-four-points-by-sheraton-bali-ungasan', '2', '360', NULL, NULL, 'https://goo.gl/maps/j3Z3da2Db8RKMo4Z8', NULL, NULL, NULL, NULL, '<ul><li><strong>Low Season </strong>- Room reservations may be canceled up to 14 days prior to arrival via a mutually agreed documented method. If cancellation occurs within 10 days of arrival or if a no-show occurs, a one-night cancellation fee including room and tax, will be assessed.</li><li><strong>High Season</strong> - Room reservations may be canceled up to 21 days prior to arrival via a mutually agreed documented method. If cancellation occurs within 20 days of arrival or if a no-show occurs, a full night stay fee including room and tax, will be assessed.</li><li><strong>Peak Season</strong> - Room reservations may be canceled up to 45 days prior to arrival via a mutually agreed documented method. If cancellation occurs within 40 days of arrival or if a no-show occurs, a full night stay fee including room and tax, will be assessed.</li></ul>', '<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&:has([data-writing-block])>*]:pointer-events-auto [content-visibility:auto] supports-[content-visibility:auto]:[contain-intrinsic-size:auto_100lvh] scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" tabindex=\"-1\" dir=\"auto\" data-turn-id=\"request-686768ed-857c-8002-a267-cfcc31ed1cbe-2\" data-testid=\"conversation-turn-390\" data-scroll-anchor=\"true\" data-turn=\"assistant\"><div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] thread-sm:[--thread-content-margin:--spacing(6)] thread-lg:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] thread-lg:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col grow\"><div data-message-author-role=\"assistant\" data-message-id=\"39a108d1-466c-481a-b2e9-e79f4d80fbd9\" dir=\"auto\" class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&]:mt-1\" data-message-model-slug=\"gpt-5\"><div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\"><div class=\"markdown prose dark:prose-invert w-full break-words light markdown-new-styling\"><p data-start=\"383\" data-end=\"591\" data-is-last-node=\"\" data-is-only-node=\"\">淡季 - 房間預訂可於抵達前14天透過雙方同意的書面方式取消。若於抵達前10天內取消或未入住（No Show），將收取一晚房費及稅金作為取消費用。<br data-start=\"456\" data-end=\"459\">\r\n旺季 - 房間預訂可於抵達前21天透過雙方同意的書面方式取消。若於抵達前20天內取消或未入住，將收取全晚房費及稅金作為取消費用。<br data-start=\"523\" data-end=\"526\">\r\n高峰季 - 房間預訂可於抵達前45天透過雙方同意的書面方式取消。若於抵達前40天內取消或未入住，將收取全晚房費及稅金作為取消費用。</p></div></div></div></div><div class=\"z-0 flex min-h-[46px] justify-start\"></div><div class=\"mt-3 w-full empty:hidden\"><div class=\"text-center\"></div></div></div></div></article><div aria-hidden=\"true\" data-edge=\"true\" class=\"pointer-events-none h-px w-px\"></div>', '<p>淡季 - 房间预订可在抵达前14天通过双方同意的书面方式取消。若在抵达前10天内取消或未入住（No Show），将收取一晚房费及税费作为取消费用。<br data-start=\"198\" data-end=\"201\">\r\n旺季 - 房间预订可在抵达前21天通过双方同意的书面方式取消。若在抵达前20天内取消或未入住，将收取全晚房费及税费作为取消费用。<br data-start=\"265\" data-end=\"268\">\r\n高峰季 - 房间预订可在抵达前45天通过双方同意的书面方式取消。若在抵达前40天内取消或未入住，将收取全晚房费及税费作为取消费用。<span style=\"font-size: 12px;\">﻿</span></p>', NULL, '2022-11-28 07:15:36', '2026-03-24 18:21:00', 1, 1),
(68, 'Fairfield By Marriot Bali Kuta Sunset Road', '17', NULL, NULL, NULL, '82aV1HDcufl5pU6qVSaInVrqxt', '17', NULL, 'Jl. Merdeka Raya No.VII, Abianbase, Kec. Kuta, Kabupaten Badung, Bali 80361', 1, 6, 'I Made Adi Artana', '03612099100', 'Expect a rewarding stay in Indonesia at Fairfield Bali Kuta Sunset Road. Guests arriving at our hotel in Kuta, Indonesia are treated to a pleasant blend of simplicity and value in a scenic, tropical setting. Visit Kuta Bali’s shops, fun attractions and the magnificent surf and sunsets of Double Six Beach. Our Kuta hotel is also only 15 minutes from Ngurah Rai International Airport. Stop by JABA Lobby&nbsp;Lounge for all-day high tea, cocktails and snacks. Join us at Jejaton Restaurant for fresh Indonesian and Western cuisine. After a day on the beach in Kuta, our airy, well-designed hotel rooms are brimming with natural light and boast free Wi-Fi and space to work, relax and rest. Maintain your fitness routine at our 24-hour gym, or cool off in our large outdoor pool, which features a bar. Host a conference or social event in one of our cutting-edge meeting rooms. Be sure to take advantage of our exclusive Kuta, Bali vacation packages when booking your escape to Indonesia.&nbsp;', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1744775795_Cover.webp', 14, 'www.marriott.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/taRxdgjuNCK4jJYLA', NULL, NULL, NULL, NULL, '<b>Low Season Cancellation Policy:</b><br><ul><li>If the cancellation is made 7 days or more before the arrival date, there is a 50% charge&nbsp;</li><li>If the cancellation is made 3 days or less before the arrival date, there is a full penalty&nbsp;</li></ul><b>High Season Cancellation Policy:</b>\r\n<br><ul><li>If the cancellation is made 14 days or more before the arrival date, there is a 50% charge</li><li>If the cancellation is made 7 days or less before the arrival date, there is a full penalty</li></ul>', NULL, NULL, NULL, '2022-11-28 07:39:08', '2026-03-24 18:21:00', 1, 1),
(69, 'Tanah Gajah Resort', '17', NULL, NULL, NULL, 'N7r4CSKmdL7bSJAY46JbJWqvnI', '17', NULL, 'Jalan Goa Gajah, Tengkulak Kaja Ubud, Gianyar, Bali 80571, Indonesia', 2, 40, 'Bima Hartono', '62361975685', 'Hidden among the lush undulating hills of Bali’s culture-rich highlands, Tanah Gajah, a Resort by Hadiprana (former The Chedi Club Tanah Gajah, Ubud) sits among thriving rice fields as far as the eye can see. Just outside the artists’ village of Ubud, the former estate of Hendra Hadiprana – one of Indonesia’s most respected art collectors – has been transformed into an intimate luxury resort with twenty individual villas, each featuring unique and original Balinese artworks from his collection.', '隱身於峇里島文化底蘊濃厚的高地之中，Tanah Gajah by Hadiprana 度假村（前身為烏布 Tanah Gajah 喜達屋俱樂部）坐落在一望無際、綠意盎然的稻田之間。鄰近藝術家之村——烏布，這片原為印尼最受尊敬的藝術收藏家之一 Hendra Hadiprana 的私人莊園，現已搖身一變為一座精緻奢華的度假村，擁有二十棟獨立別墅，每棟皆展示來自他私人收藏的獨特峇里藝術作品。', '隐匿于巴厘岛文化浓厚的高地之间，Tanah Gajah by Hadiprana 度假村（前身为乌布 Tanah Gajah 喜达屋俱乐部）坐落于一片广袤茂盛的稻田中，视野所及皆为翠绿之景。靠近艺术之村——乌布，这片曾为印尼最受尊敬的艺术收藏家之一 Hendra Hadiprana 的私人庄园，如今已蜕变为一座温馨奢华的度假胜地，共有二十栋独立别墅，每栋别墅皆收藏有他私人艺术品中的独特峇里艺术作品。', '<ul><li>Dining</li><li>Spa</li><li>Wedding &amp; events</li><li>Laundry service&nbsp;</li><li>Wi-Fi access&nbsp;</li><li>Gymnasium and Tennis Court&nbsp;</li></ul>', '<ul><li>餐飲服務</li><li>\r\n水療中心</li><li>\r\n婚禮與活動</li><li>\r\n洗衣服務</li><li>\r\n無線上網</li><li>\r\n健身房與網球場</li></ul>', '<ul><li>餐饮服务</li><li>\r\n水疗中心</li><li>\r\n婚礼与活动</li><li>\r\n洗衣服务</li><li>\r\n无线网络</li><li>\r\n健身房与网球场</li></ul>', '<b>Seasonal Policy :&nbsp;</b><br><ul><li>No check-in and check out on 19 March 2026 due to Nyepi Day&nbsp;</li></ul>', '季節性政策：<br>\r\n由於靜居日（Nyepi Day），2026年3月19日當天不接受入住與退房。', '季节性政策：<br>\r\n由于安靜日（Nyepi Day），2026年3月19日当天不接受入住和退房。', NULL, NULL, NULL, 'Active', '1700192866_Tanah-Gajah-Resort.webp', 14, 'https://www.tanahgajahubud.com/en', '2', '45', NULL, NULL, 'https://goo.gl/maps/nGpUzqZNu1cWRTY17', NULL, NULL, NULL, NULL, '<span><b>Regular Season</b> <i>(01 Apr - 15 Jul, 01 Sep - 22 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>Cancellation fee equivalent to up to 1 night’s room charge will be imposed if cancellation notice is received between 14 - 03 days prior to arrival,</li><li>Cancellation fee equivalent to up to full duration of stay room charge will be imposed if cancellation notice is received less than 03 days prior to arrival.&nbsp;</li></ul><span><b>Peak Season</b> <i>(16 Jul - 31 Aug, 23 Dec - 05 Jan) :&nbsp;</i></span><ul><li>Cancellation fee equivalent to 01 night’s room charge will be imposed if cancellation notice is received l between 31 days to 21 days to arrival,</li><li>Cancellation fee equivalent to the full duration of stay room charges will be imposed if cancellation notice is received less than 21 days prior to arrival.&nbsp;</li></ul><span><b>No Show :</b> Any no-show on a pre-booked reservation will be subject to a no-show penalty equivalent to full duration of stay&nbsp;</span><br>', '<span>一般季節（4月1日－7月15日、9月1日－12月22日、1月6日－3月31日）：<br></span><ul><li>\r\n若於抵達日前14至3天內取消，將收取相當於1晚房費的取消費用。</li><li>\r\n若於抵達日前少於3天取消，將收取整段住宿期間的全額房費作為取消費用。</li></ul><span>旺季（7月16日－8月31日、12月23日－1月5日）：<br></span><ul><li>\r\n若於抵達日前31至21天內取消，將收取1晚房費的取消費用。</li><li>\r\n若於抵達日前少於21天取消，將收取整段住宿期間的全額房費作為取消費用。</li></ul>未出現（No Show）：若預訂後未入住，將收取整段住宿期間的全額房費作為未出現罰金。', '<span>常规季节（4月1日－7月15日、9月1日－12月22日、1月6日－3月31日）：<br></span><ul><li>\r\n如在抵达日前14至3天内取消，将收取相当于1晚房费的取消费用。</li><li>\r\n如在抵达日前少于3天取消，将收取整个入住期间的全额房费作为取消费用。</li></ul><span>旺季（7月16日－8月31日、12月23日－1月5日）：<br>\r\n如在抵达日前31至21天内取消，将收取1晚房费的取消费用。<br>\r\n如在抵达日前少于21天取消，将收取整个入住期间的全额房费作为取消费用。</span>\r\n<span>未入住（No Show）：<br>\r\n若已预订但未入住，将收取整个入住期间的全额房费作为未入住罚金。</span>', NULL, '2022-11-28 07:55:47', '2025-06-30 00:26:36', 1, 1),
(70, 'The Garcia Ubud', '17', NULL, NULL, NULL, '7v3tg0BHFEPJLdIMS3ZqEhQWbp', '17', NULL, 'Jl. Raya Silungan, Lodtunduh, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 32, 'Dewi Arya', '03612013779', '<p>Encircled by lush rice fields and tropical greenery, The Garcia Ubud is a five-star boutique resort with modern luxury and a touch of contemporary elegance where you&rsquo;ll be swept into a realm of island-inspired sophistication. Stay in style with a collection of well-appointed guestrooms and private pool villas supported by high-end facilities. As a true celebration of Bali&rsquo;s heritage with a unique modern twist, this lifestyle resort is where you will encounter nothing less than pure perfection. Experience gracious hospitality that is second to none as all your needs are met with warm words and a genuine smile. Located in the charming village of Lontunduh, you are just minutes from the cultural attractions, shopping and dining options of central Ubud.</p>', NULL, NULL, '<p>&bull; Ksuna Restaurant<br />&bull; Camellie Restaurant<br />&bull; In-Room Dining<br />&bull; Kids Centre<br />&bull; Meeting Room<br />&bull; Swimming Pool<br />&bull; Gym<br />&bull; Yoga Centre<br />&bull; Alma Spa &amp; Wellness<br />&bull; Gift Shop<br />&bull; Shuttle Service<br />&bull; Wi-Fi Internet Access<br />&bull; Transport Service<br />&bull; Wedding Destination<br />&bull; MICE &amp; Event<br />&bull; Permaculture Activities<br />&bull; Signature Activities</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1700192978_The-Garcia-Ubud.webp', 14, 'http://www.thegarciaubud.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/CQwWYKS3At6XVzCy5', NULL, NULL, NULL, NULL, '<p><strong>Low / Normal Season :&nbsp;</strong></p><ul><li>5 days prior to arrival: One night&#39;s stay&nbsp;</li><li>Less than 5 days prior to arrival: 50% of full length of stay&nbsp;</li><li>Same day/No Show: Full length of stay&nbsp;</li></ul><p><strong>High / Peak Season </strong>(15 Jul - 15 Sep, 20 Dec - 10 Jan) :&nbsp;</p><ul><li>30 days prior to arrival: One night&#39;s stay&nbsp;</li><li>Less than 30 days to 14 days prior to arrival: 50% of full length of stay&nbsp;</li><li>Less than 14 days/No Show: Full length of stay&nbsp;</li></ul><p><strong>Seasonal Policy :&nbsp;</strong></p><ul><li>No Departure on 31 Dec 2023, No Arrival and Departure on &quot;Nyepi Day&quot; 11 March 2024&nbsp;</li><li>Three (3) nights minimum stay for staying over 31 Dec 2023&nbsp;</li></ul>', NULL, NULL, NULL, '2022-11-28 08:29:44', '2026-03-24 18:26:55', 1, 1),
(71, 'Anantara Ubud Bali Resort', '17', 'Bukian', 'Bali', 'Indonesia', 'lxKSGRgBX5W9XF8Mrr32BTORQm', '17', 17, 'Bukian, Bali, Indonesia', 3, 50, 'Wayan Sugiatmika', '03612017888', 'At Anantara Ubud Bali Resort, we invite you to retreat, unwind, and bathe in the glow of nature. Surrounded by lush rice fields and rainforest, the days here are tranquil, greeting the sunrise with yoga, floating in the pool overlooking Mt. Agung, and embarking on exceptional culinary and spa journeys.', '在安娜塔拉烏布峇里島度假村，我們誠摯邀請您遠離喧囂，放鬆身心，沐浴在大自然的光輝之中。被茂密的稻田與雨林所環繞，這裡的日子寧靜祥和，從晨間瑜伽迎接日出，到在俯瞰阿貢火山的泳池中漂浮，再到展開非凡的美食與水療之旅，每一刻都令人沉醉。', '在安纳塔拉乌布巴厘岛度假村，我们诚挚邀请您远离喧嚣，放松身心，沐浴在大自然的光辉中。被郁郁葱葱的稻田和雨林环绕，这里的日子宁静祥和，从日出时的瑜伽开始，在俯瞰阿贡火山的泳池中漂浮，开启一段非凡的美食与水疗之旅，每一刻都令人心醉神迷。', '<ul><li>Complimentary shuttle</li><li>Fitness centre</li><li>Spa</li><li>Heated swimming pool</li></ul>', '<ul><li>免費接駁車</li><li>\r\n健身中心</li><li>\r\n水療中心</li><li>\r\n溫水游泳池</li></ul>', '<ul><li>免费接驳车</li><li>\r\n健身中心</li><li>\r\n水疗中心</li><li>\r\n恒温游泳池</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>Minimum 3N stay during the peak seasons period&nbsp;(21 Dec - 05 Jan)</li><li>Check-out it not allowed on 31 December 2025</li><li>No check-in/check-out allowed on 19 March 2026 for Nyepi Period&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n巔峰季節期間（12月21日－1月5日）需至少入住3晚。</li><li>\r\n2025年12月31日不可辦理退房。</li><li>\r\n2026年3月19日靜居日（Nyepi）期間不可辦理入住與退房。</li></ul>', '季节性政策：<br><ul><li>\r\n高峰季节期间（12月21日－1月5日）需至少入住3晚。</li><li>\r\n2025年12月31日不可办理退房。</li><li>\r\n2026年3月19日安静日（Nyepi）期间不可办理入住和退房。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1731994990_anantara_ubud_bali_resort_family_pool_sky_view.webp', 14, 'https://www.anantara.com/ubud', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Anantara+Ubud+Bali+Resort/@-8.391857,115.2689835,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd221ef75dea143:0x682a0b68f8971fe7!5m2!4m1!1i2!8m2!3d-8.3918623!4d115.2715584!16s%2Fg%2F11g8_11lcp?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.3924748, 115.2713364, NULL, NULL, '<b>Low Season</b> <i>(14 Apr - 30 Jun, 01 Sep - 20 Dec, 06 Jan - 31 Mar):</i><br><ul><li>15 days or more prior to arrival: No cancellation fees&nbsp;</li><li>8-14 days prior to arrival: 50% of the full stay&nbsp;</li><li>0-7 days prior to arrival (incl.no show): 100% of the full stay&nbsp;</li></ul><b>High Season</b><i> (01 Jul - 31 Aug):</i>&nbsp;<br><ul><li>22 days or more prior to arrival: No cancellation fees&nbsp;</li><li>15-21 days prior to arrival: 50% of the full stay&nbsp;</li><li>0-14 days prior to arrival (incl.no show): 100% of the full stay&nbsp;</li></ul><b>Peak Season</b> <i>(21 Dec - 05 Jan):&nbsp;</i><br><ul><li>31 days or more prior to arrival: No cancellations fees&nbsp;</li><li>21-30 days prior to arrival: 50% of the full stay&nbsp;</li><li>0-20 days prior to arrival (incl.no show): 100% of the full stay&nbsp;</li></ul>', '淡季（4月14日－6月30日，9月1日－12月20日，1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達前15天或以上取消：無取消費用\r\n</li>\r\n<li>\r\n抵達前8－14天取消：收取全額住宿費的50%\r\n</li>\r\n<li>\r\n抵達前0－7天取消（含未出現）：收取全額住宿費的100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日）：\r\n<ul>\r\n<li>\r\n抵達前22天或以上取消：無取消費用\r\n</li>\r\n<li>\r\n抵達前15－21天取消：收取全額住宿費的50%\r\n</li>\r\n<li>\r\n抵達前0－14天取消（含未出現）：收取全額住宿費的100%\r\n</li>\r\n</ul>\r\n巔峰季節（12月21日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達前31天或以上取消：無取消費用\r\n</li>\r\n<li>\r\n抵達前21－30天取消：收取全額住宿費的50%\r\n</li>\r\n<li>\r\n抵達前0－20天取消（含未出現）：收取全額住宿費的100%</li></ul>', '淡季（4月14日－6月30日，9月1日－12月20日，1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达前15天或以上取消：无取消费用\r\n</li>\r\n<li>\r\n抵达前8－14天取消：收取全额住宿费用的50%\r\n</li>\r\n<li>\r\n抵达前0－7天取消（含未入住）：收取全额住宿费用的100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日）：\r\n<ul>\r\n<li>\r\n抵达前22天或以上取消：无取消费用\r\n</li>\r\n<li>\r\n抵达前15－21天取消：收取全额住宿费用的50%\r\n</li>\r\n<li>\r\n抵达前0－14天取消（含未入住）：收取全额住宿费用的100%\r\n</li>\r\n</ul>\r\n高峰季节（12月21日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达前31天或以上取消：无取消费用\r\n</li>\r\n<li>\r\n抵达前21－30天取消：收取全额住宿费用的50%\r\n</li>\r\n<li>\r\n抵达前0－20天取消（含未入住）：收取全额住宿费用的100%</li></ul>', NULL, '2022-11-28 08:40:35', '2026-03-25 19:11:54', 1, 2),
(72, 'Cicada Resort Bali Ubud, Autograph Collection', '17', 'Sebatu', 'Bali', 'Indonesia', 'eZiCw6aBM1WzlERre2IUtqHeT1', '17', 17, 'Sebatu, Bali, Indonesia', 3, 54, 'Ari Asfaro', '03618989999', 'Cicada Resort Bali Ubud, Autograph Collection sits just 10 minutes away from the renowned Tegalalang Rice Fields and a mere 25-minute drive from the breathtaking vistas of Kintamani. Thanks to our secluded location away from the bustling crowds, we ensure a peaceful and rejuvenating experience for all of our guests.Perfect for a romantic trip or honeymoon, the resort offers a charming and unique blend&amp;amp;nbsp;of Balinese and modern designs. Within, it contains 20 suites with valley views and 10 heated pool villas that have each been tailored to provide a wellness-focused experience. During your stay, you can enjoy a culinary journey at Tangelo Restaurant, which offers a concept of casual fine dining with international cuisine. Elsewhere, the resort also includes the Verdant Pool Lounge &amp;amp;amp; Bar, a casual dining concept serving Asian, international, and healthy options. For relaxation, visit Pravi SPA, which provides a range of therapeutic treatments. Alternatively, work on your fitness routine at the fitness centre.', '<span>Cicada Resort Bali Ubud，Autograph Collection 位於知名的德哥拉朗梯田僅10分鐘車程處，距離壯麗的京打馬尼（Kintamani）景觀僅約25分鐘車程。<br>\r\n度假村坐落於遠離喧囂的人群之外，為所有賓客提供寧靜且煥然一新的住宿體驗。這裡非常適合浪漫旅行或蜜月之旅，融合了峇里傳統與現代設計風格的迷人氛圍。</span>\r\n度假村內設有20間擁有山谷景觀的套房，以及10間配備加熱泳池的別墅，每間皆以健康養生為主題進行設計。入住期間，您可前往 Tangelo 餐廳展開一段美食之旅，該餐廳主打休閒精緻餐飲，供應各式國際料理。\r\n此外，度假村內還設有 Verdant Pool Lounge &amp; Bar，這是一間主打亞洲料理、國際美食與健康選項的休閒餐飲場所。若想放鬆身心，可造訪 Pravi SPA，提供多樣療癒療程；亦可前往健身中心維持您的健身計畫。', '<span>Cicada Resort Bali Ubud，Autograph Collection 距离著名的德格拉朗梯田仅10分钟车程，距离京打马尼壮丽景色仅约25分钟车程。<br>\r\n度假村地处幽静，远离喧嚣人群，为所有宾客提供宁静而焕然一新的入住体验。非常适合浪漫之旅或蜜月旅行，这里结合了巴厘传统与现代设计的独特魅力。</span>\r\n度假村拥有20间面朝山谷的套房，以及10间配备恒温泳池的别墅，每间皆以健康养生为核心设计。您可在入住期间造访 Tangelo 餐厅，开启一段美食之旅，餐厅主打休闲精致料理，提供国际菜系。\r\n此外，度假村还设有 Verdant Pool Lounge &amp; Bar，提供亚洲、国际及健康料理的休闲用餐体验。想要放松的宾客可前往 Pravi SPA，享受多种疗愈护理；也可在健身中心维持锻炼计划。', NULL, NULL, NULL, '<b>Honeymoon Benefit:&nbsp;</b><br><ul><li>Honeymoon decoration (flower petal on bed and bathub) and honeymoon cake set up in the room&nbsp;</li></ul>', '蜜月禮遇：<br><ul><li>\r\n蜜月佈置（床鋪與浴缸上的花瓣裝飾）及蜜月蛋糕將於房內準備。</li></ul>', '蜜月礼遇：<br><ul><li>\r\n蜜月布置（床铺和浴缸上的花瓣装饰）及蜜月蛋糕将在房间内准备。</li></ul>', NULL, NULL, NULL, 'inactive', 'hotels/covers/1744771254_Cover.jpg', 14, 'https://www.marriott.com', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Cicada+Resort+Bali+Ubud,+Autograph+Collection/@-8.3895893,115.2937091,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd21f452f6e050b:0xeaa2ef07d03d74e8!5m2!4m1!1i2!8m2!3d-8.3895946!4d115.296284!16s%2Fg%2F11g02yv714?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.3895893, 115.2937091, NULL, NULL, '<ul><li>During regular season, if cancellation occurs within 7 days of arrival, one-night cancellation fee will be assessed and if 3 day prior to arrival a 100% cancellation fee from the entire length of stay will be assessed.&nbsp;</li><li>During high season if cancellation occurs within 14 days of arrival, one-night cancellation fee will be assessed and if 7 days prior to arrival a 100% cancellation fee from the entire length of stay will be assessed.&nbsp;</li><li>If a no-show occurs, a full charge for the entire length of stay will be assessed </li></ul>', '<ul><li>在一般季節期間，若於抵達日前7天內取消，將收取一晚房費作為取消費用；若於抵達日前3天內取消，將收取整段住宿期間的100%房費作為取消費用。</li><li>\r\n在旺季期間，若於抵達日前14天內取消，將收取一晚房費作為取消費用；若於抵達日前7天內取消，將收取整段住宿期間的100%房費作為取消費用。</li><li>\r\n若未如期入住（No-show），將收取整段住宿期間的全額費用。</li></ul>', '<ul><li>在普通季节期间，如在抵达日前7天内取消，将收取一晚房费作为取消费用；如在抵达日前3天内取消，将收取整个住宿期间100%的取消费用。</li><li>\r\n在旺季期间，如在抵达日前14天内取消，将收取一晚房费作为取消费用；如在抵达日前7天内取消，将收取整个住宿期间100%的取消费用。</li><li>\r\n若未如期入住（No-show），将收取整个住宿期间的全额费用。</li></ul>', NULL, '2022-11-28 11:25:24', '2026-03-25 19:28:10', 1, 2),
(73, 'Nirwana Beach Resort Candidasa', '17', NULL, NULL, NULL, 'SpCLll1J6bUFh0hlSthc6CMs6b', '17', NULL, 'Jalan Sengkidu, Jl. Raya Candidasa, Sengkidu, Kec. Manggis, Kabupaten Karangasem, Bali 80871', 2, 64, 'Mardian Putra', '085829334600', 'Guests at Nirwana Beach &amp; Resort can expect a blend of luxury, comfort, and natural beauty. The resort\'s tranquil environment, combined with its comprehensive facilities and attentive service, creates a memorable and relaxing getaway. Whether you’re looking for a romantic retreat, a family vacation, or a place to unwind and recharge, Nirwana Beach &amp; Resort provides an idyllic setting and a high-quality hospitality experience.', '入住 Nirwana Beach &amp; Resort 的賓客可期待奢華、舒適與自然美景的完美結合。度假村寧靜的環境，搭配完善的設施與細緻貼心的服務，為旅客打造難忘而放鬆的假期體驗。無論您是尋求浪漫之旅、家庭度假，或只是想放鬆身心、重新充電，Nirwana Beach &amp; Resort 都提供理想的環境與高品質的待客服務。', '入住 Nirwana Beach &amp; Resort 的宾客可享受奢华、舒适与自然美景的完美融合。度假村宁静的环境，结合完善的设施和周到的服务，为宾客营造一个难忘而放松的度假体验。无论您是寻找浪漫之旅、家庭假期，还是想要放松充电，Nirwana Beach &amp; Resort 都提供理想的环境和高品质的款待体验。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Minimum stay 3 nights during peak season NY Eve (27 Dec - 05 Jan)</li></ul>', '季節性政策：<br><ul><li>\r\n跨年巔峰季期間（12月27日－1月5日）最低入住晚數為3晚。</li></ul>', '季节性政策：<br><ul><li>\r\n跨年高峰季期间（12月27日－1月5日）最低入住晚数为3晚。</li></ul>', NULL, NULL, NULL, 'Active', '1737092959_WhatsApp Image 2025-01-17 at 13.43.25.jpeg', 14, 'https://nirwanabeachandresort.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/kDAumDjLrzz3cBMX7', NULL, NULL, NULL, NULL, '<span><b>Regular Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 22 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 30% from the total booking or 1 night charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 30% from the total booking or 1 night charge</li><li>Cancellation made within 14 - 8 days to arrival : 50% from the total booking or full charge for booking 1 night&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>High Season</b> <i>(01 Jul - 31 Aug, 23 - 26 Dec) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 01 night charge</li><li>Cancellation made within 21 - 15 days to arrival : 50% of total length of stay</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>Peak Season</b> <i>(27 Dec - 05 Jan) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul>', '平季（4月1日－6月30日，9月1日－12月22日，1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達前60－22天取消：收取總預訂金額的30%或1晚房費\r\n</li>\r\n<li>\r\n抵達前21－15天取消：收取總預訂金額的30%或1晚房費\r\n</li>\r\n<li>\r\n抵達前14－8天取消：收取總預訂金額的50%，若僅預訂1晚則收取全額\r\n</li>\r\n<li>\r\n抵達前7－1天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日，12月23日－26日）：\r\n<ul>\r\n<li>\r\n抵達前60－22天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達前21－15天取消：收取總住宿期間的50%\r\n</li>\r\n<li>\r\n抵達前14－8天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前7－1天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的100%\r\n</li>\r\n</ul>\r\n巔峰季節（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達前60－22天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前21－15天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前14－8天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前7－1天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的100%</li></ul>', '常规季节（4月1日－6月30日，9月1日－12月22日，1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达前60－22天取消：收取总预订金额的30%或1晚房费\r\n</li>\r\n<li>\r\n抵达前21－15天取消：收取总预订金额的30%或1晚房费\r\n</li>\r\n<li>\r\n抵达前14－8天取消：收取总预订金额的50%，若仅预订1晚则收取全额\r\n</li>\r\n<li>\r\n抵达前7－1天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日，12月23日－26日）：\r\n<ul>\r\n<li>\r\n抵达前60－22天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达前21－15天取消：收取总住宿期间的50%\r\n</li>\r\n<li>\r\n抵达前14－8天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前7－1天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的100%\r\n</li>\r\n</ul>\r\n高峰季节（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达前60－22天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前21－15天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前14－8天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前7－1天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的100%</li></ul>', NULL, '2022-11-28 11:43:18', '2025-06-30 19:08:21', 1, 1),
(74, 'Titik Dua Ubud', '17', NULL, NULL, NULL, 'IUPREDOVxpu8syD5maVij3bVOo', '17', NULL, 'Jl. Cok Rai Pudak No.48, Peliatan, Kecamatan Ubud, Kabupaten Gianyar ,Bali, Indonesia', 2, 38, 'Prabowo Tuwiryono', '081139603939', '<p>An independent boutique hotel showcasing contemporary Indonesian design, art, and culture. Located in Peliatan Village, a short 10-min drive from Ubud, Titik Dua features 22 custom-designed rooms, a roof-top restaurant with forest views serving Modern Asian fare, and a speakeasy-inspired Coffee and Cocktail Bar. Featuring 6 multi-purpose spaces and an open-air amphitheater, to accommodate unique corporate events, wellness retreats, and intimate weddings. In keeping with the hotel&rsquo;s mission of bringing local creative talent to the global stage, Titik Dua curates a regular lineup of design-led exhibitions, innovative talks and workshops.</p>', NULL, NULL, '<p>- Free Internet Access<br />- Free Parking<br />- Restaurant<br />- Fitness Center<br />- Pool<br />- Spa<br />- Digital Key<br />- Digital Check-In<br />- Resort Property<br />- Laundry<br />- Concierge<br />- Meeting Facilities&nbsp;&nbsp; &nbsp;</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>For the reason of furniture placement and arrangement, we do not recommend to put extra bed in the room</li></ul>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1700193395_Titik-Dua-Ubud.webp', 2, 'https://titikdua.id/', '2', '45', NULL, NULL, 'https://goo.gl/maps/gAYnghvq9wM1Qwp47', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-28 12:01:25', '2026-03-24 18:26:55', 2, 1),
(75, 'Handara Golf & Resort', '17', 'Wanagiri', 'Bali', 'Indonesia', '9demoFtXj6WyR2IFHEcc82T3Vn', '17', 17, 'Jalan Pancasari, Wanagiri, Bali, Indonesia', 3, 70, 'Anggi Lisandy', '062361771234', '<span>Handara Golf &amp; Resort Bali is a mountain golf course &amp; resort. It boasts a world class golf course in a magnificent setting, cozy hotel and cottage accommodation and a beautiful dining experience. <br>Come and experience the natural wonderland featuring lush tropical gardens, cool weather, and breathtaking mountain scenery. A perfect place to getaway from the hustle and bustle.<br>Handara has benefited from some major recent renovations. Come and experience the new Breeze Terrace with amazing 180 degree panorama over the spectacular mountain view. Another unforgettable experience is the new Soyokaze restaurant where guests can enjoy Japanese cuisine by Handara’s veteran chef whilst appreciating the serene ambiance provided by the stunning panorama. Other renovations include the new Pro-Shop, Ladies Locker Room, renovated Cottage and Chalet rooms.</span>', '<span>Handara Golf &amp; Resort Bali 是一座位於山區的高爾夫球場與度假村。這裡擁有世界級的高爾夫球場、舒適的飯店與小屋住宿，以及絕佳的餐飲體驗。<br>\r\n來此親身體驗這片自然仙境，享受茂密的熱帶花園、涼爽的氣候，以及令人屏息的壯麗山景。這裡是遠離塵囂、放鬆身心的完美場所。</span>\r\nHandara 近期完成了多項重大翻新工程。全新開放的 Breeze Terrace 提供壯麗的180度山景全景，令人驚嘆。另一項令人難忘的體驗是全新的 Soyokaze 餐廳，賓客可在此享用由 Handara 資深主廚烹製的日式料理，同時欣賞壯闊景緻所營造出的寧靜氛圍。其他翻新項目還包括全新的高爾夫用品店、女士更衣室，以及經過整修的小屋與山間小屋客房。', '<span>Handara Golf &amp; Resort Bali 是一家坐落于山间的高尔夫球场与度假村。这里拥有世界级的高尔夫球场、舒适的酒店和小屋住宿，以及优质的用餐体验。<br>\r\n来此亲身体验这片自然仙境，感受郁郁葱葱的热带花园、凉爽的天气，以及令人叹为观止的壮丽山景。这是一个远离喧嚣、放松身心的理想之地。</span>\r\nHandara 最近进行了多项重大翻新。全新的 Breeze Terrace 拥有令人惊艳的180度壮观山景全景，绝对不容错过。另一段难忘的体验是全新开设的 Soyokaze 餐厅，宾客可以在宁静的氛围中，一边欣赏迷人的景致，一边享用 Handara 资深主厨烹制的精致日式料理。其他翻新还包括全新的高尔夫用品店、女士更衣室，以及翻新的小屋和山间别墅客房。', '<ul><li>Golf Lessons</li><li>Caldera Valley Tennis Court</li><li>Pro Shop</li><li>Driving Range</li><li>Locker Rooms</li><li>Golf Club Rental</li><li>Massage Treatments</li><li>Private Outdoor BB</li></ul>', '<ul><li>高爾夫課程</li><li>\r\nCaldera Valley 網球場</li><li>\r\n高爾夫專賣店</li><li>\r\n練習場</li><li>\r\n更衣室</li><li>\r\n高爾夫球具租借</li><li>\r\n按摩療程</li><li>\r\n私人戶外烤肉區</li></ul>', '<ul><li>高尔夫课程</li><li>\r\nCaldera Valley 网球场</li><li>\r\n高尔夫专卖店</li><li>\r\n练习场</li><li>\r\n更衣室</li><li>\r\n高尔夫球具租赁</li><li>\r\n按摩疗程</li><li>\r\n私人户外烧烤区</li></ul>', '<b>Seasonal Policy :&nbsp;</b><ul><li>There may be a meal charge added to bookings made for the Christmas Eve Dinner on December 24th, the Christmas Day Brunch on the 25th, and the New Year’s Eve Dinner on the 31st.</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n於12月24日的平安夜晚宴、12月25日的聖誕節早午餐，以及12月31日的新年夜晚宴期間，預訂可能需另行支付餐飲費用。</li></ul>', '季节性政策：<br><ul><li>\r\n在12月24日的平安夜晚宴、12月25日的圣诞节早午餐，以及12月31日的跨年晚宴期间，预订可能需另行收取餐食费用。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1700193532_Handara-Golf-and-Resort.webp', 14, 'https://www.handaragolfresort.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Handara+Golf+%26+Resort+Bali/@-8.2452498,115.158783,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd18ecb99acea5f:0xb7edeef6483860ff!5m2!4m1!1i2!8m2!3d-8.2452551!4d115.1613579!16s%2Fg%2F1td0jtfd?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.2462008, 115.1625731, NULL, NULL, '<ul><li>\r\nHotel cancellation: A 50% non-refundable down payment is required to secure your hotel booking \r\nwithin 7 days of receiving the confirmation.  \r\nCancellation must be submitted in writing. If cancellation is made at least 2 weeks before the date of \r\nstay, the down payment can be deposited for a future booking (reschedule).  \r\nA 100% cancellation fee will be charged for no-show guests or for any cancellation received less than \r\n2 weeks before the date of arrival.</li></ul>', '<ul><li>飯店取消政策：為了確認您的飯店預訂，需在收到確認後7天內支付50%的不可退還訂金。取消必須以書面方式提交。若在入住日前至少兩週提出取消，訂金可保留作為未來預訂（改期）使用。若未如期入住（No-show）或在入住日前少於兩週提出取消，將收取100%的取消費用。</li></ul>', '<ul><li>酒店取消政策：为确保您的酒店预订，需在收到确认后7天内支付50%不可退还的订金。取消必须以书面形式提交。如在入住日期前至少两周取消，订金可用于未来预订（改期）。若未如期入住（No-show）或在抵达日期前不足两周取消，将收取100%取消费用。</li></ul>', NULL, '2022-11-28 12:31:39', '2026-03-25 19:39:00', 1, 2),
(76, 'Munduk Moding Plantation Nature Resort & Spa', '17', NULL, NULL, NULL, 'mcPsOPOBBvGQPLFrJ0Ivmd4g2n', '17', NULL, 'Jl. Asah Gobleg, Gobleg, Kec. Banjar, Kabupaten Buleleng ,Bali, Indonesia', 4, 88, 'Gede Suparwata', '08113810123', '<p>Munduk Moding Plantation (MMP) is where Bali&rsquo;s skies blend with the water of our infinity pool, the Bali Sea and the towering volcanoes in Java. Where nature creates art. Incomparable views serenaded by birdsong and a choir of crickets. A hideaway nestled in a working coffee plantation surrounded by jungle. Here the real Bali is alive. MMP has been named the best Luxury Eco/Green Hotel in South Asia in 2020 by the World Luxury Hotels Association and our main pool was nominated by Asia Spa as one of the best 10 Infinity pools in the world in 2014.</p>', NULL, NULL, '<p>- Free Internet Access<br />- Free Parking<br />- Restaurant<br />- Pool<br />- Spa<br />- Digital Key<br />- Digital Check-In<br />- Resort Property<br />- Laundry<br />- Concierge</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Complimentary afternoon tea/coffee will be served with home-made cookies</li><li>Stay 1 night, &nbsp;will get 1 time Head &amp; Shoulder <strong>OR</strong>&nbsp;Footh Massage for 30 minutes</li><li>Stay 2 nights, &nbsp;are entitled to the following benefits: 1&nbsp;time Balinese Massage for 1 Hour for up to 2 persons <strong>OR</strong>&nbsp;alternatively 1 Hour Horse Riding <strong>OR</strong>&nbsp;Cycling <strong>OR 1</strong>&nbsp;time Lunch Trekking to nearby bamboo grove and orchids</li></ul>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1700193615_Munduk-Moding-Plantation.webp', 2, 'https://www.mundukmodingplantation.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/1UeBasVDvcLEeu858', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-28 13:33:54', '2026-03-24 18:26:55', 2, 1),
(77, 'Solia Legian Bali', '17', NULL, NULL, NULL, 'aAIJh2JfnBGBOoSOy9Qfge5H7e', '17', NULL, 'Jl. Sriwijaya No.16, Legian, Kec. Kuta, Kabupaten Badung, Bali 80361', 1, 7, 'Tari', '03614752999', 'Solia Legian Bali is an urban hotel located in the popular Legian area, near of Bali’s shop, Restaurant, Bar and Night Club. With aesthetically in fresh modern design, bright interior and stylish tastefully furnishings are a perfect match for the modern traveler, foodies and social. With tagline BEACH, PARTY, &amp; RECHARGE, Solia Legian Bali bring a one-stop entertainment concept. Featuring 136 spacious rooms with a complete list of traveler facilities, fitness center, outdoor pool, large Jacuzzi on the rooftop, three restaurant outlets and one huge indoor nightclub.', 'Solia Legian Bali 是一家位於熱門的雷吉安地區的城市酒店，鄰近峇里島的購物區、餐廳、酒吧和夜店。以清新現代的美學設計、明亮的室內空間和時尚雅緻的家具，完美契合現代旅行者、美食愛好者和社交人士的需求。秉承「BEACH, PARTY &amp; RECHARGE（海灘、派對與充電）」的口號，Solia Legian Bali 帶來一站式娛樂概念。酒店擁有136間寬敞客房，配備完善的旅行者設施，包括健身中心、戶外泳池、屋頂大型按摩浴池、三家餐廳以及一個超大室內夜店。', 'Solia Legian Bali 是一家位于热门的雷吉安地区的城市酒店，毗邻巴厘岛的购物区、餐厅、酒吧和夜店。以清新现代的美学设计、明亮的室内空间和时尚雅致的家具，完美契合现代旅行者、美食爱好者和社交人士的需求。秉承“BEACH, PARTY &amp; RECHARGE（海滩、派对与充电）”的口号，Solia Legian Bali 带来一站式娱乐概念。酒店拥有136间宽敞客房，配备完善的旅行者设施，包括健身中心、户外泳池、屋顶大型按摩浴池、三家餐厅以及一个超大室内夜店。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1755596960_6695e81d99d59557236887.webp', 14, 'https://solialegian.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/dzcKksmUFfGE1qTJA', NULL, NULL, NULL, NULL, '<b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 23 Dec, 07 Jan - 31 Mar):&nbsp;</i><br><ul><li>If the event of the cancellation made less than 7 days, 50% of room rate reserved to be applied.</li><li>If the event of the cancellation made less than 3 days, 100% of room rate reserved to be \r\napplied.</li></ul><b>High Season</b> <i>(01 Jul - 31 Aug):&nbsp;</i><br><ul><li>If the event of the cancellation made less than 14 days, 50% of room rate reserved to be \r\napplied.</li><li>If the event of the cancellation made less than 7 days, 100% of room rate reserved to be \r\napplied.</li></ul><b>Peak Season</b> <i>(24 Dec - 06 Jan) :&nbsp;</i><br><ul><li>If the event of the cancellation made less than 21 days, 50% of room rate reserved to be \r\napplied.</li><li>If the event of the cancellation made less than 14 days, 100% of room rate reserved to be \r\napplied.&nbsp;</li></ul>', '淡季（4月1日 – 6月30日，9月1日 – 12月23日，1月7日 – 3月31日）：\r\n<ul>\r\n<li>\r\n如在入住日前少於7天取消，需支付已預訂房價的50%。\r\n</li>\r\n<li>\r\n如在入住日前少於3天取消，需支付已預訂房價的100%。\r\n</li>\r\n</ul>\r\n旺季（7月1日 – 8月31日）：\r\n<ul>\r\n<li>\r\n如在入住日前少於14天取消，需支付已預訂房價的50%。\r\n</li>\r\n<li>\r\n如在入住日前少於7天取消，需支付已預訂房價的100%。\r\n</li>\r\n</ul>\r\n高峰季（12月24日 – 1月6日）：\r\n<ul>\r\n<li>\r\n如在入住日前少於21天取消，需支付已預訂房價的50%。\r\n</li>\r\n<li>\r\n如在入住日前少於14天取消，需支付已預訂房價的100%。\r\n</li>\r\n</ul>', '淡季（4月1日 – 6月30日，9月1日 – 12月23日，1月7日 – 3月31日）：\r\n<ul>\r\n<li>\r\n如在入住日前少于7天取消，需支付已预订房价的50%。\r\n</li>\r\n<li>\r\n如在入住日前少于3天取消，需支付已预订房价的100%。\r\n</li>\r\n</ul>\r\n旺季（7月1日 – 8月31日）：\r\n<ul>\r\n<li>\r\n如在入住日前少于14天取消，需支付已预订房价的50%。\r\n</li>\r\n<li>\r\n如在入住日前少于7天取消，需支付已预订房价的100%。\r\n</li>\r\n</ul>\r\n高峰季（12月24日 – 1月6日）：\r\n<ul>\r\n<li>\r\n如在入住日前少于21天取消，需支付已预订房价的50%。\r\n</li>\r\n<li>\r\n如在入住日前少于14天取消，需支付已预订房价的100%。\r\n</li>\r\n</ul>', NULL, '2022-11-28 13:51:13', '2025-08-19 21:41:34', 1, 1),
(78, 'AnandaDara Ubud Resort and SPA', '17', 'Kenderan', 'Bali', 'Indonesia', 'ml7BpJ6zjI9sBS3Bwt6IvBpnMs', '17', 17, 'Kenderan, Bali, Indonesia', 2, 45, 'Marty Uli', '081338888278', 'Nestled in the heart of Tegallalang, the AnandaDara Ubud Resort &amp;amp;amp; Spa is a testament to the seamless integration of classy design and the natural beauty of Bali. Expertly crafted by acclaimed Balinese architect, Miyoga, the resort is a harmonious blend of traditional Balinese elements and modern comforts. Surrounded by lush rice paddies and meticulously manicured gardens, AnandaDara invites guests to a serene retreat that captures the essence of Bali’s charm.', '坐落於德哥拉朗（Tegallalang）中心的 AnandaDara 烏布渡假村及水療中心，完美詮釋了優雅設計與峇里島自然之美的無縫融合。由知名峇里島建築師 Miyoga 精心打造，度假村將傳統峇里島元素與現代舒適設施巧妙結合。四周環繞著翠綠稻田與精心修剪的花園，AnandaDara 為賓客帶來一處靜謐的度假天堂，盡情感受峇里島的獨特魅力。', '坐落于德哥拉朗（Tegallalang）中心的 AnandaDara 乌布度假村及水疗中心，完美诠释了优雅设计与巴厘岛自然之美的无缝融合。由知名巴厘岛建筑师 Miyoga 精心打造，度假村将传统巴厘岛元素与现代舒适设施巧妙结合。四周环绕着翠绿稻田与精心修剪的花园，AnandaDara 为宾客带来一处静谧的度假天堂，尽情感受巴厘岛的独特魅力。', NULL, NULL, NULL, 'No check in and no check out on - seclusion day (Nyepi Day)&amp;amp;nbsp;', '寧靜日（巴厘島靜居日 / Nyepi Day）當日禁止辦理入住與退房。', '静居日（巴厘岛安宁日 / Nyepi Day）当天禁止办理入住与退房。', NULL, NULL, NULL, 'active', 'hotels/covers/1754979501_AnandaDara-Ubud_Main-Pool-scaled.webp', 14, 'https://www.anandadara.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/AnandaDara+Ubud+Resort+%26+Spa/@-8.4678317,115.2669621,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd2235d54eadbab:0x58721c2a9d4514b2!5m2!4m1!1i2!8m2!3d-8.467837!4d115.269537!16s%2Fg%2F11vq6k7r72?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.4676172, 115.2695933, NULL, NULL, '<b>Normal Season:</b> <i>01 Oct - 20 Dec 2025, 06 Jan - 31 Mar&nbsp;</i><br><b>High Season:</b> <i>01 Jul - 30 Sep&nbsp;</i><br><b>Peak Season:</b> <i>21 Dec 2025 - 05 Jan&nbsp;</i><ul><li>Prior to 14 days for the normal season and 21 days for high and peak season, no penalty fee&nbsp;</li><li>Within 14 days for the normal season any cancellation or modification is subject to first night of accommodation&nbsp;</li><li>Within 21 days for high and peak season any cancellation is subject to the 50% of accommodation at your daily \r\ncontracted room rate for each room booked&nbsp;</li><li>For No Show and shortened stay on the site/ after check-in will be 100% charged according to the initial \r\nreservation amount&nbsp;</li></ul>', '<span>平季（Normal Season）： 10月1日－12月20日、1月6日－3月31日<br>\r\n旺季（High Season）：7月1日－9月30日<br>\r\n尖峰季（Peak Season）： 12月21日－1月5日</span>\r\n<br><span>在平季入住日前14天前，旺季與尖峰季入住日前21天前取消，無需支付罰金。<br>\r\n平季入住日前14天內的任何取消或更改，需支付首晚住宿費用。<br>\r\n旺季與尖峰季入住日前21天內的任何取消，需支付每間房依照每日合約房價計算的50%住宿費用。<br>\r\n未如期入住（No Show）或入住後縮短住宿天數，將依原始預訂金額全額（100%）收取費用。</span>', '<span>平季（Normal Season）：10月1日－12月20日、1月6日－3月31日<br>\r\n旺季（High Season）： 7月1日－9月30日<br>\r\n峰季（Peak Season）：12月21日－1月5日</span>\r\n<br><span>在平季入住日前14天前，旺季与峰季入住日前21天前取消，无需支付罚金。<br>\r\n平季入住日前14天内的任何取消或更改，需支付首晚住宿费用。<br>\r\n旺季与峰季入住日前21天内的任何取消，需支付每间房依照每日合同房价计算的50%住宿费用。<br>\r\n未如期入住（No Show）或入住后缩短住宿天数，将按原始预订金额全额（100%）收取费用。</span>', NULL, '2022-11-29 07:50:14', '2026-03-25 19:10:50', 1, 2),
(79, 'Lovina Beach Club & Resort', '17', NULL, NULL, NULL, 'NjlGiZEtCrfKqE2w4iet1a8ovk', '17', NULL, 'Jl. Seririt- Singaraja, Tukadmungga, Kec. Buleleng, Kabupaten Buleleng, Bali 81119', 3, 97, 'Mardian Putra', '08113812658', 'Welcome to the heavenly Lovina Beach Club and Resort, nestled in the serene enclave of Lovina, Singaraja, just a leisurely 3-hour drive from the International Ngurah Rai Airport. Our resort beckons with 50 elegantly designed suites, each infused with modern Balinese inspiration. Sink into the plush comfort of a king-size bed and immerse yourself in a world of luxury, complete with state-of-the-art amenities to cater to your every need. Dedicated to crafting unparalleled guest experiences, our resort is the quintessential destination for both family getaways and romantic honeymooners alike. With direct access to the breathtaking Lovina Beach, guests can revel in the beauty of the horizon from our infinity pool.', '歡迎來到天堂般的 Lovina Beach Club and Resort，度假村坐落於寧靜的羅威那（Lovina），位於新加拉惹（Singaraja）的幽靜區域，距離伍拉·賴國際機場僅約三小時車程。我們擁有50間優雅設計的套房，每一間皆融合現代峇里島風格靈感。沉醉於特大號床的柔軟舒適之中，享受極致奢華生活，配備先進設施，滿足您所有需求。\r\n我們致力於打造無與倫比的賓客體驗，是家庭度假與浪漫蜜月旅行的理想之選。度假村直通壯麗的羅威那海灘，賓客可在無邊際泳池中欣賞海天一色的美景。', '<span>欢迎来到天堂般的 Lovina Beach Club and Resort，度假村位于宁静的罗威那（Lovina）、新加拉惹（Singaraja）幽静区域，距离伍拉·赖国际机场仅约三小时车程。<br>\r\n我们拥有50间优雅设计的套房，每间都融合了现代巴厘岛风格灵感。沉浸在特大床的舒适中，享受极致奢华生活，配备先进设施，满足您的所有需求。</span>\r\n度假村致力于为宾客打造无与伦比的体验，是家庭度假与浪漫蜜月旅行的理想选择。度假村直通壮观的罗威那海滩，宾客可在无边际泳池中欣赏迷人的海天一线景色。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Minimum stay 3 nights during peak season NY Eve (27 Dec - 05 Jan)</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n跨年巔峰季（12月27日－1月5日）期間，最低入住晚數為3晚。</li></ul>', '季节性政策：<br><ul><li>\r\n跨年高峰季（12月27日－1月5日）期间，最低入住晚数为3晚。</li></ul>', NULL, NULL, NULL, 'Active', '1737343385_WhatsApp Image 2025-01-20 at 11.22.30.jpeg', 14, 'https://lovinabeachclubandresort.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/Gfyx2gBq3gGcztyf9', NULL, NULL, NULL, NULL, '<span><b>Regular Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 22 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 30% from the total booking or 1 night charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 30% from the total booking or 1 night charge</li><li>Cancellation made within 14 - 8 days to arrival : 50% from the total booking or full charge for booking 1 night&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>High Season</b> <i>(01 Jul - 31 Aug, 23 - 26 Dec) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 01 night charge</li><li>Cancellation made within 21 - 15 days to arrival : 50% of total length of stay</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>Peak Season</b> <i>(27 Dec - 05 Jan) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul>', '平季（4月1日－6月30日，9月1日－12月22日，1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達前60－22天取消：收取總預訂金額的30%或1晚房費\r\n</li>\r\n<li>\r\n抵達前21－15天取消：收取總預訂金額的30%或1晚房費\r\n</li>\r\n<li>\r\n抵達前14－8天取消：收取總預訂金額的50%，若僅預訂1晚則收取全額\r\n</li>\r\n<li>\r\n抵達前7－1天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日，12月23日－26日）：\r\n<ul>\r\n<li>\r\n抵達前60－22天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達前21－15天取消：收取總住宿期間的50%\r\n</li>\r\n<li>\r\n抵達前14－8天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前7－1天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的100%\r\n</li>\r\n</ul>\r\n巔峰季節（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達前60－22天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前21－15天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前14－8天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n抵達前7－1天取消：收取總預訂金額的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取總預訂金額的100%</li></ul>', '常规季节（4月1日－6月30日，9月1日－12月22日，1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达前60－22天取消：收取总预订金额的30%或1晚房费\r\n</li>\r\n<li>\r\n抵达前21－15天取消：收取总预订金额的30%或1晚房费\r\n</li>\r\n<li>\r\n抵达前14－8天取消：收取总预订金额的50%，如仅预订1晚则收取全额\r\n</li>\r\n<li>\r\n抵达前7－1天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的100%\r\n</li>\r\n</ul>\r\n旺季（7月1日－8月31日，12月23日－26日）：\r\n<ul>\r\n<li>\r\n抵达前60－22天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达前21－15天取消：收取总住宿期间的50%\r\n</li>\r\n<li>\r\n抵达前14－8天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前7－1天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的100%\r\n</li>\r\n</ul>\r\n高峰季节（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达前60－22天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前21－15天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前14－8天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n抵达前7－1天取消：收取总预订金额的100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的100%</li></ul>', NULL, '2022-11-29 08:03:01', '2025-06-30 19:17:22', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(80, 'Luxotic Private Villas & Resort', '17', NULL, NULL, NULL, '2Oe0PYyeft4eyNYgijtAtZH3HD', '17', NULL, 'Jl. Taman Ria No.12, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80363', 1, 11, 'Yanty Zhang', '03618498968', '<span>\"Where we love is home, home that our feet may leave but not our hearts\"<br><br>Bali is an unforgettable place to create unforgettable memories with your loved ones. This home-away-from-home villa is designed ideally for a quality time with spouse, entertaining friends and spending time with your family. A perfect home for you to fill your loved ones with warm memories so it becomes treasures in their heart.</span>', '「我們所愛之處，就是家；腳步也許會離開，心卻永遠留在那裡。」\r\n<span>峇里島是與摯愛一同創造難忘回憶的絕佳地點。這間如家般溫暖的別墅，專為與伴侶共度美好時光、招待好友及陪伴家人而設計。<br>\r\n這是您理想的家外之家，讓摯愛們心中裝滿溫馨的回憶，成為他們心中永遠的珍寶。</span>', '「我们所爱之处，就是家；脚步或许会离开，心却永远留在那里。」\r\n<span>巴厘岛是与亲人一起创造难忘回忆的绝佳地方。这间宛如家一般的别墅，专为与伴侣共享时光、招待朋友以及陪伴家人而设计。<br>\r\n这是一个理想的家外之家，让你所爱的人心中充满温暖的回忆，成为他们永远珍藏的宝物。</span>', '<ul><li>Complimentary playing billiard at lobby </li></ul>', '<ul><li>大廳免費提供撞球娛樂</li></ul>', '<ul><li>大堂免费提供台球娱乐</li></ul>', '<b>Seasonal Policy: </b><ul><li>No check in and check out on 19 March 2026 due to Silent Day </li><li>No check out on 31st Dec </li></ul><b>Honeymoon Benefit: </b><ul><li>Honeymoon set up upon arrival in the room. Date of Wedding is required upon reservation </li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n由於寧靜日（Silent Day），2026年3月19日不允許辦理入住與退房。</li><li>\r\n2025年12月31日當天不允許退房。</li></ul><span>蜜月優惠：<br></span><ul><li>\r\n客房將於抵達時進行蜜月佈置。預訂時需提供結婚日期。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n由于静居日（Silent Day），2026年3月19日当天不允许办理入住和退房。</li><li>\r\n2025年12月31日当天不允许退房。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时客房将进行蜜月布置。预订时需提供结婚日期。</li></ul>', NULL, NULL, NULL, 'Active', '1731995474_Luxotic-Private-Villa-And-Resort-Nusa-Dua-Exterior.webp', 14, 'https://luxoticvilla.com/', '2', '360', NULL, NULL, 'https://goo.gl/maps/RwVcXkZc7b8WgNyx8', NULL, NULL, NULL, NULL, '<span><b>Normal Season</b> <i>(01 Apr - 14 Jul, 01 Sep - 22 Dec, 04 Jan - 03 Feb, 15 Feb - 03 Mar, 15 - 31 Mar):&nbsp;</i></span><ul><li>Cancellation 5 days&nbsp;prior to arrival: 1 night charge&nbsp;</li></ul><span><b>High Season</b>&nbsp;<i>(15 Jul - 31 Aug, 04 - 14 Feb, 04 - 14 Mar):</i>&nbsp;</span><ul><li>Cancellation 10 days&nbsp;prior to arrival: 1 night charge</li></ul><span><b>Peak Season</b> <i>(23 Dec - 03 Jan):&nbsp;</i></span><ul><li>Cancellation 21 days prior to arrival: full charge&nbsp;</li></ul>No show will be subject to a penalty equal to \"a full charge on the whole period of stay\"&nbsp;<br>', '普通季節（4月1日－7月14日、9月1日－12月22日、1月4日－2月3日、2月15日－3月3日、3月15日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達前5天取消：收取1晚房費\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日、2月4日－2月14日、3月4日－3月14日）：\r\n<ul>\r\n<li>\r\n抵達前10天取消：收取1晚房費\r\n</li>\r\n</ul>\r\n巔峰季節（12月23日－1月3日）：\r\n<ul>\r\n<li>\r\n抵達前21天取消：收取全額住宿費用\r\n</li>\r\n</ul>\r\n若未如期入住（No Show），將收取整個住宿期間的全額費用作為取消罰金。', '普通季节（4月1日－7月14日、9月1日－12月22日、1月4日－2月3日、2月15日－3月3日、3月15日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达前5天取消：收取1晚房费\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日、2月4日－2月14日、3月4日－3月14日）：\r\n<ul>\r\n<li>\r\n抵达前10天取消：收取1晚房费\r\n</li>\r\n</ul>\r\n高峰季节（12月23日－1月3日）：\r\n<ul>\r\n<li>\r\n抵达前21天取消：收取全额住宿费用\r\n</li>\r\n</ul>\r\n若未如期入住（No Show），将收取整个住宿期间的全额费用作为取消罚金。', NULL, '2022-11-29 08:19:06', '2026-02-11 23:31:31', 1, 1),
(81, 'Samuh Ocean Sunset Hotel by WizZeLa', '17', NULL, NULL, NULL, 'jgsr1qY5IW3izOh1oAmqRGTB2q', '17', NULL, 'Banjar Anyar, Dusun Sebunibus 80771, Nusa Penida', 4, 50, 'Ratna Desi', '7996905', '<p>Hotel with Ocean View in Nusa Penida<br />You can see Ocean View, Sunrise, Sunset, Lembongan</p>', NULL, NULL, '<p>- Free Internet Access<br />- Free Parking<br />- Restaurant<br />- Fitness Center<br />- Pool<br />- Spa<br />- Digital Key<br />- Digital Check-In<br />- Resort Property<br />- Laundry<br />- Concierge<br />- Meeting Facilities</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Compulsory : New Year&rsquo;s Eve Dinner on 31 December</li><li>Samuh Ocean Sunset Hotel by WizZeLa&nbsp;do not accept children under 12 year old&nbsp;</li></ul>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1700194047_Samuh-Ocean-Sunset.webp', 2, 'https://www.wizzela.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/VHpf6hHqdp5YWZg29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-29 09:11:11', '2026-03-24 18:26:55', 2, 1),
(82, 'Māua Nusa Penida', '17', NULL, NULL, NULL, 'HZEVyvCkR0AuI4T8dYP4pOKVVg', '17', NULL, 'Sakti, Nusa Penida, Klungkung Regency	,Bali, Indonesia', 4, 50, 'Bagus Indra Saputra', '03616208999', '<p>MĀUA Nusa Penida &ndash; Bali est un resort 5 &eacute;toiles, situ&eacute; sur l&rsquo;&icirc;le de Nusa Penida, nich&eacute; au sommet de la colline de Gamat Bay. Trop longtemps m&eacute;connue, Nusa Penida est une destination spectaculaire, facilement accessible depuis Bali. Ce n&rsquo;est que depuis quelques ann&eacute;es qu&rsquo;elle est devenue la destination pris&eacute;e des explorateurs aspirant &agrave; un retour &agrave; la nature.<br />À MĀUA Nusa Penida, il sera enfin possible de découvrir et de profiter de cette destination extraordinaire avec vue sur la colline de Gamat Bay dans un resort international emblématique 5 étoiles tout confort. Celui-ci se trouve &agrave; environ une demi-heure de ferry depuis Sanur et vingt minutes de voiture depuis le terminal des ferries de Nusa Penida.</p>', NULL, NULL, '<ul><li>Free Internet Access</li><li>Free Parking</li><li>Restaurant</li><li>Fitness Center</li><li>Pool</li><li>Spa</li><li>Digital Key</li><li>Digital Check-In</li><li>Resort Property</li><li>Laundry</li><li>Concierge</li><li>Meeting Facilities</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1700194133_Maua-Nusa-Penida.webp', 14, 'https://mauahotel.com/id/beranda/', '2', '45', NULL, NULL, 'https://goo.gl/maps/hiRSE2vYmHF8fvZg8', NULL, NULL, NULL, NULL, '<p><strong>Normal Season </strong>(03 Jan - 31 Mar 2024, 01 Apr - 30 Jun 2024, 16 Sep - 23 Dec 2024, 03 Jan - 31 Mar 2025) :&nbsp;</p><p>Cancellation 7 days prior to arrival : 1 nights stay will be imposed&nbsp;</p><p><strong>High Season </strong>(1 Jul - 15 Sep 2024) :&nbsp;</p><p>Cancellation 14 days prior to arrival :&nbsp;1 nights stay will be imposed&nbsp;</p><p><strong>Peak Season </strong>(24 Dec 2024 - 02 Jan 2025) :&nbsp;</p><p>Cancellation 21 days prior to arrival :&nbsp;1 nights stay will be imposed</p><p><strong>No Show :</strong> 100% penalty&nbsp;</p><p><strong>Seasonal Policy :&nbsp;</strong></p><ol><li>Respecting Silence Day (Hari Raya Nyepi) on 11&nbsp;March 2024, hotel will close starting on 10 and 11 March 2024, due to in Nusa Penida No Electric, No Water during silent Day (Hari Raya Nyepi). NO CHECK IN or CHECK OUT is allowed.</li><li>Minimum 2 nights stay is required during Peak period.</li><li>No&nbsp;Check Out&nbsp;is allowed on 31 December 2024</li><li>Compulsory Christmas Dinner on 24 Dec 2024&nbsp;(Price : TBA)&nbsp;</li><li>Compulsory New Year Eve Dinner on 31 Dec 2024&nbsp;(Price : TBA)&nbsp;</li><li>&ldquo;Silent Ocean (Nyepi Laut) will be approximately&nbsp;on 30 Sep (based on experience on 2023), No check in or check out is allowed for Maua Nusa Penida, due to boats unable to cross from and to Nusa Penida. The date of Silent Ocean (Nyepi Laut) can change anytime.&nbsp;</li><li>Respecting Silence Day (Hari Raya Nyepi) on 29 March 2025, NO CHECK IN or CHECK OUT is allowed.</li><li>Compulsory Lunch and Dinner on 29&nbsp;Mar&nbsp;2025 Silent Day&nbsp;(Price : TBA)&nbsp;</li><li>The Maua Nusa Penida hotel will close starting 28 &amp; 29 March due to in Nusa Penida no electricity, No Water during Silence Day. The Guest has to check out on 28 March 2024 and last boat from Nusa Penida to Sanur on 28 March at 13:00 PM.</li></ol>', NULL, NULL, NULL, '2022-11-29 09:32:50', '2026-03-24 18:26:55', 1, 1),
(83, 'Aryaduta Bali', '17', 'Kuta', 'Bali', 'Indonesia', 'DZHeJFqDDkY76wsL3uaSoLKTNq', '17', 17, 'Jalan Wana Segara, Kuta, Bali, Indonesia', 1, 2, 'Ida Ayu Eka Purnama', '03614754188', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'active', 'hotels/covers/1759195652_heavenly-garden.jpg', 14, 'http://www.aryaduta.com/bali', '2', '360', NULL, NULL, 'https://www.google.com/maps/place/Aryaduta+Bali/@-8.7357558,115.1642469,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd246a1a3c225a9:0x24b1527fb276a49e!5m2!4m1!1i2!8m2!3d-8.7357611!4d115.1668218!16s%2Fg%2F11hbg7rtgz?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.7357882, 115.1670519, NULL, NULL, '<ul><li>Normal Season : 7 days prior to arrival&nbsp;</li><li>High Season : 21 days prior to arrival&nbsp;</li><li>Peak Season : 30 days prior to arrival&nbsp;</li></ul><b>No Show :&nbsp;</b><br><ul><li>A one night No Show Fee will be imposed to any no show or late cancellation during Normal season. Full charge as per original booking will be imposed to any no show or late cancellation during High &amp; Peak season.&nbsp;</li></ul>', '<span>**普通季節：**須於抵達前7天取消<br>\r\n**旺季：**須於抵達前21天取消<br>\r\n**巔峰季節：**須於抵達前30天取消</span>\r\n<span>未如期入住（No Show）：<br>\r\n在普通季節，若未如期入住或臨時取消，將收取一晚房費作為未入住罰金。<br>\r\n在旺季與巔峰季節，若未如期入住或臨時取消，將收取原始預訂的全額費用。</span>', '<span>**普通季节：**须在抵达前7天取消<br>\r\n**旺季：**须在抵达前21天取消<br>\r\n**高峰季节：**须在抵达前30天取消</span>\r\n<span>未如期入住（No Show）：<br>\r\n在普通季节，若未如期入住或临时取消，将收取一晚房费作为未入住罚金。<br>\r\n在旺季与高峰季节，若未如期入住或临时取消，将收取原始预订的全部费用。</span>', NULL, '2022-11-29 09:52:57', '2026-03-25 19:12:46', 1, 2),
(84, 'Loccal Collection Hotel Komodo', '17', NULL, NULL, NULL, 'C1vscY2NRJDzYkR20mkNvUfVLe', '17', NULL, 'Labuan Bajo, Komodo, West Manggarai Regency, East Nusa Tenggara', 1, 3, 'Aulia Adekayanti', '03852440499', 'Built into the cliffs of Labuan Bajo, Local Collection’s unique aesthetic fuses local craftsmanship and materials with elegant simplicity and attention to detail.', '坐落於拉布安巴焦的懸崖上，Local Collection 以獨特的美學風格，融合在地工藝與材料，展現優雅簡約與對細節的極致講究。', '建于拉布安巴焦的悬崖之上，Local Collection 独特的美学融合了本地工艺与材料，展现出优雅的简约风格与对细节的精致追求。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1731995661_GQHPVipaMAA8zX4.webp', 14, 'http://loccalcollection.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/WDqPGrwVgATyKhp6A', NULL, NULL, NULL, NULL, '<span><b>Low Season</b> <i>(01 Mar - 30 Jun, 11 Sep - 19 Dec, 06 Jan - 28 Feb):</i>&nbsp;</span><ul><li>Up to 21 days prior to arrival: No Cancellation Fee&nbsp;</li><li>Less than 21 days prior to arrival:&nbsp;50% charges of the price of 1 (one) night</li><li>Less than 10 days prior to arrival:&nbsp;100% charge of the price of 1 (one) night</li></ul><b>High Season &amp; Chinese New Year</b>&nbsp;<i>(01 Jul - 10 Sep):</i><ul><li>Up tp 40 days prior to arrival:&nbsp;No Cancellation Fee</li><li>Less than 40 days prior to arrival:&nbsp;50% charges of the price of 1 (one) night</li><li>Less than 20 days prior to arrival:&nbsp;100% charge of the price of 1 (one) night</li></ul><b>Peak Season</b> <i>(</i><i>20 Dec - 05 Jan):&nbsp;</i><ul><li>Up to 60 days prior to arrival:&nbsp;No Cancellation Fee</li><li>Less than 59 days prior to arrival:&nbsp;50% charges of the price of 1 (one) night</li><li>Less than 30 days prior to arrival:&nbsp;100% charge of the price of 1 (one) night</li></ul>', '淡季（3月1日－6月30日、9月11日－12月19日、1月6日－2月28日）：\r\n<ul>\r\n<li>\r\n抵達前21天以前取消：不收取取消費用\r\n</li>\r\n<li>\r\n抵達前少於21天取消：收取一晚房費的50%\r\n</li>\r\n<li>\r\n抵達前少於10天取消：收取一晚房費的100%\r\n</li>\r\n</ul>\r\n旺季與農曆新年期間（7月1日－9月10日）：\r\n<ul>\r\n<li>\r\n抵達前40天以前取消：不收取取消費用\r\n</li>\r\n<li>\r\n抵達前少於40天取消：收取一晚房費的50%\r\n</li>\r\n<li>\r\n抵達前少於20天取消：收取一晚房費的100%\r\n</li>\r\n</ul>\r\n巔峰季節（12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達前60天以前取消：不收取取消費用\r\n</li>\r\n<li>\r\n抵達前少於59天取消：收取一晚房費的50%\r\n</li>\r\n<li>\r\n抵達前少於30天取消：收取一晚房費的100%</li></ul>', '淡季（3月1日－6月30日、9月11日－12月19日、1月6日－2月28日）：\r\n<ul>\r\n<li>\r\n抵达前21天以前取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前少于21天取消：收取一晚房费的50%\r\n</li>\r\n<li>\r\n抵达前少于10天取消：收取一晚房费的100%\r\n</li>\r\n</ul>\r\n旺季及农历新年（7月1日－9月10日）：\r\n<ul>\r\n<li>\r\n抵达前40天以前取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前少于40天取消：收取一晚房费的50%\r\n</li>\r\n<li>\r\n抵达前少于20天取消：收取一晚房费的100%\r\n</li>\r\n</ul>\r\n高峰季节（12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达前60天以前取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前少于59天取消：收取一晚房费的50%\r\n</li>\r\n<li>\r\n抵达前少于30天取消：收取一晚房费的100%</li></ul>', NULL, '2022-11-29 11:40:09', '2026-03-24 18:26:55', 1, 1),
(85, 'Loccal Collection Hotel', '17', NULL, NULL, NULL, 'N2A8n2Z2LjwZWvZYjmAIzeyioj', '17', NULL, 'Labuan Bajo, Komodo, West Manggarai Regency	, East Nusa Tenggara, Indonesia', 1, 1, 'Mr. Yunus', '03852440499', '<p>Built into the cliffs of Labuan Bajo, Local Collection&rsquo;s unique aesthetic fuses local craftsmanship and materials with elegant simplicity and attention to detail.</p>', NULL, NULL, '<p>- Free Internet Access<br />- Free Parking<br />- Restaurant<br />- Fitness Center<br />- Pool<br />- Spa<br />- Digital Key<br />- Digital Check-In<br />- Resort Property<br />- Laundry<br />- Concierge<br />- Meeting Facilities</p>', NULL, NULL, '<p>Daily breakfast</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1700194410_Local-Collection.webp', 2, 'https://loccalcollection.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/YG4qDBaeWRR4Qo4A9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-29 11:56:24', '2026-03-24 18:26:55', 2, 1),
(86, 'Paradisus by Meliá Bali', '17', NULL, NULL, NULL, 'BQfSVrQIR4RmCa66wuVPSVeSTm', '17', NULL, 'Kawasan Pariwisata ITDC Lot N1, Bali, 80363', 1, 14, 'Yeni Lestari', '0361771510', 'Welcome to the first hotel where the destination is included, a sanctuary that invites you to experience the stunning natural and cultural beauty of the island. An exclusive resort in Bali located off the stunning coast of Nusa Dua and only 12km from Ngurah Rai International Airport. With a deep commitment to sustainability, it uses environmentally friendly materials in its rooms and other public areas.<div><div><div>Connect with all the exoticism of the island at Paradisus by Meliá Bali, a sublime five-star resort by the sea. Savor the wide range of dining options and tasty dishes with fresh ingredients from nearby farms and organic markets. Discover the exclusive services at The Reserve (adults only) and Family Concierge for an unbeatable stay. Immerse yourself in Balinese nature and culture thanks to a carefully selected choice of life-enriching experiences both inside and outside the resort and also supporting local communities.</div></div></div>', '<span>歡迎來到全球首家「目的地即體驗」的飯店，一處靜謐聖地，邀您親身感受這座島嶼令人驚嘆的自然與文化之美。這家位於峇里島努沙杜瓦迷人海岸的頂級度假村，距離伍拉·賴國際機場僅12公里。<br>\r\n飯店致力於永續發展，客房及公共區域皆採用環保材料建造。</span>\r\n<span>在峇里島的 Paradisus by Meliá，與島嶼的異國風情連結，享受這座臨海五星度假村的極致奢華。品嚐多樣化餐飲選擇與使用在地有機市集與農場的新鮮食材所烹調的美味佳餚。探索為您量身打造的專屬服務，包括僅限成人的 The Reserve 區域與家庭專屬禮賓服務，享受無與倫比的住宿體驗。<br>\r\n透過精心設計的豐富活動，沉浸於峇里島自然與文化之中，並同時支持當地社區。</span>', '<span>欢迎来到全球首家“目的地即体验”的酒店，一处宁静圣地，邀您亲身体验这座岛屿令人惊艳的自然与文化之美。坐落于巴厘岛努沙杜瓦迷人海岸的奢华度假村，距离伍拉·赖国际机场仅12公里。<br>\r\n酒店秉持可持续理念，客房及公共区域均采用环保材料。</span>\r\n<span>在 Paradisus by Meliá Bali，与这座岛屿的异国风情深度连接，尊享海滨五星度假村的至臻体验。品尝种类丰富、选用本地农场与有机市场新鲜食材烹制的美味佳肴。探索专属尊享服务，包括仅限成人的 The Reserve 区域和家庭礼宾服务，尽享无与伦比的入住体验。<br>\r\n透过精心挑选的多元体验，沉浸于巴厘岛的自然与文化之中，同时支持本地社区的可持续发展。</span>', NULL, NULL, NULL, '<ul><li>Minimum stay 3 nights valid for booking on the period of 27 December – 06 January&nbsp;</li><li>No departure allowed on 31 December&nbsp;</li><li>No check in and check out on Nyepi (19th March 2026)&nbsp;</li></ul>', '<ul><li>最少入住 3 晚，適用於 12 月 27 日至 1 月 6 日期間的預訂</li><li>\r\n12 月 31 日不可退房</li><li>\r\n靜居日（2026 年 3 月 19 日）不可辦理入住與退房</li></ul>', '<ul><li>最少入住 3 晚，适用于 12 月 27 日至 1 月 6 日期间的预订</li><li>\r\n12 月 31 日不可退房</li><li>\r\n安静日（2026 年 3 月 19 日）不可办理入住与退房</li></ul>', NULL, NULL, NULL, 'active', '1753261585_Cover.avif', 14, 'https://www.melia.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/ocrTtJ7KSGDdXVwD8', NULL, NULL, NULL, NULL, '<b>Low Season:&nbsp;</b><br><ul><li>4 days or more prior to arrival : No cancellation fee</li><li>3 days prior to arrival : One-night cancellation fee&nbsp;</li><li>2-0 days prior to arrival (incl. no show) : 100% of the full stay&nbsp;</li><li>Early departure : 100% of the full stay&nbsp;</li></ul><b>High Season</b> <b><i>(01 Jul - 31 Aug) :</i></b><br><ul><li>15 days or more prior to arrival : No cancellation fee&nbsp;</li><li>14 days prior to arrival : One-night cancellation fee&nbsp;</li><li>13-0 days prior to arrival (incl. no show) : 100% of the full stay</li><li>Early departure : 100% of the full stay&nbsp;</li></ul><b>Peak Season <i>(27 Dec - 06 Jan) :&nbsp;</i></b><br><ul><li>22 days or more prior to arrival : No cancellation fee&nbsp;</li><li>21 days prior to arrival : One-night cancellation fee&nbsp;</li><li>20-0 days prior to arrival (incl. no show) : 100% of the full stay&nbsp;</li><li>Early departure : 100% of the full stay&nbsp;</li></ul>', '淡季：\r\n<ul>\r\n<li>\r\n抵達日前 4 天或更早取消：免收取消費\r\n</li>\r\n<li>\r\n抵達日前 3 天取消：收取一晚取消費\r\n</li>\r\n<li>\r\n抵達日前 2 天至當天（含未入住）：收取全額住宿費用的 100%\r\n</li>\r\n<li>\r\n提早退房：收取全額住宿費用的 100%\r\n</li>\r\n</ul>\r\n旺季（7 月 1 日至 8 月 31 日）：\r\n<ul>\r\n<li>\r\n抵達日前 15 天或更早取消：免收取消費\r\n</li>\r\n<li>\r\n抵達日前 14 天取消：收取一晚取消費\r\n</li>\r\n<li>\r\n抵達日前 13 天至當天（含未入住）：收取全額住宿費用的 100%\r\n</li>\r\n<li>\r\n提早退房：收取全額住宿費用的 100%\r\n</li>\r\n</ul>\r\n巔峰季（12 月 27 日至 1 月 6 日）：\r\n<ul>\r\n<li>\r\n抵達日前 22 天或更早取消：免收取消費\r\n</li>\r\n<li>\r\n抵達日前 21 天取消：收取一晚取消費\r\n</li>\r\n<li>\r\n抵達日前 20 天至當天（含未入住）：收取全額住宿費用的 100%\r\n</li>\r\n<li>\r\n提早退房：收取全額住宿費用的 100%\r\n</li>\r\n</ul>', '淡季：\r\n<ul>\r\n<li>\r\n抵达前 4 天或更早取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前 3 天取消：收取一晚房费作为取消费\r\n</li>\r\n<li>\r\n抵达前 2 天至当天（含未入住）：收取全额住宿费用的 100%\r\n</li>\r\n<li>\r\n提前退房：收取全额住宿费用的 100%\r\n</li>\r\n</ul>\r\n旺季（7 月 1 日至 8 月 31 日）：\r\n<ul>\r\n<li>\r\n抵达前 15 天或更早取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前 14 天取消：收取一晚房费作为取消费\r\n</li>\r\n<li>\r\n抵达前 13 天至当天（含未入住）：收取全额住宿费用的 100%\r\n</li>\r\n<li>\r\n提前退房：收取全额住宿费用的 100%\r\n</li>\r\n</ul>\r\n高峰季节（12 月 27 日至 1 月 6 日）：\r\n<ul>\r\n<li>\r\n抵达前 22 天或更早取消：不收取取消费用\r\n</li>\r\n<li>\r\n抵达前 21 天取消：收取一晚房费作为取消费\r\n</li>\r\n<li>\r\n抵达前 20 天至当天（含未入住）：收取全额住宿费用的 100%\r\n</li>\r\n<li>\r\n提前退房：收取全额住宿费用的 100%</li></ul>', NULL, '2022-11-29 12:24:19', '2026-03-24 18:26:55', 1, 1),
(87, 'TA\'AKTANA, a Luxury Collection Resort & Spa Labuan Bajo', '17', NULL, NULL, NULL, 'GSf2K7IDuRCdfMk8foSgZB9WXH', '17', NULL, 'Pantai Wae Rana, Labuan Bajo, East Nusa Tenggara 86763', 1, 2, 'TA\'AKTANA', '03852381888', '<p>For those who yearn to not just discover Labuan Bajo but embrace it, dive beneath the surface and explore like a local at TA&#39;AKTANA, a Luxury Collection Resort and Spa, Labuan Bajo. Every aspect of our&nbsp;hotel pays homage to the traditions and culture of the extraordinary island of Flores. Inspired by the Lingko fields and their spider web-shaped rice terraces, our luxury resort is a living testament to Labuan Bajo&rsquo;s unique heritage. Relax in beautifully appointed accommodations including family villas and overwater villas with Butler service. Whether you prefer lounging by the Olympic-sized swimming pool, treating young ones to new adventures at the Kids Club or reveling in breathtaking sunsets from the overwater bar, there&#39;s something for every guest. Discover the magic of Labuan Bajo, Flores where past and present intertwine to create a sense of wonder and reverence for the island&#39;s rich heritage. Your journey of exploration begins here, at TA&#39;AKTANA, a Luxury Collection Resort and Spa, Labuan Bajo.</p>', NULL, NULL, NULL, NULL, NULL, '<p><strong>Honeymoon &amp; Wedding Anniversary Benefits:&nbsp;</strong></p><ul><li>TA&#39;AKTANA, a Luxury Collection Resort &amp; Spa Labuan Bajo honeymoon gift per room per stay.&nbsp;</li></ul><p><em>Above benefits are subject to change without prior notice&nbsp;</em></p>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1722922708_Cover.jfif', 14, 'www.marriott.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/oK3iNw5y9ik9ZSjX9', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-11-29 12:48:16', '2026-03-24 18:26:55', 1, 1),
(88, 'Hanging Garden of Bali', '17', NULL, NULL, NULL, 'luGePy6352cga9KIa6IRc73g6e', '17', NULL, 'Buahan, Payangan, Gianyar Regency, Bali 80571', 2, 47, 'Inge Yuanita', '0361982700', '<span>Discover unparalleled luxury at Hanging Gardens of Bali, the ultimate jungle resort. Nestled in the heart of the jungle near Payangan, north of Ubud, this architectural marvel is surrounded by lush forests.<br><br>Immerse yourself in a unique experience where nature and opulence converge. Whether for a romantic getaway, a family adventure, or a solo escape, Hanging Gardens of Bali offers a luxurious sanctuary that captivates the senses and rejuvenates the soul.</span>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1731995830_width_1280_HangingGardensBali_exterior2.webp', 14, 'https://hanginggardensofbali.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/36zkpN3QW5GAGWwD9', NULL, NULL, NULL, NULL, '<b>Low Season:&nbsp;</b><br><ul><li>Cancellation over 30 days no cancellation charges&nbsp;</li><li>30 days to 15 days 50% cancellation charge&nbsp;</li><li>Less than 14 days 100% cancellation charge&nbsp;</li></ul><b>High &amp; Peak Season :&nbsp;</b><br><ul><li>Cancellation over 45 days no cancellation charges&nbsp;</li><li>45 days to 30 days 50% cancellation charge&nbsp;</li><li>Less than 30 days 100% cancellation charge&nbsp;</li></ul><b>Seasonal Policy:</b>&nbsp;<br><ul><li>December 29, 2025 arrivals must have a 3 nights minimum length of stay&nbsp;</li><li>No check-out allowed on December 31</li></ul><br>', NULL, NULL, NULL, '2022-11-29 13:08:44', '2026-03-24 18:26:55', 1, 1),
(89, 'Puri Bagus Lovina', '17', NULL, NULL, NULL, 'o9fey7AfRFb1dhNBUUrxo7gHY1', '17', NULL, 'Jl. Seririt- Singaraja No.Desa, Pemaron, Lovina, Kabupaten Buleleng, Bali 81151', 4, 96, 'Jaya Ishwari', '036221430', 'Located in the private beachfront and built in traditional Balinese thatched roof architecture, Puri Bagus Lovina offers 40 spacious villas including two suites with private pool and dining room.This beautiful resort provided plenty of space between each villa for stunning tropical gardens to enhance your privacy. The guest rooms offer touches of old Bali, with large open-air verandah and customary open-air showers in the privacy of interior gardens.', '<span>坐落於私人海濱地段，並採用傳統峇里島茅草屋頂建築風格，Puri Bagus Lovina 提供 40 間寬敞的別墅，其中包括兩間擁有私人泳池與用餐空間的套房。這座美麗的度假村在每棟別墅之間留有充足的空間，以熱帶花園增添私密性。<br>\r\n客房展現出舊時峇里的風情，設有寬敞的開放式陽台，以及位於內部花園中的傳統露天淋浴設施，讓您盡享隱私與自然交融的體驗。</span>', '坐落在私人海滨区域，并采用传统巴厘岛茅草屋顶建筑风格，Puri Bagus Lovina 提供 40 间宽敞别墅，其中包括两间设有私人泳池和用餐区的套房。这个美丽的度假村在每栋别墅之间保留了充足空间，以热带花园提升您的私密体验。<br>\r\n客房充满了旧时巴厘风情，设有宽敞的开放式阳台，以及位于内花园中的传统露天淋浴设施，为您带来自然与私密兼具的享受。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>Compulsory New Year Eve Dinner 31 December (Price at additional charge)</li><li>No check-in/checkout on March 19, 2026 Balinese Day of Silence&nbsp;</li></ul><b>Honeymoon Benefit:&nbsp;</b><br><ul><li>Flower Petal on the Bed&nbsp;</li><li>Seasonal Tropical Fruits basket&nbsp;</li><li>A Gift from the resort&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2025年12月31日需參加強制性新年晚宴（費用另計）</li><li>\r\n2026年3月19日峇里島寧靜日（Nyepi Day）當天不允許辦理入住與退房</li></ul><span>蜜月優惠：<br></span><ul><li>\r\n床上花瓣裝飾</li><li>\r\n時令熱帶水果籃</li><li>\r\n來自度假村的精美禮品</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2025年12月31日需参加强制性新年晚宴（费用另计）</li><li>\r\n2026年3月19日巴厘岛静居日（Nyepi Day）当天不允许办理入住和退房</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n床上花瓣装饰</li><li>\r\n季节热带水果篮</li><li>\r\n来自度假村的精美礼物</li></ul>', NULL, NULL, NULL, 'Active', '1744859708_Cover.webp', 14, 'http://www.puribaguslovina.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/dw6CHam7ALRS49Sb9', NULL, NULL, NULL, NULL, '<b>Low &amp; Shoulder Seasons :</b><br><ul><li>Cancellation received within 21 days from booked arrival date shall not be subject to any penalties.  One night contracted room rate \r\nwill be charged for any cancellation received less than 21 but more than 14 days from booked arrival date. Less than 14 days notice and voluntary no show will \r\nbe charged in full for the room nights booked. Early departure and or check out will be charged in full for the room nights booked. </li></ul><b>High Season</b> <i>(01 Jul - 31 Aug):&nbsp;</i><br><ul><li>Cancellation received within 30 days from booked arrival date shall not be subject to any penalties.  One night contracted room rate will be \r\ncharged for any cancellation received less than 30 but more than 21 days from booked arrival date. Less than 21days notice and voluntary no show will be \r\ncharged in full for the room nights booked. Early departure and or check out will be charged in full for the room nights booked.</li></ul>', '<span>淡季與肩季：<br></span><ul><li>\r\n在預訂抵達日前21天內取消預訂，不會產生任何罰金。若於抵達日前少於21天但超過14天內取消，將收取一晚房費作為取消費用。若在14天內取消或自願未入住（No Show），將收取整個預訂住宿晚數的全額費用。提前退房或提前辦理退房也將收取全額住宿費用。</li></ul><span>旺季（7月1日－8月31日）：<br></span><ul><li>\r\n在預訂抵達日前30天內取消預訂，不會產生任何罰金。若於抵達日前少於30天但超過21天內取消，將收取一晚房費作為取消費用。若在21天內取消或自願未入住（No Show），將收取整個預訂住宿晚數的全額費用。提前退房或提前辦理退房也將收取全額住宿費用。</li></ul>', '<span>淡季与肩季：<br></span><ul><li>\r\n在预订抵达日前21天内取消，不收取任何费用。若在抵达日前少于21天但多于14天取消，将收取一晚房费作为取消费用。若在14天内取消或自愿未入住（No Show），将收取全部预订晚数的房费。提前退房或提前办理退房也将收取全部房晚的费用。</li></ul><span>旺季（7月1日－8月31日）：<br></span><ul><li>\r\n在预订抵达日前30天内取消，不收取任何费用。若在抵达日前少于30天但多于21天取消，将收取一晚房费作为取消费用。若在21天内取消或自愿未入住（No Show），将收取全部预订晚数的房费。提前退房或提前办理退房也将收取全部房晚的费用。</li></ul>', NULL, '2022-11-29 13:32:13', '2025-06-30 19:50:43', 1, 1),
(90, 'Maua Nusa Penida', '17', NULL, NULL, NULL, 'RkyrQ2pYpmNnzgBMc4LGVz1AZY', '17', NULL, 'Sakti, Nusa Penida, Klungkung Regency, Bali 80771', 3, 61, 'Yeni Navitarini', '03616208999', 'MĀUA as a brand displays the special environmental connection of a resort or hotel complex. It is related to biodiversity, environmental conservation and cultural understanding where guests will experience the unity of nature, uniting the strength and friendship of the people who serve and enhancing the guest experience.', 'MĀUA 作為一個品牌，展現了度假村或飯店與自然環境之間的特殊連結。它與生物多樣性、環境保育以及文化理解息息相關，讓賓客體驗與自然的和諧共生，並凝聚服務人員的力量與友誼，進一步提升整體入住體驗。', 'MĀUA 作为一个品牌，展现了度假村或酒店与自然环境之间的特殊联系。它与生物多样性、环境保护以及文化理解密切相关，让宾客体验与自然的和谐共处，融合服务人员的力量与友谊，进一步提升整体入住体验。', NULL, NULL, NULL, '<b>Seasonal Policy: </b><ul><li>Compulsory Chirstmas Eve Dinner on 24 Dec (Price at additional charge)</li><li>Compulsory New Year Dinner on 31 Dec (Price at additional charge) </li><li>No Check Out is allowed on 31 December </li><li>Respecting Silence Day (Hari Raya Nyepi) on 08 March 2027, no check in or check out is allowed </li></ul>', '季節性政策：<br data-start=\"38\" data-end=\"41\" data-is-only-node=\"\">\r\n• 12 月 24 日聖誕夜晚宴為強制性（需另加收費）<br data-start=\"68\" data-end=\"71\">\r\n• 12 月 31 日跨年晚宴為強制性（需另加收費）<br data-start=\"97\" data-end=\"100\">\r\n• 12 月 31 日不允許辦理退房<br data-start=\"118\" data-end=\"121\">\r\n• 因應寧靜日（Nyepi／巴厘島靜居日）於 2027 年 3 月 8 日，當日不接受入住或退房', '<div>季节性政策：<br data-start=\"215\" data-end=\"218\" data-is-only-node=\"\">\r\n• 12 月 24 日圣诞夜晚宴为强制性（需额外收费）<br data-start=\"245\" data-end=\"248\">\r\n• 12 月 31 日跨年晚宴为强制性（需额外收费）<br data-start=\"274\" data-end=\"277\">\r\n• 12 月 31 日不允许办理退房<br data-start=\"295\" data-end=\"298\">\r\n• 因遵守静居日（Nyepi／巴厘岛安宁日）于 2027 年 3 月 8 日，当日不接受入住或退房</div>', NULL, NULL, NULL, 'Active', '1759195783_349036712.jpg', 14, 'https://mauahotel.com/', '2', '360', NULL, NULL, 'https://goo.gl/maps/4KjjBZBxXayPQZxC9', NULL, NULL, NULL, NULL, '<span><b>Normal Season</b> <i>(01 Apr - 30 Jun, 01 Oct - 31 Mar): </i></span><ul><li>7 days prior to arrival: cancellation fee equal to 1 (one) night stay will be imposed </li></ul><span><b>High Season</b> <i>(01 Jul - 30 Sep):</i></span><ul><li>14 days prior to arrival: cancellation fee equal to 1 (one) night stay will be imposed </li></ul>100% penalty will be imposed for any no show <br>', '<span>普通季節（4月1日－6月30日、10月1日－翌年3月31日）：<br></span><ul><li>\r\n抵達前7天內取消，將收取等同1晚住宿費的取消費用。</li></ul><span>旺季（7月1日－9月30日）：<br></span><ul><li>\r\n抵達前14天內取消，將收取等同1晚住宿費的取消費用。</li></ul>\r\n如未如期入住（No Show），將收取100%全額罰金。', '<span>普通季节（4月1日－6月30日、10月1日－次年3月31日）：<br></span><ul><li>\r\n在抵达前7天内取消，将收取相当于1晚住宿费用的取消费。</li></ul><span>旺季（7月1日－9月30日）：<br></span><ul><li>\r\n在抵达前14天内取消，将收取相当于1晚住宿费用的取消费。</li></ul>\r\n若未如期入住（No Show），将收取100%全额罚金。', NULL, '2022-12-03 06:40:54', '2026-01-26 19:09:39', 1, 1),
(91, 'Swiss-Belhotel Pecatu', '17', NULL, NULL, NULL, '9Sknuo3KReX8atjyOskKu79K2r', '17', NULL, 'Indah Resort Bali, Pecatu Indah Raya Blok G2, Pecatu, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 16, 'Yeni Navitarini', '03613302999', 'Swiss-Belresort Pecatu merupakan resor bintang empat bertaraf internasional di resor komplek perbukitan yang dikenal sebagai Pecatu Indah Resort. Terletak di semenanjung selatan Pulau Bali, sebuah area terkenal untuk para peselancar, pe-golf, bulan madu dan untuk Anda yang ingin berwisata ke Bali untuk mencari ketenangan.', 'Swiss-Belresort Pecatu 是一家位於國際標準的四星級渡假村，坐落在著名的山丘度假區——Pecatu Indah Resort。位於峇里島南端的半島地區，這裡是衝浪愛好者、高爾夫球手、新婚蜜月夫妻，以及尋求平靜假期旅人的理想目的地。', 'Swiss-Belresort Pecatu 是一家国际标准的四星级度假村，位于著名的山丘度假区——Pecatu Indah Resort。地处巴厘岛南部半岛地区，是冲浪爱好者、高尔夫球手、度蜜月的新人，以及前往巴厘岛寻找宁静之旅的理想之地。', '<ul><li>Laundry and dry cleaning</li><li>Massage & Spa</li><li>Business service center</li><li>Lagoon swimming pool (children and adults)</li><li>24 hour CCTV and security cameras</li><li>Guest elevator with security access</li><li>Parking area</li><li>Valet parking service</li></ul>', '<ul><li>洗衣與乾洗服務</li><li>\r\n按摩與水療</li><li>\r\n商務服務中心</li><li>\r\n潟湖式游泳池（兒童與成人）</li><li>\r\n24小時閉路電視與安全監控系統</li><li>\r\n設有安全門禁的客用電梯</li><li>\r\n停車區</li><li>\r\n代客泊車服務</li></ul>', '<ul><li>洗衣和干洗服务</li><li>\r\n按摩和水疗</li><li>\r\n商务服务中心</li><li>\r\n环礁式游泳池（儿童与成人）</li><li>\r\n24小时闭路电视和安全监控</li><li>\r\n带安全门禁的客用电梯</li><li>\r\n停车区域</li><li>\r\n代客泊车服务</li></ul>', '<span style=\"font-weight: bolder;\">Seasonal Policy:&nbsp;</span><ol><li>Compulsory New Year Eve Dinner on 31 Dec (Price at additional charge)</li><li>Compulsory Lunch &amp; Dinner on 08 Mar 2027 (Price at additional charge)&nbsp;</li><li>No Check Out is allowed on 31 December&nbsp;</li><li>Respecting Silence Day (Hari Raya Nyepi) on 08 March 2027, no check in or check out is allowed&nbsp;</li></ol>', '<p data-start=\"136\" data-end=\"148\"><strong data-start=\"136\" data-end=\"146\">季節性政策：</strong></p>\r\n<ul data-start=\"149\" data-end=\"282\">\r\n<li data-start=\"149\" data-end=\"178\">\r\n<p data-start=\"151\" data-end=\"178\">12 月 31 日除夕晚宴為強制參加（需另行付費）</p>\r\n</li>\r\n<li data-start=\"179\" data-end=\"211\">\r\n<p data-start=\"181\" data-end=\"211\">2027 年 3 月 8 日強制午餐及晚餐（需另行付費）</p>\r\n</li>\r\n<li data-start=\"212\" data-end=\"230\">\r\n<p data-start=\"214\" data-end=\"230\">12 月 31 日不允許退房</p>\r\n</li>\r\n<li data-start=\"231\" data-end=\"282\">\r\n<p data-start=\"233\" data-end=\"282\">為尊重靜居日（Nyepi／巴厘島安寧日）於 2027 年 3 月 8 日，當日不允許入住或退房</p></li></ul>', '<p data-start=\"323\" data-end=\"335\"><strong data-start=\"323\" data-end=\"333\">季节性政策：</strong></p>\r\n<ul data-start=\"336\" data-end=\"469\">\r\n<li data-start=\"336\" data-end=\"365\">\r\n<p data-start=\"338\" data-end=\"365\">12 月 31 日除夕晚宴为强制参加（需额外收费）</p>\r\n</li>\r\n<li data-start=\"366\" data-end=\"398\">\r\n<p data-start=\"368\" data-end=\"398\">2027 年 3 月 8 日强制午餐及晚餐（需额外收费）</p>\r\n</li>\r\n<li data-start=\"399\" data-end=\"417\">\r\n<p data-start=\"401\" data-end=\"417\">12 月 31 日不允许退房</p>\r\n</li>\r\n<li data-start=\"418\" data-end=\"469\">\r\n<p data-start=\"420\" data-end=\"469\">为尊重静居日（Nyepi／巴厘岛安宁日）于 2027 年 3 月 8 日，当日不允许入住或退房</p></li></ul>', NULL, NULL, NULL, 'Active', '1731996168_Swiss-Belhotel-Segara-Resort-Spa-Nusa-Dua-Exterior.webp', 14, 'https://swiss-belhotel.com/swiss-belresort-pecatu', '2', '360', NULL, NULL, 'https://goo.gl/maps/p7TAhhQKSfTo2Dmc9', NULL, NULL, NULL, NULL, '<b>Normal Season:&nbsp;</b><ul><li>7 days prior to arrival: cancellation fee equal to 1 (one) night stay will be imposed&nbsp;</li></ul><span><b>High Season</b> <i>(15 Jul - 15 Aug, 3-9 Feb, 7-14 Mar):</i></span><ul><li>21 days prior to arrival:&nbsp;cancellation fee equal to 1 (one) night stay will be imposed&nbsp;</li></ul><span><b>Peak Season</b>&nbsp;<i>(24 Dec - 06 Jan):&nbsp;</i></span><ul><li>30 days prior to arrival:&nbsp;cancellation fee equal to 1 (one) night stay will be imposed&nbsp;</li></ul><b>100% penalty will be imposed for any no show&nbsp;</b><br>', '<p data-start=\"0\" data-end=\"73\">一般季節：<br data-start=\"37\" data-end=\"40\">\r\n• 入住日前 7 天內取消，將收取相當於 1 晚住宿的取消費用</p>\r\n<p data-start=\"75\" data-end=\"155\">旺季（7 月 15 日－8 月 15 日、2 月 3－9 日、3 月 7－14 日）：<br data-start=\"118\" data-end=\"121\">\r\n• 入住日前 21 天內取消，將收取相當於 1 晚住宿的取消費用</p>\r\n<p data-start=\"157\" data-end=\"217\">高峰季（12 月 24 日－1 月 6 日）：<br data-start=\"180\" data-end=\"183\">\r\n• 入住日前 30 天內取消，將收取相當於 1 晚住宿的取消費用</p>\r\n<p data-start=\"219\" data-end=\"254\">未入住（No Show）：<br data-start=\"232\" data-end=\"235\">\r\n• 將收取 100% 全額住宿費用</p>', '<div class=\"flex flex-col text-sm pb-25\"><article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" tabindex=\"-1\" dir=\"auto\" data-turn-id=\"d3e35c03-a417-44cf-aebb-2dc673dd5bfe\" data-testid=\"conversation-turn-555\" data-scroll-anchor=\"true\" data-turn=\"assistant\"><div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\"><div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\"><div class=\"flex max-w-full flex-col grow\"><div data-message-author-role=\"assistant\" data-message-id=\"85080f31-ff02-4385-bd8c-2a9333b4525a\" dir=\"auto\" class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" data-message-model-slug=\"gpt-5-2\"><div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\"><div class=\"markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling\"><p data-start=\"261\" data-end=\"333\">普通季节：<br data-start=\"297\" data-end=\"300\">\r\n• 入住日前 7 天内取消，将收取相当于 1 晚住宿的取消费用</p>\r\n<p data-start=\"335\" data-end=\"415\">旺季（7 月 15 日－8 月 15 日、2 月 3－9 日、3 月 7－14 日）：<br data-start=\"378\" data-end=\"381\">\r\n• 入住日前 21 天内取消，将收取相当于 1 晚住宿的取消费用</p>\r\n<p data-start=\"417\" data-end=\"477\">高峰季（12 月 24 日－1 月 6 日）：<br data-start=\"440\" data-end=\"443\">\r\n• 入住日前 30 天内取消，将收取相当于 1 晚住宿的取消费用</p>\r\n<p data-start=\"479\" data-end=\"512\" data-is-last-node=\"\" data-is-only-node=\"\">未入住（No Show）：<br data-start=\"492\" data-end=\"495\">\r\n• 将收取 100% 全额住宿费用</p></div></div></div></div><div class=\"z-0 flex min-h-[46px] justify-start\"></div><div class=\"mt-3 w-full empty:hidden\"><div class=\"text-center\"></div></div></div></div></article></div><div aria-hidden=\"true\" data-edge=\"true\" class=\"pointer-events-none h-px w-px absolute bottom-0\"></div>', NULL, '2022-12-03 07:26:54', '2026-01-26 19:24:06', 1, 1),
(92, 'Mahagiri Resort', '17', NULL, NULL, NULL, '5lX0cArG3nBNKC0zPf0eBvJ4o7', '17', NULL, 'Banjar Kaja Desa Jungutbatu, Nusa Lembongan, Kec. Nusa Penida, Kabupaten Klungkung, Bali 80771', 3, 33, 'Chrisna Dewi', '081139608910', 'Mahagiri Resort Nusa Lembongan sits on the largest white sand beach on the island. Called Pantai Mahagiri, the beach is equally as famous for its sunrises and sunsets with views going back to mainland Bali and majestic Mount Agung.Our beach club offers an international cuisine and a full service bar that you can enjoy in the restaurant or while relaxing around our beach club swimming pools. We also have a beach bar for sunset cocktails as you listen to the waves rolling in.Our rooms offer total privacy and we have accommodation to suit your needs, whether travelling alone, with your family, or looking for a romantic getaway in our one bedroom villas with their own pool.Your tropical island paradise awaits at Mahagiri Resort Nusa Lembongan', 'Mahagiri Resort Nusa Lembongan 坐落於島上最大的白色沙灘上，稱為 Mahagiri 海灘。這片沙灘以壯麗的日出與日落聞名，可眺望峇里本島與雄偉的阿貢火山。我們的沙灘俱樂部提供國際美食及全方位酒吧服務，您可以在餐廳內享用，也可以在泳池旁輕鬆放鬆時品味。我們亦設有沙灘酒吧，是觀賞日落、聆聽海浪聲的絕佳地點。\r\n我們的客房提供絕對的隱私，無論您是獨自旅行、與家人同行，或是尋找浪漫度假的旅人，我們都有適合您的住宿選擇，包括擁有私人泳池的一臥室別墅。\r\n熱帶島嶼天堂正等著您前來體驗 — 就在 Mahagiri Resort Nusa Lembongan。', 'Mahagiri Resort Nusa Lembongan 坐落于岛上最大的白色沙滩上，名为 Mahagiri 海滩。这片沙滩因其壮观的日出与日落而闻名，视野可直达巴厘岛本岛与雄伟的阿贡火山。\r\n我们的沙滩俱乐部提供国际美食及全方位酒吧服务，您可以选择在餐厅内用餐，也可在沙滩俱乐部泳池旁轻松享受。此外，我们设有沙滩酒吧，是享用日落鸡尾酒、聆听海浪声的理想场所。\r\n我们的客房提供绝对的私密空间，无论是独自旅行、家庭出游，还是寻找浪漫假期，我们都能提供适合的住宿选择，包括配有私人泳池的一卧室别墅。\r\n您理想的热带海岛天堂，就在 Mahagiri Resort Nusa Lembongan 等着您。', NULL, NULL, NULL, 'FAST BOAT SCHEDULE:<ul><li>From Sanur to Lembongan: 08.30, 10.00, 11.00, 12.00, 14.00, 17.00</li><li>From Lembongan to Sanur: 08.00, 09.00, 11.00, 12.15, 13.00, 16.00</li></ul>', '快艇時刻表：<br><ul><li>\r\n從沙努爾（Sanur）前往藍夢島（Lembongan）：08:30、10:00、11:00、12:00、14:00、17:00</li><li>\r\n從藍夢島（Lembongan）前往沙努爾（Sanur）：08:00、09:00、11:00、12:15、13:00、16:00</li></ul>', '快艇时刻表：<br><ul><li>\r\n从沙努尔（Sanur）前往蓝梦岛（Lembongan）：08:30、10:00、11:00、12:00、14:00、17:00</li><li>\r\n从蓝梦岛（Lembongan）前往沙努尔（Sanur）：08:00、09:00、11:00、12:15、13:00、16:00</li></ul>', NULL, NULL, NULL, 'Active', '1759195938_505127189.jpg', 2, 'https://www.mahagiriresortnusalembongan.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/aAAWJ4S4eZ3qJudm9', NULL, NULL, NULL, NULL, 'Low Season (01 Apr - 31 May, 01 - 19 Dec, 06 Jan - 31 Mar):&nbsp;<ul><li>1 room night charges: 14 days&nbsp;</li><li>50% charges of total room night reserved: 7 days&nbsp;</li><li>100% charges of total room night reserved: 24 hrs / no show&nbsp;</li><li>100% charges of total room night reserved: early departure&nbsp;</li></ul>High Season (01 Jun - 30 Nov, 20 Dec - 05 Jan):&nbsp;<ul><li>1 room night charges: 21 days&nbsp;</li><li>50% charges of total room night reserved: 14 days&nbsp;</li><li>100% charges of total room night reserved: 7 days / no show&nbsp;</li><li>100% charges of total room night reserved: early departure&nbsp;</li></ul>', '淡季（4月1日－5月31日，12月1日－12月19日，翌年1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達前14天內取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達前7天內取消：收取總預訂房晚數的50%\r\n</li>\r\n<li>\r\n抵達前24小時內取消或未入住（No Show）：收取總預訂房晚數的100%\r\n</li>\r\n<li>\r\n提早退房：收取總預訂房晚數的100%\r\n</li>\r\n</ul>\r\n旺季（6月1日－11月30日，12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達前21天內取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達前14天內取消：收取總預訂房晚數的50%\r\n</li>\r\n<li>\r\n抵達前7天內取消或未入住（No Show）：收取總預訂房晚數的100%\r\n</li>\r\n<li>\r\n提早退房：收取總預訂房晚數的100%</li></ul>', '<div><div><div><div><div><div>淡季（4月1日－5月31日，12月1日－12月19日，次年1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达前14天内取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达前7天内取消：收取总预订房晚数的50%\r\n</li>\r\n<li>\r\n抵达前24小时内取消或未入住（No Show）：收取总预订房晚数的100%\r\n</li>\r\n<li>\r\n提前退房：收取总预订房晚数的100%\r\n</li>\r\n</ul>\r\n旺季（6月1日－11月30日，12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达前21天内取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达前14天内取消：收取总预订房晚数的50%\r\n</li>\r\n<li>\r\n抵达前7天内取消或未入住（No Show）：收取总预订房晚数的100%\r\n</li>\r\n<li>\r\n提前退房：收取总预订房晚数的100%</li></ul></div></div></div></div></div></div><div></div>', NULL, '2022-12-03 07:58:35', '2025-09-29 17:32:18', 2, 1),
(93, 'K Club Ubud - Luxury Villa', '17', NULL, NULL, NULL, 'iHOv2zeyuwxdEQID1bjorXGf6H', '17', NULL, 'Jalan Raya Cebok , Kedisan Tegallalang, Kedisan, Kecamatan Ubud, Kabupaten Gianyar, Bali 80561', 2, 48, 'Ayu Puspita', '087700033888', 'Nestled in Ubud, K-Club is a luxury resort with 30 serviced villas, ranging from 2 to 5 bedrooms. Each villa offers stunning views of lush jungles, scenic paddy fields, and manicured gardens. Designed for comfort and elegance, K-Club blends modern luxury with traditional charm, ensuring a serene and unforgettable stay.', '坐落於烏布的 K-Club 是一間豪華度假村，擁有30間服務式別墅，從兩房到五房不等。每棟別墅皆可欣賞鬱鬱蔥蔥的叢林、美麗的稻田景觀及精緻的花園景致。K-Club 將現代奢華與傳統魅力完美融合，專為舒適與優雅而設計，為您帶來寧靜且難忘的住宿體驗。', '坐落于乌布的 K-Club 是一家豪华度假村，拥有30栋服务式别墅，从两房至五房不等。每栋别墅都可欣赏郁郁葱葱的丛林、美丽的稻田和精致的花园景色。K-Club 将现代奢华与传统魅力完美融合，专为舒适与优雅而打造，确保为您带来宁静而难忘的入住体验。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;<br></b><ul><li>Minimum length of stay is three (3) nights booking stay over 30 and 31 December&nbsp;</li></ul><b>Honeymoon Benefits:&nbsp;</b><br><ul><li>Romantic Honeymoon Decoration on the bed&nbsp;</li><li>Honeymoon Cake for a sweet celebration&nbsp;</li></ul><b>Birthday Benefits:&nbsp;</b><br><ul><li>Festive Birthday Decoration on the bed&nbsp;</li><li>Birthday Cake to mark the occasion&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月30日與31日的入住需至少連住三（3）晚。</li></ul>蜜月禮遇：\r\n<ul>\r\n<li>\r\n浪漫蜜月床上裝飾\r\n</li>\r\n<li>\r\n蜜月蛋糕以甜蜜慶祝\r\n</li>\r\n</ul>\r\n生日禮遇：\r\n<ul>\r\n<li>\r\n床上節慶生日裝飾\r\n</li>\r\n<li>\r\n生日蛋糕為您紀念這特別的日子</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n12月30日和31日的入住需至少连续入住三（3）晚。</li></ul>蜜月礼遇：\r\n<ul>\r\n<li>\r\n浪漫蜜月床上装饰\r\n</li>\r\n<li>\r\n蜜月蛋糕甜蜜庆祝\r\n</li>\r\n</ul>\r\n生日礼遇：\r\n<ul>\r\n<li>\r\n床上节日生日装饰\r\n</li>\r\n<li>\r\n生日蛋糕纪念这一特别时刻</li></ul>', NULL, NULL, NULL, 'Active', '1754466635_685dc27768e6d926712751.jpg', 14, 'https://kclububud.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/CknQv1xm6c9va6XV9', NULL, NULL, NULL, NULL, '<b>Low Season&nbsp;</b><i>(01 Apr - 30 Jun, 01 Sep - 19 Dec, 10 Jan - 31 Mar):</i><br><ul><li>Cancellation 21 days : 1 Night Charge&nbsp;</li><li>Cancellation 14 days : Full Charge&nbsp;</li></ul><b>High Season</b> <i>(01 Jul - 31 Aug):&nbsp;</i><br><ul><li>Cancellation 45 days : 1 Night Charge&nbsp;</li><li>Cancellation 30 days : Full Charge&nbsp;</li></ul><b>Peak Season</b> <i>(20 Dec - 09 Jan):&nbsp;</i><br><ul><li>Cancellation 30 days : Full Charge&nbsp;</li></ul><b>No Show:</b>&nbsp;No show will be subject to a penalty equal to the full \r\nnight length of stay room charge.  <br>', '<span>淡季（4月1日－6月30日、9月1日－12月19日、翌年1月10日－3月31日）：<br></span><ul><li>\r\n取消入住若在抵達前21天內：收取1晚房費</li><li>\r\n取消入住若在抵達前14天內：收取全額房費</li></ul><span>旺季（7月1日－8月31日）：<br></span><ul><li>\r\n取消入住若在抵達前45天內：收取1晚房費</li><li>\r\n取消入住若在抵達前30天內：收取全額房費</li></ul><span>尖峰季節（12月20日－1月9日）：<br></span><ul><li>\r\n取消入住若在抵達前30天內：收取全額房費</li></ul>未入住（No Show）：將收取全額住宿期間的房費作為罰金。', '<span>淡季（4月1日－6月30日、9月1日－12月19日、次年1月10日－3月31日）：<br></span><ul><li>\r\n如在抵达前21天取消：收取1晚房费</li><li>\r\n如在抵达前14天取消：收取全额房费</li></ul><span>旺季（7月1日－8月31日）：<br></span><ul><li>\r\n如在抵达前45天取消：收取1晚房费</li><li>\r\n如在抵达前30天取消：收取全额房费</li></ul><span>高峰季节（12月20日－1月9日）：<br></span><ul><li>\r\n如在抵达前30天取消：收取全额房费</li></ul>未入住（No Show）：将收取整段入住期间的全额房费作为罚金。', NULL, '2022-12-03 08:16:43', '2025-08-05 23:50:35', 1, 1),
(94, 'Alaya Resort Ubud', '17', 'Ubud', 'Bali', 'Indonesia', 'GXOIKI1pZo6HT7KQYFQIoOf3fs', '17', 17, 'Jalan Monkey Forest, Ubud, Bali, Indonesia', 2, 36, 'Nila Kresna', '0361972200', 'With 106 luxurious rooms, Alaya Resort Ubud is a sanctuary of serenity and sophistication in the culturally charged village of Ubud in the island of Bali. It has been built with rare sensitivity towards the surrounding environment and shares its rice terrace views with a number of the communities’ local independent cafes and eateries, including the neighbouring Bebek Bengil restaurant and Monkey Forest. As part of Ubud’s evolving hospitality scene, the exotic boutique property offers guests a stylish place to stay that reflects Ubud’s and Bali’s unique artistry. A number Bali’s most respected and talented designers have collaborated to create this elegant hotel with a distinct sense of belonging.', '擁有106間豪華客房的 Alaya Resort Ubud，是位於峇里島烏布文化氛圍濃厚村莊中的一處寧靜且精緻的避風港。度假村在建造時展現了對周遭環境的極高敏感度，並與當地社區的獨立咖啡館與餐廳共享壯麗的稻田景觀，包括鄰近的 Bebek Bengil 餐廳與猴子森林。作為烏布蓬勃發展的旅宿業的一部分，這間充滿異國情調的精品度假村為旅客提供時尚的住宿體驗，展現烏布與峇里島獨特的藝術魅力。多位峇里島最受尊敬與才華洋溢的設計師共同打造出這座充滿歸屬感的優雅飯店。', '拥有106间豪华客房的 Alaya Resort Ubud，是位于巴厘岛乌布文化氛围浓厚村庄中的一处宁静而精致的避世之所。度假村在建设时展现了对周边环境的高度敏感性，并与社区中多家本地独立咖啡馆与餐厅共享稻田美景，包括邻近的 Bebek Bengil 餐厅和猴森林。作为乌布不断发展的酒店业的一部分，这家充满异国情调的精品度假酒店为宾客提供一个时尚的住宿之所，展现乌布与巴厘岛独特的艺术气息。多位巴厘岛最受尊敬与才华横溢的设计师携手打造出这座充满归属感的优雅酒店。', NULL, NULL, NULL, '<b>Honeymoon Benefit Min. 2 Nights Stay :</b>&nbsp;<ul><li>Flower arragement on the bed upon arrival&nbsp;</li><li>Honeymoon cake&nbsp;</li></ul><b>Children Policy :&nbsp;</b><ul><li>Baby Food (12 months old and below) - No baby food provided by Alaya Resort Ubud</li><li>Toddler – 12 months old up to 2 years old get FOC meal based on existing menu available</li></ul>', '蜜月禮遇（最少入住2晚）：\r\n<ul>\r\n<li>\r\n入住時床上花藝擺設\r\n</li>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n</ul>\r\n兒童政策：\r\n<ul>\r\n<li>\r\n嬰兒食品（12個月以下）－Alaya Resort Ubud 不提供嬰兒食品\r\n</li>\r\n<li>\r\n幼兒（12個月至2歲）可免費享用現有菜單上的餐點\r\n</li>\r\n</ul>', '蜜月礼遇（最少入住2晚）：\r\n<ul>\r\n<li>\r\n入住时床上花艺布置\r\n</li>\r\n<li>\r\n蜜月蛋糕\r\n</li>\r\n</ul>\r\n儿童政策：\r\n<ul>\r\n<li>\r\n婴儿食品（12个月以下）－Alaya Resort Ubud 不提供婴儿食品\r\n</li>\r\n<li>\r\n幼儿（12个月至2岁）可根据现有菜单免费享用餐食</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1747963142_109387161.jpg', 14, 'http://alayahotels.com/alayaresortubud/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Alaya+Resort+Ubud/@-8.5184623,115.2617144,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd23d6c35a395c7:0x3153cf85768a9667!5m2!4m1!1i2!8m2!3d-8.5184676!4d115.2642893!16s%2Fg%2F11zbqqbjs?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.5185885, 115.2636070, NULL, NULL, '<span><b>Low Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 19 Dec, 08 Jan - 31 Mar) :&nbsp;</i></span><ul><li>Cancellation 14&nbsp;Days prior to arrival : 50%&nbsp;of full length of stay&nbsp;</li><li>Cancellation 7 Days prior to arrival or No-show : 100% for full length of stay&nbsp;</li></ul><span><b>High &amp; Peak Season</b> <i>(01 Jul - 31 Aug &amp; 20 Dec - 07 Jan) :&nbsp;</i></span><br><ul><li>Cancellation 21 Days prior to arrival : 50% of full length&nbsp;of stay</li><li>Cancellation 14 Days prior to arrival or No-show : 100% for full length of stay&nbsp;</li></ul>', '淡季（4月1日－6月30日、9月1日－12月19日、翌年1月8日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達前14天取消：需支付全住宿費用的50%\r\n</li>\r\n<li>\r\n抵達前7天內取消或未入住（No-show）：需支付全住宿費用的100%\r\n</li>\r\n</ul>\r\n旺季與尖峰季（7月1日－8月31日 &amp; 12月20日－翌年1月7日）：\r\n<ul>\r\n<li>\r\n抵達前21天取消：需支付全住宿費用的50%\r\n</li>\r\n<li>\r\n抵達前14天內取消或未入住（No-show）：需支付全住宿費用的100%</li></ul>', '淡季（4月1日－6月30日、9月1日－12月19日、次年1月8日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达前14天取消：需支付全部住宿费用的50%\r\n</li>\r\n<li>\r\n抵达前7天内取消或未入住（No-show）：需支付全部住宿费用的100%\r\n</li>\r\n</ul>\r\n旺季与高峰期（7月1日－8月31日 &amp; 12月20日－次年1月7日）：\r\n<ul>\r\n<li>\r\n抵达前21天取消：需支付全部住宿费用的50%\r\n</li>\r\n<li>\r\n抵达前14天内取消或未入住（No-show）：需支付全部住宿费用的100%</li></ul>', NULL, '2022-12-05 07:12:43', '2026-03-25 19:04:30', 1, 2),
(95, 'Tjendana Kanaka Jungle Resort Ubud', '17', NULL, NULL, NULL, 'kD1FUXxwZM9wgkNeQGFHX4fbrX', '17', NULL, 'Kelusa, Payangan, Gianyar Regency, Bali 80561', 2, 50, 'Mardian Putra', '08113971862', 'Immerse yourself in the serenity of nature at Tjendana Kanaka Jungle Resort Ubud, where luxury meets tranquility. Our villas are nestled in the heart of Ubud’s lush greenery, offering a peaceful retreat from the busy city life. Experience unparalleled comfort and privacy, surrounded by the soothing sounds of nature, Perfect for honeymooners, couples, or families seeking relaxation and reconnection. Discover a sanctuary designed for true relaxation and rejuvenation.', NULL, NULL, NULL, NULL, NULL, '<b>Seasonal Policy:</b>&nbsp;<ul><li>Minimum stay 3 nights during peak season NY Eve (27 Dec - 05 Jan)</li></ul>', NULL, NULL, NULL, NULL, NULL, 'Active', '1737352848_568720540.jpg', 14, 'https://tjendanakanakaresort.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/MhRVvQzhRaDGTHts9', NULL, NULL, NULL, NULL, '<span><b>Regular Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 22 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 30% from the total booking or 1 night charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 30% from the total booking or 1 night charge</li><li>Cancellation made within 14 - 8 days to arrival : 50% from the total booking or full charge for booking 1 night&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>High Season</b> <i>(01 Jul - 31 Aug, 23 - 26 Dec) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 01 night charge</li><li>Cancellation made within 21 - 15 days to arrival : 50% of total length of stay</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><span><b>Peak Season</b> <i>(27 Dec - 05 Jan) :&nbsp;</i></span><ul><li>Cancellation made within 60 - 22 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul>', NULL, NULL, NULL, '2022-12-14 13:51:22', '2025-05-14 18:44:58', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(96, 'Alaya Dedaun Kuta', '17', 'Kuta', 'Bali', 'Indonesia', 'MvspVrfeJSYKjT1VFAJ4gwYpx3', '17', 17, 'Jalan Legian, Kuta, Bali, Indonesia', 2, 9, 'Ayu Puspita', '0361756276', '<p>Steeped in romance, Alaya Dedaun Kuta brings affordable luxury and understated Indonesian elegance to Bali’s favourite beachside playground. Designed to embrace the spirit of a traditional village, the property features a collection of just 12 private villas in a concept attuned to the attributes of outdoor living.</p><p>Each villa is a tropical retreat secluded within a native garden compound featuring a generous sized swimming pool and ample space to unwind. Bedroom suites are styled to evoke a sense of privacy with canopied beds and indulging bathroom facilities. Attentive butler service ensures that all needs are effortlessly taken care of with a warm Balinese smile.</p>', NULL, NULL, '<ul><li>Butler service</li><li>Private swimming pool</li><li>Fully equipped gourmet kitchen</li><li>Stylish living environment</li><li>Separate shower and bathtub</li><li>Air conditioning</li><li>Alaya Signature Amenities PAGI</li><li>Slippers and kimonos</li><li>Access to gym facilities</li><li>Laundry, dry cleaning, and pressing service</li><li>Minibar</li><li>Espresso coffee and tea making facilities</li><li>Iron (on request)</li><li>Baby cot (on request)</li><li>Safety deposit box</li><li>Hairdryer</li><li>Cable TV (international and local channels)</li><li>IDD telephone</li><li>Integrated in-room entertainment system (Alaya)</li><li>Evening turndown service</li></ul>', NULL, NULL, '<p><strong>Children Policy :&nbsp;</strong></p><ul><li>Baby food (12 months old and below) - No baby food provided&nbsp;</li><li>Baby cots shall be supplied free of charge and must be requested at the time of reservation&nbsp;</li></ul><p><strong>Honeymooners Benefits Minimum 2 Nights Stay:</strong></p><p>All honeymooners receive upon arrival on complimentary:</p><ul><li>Honeymoon decoration on the bed and bath tub</li><li>Honeymoon cake</li></ul>', NULL, NULL, NULL, NULL, NULL, 'active', 'hotels/covers/1700195476_Alaya-Dedaun-Kuta.webp', 14, 'https://alayahotels.com/alaya-dedaun-kuta', '2', '45', '11:00', '13:00', 'https://www.google.com/maps/place/Alaya+Dedaun+Kuta/@-8.7131797,115.1732686,18.5z/data=!4m9!3m8!1s0x2dd24702420401f1:0x3179d5feabe35c2b!5m2!4m1!1i2!8m2!3d-8.7132366!4d115.1735126!16s%2Fg%2F11h81hd1zd?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.7131612, 115.1739573, NULL, NULL, '<p><strong>Low Season</strong> <em>(01 Apr - 14 Jul, 01 Sep - 19 Dec, 08 Jan - 31 Mar):&nbsp;</em></p><ul><li>Cancellation 14&nbsp;days prior to arrival : 50% of full length of stay&nbsp;</li><li>Cancellation 7 days prior to arrival or No-show&nbsp;: 100% for full length of stay&nbsp;</li></ul><p><strong>High &amp; Peak Season</strong> <em>(20 Dec - 07 Jan &amp; 15 Jul - 31 Aug):</em>&nbsp;</p><ul><li>Cancellation 21 days prior to arrival : 50% of full length of stay&nbsp;</li><li>Cancellation 14 days prior to arrival or No-show : 100% for full length of stay</li></ul>', NULL, NULL, NULL, '2023-03-27 09:26:50', '2026-03-25 19:03:01', 1, 2),
(98, 'The Leaf Jimbaran', '17', NULL, NULL, NULL, 'POqhnrskzHD3l6CiUxOgHIGyMn', '17', NULL, 'Karang-Mas, Sejahtera Jl. Jepun No.81, Jimbaran, Badung Regency, Bali 80361', 1, 12, 'Nyoman Ariawan', '03614725445', '<span style=\"color: rgb(25, 25, 25); font-family: Lato; font-size: 14px; text-align: center;\">The Leaf Jimbaran is a private luxury resort, tastefully furnished and elegantly decorated with a modern touch. It ensures privacy to embrace the sense of intimacy, peace and harmony due to our secluded location in Jimbaran.</span>', 'The Leaf Jimbaran 是一座私人奢華度假村，陳設高雅，融合現代風格的精緻設計。度假村坐落於金巴蘭靜謐隱蔽之地，確保賓客享有高度隱私，沉浸於親密、寧靜與和諧的度假氛圍之中。', 'The Leaf Jimbaran 是一座私人奢华度假村，陈设考究，融合现代风格的优雅设计。度假村位于金巴兰幽静隐秘的地段，确保宾客尊享高度私密空间，尽情感受亲密、宁静与和谐的度假氛围。', NULL, NULL, NULL, '<ol><li>A minimum stay of 3 (three) nights will be applied for bookings during Peak Season (24 Dec - 05 Jan) (passing New Year eve)&nbsp;</li><li>No check-in and check outs permitted on December 31, Januari 1, and Silent day&nbsp;</li><li>Compulsory New Year Dinner on 31 December : Price (TBA)&nbsp;</li></ol>', '<p>高峰季（12 月 24 日－1 月 5 日，含跨年夜）之預訂，需至少入住 <strong data-start=\"214\" data-end=\"221\">3 晚</strong>。<br data-start=\"222\" data-end=\"225\">\r\n12 月 31 日、1 月 1 日及靜居日（Nyepi）<strong data-start=\"253\" data-end=\"267\">不提供入住或退房服務</strong>。</p><p>12 月 31 日跨年晚宴為強制性（價格待定）</p>', '<div>高峰季（12 月 24 日－1 月 5 日，含跨年夜）期间的预订，需至少入住 <strong data-start=\"347\" data-end=\"354\">3 晚</strong>。<br data-start=\"355\" data-end=\"358\">\r\n12 月 31 日、1 月 1 日及静居日（Nyepi）<strong data-start=\"386\" data-end=\"400\">不允许办理入住或退房</strong>。</div><div>12 月 31 日跨年晚宴为强制性（价格待定）</div><div><div></div></div>', NULL, NULL, NULL, 'Active', '1769756059_lobby exterior .jpg', 14, 'http://www.theleafjimbaran.com/', '2', '360', NULL, NULL, 'https://goo.gl/maps/jWb5D1kYUX1cXwzp7', NULL, NULL, NULL, NULL, '<p><b>Low Seasons : </b></p><ol><li>Within 7 days : 50% accommodation charge </li><li>\r\nOn arrival day  : entire stay accommodation charge</li></ol><p><b>High Seasons (02 - 08 Apr 2026, 01 Jul - 31 Aug 2026, 01 - 07 Oct, 03 - 09 Feb 2026, 25 - 31 Mar 2027) and Peak Seasons (24 Dec - 05 Jan) :</b></p><ol><li> \r\nWithin 21 days : 50% accommodation charge </li><li>\r\nWithin 14 days : entire stay accommodation charge</li></ol><p><br></p><p>In the case of \"No Show\" on, entire stay accommodation charge from number of room(s) confirmed \r\nwill be charged </p>', '<p data-start=\"144\" data-end=\"153\"><strong data-start=\"144\" data-end=\"151\">淡季：</strong></p>\r\n<ul data-start=\"154\" data-end=\"203\">\r\n<li data-start=\"154\" data-end=\"180\">\r\n<p data-start=\"156\" data-end=\"180\">入住日前 7 天內取消：收取 50% 住宿費</p>\r\n</li>\r\n<li data-start=\"181\" data-end=\"203\">\r\n<p data-start=\"183\" data-end=\"203\">入住當日取消或未入住：收取全程住宿費</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"205\" data-end=\"326\"><strong data-start=\"205\" data-end=\"324\">旺季（2026 年 4 月 2–8 日、2026 年 7 月 1 日–8 月 31 日、10 月 1–7 日、2026 年 2 月 3–9 日、2027 年 3 月 25–31 日）及高峰季（12 月 24 日–1 月 5 日）：</strong></p>\r\n<ul data-start=\"327\" data-end=\"379\">\r\n<li data-start=\"327\" data-end=\"354\">\r\n<p data-start=\"329\" data-end=\"354\">入住日前 21 天內取消：收取 50% 住宿費</p>\r\n</li>\r\n<li data-start=\"355\" data-end=\"379\">\r\n<p data-start=\"357\" data-end=\"379\">入住日前 14 天內取消：收取全程住宿費</p><p data-start=\"357\" data-end=\"379\"><br></p><p data-start=\"357\" data-end=\"379\">如發生未入住（No Show）情況，將依已確認之房間數量，收取全程住宿費用。</p></li></ul>', '<p data-start=\"420\" data-end=\"429\"><strong data-start=\"420\" data-end=\"427\">淡季：</strong></p>\r\n<ul data-start=\"430\" data-end=\"481\">\r\n<li data-start=\"430\" data-end=\"457\">\r\n<p data-start=\"432\" data-end=\"457\">入住日前 7 天内取消：收取 50% 住宿费用</p>\r\n</li>\r\n<li data-start=\"458\" data-end=\"481\">\r\n<p data-start=\"460\" data-end=\"481\">入住当日取消或未入住：收取全程住宿费用</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"483\" data-end=\"604\"><strong data-start=\"483\" data-end=\"602\">旺季（2026 年 4 月 2–8 日、2026 年 7 月 1 日–8 月 31 日、10 月 1–7 日、2026 年 2 月 3–9 日、2027 年 3 月 25–31 日）及高峰季（12 月 24 日–1 月 5 日）：</strong></p>\r\n<ul data-start=\"605\" data-end=\"659\">\r\n<li data-start=\"605\" data-end=\"633\">\r\n<p data-start=\"607\" data-end=\"633\">入住日前 21 天内取消：收取 50% 住宿费用</p>\r\n</li>\r\n<li data-start=\"634\" data-end=\"659\">\r\n<p data-start=\"636\" data-end=\"659\">入住日前 14 天内取消：收取全程住宿费用</p><p data-start=\"636\" data-end=\"659\"><br></p><p data-start=\"636\" data-end=\"659\">如发生未入住（No Show）情况，将根据已确认的房间数量，收取全程住宿费用。</p></li></ul>', NULL, '2023-05-28 18:23:40', '2026-02-01 19:27:48', 1, 1),
(99, 'Vivara Private Pool Villas & Spa Retreat', '17', NULL, NULL, NULL, 'TB8Da37WviIysV6yHNuzLxndLM', '17', NULL, 'Jl. Karang Mas, Jimbaran, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 5, 'Gustra', '03614724977', 'Vivara Jimbaran Bali is a luxurious retreat with private pool villas offering a memorable and personalized royal experience near Jimbaran Beach. Step into the world of Vivara Bali, Jimbaran Bali, offering luxurious villas with private pools surrounded by lush greenery. This is the perfect place for travelers looking for a romantic retreat, golf, getaway, relaxing stay, family vacation, or a base for their travels. Explore the culture and stunning beaches of this paradise island.', 'Vivara Jimbaran Bali 是一座豪華的度假勝地，擁有私人泳池別墅，提供難忘且量身打造的皇室體驗，鄰近金巴蘭海灘。走進 Vivara Bali 的世界，金巴蘭峇里島為您呈獻被綠意環繞的奢華私人泳池別墅。這裡是尋求浪漫之旅、高爾夫假期、放鬆住宿、家庭旅行，或作為探索之基地的旅客的理想選擇。探索這座天堂島嶼的文化與迷人海灘。', 'Vivara Jimbaran Bali 是一家豪华度假村，提供带私人泳池的别墅，带来难忘且个性化的皇室体验，靠近金巴兰海滩。走进 Vivara Bali 的世界，金巴兰巴厘岛为您呈现被郁郁葱葱绿意环绕的奢华私人泳池别墅。这里是寻找浪漫之旅、高尔夫假期、放松住宿、家庭度假或作为旅行基地的游客的理想之选。探索这座天堂岛屿的文化和迷人海滩。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1731996699_661dff6eea11b788232576.webp', 14, 'http://www.vivarabali.com/', '2', '360', NULL, NULL, 'https://goo.gl/maps/Wwd2KeRQQEBPW5E29', NULL, NULL, NULL, NULL, '<ul><li>All cancellations made within 15 days before arrival in normal season & 21 days during High <i>(01 Jul - 31 Aug)</i> /Peak season will charge 1 night cancellation fee. And if, within 7 days before arrival in Normal Season, 14 days in High/Peak season will be charged 50% from the total booking. Full charge will be applied for cancellation below than 6 days prior arrival. </li><li>In case of No Show and early check out, entirely 100% charge of booking will be applied. </li></ul>', '<ul><li>所有在正常季節入住前15天內取消的預訂，以及在旺季（7月1日至8月31日）／巔峰季節入住前21天內取消的預訂，將收取1晚的取消費用。 若在正常季節入住前7天內、或在旺季／巔峰季節入住前14天內取消，將收取總預訂金額的50%。若在抵達前6天內取消，將收取總預訂金額的100%作為取消費用。</li><li>如未出現（No Show）或提前退房，將收取總預訂金額的100%作為費用。</li></ul>', '<ul><li>所有在正常季节入住前15天内取消的预订，以及在旺季（7月1日至8月31日）／高峰季节入住前21天内取消的预订，将收取1晚的取消费用。若在正常季节入住前7天内，或在旺季／高峰季节入住前14天内取消，将收取总预订金额的50%。若在抵达前6天内取消，将收取总预订金额的100%作为取消费用。</li><li>\r\n如未入住（No Show）或提前退房，将收取总预订金额的100%作为费用。</li></ul>', NULL, '2023-05-28 19:43:11', '2026-03-24 18:21:00', 1, 1),
(100, 'Sofitel Bali Nusa Dua Beach Resort', '17', NULL, NULL, NULL, 'pYPl247FEaLmzMwbvhlpSFKTJL', '17', NULL, 'Itdc Tourism Complex, Jl. Nusa Dua Lot N5, Benoa, South Kuta, Badung Regency, Bali 80363', 1, 14, 'Teza Badina Korompis', '03618492888', 'Imagine a luxury hotel on a beach in the sought-after enclave of Nusa Dua. A space imbued with Balinese spirit and French elegance. Stunning lagoon pools and venues for events and spectacular weddings in our beachfront ballroom.<br>At Sofitel Bali Nusa Dua Beach Resort, discover opulent villas and plunge-pool rooms. A luxe Balinese spa and eco-conscious values. Two bars, three restaurants and the famous Cucina Brunch. Exclusive VIP lounge at Club Millésime and entertainment at Manarai Beach House.', '想像一間位於夢幻地段努沙杜瓦（Nusa Dua）海灘上的奢華飯店，一個融合峇里島精神與法式優雅的空間。壯觀的潟湖泳池、可舉辦活動與盛大婚禮的海濱宴會廳，盡顯尊貴氛圍。\r\n在 Sofitel Bali Nusa Dua Beach Resort，您將體驗到奢華的別墅與私人泳池房型、極致放鬆的峇里式水療與永續環保理念。飯店內設有兩間酒吧、三間餐廳，以及聞名遐邇的 Cucina 早午餐。尊貴的 Club Millésime 貴賓專屬休息室與 Manarai Beach House 的娛樂活動也為您的假期增添精彩。', '想象一家位于热门目的地努沙杜瓦（Nusa Dua）海滩的奢华酒店，一个融合巴厘岛精神与法式优雅的空间。壮观的泻湖泳池，以及可举办活动与盛大婚礼的海滨宴会厅。\r\n在 Sofitel Bali Nusa Dua Beach Resort，您将发现豪华别墅与私人泳池客房，巴厘式奢华水疗体验，以及注重环保的理念。酒店设有两间酒吧、三间餐厅，以及著名的 Cucina 早午餐。尊贵的 Club Millésime 贵宾专属休息室和 Manarai Beach House 的娱乐活动也让您享受非凡假期。', '<ul><li>Swimming Pools</li><li>Spa and Wellness</li><li>Fitness Center</li><li>Beach Access</li><li>Kids\' Club</li><li>Free Wi-Fi</li><li>24-Hour Room Service</li></ul>', '<ul><li><li>游泳池</li><li>水療與養生設施</li><li>健身中心</li><li>海灘通道</li><li>兒童俱樂部</li><li>免費無線上網</li><li>24小時客房服務</li></li></ul>', '<ul><li><li>游泳池</li><li>水疗与养生设施</li><li>健身中心</li><li>海滩通道</li><li>儿童俱乐部</li><li>免费无线网络</li><li>24小时客房服务</li></li></ul>', '<b>Seasonal Policy :&nbsp;</b><ul><li>Compulsory New Year Eve Dinner on 31 December 2025 (Price at additional charge)&nbsp;</li><li>Minimum length of stay is three (3) nights for booking stay over 30 and 31 December.</li><li>Close-out Dates : Silent Day, 19&nbsp;March 2026 (No check in and check out)&nbsp;</li></ul><b><u>Bonus Offer : Honeymoon&nbsp;</u></b><br><b>Minimum three (3) nights stay receive a surprised in-room honeymoon decorations, honeymoon cocktail for 2 people \r\nat Le Bar and honeymoon cake/chocolate upon arrival.</b> <br><ul><li>Honeymoon benefits are subject to change without prior notice and subject to availability.&nbsp;</li><li>Date of Wedding is required upon reservation&nbsp;</li><li>Applicable for maximum one (1) year after the stated wedding date</li></ul><b><u>Bonus Offer : Family Holiday</u></b><br><ul><li><b>Complimentary accommodation and breakfast for one (1) child under twelve (12) years old, additional with one (1) \r\nbaby crib or rollaway bed.&nbsp;</b></li></ul>Complimentary baby crib/rollaway bed should be booked upon reservation and subject to availability.&nbsp;<br><ul><li><b>Complimentary daily selected 2 hours free activity at Kids Club for one (1) child aged four (4) until twelve (12) years old, \r\nsubject to Kids Club\'s schedule.&nbsp;</b></li></ul>This daily complimentary 2 hours is non-accumulative. \r\nAdditional fee applies to a child aged 1-3 years old, and must be accompanied by authorized parent/guardian. \r\nAdditional fee applies to parent/guardian.&nbsp;<br>', '<span>季節性政策：<br></span><ul><li>\r\n2025年12月31日需參加跨年晚宴（額外收費）</li><li>\r\n凡於12月30日及31日期間入住者，最少需住宿三（3）晚</li><li>封閉日期：靜居日，2026年3月19日（不接受入住及退房）</li></ul><span>【額外優惠：蜜月禮遇】<br>\r\n凡連住三（3）晚，可享有以下驚喜蜜月禮遇：</span>\r\n<ul>\r\n<li>\r\n客房內蜜月驚喜佈置\r\n</li>\r\n<li>\r\n於 Le Bar 享用雙人蜜月雞尾酒\r\n</li>\r\n<li>\r\n<span>抵達時提供蜜月蛋糕或巧克力<br>\r\n※蜜月禮遇如有變更恕不另行通知，並視供應情況而定<br>\r\n※訂房時需提供結婚日期<br>\r\n※適用於結婚日期起一年內之入住</span>\r\n</li>\r\n</ul>\r\n【額外優惠：家庭假期】\r\n<ul>\r\n<li>\r\n一名12歲以下兒童可免費入住並享用早餐，並可額外提供一張嬰兒床或加床（需於預訂時提出，視供應情況而定）\r\n</li>\r\n<li>\r\n<span>每天免費參加精選兒童俱樂部活動2小時（適用於4至12歲孩童，依兒童俱樂部活動時間表為準）<br>\r\n※此免費活動每日限用，不可累積<br>\r\n※1-3歲孩童參與需支付額外費用，且須有家長或監護人陪同<br>\r\n※家長／監護人陪同亦需支付額外費用</span></li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2025年12月31日需参加跨年晚宴（额外收费）</li><li>\r\n凡于12月30日及31日期间入住者，最少需入住三（3）晚</li><li>封闭日期：静居日，2026年3月19日（不接受入住及退房）</li></ul><span>【额外优惠：蜜月礼遇】<br>\r\n凡连续入住三（3）晚，可享以下蜜月惊喜：</span>\r\n<ul>\r\n<li>\r\n客房内蜜月惊喜布置\r\n</li>\r\n<li>\r\n于 Le Bar 享用双人蜜月鸡尾酒\r\n</li>\r\n<li>\r\n<span>抵达时提供蜜月蛋糕或巧克力<br>\r\n※蜜月礼遇如有更动恕不另行通知，且视房况供应情况而定<br>\r\n※预订时须提供结婚日期<br>\r\n※适用于结婚日期起一年内入住</span>\r\n</li>\r\n</ul>\r\n【额外优惠：家庭假期】\r\n<ul>\r\n<li>\r\n一名12岁以下儿童可免费入住并享用早餐，另提供一张婴儿床或加床（需在预订时提出，视供应情况而定）\r\n</li>\r\n<li>\r\n<span>每日提供一名4至12岁儿童免费2小时精选儿童俱乐部活动（依儿童俱乐部日程安排为准）<br>\r\n※此免费活动每日限一次，不可累计<br>\r\n※1-3岁儿童参加需支付额外费用，且需由家长／监护人陪同<br>\r\n※家长／监护人陪同亦需支付费用</span></li></ul>', NULL, NULL, NULL, 'Active', '1700199339_Sofitel-Hotel-and-Resort.webp', 14, 'sofitel.accor.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/pGooxvuw1X9bsApM9', NULL, NULL, NULL, NULL, '<span><b>Low Season</b> <i>(07 Apr - 30 Jun, 01 Sep - 19 Dec, 05 Jan - 31 Mar):&nbsp;</i></span><ul><li>Cancellation 7 days prior to arrival : 1 night charge&nbsp;</li></ul><span><b>High Season</b> <i>(01 - 06 Apr, 01 Jul - 31 Aug):&nbsp;</i></span><ul><li>Cancellation 14 days prior to arrival : 1 night charge&nbsp;</li></ul><span><b>Peak Season</b> <i>(20 Dec - 04 Jan):&nbsp;</i></span><ul><li>Cancellation 21 days prior to arrival : Full&nbsp;charge&nbsp;</li></ul><b>No Show :</b> 100% charge&nbsp;<br>', '<span>淡季（4月7日－6月30日、9月1日－12月19日、1月5日－3月31日）：<br></span><ul><li>\r\n抵達前7天取消：收取1晚房費</li></ul><span>旺季（4月1日－4月6日、7月1日－8月31日）：<br></span><ul><li>\r\n抵達前14天取消：收取1晚房費</li></ul><span>尖峰季（12月20日－1月4日）：<br></span><ul><li>\r\n抵達前21天取消：收取全額費用</li></ul>未出現（No Show）：收取100%全額費用', '<span>淡季（4月7日－6月30日、9月1日－12月19日、1月5日－3月31日）：<br></span><ul><li>\r\n抵达前7天取消：收取1晚房费</li></ul><span>旺季（4月1日－4月6日、7月1日－8月31日）：<br></span><ul><li>\r\n抵达前14天取消：收取1晚房费</li></ul><span>高峰季（12月20日－1月4日）：<br></span><ul><li>\r\n抵达前21天取消：收取全部费用</li></ul>未出现（No Show）：收取100%全额费用', NULL, '2023-05-29 01:05:16', '2025-06-30 22:03:53', 1, 1),
(101, 'Mercure Bali Legian', '17', NULL, NULL, NULL, 'cb2epqiOA4IXtU4qVPtSK4wINX', '17', NULL, 'Jln Legian No.328, Legian, Kelod, Bali, 80361', 1, 7, 'Sri Budiarti', '03619386100', 'Mercure Bali Legian is strategically located in the Legian area, at the crossroads of various popular tourist attractions. It is close to nearby points of interest such as Legian, Seminyak, and Kuta beach areas. Kuta–Legian Beach is only a 7-minute walk from the hotel. Mercure Bali Legian is perfect for business or leisure trips, and ideal for honeymoons, corporate clients, or family stays. It is part of the MyResorts program, which offers exclusive experiences for ALL members.\r\nStrategically situated on Legian main street and just a short walk to the famous Kuta and Legian beaches, nightlife, a variety of restaurants, and the renowned Seminyak shopping district. Located 15 minutes on foot from the Beachwalk shopping center, Mercure Bali Legian is perfect for explorers.', '美居巴厘島雷吉安酒店位於雷吉安地區的戰略位置，處於多處熱門旅遊景點的交匯處。酒店鄰近雷吉安、塞米亞克和庫塔海灘等著名景點，步行至庫塔–雷吉安海灘僅需7分鐘。美居巴厘島雷吉安酒店非常適合商務或休閒旅行，也是蜜月、新人、企業客戶或家庭入住的理想之選。酒店是 MyResorts 計劃的一部分，為 ALL 會員提供獨家體驗。酒店地處雷吉安主街，步行即可到達著名的庫塔和雷吉安海灘、熱鬧的夜生活、多樣化的餐廳以及聞名遐邇的塞米亞克購物區。步行15分鐘即可到達 Beachwalk 購物中心，是熱愛探索的旅客的絕佳選擇。', '美居巴厘岛雷吉安酒店位于雷吉安地区的战略位置，处于多处热门旅游景点的交汇处。酒店邻近雷吉安、塞米亚克和库塔海滩等著名景点，步行至库塔–雷吉安海滩仅需7分钟。美居巴厘岛雷吉安酒店非常适合商务或休闲旅行，也是蜜月、新人、企业客户或家庭入住的理想之选。酒店是 MyResorts 计划的一部分，为 ALL 会员提供独家体验。酒店地处雷吉安主街，步行即可到达著名的库塔和雷吉安海滩、热闹的夜生活、多样化的餐厅以及闻名遐迩的塞米亚克购物区。步行15分钟即可到达 Beachwalk 购物中心，是热爱探索的旅客的绝佳选择。', NULL, NULL, NULL, '<ul><li>No Check-in and Check-out on Nyepi Day&nbsp;</li><li>No Check-in and Check-out on 31st Dec 25, with minimum of stay 3 nights during peak season (22 December 2025 - 05 Jan 2026)&nbsp;</li></ul>', '靜居日（Nyepi Day）當天不可辦理入住和退房。<br>\r\n2025年12月31日不可辦理入住和退房，旺季（2025年12月22日–2026年1月5日）期間需至少入住3晚。', '静居日（Nyepi Day）当天不可办理入住和退房。<br>\r\n2025年12月31日不可办理入住和退房，旺季（2025年12月22日–2026年1月5日）期间需至少入住3晚。', NULL, NULL, NULL, 'inactive', '1755065464_8450_ho_00_p_2048x1536.jpg', 14, 'https://all.accor.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/kK6y9nyBPwUHjktp7', NULL, NULL, NULL, NULL, '1 night cancellation apply for cancellation made within 3 days prior to arrival&nbsp;', '在抵達日期前3天內取消預訂，將收取1晚的取消費用。', '在抵达日期前3天内取消预订，将收取1晚的取消费用。', NULL, '2023-05-29 20:11:08', '2026-03-24 18:26:55', 1, 1),
(102, 'Mason Elephant Park & Lodge', '17', NULL, NULL, NULL, 'WGpcrnxH7F1wp6ytqT9CRdNdbS', '17', NULL, 'Jalan Elephant Safari Park Banjar Desa Taro Tegallalang, Taro, Kec. Tegallalang, Kabupaten Gianyar, Bali 80561', 2, 51, 'Ratna Devi', '0361721480', 'Welcome to Bali\'s \"Most Unique\" Hotel and the&nbsp;World Luxury Hotel Awards 2019 Winner&nbsp;for&nbsp;Best Luxury Lodge in Asia and Best Luxury Eco Safari Lodge in the World. We are committed to providing our guests with a once in a lifetime experience amongst Bali’s largest herd of rescued Sumatran elephants. Staying at the Lodge is a rewarding experience as you can interact in numerous ways with these majestic creatures and get up close &amp; personal with them. The park is fully committed to conservation and has set new standards in how to care for elephants in a purpose-built environment. Here you can see that they are well cared for in a healthy and stimulating environment that caters to all their daily needs.', '歡迎來到峇里島「最獨特」的飯店——榮獲2019年世界奢華酒店大獎，亞洲最佳奢華旅舍以及全球最佳奢華生態野生動物旅舍。我們致力於為賓客提供一次終身難忘的體驗，與峇里島最大群體的蘇門答臘救援大象共度時光。\r\n入住本旅舍是極具價值的體驗，您可透過多種互動方式與這些雄偉的大象親密接觸。園區完全致力於保育工作，並在為大象量身打造的空間中，建立了全新的照護標準。在這裡，您將看到大象們在健康且充滿刺激的環境中，獲得細心照料，日常需求無一遺漏。', '欢迎来到巴厘岛“最独特”的酒店——2019年世界奢华酒店大奖获奖者，荣获亚洲最佳奢华旅舍及全球最佳奢华生态野生动物旅舍称号。我们致力于为宾客提供一次终生难忘的体验，与巴厘岛最大的获救苏门答腊大象群共度美好时光。\r\n入住本旅舍将是一段充满意义的旅程，您可以通过多种方式与这些雄伟的大象亲密互动。园区全力投入保护工作，在专门打造的环境中为大象设立了新的照护标准。在这里，您将看到它们在健康、富有刺激的环境中被悉心照顾，每日所需一应俱全。', NULL, NULL, NULL, '<b>Honeymoon Bonus:&nbsp;</b><ul><li>Complimentary Honeymoon Cake and In-room Decoration.</li><li>One time Afternoon High Tea per stay at Mammoth Head Bar, Terrace and Lounge.</li><li>All room types will receive above services.&nbsp;</li></ul>', '蜜月禮遇：<br><ul><li>\r\n免費蜜月蛋糕與客房內佈置。</li><li>\r\n每次入住可享一次下午高茶，地點為 Mammoth Head Bar、Terrace 和 Lounge。</li><li>\r\n所有房型皆可享上述服務。</li></ul>', '蜜月礼遇：<br><ul><li>\r\n免费蜜月蛋糕及客房内布置。</li><li>\r\n每次入住可享一次下午高茶，地点为 Mammoth Head Bar、Terrace 和 Lounge。</li><li>\r\n所有房型均可享受上述服务。</li></ul>', NULL, NULL, NULL, 'Active', '1731996864_Bali-Interiors2017_12_30-15.webp', 14, 'https://www.masonelephantlodge.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/AbEWAxFxgZBLnzXw8', NULL, NULL, NULL, NULL, '<ul><li>Notification of cancellation shall be made 7 (seven) days prior to check in date for period stay from 1 Apr - 14 Jul, 16 Aug - 31 Mar, or else one night cancellation fee will apply for 14 (fourteen) days prior to check in date for period stay from 15 Jul - 15 Aug, or else one night cancellation fee will apply.&nbsp;</li></ul><b>No Show:&nbsp;</b><br><ul><li>Tour Operator will be charged at full amount of booking in case of No Show / Early Check Out for period stay from 15 July-15 August or one night amount of booking in case of No Show / Early Check Out for period stay from 1 April-14 July, 16 August-31 March.&nbsp;No Show charges will be calculated based on number of rooms booked.</li></ul>', '<ul><li>如需取消預訂，請在入住日前至少 7 天通知，適用於入住期間為 4 月 1 日至 7 月 14 日、8 月 16 日至 3 月 31 日；否則將收取一晚取消費。若入住期間為 7 月 15 日至 8 月 15 日，則須在入住日前至少 14 天通知取消；否則將收取一晚取消費。</li></ul><span>未入住（No Show）：<br></span><ul><li>\r\n若入住期間為 7 月 15 日至 8 月 15 日，未入住或提前退房，將向旅行社收取全額訂單費用。若入住期間為 4 月 1 日至 7 月 14 日、8 月 16 日至 3 月 31 日，未入住或提前退房，將收取相當於一晚的費用。未入住費用將根據預訂的房間數計算。</li></ul>', '<ul><li>如需取消预订，请在入住日前至少 7 天通知，适用于入住期间为 4 月 1 日至 7 月 14 日、8 月 16 日至 3 月 31 日；否则将收取一晚取消费。若入住期间为 7 月 15 日至 8 月 15 日，则须在入住日前至少 14 天通知取消；否则将收取一晚取消费。</li></ul><span>未入住（No Show）：<br></span><ul><li>\r\n若入住期间为 7 月 15 日至 8 月 15 日，未入住或提前退房，将向旅行社收取全部预订金额。若入住期间为 4 月 1 日至 7 月 14 日、8 月 16 日至 3 月 31 日，未入住或提前退房，将收取相当于一晚的费用。未入住费用将根据预订的房间数量计算。</li></ul>', NULL, '2023-05-30 22:25:31', '2025-06-30 22:40:18', 1, 1),
(103, 'Ulu Segara Luxury Suites & Villas', '17', NULL, NULL, NULL, 'EA1AG5EnCcAZ6w9Sk1ZqIiskjs', '17', NULL, 'Jl. Raya Nusa Dua Selatan, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80363', 1, 18, 'Indah', '03618468188', 'With exquisite villas and a coveted location along the beach on the southern tip of the island, this 5-star destination hotel promises a getaway marked with utter relaxation and all-encompassing exclusivity. A stunning ocean view in Bali, offers 46 of suites and villas, many of which affording sunrise beach view. Be part of the Ulu Segara, experience a vibrant and tranquility one of the most popular beaches in Bali.', '擁有精緻別墅與島嶼南端海灘上的黃金地段，這家五星級度假酒店承諾為您帶來一段徹底放鬆且極致私密的假期體驗。壯麗的峇里島海景，共提供 46 間套房與別墅，其中許多客房可欣賞日出海灘景致。成為 Ulu Segara 的一部分，體驗這片峇里島最受歡迎海灘之一的活力與寧靜。', '拥有精致别墅与岛屿南端海滩上的黄金地段，这家五星级度假酒店承诺为您带来彻底放松且极致私密的假期体验。壮丽的巴厘岛海景，共提供 46 间套房与别墅，其中许多客房可欣赏日出海滩美景。成为 Ulu Segara 的一部分，体验这片巴厘岛最受欢迎海滩之一的活力与宁静。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>Compulsory New Year Eve Dinner on 31 December : TBA&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n12月31日需參加強制性跨年晚宴：價格待定</li></ul>', '季节性政策：<br><ul><li>\r\n12月31日需参加强制性跨年晚宴：价格待定</li></ul>', NULL, NULL, NULL, 'Active', '1731996997_b734c5b73de3533abe6b16f6a92cafdd.webp', 14, 'www.ulusegara.com', '2', '45', NULL, NULL, 'https://goo.gl/maps/oa2qg7AsvDbon4HB8', NULL, NULL, NULL, NULL, '<ul><li>Cancellation within 14 days all seasons, any cancellation will be subjected to fee equal to one night room charge.&nbsp;</li></ul><ul><li>No Show: No show will be charged a penalty equal to 100% of the stay&nbsp;</li></ul>', '<ul><li>所有季節若於14天內取消，將收取相當於一晚房費的取消費用。</li><li>\r\n未出現（No Show）：未出現將收取相當於整段住宿費用的罰金。</li></ul>', '<ul><li>所有季节若在14天内取消，将收取相当于一晚房费的取消费用。</li><li>\r\n未入住（No Show）：未入住将收取相当于整个住宿费用的罚金。</li></ul>', NULL, '2023-05-31 01:28:37', '2025-06-30 22:48:46', 1, 1),
(104, 'Four Seasons Resort Bali At Sayan', '17', NULL, NULL, NULL, 'rhXp7x2XucweS2PI7bQrUlWLvh', '17', NULL, 'Jl. Raya Sayan, Sayan, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 3, 39, 'Elis Tanthra', '0361977577', 'Four Seasons Resort Sayan encapsulates Bali at its philosophical and soulful best: a sublime hillside haven where man, humanity and nature unite with purest intent. Only a 10 minute drive from the stylish boutiques, artist ateliers and atmospheric eateries of boho-chic Ubud, Four Seasons Sayan is an inspiring base from which to explore Bali\'s cultural heart or to retreat into nature\'s meditative embrace. Arrive via a dramatic bridge, beneath which the Ayung River valley spreads its tropical arms. Descend from the gravity-defying rooftop lotus pond to the two-tiered swimming pool cantilevered over the river, through an enchanting forest that cocoons just 60 suites and villas. Choose from secluded treetop accommodations or riverside sanctuaries – all ultra-comfortable and authentically Balinese, furnished with traditional ikat fabrics, antique furnishings and Indonesian artefacts.', '四季渡假村賽安（Four Seasons Resort Sayan）完美體現峇里島最深層的哲學與靈魂精髓：這是一處絕美的山丘天堂，人、社會與自然在此以最純粹的意念合而為一。距離波希米亞風格的烏布市中心僅十分鐘車程，鄰近時尚精品店、藝術工作室與充滿氛圍的餐廳，四季賽安是一處靈感湧現的據點，無論是深入探索峇里島的文化核心，還是沉浸在大自然的靜謐懷抱中。\r\n進入渡假村需穿越一座壯觀的橋樑，橋下便是綠意盎然的阿漾河谷。從高空漂浮的蓮花池屋頂一路下行，穿越一座迷人的森林，來到懸於河面上的雙層泳池。渡假村僅設有60間套房與別墅，提供完整隱私與靜謐感。\r\n您可選擇隱密的樹梢住宿，或靠近河岸的靜謐居所——每間皆極為舒適且擁有道地的峇里島風格，搭配傳統伊卡織品、古董家具與印尼藝術品。', '四季度假村赛安（Four Seasons Resort Sayan）完美呈现峇里岛哲学与灵魂的精髓：一个崇高的山丘天堂，在这里，人类与自然以最纯粹的初心合而为一。距离波西米亚风情的乌布市中心仅10分钟车程，四季赛安是探索峇里文化之心或沉浸于自然冥想怀抱的理想出发点。\r\n您将经由一座壮观的桥梁抵达，桥下便是热带植被繁盛的阿勇河谷。从漂浮空中的莲花池屋顶一路而下，穿越一片环绕着60间套房与别墅的魔幻森林，抵达悬于河流之上的双层泳池。\r\n无论是隐秘的树梢住宿还是靠近河畔的宁静圣所——每间房型皆舒适惬意，充满地道的巴厘风情，装饰以传统伊卡纺织品、古董家具和印尼艺术品。', '<ul><li>Pool Facilities&nbsp;</li><li>Salon (Open-By Appointment Only)&nbsp;</li><li>Fitness Centre&nbsp;</li><li>Spa&nbsp;</li><li>Local Shuttle / Car Service&nbsp;</li><li>Airport Transportation&nbsp;</li><li>Parking &amp; Valet&nbsp;</li><li>Riverside&nbsp;</li><li>Ayung Terrace&nbsp;</li><li>Chef\'s Table at Sokasi&nbsp;</li><li>Jati Bar&nbsp;</li><li>Kids Club&nbsp;</li><li>Babysitting Service&nbsp;</li></ul>', '<ul><li>泳池設施</li><li>\r\n美髮沙龍（僅限預約開放）</li><li>\r\n健身中心</li><li>\r\n水療中心</li><li>\r\n本地接駁／包車服務</li><li>\r\n機場接送</li><li>\r\n停車場與代客泊車服務</li><li>\r\n河畔景觀</li><li>\r\nAyung Terrace 餐廳</li><li>\r\nSokasi 主廚餐桌體驗</li><li>\r\nJati 酒吧</li><li>\r\n兒童俱樂部</li><li>\r\n保母服務</li></ul>', '<ul><li>泳池设施</li><li>\r\n美发沙龙（仅限预约开放）</li><li>\r\n健身中心</li><li>\r\n水疗中心</li><li>\r\n本地接驳／包车服务</li><li>\r\n机场接送</li><li>\r\n停车场与代客泊车服务</li><li>\r\n河畔景观</li><li>\r\nAyung Terrace 餐厅</li><li>\r\nSokasi 主厨餐桌体验</li><li>\r\nJati 酒吧</li><li>\r\n儿童俱乐部</li><li>\r\n保姆服务</li></ul>', '<b>Children Policy:&nbsp;<br></b><ul><li>One extra bed (not including breakfast) will be given complimentary for a child below 18 years old \r\n(17.99 years old) sharing a bedroom with parents&nbsp;</li><li>Maximum 2 children can share a bedroom with parents with one (1) additional extra bed&nbsp;<b></b></li></ul><b>Honeymooners will get the following benefit :&nbsp;</b><ul><li>Tropical flower bouquet upon arrival&nbsp;</li><li>Honeymoon sweets</li><li>Flower petals arrangements</li></ul>', '<span>兒童政策：<br></span><ul><li>\r\n未滿18歲（17.99歲）與父母同住的兒童可免費提供一張加床（不含早餐）。</li><li>\r\n每間房最多可容納2位兒童與父母同住，並提供一（1）張額外加床。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時贈送熱帶花束</li><li>\r\n蜜月甜點</li><li>\r\n花瓣裝飾</li></ul>', '<span>儿童政策：<br></span><ul><li>\r\n18岁以下（17.99岁）与父母同住的儿童可免费提供一张加床（不含早餐）。</li><li>\r\n每间房最多允许2位儿童与父母同住，并可提供一（1）张额外加床。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时赠送热带花束</li><li>\r\n蜜月甜点</li><li>\r\n花瓣装饰</li></ul>', NULL, NULL, NULL, 'Active', '1700199668_Four-Season-Resort-Bali.webp', 14, 'https://www.fourseasons.com/sayan/', '2', '45', NULL, NULL, 'https://goo.gl/maps/kas9q9nH2abh7hVp8', NULL, NULL, NULL, NULL, '<span><b>Low Season, Shoulder Season and High Season</b>&nbsp;<i>(01 Apr - 31 May, 10 Oct - 20 Dec, 09 Jan - 31 Mar, 01 Jun - 09 Jul, 01 Sep - 09 Oct, 10 Jul - 31 Aug) :</i>&nbsp;</span><ul><li>Cancellations within 14 days prior to arrival will be subejct to a cancellation fee equal to one&nbsp;night\'s accommodation at the contracted rates, plus applicable taxes and service charge.</li></ul><span><b>Peak Season</b>&nbsp;<i>(21 Dec - 08 Jan) :&nbsp;</i></span><ul><li>Cancellations within 30 days prior to arrival will be subject to a full night\'s accommodation booked at the contracted rates, plus applicable taxes and service charge.</li></ul><b>No Show Policy :</b>&nbsp;<br><ul><li>A reservation is considered a no show if arrival does not occur on the date reserved. A fee equivalent on the full night\'s accommodation booked.&nbsp;</li></ul>', '<span>淡季、中間季節與旺季（4月1日 - 5月31日、10月10日 - 12月20日、1月9日 - 3月31日、6月1日 - 7月9日、9月1日 - 10月9日、7月10日 - 8月31日）：<br></span><ul><li>\r\n如在抵達日前14天內取消預訂，將收取等同於一晚住宿費（依合約價格計算）之取消費，另加相關稅金與服務費。</li></ul><span>尖峰季節（12月21日 - 1月8日）：<br></span><ul><li>\r\n如在抵達日前30天內取消預訂，將收取整筆已預訂住宿費（依合約價格計算）之取消費，另加相關稅金與服務費。</li></ul><span>未入住政策：<br></span><ul><li>\r\n若預訂當天未抵達，將視為未入住（No Show），並將收取整筆預訂住宿費作為費用。</li></ul>', '<span>淡季、肩季及旺季（4月1日 - 5月31日、10月10日 - 12月20日、1月9日 - 3月31日、6月1日 - 7月9日、9月1日 - 10月9日、7月10日 - 8月31日）：<br></span><ul><li>\r\n若在抵达日前14天内取消预订，将收取相当于一晚房费（按合同价）作为取消费用，另加适用税费和服务费。</li></ul><span>旺季（12月21日 - 1月8日）：<br></span><ul><li>\r\n若在抵达日前30天内取消预订，将收取全额已预订房费（按合同价）作为取消费用，另加适用税费和服务费。</li></ul><span>未入住政策：<br></span><ul><li>\r\n如在预订的抵达日期未入住，将视为“未入住”，并收取全额房费作为费用。</li></ul>', NULL, '2023-06-08 19:02:22', '2025-06-30 22:59:14', 1, 1),
(105, 'The Mulia, Mulia Resort & Villas', '17', NULL, NULL, NULL, 'cNAftqTZSsv3KL0hRyl5S84nrT', '17', NULL, 'Jl. Raya Nusa Dua Selatan, Kawasan Sawangan, Benoa Kec. Kuta Selatan Kab. Badung, Bali 80361', 1, 15, 'Yosua Putra', '03618467777', 'Discover Luxurious Accomodation in Nusa Dua <span>With 526 enchanting guest rooms and suites that are among the largest on the island, our opulent accommodation in Nusa Dua, Bali offers unparalleled comfort and style. Choose from uniquely designed hotel rooms, ideal for couples or families holidaying on the stunning Nusa Dua beachfront.<br><br>After a long day of exploring Bali, retreat to your room and indulge in our signature plush bedding, luxurious marble bathrooms and high-tech enhancements, all distinctly designed to pamper you. Relax on the spacious balcony as you dwell amongst the beauty of our tranquil surroundings and take in the refreshing sea breeze. Our accommodation options aim to provide unmatched relaxation for every guest of Mulia Resort.</span>', '<span>探索努沙杜瓦的奢華住宿<br>\r\n擁有526間迷人的客房與套房，我們在峇里島努沙杜瓦的豪華住宿是島上面積最大之一，提供無與倫比的舒適與風格。從獨具設計感的客房中挑選，無論是情侶或家庭，都能在美麗的努沙杜瓦海濱享受理想假期。</span>\r\n在探索峇里島一整天後，回到您的房間，沉浸於我們標誌性的柔軟寢具、奢華的大理石浴室與先進的科技設施中，這一切都為了寵愛您而設計。於寬敞的陽台上放鬆身心，沉醉於寧靜環境的美景與沁涼的海風。我們的住宿選擇旨在為每一位慕利雅度假村的賓客提供無與倫比的放鬆體驗。', '<span>探索努沙杜瓦的奢华住宿<br>\r\n拥有526间迷人的客房与套房，我们在巴厘岛努沙杜瓦的豪华住宿是岛上面积最大之一，提供无与伦比的舒适与风格。从独具设计感的客房中挑选，无论是情侣还是家庭，都能在美丽的努沙杜瓦海滨享受理想假期。</span>\r\n在探索巴厘岛一整天后，回到您的房间，沉浸于我们标志性的柔软寝具、奢华的大理石浴室与先进的科技设施中，这一切都为宠爱您而设计。在宽敞的阳台上放松身心，沉醉于宁静环境的美景与清新的海风。我们的住宿选项旨在为每一位穆丽雅度假村的宾客提供无与伦比的放松体验。', '<ul><li>Fitnesss Centre </li><li>ZJ\'s Bar, except during special event </li><li>Array of sport and leisure activities (details to be forwarded separately) </li><li>Mulia Kidz facility during normal operating hours</li><li>Internet access </li></ul>', '<ul><li>健身中心</li><li>\r\nZJ’s Bar（特殊活動期間除外）</li><li>\r\n多樣的運動與休閒活動（詳細資訊將另行提供）</li><li>\r\nMulia Kidz 兒童設施（於正常營業時間內開放）</li><li>\r\n網路連線服務</li></ul>', '<ul><li>健身中心</li><li>\r\nZJ’s Bar（特殊活动期间除外）</li><li>\r\n多样的运动与休闲活动（详细信息将另行提供）</li><li>\r\nMulia Kidz 儿童设施（在正常营业时间内开放）</li><li>\r\n网络连接服务</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1747963374_6703906162b2d23321fa1b0b_MRB - Courtyard View (1).webp', 14, 'www.themulia.com', '2', '360', NULL, NULL, 'https://goo.gl/maps/51KNCjTdLX49pD9M8', NULL, NULL, NULL, NULL, '<b>Regular Season : </b><ul><li>A cancellation fee equivalent up to two room nights for cancelation made less than 72 hours prior to arrival</li><li>A no show equivalent up to two nights will be charged for each room whereby booking will be cancelled immediately </li></ul><span><b>High Season </b><b>: </b></span><ul><li>A cancellation fee equivalent up to two room nights for cancellation made less than 14 hours prior to arrival </li><li>A no show fee equivalent to 50% of the total room nights or two nights whichever is greater will be charged for each room whereby booking will be cancelled immediately </li></ul><b>Peak Season</b><i> </i><b>: </b><ul><li>A cancellation within 30 days prior to arrival is charged the full length of stay </li><li>A no show fee equivalent to full length of stay </li></ul><b>Split Seasons : </b><ul><li>A cancellation that falls into two seasonality, its fee will be defined based on policy of whichever seasons that has greater and longer cancellation policy </li><li>A no show that falls into two seasonality, its fee will be defined based on policy of whichever seasons that has greater no show charges </li></ul>', '<span>一般季節：<br></span><ul><li>\r\n若於抵達前72小時內取消，將收取相當於最多兩晚房費的取消費。</li><li>\r\n若無人報到（No Show），將收取相當於最多兩晚房費的費用，並立即取消預訂。</li></ul><span>旺季：<br></span><ul><li>\r\n若於抵達前14小時內取消，將收取相當於最多兩晚房費的取消費。</li><li>\r\n若無人報到，將收取相當於50%總住宿晚數或兩晚房費（以較高者為準），並立即取消預訂。</li></ul><span>巔峰季節：<br></span><ul><li>\r\n若於抵達前30天內取消，將收取整段住宿期間的房費。</li><li>\r\n若無人報到，將收取整段住宿期間的房費。</li></ul><span>跨季節期間：<br></span><ul><li>\r\n若取消政策涉及兩個季節，將依據取消政策較嚴格及時間較長之季節計算取消費用。</li><li>\r\n若無人報到涉及兩個季節，將依據無人報到費用較高之季節計算費用。</li></ul>', '<span>普通季节：<br></span><ul><li>\r\n若在抵达前72小时内取消，将收取最多相当于两晚房费的取消费用。</li><li>若未入住（No Show），将收取最多相当于两晚房费的费用，并立即取消预订。</li></ul><span>高峰季节：<br></span><ul><li>\r\n若在抵达前14小时内取消，将收取最多相当于两晚房费的取消费用。</li><li>\r\n若未入住，将收取总住宿晚数的50%或两晚房费（以较高者为准），并立即取消预订。</li></ul><span>巅峰季节：<br></span><ul><li>\r\n若在抵达前30天内取消，将收取全程住宿费用。</li><li>\r\n若未入住，将收取全程住宿费用。</li></ul><span>跨季节期间：<br></span><ul><li>\r\n若取消时间跨越两个季节，将依据取消政策较严格和天数较长的季节为准收取费用。</li><li>若未入住跨越两个季节，将依照无入住费用较高的季节为准收取费用。</li></ul>', NULL, '2023-06-22 02:07:16', '2026-03-24 18:21:00', 1, 1),
(106, 'Katamaran Hotel & Resort Komodo', '17', NULL, NULL, NULL, 'qLsZeEptyHYbRGrc74qyVf7bYL', '17', NULL, 'Pantai Waecicu, Labuan Bajo, Kec. Komodo, Kabupaten Manggarai Barat, Nusa Tenggara Tim. 86554', 1, 3, 'Patrisius Baur', '08113820208', '<span style=\"color: rgb(51, 51, 51); font-family: \"Plus Jakarta Sans\", sans-serif; font-size: 14px; letter-spacing: 1px; text-align: justify;\">Luxury Redefined at Katamaran Hotel & Resort Komodo Your Exclusive 5-Star Escape in Labuan Bajo<br></span><span style=\"color: rgb(51, 51, 51); font-family: \"Plus Jakarta Sans\", sans-serif; font-size: 14px; letter-spacing: 1px; text-align: justify;\">Nestled in the breathtaking coastal paradise of Labuan Bajo, Katamaran Hotel & Resort Komodo is a 5-star sanctuary where luxury meets adventure. Whether you seek an exhilarating journey to Komodo National Park or a tranquil retreat by the turquoise waters of Flores, our resort offers the perfect blend of comfort, world-class service, and natural beauty.</span><span style=\"color: rgb(51, 51, 51); font-family: \"Plus Jakarta Sans\", sans-serif; font-size: 14px; letter-spacing: 1px; text-align: justify;\"></span>', '<p data-start=\"174\" data-end=\"218\"><strong data-start=\"174\" data-end=\"218\">卡塔馬蘭科莫多酒店與度假村，重新定義奢華<br data-start=\"196\" data-end=\"199\">\r\n您於拉布安巴佐的尊貴五星級度假天堂</strong></p>\r\n<p data-start=\"220\" data-end=\"349\">坐落於拉布安巴佐壯麗迷人的海岸天堂之中，卡塔馬蘭科莫多酒店與度假村是一處結合奢華與冒險的五星級度假勝地。無論您嚮往前往科莫多國家公園展開刺激探索之旅，或是在弗洛勒斯湛藍碧海旁享受寧靜悠閒的度假時光，本度假村皆為您呈獻舒適體驗、世界級服務與自然美景的完美融合。</p>', '<p data-start=\"389\" data-end=\"433\"><strong data-start=\"389\" data-end=\"433\">卡塔马兰科莫多酒店与度假村，重新定义奢华<br data-start=\"411\" data-end=\"414\">\r\n您在拉布安巴佐的专属五星级度假之选</strong></p>\r\n<p data-start=\"435\" data-end=\"564\">坐落于拉布安巴佐壮丽迷人的海岸天堂之中，卡塔马兰科莫多酒店与度假村是一处将奢华与探险完美结合的五星级度假胜地。无论您渴望前往科莫多国家公园展开精彩探险，或是在弗洛勒斯清澈碧蓝的海水旁享受宁静假期，本度假村都将为您呈现舒适体验、世界级服务与自然美景的完美融合。</p>', NULL, NULL, NULL, '<span><b>Seasonal Policy:</b> <br></span><ul><li>Unable to late check-out on 31 st December 2025 during peak period of New Year</li></ul><b>Honeymoon/Anniversary Benefit: </b><ul><li>1x Complimentary standard room decoration </li></ul><b>Birthday Benefit: </b><ul><li>1x Complimentary birthday cake </li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n於2025年12月31日跨年旺季期間無法延遲退房。</li></ul><span>蜜月／週年紀念禮遇：<br></span><ul><li>\r\n贈送一次標準房間佈置。</li></ul><span>生日禮遇：<br></span><ul><li>\r\n贈送一次生日蛋糕。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2025年12月31日跨年高峰期无法延迟退房。</li></ul>\r\n<span>蜜月／周年纪念礼遇：<br></span><ul><li>\r\n赠送一次标准房间布置。</li></ul><span>生日礼遇：<br></span><ul><li>\r\n赠送一次生日蛋糕。</li></ul>', NULL, NULL, NULL, 'Active', '1732245361_eeaa25469b4fdc8d3bf2df1a419f93ef.jpg', 14, 'https://katamaranresort.com/en/', '2', '360', NULL, NULL, '-8.412435798129431, 115.23868191534456', NULL, NULL, NULL, NULL, '<b>Low Season: </b><ul><li>0 - 7 days prior to arrival : The total amount of the reservation will be charged for the1st night of room charge</li><li>8 days or more prior to arrival : Free of charge </li></ul><b>High - Peak Season & Holiday:</b><ul><li>0 - 14 days prior to arrival : The total amount of the reservation will be charged for the 1 night of room charge </li><li>15 days or more prior to arrival : Free of charge </li></ul><b>No Show & Shortened Stay (Early Check-out) :</b> The total amount of the reservation will be charged <br>', '<span>淡季：<br></span><ul><li>\r\n抵達前 0 至 7 天內取消：將收取預訂總金額中第 1 晚的房費</li><li>\r\n抵達前 8 天或以上取消：免費取消</li></ul><span>旺季／尖峰季節及假期：<br></span><ul><li>\r\n抵達前 0 至 14 天內取消：將收取預訂總金額中第 1 晚的房費</li><li>\r\n抵達前 15 天或以上取消：免費取消</li></ul>未出現與縮短住宿（提前退房）：將收取預訂的全部金額', '<span>淡季：<br></span><ul><li>\r\n抵达前 0 至 7 天内取消：将收取预订总金额中第 1 晚的房费</li><li>\r\n抵达前 8 天或以上取消：免费取消</li></ul>\r\n<span>旺季／高峰季节及假期：<br></span><ul><li>\r\n抵达前 0 至 14 天内取消：将收取预订总金额中第 1 晚的房费</li><li>\r\n抵达前 15 天或以上取消：免费取消</li></ul><span>未入住及缩短住宿（提前退房）：<br></span><ul><li>\r\n将收取预订的全部金额</li></ul>', NULL, '2023-07-10 09:24:55', '2026-01-12 19:19:37', 1, 1),
(107, 'Lembongan Beach Club & Resort', '17', NULL, NULL, NULL, 'KCSPYfFeAaVwnMkTpgpY3tyz3A', '17', NULL, 'Jalan Jungut Batu Beach, Nusa Lembongan, Jungutbatu, Kec. Nusa Penida, Kabupaten Klungkung, Bali 87500', 1, 23, 'Mardian Putra', '082146425043', 'Indulge in the serene beauty of lembongan while staying at lembongan beach club &amp; resort, a 42 meticulously crafted balinese contemporary villas designed for couples, honeymooners, friends, and families. Each villa option, such as the one-bedroom garden villa, one bedroom private pool villa, and more, provides the ultimate escape ambiance for guests seeking a tranquil retreat.', '在藍夢島海灘俱樂部與度假村（Lembongan Beach Club &amp; Resort）沉浸於寧靜之美，度過悠然時光。這裡擁有42棟精心打造的巴厘當代風格別墅，特別適合情侶、新婚夫婦、朋友及家庭入住。各種別墅選擇，如一臥室花園別墅、一臥室私人泳池別墅等，為尋求靜謐度假的賓客提供絕佳的避世氛圍。', '在蓝梦岛海滩俱乐部与度假村（Lembongan Beach Club &amp; Resort）尽情享受宁静之美，度过惬意时光。这里拥有42栋精心打造的巴厘岛当代风格别墅，非常适合情侣、蜜月夫妻、朋友和家庭入住。各类别墅选择，如一卧室花园别墅、一卧室私人泳池别墅等，为寻求宁静度假的宾客营造理想的避世氛围。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Minimum stay 3 nights during peak season NY Eve (27 Dec - 05 Jan)</li><li>Compulsory New Year Dinner on 31 Dec 2025 (Price at additional charge)&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n跨年巔峰季期間（12月27日 - 1月5日）最少需入住3晚</li><li>\r\n2025年12月31日須參加強制性跨年晚宴（費用另計）</li></ul>', '季节性政策：<br><ul><li>\r\n跨年高峰季期间（12月27日 - 1月5日）最低入住3晚</li><li>\r\n2025年12月31日需参加强制性跨年晚宴（价格另计）</li></ul>', NULL, NULL, NULL, 'Active', '1737337345_Cover.jpeg', 14, 'https://lembonganbeachclubandresort.com/', '2', '45', NULL, NULL, 'https://goo.gl/maps/wTLz7fDqMp4WQdws9', NULL, NULL, NULL, NULL, '<b>Regular Season</b> <i>(01 Apr - 30 Jun, 01 Sep - 22 Dec, 06 Jan - 31 Mar) :&nbsp;</i><ul><li>Cancellation made within 60 - 22 days to arrival : 30% from the total booking or 1 night charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 30% from the total booking or 1 night charge</li><li>Cancellation made within 14 - 8 days to arrival : 50% from the total booking or full charge for booking 1 night&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><b>High Season</b><i> (01 Jul - 31 Aug, 23 - 26 Dec) :&nbsp;</i><ul><li>Cancellation made within 60 - 22 days to arrival : 01 night charge</li><li>Cancellation made within 21 - 15 days to arrival : 50% of total length of stay</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul><b>Peak Season</b> <i>(27 Dec - 05 Jan) :&nbsp;</i><ul><li>Cancellation made within 60 - 22 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 21 - 15 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 14 - 8 days to arrival : 100% of total booked charge&nbsp;</li><li>Cancellation made within 7 - 1 days to arrival : 100% of total booked charge&nbsp;</li><li>No Show : 100% of total booked charge&nbsp;</li></ul>', '平季（4月1日 - 6月30日、9月1日 - 12月22日、1月6日 - 3月31日）：\r\n<ul>\r\n<li>\r\n抵達前 60 至 22 天取消：將收取總預訂金額的 30% 或一晚房費\r\n</li>\r\n<li>\r\n抵達前 21 至 15 天取消：將收取總預訂金額的 30% 或一晚房費\r\n</li>\r\n<li>\r\n抵達前 14 至 8 天取消：將收取總預訂金額的 50% 或預訂僅1晚則全額收費\r\n</li>\r\n<li>\r\n抵達前 7 至 1 天取消：收取預訂總金額的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取預訂總金額的 100%\r\n</li>\r\n</ul>\r\n旺季（7月1日 - 8月31日、12月23日 - 12月26日）：\r\n<ul>\r\n<li>\r\n抵達前 60 至 22 天取消：收取一晚房費\r\n</li>\r\n<li>\r\n抵達前 21 至 15 天取消：收取總住宿期間的 50%\r\n</li>\r\n<li>\r\n抵達前 14 至 8 天取消：收取預訂總金額的 100%\r\n</li>\r\n<li>\r\n抵達前 7 至 1 天取消：收取預訂總金額的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取預訂總金額的 100%\r\n</li>\r\n</ul>\r\n巔峰季（12月27日 - 1月5日）：\r\n<ul>\r\n<li>\r\n抵達前 60 至 22 天取消：收取預訂總金額的 100%\r\n</li>\r\n<li>\r\n抵達前 21 至 15 天取消：收取預訂總金額的 100%\r\n</li>\r\n<li>\r\n抵達前 14 至 8 天取消：收取預訂總金額的 100%\r\n</li>\r\n<li>\r\n抵達前 7 至 1 天取消：收取預訂總金額的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取預訂總金額的 100%</li></ul>', '平季（4月1日 - 6月30日、9月1日 - 12月22日、1月6日 - 3月31日）：\r\n<ul>\r\n<li>\r\n抵达前 60 至 22 天取消：收取总预订金额的 30% 或一晚房费\r\n</li>\r\n<li>\r\n抵达前 21 至 15 天取消：收取总预订金额的 30% 或一晚房费\r\n</li>\r\n<li>\r\n抵达前 14 至 8 天取消：收取总预订金额的 50% 或若仅预订1晚则收取全额\r\n</li>\r\n<li>\r\n抵达前 7 至 1 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的 100%\r\n</li>\r\n</ul>\r\n旺季（7月1日 - 8月31日、12月23日 - 12月26日）：\r\n<ul>\r\n<li>\r\n抵达前 60 至 22 天取消：收取一晚房费\r\n</li>\r\n<li>\r\n抵达前 21 至 15 天取消：收取总住宿天数的 50%\r\n</li>\r\n<li>\r\n抵达前 14 至 8 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 7 至 1 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的 100%\r\n</li>\r\n</ul>\r\n巅峰季（12月27日 - 1月5日）：\r\n<ul>\r\n<li>\r\n抵达前 60 至 22 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 21 至 15 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 14 至 8 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n抵达前 7 至 1 天取消：收取总预订金额的 100%\r\n</li>\r\n<li>\r\n未入住（No Show）：收取总预订金额的 100%</li></ul>', NULL, '2023-08-13 18:40:53', '2025-07-01 00:21:24', 1, 1),
(108, 'Four Seasons Resort Bali at Jimbaran', '17', NULL, NULL, NULL, 'BL1Szj6Pg8BMTVJTO2G8yhX2UR', '17', NULL, 'Jimbaran, South Kuta, Badung Regency, Bali 80361', 2, 10, 'Elis Tanthra', '0361701010', 'Become one with Bali’s magical energy and gentle nature. Sheltered in a calm bay along three miles of sand, our breezy villas channel an authentic Balinese village. Together with unforgettable views and authentic arts offerings, we bring you a deeper understanding of the island’s stunning landscapes and inimitable culture.', '與峇里島神奇的能量與溫柔的自然融為一體。坐落於三英里長沙灘的寧靜海灣中，我們通風的別墅傳遞著正宗的峇里島村莊氛圍。結合令人難忘的景緻與地道的藝術體驗，我們為您帶來對島嶼壯麗景觀與獨特文化更深層的理解。', '与巴厘岛神奇的能量与温柔的自然融为一体。坐落于三英里长的沙滩宁静海湾中，我们通风的别墅传达着地道的巴厘岛村庄氛围。结合令人难忘的美景与地道的艺术体验，我们为您带来对这座岛屿壮丽风景与独特文化更深层的理解。', '<ul><li>Complimentary Premium WI-FI&nbsp;</li><li>Watersports&nbsp;</li><li>SPA&nbsp;</li><li>24- Hour in- Rooom Dining&nbsp;</li><li>Multilingual Concierges&nbsp;</li><li>Family Friendly&nbsp;</li><li>Luxury Bath Products&nbsp;</li><li>Fitnes Centre&nbsp;</li></ul>', '<ul><li>免費高級 Wi-Fi</li><li>\r\n水上運動</li><li>\r\n水療中心</li><li>\r\n24 小時客房餐飲服務</li><li>\r\n多語言禮賓服務</li><li>\r\n親子友善</li><li>\r\n奢華沐浴用品</li><li>\r\n健身中心</li></ul>', '<ul><li>免费高级 Wi-Fi</li><li>\r\n水上运动</li><li>\r\n水疗中心</li><li>\r\n24 小时客房送餐服务</li><li>\r\n多语言礼宾服务</li><li>\r\n亲子友好</li><li>\r\n奢华沐浴用品</li><li>\r\n健身中心</li></ul>', '<b>Children Policy:&nbsp;<br></b><ul><li>One extra bed (not including breakfast) will be given complimentary for a child below 18 years old (17.99 years old) sharing a bedroom with parents&nbsp;</li><li>Maximum 2 children can share a bedroom with parents with one (1) additional extra bed&nbsp;</li></ul><b>Honeymooners will get the following benefits :&nbsp;</b><ul><li>Tropical flower bouquet upon arrival&nbsp;</li><li>Honeymoon sweets</li><li>Flower petals arrangement&nbsp;</li></ul>', '<span>兒童政策：<br></span><ul><li>\r\n與父母同住的未滿18歲（17.99歲以下）兒童可免費提供一張加床（不含早餐）</li><li>最多可有2位兒童與父母同住，僅提供一（1）張加床</li></ul>蜜月禮遇：\r\n<ul>\r\n<li>\r\n抵達時贈送熱帶花束\r\n</li>\r\n<li>\r\n蜜月甜點\r\n</li>\r\n<li>\r\n花瓣裝飾佈置</li></ul>', '<span>儿童政策：<br></span><ul><li>\r\n与父母同住的未满18岁（17.99岁以下）儿童可免费提供一张加床（不含早餐）</li><li>\r\n最多允许2位儿童与父母同住，仅提供一（1）张加床</li></ul>蜜月礼遇：\r\n<ul>\r\n<li>\r\n抵达时赠送热带花束\r\n</li>\r\n<li>\r\n蜜月甜点\r\n</li>\r\n<li>\r\n花瓣装饰布置</li></ul>', NULL, NULL, NULL, 'Active', '1700199958_Four-Season-Resort-Jimbaran.webp', 14, 'https://www.fourseasons.com/jimbaranbay/', '2', '45', NULL, NULL, 'https://goo.gl/maps/GYkjEoycyqztFWmo8', NULL, NULL, NULL, NULL, '<span><b>Low Season, Shoulder Season and High Season</b>&nbsp;<i>(01 Apr - 31 May, 10 Oct - 20 Dec, 09 Jan - 31 Mar, 01 Jun - 09 Jul, 01 Sep - 09 Oct, 10 Jul - 31 Aug) :</i>&nbsp;</span><ul><li>Cancellations within 14 days prior to arrival will be subejct to a cancellation fee equal to one&nbsp;night\'s accommodation at the contracted rates, plus applicable taxes and service charge.</li></ul><span><b>Peak Season</b> <i>(21 Dec - 08 Jan) :&nbsp;</i></span><ul><li>Cancellations within 30 days prior to arrival will be subject to a full night\'s accommodation booked at the contracted rates, plus applicable taxes and service charge.</li></ul><b>No Show Policy :</b>&nbsp;<br><ul><li>A reservation is considered a no show if arrival does not occur on the date reserved. A fee equivalent on the full night\'s accommodation booked.&nbsp;</li></ul>', '<span>淡季、肩季與旺季（4月1日－5月31日、10月10日－12月20日、1月9日－3月31日、6月1日－7月9日、9月1日－10月9日、7月10日－8月31日）：<br></span><ul><li>\r\n於入住前14天內取消預訂，將收取相當於一晚住宿費用（依照合約價格計算）及適用的稅金與服務費。</li></ul><span>巔峰季節（12月21日－1月8日）：<br></span><ul><li>\r\n於入住前30天內取消預訂，將收取全部預訂住宿之費用（依照合約價格計算）及適用的稅金與服務費。</li></ul><span>未到政策：<br></span><ul><li>\r\n若客人於預訂日期當天未入住，則視為未到，將收取預訂總住宿晚數之費用。</li></ul>', '<span>淡季、肩季和旺季（4月1日－5月31日、10月10日－12月20日、1月9日－3月31日、6月1日－7月9日、9月1日－10月9日、7月10日－8月31日）：<br></span><ul><li>\r\n在抵达日期前14天内取消预订，将收取一晚住宿的取消费用（按合同价计算），另加适用税费和服务费。</li></ul><span>高峰季节（12月21日－1月8日）：<br></span><ul><li>\r\n在抵达日期前30天内取消预订，将收取全部预订住宿的费用（按合同价计算），另加适用税费和服务费。</li></ul><span>未到政策：<br></span><ul><li>\r\n若未在预订日期当天办理入住，将视为未到，并收取全部预订住宿的费用。</li></ul>', NULL, '2023-09-06 20:02:08', '2025-07-01 18:02:54', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(109, 'Hoshinoya Bali', '17', NULL, NULL, NULL, 'Yx2wQ8MFwmg7DhcKVL5c57BRDQ', '17', NULL, 'Br. Pengembungan, Pejeng Kangin, Tampaksiring, Pejeng Kangin, Kec. Tampaksiring, Kabupaten Gianyar, Bali 80552', 3, 48, 'Hoshinoya Bali', '03618493080', 'Take a deep breath and you will feel the purity of the air born from the splendor of the Ubud forest fill your body. Bali has a religious belief in Hindu Dharma, a combination of Hindu teachings and animism that has long been rooted in the lives of the Dewata people. As part of a society that maintains harmony between humans, nature and the Creator, HOSHINOYA Bali every morning gives flower offerings as an expression of gratitude to Yang Almighty. At night you will hear the sound of gamelan which will give you awareness of the presence of the Creator as your body receives energy from nature. Gradually you will feel inner calm.', '深吸一口氣，您會感受到烏布森林壯麗景致所孕育的純淨空氣充滿全身。峇里島信仰印度達摩教（Hindu Dharma），這是印度教教義與泛靈信仰的結合，早已深植於「神之島」人民的生活中。作為一個維持人、自然與神明和諧共處的社會的一部分，HOSHINOYA Bali 每天清晨都會獻上鮮花供奉，以表達對萬物之主的感恩。夜晚時分，您將聽見伽美蘭的樂聲，喚起您對造物主存在的感知，同時身體也將從大自然中獲得能量。漸漸地，您將感受到內心的平靜。', '深吸一口气，您会感受到乌布森林壮丽景色中孕育的纯净空气充满全身。巴厘岛信奉印度达摩教（Hindu Dharma），这是印度教教义与泛灵信仰的结合，早已深植于神之岛人民的生活中。作为一个维持人与自然及造物主之间和谐共处的社会一员，HOSHINOYA Bali 每天清晨都会献上花朵供奉，以表达对万物之主的感恩。夜晚，您将听见伽美兰乐声，让您意识到造物主的存在，同时身体也从大自然中汲取能量。渐渐地，您会感受到内在的平静。', '<ul><li>SPA</li><li>Pool</li></ul>', '<ul><li>SPA</li><li>\r\n游泳池</li></ul>', '<ul><li>SPA</li><li>\r\n游泳池</li></ul>', '<b>Child Policy :&nbsp;</b><ul><li>Bed sharing with children from 3 to 11 years old no extra person charge applies&nbsp;</li><li>For children under 12. bed sharing is available up to the maximum occupancy&nbsp;</li><li>Children over 12 years old and above : Adult meal rates apply&nbsp;</li><li>Every child must be mentioned upon reservation&nbsp;</li></ul>', '兒童政策：<br><ul><li>\r\n3 至 11 歲兒童共用床位者，不收取額外人數費用。</li><li>\r\n12 歲以下兒童可共用床位，但須遵守最大入住人數限制。</li><li>\r\n12 歲及以上兒童：適用成人餐食費用。</li><li>\r\n每位兒童皆須於預訂時註明。</li></ul>', '儿童政策：<br><ul><li>\r\n3 至 11 岁儿童同床入住，不收取额外人数费用。</li><li>\r\n12 岁以下儿童可同床入住，须遵守最大入住人数限制。</li><li>\r\n12 岁及以上儿童：按成人餐食收费。</li><li>\r\n每位儿童须在预订时注明。</li></ul>', NULL, NULL, NULL, 'Active', '1759196056_Hoshonoya.jpg', 2, 'https://hoshinoya.com/bali/id/', '2', '45', NULL, NULL, 'https://goo.gl/maps/doU77jMV7kXgCwGNA', NULL, NULL, NULL, NULL, '<ul><li>First one night will be charged for cancellation made within 21 days prior to guest\'s arrival date.&nbsp;</li><li>100% cancellation charge of full Company contracted rate for cancellation made 3 days or less prior to guest\'s arrival date.</li><li>A reservation is considered \"no show\" if arrival does not occur on the date reserved and the hotel is not notified of any emergency delays in writing.</li></ul>', '<ul><li>如於入住日前21天內取消，將收取第一晚房費作為取消費用。</li><li>\r\n如於入住日前3天或更短時間內取消，將收取全額公司合約價格的100%作為取消費用。</li><li>\r\n若賓客未於預訂日期入住，且飯店未收到任何書面緊急延遲通知，該預訂將視為「未出現（No Show）」。</li></ul>', '<ul><li>如在入住日期前21天内取消，将收取首晚房费作为取消费用。</li><li>\r\n如在入住日期前3天或更短时间内取消，将收取公司合同价的100%作为取消费用。</li><li>\r\n若客人未在预定日期抵达且酒店未收到任何书面紧急延误通知，则该预订将被视为“未到店（No Show）”。</li></ul>', NULL, '2023-09-13 21:01:52', '2025-09-29 17:34:16', 2, 1),
(110, 'Desa Visesa Ubud', '17', 'Ubud', 'Bali', 'Indonesia', 'jeV8isBzNql83p913Mf8Q0soqs', '17', 17, 'Jalan Juwuk Manis, Ubud, Bali, Indonesia', 3, 40, 'Andi Syahputra', '03612091788', 'Our accommodations are meticulously designed in keeping with the Balinese Hindu philosophy of Tri Hita Karana (harmony between Gods, human beings and nature).The traditional aesthetics are evident from the moment you step to our village. A journey of exploring the island’s culture, nature and spiritual nuance through respectful interactions with the local community with a comprehensive array of experiences that are based on traditional heritage and ceremonial way of life.', '我們的住宿設計精心體現巴厘島印度教「三和理念」（Tri Hita Karana）——神、人與自然之間的和諧。從您踏入我們村莊的那一刻起，傳統美學便隨處可見。這是一段探索島嶼文化、自然與精神氛圍的旅程，透過與當地社區的尊重互動，提供一系列根植於傳統遺產與儀式生活方式的體驗。', '我们的住宿精心设计，体现了巴厘岛印度教的“三和理念”（Tri Hita Karana）——神、人类与自然之间的和谐。从您踏入我们村庄的那一刻起，传统美学便可见一斑。这是一段探索岛屿文化、自然与精神氛围的旅程，通过与当地社区的尊重互动，提供一系列基于传统遗产和仪式生活方式的体验。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>No check in and check out at 31 December&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月31日不接受辦理入住與退房。</li></ul>', '季节性政策：<br><ul><li>\r\n12月31日不接受办理入住与退房。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1700200073_Desa-Visesa-Ubud.webp', 14, 'https://visesaubud.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Visesa+Ubud+Resort/@-8.490227,115.2624875,17z/data=!4m9!3m8!1s0x2dd23d4bb923195d:0xfd5fabcae2ec446!5m2!4m1!1i2!8m2!3d-8.4902323!4d115.2650624!16s%2Fg%2F11bz__nmq7?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.4900259, 115.2642126, NULL, NULL, '<span><b>Regular Season</b><i> (01 Apr - 30 Jun, 01 Sep - 19 Dec, 06 Jan - 31 Mar):&nbsp;</i></span><ul><li>&lt; 7 Days : 1 Room Nights Charge&nbsp;</li><li>&lt; 72 Hours / No Show : 100% Charge&nbsp;</li></ul><span><b>High &amp; Peak Season</b> <i>(01 Jul - 31 Aug &amp; 20 Dec - 05 Jan):&nbsp;</i></span><ul><li>&lt; 30 Days : 1 Room Nights Charge&nbsp;</li><li>&lt; 14 Days : 100% Charge&nbsp;</li></ul>', '一般季節（4月1日 - 6月30日、9月1日 - 12月19日、1月6日 - 3月31日）：\r\n<ul>\r\n<li>\r\n少於7天取消：收取1晚房費\r\n</li>\r\n<li>\r\n少於72小時 / 未入住：收取100%房費\r\n</li>\r\n</ul>\r\n旺季與尖峰季節（7月1日 - 8月31日 &amp; 12月20日 - 1月5日）：\r\n<ul>\r\n<li>\r\n少於30天取消：收取1晚房費\r\n</li>\r\n<li>\r\n少於14天取消：收取100%房費</li></ul>', '常规季节（4月1日 - 6月30日、9月1日 - 12月19日、1月6日 - 3月31日）：\r\n<ul>\r\n<li>\r\n少于7天取消：收取1晚房费\r\n</li>\r\n<li>\r\n少于72小时 / 未入住：收取100%房费\r\n</li>\r\n</ul>\r\n旺季与高峰季节（7月1日 - 8月31日 &amp; 12月20日 - 1月5日）：\r\n<ul>\r\n<li>\r\n少于30天取消：收取1晚房费\r\n</li>\r\n<li>\r\n少于14天取消：收取100%房费</li></ul>', NULL, '2023-09-14 00:11:31', '2026-03-25 19:37:21', 1, 2),
(111, 'Pramana Watu Kurung', '17', NULL, NULL, NULL, 'gezBkEePyzYW9DIL39M077R90P', '17', NULL, 'Jalan Batu Kurung II, Ubud, Bali, Indonesia', 2, 39, 'Ratni', '0361981799', '<p>Pramana Watu Kurung is part of a Balinese village on the outskirts of Ubud and as a result of this unique location, activities for in-house guests are influenced by local art and culture. From classes teaching how to make temple offerings to mastering the graceful movements of traditional dance and learning to cook Balinese cuisine, there is something for just about everyone.</p>', NULL, NULL, '<p>Internet Wi-Fi access in the room and public area&nbsp;</p>', NULL, NULL, '<p><strong>Honeymoon Benefit:&nbsp;</strong></p><ol><li>Simple flower decoration on bed on arrival&nbsp;</li><li>Honeymoon cake&nbsp;</li><li>Double Bed guaranteed</li></ol><p><strong>Special Offer:</strong></p><ol><li>Stay minimum 3 Nights on selected room type get 1 time for 1 Hour Spa Treatment Balinese Massage for a Couple&nbsp;</li><li>Stay minimum 6 Nights on selected room type get 1 time for set lunch for a Couple&nbsp;</li></ol>', NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1731997219_img-artist-village-by-pramana-watu-kurung-ubud-bali-1.webp', 2, 'https://www.pramanawatukurung.com', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Pramana+Watu+Kurung/@-8.4711725,115.2426653,17z/data=!4m10!3m9!1s0x2dd222db87d85c11:0x1ca837ea53457269!5m3!1s2026-03-25!4m1!1i2!8m2!3d-8.4711778!4d115.2452402!16s%2Fg%2F11g01w1c34?entry=ttu&g_ep=EgoyMDI2MDMyMi4wIKXMDSoASAFQAw%3D%3D', -8.4713323, 115.2447249, NULL, NULL, '<p><strong>Low Season:&nbsp;</strong></p><ol><li>Cancellation 30 days prior to arrival: One (1) night accommodation charge&nbsp;</li><li>Cancellation 14 days prior to arrival: Entire stay accommodation charge&nbsp;</li></ol><p><strong>High/Peak Season</strong> <em>(01 Jul - 31 Aug &amp; 20 Dec - 07 Jan):&nbsp;</em></p><ol><li>Cancellation 45 days prior to arrival: One (1) night accommodation charge&nbsp;</li><li>Cancellation 21 days prior to arrival: Entire stay accommodation charge&nbsp;</li></ol><p><strong>No Show:</strong> Deposit will be automatically forfeited&nbsp;</p><p><strong>Seasonal Policy:&nbsp;</strong></p><p>Check out is not allowed on 31 Dec&nbsp;</p>', NULL, NULL, NULL, '2023-09-15 02:59:13', '2026-03-25 01:28:36', 2, 2),
(112, 'The Sun of Granary Resort & Villas', '17', NULL, NULL, NULL, '1t1Z1KpzipLJfr2NUP1Dhmx6g8', '17', NULL, 'Banjar Pinjul, Kenderan, Kec. Tegallalang, Kabupaten Gianyar, Bali 80561', 2, 47, 'Ni Made Ponianti', '03619089028', 'The Sun of Granary Resort and Villas presents “an escape to paradise” in the traditional village of Kenderan, Tegallalang, a part of Ubud region. With locally inspired experiences set against the lush greenery of Tegallalang, the resort takes you closer to the heart and soul of Ubud. Complemented by the surrounding lavish scenery and tranquil ambience, The Sun of Granary Resort and Villas truly lives up to its name. We welcome you on a journey to feel fully connected with nature.<br>Encompassing a collection of 24 Balinese stylishly appointed rooms and villas, The Sun of Granary Resort and Villas was designed with a focus to discover the simple pleasures in an idyllic haven. It is a place to unwind and drown into the peacefulness of scenic greenery. A million miles away from the daily hustle and bustle; we invite you to feel the true spirit of Balinese hospitality and get a chance to reconnect with family and friends in your own private sanctuary at The Sun of Granary Ubud Resort and Villas, where excitement and action are never far away.', 'The Sun of Granary Resort and Villas 座落於烏布地區的德哥拉朗肯德蘭傳統村莊，呈獻一場「通往天堂的逃逸之旅」。以在地文化為靈感，融合德哥拉朗鬱鬱蔥蔥的綠意，度假村將您帶往烏布的心靈與靈魂深處。在周圍奢華景致與寧靜氛圍的襯托下，The Sun of Granary Resort and Villas 名副其實。我們誠摯邀請您踏上一段與大自然深度連結的旅程。\r\nThe Sun of Granary Resort and Villas 擁有24間富有峇里風格的精緻客房與別墅，設計理念著重於在這片理想的世外桃源中發現生活的純粹樂趣。這裡是放鬆身心、沉浸於綠意與靜謐之中的理想之地。遠離日常的喧囂與忙碌，我們邀您在 The Sun of Granary Ubud Resort and Villas 私密的避世天堂中，重新連結摯親好友，體驗真正的峇里式款待，而精彩與動感永遠不會太遙遠。', 'The Sun of Granary Resort and Villas 坐落于乌布地区德哥拉朗的肯德兰传统村庄，呈现一场“通往天堂的逃逸之旅”。结合当地文化灵感与德哥拉朗郁郁葱葱的绿意，度假村将您带入乌布的心灵与灵魂深处。在周围奢华的自然景观与宁静氛围的映衬下，The Sun of Granary Resort and Villas 实至名归。我们诚邀您踏上一段与大自然深度连接的旅程。\r\nThe Sun of Granary Resort and Villas 拥有24间极具巴厘风格的精致客房与别墅，设计理念旨在于这片世外桃源中寻找简单的幸福。这是一个放松自我、沉浸于绿意与宁静之中的理想之地。远离日常的喧嚣与忙碌，我们诚邀您在 The Sun of Granary Ubud Resort and Villas 私人避世天堂中，重新连接家人与朋友，感受地道的巴厘式热情好客，而精彩与活力也从不遥远。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><br><ul><li>No Check In and Check Out on - seclusion day (Nyepi Day)&nbsp;</li></ul><b></b><b>Child Policy:&nbsp;<br></b><ul><li>Children between 0 – 3 years of age can share the bed with parents with no surcharge.</li><li>Children over 11 years of age will be charged as an adult.&nbsp;</li><li>Baby cots shall be supplied free of charge and must be requested at the time of reservation</li></ul><b>Honeymoon Benefits:&nbsp;</b><br><ul><li>Honeymoon benefits available based on request (flower decoration on the bed &amp; cake)</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n靜居日（Nyepi Day）當天不接受入住與退房。</li></ul><span>兒童政策：<br></span><ul><li>\r\n0至3歲的兒童可與父母同床，不收取額外費用。</li><li>11歲以上的兒童將以成人計價。</li><li>嬰兒床可免費提供，須於預訂時提出申請。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n蜜月禮遇可依要求提供（床上花卉裝飾與蛋糕）。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n在寂静日（Nyepi Day）当天不接受入住和退房。</li></ul><span>儿童政策：<br></span><ul><li>\r\n0至3岁的儿童可与父母同床，不收取额外费用。</li><li>11岁以上的儿童将按成人计费。</li><li>婴儿床可免费提供，须在预订时提出申请。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n蜜月礼遇可根据要求提供（床上花卉装饰与蛋糕）。</li></ul>', NULL, NULL, NULL, 'Active', '1747963860_Photo-gallery_drone-view1_facilities.webp', 14, 'https://www.thesunofgranaryubud.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/GX7yyUu9MEQekUqS8', NULL, NULL, NULL, NULL, '<b>Low Season:</b> <i>01 Apr - 30 Jun, 01 Sep - 23 Dec, 06 Jan - 31 Mar&nbsp;</i><br><b>High Season:</b> <i>01 Jul - 31 Aug&nbsp;</i><br><b>Peak Season:</b> <i>24 Dec - 05 Jan&nbsp;</i><br><ul><li>Prior to 7 days for the normal season and 14 days for the high and peak season, no penalty fee&nbsp;</li><li>Within 7 days for the normal season and 14 days for the high and peak season, any cancellation is subject to the first night of accommodation at your daily contracted room rate for each room booked&nbsp;</li><li>Any amendment after check in or no show will be 100% charged according to the initial reservation amount&nbsp;</li></ul>', '<span>淡季：4月1日－6月30日、9月1日－12月23日、1月6日－3月31日<br>\r\n旺季：7月1日－8月31日<br>\r\n巔峰季：12月24日－1月5日</span>\r\n<br><ul><li>若在淡季入住前7天、或旺季與巔峰季入住前14天取消，則不收取任何費用。</li><li>若在淡季入住前7天內、或旺季與巔峰季入住前14天內取消，則每間已預訂房間將收取每日合約房價的首晚費用作為取消費用。</li><li>如在入住後更改預訂，或未入住（No Show），將按原始預訂金額收取100%費用。</li></ul>', '<span>淡季：4月1日－6月30日、9月1日－12月23日、1月6日－3月31日<br>\r\n旺季：7月1日－8月31日<br>\r\n巅峰季：12月24日－1月5日</span>\r\n<br><ul><li>若在淡季入住前7天、或旺季和巅峰季入住前14天取消，将不收取任何费用。</li><li>若在淡季入住前7天内、或旺季和巅峰季入住前14天内取消，则每间已预订房间将收取每日合同房价的首晚作为取消费用。</li><li>如入住后更改预订，或未入住（No Show），将按原始预订金额收取100%费用。</li></ul>', NULL, '2023-09-22 01:38:35', '2025-07-07 19:20:21', 1, 1),
(113, 'Raffles Bali', '17', NULL, NULL, NULL, 'hGmdmsqDUUUY7GVZiIvNvSoYb8', '17', NULL, 'Jl. Karang Mas Sejahtera No.1A, Jimbaran, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 10, 'Bernadet Debby GALISTA', '03612015800', '<div><span style=\"font-size: 14.4px; text-transform: uppercase;\">Your secluded haven in Bali</span></div><div><span style=\"font-size: 14.4px; text-transform: uppercase;\"><br></span></div><div><span style=\"font-size: 14.4px; text-transform: uppercase;\">Cascading down the hillside towards the Indian Ocean, Raffles Bali is the ultimate in refined barefoot luxury. Our 32 villas, each with its own pool and garden, offer peace and privacy to soothe the soul, with views across Jimbaran Bay that seem to go on forever.</span></div>', '<p data-start=\"65\" data-end=\"79\"><strong data-start=\"65\" data-end=\"79\">您在峇里島的隱世天堂</strong></p><p>\r\n</p><p data-start=\"81\" data-end=\"195\">Raffles Bali 坐落於層層山坡之上，向著印度洋緩緩延伸，呈現極致精緻的赤足奢華體驗。度假村擁有 32 棟別墅，每棟皆配備私人泳池與花園，營造寧靜私密的氛圍，撫慰身心靈。俯瞰金巴蘭灣的壯麗景色，視野遼闊，彷彿延伸至天際。</p>', '<p data-start=\"235\" data-end=\"249\"><strong data-start=\"235\" data-end=\"249\">您在巴厘岛的隐秘天堂</strong></p><p>\r\n</p><p data-start=\"251\" data-end=\"354\">Raffles Bali 依山而建，层层延伸至印度洋，呈现极致精致的赤足奢华体验。度假村设有 32 栋别墅，每栋均配备私人泳池与花园，私密宁静，抚慰身心灵。俯瞰金巴兰湾的壮丽景色，视野无垠，仿佛延伸至天际。</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1765851188_aja_p_6160-12.webp', 14, 'https://www.raffles.com/bali', '2', '360', NULL, NULL, 'https://maps.app.goo.gl/E2wHEjPyJsigE3ht5', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-11-16 21:22:22', '2026-03-24 18:21:00', 1, 1),
(114, 'Swiss-Belhotel Tuban', '17', NULL, NULL, NULL, 'WVJhSdS3yYBVQCCHE4jG9E6mGW', '17', NULL, 'Jalan Kubu Anyar No. 31, Kuta, Bali , Indonesia', 1, 2, 'Yeni', '03616200581', 'Swiss-Belhotel Tuban is located in the world-class main tourist destination of Kuta. Swiss-Belhotel Tuban is a four-star hotel that offers affordable luxury with a harmonious blend of Balinese characteristics, offering an unforgettable holiday experience on the Island of the Gods. The perfect place for a romantic weekend or holiday with the family or business activities, this hotel is located in a strategic location with easy access to entertainment venues, nightlife venues and restaurants in Kuta, only 15 minutes walk! Or, you can use the free shuttle facility from the hotel to Discovery Shopping Mall.', 'Swiss-Belhotel Tuban 位於世界級旅遊勝地庫塔的核心地段，是一家結合峇里特色的四星級酒店，提供兼具實惠與奢華的住宿體驗，為您在這座「眾神之島」帶來難忘的假期。不論是浪漫週末、家庭度假，或是商務活動，這裡都是理想之選。酒店地理位置優越，步行15分鐘即可輕鬆抵達庫塔的娛樂場所、夜生活熱點與各式餐廳！此外，酒店還提供前往 Discovery 購物中心的免費接駁服務。', 'Swiss-Belhotel Tuban 位于世界级旅游胜地库塔的核心地段，是一家融合巴厘特色的四星级酒店，提供兼具实惠与奢华的住宿体验，为您在这座“众神之岛”带来难忘的假期。无论是浪漫周末、家庭度假，还是商务活动，这里都是理想之选。酒店地理位置优越，步行15分钟即可轻松到达库塔的娱乐场所、夜生活热点和各类餐厅！此外，酒店还提供前往 Discovery 购物中心的免费接驳服务。', '<ul><li>Swiss-Cafe™ Restaurant</li><li>Bale Sunset Lounge</li><li>Lila Bar</li><li>Samuan Meeting Room</li><li>Gyms</li><li>Swimming pool measuring 11x25.7m</li><li>Children\'s swimming pool</li><li>Flexible room configuration</li><li>Lobby and Porte-cochere</li><li>Free parking area</li><li>CCTV and 24 hour security</li><li>Luggage space</li><li>Airport Transportation</li><li>Free pick-up and drop-off to Discovery Shopping Mall</li><li>Wi-Fi internet access</li><li>Laundry service</li></ul>', '<ul><li>Swiss-Cafe™ 餐廳</li><li>\r\nBale Sunset 日落酒廊</li><li>\r\nLila 酒吧</li><li>\r\nSamuan 會議室</li><li>\r\n健身房</li><li>\r\n11x25.7 公尺游泳池</li><li>\r\n兒童游泳池</li><li>\r\n靈活的房型配置</li><li>\r\n大廳與車道門廊</li><li>\r\n免費停車區</li><li>\r\nCCTV 監控與 24 小時保全</li><li>\r\n行李寄放區</li><li>\r\n機場接送服務</li><li>\r\n前往 Discovery 購物中心的免費接駁服務</li><li>\r\nWi-Fi 無線網路</li><li>\r\n洗衣服務</li></ul>', '<ul><li>Swiss-Cafe™ 餐厅</li><li>\r\nBale Sunset 日落酒廊</li><li>\r\nLila 酒吧</li><li>\r\nSamuan 会议室</li><li>\r\n健身房</li><li>\r\n11x25.7 米游泳池</li><li>\r\n儿童游泳池</li><li>\r\n灵活的房型配置</li><li>\r\n大堂及车道门廊</li><li>\r\n免费停车区域</li><li>\r\nCCTV 监控与 24 小时安保</li><li>\r\n行李寄存区</li><li>\r\n机场接送服务</li><li>\r\n前往 Discovery 购物中心的免费接驳服务</li><li>\r\nWi-Fi 无线网络</li><li>\r\n洗衣服务</li></ul>', '<b>Seasonal Policy:&nbsp;</b><ul><li>Compulsory Christmas &amp; New Year Eve Dinner on 25 and 31 Dec (Price at additional charge)</li><li>No Check Out is allowed on 31 December&nbsp;</li><li>Respecting Silence Day (Hari Raya Nyepi) on 19 March 2026, no check in or check out is allowed&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n12月25日與12月31日需強制參加聖誕節與跨年夜晚宴（需另行收費）。</li><li>12月31日當天不允許辦理退房手續。</li><li>配合寂靜日（Hari Raya Nyepi，2026年3月19日），當天不得辦理入住與退房。</li></ul>', '季节性政策：<br><ul><li>\r\n12月25日与12月31日须强制参加圣诞节及跨年夜晚宴（需额外收费）。</li><li>12月31日当天不允许办理退房手续。</li><li>配合寂静日（Hari Raya Nyepi，2026年3月19日），当天不得办理入住与退房。</li></ul>', NULL, NULL, NULL, 'active', '1731997364_Berita_232712031214_swiss-belhotel-internasional-sasar-pelancong-bisnis-dan-wisata-tawarkan-pilihan-hotel-di-bali-serta-lombok.webp', 14, 'https://www.swiss-belhotel.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/oCiQGjXnDZG6L1sv8', NULL, NULL, NULL, NULL, '<b>Normal Season:&nbsp;</b><ul><li>7 days prior to arrival: cancellation fee equal to 1 (one) night stay will be imposed&nbsp;</li></ul><span><b>High Season</b>&nbsp;<i>(15 Jul - 31 Aug):</i></span><ul><li>14 days prior to arrival:&nbsp;cancellation fee equal to 1 (one) night stay will be imposed&nbsp;</li></ul><span><b>Peak Season</b>&nbsp;<i>(20 Dec - 04 Jan):&nbsp;</i></span><ul><li>21 days prior to arrival:&nbsp;cancellation fee equal to 1 (one) night stay will be imposed&nbsp;</li></ul>100% penalty will be imposed for any no show&nbsp;<br>', '<span>一般季節：<br></span><ul><li>\r\n入住前7天內取消，將收取相當於1晚住宿費的取消費。</li></ul><span>旺季（7月15日至8月31日）：<br></span><ul><li>\r\n入住前14天內取消，將收取相當於1晚住宿費的取消費。</li></ul><span>巔峰季節（12月20日至1月4日）：<br></span><ul><li>\r\n入住前21天內取消，將收取相當於1晚住宿費的取消費。</li></ul>如未入住（No Show），將收取100%全額罰金。', '<span>普通季节：<br></span><ul><li>\r\n入住前7天内取消，将收取相当于1晚住宿费用的取消费。</li></ul><span>旺季（7月15日至8月31日）：<br></span><ul><li>\r\n入住前14天内取消，将收取相当于1晚住宿费用的取消费。</li></ul><span>巅峰季节（12月20日至1月4日）：<br></span><ul><li>\r\n入住前21天内取消，将收取相当于1晚住宿费用的取消费。</li></ul>若未入住（No Show），将收取100%全额罚金。', NULL, '2024-01-11 21:11:32', '2026-03-24 18:26:55', 1, 1),
(115, 'Cross Bali Breakers', '17', 'Jimbaran', 'Bali', 'Indonesia', '7SECzNA5dDtnc5nCXAl6AxpFfX', '17', 17, 'Jalan Pantai Balangan, Jimbaran, Bali, Indonesia', 1, 1, 'Kiky', '03616201008', 'Located close to the legendary surf breaks of Balangan Beach in south Bali, Cross Bali Breakers Resort features 57 Deluxe Private Pool Villas in Bali nestled amid the lush natural landscape. The peaceful ambiance and personalized service create a luxurious haven for couples, friends and families alike.', 'Cross Bali Breakers Resort 坐落於峇里島南部，鄰近傳奇衝浪勝地巴蘭岸海灘，擁有 57 間豪華私人泳池別墅，坐落在翠綠自然景觀之中。寧靜的氛圍與貼心的個人化服務，共同營造出一處專屬於情侶、朋友與家庭的奢華天堂。', 'Cross Bali Breakers Resort 坐落于巴厘岛南部，靠近传奇冲浪胜地巴兰岸海滩，拥有57间豪华私人泳池别墅，坐落于郁郁葱葱的自然景观中。宁静的氛围与贴心的个性化服务，为情侣、朋友和家庭营造出一个奢华的度假天堂。', '<ul><li>High speed wifi</li><li>Dining area</li><li>Air conditioning</li><li>Hair dryer</li><li>Bluetooth speaker</li><li>Mini bar</li><li>Safe deposit box</li><li>Working desk</li><li>Private balcony</li><li>Coffee maker</li><li>Tv with satellite</li><li>Dvd player</li></ul>', '<ul><li>高速無線網路</li><li>\r\n用餐區</li><li>\r\n空調</li><li>\r\n吹風機</li><li>\r\n藍牙喇叭</li><li>\r\n迷你吧</li><li>\r\n保險箱</li><li>\r\n書桌</li><li>\r\n私人陽台</li><li>\r\n咖啡機</li><li>\r\n衛星電視</li><li>\r\nDVD 播放機</li></ul>', '<ul><li>高速无线网络</li><li>\r\n用餐区</li><li>\r\n空调</li><li>\r\n吹风机</li><li>\r\n蓝牙音响</li><li>\r\n迷你吧</li><li>\r\n保险箱</li><li>\r\n书桌</li><li>\r\n私人阳台</li><li>\r\n咖啡机</li><li>\r\n卫星电视</li><li>\r\nDVD 播放机</li></ul>', '<b>Seasonal Policy:&nbsp;</b><br><ul><li>A minimum of 3 consecutive nights stay is required during high (15 Jul - 31 Aug) and peak season (24 Dec - 05 Jan)&nbsp;</li><li>Check-out is NOT allowed on 31 December.</li><li>Compulsory New Year Eve (Price at additional charge)&nbsp;</li></ul><b>Honeymoon Offer &amp; Anniversaries:</b><br><ul><li>The following benefits apply to all over guests celebrating their honeymoon or anniversary. Unless otherwise approved, Honeymoons must be conducted within the year of wedding or within 3 months of wedding date. (e.g. married 30 November eligible no later than 28 February). Anniversaries celebrated are 1, 5, 10, 15, 20, 25, 50 upwards Wedding Certificate or Copy must be presented if requested by property.</li></ul><b>Minimum 3 Nights stay to receive:&nbsp;</b><ul><li>Honeymoon amenities set up on arrival&nbsp;</li><li>1x a 60 minutes massage for 2 persons at Alo\'e Spa (reservation in advance required)&nbsp;</li><li>1x a romantic floating bubbly breakfast for 2 persons at the Villa&nbsp;</li></ul><b>Child Policy:&nbsp;</b><br><ul><li>Children under 4 years of age on check-in stay free on a bed and breakfast when sharing existing bedding. A complimentary baby cot can be provided on request and subject to available at time of booking.&nbsp;When an extra bed is brought into the guest room, the applicable extra bed charges shown in this contract will always apply.</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n在旺季（7月15日至8月31日）與巔峰季節（12月24日至1月5日）期間，需至少連續入住3晚。</li><li>12月31日不允許退房。</li><li>跨年夜需參加強制性晚宴（費用另計）。</li></ul>蜜月與結婚紀念優惠：<br><ul><li>\r\n以下福利適用於所有慶祝蜜月或結婚紀念的住客。除非另有核准，蜜月須於結婚當年或結婚日起3個月內進行（例如：11月30日結婚，最遲適用至2月28日）。可慶祝的結婚紀念為：第1、5、10、15、20、25、50周年及以上。若飯店要求，須出示結婚證書或影本。&nbsp;</li></ul>凡入住至少3晚可享有以下禮遇：<br><ul>\r\n<li>\r\n抵達時蜜月禮遇布置\r\n</li>\r\n<li>\r\n於 Alo\'e Spa 享受 60 分鐘雙人按摩乙次（需提前預約）\r\n</li>\r\n<li>\r\n別墅內享用一次浪漫漂浮香檳早餐（限2人）\r\n</li>\r\n</ul>\r\n<span>兒童政策：<br></span><ul><li>\r\n4歲以下兒童於入住時與父母同床可免費享有早餐。可免費提供嬰兒床，需於訂房時提出並視供應情況而定。若需加床，將依本合約所載費用收取加床費。</li></ul>', '<span>季节性政策：<br></span><ul><li>在旺季（7月15日至8月31日）与巅峰季节（12月24日至1月5日）期间，需至少连续入住3晚。</li><li>12月31日不允许退房。</li><li>跨年夜需参加强制性晚宴（费用另计）。&nbsp;</li></ul><br>蜜月与结婚纪念优惠：<br><ul><li>\r\n以下福利适用于所有庆祝蜜月或结婚纪念的住客。除非另有批准，蜜月须在结婚当年或结婚日起3个月内进行（例如：11月30日结婚，最迟适用至2月28日）。可庆祝的结婚纪念为：第1、5、10、15、20、25、50周年及以上。如酒店要求，须出示结婚证书或影印件。</li></ul>凡入住至少3晚可享以下礼遇：\r\n<ul>\r\n<li>\r\n入住当天提供蜜月布置\r\n</li>\r\n<li>\r\n于 Alo\'e Spa 享受一次60分钟双人按摩（需提前预约）\r\n</li>\r\n<li>\r\n在别墅内享用一次浪漫漂浮香槟早餐（限2人）\r\n</li>\r\n</ul>\r\n<span>儿童政策：<br></span><ul><li>\r\n4岁以下儿童在入住时与父母共床可免费享受早餐。可根据请求免费提供婴儿床，须视预订时是否有库存而定。若需加床，则一律依本合同所列加床费用收取。</li></ul>', NULL, NULL, NULL, 'active', 'hotels/covers/1731997477_3c97090d0ce1375cb94cd36e8ccced21.webp', 14, 'https://www.crosshotelsandresorts.com/crossbali', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Cross+Bali+Breakers/@-8.8023693,115.1311722,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd245f39fec251f:0xb7449bc01fc31dc7!5m2!4m1!1i2!8m2!3d-8.8023746!4d115.1337471!16s%2Fg%2F11ghs7kw5f?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.8023913, 115.1338094, NULL, NULL, '<span><b>Low Season </b><i>(01 Apr - 14 Jul, 01 Sep - 23 Dec, 06 Jan - 31 Mar):</i><br></span><ul><li>Cancellation received by the hotel less than 7 days prior to arrival day, a cancellation fee equivalent to the contract rate of one nights will be applied.&nbsp;</li></ul><b>High Season</b><i> (15 Jul - 31 Aug):</i><br><ul><li>Cancellation received by the hotel less than 14 days prior to arrival day, a cancellation fee equivalent to 50% of the total room charged will be applied.&nbsp;</li></ul><span><b>Peak Season</b> <i>(24 Dec - 05 Jan):&nbsp;</i><br></span><ul><li>Cancellation received by the hotel less than 28 days prior to arrival day, a cancellation fee equivalent to 100% of the total room charge will be applied.&nbsp;</li></ul><span><b>No Show:&nbsp;</b><br></span><ul><li>A reservation is considered “No show” if arrival does not occur on the date reserved and the hotel is not notified of any emergency delays in writing, the hotel reserves the right to charge a no-show fee 100% of total room charge.&nbsp;</li></ul>', '<span>淡季（4月1日－7月14日、9月1日－12月23日、1月6日－3月31日）：<br></span><ul><li>\r\n若於抵達日前7天內取消，將收取相當於一晚合約房價的取消費。</li></ul><span>旺季（7月15日－8月31日）：<br></span><ul><li>\r\n若於抵達日前14天內取消，將收取相當於總房費50%的取消費。</li></ul><span>巔峰季節（12月24日－1月5日）：<br></span><ul><li>\r\n若於抵達日前28天內取消，將收取相當於總房費100%的取消費。</li></ul><span>未入住（No Show）：<br></span><ul><li>\r\n若客人未於預訂日期抵達，且飯店未收到任何書面形式的延誤通知，將視為「未入住」，飯店有權收取100%總房費的未入住費用。</li></ul>', '<span>淡季（4月1日－7月14日、9月1日－12月23日、1月6日－3月31日）：<br></span><ul><li>\r\n如在抵达日前7天内取消，将收取相当于一晚合同房价的取消费用。</li></ul><span>旺季（7月15日－8月31日）：<br></span><ul><li>\r\n如在抵达日前14天内取消，将收取相当于总房费50%的取消费用。</li></ul><span>巅峰季节（12月24日－1月5日）：<br></span><ul><li>\r\n如在抵达日前28天内取消，将收取相当于总房费100%的取消费用。</li></ul><span>未入住（No Show）：<br></span><ul><li>\r\n若未在预订日期抵达，且酒店未收到任何书面形式的紧急延误通知，则视为“未入住”，酒店有权收取100%总房费作为未入住费用。</li></ul>', NULL, '2024-01-14 23:29:32', '2026-03-25 19:36:18', 1, 2),
(116, 'Samsara Ubud', '17', NULL, NULL, NULL, '9aaOEoTh0YN4LCNlfs9abE6idq', '17', NULL, 'Banjar Ayah, Desa Kelusa, Payangan Ubud Bali - 80572 Indonesia', 2, 49, 'Anita', '62811846769', '<p>At Samsara Ubud, we believe the ultimate luxury is connection. The resort and the experience have been designed to allow our guests to reconnect with nature, with their loved ones and most importantly, with themselves.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1707705663_Samsara Ubud.webp', 14, 'www.samsaraubud.com', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/banVmptET4Hgw2WM7', NULL, NULL, NULL, NULL, '<p><strong>Low Season</strong> (01 Apr - 30 Jun 2024, 01 Sep - 20 Dec 2024, 06 Jan - 31 Mar 2025):&nbsp;</p><p>Any cancelation received within 14 days before the arrival date will incur a one-night cancelation free for all villas acquired&nbsp;</p><p><strong>High Season</strong> (01 Jul - 31 Aug 2024, 21 Dec 2024 - 05 Jan 2025):&nbsp;</p><p>Any cancelation received within 14 days before the arrival date will incur full-night charge for all villas acquired&nbsp;</p><p><strong>No Show:&nbsp;</strong></p><p>Samsara Ubud will charge a full-night charge for all villas acquired&nbsp;</p><p><strong>Seasonal Policy:&nbsp;</strong></p><p>No Check-Out Policy applies on every 31 Dec, and No Check-in and Out Policy on Nyepi Day&nbsp;</p>', NULL, NULL, NULL, '2024-02-11 19:41:03', '2026-03-24 18:26:55', 1, 1),
(117, 'Kayumanis Jimbaran Private Estate', '17', NULL, NULL, NULL, 'aZ6NeKoEvC3wVwOQe2Aw73wfbJ', '17', NULL, 'Jl. Yoga Perkanthi Lingkungan, pesalakan, Jimbaran, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 3, 'Putu Agustini', '0361705777', 'Kayumanis Jimbaran Private Estate &amp; Spa is an exclusive sanctuary inspired by the sense of community that exists within a traditional Balinese village. The property is spread across a former coconut grove where towering palms sway gently in the sea breeze. All 20 contemporary villas and supporting facilities are attuned to the island’s tropical environment. Indigenous materials such as hardwoods and local stone have been utilized in a design concept that emulates Bali’s open style of living.', 'Kayumanis Jimbaran Private Estate &amp; Spa 是一處靈感來自傳統峇里村莊社群精神的專屬靜謐天地。度假村坐落於原椰林園地之上，高聳的椰子樹在海風中輕輕搖曳。全區擁有20棟現代風格的別墅及完善的設施，完美融合島嶼熱帶環境。設計上採用本地素材，如硬木與當地石材，體現峇里島獨有的開放式生活美學。', '<div><div><div><div><div>Kayumanis Jimbaran Private Estate &amp; Spa 是一处灵感源自传统巴厘村庄社区精神的专属静谧天地。度假村坐落于原椰林之上，高耸的椰子树在海风中轻轻摇曳。全区共设有20栋现代风格别墅及完善设施，与岛屿的热带环境自然协调。设计理念采用本地材料，如硬木和当地石材，体现巴厘岛独特的开放式生活方式。</div></div></div></div><div><div><div></div></div></div><div><div></div></div></div><div><div></div></div>', NULL, NULL, NULL, '<span><b>Seasonal Policy:</b>&nbsp;<br></span><ul><li>Minimum 3 nights consecutive stay require for staying over period of 24 Dec&nbsp;- 03 Jan&nbsp;(Peak Season)&nbsp;</li><li>No check out for period of 30 - 31 December</li></ul><b>Honeymoon benefits:&nbsp;</b>\r\n\r\n<br><ul><li>Flower\r\n     bath on arrrival&nbsp;</li><li>Honeymoon\r\n     cake&nbsp;</li><li>Honeymoon\r\n     gift</li></ul><b>Airport Transfer:</b>&nbsp;<br><ul><li>Airport transfer service is available based on complimentary&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n在巔峰季節（12月24日至1月3日）期間，需連續入住至少3晚。</li><li>\r\n12月30日至31日期間不可辦理退房。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時提供花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月禮物</li></ul><span>機場接送服務：<br></span><ul><li>\r\n提供免費機場接送服務</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n在巅峰季节（12月24日至1月3日）期间，需连续入住至少3晚。</li></ul>\r\n12月30日至31日期间不可办理退房。\r\n<br><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时提供花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月礼物</li></ul><span>机场接送服务：<br></span><ul><li>\r\n提供免费机场接送服务</li></ul>', NULL, NULL, NULL, 'Active', '1709695289_Cover.webp', 14, 'https://www.kayumanisjimbaran.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/5mLXnSrm7XkAG9Eq9', NULL, NULL, NULL, NULL, '<span><b>Low Season</b>&nbsp;<i>(01 Apr - 14 Jul, 16 Sep - 23 Dec,\r\n04 Jan - 31 Mar):&nbsp;</i><br>\r\n</span>\r\n\r\n<ul>\r\n <li>Cancellation\r\n     within 21 (twenty one) days on low season is subject to 1 (one) night\r\n     cancellation fee&nbsp;</li>\r\n</ul>\r\n\r\n<span><b>High Season</b>&nbsp;<i>(15 Jul - 15 Sep):&nbsp;</i><br>\r\n</span>\r\n\r\n<ul>\r\n <li>Cancellation\r\n     within 30 (thirty) days on high season is subject to 2 (two) nights\r\n     cancellation fee&nbsp;</li>\r\n</ul>\r\n\r\n<span><b>Peak Season</b>&nbsp;<i>(24 Dec - 03 Jan):</i>&nbsp;<br></span><ul><li>Cancellation\r\n     within 45 (fourty five) days on peak season is subject to 2 (two) nights\r\n     cancellation fee&nbsp;</li></ul>\r\n\r\n<span><i>No show and early departure are subject to full amount/100%\r\ncancellation fee of the total number of room nights reserved&nbsp;</i><br></span><ul>\r\n</ul>', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n如於抵達日前21天內取消，將收取1晚取消費。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n如於抵達日前30天內取消，將收取2晚取消費。</li></ul><span>巔峰季節（12月24日－1月3日）：<br></span><ul><li>\r\n如於抵達日前45天內取消，將收取2晚取消費。</li></ul><span>未入住或提前退房：<br>\r\n將收取預訂總晚數的全額費用（100%取消費）。</span>', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n如在抵达日前21天内取消，将收取1晚取消费用。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n如在抵达日前30天内取消，将收取2晚取消费用。</li></ul><span>巅峰季节（12月24日－1月3日）：<br></span><ul><li>\r\n如在抵达日前45天内取消，将收取2晚取消费用。</li></ul><span>未入住或提前退房：<br>\r\n将收取预订总晚数的全部费用（100%取消费）。</span>', NULL, '2024-03-05 20:21:29', '2025-07-07 20:12:32', 1, 1),
(118, 'Kayumanis Ubud Private Villa and Spa', '17', NULL, NULL, NULL, 'pHYM7NVuVCyRgO7NcmfCxmOAEm', '17', NULL, 'Jl. Raya Sayan Jl. Baung, Sayan, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 2, 31, 'Putu Agustini', '0361972777', 'Kayumanis Ubud Private Villas &amp; Spa is cocooned within a tropical forest overlooking the Ayung River. It is part of a traditional Balinese village whereby daily life revolves around a cultural calendar of religious ceremonies and community events. Significantly distanced from mainstream activity, the resort is luxury hideaway where you will feel rejuvenated by the sights and sounds of nature.&nbsp;With a design concept that is in harmony with the surrounding environment, Kayumanis Ubud offers a collection of well-appointed Balinese villas and supporting lifestyle facilities. Every effort has been made to tread lightly and respect the immediate landscape. From preserving mature trees to the choice of indigenous materials such as coconut wood, thatched rooftops and textured stone, the property is a model of sustainable hospitality.', 'Kayumanis Ubud Private Villas &amp; Spa 座落於熱帶雨林之中，俯瞰阿勇河，靜靜隱身於峇里傳統村落的一隅，這裡的日常生活圍繞著宗教祭典與社區活動的文化節奏展開。遠離城市喧囂，這座度假村是一處奢華的靜修天地，讓您在大自然的景致與聲音中重拾身心平衡。\r\n其設計理念與周圍環境相協調，Kayumanis Ubud 精心打造一系列富有峇里風格的別墅與生活設施，展現對自然的敬重與細膩匠心。從保留原生老樹，到選用本地素材如椰木、茅草屋頂與質感石材，整座度假村體現了可持續款待的典範。', 'Kayumanis Ubud Private Villas &amp; Spa 坐落在热带雨林中，俯瞰阿勇河，静静隐匿于一个传统巴厘村庄之内，这里的日常生活围绕宗教仪式和社区活动的文化历程展开。远离主流的喧嚣活动，度假村是一处奢华的隐世之所，让您在大自然的景色与声音中焕发身心活力。\r\nKayumanis Ubud 的设计理念与周围环境和谐共融，提供一系列精致的巴厘别墅与配套生活设施，处处体现对自然环境的尊重。从保留原生老树到选用本地材料如椰木、茅草屋顶和纹理石材，该度假村是可持续接待理念的典范。', NULL, NULL, NULL, '<span><b>Seasonal Policy:</b>&nbsp;<br></span><ul><li>Minimum 3 nights consecutive stay require for staying over period of 24 Dec&nbsp;- 03 Jan&nbsp;(Peak Season)&nbsp;</li><li>No check out for period of 30 - 31 December</li></ul><b>Honeymoon benefits:&nbsp;</b>\r\n\r\n<ul>\r\n <li>Flower\r\n     bath on arrrival&nbsp;</li>\r\n <li>Honeymoon\r\n     cake&nbsp;</li>\r\n <li>Honeymoon\r\n     gift&nbsp;</li>\r\n</ul>', '<span>季節性政策：<br></span><ul><li>\r\n於巔峰季節（12月24日至1月3日）期間入住，需連續入住至少3晚。</li><li>\r\n12月30日至31日不允許辦理退房。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時提供花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月禮物</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n在巅峰季节（12月24日至1月3日）期间入住，需连续入住至少3晚。</li><li>\r\n12月30日至31日不允许办理退房。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时提供花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月礼物</li></ul>', NULL, NULL, NULL, 'Active', '1709697416_Cover.webp', 14, 'https://www.kayumanisubud.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/ALiJQ5uvWb9aiD8Q7', NULL, NULL, NULL, NULL, '<span><b>Low Season</b>&nbsp;<i>(01 Apr - 14 Jul, 16 Sep - 23 Dec,\r\n04 Jan - 31 Mar):&nbsp;</i><br>\r\n</span>\r\n\r\n<ul>\r\n <li>Cancellation\r\n     within 21 (twenty one) days on low season is subject to 1 (one) night\r\n     cancellation fee&nbsp;</li>\r\n</ul>\r\n\r\n<span><b>High Season</b>&nbsp;<i>(15 Jul - 15 Sep):&nbsp;</i><br>\r\n</span>\r\n\r\n<ul>\r\n <li>Cancellation\r\n     within 30 (thirty) days on high season is subject to 2 (two) nights\r\n     cancellation fee&nbsp;</li>\r\n</ul>\r\n\r\n<span><b>Peak Season</b>&nbsp;<i>(24 Dec - 03 Jan):</i>&nbsp;<br>\r\n</span>\r\n\r\n<ul>\r\n <li>Cancellation\r\n     within 45 (fourty five) days on peak season is subject to 2 (two) nights\r\n     cancellation fee&nbsp;</li>\r\n</ul>\r\n\r\n<span><i>No show and early departure are subject to full amount/100%\r\ncancellation fee of the total number of room nights reserved</i>&nbsp;<br></span><ul>\r\n</ul>', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n若於抵達日前21天內取消，將收取1晚取消費用。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n若於抵達日前30天內取消，將收取2晚取消費用。</li></ul><span>巔峰季節（12月24日－1月3日）：<br></span><ul><li>\r\n若於抵達日前45天內取消，將收取2晚取消費用。</li></ul>若未入住（No Show）或提前退房，將收取預訂房晚總額的100%作為取消費。', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n如在抵达日前21天内取消，将收取1晚取消费用。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n如在抵达日前30天内取消，将收取2晚取消费用。</li></ul><span>巅峰季节（12月24日－1月3日）：<br></span><ul><li>\r\n如在抵达日前45天内取消，将收取2晚取消费用。</li></ul>如未入住（No Show）或提前退房，将收取预订总房晚数的100%作为取消费用。', NULL, '2024-03-05 20:56:56', '2025-07-07 22:00:35', 1, 1),
(119, 'Kayumanis Nusa Dua Private Villa', '17', NULL, NULL, NULL, 'fdX3wFuVNVKAPmcbdtxj4MnmNc', '17', NULL, 'BTDC Area, Jl. Nusa Dua, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80363', 1, 9, 'Putu Agustini', '0361770777', 'Kayumanis Nusa Dua Private Villa &amp; Spa is located within an exclusive tourism enclave known for its long stretch of white sand beach, manicured gardens and high-end hotels. The property is a serene setting of quiet sophistication and understated elegance that lends itself to tropical relaxation. It celebrates the essence of Balinese luxury with a collection of well-appointed villas and supporting facilities. Hospitality at Kayumanis Nusa Dua Private Villa &amp; Spa warmlyreflects the gracious spirit of Bali. Every villa has a personal butler on duty who is tasked to anticipate and take care of every conceivable need. In fact, our entire team go above and beyond the call of duty to offer service that is second to none. You will find yourself embraced by a unique sense of belonging that is remembered long after you return home.', 'Kayumanis Nusa Dua Private Villa &amp; Spa 坐落於努沙杜瓦尊貴的觀光區內，該區以綿延潔白沙灘、修剪整齊的花園與高端飯店聞名。這座度假村展現低調優雅的靜謐氛圍，是熱帶度假的理想選擇。<br>\r\n度假村以設施完善的私人別墅與各項配套設施，體現出峇里島奢華生活的精髓。Kayumanis Nusa Dua Private Villa &amp; Spa 的待客服務，溫暖地展現出峇里人熱情好客的精神。<br>\r\n每間別墅皆配有專屬管家，貼心掌握並照料賓客的一切需求。我們的整個團隊更是竭盡所能，提供無可比擬的卓越服務。<br>\r\n在這裡，您將感受到獨特的歸屬感，這份感動將會長存於心，縈繞於回憶之中。', 'Kayumanis Nusa Dua Private Villa &amp; Spa 位于努沙杜瓦高端旅游区，该地区以绵延洁白的沙滩、精致园林和高级酒店而闻名。度假村拥有宁静而优雅的氛围，是热带度假的理想之选。<br>\r\n度假村通过精致的别墅和完善的配套设施，诠释了巴厘岛奢华生活的精髓。Kayumanis Nusa Dua Private Villa &amp; Spa 的热情款待，充分展现了巴厘岛人民的优雅与好客精神。<br>\r\n每栋别墅配有专属私人管家，贴心照顾宾客的各种需求。我们的整个团队更是超越职责，致力于提供无与伦比的服务体验。<br>\r\n在这里，您将感受到一种独特的归属感，这份温暖的记忆将伴随您回家，久久难忘。', NULL, NULL, NULL, '<span><b>Seasonal Policy:</b>&nbsp;<br></span><ul><li>Minimum 3 nights consecutive stay require for staying over period of 24 Dec&nbsp;- 03 Jan&nbsp;(Peak Season)&nbsp;</li><li>No check out for period of 30 - 31 December</li></ul><b>Honeymoon benefits:&nbsp;</b><br><ul><li>Flower bath on arrrival&nbsp;</li><li>Honeymoon cake&nbsp;</li><li>Honeymoon gift&nbsp;</li></ul><b>Airport Transfer:</b>&nbsp;<br><ul><li>Airport transfer service is available based on complimentary&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n於巔峰季節（12月24日至1月3日）期間入住，需連續入住至少3晚。</li><li>12月30日至31日不允許退房。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時提供花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月禮物</li></ul><span>機場接送：<br></span><ul><li>\r\n提供免費機場接送服務</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n在巅峰季节（12月24日至1月3日）期间入住，需连续入住至少3晚。</li><li>\r\n12月30日至31日不允许办理退房。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时提供花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月礼物</li></ul><span>机场接送：<br></span><ul><li>\r\n提供免费机场接送服务</li></ul>', NULL, NULL, NULL, 'Active', '1709704498_Cover.webp', 14, 'https://kayumanisnusadua.com/?utm_source=business&utm_medium=business&utm_campaign=business&utm_id=business&utm_term=business&utm_content=business', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/ci7msTywvYnWwv3N6', NULL, NULL, NULL, NULL, '<span><b>Low Season</b>&nbsp;<i>(01 Apr - 14 Jul, 16 Sep - 23 Dec, 04 Jan - 31 Mar):&nbsp;</i><br></span><ul><li>Cancellation within 21 (twenty one) days on low season is subject to 1 (one) night cancellation fee&nbsp;</li></ul><span><b>High Season</b>&nbsp;<i>(15 Jul - 15 Sep):&nbsp;</i><br></span><ul><li>Cancellation within 30 (thirty) days on high season is subject to 2 (two) nights cancellation fee&nbsp;</li></ul><span><b>Peak Season</b>&nbsp;<i>(24 Dec - 03 Jan):</i>&nbsp;<br></span><ul><li>Cancellation within 45 (fourty five) days on peak season is subject to 2 (two) nights cancellation fee&nbsp;</li></ul><span><i>No show and early departure are subject to full amount/100% cancellation fee of the total number of room nights reserved&nbsp;</i><br></span>', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n若於抵達日前21天內取消，將收取1晚取消費。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n若於抵達日前30天內取消，將收取2晚取消費。</li></ul><span>巔峰季節（12月24日－1月3日）：<br></span><ul><li>\r\n若於抵達日前45天內取消，將收取2晚取消費。</li></ul><span>未入住或提前退房：<br>\r\n將收取所預訂房晚總額的100%作為取消費用。</span>', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n如在抵达日前21天内取消，将收取1晚取消费用。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n如在抵达日前30天内取消，将收取2晚取消费用。</li></ul><span>巅峰季节（12月24日－1月3日）：<br></span><ul><li>\r\n如在抵达日前45天内取消，将收取2晚取消费用。</li></ul><span>未入住或提前退房：<br>\r\n将收取所预订房晚总额的100%作为取消费用。</span>', NULL, '2024-03-05 22:54:58', '2025-07-07 22:58:32', 1, 1),
(120, 'Kayumanis Sanur Private Villa and Spa', '17', NULL, NULL, NULL, 'lhzK3Md2Ua1WFN7gcCqh8CPwQM', '17', NULL, 'Jl. Tirta Akasa No.28, Sanur, Denpasar Selatan, Kota Denpasar, Bali 80228', 1, 14, 'Putu Agustini', '0361270260', 'Enveloped within a lush garden setting that celebrates the harmony of Balinese living, Kayumanis Sanur Private Villa &amp; Spa is inspired by the layout of a traditional village. The property features a collection of just 11 units and supporting facilities connected by a stone path that winds its way beneath the trees. From the first moment of arrival, you will feel yourself embraced by warm hospitality and a unique sense of belonging. Sanur is a laid-back village with a rich history steeped in art, culture and tradition. As Bali’s first real tourist destination, it is home to a number of sacred Hindu temples and sites of interest. Blessed with a stretch of white sand beach sheltered by gentle waters, Sanur has a calming spirit that draws people back time and time again. Kayumanis Sanur channels that same energy to create a nurturing home environment.', 'Kayumanis Sanur Private Villa &amp; Spa 坐落於鬱鬱蔥蔥的花園中，展現峇里生活的和諧之美，其設計靈感源自傳統村莊的格局。整個園區僅有 11 棟別墅，由蜿蜒穿梭於樹蔭下的石板小徑相連，打造靜謐私密的空間。一抵達，您便會被溫暖的款待與獨特的歸屬感所包圍。\r\n沙努爾（Sanur）是一個悠閒的小村莊，擁有豐富的藝術、文化與傳統歷史。作為峇里島第一個真正的觀光目的地，這裡擁有多座神聖的印度教寺廟與值得探索的景點。潔白的沙灘與平靜的海水，讓沙努爾散發出寧靜療癒的氛圍，吸引人們一次又一次地回訪。Kayumanis Sanur 正是承襲了這份能量，打造出溫馨療癒的居家環境。', 'Kayumanis Sanur Private Villa &amp; Spa 坐落在郁郁葱葱的花园中，彰显巴厘生活的和谐之美，灵感源自传统村庄的布局。整座度假村仅设有 11 栋别墅，由石径小路相连，蜿蜒穿梭于绿荫之间，营造出静谧而私密的空间。从您抵达的第一刻起，便能感受到热情好客的接待与独特的归属感。\r\n沙努尔是一个悠闲的村庄，拥有丰富的艺术、文化与传统历史。作为巴厘岛最早的旅游目的地，这里坐落着许多神圣的印度教庙宇及景点。洁白的沙滩与平静的海水赋予沙努尔一种令人心神安定的气息，让人们一再回访。Kayumanis Sanur 亦传承这种能量，营造出如家般温暖的疗愈环境。', NULL, NULL, NULL, '<span><b>Seasonal Policy:</b>&nbsp;<br></span><ul><li>Minimum 3 nights consecutive stay require for staying over period of 24 Dec&nbsp;- 03 Jan&nbsp;(Peak Season)&nbsp;</li><li>No check out for period of 30 - 31 December</li></ul><b>Honeymoon benefits:&nbsp;</b><ul><li>Flower bath on arrrival&nbsp;</li><li>Honeymoon cake&nbsp;</li><li>Honeymoon gift&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n於巔峰季節（12月24日至1月3日）期間入住，需連續入住至少3晚。</li><li>\r\n12月30日至31日不可退房。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n抵達時享有花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月禮物</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n在巅峰季节（12月24日至1月3日）期间入住，需连续入住至少3晚。</li><li>\r\n12月30日至31日不可办理退房。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n抵达时享有花瓣浴</li><li>\r\n蜜月蛋糕</li><li>\r\n蜜月礼物</li></ul>', NULL, NULL, NULL, 'Active', '1709706019_Cover.webp', 14, 'https://www.kayumanissanur.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/Bmjxk64QZW2CzhwV7', NULL, NULL, NULL, NULL, '<span><b>Low Season</b>&nbsp;<i>(01 Apr - 14 Jul, 16 Sep - 23 Dec, 04 Jan - 31 Mar):&nbsp;</i><br></span><ul><li>Cancellation within 21 (twenty one) days on low season is subject to 1 (one) night cancellation fee&nbsp;</li></ul><span><b>High Season</b>&nbsp;<i>(15 Jul - 15 Sep):&nbsp;</i><br></span><ul><li>Cancellation within 30 (thirty) days on high season is subject to 2 (two) nights cancellation fee&nbsp;</li></ul><span><b>Peak Season</b>&nbsp;<i>(24 Dec - 03 Jan):</i>&nbsp;<br></span><ul><li>Cancellation within 45 (fourty five) days on peak season is subject to 2 (two) nights cancellation fee&nbsp;</li></ul><span><i>No show and early departure are subject to full amount/100% cancellation fee of the total number of room nights reserved&nbsp;</i><br></span>', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n若於抵達日前21天內取消，將收取1晚取消費。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n若於抵達日前30天內取消，將收取2晚取消費。</li></ul><span>巔峰季節（12月24日－1月3日）：<br></span><ul><li>\r\n若於抵達日前45天內取消，將收取2晚取消費。</li></ul><span>未入住或提前退房：<br>\r\n將收取所預訂房晚總數的100%作為取消費用。</span>', '<span>淡季（4月1日－7月14日、9月16日－12月23日、1月4日－3月31日）：<br></span><ul><li>\r\n如在抵达日前21天内取消，将收取1晚取消费用。</li></ul><span>旺季（7月15日－9月15日）：<br></span><ul><li>\r\n如在抵达日前30天内取消，将收取2晚取消费用。</li></ul><span>巅峰季节（12月24日－1月3日）：<br></span><ul><li>\r\n如在抵达日前45天内取消，将收取2晚取消费用。</li></ul><span>未入住或提前退房：<br>\r\n将收取预订总房晚数的100%作为取消费用。</span>', NULL, '2024-03-05 23:20:19', '2025-07-07 23:58:20', 1, 1),
(121, 'The Royal Santrian', '17', NULL, NULL, NULL, 'xNgijFBw1Fr4k9exFExxwBZ1dH', '17', NULL, 'Nusa Dua, Jl. Pratama, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 2, 'Eka Widiningsih', '0361778181', 'The Royal Santrian in Nusa Dua is an elegant haven by the sea, a collection of luxury villas designed to fulfill your desires for seclusion, comfort and the good life.', 'The Royal Santrian 坐落於努沙杜瓦海濱，是一處優雅的避世天堂，由一系列奢華別墅所組成，專為滿足您對私密性、舒適與美好生活的嚮往而設計。', 'The Royal Santrian 位于努沙杜瓦海边，是一处优雅的海滨天堂，由多栋豪华别墅组成，专为满足您对私密、舒适与美好生活的渴望而设计。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Minimum 3 nights stay is required during Peak Season and No check-in and No check-out on 31 December</li><li>Compulsory New Year\'s Eve Dinner on 31 December 2025 (Price at additional charge)&nbsp;</li></ul><b>Honeymooner Benefit:&nbsp;</b><br><ul><li>Honeymoon couple will receive romantic arrangement in the villa and honeymoon cake upon arrival</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n巔峰季節期間須至少入住3晚，且12月31日不接受入住或退房。</li><li>\r\n2025年12月31日須參加跨年夜強制晚宴（需另付費用）。</li></ul><span>蜜月禮遇：<br></span><ul><li>\r\n蜜月夫妻可於抵達時享有別墅內的浪漫佈置與蜜月蛋糕。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n巅峰季节期间需至少入住3晚，且12月31日不可办理入住与退房。</li><li>\r\n2025年12月31日需参加跨年夜强制晚宴（另行收费）。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n蜜月夫妻在抵达时可享受别墅浪漫布置及蜜月蛋糕。</li></ul>', NULL, NULL, NULL, 'Active', '1710385762_by9p0490-1580112727.webp', 14, 'http://www.theroyalsantrian.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/m4ijY2eGT9RWrCFs9', NULL, NULL, NULL, NULL, '<span><b>Regular Season</b> <i>(01 Apr - 15 Jul, 16 Sep - 22 Dec, 08 Jan - 31 Mar):&nbsp;</i><br></span><ul><li>Cancellations within 14 days for regular season prior to arrival will be charged the whole nights of the confirmed nights.&nbsp;</li></ul><span><b>High Season</b> <i>(16 Jul - 15 Sep):&nbsp;</i><br></span><ul><li>Cancellations within 21 days for high season prior to arrival will be charged the whole nights of the confirmed nights.&nbsp;</li></ul><span><b>Peak Season</b> <i>(23 Dec - 07 Jan):&nbsp;</i><br></span><ul><li>Cancellation received within 30 days prior to arrival for peak season will be charged the whole nights of the confirmed nights.&nbsp;No show are subject to 100% full charge for the whole period of stay&nbsp;</li></ul>', '<span>平季（4月1日－7月15日、9月16日－12月22日、1月8日－3月31日）：<br></span><ul><li>\r\n如於抵達日前14天內取消，將收取全數已確認晚數的房費。</li></ul><span>旺季（7月16日－9月15日）：<br></span><ul><li>\r\n如於抵達日前21天內取消，將收取全數已確認晚數的房費。</li></ul><span>巔峰季節（12月23日－1月7日）：<br></span><ul><li>\r\n如於抵達日前30天內取消，將收取全數已確認晚數的房費。若未入住（No Show），將收取整個入住期間的全額費用（100%）。</li></ul>', '<span>平季（4月1日－7月15日、9月16日－12月22日、1月8日－3月31日）：<br></span><ul><li>\r\n如在抵达日前14天内取消，将收取全部已确认晚数的房费。</li></ul><span>旺季（7月16日－9月15日）：<br></span><ul><li>\r\n如在抵达日前21天内取消，将收取全部已确认晚数的房费。</li></ul><span>巅峰季节（12月23日－1月7日）：<br></span><ul><li>\r\n如在抵达日前30天内取消，将收取全部已确认晚数的房费。如未入住（No Show），将收取整个入住期间的全额费用（100%）。</li></ul>', NULL, '2024-03-13 20:09:22', '2025-07-08 00:14:26', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(122, 'Kamandalu Ubud', '17', NULL, NULL, NULL, 'IL0RfPHIi1MQndJn9db6qiK3tq', '17', NULL, 'Jl. Raya Andong No. 32', 2, 30, 'Ayu Swandewi', '0361975825', 'Kamandalu Ubud has been enchanting guests since 1992 with its traditional village concept incorporating luxury accommodation within a natural landscape that features productive rice terraces. The property underwent extensive renovation in 2019, which included the establishment of two brand new villa categories. All facilities and villa interiors were upgraded to anticipate the needs of modern travellers and provide an enriching experience on the island of Bali.', 'Kamandalu Ubud 自 1992 年起便以傳統村莊概念，結合奢華住宿與富饒稻田的自然景觀，持續吸引著旅客。<br>\r\n2019 年，飯店進行了全面翻新，包括新增兩種全新別墅房型。所有設施與別墅內部皆已升級，以滿足現代旅客的需求，並在峇里島提供豐富難忘的體驗。', '<div><div><div><div><div><div><span>Kamandalu Ubud 自1992年起便以傳統村莊概念，融合奢華住宿與富饒稻田的自然景观，持续吸引着宾客。<br>\r\n酒店于2019年进行了全面翻新，包括新增两个全新别墅房型。所有设施及别墅内部皆已升级，以满足现代旅行者的需求，带来在巴厘岛丰富而深刻的入住体验。</span></div></div></div></div><div><div><div><div></div></div></div></div><div><div></div></div></div><div><br></div></div><div></div>', '<ul><li>Aira swimming pool with kids\' pool</li><li>A Swim-up Bar</li><li>Awana Pool and Lounge</li><li>An indoor kids\' room</li><li>Rumah Yoga&nbsp;</li><li>Forest Deck: For breakfast, lunch and&nbsp;dinner with a view of the jungle&nbsp;</li><li>Meeting Room&nbsp;</li><li>Chaya Spa: A private villa spa</li><li>Village Club: A cozy club lounge exclusively for Pool Villa guests</li><li>Alun-Alun: A wedding venue as well as a romantic dinner venue</li><li>Vedika: Tropical huts amidst the rice terraces for a picnic lunch or an afternoon tea</li><li>Photo moments on the boat, Andalu Shop: A boutique where you can find Balinese arts, crafts and sundries souvenir</li></ul>', '<ul><li><li>Aira 游泳池與兒童池</li><li>泳池吧台</li><li>Awana 泳池與休憩區</li><li>室內兒童遊戲室</li><li>Rumah 瑜伽館</li><li>森林觀景台：可享叢林美景的早餐、午餐與晚餐場地</li><li>會議室</li><li>Chaya Spa：私人別墅水療</li><li>Village Club：僅限泳池別墅住客的溫馨會所</li><li>Alun-Alun：可作為婚禮場地或浪漫晚餐地點</li><li>Vedika：位於稻田間的熱帶涼亭，適合野餐午餐或下午茶</li><li>船上拍照時刻、Andalu 商店：販售峇里島藝術品、手工藝品及紀念品的精品店</li></li></ul>', '<ul><li>Aira 游泳池和儿童池\r\n</li>\r\n<li>\r\n泳池吧台\r\n</li>\r\n<li>\r\nAwana 泳池和休闲区\r\n</li>\r\n<li>\r\n室内儿童游戏室\r\n</li>\r\n<li>\r\nRumah 瑜伽馆\r\n</li>\r\n<li>\r\n森林观景台：享受丛林美景的早餐、午餐与晚餐场地\r\n</li>\r\n<li>\r\n会议室\r\n</li>\r\n<li>\r\nChaya Spa：私人别墅水疗中心\r\n</li>\r\n<li>\r\nVillage Club：专为泳池别墅住客提供的温馨会所\r\n</li>\r\n<li>\r\nAlun-Alun：可用于婚礼或浪漫晚宴的场地\r\n</li>\r\n<li>\r\nVedika：坐落于稻田中的热带凉亭，适合野餐午餐或下午茶\r\n</li>\r\n<li>\r\n船上拍照留念、Andalu 商店：一家精品店，提供巴厘岛艺术品、手工艺品及纪念品\r\n</li>\r\n</ul>', '<b>Seasonal Policy:&nbsp;</b><br><ul><li>Guest not allowed to check-out on 31 Dec&nbsp;</li><li>No late check-out during High Season 15 Jul - 31 Aug &amp; 23 Dec - 05 Jan</li></ul><b>Honeymooner &amp; Wedding Anniversary Extra Benefits:&nbsp;<br></b><ul><li>Flower petals on bathtub upon arrival&nbsp;</li><li>Decoration on bed and honeymoon cake upon arrival&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n禁止於12月31日辦理退房。</li><li>\r\n在旺季期間（7月15日 - 8月31日 及 12月23日 - 1月5日）不提供延遲退房服務。</li></ul><span>蜜月與結婚週年額外禮遇：<br></span><ul><li>\r\n入住時浴缸上裝飾花瓣</li><li>\r\n床鋪蜜月佈置與迎賓蛋糕</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n禁止在12月31日退房。</li><li>\r\n在旺季期间（7月15日 - 8月31日 以及12月23日 - 1月5日）不提供延迟退房服务。</li></ul><span>蜜月与结婚纪念日额外礼遇：<br></span><ul><li>\r\n抵达时浴缸撒花瓣</li><li>\r\n床上蜜月装饰及迎宾蛋糕</li></ul>', NULL, NULL, NULL, 'Active', '1712896298_cover.webp', 14, 'https://www.kamandaluresort.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/YzVoocsopdYQduTv7', NULL, NULL, NULL, NULL, '<span><b>Normal &amp; Low Season&nbsp;</b><i>(01 Apr - 14 Jul, 01 Sep - 22 Dec, 06 Jan - 11 Feb, 23 Feb - 31 Mar) :</i>&nbsp;<b>&nbsp;</b></span><ul><li>30 days prior to arrival: Not applicable&nbsp;</li><li>29 - 14 days prior to arrival: 1 night cancellation fee from the cancelled room or night\'s&nbsp;</li><li>13 - 7 days prior to arrival: Full cancellation fee from the cancelled room or night\'s&nbsp;</li></ul><span><b>High &amp; Peak Season&nbsp;</b><i>(15 Jul - 31 Aug, 23 Dec - 05 Jan, 12 - 22 Feb) :</i></span><ul><li>60 days prior to arrival: Not applicable&nbsp;</li><li>59 - 30 days: 1 night cancellation fee from the cancelled room or night\'s&nbsp;</li><li>29 - 21 days: Full cancellation fee from the cancelled room or night\'s&nbsp;</li></ul>', NULL, NULL, NULL, '2024-04-11 21:31:38', '2025-07-15 23:45:36', 1, 1),
(123, 'Nusa Dua Beach Hotel & Spa, Bali', '17', NULL, NULL, NULL, 'lSg8560pfTae30r6Nv4PWkIp1S', '17', NULL, 'Kawasan Pariwisata Nusa Dua Lot. North 4, Jl. Nusa Dua, Benoa, South Kuta, Badung Regency, Bali 80363', 1, 15, 'Pitri Jayanti', '0361771210', 'Nusa Dua Beach Hotel &amp; Spa is located on Bali’s southern peninsula, just 15 minutes from Ngurah Rai International Airport via the Bali Mandara toll road. The hotel has welcomed kings and queens, presidents and other dignitaries over the years. Each guestroom is decorated with authentic Balinese furnishing and offers stunning views of manicured tropical gardens or vistas of the ocean from the terrace or balcony. The 5-star Nusa Dua Beach Hotel &amp; Spa, Bali features 3 outdoor pools and direct beach access. The resort resembles a Balinese palace with complete&nbsp;<a target=\"_blank\" rel=\"nofollow\" href=\"https://www.nusaduahotel.com/facility/spa/\">Spa facilities</a>, 4 Restaurants, and 4 Bars.', '努沙杜瓦海灘度假村及水療中心位於峇里島南半島，距離伍拉·賴國際機場僅15分鐘車程，可經由峇里曼達拉高速公路直達。多年來，酒店曾迎接過國王、王后、總統以及眾多貴賓。每間客房皆配有道地的峇里島風格傢俱，並可透過私人露臺或陽台欣賞繁茂熱帶花園美景或壯麗海景。\r\n這家五星級度假村設有三座室外泳池、直通海灘的便利通道以及世界級設施。努沙杜瓦海灘度假村及水療中心宛如一座峇里島皇宮，並配備完善的水療中心、四間精緻餐廳及四個活力酒吧。', '努沙杜瓦海滩度假村及水疗中心位于巴厘岛南半岛，距离伍拉·赖国际机场仅15分钟车程，经由巴厘曼达拉高速公路直达。多年来，酒店曾接待过国王、王后、总统以及众多贵宾。每间客房都配有地道的巴厘岛风格家具，并可通过私人露台或阳台欣赏郁郁葱葱的热带花园美景或壮丽的海景。\r\n这家五星级度假村设有三座室外泳池、直通海滩的便捷通道以及世界一流的设施。努沙杜瓦海滩度假村及水疗中心宛如一座巴厘岛宫殿，配备完善的水疗中心、四间精致餐厅以及四个活力酒吧。', NULL, NULL, NULL, '<b>For staying over the New Year’s Eve of 31 December 2025:</b> <br><ul><li>Minimum stay of 3 nights is required</li><li>NO check-out on 31 December</li><li>Compulsory New Year’s Eve Dinner on 31 December 2025 will apply.&nbsp;</li></ul>', '跨年夜（2025年12月31日）入住規定：\r\n<ul>\r\n<li>\r\n需至少入住3晚\r\n</li>\r\n<li>\r\n2025年12月31日當天不可退房\r\n</li>\r\n<li>\r\n2025年12月31日需強制參加新年夜晚宴</li></ul>', '跨年夜（2025年12月31日）入住规定：\r\n<ul>\r\n<li>\r\n需至少入住3晚\r\n</li>\r\n<li>\r\n2025年12月31日当天不可退房\r\n</li>\r\n<li>\r\n2025年12月31日需强制参加新年夜晚宴</li></ul>', NULL, NULL, NULL, 'inactive', '1756180772_2024-01-18.webp', 14, 'http://www.nusaduahotel.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/8TmHPQsR4P6TmYft8', NULL, NULL, NULL, NULL, '<b>(01 Sep&nbsp;- 24 Dec\'25, 06 Jan - 13 Feb\'26, 21 Feb - 31 Mar\'26) :&nbsp;</b><br><ul><li>7 days prior to arrival : One night\'s stay&nbsp;</li><li>Less than 7 days prior to arrival : 50% of full length of stay&nbsp;</li><li>Same day / No Show : Full length of stay&nbsp;</li></ul><b>(26 - 31 Aug\'25, 25 Dec\'25 - 05 Jan\'26) :&nbsp;</b><br><ul><li>30 days prior to arrival : One night\'s stay&nbsp;</li><li>Less than 30 days prior to arrival : 50% of full length of stay&nbsp;</li><li>Same day / No Show : Full length of stay&nbsp;</li></ul><b>CNY Period (14 - 20 Feb\'26) :</b><br><ul><li>45 days prior to arrival : One night\'s stay&nbsp;</li><li>Less than 45 days prior to arrival : 50% of full length of stay&nbsp;</li><li>Same day / No Show : Full length of stay&nbsp;</li></ul>', '2025年9月1日 – 12月24日，2026年1月6日 – 2月13日，2026年2月21日 – 3月31日）：\r\n<ul>\r\n<li>\r\n抵達日前7天：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前少於7天：收取全程住宿費用的50%\r\n</li>\r\n<li>\r\n當天取消 / 未入住（No Show）：收取全程住宿費用\r\n</li>\r\n</ul>\r\n（2025年8月26日 – 8月31日，2025年12月25日 – 2026年1月5日）：\r\n<ul>\r\n<li>\r\n抵達日前30天：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前少於30天：收取全程住宿費用的50%\r\n</li>\r\n<li>\r\n當天取消 / 未入住（No Show）：收取全程住宿費用\r\n</li>\r\n</ul>\r\n春節期間（2026年2月14日 – 2月20日）：\r\n<ul>\r\n<li>\r\n抵達日前45天：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前少於45天：收取全程住宿費用的50%\r\n</li>\r\n<li>\r\n當天取消 / 未入住（No Show）：收取全程住宿費用</li></ul>', '（2025年9月1日 – 12月24日，2026年1月6日 – 2月13日，2026年2月21日 – 3月31日）：\r\n<ul>\r\n<li>\r\n抵达日前7天：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前少于7天：收取全程住宿费用的50%\r\n</li>\r\n<li>\r\n当天取消 / 未入住（No Show）：收取全程住宿费用\r\n</li>\r\n</ul>\r\n（2025年8月26日 – 8月31日，2025年12月25日 – 2026年1月5日）：\r\n<ul>\r\n<li>\r\n抵达日前30天：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前少于30天：收取全程住宿费用的50%\r\n</li>\r\n<li>\r\n当天取消 / 未入住（No Show）：收取全程住宿费用\r\n</li>\r\n</ul>\r\n春节期间（2026年2月14日 – 2月20日）：\r\n<ul>\r\n<li>\r\n抵达日前45天：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前少于45天：收取全程住宿费用的50%\r\n</li>\r\n<li>\r\n当天取消 / 未入住（No Show）：收取全程住宿费用</li></ul>', NULL, '2024-04-14 20:26:52', '2026-03-24 18:26:55', 1, 1),
(124, 'Sanctoo Suites & Villas', '17', NULL, NULL, NULL, 'tVTTRMY1cv7Mo8a98C2UYrwLnC', '17', NULL, 'Jalan Ulun Suwi II, Singapadu, Kec. Sukawati, Kabupaten Gianyar, Bali 80582', 1, 29, 'Agus Suarjana', '03614711222', 'Home of the ExtraordinaryEscape into a sophisticated sanctuary where the river rushes past your doorstep, where happiness radiates and smile is a language of our genuineness; An open door to the excitement of extraordinary journeys.', '非凡之所，幸福之源<br>\r\n逃離日常，進入一處精緻的靜謐天地，讓潺潺河水從門前流過，幸福在此綻放，微笑成為我們真誠待客的語言；這裡，是通往非凡旅程的敞開之門。', '非凡之地，幸福之源<br>\r\n逃離喧囂，走進一處精緻的靜謐之所，河水在門前流淌，幸福在這裡洋溢，微笑是我們真誠的語言；這是一扇通往非凡旅程的大門。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;<br></b><ul><li>Check-out not allowed on 31 December&nbsp;</li><li>No check-in/check-out permitted on 29 March 2025 (Nyepi Day) </li></ul><b>Honeymoon/Wedding Anniversary:&nbsp;</b><ul><li>Bed adomed with flower petals upon arrival&nbsp;</li><li>Special Honeymoon or Wedding Anniversary cake&nbsp;</li><li>Personalized greeting card&nbsp;</li></ul><b>Birthday:&nbsp;</b><ul><li>Special Birthday cake&nbsp;</li><li>Personalized Greeting card&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月31日不允許辦理退房</li><li>\r\n2025年3月29日（靜居日 Nyepi）不允許辦理入住與退房</li></ul>蜜月／結婚週年紀念：\r\n<ul>\r\n<li>\r\n抵達時床鋪以花瓣裝飾\r\n</li>\r\n<li>\r\n特別蜜月或結婚週年蛋糕\r\n</li>\r\n<li>\r\n客製化祝賀卡片\r\n</li>\r\n</ul>\r\n生日：\r\n<ul>\r\n<li>\r\n特別生日蛋糕\r\n</li>\r\n<li>\r\n客製化祝賀卡片</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n12月31日不允许退房</li><li>\r\n2025年3月29日（靜居日 Nyepi）不允许办理入住和退房</li></ul>蜜月／结婚周年纪念：\r\n<ul>\r\n<li>\r\n抵达时床铺装饰花瓣\r\n</li>\r\n<li>\r\n特别蜜月或结婚周年蛋糕\r\n</li>\r\n<li>\r\n个性化贺卡\r\n</li>\r\n</ul>\r\n生日：\r\n<ul>\r\n<li>\r\n特别生日蛋糕\r\n</li>\r\n<li>\r\n个性化贺卡</li></ul>', NULL, NULL, NULL, 'Active', '1737428095_Cover.jpg', 14, 'http://www.sanctoo.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/MkDH19RDkDDoV7Qw8', NULL, NULL, NULL, NULL, 'One night cancellation fee will be occurred for cancelation made.<ul><li>14 days – 7 days of arrival (Low season period 06 Jan - 14 Jul &amp; 01 Sep - 19 Dec)</li><li>21 days – 14 days of arrival (High and Peak season period&nbsp;01 Jul - 31 Aug &amp; 20 Dec - 05 Jan)</li></ul>Full night-100% from the entire amount will be applied for cancellation made.<ul><li>Less 7 days or No-show (Low season period&nbsp;06 Jan - 14 Jul &amp; 01 Sep - 19 Dec)</li><li>Less 14 Days or No Show (Peak &amp; High season period&nbsp;01 Jul - 31 Aug &amp; 20 Dec - 05 Jan)</li></ul>', '如在以下期間內取消預訂，將產生一晚取消費用：\r\n<ul>\r\n<li>\r\n低季期間（1月6日 - 7月14日 &amp; 9月1日 - 12月19日）：抵達前14至7天內取消\r\n</li>\r\n<li>\r\n旺季與尖峰季期間（7月1日 - 8月31日 &amp; 12月20日 - 1月5日）：抵達前21至14天內取消\r\n</li>\r\n</ul>\r\n如在以下期間取消預訂，將收取全額住宿費（100%）：\r\n<ul>\r\n<li>\r\n低季期間：少於7天取消或未出現（No-show）\r\n</li>\r\n<li>\r\n旺季與尖峰季期間：少於14天取消或未出現（No-show）\r\n</li>\r\n</ul>', '如在以下期間內取消預訂，將產生一晚的取消費：\r\n<ul>\r\n<li>\r\n淡季期間（1月6日 - 7月14日 &amp; 9月1日 - 12月19日）：抵達前14至7天取消\r\n</li>\r\n<li>\r\n旺季與高峰季期間（7月1日 - 8月31日 &amp; 12月20日 - 1月5日）：抵達前21至14天取消\r\n</li>\r\n</ul>\r\n如在以下期間取消預訂，將收取全額住宿費（100%）：\r\n<ul>\r\n<li>\r\n淡季期間：少於7天內取消或未出現（No-show）\r\n</li>\r\n<li>\r\n旺季與高峰季期間：少於14天內取消或未出現（No-show）</li></ul>', NULL, '2024-10-08 20:01:37', '2025-07-15 23:32:02', 1, 1),
(125, 'Novotel Bali Nusa Dua', '17', NULL, NULL, NULL, 'pqBERwAdEr288dz9ERXCQUvr6c', '17', NULL, 'Jl. Pantai Mengiat, Benoa, Kec. Kuta Sel., Bali, 80363', 1, 14, 'Ngurah Surya Aditya', '03618480555', 'Situated in the prestigious ITDC Nusa Dua with a secure gate, Novotel Bali Nusa Dua features 173 modern and spacious rooms with spacious terraces or balconies as well as apartment suites complete with kitchenettes, living and dining areas. A stunning 1,500 m² lagoon pool set amidst tropical gardens and a private beach club with panoramic sunrise views ensure the ultimate resort experience. As part of the MyResorts program, Novotel Bali Nusa Dua offers exclusive experiences for Le Club AccorHotels members.', '位於尊貴的努沙杜瓦ITDC區，並設有安全門禁，巴里島努沙杜瓦諾富特酒店擁有173間現代寬敞的客房，設有寬敞的露台或陽台，以及配備小廚房、客廳和餐廳區的套房公寓。佔地1,500平方米的壯麗潟湖泳池環繞熱帶花園，以及可欣賞日出美景的私人沙灘俱樂部，確保您享有極致的度假體驗。作為 MyResorts 計畫的一部分，巴里島努沙杜瓦諾富特酒店為 AccorHotels 樂雅會會員提供專屬體驗。', '位于尊贵的努沙杜瓦ITDC区域，并设有安全门禁，巴厘岛努沙杜瓦诺富特酒店拥有173间现代宽敞的客房，设有宽敞的露台或阳台，以及配备小厨房、客厅和餐厅区的套房公寓。占地1,500平方米的壮丽潟湖泳池环绕热带花园，以及可欣赏日出美景的私人沙滩俱乐部，确保您享有极致的度假体验。作为 MyResorts 计划的一部分，巴厘岛努沙杜瓦诺富特酒店为 AccorHotels 乐雅会会员提供专属体验。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1731997611_zkqj9br33twuhlslk6n.webp', 14, 'https://all.accor.com/lien_externe.svlt?goto=fiche_hotel&code_hotel=6328&merchantid=seo-maps-ID-6328&sourceid=aw-cen&utm_medium=seo%20maps&utm_source=google%20Maps&utm_campaign=seo%20maps', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/QPuM7CVnVUH32cby6', NULL, NULL, NULL, NULL, '<b>High &amp; Peak Season Period:&nbsp;</b><ul><li>For cancellations received inside 14 days prior to arrival date one (1) night cancellation at contracted rate will be charged&nbsp;</li><li>For cancellations received inside 7 days of arrival, the hotel will apply a charge equivalent to 50% of the contracted rate for the entire stay&nbsp;</li><li>For cancellations received inside 3 days of arrival the hotel will apply a charge equivalent to 100% of the contracted rate for the entire stay&nbsp;</li><li>For reservations amendments which shorten the stay or and or no-show, the same cancellation conditions will apply&nbsp;</li></ul><b>Low Season Period:&nbsp;</b><ul><li>For cancellations received inside 7 days prior to arrival date one (1) night cancellation at contracted rate will be charged&nbsp;</li><li>For cancellations received inside 6 days of arrival, the hotel will apply a charge equivalent to 50% of the contracted rate for the entire stay&nbsp;</li><li>For cancellations received inside 3 days of arrival the hotel will apply a charge equivalent to 100% to the contracted rate for the entire stay&nbsp;</li><li>For reservation amendments which shorten the stay or and or no-show, the same cancellation conditions will apply&nbsp;</li></ul>', '旺季與尖峰季節期間：\r\n<ul>\r\n<li>\r\n若在抵達日期前14天內取消，將收取1晚房費（依合約價格）。\r\n</li>\r\n<li>\r\n若在抵達日前7天內取消，將收取整段住宿費用的50%（依合約價格）。\r\n</li>\r\n<li>\r\n若在抵達日前3天內取消，將收取整段住宿費用的100%（依合約價格）。\r\n</li>\r\n<li>\r\n若修改訂房（縮短住宿天數）或未入住，亦將依上述取消條款處理。\r\n</li>\r\n</ul>\r\n淡季期間：\r\n<ul>\r\n<li>\r\n若在抵達日期前7天內取消，將收取1晚房費（依合約價格）。\r\n</li>\r\n<li>\r\n若在抵達日前6天內取消，將收取整段住宿費用的50%（依合約價格）。\r\n</li>\r\n<li>\r\n若在抵達日前3天內取消，將收取整段住宿費用的100%（依合約價格）。\r\n</li>\r\n<li>\r\n若修改訂房（縮短住宿天數）或未入住，亦將依上述取消條款處理。</li></ul>', '旺季与高峰季期间：\r\n<ul>\r\n<li>\r\n若在抵达日期前14天内取消，将收取1晚房费（按合约价格）。\r\n</li>\r\n<li>\r\n若在抵达日前7天内取消，将收取整个住宿期间费用的50%（按合约价格）。\r\n</li>\r\n<li>\r\n若在抵达日前3天内取消，将收取整个住宿期间费用的100%（按合约价格）。\r\n</li>\r\n<li>\r\n若修改预订（缩短住宿天数）或未入住，同样适用上述取消条款。\r\n</li>\r\n</ul>\r\n淡季期间：\r\n<ul>\r\n<li>\r\n若在抵达日期前7天内取消，将收取1晚房费（按合约价格）。\r\n</li>\r\n<li>\r\n若在抵达日前6天内取消，将收取整个住宿期间费用的50%（按合约价格）。\r\n</li>\r\n<li>\r\n若在抵达日前3天内取消，将收取整个住宿期间费用的100%（按合约价格）。\r\n</li>\r\n<li>\r\n若修改预订（缩短住宿天数）或未入住，同样适用上述取消条款。</li></ul>', NULL, '2024-10-11 02:48:38', '2026-03-24 18:26:55', 1, 1),
(126, 'Test Hotel', '17', NULL, NULL, NULL, 'JF1r0dvDJjV4pFKLL9HQX6SAAS', '17', NULL, 'Denpasar', 15, 2, 'Ms. Abc', '1234567890', '<p>asasd</p>', NULL, NULL, '<p>asdad</p>', NULL, NULL, '<p>asdasasd</p>', NULL, NULL, NULL, NULL, NULL, 'inactive', '1731664527_Birmingham Alabama Wedding Planner _ Coaching for Wedding Businesses (1).webp', 2, 'www.aaaaaa', '2', '360', NULL, NULL, 'https://goo.gl/maps/WPHoALzdQaJWdWrx7', NULL, NULL, NULL, NULL, '<p>asdasd</p>', NULL, NULL, NULL, '2024-11-15 01:55:27', '2026-03-24 18:26:55', 2, 1),
(127, 'Impiana Private Villas Seminyak', '17', NULL, NULL, NULL, 'KBt76ISM4AfCQEANEvOvunAPR7', '17', NULL, 'Jl. Kunti I No.118X, Seminyak, Kec. Kuta, Kabupaten Badung, Bali 80361', 1, 10, 'Desy Antari', '0361730840', 'Bali is dubbed as “The Island of the Gods”, renowned for its breathtaking natural beauty as well as the cultural richness that entices travelers to entreat in. Among the to-go lists within the island is Seminyak, boasting the vibrant atmosphere with some of the most astounding beaches in Bali. Experience all-around sensory indulgence with world-class dining destinations, a variety of luxury spa treatments, high-end shopping spots, and exquisite nightlife.Conveniently nestled within walking distance from Seminyak’s beaches are the forty-eight exclusive villas of Impiana Private Villas Seminyak that are perfect for individual travelers, couples, families, and groups who seek an idyllic destination in the midst of lively Seminyak.Be immersed in a luxurious experience like no other that Impiana Private Villas Seminyak has to offer.', '峇里島被譽為「眾神之島」，以令人屏息的自然美景及豐富的文化魅力吸引著世界各地旅人。島上熱門的旅遊地點之一為水明漾（Seminyak），以其充滿活力的氛圍與令人驚艷的海灘聞名。在這裡，您可盡情享受世界級的美食饗宴、多樣化的頂級水療療程、奢華購物及精緻夜生活，帶來全方位的感官盛宴。\r\n<span>Impiana Private Villas Seminyak 擁有 48 棟獨棟別墅，步行即可抵達水明漾海灘，地理位置極為便利。無論是獨自旅行、情侶度假、家庭旅遊或團體出行，皆能在熱鬧的水明漾中心找到一處理想的世外桃源。<br>\r\n沉浸於 Impiana Private Villas Seminyak 所帶來的無與倫比奢華體驗中，開啟一段難忘的旅程。</span>', '巴厘岛被誉为“众神之岛”，不仅拥有令人惊叹的自然美景，也以其丰富的文化魅力吸引着无数旅人。在岛上的热门目的地之一——水明漾（Seminyak），您将感受到充满活力的氛围以及巴厘岛最迷人的海滩之一。这里汇聚了世界级的美食餐厅、多样化的奢华水疗、高端购物场所和精彩夜生活，带来全方位的感官享受。\r\n<span>Impiana Private Villas Seminyak 拥有48栋专属别墅，地理位置优越，步行即可到达水明漾海滩。无论是单人旅行、情侣度假、家庭出游或团体聚会，这里都是您在热闹水明漾中心寻找宁静世外桃源的理想之地。<br>\r\n在 Impiana Private Villas Seminyak，尽情享受一场别具一格的奢华体验。</span>', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Minimum 5 nights stay within the period of 27th December 2025 – 03rd January 2026. No check out on 31st December 2025 and 01st January 2026.</li><li>Pleased be informed that Bali Island celebrates Nyepi (Silent) Day, a Balinese “Day of Silence” on 19 March 2026. No outdoor activities are allowed on that day, including no check in and no check out</li></ul><b>Honeymoon Benefits:</b><br><ul><li>Honeymoon decoration in the villa with “Honeymooners” notification must be indicated upon making reservation.</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n2025年12月27日至2026年1月3日期間，最少需入住5晚。2025年12月31日與2026年1月1日不可辦理退房手續。</li><li>\r\n敬請注意，峇里島將於2026年3月19日慶祝**「靜居日（Nyepi Day）」，這是一個峇里島的「靜默之日」。在該日禁止一切戶外活動，包括辦理入住與退房**。</li></ul><span>蜜月福利：<br></span><ul><li>\r\n別墅內將進行蜜月佈置，預訂時須註明為「蜜月旅客（Honeymooners）」。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n2025年12月27日至2026年1月3日期间，最少需入住5晚。2025年12月31日及2026年1月1日不可办理退房手续。</li><li>\r\n请注意，巴厘岛将在2026年3月19日庆祝宁静日（Nyepi Day），这是一年一度的“沉默日”。当天不允许进行任何户外活动，包括入住和退房。</li></ul><span>蜜月礼遇：<br></span><ul><li>\r\n别墅将进行蜜月布置，预订时必须注明“蜜月旅客（Honeymooners）”身份。</li></ul>', NULL, NULL, NULL, 'Active', '1732607152_WhatsApp Image 2024-11-26 at 15.40.45.jpeg', 14, 'https://www.impianaseminyak.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/D7DCVy3vNj5ExVNi7', NULL, NULL, NULL, NULL, '<b>Low Season: </b>01 Nov - 22 Dec, 06 Jan - 31 Mar&nbsp;<br><b>Shoulder Season:</b> 01 Apr - 31 May, 01 Sep - 31 Oct&nbsp;<br><b>High Season:</b> 01 Jun - 31 Aug&nbsp;<br><b>Peak Season:</b> 23 Dec - 05 Jan&nbsp;<ul><li>Cancellations made within 45 days of arrival during low season or 60 days of arrival during shoulder and high season or 75 days of arrival during peak season will result in a cancellation fee of 1 (one) night accommodation.</li><li>Cancellations made within 21 days of arrival during low season or 30 days of arrival during shoulder and high season or 45 days of arrival during peak season will result in a cancellation fee of 50% of the total invoice.</li><li>Cancellations made within 3 days of arrival during any season will result in a cancellation fee of 100% of the complete invoice.</li><li>No show without prior cancellation notification will be charged at 100% of the total invoice. In case of early check-out, 100% of the remaining nights will be charged.</li></ul>', '<span>淡季：11月1日 - 12月22日、1月6日 - 3月31日<br>\r\n肩季：4月1日 - 5月31日、9月1日 - 10月31日<br>\r\n旺季：6月1日 - 8月31日<br>\r\n巔峰季：12月23日 - 1月5日</span>\r\n<ul>\r\n<li>\r\n若於淡季抵達前45天內、肩季與旺季抵達前60天內、或巔峰季抵達前75天內取消預訂，將收取 1晚房費作為取消費用。\r\n</li>\r\n<li>\r\n若於淡季抵達前21天內、肩季與旺季抵達前30天內、或巔峰季抵達前45天內取消預訂，將收取 總帳單金額的50%。\r\n</li>\r\n<li>\r\n任何季節，若於抵達前3天內取消，將收取 總帳單金額的100%。\r\n</li>\r\n<li>\r\n若未提前取消並未入住（No Show），將收取 總帳單金額的100%。\r\n</li>\r\n<li>\r\n若提前退房，剩餘晚數也將收取100%費用。</li></ul>', '<span>淡季：11月1日 - 12月22日、1月6日 - 3月31日<br>\r\n肩季：4月1日 - 5月31日、9月1日 - 10月31日<br>\r\n旺季：6月1日 - 8月31日<br>\r\n高峰季：12月23日 - 1月5日</span>\r\n<ul>\r\n<li>\r\n如果在淡季抵达前45天内、肩季和旺季抵达前60天内、或高峰季抵达前75天内取消预订，将收取 1晚房费作为取消费用。\r\n</li>\r\n<li>\r\n如果在淡季抵达前21天内、肩季和旺季抵达前30天内、或高峰季抵达前45天内取消预订，将收取 总账单金额的50%。\r\n</li>\r\n<li>\r\n任何季节，如在抵达前3天内取消，将收取 总账单金额的100%。\r\n</li>\r\n<li>\r\n若未提前通知取消并未入住（No Show），将收取 总账单金额的100%。\r\n</li>\r\n<li>\r\n若提前退房，剩余晚数也将全额收费。</li></ul>', NULL, '2024-11-25 23:45:52', '2025-07-15 22:45:32', 1, 1),
(128, 'Nusa Dua Bayview', '17', NULL, NULL, NULL, 'C1rLV3rqzcamm2iAOjjKaAfxTG', '17', NULL, 'Jl. Dharmawangsa No.19A, Benoa, Kec. Kuta Sel., Kabupaten Badung, Bali 80361', 1, 15, 'Doli Nafati Tela', '0817565756', 'Discover opulent living at Nusa Dua Bayview—a luxury villa seamlessly integrating contemporary architecture with elegant interiors, ensuring utmost privacy and a delightful ambiance.', '探索努沙杜瓦海景灣的奢華生活——這座豪華別墅完美融合現代建築與優雅內飾，確保極致隱私與愉悅氛圍。', '探索努沙杜瓦海景湾的奢华生活——这座豪华别墅完美融合现代建筑与优雅内饰，确保极致私密与愉悦氛围', NULL, NULL, NULL, '<span><b>Seasonal Policy:</b>&nbsp;<br></span><ul><li>NYE Compulsory Dinner policy for children age 0-4 years is free of charge and 5 – 11 Y.O. is chargeable (Price: TBA)&nbsp;</li></ul><b>Child Policy:&nbsp;</b><br><ul><li>No extra bed and baby cot Up to 2 children 0-4 years old sharing the same bed with parents or using existing bed are free of charge, children 5-11 y.o are chargeable for extra child, Children aged 12 years and older are considered adults and will be charged an additional fee, which includes breakfast and an extra bed.</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n跨年夜強制性晚宴政策：0–4歲兒童免費，5–11歲兒童需收費（價格待定）</li></ul><span>兒童政策：<br></span><ul><li>\r\n不提供加床與嬰兒床。最多可有2位0–4歲兒童與父母共床或使用現有床鋪，免費入住；5–11歲兒童需支付額外兒童費用；12歲及以上的兒童視同成人，需支付額外費用，費用已包含早餐與加床服務。</li></ul>', '<span>季节性政策：<br></span><ul><li>\r\n跨年夜强制晚宴政策：0–4岁儿童免费，5–11岁儿童需收费（价格待定）</li></ul><span>儿童政策：<br></span><ul><li>\r\n不提供加床和婴儿床。最多允许2位0–4岁儿童与父母共床或使用现有床铺免费入住；5–11岁儿童将按额外儿童收费；12岁及以上儿童视为成人，需支付额外费用，费用包括早餐及加床服务。</li></ul>', NULL, NULL, NULL, 'Active', '1733119199_Nusa Dua Bayview.jpg', 14, 'https://www.nusaduabayview.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/Hv46RRoh7CQt246b9', NULL, NULL, NULL, NULL, '<ul><li>One night rate will be charged for any cancellation made within 14 days prior to each guest arrival in low season. (06 Jan - 31 Jun, 01 Sep - 20 Dec)&nbsp;</li><li>One night rate will be charged for any cancellation made within 30 days prior to each to each guest arrival in high season. (1 July - 31 August)</li><li>Full night’s rate or equal to 100% of total room nights booked will be charged for any no show or cancellation made within 24 hours.</li><li>The group cancellation policy is referring to the agreement made on confirmation letter</li></ul>', '<ul><li>在淡季（1月6日至6月30日、9月1日至12月20日）內，如於入住日前14天內取消，將收取一晚房費作為取消費用。</li><li>\r\n在旺季（7月1日至8月31日）內，如於入住日前30天內取消，將收取一晚房費作為取消費用。</li><li>\r\n若於入住日前24小時內取消或未入住（No Show），將收取全數房晚費用或相當於總訂房金額的100%。</li><li>\r\n團體訂房之取消條款以確認信中所列之協議為準。</li></ul>', '<ul><li>在淡季（1月6日至6月30日、9月1日至12月20日），如在入住日前14天内取消，将收取一晚房费作为取消费用。</li><li>\r\n在旺季（7月1日至8月31日），如在入住日前30天内取消，将收取一晚房费作为取消费用。</li><li>\r\n若在入住日前24小时内取消或未入住（No Show），将收取全部房晚费用或相当于总预订金额的100%。</li><li>\r\n团队预订的取消政策以确认函中所达成的协议为准。</li></ul>', NULL, '2024-12-01 21:59:59', '2025-07-15 22:33:37', 1, 1),
(129, 'Regent Bali Canggu', '17', NULL, NULL, NULL, 'IhDBKvRbCTqgKSU9yiex6QIvxy', '17', NULL, 'Jl. Pantai Batu Bolong No.93xx, Canggu, Kec. Kuta Utara, Kabupaten Badung, Bali 80361', 1, 21, 'Ratika Dewi', '03612019999', 'A coastal haven where Bali\'s spirit unravelsOn Canggu Beach, surfers are silhouetted in the morning sun, boards under arms ready to take on Bali\'s famous reef breaks.&nbsp;Watching the waves, listening to the call of the Indian Ocean, you might catch the scent of incense or the melody of the gamelan emitting from Pura Batu Mejan, a centuries old sea temple set on rock as black as jet. A blessed way to begin each day.', '一處海岸天堂，展現峇里島的靈魂<br>\r\n在蒼古海灘，衝浪者身影映照於晨光中，挾著衝浪板準備挑戰峇里著名的礁岩浪潮。凝視浪花、聆聽印度洋的呼喚，你或許能聞到祭拜的香氣，或聽見峇里島傳統甘美朗樂音從古老的巴圖梅詹海神廟（Pura Batu Mejan）傳來，那座廟宇矗立於如黑玉般的岩石之上。如此祝福的一天，自此展開。', '一处海岸天堂，展现巴厘岛的灵魂<br>\r\n在苍古海滩，冲浪者在晨曦中留下身影，怀抱冲浪板，准备迎接巴厘岛著名的礁石浪潮。凝视海浪，聆听印度洋的呼唤，你或许能闻到香火的气息，或听见从古老的巴图梅詹海神庙（Pura Batu Mejan）传来的甘美朗乐曲，那座海神庙静立于如黑曜石般的岩石之上。如此被祝福的一天，就此开启。', 'In room features and amenities:&nbsp;<ul><li>Furnished balcony with dining table and day bed&nbsp;</li><li>Cocktail making accessories, including cocktail shaker&nbsp;</li><li>Kevala customised ceramic (tea cup &amp; tea pot)&nbsp;</li><li>English fine china and porcelain by Wedgwood&nbsp;</li><li>Sodashi skincare as in - room amenities&nbsp;</li><li>Pillow menu - selection of 5 pillow types&nbsp;</li><li>Dyson hairdryer&nbsp;</li><li>Nespresso coffee machine and capsules</li><li>Bath menu - a menu with curated bath ritualas (additional fees may be apply)&nbsp;</li></ul>', '客房內設施與備品：\r\n<ul>\r\n<li>\r\n配有餐桌與躺椅的家具陽台\r\n</li>\r\n<li>\r\n雞尾酒調製配件（含搖酒器）\r\n</li>\r\n<li>\r\nKevala 客製陶瓷（茶杯與茶壺）\r\n</li>\r\n<li>\r\n英國 Wedgwood 高級骨瓷餐具\r\n</li>\r\n<li>\r\nSodashi 護膚品作為客房備品\r\n</li>\r\n<li>\r\n枕頭選單 —— 提供5種枕頭選擇\r\n</li>\r\n<li>\r\nDyson 吹風機\r\n</li>\r\n<li>\r\nNespresso 咖啡機與膠囊\r\n</li>\r\n<li>\r\n沐浴選單 —— 精選沐浴儀式體驗（可能需額外付費）</li></ul>', '客房内设施与备品：\r\n<ul>\r\n<li>\r\n配有餐桌和躺椅的家具阳台\r\n</li>\r\n<li>\r\n鸡尾酒调制配件（含摇酒器）\r\n</li>\r\n<li>\r\nKevala 定制陶瓷（茶杯与茶壶）\r\n</li>\r\n<li>\r\n英国 Wedgwood 高级骨瓷餐具\r\n</li>\r\n<li>\r\nSodashi 护肤品作为客房用品\r\n</li>\r\n<li>\r\n枕头菜单 —— 提供5种枕头选择\r\n</li>\r\n<li>\r\nDyson 吹风机\r\n</li>\r\n<li>\r\nNespresso 咖啡机及胶囊\r\n</li>\r\n<li>\r\n沐浴菜单 —— 精选沐浴仪式（可能需额外付费）</li></ul>', '<b>Seasonal Policy:</b>&nbsp;<ul><li>A minimum length of stay of 3 nights is applicable from 28 Dec - 04 Jan&nbsp;</li><li>No check-out allowed on 31 Dec 2025&nbsp;</li><li>Respecting the Balinese Nyepi Celebration (Silent Day) on 19 Mar 2026, the resort will not be able to service guest arriving/departing. Guests staying over the mentioned dates will be able to enjoy the resort facilities with discretion&nbsp;</li></ul><b>Honeymoon Benefits:&nbsp;</b><br>Honeymoon stay dates must fall within 12 months of the wedding date and applicable for all periods. A valid marriage certificate is required and must be provided at the time of booking. The benefits can be combined with other discount.&nbsp;<ul><li>Personalised welcome card&nbsp;</li><li>A specially crafted welcome cake for two&nbsp;</li><li>Complimentary&nbsp;bottle of wine provided upon arrival&nbsp;</li></ul>', '季節性政策：\r\n<ul>\r\n<li>\r\n2025年12月28日至2026年1月4日期間，需至少入住3晚\r\n</li>\r\n<li>\r\n2025年12月31日不可辦理退房\r\n</li>\r\n<li>\r\n為尊重峇里島的靜寂日（Nyepi）慶祝活動，於2026年3月19日當天，度假村將無法提供客人辦理入住與退房服務。當天留宿的賓客仍可於度假村內有限度地使用設施\r\n</li>\r\n</ul>\r\n蜜月福利：\r\n<ul>\r\n<li>\r\n蜜月入住日期須為結婚日期起12個月內，適用於所有期間\r\n</li>\r\n<li>\r\n預訂時須出示有效的結婚證明文件\r\n</li>\r\n<li>\r\n此優惠可與其他折扣併用\r\n</li>\r\n<li>\r\n專屬歡迎卡\r\n</li>\r\n<li>\r\n為二人特製的歡迎蛋糕\r\n</li>\r\n<li>\r\n抵達時提供一瓶免費葡萄酒</li></ul>', '季节政策：\r\n<ul>\r\n<li>\r\n2025年12月28日至2026年1月4日期间，最低入住需为3晚\r\n</li>\r\n<li>\r\n2025年12月31日不可办理退房\r\n</li>\r\n<li>\r\n为尊重巴厘岛的安寧日（Nyepi）庆祝活动，2026年3月19日当日，度假村将无法为客人办理入住或退房手续。入住期间的客人仍可在度假村内酌情使用设施\r\n</li>\r\n</ul>\r\n蜜月礼遇：\r\n<ul>\r\n<li>\r\n蜜月入住日期需在结婚日期起12个月内，适用于所有时间段\r\n</li>\r\n<li>\r\n预订时需提供有效的结婚证书\r\n</li>\r\n<li>\r\n可与其他优惠组合使用\r\n</li>\r\n<li>\r\n个性化欢迎卡\r\n</li>\r\n<li>\r\n为两人精心准备的欢迎蛋糕\r\n</li>\r\n<li>\r\n抵达时赠送一瓶葡萄酒</li></ul>', NULL, NULL, NULL, 'Active', '1734058079_0. Cover.jpeg', 14, 'https://www.ihg.com/regent/hotels/us/en/bali/dpscr/hoteldetail?cm_mmc=YextLocal-_--_-ID-_-DPSCR', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/8EEdUwU2SkK3ri9V9', NULL, NULL, NULL, NULL, '<span><b>Normal Season</b>&nbsp;<i>(01 Apr - 19 Dec, 11 Jan - 31 Mar):</i></span><ul><li>First Night Cancellation Policy: 7 Days&nbsp;</li><li>Entire Stay Cancellation Policy: 24 Hours, No Show, Early Departure&nbsp;</li></ul><b>High Season:&nbsp;</b><ul><li>First Night Cancellation Policy: 21&nbsp;Days&nbsp;</li><li>Entire Stay Cancellation Policy: 7 Days, No Show, Early Departure</li></ul><span><b>Peak Season</b>&nbsp;(20 Dec - 10 Jan):</span><ul><li>First Night Cancellation Policy: 30&nbsp;Days&nbsp;</li><li>Entire Stay Cancellation Policy: 21 Days, No Show, Early Departure</li></ul>', '平季（4月1日 - 12月19日、1月11日 - 3月31日）：\r\n<ul>\r\n<li>\r\n首晚取消政策：提前7天\r\n</li>\r\n<li>\r\n全部住宿取消政策：提前24小時、未入住（No Show）、提前退房\r\n</li>\r\n</ul>\r\n旺季：\r\n<ul>\r\n<li>\r\n首晚取消政策：提前21天\r\n</li>\r\n<li>\r\n全部住宿取消政策：提前7天、未入住、提前退房\r\n</li>\r\n</ul>\r\n巔峰季（12月20日 - 1月10日）：\r\n<ul>\r\n<li>\r\n首晚取消政策：提前30天\r\n</li>\r\n<li>\r\n全部住宿取消政策：提前21天、未入住、提前退房\r\n</li>\r\n</ul>', '普通季节（4月1日 - 12月19日，1月11日 - 3月31日）：\r\n<ul>\r\n<li>\r\n首晚取消政策：提前7天\r\n</li>\r\n<li>\r\n全部住宿取消政策：提前24小时、未入住（No Show）、提前退房\r\n</li>\r\n</ul>\r\n旺季：\r\n<ul>\r\n<li>\r\n首晚取消政策：提前21天\r\n</li>\r\n<li>\r\n全部住宿取消政策：提前7天、未入住、提前退房\r\n</li>\r\n</ul>\r\n巅峰季节（12月20日 - 1月10日）：\r\n<ul>\r\n<li>\r\n首晚取消政策：提前30天\r\n</li>\r\n<li>\r\n全部住宿取消政策：提前21天、未入住、提前退房</li></ul>', NULL, '2024-12-12 18:47:59', '2025-07-15 22:13:24', 1, 1),
(130, 'Bintang Flores Hotel', '17', 'Labuan Bajo', 'Nusa Tenggara Timur', 'Indonesia', 'shrCVC0FQFjZBAeHObFLFEzKF8', '17', 30, 'Jalan Pantai Pede, Wae Mata, Labuan Bajo, Nusa Tenggara Timur, Indonesia', 1, 3, 'Nonik', '03852443755', 'The Bintang Flores Hotel is a five-storey hotel set in a spacious tropical garden. Drawing on Indonesian architectural influences, The Bintang Flores Hotel combines local style and charm with modern conveniences and international standards of service. With a large swimming pool and private white-sand beach, the hotel offers complete water-sports facilities in a protected environment suitable for families.', 'Bintang Flores Hotel 是一棟五層樓的飯店，坐落於寬敞的熱帶花園中。飯店融合印尼建築風格與當地特色魅力，同時結合現代便利設施與國際級服務標準。擁有大型游泳池與私人白沙灘，飯店提供完善的水上活動設施，為家庭旅客打造一個安全舒適的環境。', 'Bintang Flores Hotel 是一家五层楼高的酒店，坐落在宽敞的热带花园中。酒店融合印尼建筑风格与本地特色魅力，同时结合现代化便利设施与国际服务标准。配有大型游泳池和私人白沙滩，酒店提供完善的水上运动设施，为家庭旅客打造一个安全舒适的环境。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'active', 'hotels/covers/1738036297_213591633.jpg', 14, 'https://bintangfloreshotel.com/', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Bintang+Flores+Hotel/@-8.5108349,119.8743341,17z/data=!3m1!4b1!4m9!3m8!1s0x2db37469e06f52f1:0x96854237c9fcd0c8!5m2!4m1!1i2!8m2!3d-8.5108402!4d119.876909!16s%2Fg%2F121v8hcx?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.5106536, 119.8763246, NULL, NULL, NULL, NULL, NULL, NULL, '2025-01-27 19:51:37', '2026-03-25 19:23:35', 1, 2),
(131, 'Tejaprana Resort & Spa', '17', NULL, NULL, NULL, '5sOk7afsVe55ZQj4leff73TZjH', '17', NULL, 'Jl. Raya Tegallalang, Banjar Sapat, Kecamatan Ubud, Kabupaten Gianyar, Bali 80561', 2, 44, 'Dewa Ayu Indira', '03619080939', '<span>Tejaprana Resort &amp; Spa is snuggly nestled in the&nbsp;<a target=\"_blank\" rel=\"nofollow\" href=\"https://www.tejapranaresort.com/location/\">lush jungles of the Petanu</a>&nbsp;river valley in Tegallalang, a mere 4 kilometers from the lively cultural town of Ubud. Designed by an award winning Balinese architect renown for his ability in creating serene spaces immersed with Balinese Taksu, or life quintessence, let Tejaprana Resort &amp; Spa be your space to clear mind and spirit.</span>Start the day basking in the morning sun as it breaks the jungle treetop of the river valley across the resort.<span>Tejaprana Resort &amp; Spa comprises&nbsp;<a target=\"_blank\" rel=\"nofollow\" href=\"https://www.tejapranaresort.com/rooms/\">28 cozily furnished villas</a>, all facing east allowing you to take full advantage of the warmth and benefits of the morning sun. Each villa is complemented with a gazebo, an infinity plunge pool and an outdoor natural stone bathtub bringing you yet closer to the Balinese landscape embracing the resort. Tejaprana Resort and Spa is designed by&nbsp;<a target=\"_blank\" rel=\"nofollow\" href=\"http://www.artearchitect.com/\">Arte Architect and Associates</a>.</span>', 'Tejaprana Resort &amp; Spa 座落於德哥拉朗（Tegallalang）佩塔努河谷（Petanu River Valley）茂密的叢林中，距離充滿文化氣息的烏布城僅約4公里。這座度假村由屢獲殊榮的峇里建築師精心打造，以其能夠營造充滿「Taksu」（峇里語中代表生命精髓）氛圍的寧靜空間而聞名。讓 Tejaprana Resort &amp; Spa 成為您清理心靈與精神的靜謐之地。\r\n清晨時分，當陽光灑落穿透度假村對面的河谷樹梢，展開嶄新的一天。Tejaprana Resort &amp; Spa 擁有28間溫馨別墅，全數朝東，讓您充分享受晨光的溫暖與滋養。每間別墅皆配備涼亭、無邊際冷水池與天然石材打造的戶外浴缸，讓您更親近環繞度假村的峇里自然景觀。\r\nTejaprana Resort &amp; Spa 由 Arte Architect and Associates 精心設計。', '<div><div><div><div><div><div>Tejaprana Resort &amp; Spa 坐落在德哥拉朗（Tegallalang）佩塔努河谷（Petanu River Valley）郁郁葱葱的丛林中，距离充满文化氛围的乌布仅约4公里。度假村由屡获殊荣的巴厘岛建筑师设计，以其打造充满巴厘“灵气”（Taksu，即生命精髓）氛围的宁静空间而闻名。Tejaprana Resort &amp; Spa 将成为您放松心灵、净化精神的理想之所。\r\n清晨，阳光透过河谷对岸的树冠洒下，为您开启美好的一天。Tejaprana Resort &amp; Spa 拥有28间温馨别墅，全部朝东而建，让您充分沐浴在清晨阳光的温暖中。每间别墅皆配有凉亭、无边际冷水池和天然石材户外浴缸，让您更贴近环绕度假村的巴厘自然景致。\r\nTejaprana Resort &amp; Spa 由 Arte Architect and Associates 设计打造。</div></div></div></div></div></div><div></div>', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>Compulsory dinner: TBA&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n強制性晚宴：待定</li></ul>', '季节性政策：<br><ul><li>\r\n强制性晚宴：待定</li></ul>', NULL, NULL, NULL, 'Active', '1738546760_Cover.jpg', 14, 'http://www.tejapranaresort.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/NoNTqkvBieddQAvv9', NULL, NULL, NULL, NULL, '<ul><li>Cancellations of room reservation made 14 days or more in advance of the check in date, will receive a 100% refund</li><li>Cancellations made within 8 - 13 days will incur a 30% fee.</li><li>Cancellations made 7 days or less of the check in date will NO RECEIVE any refund</li></ul>', '<ul><li>在入住日期前14天或以上取消訂房，可獲100%全額退款。</li><li>\r\n於入住日前8至13天內取消，將收取30%取消手續費。</li><li>\r\n若於入住日前7天內取消，將不予任何退款。</li></ul>', '<ul><li>在入住日期前14天或以上取消订房，可获得100%全额退款。</li><li>\r\n在入住日前8至13天内取消，将收取30%取消手续费。</li><li>\r\n如在入住日前7天内取消，将不予任何退款。</li></ul>', NULL, '2025-02-02 17:39:20', '2025-07-15 22:08:10', 1, 1),
(132, 'Tejaprana Bisma', '17', NULL, NULL, NULL, 'ih3RjFnurJsWviqxAJ4tbbMFCL', '17', NULL, 'Jl. Bisma, Ubud, Kecamatan Ubud, Kabupaten Gianyar, Bali 80571', 43, 2, 'Dewa Ayu Indira', '03616207070', 'Escape to our luxuriously comfortable villas, seamlessly blending contemporary elegance with lush landscapes. Immerse yourself in nature’s embrace, indulging in serenity that creates an idyllic peaceful hideaway.', '逃離塵囂，入住我們奢華舒適的別墅，現代優雅與鬱鬱蔥蔥的自然景致完美融合。沉浸於大自然的懷抱，享受寧靜氛圍，締造如詩如畫的靜謐天堂。', '<div><div><div><div><div>远离喧嚣，入住我们奢华舒适的别墅，现代优雅与郁郁葱葱的自然景观完美融合。沉浸于大自然的怀抱，尽享宁静时光，打造理想的静谧度假天堂。</div></div></div></div><div><div><div><div></div></div></div></div></div><div><br></div>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1738548697_Cover.jpg', 14, 'https://www.tejapranabisma.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/yJFdJ5ZouckQfVCNA', NULL, NULL, NULL, NULL, '<ul><li>Cancellations of room reservation made 14 days or more in advance of the check in date, will receive a 100% refund</li><li>Cancellations made within 8 - 13 days will incur a 30% fee</li><li>Cancellations made 7 days or less of the check in date will NO RECEIVE any refund</li></ul>', '<ul><li>在入住日前14天或以上取消訂房，可獲100%退款。</li><li>\r\n入住日前8至13天內取消，將收取30%手續費。</li><li>\r\n入住日前7天或以內取消，將不予退款。</li></ul>', '<ul><li>在入住日前14天或以上取消订房，可获得100%退款。</li><li>\r\n入住日前8至13天内取消，将收取30%手续费。</li><li>\r\n入住日前7天或以内取消，将不予退款。</li></ul>', NULL, '2025-02-02 18:11:37', '2025-07-15 19:45:02', 1, 1),
(133, 'Episode Kuta', '17', NULL, NULL, NULL, 'weNj3DVZfePEJJzWBBnOYTUdfG', '17', NULL, 'Jl. Bypass Ngurah Rai No.99, Kuta, Kec. Kuta, Kabupaten Badung, Bali 80362', 1, 7, 'Gani', '03618948999', 'A short 10-minute drive from Ngurah Rai International Airport, Episode Kuta Bali is the ideal location of choice for both business and leisure travelers. Located in the central area of Simpang Dewa Ruci and connected to Bali Galleria Shopping Mall, the hotel is only a 15-minute drive to Kuta with its beautiful beaches, the fun-filled Waterbom Park, and entertainment areas of Legian &amp; Seminyak areas. The hotel is also within easy reach to a number of other attraction areas of Nusa Dua, Jimbaran, Sanur, Ubud, and Tanah Lot. Episode Kuta Bali offers 178 rooms with a modern chic design offering high-speed WIFI Internet connectivity, an all-day dining restaurant, poolside bar, signature lap pool, gym, kids\' corner, spa, internet corner, and meeting rooms.', '距離伍拉·賴國際機場僅需短短10分鐘車程，Episode Kuta Bali 是商務與休閒旅客的理想下榻地點。酒店位於Simpang Dewa Ruci的核心地段，並與峇里島Galleria購物中心相連，開車15分鐘即可抵達庫塔迷人的海灘、充滿樂趣的Waterbom水上樂園，以及樂揚和水明漾的娛樂區。酒店同時也方便前往努沙杜瓦、金巴蘭、沙努爾、烏布和海神廟等多個著名景點。\r\nEpisode Kuta Bali 提供178間現代時尚設計的客房，設有高速無線網路、全日制餐廳、池畔酒吧、標誌性泳池、健身房、兒童遊戲區、Spa、網路區以及多功能會議室，滿足各類旅客的需求。', '距离伍拉·赖国际机场仅需10分钟车程，Episode Kuta Bali 是商务与休闲旅客的理想选择。酒店位于Simpang Dewa Ruci 中心地带，并与巴厘岛Galleria购物中心相连，开车15分钟即可到达库塔迷人的海滩、充满乐趣的Waterbom水上乐园，以及雷吉安和水明漾的娱乐区。酒店还可轻松前往努沙杜瓦、金巴兰、沙努尔、乌布和海神庙等多个热门景点。\r\nEpisode Kuta Bali 提供178间现代时尚设计的客房，配备高速无线网络、全日餐厅、池畔酒吧、标志性泳池、健身房、儿童角、SPA、水疗区、网吧和会议室，全方位满足旅客所需。', NULL, NULL, NULL, '<b>Seasonal Policy:&nbsp;</b><ul><li>No check out 31 December 2025</li><li>31 December 2025 have compulsory dinner, all guest stay must be join this dinner&nbsp;</li><li>Rate 31 December 2025 is include for Compulsory Dinner&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n2025年12月31日不可辦理退房。</li><li>\r\n2025年12月31日需參加強制性晚宴，所有入住賓客皆須參與。</li><li>\r\n2025年12月31日的房價已包含強制性晚宴費用。</li></ul>', '季节性政策：<br><ul><li>\r\n2025年12月31日不可办理退房。</li><li>\r\n2025年12月31日需参加强制性晚宴，所有入住宾客必须参加。</li><li>\r\n2025年12月31日的房价已包含强制性晚宴费用。</li></ul>', NULL, NULL, NULL, 'Active', '1739165931_cover.jpg', 14, 'https://episodekutabali.jhlcollections.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/3RR4Mjw1QhBWKdxK6', NULL, NULL, NULL, NULL, '<b>Low, High &amp; Peak Season Period:&nbsp;</b><ul><li>Any cancellation made less than 3 days prior to arrival or no show : 1 night of the initial booking will be charged.</li><li>Should a guest check in and would like to leave before the end of his stay, a 100% cancellation fee will be applied on the remaining of the stay&nbsp;</li></ul>', '<span>淡季、旺季與巔峰季期間：<br></span><ul><li>\r\n如在抵達日前3天內取消或未入住，將收取原訂房1晚的費用。</li><li>\r\n若客人在入住後提前退房，剩餘住宿天數將收取100%取消費用。</li></ul>', '淡季、旺季及高峰季期间：<br><ul><li>\r\n如在抵达日前3天内取消或未入住，将收取原预订1晚的费用。</li><li>\r\n若客人入住后提前退房，剩余住宿天数将收取100%取消费用。</li></ul>', NULL, '2025-02-09 21:38:51', '2025-07-15 19:43:00', 1, 1),
(134, 'Potato Head Suites & Studios', '17', NULL, NULL, NULL, 'jCkOUcRcA9oK1dWZiICzV8ANfF', '17', NULL, 'Jl. Petitenget No.51B, Seminyak, Kec. Kuta Utara, Kabupaten Badung, Bali 80361', 1, 14, 'Erwan Chandra', '03616207979', '<div><span style=\"font-size: 14.4px;\">Welcome to Desa Potato Head,</span></div><div><span style=\"font-size: 14.4px;\">a cultural village rooted in craft, community, and regeneration.</span></div><div><span style=\"font-size: 14.4px;\">Stay, play, nourish, and create—cultivating culture through the art of good times.</span></div>', '歡迎來到 Desa Potato Head，<br data-start=\"287\" data-end=\"290\">\r\n一個以手工藝、社區與再生為根基的文化村。<br data-start=\"310\" data-end=\"313\">\r\n在這裡住宿、娛樂、滋養與創造——<br data-start=\"329\" data-end=\"332\">\r\n透過美好時光的藝術培育文化。', '<p>欢迎来到 Desa Potato Head，<br data-start=\"155\" data-end=\"158\">\r\n一个以手工艺、社区和再生为根基的文化村。<br data-start=\"178\" data-end=\"181\">\r\n在这里住宿、娱乐、滋养与创造——<br data-start=\"197\" data-end=\"200\">\r\n通过美好时光的艺术来培育文化</p>', NULL, NULL, NULL, '<p><b>Honeymoon Perks:&nbsp;</b></p><ol><li>Special room decorations set-up with fresh flowers&nbsp;</li><li>One-time complimentary cake&nbsp;</li></ol>', '<p><strong data-start=\"175\" data-end=\"184\">蜜月禮遇：</strong><br data-start=\"184\" data-end=\"187\">\r\n• 客房特別浪漫佈置，搭配新鮮花卉<br data-start=\"204\" data-end=\"207\">\r\n• 一次性免費蛋糕一份</p>', '<p><strong data-start=\"260\" data-end=\"269\">蜜月礼遇：</strong><br data-start=\"269\" data-end=\"272\">\r\n• 客房特别浪漫布置，搭配新鲜花卉<br data-start=\"289\" data-end=\"292\">\r\n• 一次性免费蛋糕一份</p>', NULL, NULL, NULL, 'inactive', '1761547756_244284475.jpg', 14, 'https://seminyak.potatohead.co/', '2', '360', NULL, NULL, 'https://maps.app.goo.gl/8BgPTpfnBfumga2r5', NULL, NULL, NULL, NULL, '<p><b>Low Season (04 Jan - 30 Jun, 01 - 30 Sep): </b></p><ol><li>Within 14 days of arrival : 1 night penalty </li><li>Within 7 days of arrival : 100% penalty charged </li></ol><p><b>High Season (01 Jul - 31 Aug): </b></p><ol><li>Within 30 days of arrival : 1 night penalty </li><li>Within 14 days of arrival : 100% penalty charged <br></li></ol><p>No Show: Clients who do not show will be charged for the entire length of stay. </p>', '<div><p data-start=\"131\" data-end=\"175\"><strong data-start=\"131\" data-end=\"173\">淡季（1 月 4 日－6 月 30 日、9 月 1 日－9 月 30 日）：</strong></p>\r\n<ul data-start=\"176\" data-end=\"232\">\r\n<li data-start=\"176\" data-end=\"204\">\r\n<p data-start=\"178\" data-end=\"204\">入住前 14 天內取消：收取 1 晚房費作為罰金</p>\r\n</li>\r\n<li data-start=\"205\" data-end=\"232\">\r\n<p data-start=\"207\" data-end=\"232\">入住前 7 天內取消：收取 100% 全額罰金</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"234\" data-end=\"261\"><strong data-start=\"234\" data-end=\"259\">旺季（7 月 1 日－8 月 31 日）：</strong></p>\r\n<ul data-start=\"262\" data-end=\"319\">\r\n<li data-start=\"262\" data-end=\"290\">\r\n<p data-start=\"264\" data-end=\"290\">入住前 30 天內取消：收取 1 晚房費作為罰金</p>\r\n</li>\r\n<li data-start=\"291\" data-end=\"319\">\r\n<p data-start=\"293\" data-end=\"319\">入住前 14 天內取消：收取 100% 全額罰金</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"321\" data-end=\"340\"><strong data-start=\"321\" data-end=\"338\">未入住（No Show）：</strong></p>\r\n<ul data-start=\"341\" data-end=\"364\">\r\n<li data-start=\"341\" data-end=\"364\">\r\n<p data-start=\"343\" data-end=\"364\">未如期入住之客人，將被收取全程住宿費用</p></li></ul></div>', '<div><p data-start=\"404\" data-end=\"448\"><strong data-start=\"404\" data-end=\"446\">淡季（1 月 4 日－6 月 30 日、9 月 1 日－9 月 30 日）：</strong></p>\r\n<ul data-start=\"449\" data-end=\"505\">\r\n<li data-start=\"449\" data-end=\"477\">\r\n<p data-start=\"451\" data-end=\"477\">入住前 14 天内取消：收取 1 晚房费作为罚金</p>\r\n</li>\r\n<li data-start=\"478\" data-end=\"505\">\r\n<p data-start=\"480\" data-end=\"505\">入住前 7 天内取消：收取 100% 全额罚金</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"507\" data-end=\"534\"><strong data-start=\"507\" data-end=\"532\">旺季（7 月 1 日－8 月 31 日）：</strong></p>\r\n<ul data-start=\"535\" data-end=\"592\">\r\n<li data-start=\"535\" data-end=\"563\">\r\n<p data-start=\"537\" data-end=\"563\">入住前 30 天内取消：收取 1 晚房费作为罚金</p>\r\n</li>\r\n<li data-start=\"564\" data-end=\"592\">\r\n<p data-start=\"566\" data-end=\"592\">入住前 14 天内取消：收取 100% 全额罚金</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"594\" data-end=\"613\"><strong data-start=\"594\" data-end=\"611\">未入住（No Show）：</strong></p>\r\n<ul data-start=\"614\" data-end=\"634\" data-is-last-node=\"\" data-is-only-node=\"\">\r\n<li data-start=\"614\" data-end=\"634\" data-is-last-node=\"\">\r\n<p data-start=\"616\" data-end=\"634\" data-is-last-node=\"\">未按期入住的客人将被收取全程住宿费用</p></li></ul></div>', NULL, '2025-02-10 19:29:55', '2026-03-24 18:21:00', 1, 1),
(135, 'Meruorah Komodo Labuan Bajo', '17', NULL, NULL, NULL, '1R65wK01gn2vM1kk4PutNTPojx', '17', NULL, 'Kawasan Marina, Jl. Soekarno Hatta, Labuan Bajo, Kec. Komodo, Kabupaten Manggarai Barat, Nusa Tenggara Tim. 86711', 1, 3, 'Sonja Tomasowa', '03852440234', 'Meruorah Komodo Labuan Bajo is your gateway to island-hopping adventures and the breathtaking landscapes of Flores. Conveniently located in the heart of downtown Labuan Bajo, our 5-star hotel is situated within the same complex as Plaza Marina, a vibrant commercial area featuring a variety of dining options, retail stores, a pharmacy, and banking facilities.Just a 10-minute drive from Komodo Airport, Meruorah Komodo Labuan Bajo offers seamless access to local culinary streets, the bustling harbor for island excursions, and the legendary Komodo dragons. Whether you’re here for exploration or relaxation, our hotel serves as an exclusive retreat where you can unwind while embracing stunning panoramic views.', 'Meruorah Komodo Labuan Bajo 是您展開跳島冒險與探索弗洛勒斯壯麗景觀的絕佳起點。酒店位於 Labuan Bajo 鬧區的核心地帶，地理位置便利，與熱鬧的 Plaza Marina 商業區為同一園區，該商圈擁有多樣化的餐飲選擇、零售商店、藥局及銀行設施。<br>\r\n距離科莫多機場僅10分鐘車程，Meruorah Komodo Labuan Bajo 為您提供便捷通達的本地美食街、跳島之旅的港口，以及傳奇的科莫多巨蜥。不論您是為了探險或放鬆而來，酒店都是一處專屬靜謐的休憩天堂，讓您在享受壯麗全景之際放慢步調。', 'Meruorah Komodo Labuan Bajo 是您开启跳岛探险和欣赏弗洛勒斯壮丽风光的理想门户。酒店位于 Labuan Bajo 市中心的核心地带，位置便利，坐落于与 Plaza Marina 同一商业区内，该区域拥有多样化的餐饮选择、零售商店、药房及银行设施。<br>\r\n距离科莫多机场仅10分钟车程，Meruorah Komodo Labuan Bajo 为前往本地美食街、跳岛码头以及传奇科莫多巨蜥的探访提供无缝连接。不论您是来探险还是放松，酒店都是一个专属的静谧度假之所，让您在欣赏迷人全景的同时尽情放松身心。', NULL, NULL, NULL, '<b>Seasonal Policy:</b>&nbsp;<ul><li>Compulsory New Year Eve Dinner 31 December 2025 (Price at additional charge)&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n2025年12月31日需參加強制性新年前夕晚宴（需額外收費）</li></ul>', '季节性政策：<br><ul><li>\r\n2025年12月31日须参加强制性新年前夜晚宴（需额外收费）</li></ul>', NULL, NULL, NULL, 'Active', '1739252825_meruorah-komodo-labuan.jpg', 14, 'https://meruorahlabuanbajo.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/Sn9U4S6GHE2TcEkY8', NULL, NULL, NULL, NULL, '<ul><li>Up to 10 rooms and/or low season : 30 days prior to arrival&nbsp;</li><li>More than 10 rooms and/or high season and/or peak season : 60 days prior to arrival&nbsp;</li></ul>', '<ul><li>最多10間房且/或淡季：須於抵達日前30天取消</li><li>\r\n超過10間房且/或旺季及/或巔峰季：須於抵達日前60天取消</li></ul>', '最多10间房且/或淡季：需在抵达日前30天取消<br>\r\n超过10间房且/或旺季及/或高峰季：需在抵达日前60天取消', NULL, '2025-02-10 21:47:05', '2025-07-15 19:34:53', 1, 1),
(136, 'Sudamala Resort Sanur', '17', NULL, NULL, NULL, 'c0QPG88n1Sy5Dm51bPbaI2Mt5Z', '17', NULL, 'Jl. Sudamala No.20, Sanur Kauh, Denpasar Selatan, Kota Denpasar, Bali 80227', 1, 15, 'Adi Gunawan', '0361288555', 'Sudamala Sanur Cultural elegance in serene Bali. Immerse in Taksu at our spacious, inviting retreat.', 'Sudamala Sanur，峇里島寧靜中的文化優雅之所。沉浸於我們寬敞而溫馨的度假天地，體驗真正的「Taksu」（靈性魅力）。', 'Sudamala Sanur，峇里岛宁静之中展现文化优雅。沉浸于我们宽敞舒适的度假天地，感受真正的“Taksu”（灵性魅力）。', '<ul><li>Swimming Pool&nbsp;</li><li>Restaurant&nbsp;</li><li>Spa&nbsp;</li><li>Yoga Pavilion&nbsp;</li><li>Reserved Beach Area&nbsp;</li><li>Sudakara Art and function space&nbsp;</li><li>Meeting room and function space&nbsp;</li></ul>', '<ul><li>游泳池</li><li>\r\n餐廳</li><li>\r\n水療中心</li><li>\r\n瑜伽亭</li><li>\r\n專屬沙灘區</li><li>\r\nSudakara 藝術與多功能空間</li><li>\r\n會議室與多功能空間</li></ul>', '<ul><li>游泳池</li><li>\r\n餐厅</li><li>\r\n水疗中心</li><li>\r\n瑜伽亭</li><li>\r\n专属沙滩区</li><li>\r\nSudakara 艺术及多功能空间</li><li>\r\n会议室及多功能空间</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1739328133_Cover.png', 14, 'https://www.sudamalaresorts.com/resort/sudamala-resort-sanur/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/Zc7v3vLiAAkmD2748', NULL, NULL, NULL, NULL, '<span><b>Low, Shoulder Season</b><i> (01 - 30 Apr, 01 May - 14 Jul, 01 Sep - 31 Oct, 01 Nov - 26 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>14 - 04 days prior to arrival : One night\'s charge&nbsp;</li><li>03 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><span><b>High Season</b><i> (15 Jul - 31 Aug) :&nbsp;</i></span><ul><li>30 - 15 days prior to arrival : One night\'s charge&nbsp;</li><li>14 - 08 days prior to arrival : 50% charge of total room night reserved&nbsp;</li><li>07 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><span><b>Peak Season</b> <i>(27 Dec - 05 Jan) :&nbsp;</i></span><ul><li>45 - 30&nbsp;days prior to arrival : One night\'s charge&nbsp;</li><li>29 - 08 days prior to arrival : 50% charge of total room night reserved&nbsp;</li><li>07 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><b>All Season :</b><ul><li>No Show/ Early Departure : Full charge of total room night reserved</li></ul>', '淡季／肩季（4月1日－4月30日、5月1日－7月14日、9月1日－10月31日、11月1日－12月26日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達日前14至4天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前3至1天取消：收取全數預訂房晚費用\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日）：\r\n<ul>\r\n<li>\r\n抵達日前30至15天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前14至8天取消：收取總房費的50%\r\n</li>\r\n<li>\r\n抵達日前7至1天取消：收取全數預訂房晚費用\r\n</li>\r\n</ul>\r\n巔峰季（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達日前45至30天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前29至8天取消：收取總房費的50%\r\n</li>\r\n<li>\r\n抵達日前7至1天取消：收取全數預訂房晚費用\r\n</li>\r\n</ul>\r\n<span>所有季節：<br>\r\n未入住／提前退房：收取全數預訂房晚費用</span>', '淡季／肩季（4月1日－4月30日、5月1日－7月14日、9月1日－10月31日、11月1日－12月26日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达日前14至4天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前3至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日）：\r\n<ul>\r\n<li>\r\n抵达日前30至15天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前14至8天取消：收取总房费的50%\r\n</li>\r\n<li>\r\n抵达日前7至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n巅峰季节（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达日前45至30天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前29至8天取消：收取总房费的50%\r\n</li>\r\n<li>\r\n抵达日前7至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n<span>所有季节通用：<br>\r\n未入住／提前退房：收取全部预订房晚费用</span>', NULL, '2025-02-11 18:42:13', '2025-07-15 19:30:43', 1, 1);
INSERT INTO `hotels` (`id`, `name`, `location`, `city`, `province`, `country`, `code`, `region`, `destination_id`, `address`, `airport_duration`, `airport_distance`, `contact_person`, `phone`, `description`, `description_traditional`, `description_simplified`, `facility`, `facility_traditional`, `facility_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `wedding_info`, `entrance_fee`, `wedding_cancellation_policy`, `status`, `cover`, `author_id`, `web`, `min_stay`, `max_stay`, `check_in_time`, `check_out_time`, `map`, `latitude`, `longitude`, `benefits`, `optional_rate`, `cancellation_policy`, `cancellation_policy_traditional`, `cancellation_policy_simplified`, `deleted_at`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES
(137, 'Sudamala Resort Seraya', '17', NULL, NULL, NULL, '9oRTrj6El1yiba6gun9y7HKPAz', '17', NULL, 'Pulau Seraya Kecil, Labuan Bajo, Kec. Komodo, Kabupaten Manggarai Barat, Nusa Tenggara Tim.', 3, 20, 'Adi Gunawan', '0361288555', 'Nestled on serene Seraya Kecil island, Sudamala Resort, Seraya in Flores-Komodo, Indonesia, offers authentic tropical barefoot resort. This tranquil sanctuary provides a secluded getaway amidst pristine natural wonders – translucent white sandy beaches, crystal-clear waters, and vibrant underwater life. A Robinson Crusoe experience unfolds, where unspoiled nature pampers every sense. Sudamala Resort, Seraya, elevates barefoot resort through simple details, inviting you to indulge in a relaxing holiday. Lounge on the private beach or by the beachfront saltwater pool, letting soft white sands cradle your feet.', '座落於寧靜的 Seraya Kecil 小島，印尼弗洛勒斯–科莫多地區的 Sudamala Resort, Seraya 提供一處純粹的熱帶赤足度假天堂。這片靜謐的避世之地坐擁未受破壞的自然奇景——潔白透亮的沙灘、水晶般清澈的海水與繽紛的海底世界，如同羅賓漢式的探險體驗，在這片原始大自然中，您的每一感官都將被溫柔寵愛。<br>\r\nSudamala Resort, Seraya 以細膩而簡約的細節提升赤足度假體驗，邀您沉浸於放鬆的假期時光。您可在私人海灘或面海的海水泳池旁悠閒休憩，讓柔軟的白沙輕拂雙足，盡享自然恩賜。', '坐落在宁静的 Seraya Kecil 小岛，印尼弗洛勒斯–科莫多地区的 Sudamala Resort, Seraya 提供纯正的热带赤足度假体验。这片宁静的世外桃源被原始自然奇观所环绕——洁白通透的沙滩、清澈见底的海水和绚丽的海底世界，仿佛一场鲁滨逊式的探险之旅，在未经雕琢的大自然中唤醒每一寸感官。<br>\r\nSudamala Resort, Seraya 以细致而简约的设计提升赤足度假体验，邀您享受惬意放松的假期。无论是在私人海滩上，还是在面朝大海的咸水泳池边躺卧，任由柔软白沙轻轻拥抱双足，皆可尽享自然与宁静的美好时光。', '<ul><li>Swimming Pool&nbsp;</li><li>Restaurant&nbsp;</li><li>Spa&nbsp;</li><li>Gym&nbsp;</li><li>Aqura Dive Center&nbsp;</li><li>Direct beach access&nbsp;</li><li>House reef&nbsp;</li></ul>', '<ul><li>游泳池</li><li>\r\n餐廳</li><li>\r\n水療中心</li><li>\r\n健身房</li><li>\r\nAqura 潛水中心</li><li>\r\n直通海灘通道</li><li>\r\n屋前珊瑚礁</li></ul>', '<ul><li>游泳池</li><li>\r\n餐厅</li><li>\r\n水疗中心</li><li>\r\n健身房</li><li>\r\nAqura 潜水中心</li><li>\r\n直通海滩通道</li><li>\r\n屋前珊瑚礁</li></ul>', '<b>Seasonal Policy :&nbsp;</b><ul><li>No check out on 31 December&nbsp;</li><li>Minimum stay of three (3) consecutive nights is required during peak season period (27 Dec - 05 Jan)&nbsp;</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月31日不允許退房</li><li>\r\n巔峰季期間（12月27日－1月5日）須至少連續入住三（3）晚</li></ul>', '季节性政策：<br><ul><li>\r\n12月31日不可退房</li><li>\r\n巅峰季期间（12月27日－1月5日）需至少连续入住三（3）晚</li></ul>', NULL, NULL, NULL, 'Active', '1739341707_cover.jpg', 14, 'http://www.sudamalaresorts.com/seraya/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/y38QncZxCiZmmgE86', NULL, NULL, NULL, NULL, '<span><b>Low, Shoulder Season</b> <i>(01 - 30 Apr, 01 May - 14 Jul, 01 Sep - 31 Oct, 01 Nov - 26 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>14 - 04 days prior to arrival : One night\'s charge&nbsp;</li><li>03 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><span><b>High Season</b> <i>(15 Jul - 31 Aug) :&nbsp;</i></span><ul><li>30 - 15 days prior to arrival : One night\'s charge&nbsp;</li><li>14 - 08 days prior to arrival : 50% charge of total room night reserved&nbsp;</li><li>07 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><span><b>Peak Season</b> (<i>27 Dec - 05 Jan) :&nbsp;</i></span><ul><li>45 - 30&nbsp;days prior to arrival : One night\'s charge&nbsp;</li><li>29 - 08 days prior to arrival : 50% charge of total room night reserved&nbsp;</li><li>07 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><b>All Season :</b><ul><li>No Show/ Early Departure : Full charge of total room night reserved</li></ul>', '淡季 / 肩季（4月1日－4月30日、5月1日－7月14日、9月1日－10月31日、11月1日－12月26日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達日前14至4天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前3至1天取消：收取全額預訂房晚費用\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日）：\r\n<ul>\r\n<li>\r\n抵達日前30至15天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前14至8天取消：收取總預訂房晚費用的50%\r\n</li>\r\n<li>\r\n抵達日前7至1天取消：收取全額預訂房晚費用\r\n</li>\r\n</ul>\r\n巔峰季節（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達日前45至30天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前29至8天取消：收取總預訂房晚費用的50%\r\n</li>\r\n<li>\r\n抵達日前7至1天取消：收取全額預訂房晚費用\r\n</li>\r\n</ul>\r\n<span>所有季節：<br></span><ul><li>\r\n未入住（No Show）/ 提早退房：收取全額預訂房晚費用</li></ul>', '<div>淡季 / 肩季（4月1日－4月30日、5月1日－7月14日、9月1日－10月31日、11月1日－12月26日、1月6日－3月31日）：</div><ul>\r\n<li>\r\n抵达日前14至4天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前3至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日）：\r\n<br><ul>\r\n<li>\r\n抵达日前30至15天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前14至8天取消：收取总预订房晚费用的50%\r\n</li>\r\n<li>\r\n抵达日前7至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n巅峰季节（12月27日－1月5日）：\r\n<br><ul>\r\n<li>\r\n抵达日前45至30天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前29至8天取消：收取总预订房晚费用的50%\r\n</li>\r\n<li>\r\n抵达日前7至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n所有季节通用：<br>\r\n未入住（No Show）/ 提前退房：收取全部预订房晚费用<br><div></div>', NULL, '2025-02-11 22:28:27', '2025-07-15 19:27:21', 1, 1),
(138, 'Sudamala Resort, Komodo Labuan Bajo', '17', NULL, NULL, NULL, 'FuTqtn9UlyqU5yb7ztCZXZVtC8', '17', NULL, 'Gorontalo, Jl. Pantai Pede No.Km. 3, Labuan Bajo, Kabupaten Manggarai Barat, Nusa Tenggara Tim. 86554', 1, 5, 'Adi Gunawan', '03852385555', 'Sudamala Resort, Komodo, Labuan Bajo, the gateway to Komodo National Park, adventurers to experience Flores’ wonders embracing local culture &amp; beauty.', 'Sudamala Resort, Komodo（位於拉布安巴佐），是通往科莫多國家公園的大門，邀請冒險者探索弗洛勒斯島的奇觀，並擁抱當地文化與自然之美。', 'Sudamala Resort, Komodo（位于拉布安巴佐），是通往科莫多国家公园的门户，邀您一同探索弗洛勒斯的奇迹，感受当地文化与自然之美。', '<ul><li>Swimming Pool&nbsp;</li><li>Beach Front Restaurant&nbsp;</li><li>Manta Cafe</li><li>Spa&nbsp;</li><li>Gym&nbsp;</li><li>Aqura Dive Center&nbsp;</li><li>Meeting room and function space&nbsp;</li><li>Direct beach access&nbsp;</li></ul>', '<ul><li>游泳池</li><li>\r\n海濱餐廳</li><li>\r\nManta 咖啡館</li><li>\r\n水療中心</li><li>\r\n健身房</li><li>\r\nAqura 潛水中心</li><li>\r\n會議室與多功能空間</li><li>\r\n直通海灘通道</li></ul>', '<ul><li>游泳池</li><li>\r\n海滨餐厅</li><li>\r\nManta 咖啡馆</li><li>\r\n水疗中心</li><li>\r\n健身房</li><li>\r\nAqura 潜水中心</li><li>\r\n会议室与多功能空间</li><li>\r\n直通海滩通道</li></ul>', '<b>Seasonal Policy :&nbsp;</b><ul><li>No check out on 31 December&nbsp;</li><li>Minimum stay of three (3) consecutive nights is required during peak season period (27 Dec - 05 Jan)&nbsp;</li></ul>', '季節性政策：<br><ul><li>\r\n12月31日不允許辦理退房</li><li>\r\n巔峰季期間（12月27日－1月5日）須至少連續入住三（3）晚</li></ul>', '季节性政策：<br><ul><li>\r\n12月31日不可办理退房</li><li>\r\n巅峰季期间（12月27日－1月5日）须至少连续入住三（3）晚</li></ul>', NULL, NULL, NULL, 'Active', '1739410886_Cover.jpg', 14, 'https://www.sudamalaresorts.com/resort/sudamala-resort-komodo/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/yxAUpgX88FuoBptG6', NULL, NULL, NULL, NULL, '<span><b>Low, Shoulder Season</b><i> (01 - 30 Apr, 01 May - 14 Jul, 01 Sep - 31 Oct, 01 Nov - 26 Dec, 06 Jan - 31 Mar) :&nbsp;</i></span><ul><li>14 - 04 days prior to arrival : One night\'s charge&nbsp;</li><li>03 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><span><b>High Season</b><i> (15 Jul - 31 Aug) :&nbsp;</i></span><ul><li>30 - 15 days prior to arrival : One night\'s charge&nbsp;</li><li>14 - 08 days prior to arrival : 50% charge of total room night reserved&nbsp;</li><li>07 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><span><b>Peak Season</b> <i>(27 Dec - 05 Jan) :&nbsp;</i></span><ul><li>45 - 30&nbsp;days prior to arrival : One night\'s charge&nbsp;</li><li>29 - 08 days prior to arrival : 50% charge of total room night reserved&nbsp;</li><li>07 - 01 days prior to arrival : Full charge of total room night reserved&nbsp;</li></ul><b>All Season :</b><ul><li>No Show/ Early Departure : Full charge of total room night reserved</li></ul>', '淡季 / 肩季（4月1日－4月30日、5月1日－7月14日、9月1日－10月31日、11月1日－12月26日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達日前14至4天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前3至1天取消：收取全部預訂房晚費用\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日）：\r\n<ul>\r\n<li>\r\n抵達日前30至15天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前14至8天取消：收取總房費的50%\r\n</li>\r\n<li>\r\n抵達日前7至1天取消：收取全部預訂房晚費用\r\n</li>\r\n</ul>\r\n巔峰季（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達日前45至30天取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前29至8天取消：收取總房費的50%\r\n</li>\r\n<li>\r\n抵達日前7至1天取消：收取全部預訂房晚費用\r\n</li>\r\n</ul>\r\n<span>所有季節通用：<br></span><ul><li>\r\n未入住（No Show）或提前退房：收取全部預訂房晚費用</li></ul>', '淡季 / 肩季（4月1日－4月30日、5月1日－7月14日、9月1日－10月31日、11月1日－12月26日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达日前14至4天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前3至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n旺季（7月15日－8月31日）：\r\n<ul>\r\n<li>\r\n抵达日前30至15天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前14至8天取消：收取总房费的50%\r\n</li>\r\n<li>\r\n抵达日前7至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n巅峰季节（12月27日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达日前45至30天取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前29至8天取消：收取总房费的50%\r\n</li>\r\n<li>\r\n抵达日前7至1天取消：收取全部预订房晚费用\r\n</li>\r\n</ul>\r\n<span>所有季节通用：<br></span><ul><li>\r\n未入住（No Show）或提前退房：收取全部预订房晚费用</li></ul>', NULL, '2025-02-12 17:41:26', '2025-07-15 19:22:19', 1, 1),
(139, 'Buahan, a Banyan Tree Escape', '17', 'Gianyar', 'Bali', 'Indonesia', 'JtqXbsWGlEeRbrOZQ207ByoGxU', '17', 17, 'Gianyar, Bali, Indonesia', 3, 55, 'Lina Suryati', '03616208181', '<p>This is a place where time passes at a different pace. A place to disconnect and reconnect in unfamiliar ways. Welcome to Buahan, a Banyan Tree Escape.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1739760571_Cover .png', 14, 'https://escape.banyantree.com/indonesia/buahan', '2', '45', NULL, NULL, 'https://www.google.com/maps/place/Buahan,+a+Banyan+Tree+Escape/@-8.3653677,115.2358969,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd221fd7746c2d3:0xe04e192e4db83f01!5m2!4m1!1i2!8m2!3d-8.365373!4d115.2384718!16s%2Fg%2F11j2427587?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.3655144, 115.2385919, NULL, NULL, '<p>Cancellation after bookings are made is subject 100% from the total room revenue&nbsp;</p>', NULL, NULL, NULL, '2025-02-16 18:49:31', '2026-03-25 19:24:24', 1, 2),
(140, 'Mahagiri Villas Sanur', '17', NULL, NULL, NULL, 'oVMJKpm9sttPpi4ijqDGmcrVax', '17', NULL, 'Jl. Pungutan No.31, Sanur, Denpasar Selatan, Kota Denpasar, Bali 80227', 1, 16, 'Crisna Dewi', '08113909088', 'Sanur makes a perfect alternative to the busy towns in the south of Bali such as Kuta and Seminyak. In town, there are lively streets full of boutique shops, restaurants, bars and beach bars. More and more people fall in love with this town that is great for cycling and exploring on foot.Hidden away in a quiet street in the heart of Sanur, Mahagiri Villas Sanur is a charming complex of 17 luxury villas designed to capture the essence of a traditional Balinese community in the spiritually charged village of Sanur. The exclusive villas are a well-balanced fusion of island artistry and modern elegance. The entire property is a boutique enclave encompassed within a landscape of tropical greenery.', '相較於峇里島南部熱鬧的庫塔（Kuta）和水明漾（Seminyak），沙努爾（Sanur）是一個絕佳的替代選擇。小鎮街道熱鬧非凡，擁有眾多精品店、餐廳、酒吧和海灘酒吧。越來越多旅人愛上這座適合騎行與徒步探索的小鎮。\r\n隱藏於沙努爾中心一條寧靜街道內，Mahagiri Villas Sanur 是一處迷人的度假村，由17棟豪華別墅組成，靈感來自傳統巴厘社區的精髓，坐落於這座充滿靈性氛圍的村落。這些獨立別墅巧妙融合島嶼藝術與現代優雅，是一處精品式秘境，被熱帶綠意所環繞，散發著恬靜而尊貴的氣息。', '相较于巴厘岛南部热闹的库塔（Kuta）和水明漾（Seminyak），沙努尔（Sanur）是一个完美的替代选择。镇上街道热闹非凡，遍布精品商店、餐厅、酒吧和海滩酒吧。越来越多的人爱上这座适合骑行和徒步探索的小镇。\r\n隐藏在沙努尔中心一条安静街道中，Mahagiri Villas Sanur 是一座迷人的度假村，由17栋豪华别墅组成，旨在捕捉传统巴厘社区的精神本质，坐落于这座充满灵性气息的村庄。这些独栋别墅是岛屿艺术与现代优雅的完美结合，整个度假区被热带绿意环绕，是一个专属的精品绿洲。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Active', '1739772027_Cover .png', 14, 'http://www.mahagirivillassanur.com/', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/eoiYiRL8CW1xHZjA6', NULL, NULL, NULL, NULL, '<b>Low Season</b> <i>(01 Apr - 31 May, 16 Sep - 19 Dec, 06 Jan - 31 Mar) :&nbsp;</i><ul><li>1 room night charges : 14 days&nbsp;</li><li>50% charges of total room night reserved : 7 days&nbsp;</li><li>100% charges of total room night reserved : 24 hours/no show&nbsp;</li><li>100% charges of total room night reserved : Early departure&nbsp;</li></ul><b>High Season</b><i> (01 Jun - 15 Sep, 20 Dec - 05 Jan) :&nbsp;</i><ul><li>1 room night charges : 21 days&nbsp;</li><li>50% charges of total room night reserved : 7 days&nbsp;</li><li>100% charges of total room night reserved : 24 hours/no show&nbsp;</li><li>100% charges of total room night reserved : Early departure&nbsp;&nbsp;</li></ul><b>Seasonal Policy :&nbsp;</b><ul><li>Compulsory New Year Dinner on 31 December 2025 (Price at additional charge)&nbsp;</li></ul>', '淡季（4月1日－5月31日、9月16日－12月19日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵達日前14天內取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前7天內取消：收取訂房總晚數費用的50%\r\n</li>\r\n<li>\r\n抵達前24小時內取消 / 未入住（No Show）：收取訂房總晚數費用的100%\r\n</li>\r\n<li>\r\n提早退房：收取訂房總晚數費用的100%\r\n</li>\r\n</ul>\r\n旺季（6月1日－9月15日、12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n抵達日前21天內取消：收取1晚房費\r\n</li>\r\n<li>\r\n抵達日前7天內取消：收取訂房總晚數費用的50%\r\n</li>\r\n<li>\r\n抵達前24小時內取消 / 未入住：收取訂房總晚數費用的100%\r\n</li>\r\n<li>\r\n提早退房：收取訂房總晚數費用的100%\r\n</li>\r\n</ul>\r\n<span>季節性政策：<br></span><ul><li>\r\n2025年12月31日須參加強制性跨年晚宴（費用另計）</li></ul>', '淡季（4月1日－5月31日、9月16日－12月19日、1月6日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达日前14天内取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前7天内取消：收取总预订房晚费用的50%\r\n</li>\r\n<li>\r\n抵达前24小时内取消 / 未入住（No Show）：收取总预订房晚费用的100%\r\n</li>\r\n<li>\r\n提前退房：收取总预订房晚费用的100%\r\n</li>\r\n</ul>\r\n旺季（6月1日－9月15日、12月20日－1月5日）：\r\n<ul>\r\n<li>\r\n抵达日前21天内取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达日前7天内取消：收取总预订房晚费用的50%\r\n</li>\r\n<li>\r\n抵达前24小时内取消 / 未入住：收取总预订房晚费用的100%\r\n</li>\r\n<li>\r\n提前退房：收取总预订房晚费用的100%\r\n</li>\r\n</ul>\r\n<span>季节性政策：<br></span><ul><li>\r\n2025年12月31日须参加强制性跨年晚宴（费用另计）</li></ul>', NULL, '2025-02-16 22:00:27', '2025-07-15 19:18:20', 1, 1),
(141, 'TA\'AKTANA, a Luxury Collection Resort & Spa Labuan Bajo', '17', NULL, NULL, NULL, 'iVV8v7FYpAjQyPnaiSRdFwgJmO', '17', NULL, 'Pantai Wae Rana, Labuan Bajo, East Nusa Tenggara 86763', 1, 3, 'Dwi Indrawati', '03852381888', 'For those who yearn to not just discover Labuan Bajo but embrace it, dive beneath the surface and explore like a local at TA\'AKTANA, a Luxury Collection Resort and Spa, Labuan Bajo. Every aspect of our&nbsp;hotel pays homage to the traditions and culture of the extraordinary island of Flores. Inspired by the Lingko fields and their spider web-shaped rice terraces, our Indonesia luxury resort is a living testament to Labuan Bajo’s unique heritage. Relax in beautifully appointed accommodations including family villas and overwater villas with Butler service. Whether you prefer lounging by the Olympic-sized swimming pool, treating young ones to new adventures at the Kids Club, or reveling in breathtaking sunsets from the overwater bar, there\'s something for every guest. Discover the magic of Labuan Bajo where past and present intertwine to create a sense of wonder and reverence for the island\'s rich heritage. Your journey of exploration begins here, at TA\'AKTANA, a Luxury Collection Resort and Spa, Labuan Bajo.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1742455750_Cover.jfif', 14, 'https://www.marriott.com/en-us/hotels/lbjlc-taaktana-a-luxury-collection-resort-and-spa-labuan-bajo/overview/?scid=f2ae0541-1279-4f24-b197-a979c79310b0', '2', '45', NULL, NULL, 'https://maps.app.goo.gl/84zuCgnbt7GYRv3EA', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-03-19 23:29:10', '2026-03-24 18:26:55', 1, 1),
(142, 'Abisena Ubud Bali', '17', 'Keliki', 'Bali', 'Indonesia', 'koEWkA2Uc1abCbsdxlamJ9wDf5', '17', 17, 'Keliki, Bali, Indonesia', 2, 44, 'I Wayan Parka', '03616201123', 'The Abisena Ubud Bali is a masterpiece inspired by mythical legends. The tale of Bima\'s brave exploration, which led to the discovery of Tirta Kamandalu, the sacred life-giving waters, shapes the resort. Each element of The Abisena, from the natural backdrop, which is perfectly intertwined with the elegant space, reflects the essence of Bima\'s journey; spiritual renewal and physical rejuvenation.<br><br>At the Abisena Ubud, contemporary elegance merges with timeless tradition, creating a unique and sensorial journey. The rich heritage of Ubud is on show at every turn, with the celebration of local culture a focal point of its sleek design. Indulge in homely comforts whilst honouring the past in a setting designed to captivate the senses.', 'The Abisena Ubud Bali 是一件受神話傳說啟發而誕生的傑作。度假村靈感來自比馬（Bima）勇敢探索之旅，發現了具有神聖生命力的甘曼達露聖水（Tirta Kamandalu）的故事。The Abisena 的每一處元素，從自然背景與優雅空間的完美融合，皆體現了比馬旅程的精髓——精神淨化與身心重生。\r\n在 Abisena Ubud，現代優雅與永恆傳統交織融合，帶來獨特的多感官體驗。烏布的深厚文化底蘊隨處可見，當地文化的讚頌亦成為其時尚設計的核心。賓客可在充滿人情味的舒適空間中沉浸，並在這個設計細膩、感官迷人的場域中，向過去致敬。', 'The Abisena Ubud Bali 是一部受神话传说启发而诞生的杰作。度假村灵感源自毗摩（Bima）勇敢探索之旅，并发现了具有神圣生命之力的甘曼达露圣水（Tirta Kamandalu）。The Abisena 的每一处细节，从自然景致与优雅空间的完美融合，都体现了毗摩旅程的精髓——心灵净化与身心焕新。\r\n在 Abisena Ubud，现代优雅与永恒传统完美交汇，带来独特的感官之旅。乌布丰富的文化遗产在每一处细节中展现无遗，当地文化的呈现更是简约设计的核心。宾客可在温馨舒适的环境中尽情享受，同时在这个专为感官而设的空间中，向传统致敬。', NULL, NULL, NULL, '<b>Seasonal Policy:</b>&nbsp;<br><ul><li>No check out on December 31st&nbsp;</li></ul><b>Honeymoon and Anniversary benefits:&nbsp;</b><br><ul><li>Romantic interior decorations set up upon check-in&nbsp;</li><li>Complimentary cake for honeymoon or anniversary celebrations</li></ul>', '<span>季節性政策：<br></span><ul><li>\r\n12月31日不允許辦理退房</li></ul><span>蜜月與週年禮遇：<br></span><ul><li>\r\n辦理入住時提供浪漫室內佈置</li><li>\r\n贈送蜜月或週年慶祝蛋糕一份</li></ul>', '<div>季节性政策：<br></div><ul><li>12月31日不可办理退房</li></ul>蜜月及周年礼遇：<br><ul><li>入住时提供浪漫室内装饰</li><li>赠送蜜月或周年庆祝蛋糕一份</li></ul><div><div></div></div><div><div></div></div><div></div><div></div>', NULL, NULL, NULL, 'inactive', 'hotels/covers/1744789060_ABISENA-WELLNESS-HOTEL-AND-RESORT-UBUD-LOBBY.webp', 14, 'https://abisenaubud.com/', '2', '45', '11:00', '13:00', 'https://www.google.com/maps/place/Abisena+Wellness+and+Resort+Ubud/@-8.4600015,115.2567105,17z/data=!4m9!3m8!1s0x2dd22300d43f11b1:0xdd8e485a87028f24!5m2!4m1!1i2!8m2!3d-8.4600068!4d115.2592854!16s%2Fg%2F11qnldxs1t?entry=ttu&g_ep=EgoyMDI2MDMxOC4xIKXMDSoASAFQAw%3D%3D', -8.4607406, 115.2582312, NULL, NULL, '<b>Low Season</b> <i>(01 Apr - 31 May, 01 Oct - 19 Dec, 11 Jan - 31 Mar):</i><br><ul><li>&lt; 14 Days: 1 Room Nights Charge</li><li>&lt; 72 Hours /No Show: 100% Charge&nbsp;</li></ul><b>High &amp; Peak Season</b> <i>(01 Jun - 30 Sep, 20 Dec - 10 Jan):&nbsp;</i><br><ul><li>&lt; 30 Days: 1 Room Nights Charge&nbsp;</li><li>&lt; 96 Hours /No Show: 100% Charge&nbsp;</li></ul>', '淡季（4月1日－5月31日、10月1日－12月19日、1月11日－3月31日）：\r\n<ul>\r\n<li>\r\n取消於抵達日前14天內：收取1晚房費\r\n</li>\r\n<li>\r\n取消於抵達前72小時內 / 未入住（No Show）：收取100%房費\r\n</li>\r\n</ul>\r\n旺季與巔峰季節（6月1日－9月30日、12月20日－1月10日）：\r\n<ul>\r\n<li>\r\n取消於抵達日前30天內：收取1晚房費\r\n</li>\r\n<li>\r\n取消於抵達前96小時內 / 未入住（No Show）：收取100%房費</li></ul>', '淡季（4月1日－5月31日、10月1日－12月19日、1月11日－3月31日）：\r\n<ul>\r\n<li>\r\n抵达日前14天内取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达前72小时内取消 / 未入住（No Show）：收取100%房费\r\n</li>\r\n</ul>\r\n旺季与巅峰季节（6月1日－9月30日、12月20日－1月10日）：\r\n<ul>\r\n<li>\r\n抵达日前30天内取消：收取1晚房费\r\n</li>\r\n<li>\r\n抵达前96小时内取消 / 未入住（No Show）：收取100%房费</li></ul>', NULL, '2025-04-15 23:37:40', '2026-03-25 18:55:03', 1, 2),
(143, 'RIMBA by AYANA Bali', '17', NULL, NULL, NULL, 'EGlzv6bkW4osmyoOmZhYbqq8F3', '17', NULL, 'Sejahtera, Jl. Karang Mas, Jimbaran, South Kuta, Badung Regency, Bali 80364', 1, 15, 'Jusdent Zhou', '03618468468', 'In the heart of Bali\'s forest green, RIMBA: a serene dream. An oasis where water and lushness blend, nature\'s embrace, a peaceful friend. Blooming flowers grace the dining space, at the pool bar time slows its pace. With dances that tell of culture\'s grace, embark on a journey, find your place.', '在峇里島翠綠森林的心臟地帶，RIMBA：一場寧靜的夢境。<br>\r\n這是一片綠意與水融合的綠洲，大自然的懷抱，如摯友般溫柔。<br>\r\n盛開的花朵妝點用餐空間，池畔酒吧讓時間緩緩流動。<br>\r\n傳統舞蹈訴說著文化的優雅，展開一段旅程，尋找屬於你的歸屬。', '<div><div><div><div><div><div><span>在巴厘岛翠绿森林的中心，RIMBA：一场宁静的梦境。<br>\r\n这是一个水与绿意交融的绿洲，大自然的怀抱，如挚友般温柔。<br>\r\n盛开的花朵点缀餐厅空间，泳池酒吧让时间慢下来。<br>\r\n传统舞蹈诉说文化的优雅，展开一段旅程，找到属于你的归属。</span></div></div></div></div><div><div><div></div></div></div><div><div></div></div></div><div><br></div></div><div></div>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', '1759198188_RIMBA-AYANA.jpg', 14, 'https://www.ayana.com/bali/rimba-by-ayana/', '2', '360', NULL, NULL, 'https://maps.app.goo.gl/aosFTKLC7HNwLGAh7', NULL, NULL, NULL, NULL, '<b>Regular Season:</b> 04-Jun-25- 31-Jul-25 | 01-Sep-25- 30-Sep-25 | 08-Oct-25- 23-Dec-25 | 06-Jan-26- 13-Feb-26\r\n 23-Feb-26- 17-Mar-26 | 24-Mar-26- 28-Apr-26 | 07-May-26- 31-Jul-26 | 01-Sep-26- 23-Sep-26\r\n 28-Sep-26- 30-Sep-26<br><ul><li>7 days prior to arrival: 1 night charge </li></ul><b>High Season:</b> 01-Aug-25- 31-Aug-25 | 01-Oct-25- 07-Oct-25 | 24-Dec-25- 28-Dec-25 | 03-Jan-26- 05-Jan-26\r\n 14-Feb-26- 22-Feb-26 | 18-Mar-26- 23-Mar-26 | 29-Apr-26- 06-May-26 | 01-Aug-26- 31-Aug-26\r\n 24-Sep-26- 27-Sep-26 <br><ul><li>14 days prior to arrival: 1 night charge </li></ul><b>Peak Season:</b> 29-Dec-25- 02-Jan-26<ul><li>30 days prior to arrival: 1 night charge </li></ul><b>NO SHOW:</b> <br><ul><li>A reservation is considered “no show” if arrival does not occur on the date reserved and the Hotel \r\nis not notified of any emergency delays in writing. No show will be subject to a penalty equal to “a \r\nfull charge on whole period of stay” (including all the additional arrangement).  </li><li>No show must be paid without reliance on billed vouchers since the clients did not arrive in the \r\nhotel, no voucher will be submitted.</li></ul>', '<span>平日季（Regular Season）：<br>\r\n2025年6月4日－7月31日｜2025年9月1日－9月30日｜2025年10月8日－12月23日｜2026年1月6日－2月13日｜2026年2月23日－3月17日｜2026年3月24日－4月28日｜2026年5月7日－7月31日｜2026年9月1日－9月23日｜2026年9月28日－9月30日<br></span><ul><li>\r\n抵達日前7天內取消：收取1晚房費</li></ul><span>旺季（High Season）：<br>\r\n2025年8月1日－8月31日｜2025年10月1日－10月7日｜2025年12月24日－12月28日｜2026年1月3日－1月5日｜2026年2月14日－2月22日｜2026年3月18日－3月23日｜2026年4月29日－5月6日｜2026年8月1日－8月31日｜2026年9月24日－9月27日<br></span><ul><li>\r\n抵達日前14天內取消：收取1晚房費</li></ul><span>巔峰季（Peak Season）：<br>\r\n2025年12月29日－2026年1月2日<br></span><ul><li>\r\n抵達日前30天內取消：收取1晚房費</li></ul><span>未出現（No Show）：<br></span><ul><li>\r\n若預訂客人在預定入住日未到且未以書面通知飯店延遲，將視為「未出現」。未出現將被收取整個住宿期間的全額費用（包含所有附加安排）。</li><li>未出現者須支付相關費用，並不得依賴任何已開立之代金券，因為客人未實際入住，故不會提交代金券。</li></ul>', '<span>平季（Regular Season）：<br>\r\n2025年6月4日－7月31日｜2025年9月1日－9月30日｜2025年10月8日－12月23日｜2026年1月6日－2月13日｜2026年2月23日－3月17日｜2026年3月24日－4月28日｜2026年5月7日－7月31日｜2026年9月1日－9月23日｜2026年9月28日－9月30日<br></span><ul><li>\r\n抵达日前7天内取消：收取1晚房费</li></ul><span>旺季（High Season）：<br>\r\n2025年8月1日－8月31日｜2025年10月1日－10月7日｜2025年12月24日－12月28日｜2026年1月3日－1月5日｜2026年2月14日－2月22日｜2026年3月18日－3月23日｜2026年4月29日－5月6日｜2026年8月1日－8月31日｜2026年9月24日－9月27日<br></span><ul><li>\r\n抵达日前14天内取消：收取1晚房费</li></ul><span>旺季高峰期（Peak Season）：<br>\r\n2025年12月29日－2026年1月2日<br></span><ul><li>\r\n抵达日前30天内取消：收取1晚房费</li></ul><span>未入住（No Show）：<br></span><ul><li>\r\n若预订客人在预定入住日期未到且未以书面通知酒店有紧急延误，将视为“未入住”。未入住将被收取整个住宿期间的全额费用（包括所有额外安排）。</li><li>未入住者必须支付相关费用，不得依赖任何代金券，因为客人未抵达酒店，将不提交代金券。</li></ul>', NULL, '2025-06-12 17:49:15', '2026-03-24 18:21:00', 1, 1),
(144, 'AYANA Segara Bali', '17', 'Balangan', 'Bali', 'Indonesia', 'iExDPE81GdMOSNBEPtg8HQKJZT', '17', 17, 'Jalan Ritz Carlton, Balangan, Bali, Indonesia', 1, 15, 'Jusdent Zhou', '0361702222', 'On Bali\'s heights, traditions bloom, modern forms kissed by ocean’s plume. Vibrant blooms greet dawn\'s embrace, welcoming travelers to this sacred place. A realm of rest, discovery’s door, ancient roots and dreams explore.&amp;nbsp;On this hilltop where breezes sing, eternal dance of time&amp;nbsp;they bring.', '在峇里島的高地上，傳統綻放，現代形態親吻著海洋的浪花。繽紛的花朵迎接黎明的擁抱，歡迎旅人來到這片神聖之地。一個休憩與探索的境界，古老根源與夢想交織綻放。在這山巔之上，微風吟唱，帶來時光的永恆之舞。', '在巴厘岛的高地上，传统绽放，现代形态亲吻着海洋的浪花。缤纷的花朵迎接黎明的拥抱，欢迎旅人来到这片神圣之地。一个休憩与探索的境界，古老根源与梦想交织绽放。在这山巅之上，微风吟唱，带来时光的永恒之舞。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1759198094_segara-ayana--scaled.jpg', 14, 'https://www.ayana.com/bali/ayana-segara/', '2', '360', NULL, NULL, 'https://www.google.com/maps/place/AYANA+Segara+Bali/@-8.7874822,115.1378222,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd24591e9ebebd3:0x8ab63d8b6077342a!5m2!4m1!1i2!8m2!3d-8.7874875!4d115.1403971!16s%2Fg%2F11sbdh4gms?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.7871764, 115.1405254, NULL, NULL, '<b>Regular Season:</b>&nbsp;04-Jun-25- 31-Jul-25 | 01-Sep-25- 30-Sep-25 | 08-Oct-25- 23-Dec-25 | 06-Jan-26- 13-Feb-26 23-Feb-26- 17-Mar-26 | 24-Mar-26- 28-Apr-26 | 07-May-26- 31-Jul-26 | 01-Sep-26- 23-Sep-26 28-Sep-26- 30-Sep-26<br><ul><li>7 days prior to arrival: 1 night charge&nbsp;</li></ul><b>High Season:</b>&nbsp;01-Aug-25- 31-Aug-25 | 01-Oct-25- 07-Oct-25 | 24-Dec-25- 28-Dec-25 | 03-Jan-26- 05-Jan-26 14-Feb-26- 22-Feb-26 | 18-Mar-26- 23-Mar-26 | 29-Apr-26- 06-May-26 | 01-Aug-26- 31-Aug-26 24-Sep-26- 27-Sep-26&nbsp;<br><ul><li>14 days prior to arrival: 1 night charge&nbsp;</li></ul><b>Peak Season:</b>&nbsp;29-Dec-25- 02-Jan-26<ul><li>30 days prior to arrival: 1 night charge&nbsp;</li></ul><b>NO SHOW:</b><br><ul><li>A reservation is considered “no show” if arrival does not occur on the date reserved and the Hotel is not notified of any emergency delays in writing. No show will be subject to a penalty equal to “a full charge on whole period of stay” (including all the additional arrangement).&nbsp;&nbsp;</li><li>No show must be paid without reliance on billed vouchers since the clients did not arrive in the hotel, no voucher will be submitted.</li></ul>', '<span>平日季（Regular Season）：<br>2025年6月4日－7月31日｜2025年9月1日－9月30日｜2025年10月8日－12月23日｜2026年1月6日－2月13日｜2026年2月23日－3月17日｜2026年3月24日－4月28日｜2026年5月7日－7月31日｜2026年9月1日－9月23日｜2026年9月28日－9月30日<br></span><ul><li>抵達日前7天內取消：收取1晚房費</li></ul><span>旺季（High Season）：<br>2025年8月1日－8月31日｜2025年10月1日－10月7日｜2025年12月24日－12月28日｜2026年1月3日－1月5日｜2026年2月14日－2月22日｜2026年3月18日－3月23日｜2026年4月29日－5月6日｜2026年8月1日－8月31日｜2026年9月24日－9月27日<br></span><ul><li>抵達日前14天內取消：收取1晚房費</li></ul><span>巔峰季（Peak Season）：<br>2025年12月29日－2026年1月2日<br></span><ul><li>抵達日前30天內取消：收取1晚房費</li></ul><span>未出現（No Show）：<br></span><ul><li>若預訂客人在預定入住日未到且未以書面通知飯店延遲，將視為「未出現」。未出現將被收取整個住宿期間的全額費用（包含所有附加安排）。</li><li>未出現者須支付相關費用，並不得依賴任何已開立之代金券，因為客人未實際入住，故不會提交代金券。</li></ul>', '<span>平季（Regular Season）：<br>2025年6月4日－7月31日｜2025年9月1日－9月30日｜2025年10月8日－12月23日｜2026年1月6日－2月13日｜2026年2月23日－3月17日｜2026年3月24日－4月28日｜2026年5月7日－7月31日｜2026年9月1日－9月23日｜2026年9月28日－9月30日<br></span><ul><li>抵达日前7天内取消：收取1晚房费</li></ul><span>旺季（High Season）：<br>2025年8月1日－8月31日｜2025年10月1日－10月7日｜2025年12月24日－12月28日｜2026年1月3日－1月5日｜2026年2月14日－2月22日｜2026年3月18日－3月23日｜2026年4月29日－5月6日｜2026年8月1日－8月31日｜2026年9月24日－9月27日<br></span><ul><li>抵达日前14天内取消：收取1晚房费</li></ul><span>旺季高峰期（Peak Season）：<br>2025年12月29日－2026年1月2日<br></span><ul><li>抵达日前30天内取消：收取1晚房费</li></ul><span>未入住（No Show）：<br></span><ul><li>若预订客人在预定入住日期未到且未以书面通知酒店有紧急延误，将视为“未入住”。未入住将被收取整个住宿期间的全额费用（包括所有额外安排）。</li><li>未入住者必须支付相关费用，不得依赖任何代金券，因为客人未抵达酒店，将不提交代金券。</li></ul>', NULL, '2025-06-12 20:16:10', '2026-03-25 19:18:52', 1, 2),
(145, 'AYANA Resort Bali', '17', 'Balangan', 'Bali', 'Indonesia', 'xwofrh5z4RSNls6y3fjhvDYrbP', '17', 17, 'Jalan Ritz Carlton, Balangan, Bali, Indonesia', 1, 15, 'Jusdent Zhou', '0361702222', 'AYANA Resort, where elegance resides, homage to Balinese traditions thrives. With natural materials in graceful design, a classic ambiance that truly aligns. Pools, spas, and dining in grand array, satisfying desires with each new day. In lush green forests, by the cobalt sea, it captures the essence of paradise\'s decree.', 'AYANA 度假村，優雅之所，致敬峇里傳統之所。在自然材質與優雅設計中，展現出和諧的經典氛圍。泳池、水療與餐飲多樣齊備，每一天皆滿足渴望。在翠綠森林與深藍海洋之間，捕捉天堂本意的精髓。', 'AYANA 度假村，优雅之所，致敬巴厘传统之所。在自然材质与优雅设计中，展现出和谐的经典氛围。泳池、水疗与餐饮多样齐备，每一天皆满足渴望。在翠绿森林与深蓝海洋之间，捕捉天堂本意的精髓。', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'inactive', 'hotels/covers/1749800618_kv-01_N2DY3A.webp', 14, 'https://www.ayana.com/', '2', '360', NULL, NULL, 'https://www.google.com/maps/place/AYANA+Resort+Bali/@-8.7862118,115.1366976,17z/data=!3m1!4b1!4m9!3m8!1s0x2dd2448af6f410a5:0x313ee67691a146ca!5m2!4m1!1i2!8m2!3d-8.7862171!4d115.1392725!16s%2Fg%2F1tf215vh?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.7862176, 115.1392877, NULL, NULL, '<b>Regular Season:</b>&nbsp;04-Jun-25- 31-Jul-25 | 01-Sep-25- 30-Sep-25 | 08-Oct-25- 23-Dec-25 | 06-Jan-26- 13-Feb-26 23-Feb-26- 17-Mar-26 | 24-Mar-26- 28-Apr-26 | 07-May-26- 31-Jul-26 | 01-Sep-26- 23-Sep-26 28-Sep-26- 30-Sep-26<br><ul><li>7 days prior to arrival: 1 night charge&nbsp;</li></ul><b>High Season:</b>&nbsp;01-Aug-25- 31-Aug-25 | 01-Oct-25- 07-Oct-25 | 24-Dec-25- 28-Dec-25 | 03-Jan-26- 05-Jan-26 14-Feb-26- 22-Feb-26 | 18-Mar-26- 23-Mar-26 | 29-Apr-26- 06-May-26 | 01-Aug-26- 31-Aug-26 24-Sep-26- 27-Sep-26&nbsp;<br><ul><li>14 days prior to arrival: 1 night charge&nbsp;</li></ul><b>Peak Season:</b>&nbsp;29-Dec-25- 02-Jan-26<ul><li>30 days prior to arrival: 1 night charge&nbsp;</li></ul><b>NO SHOW:</b><br><ul><li>A reservation is considered “no show” if arrival does not occur on the date reserved and the Ho