INSERT INTO `hotel_rooms` (`id`, `hotels_id`, `room_view_id`, `cover`, `rooms`, `capacity_adult`, `capacity_child`, `view`, `beds`, `size`, `amenities`, `amenities_traditional`, `amenities_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `include`, `include_traditional`, `include_simplified`, `status`, `created_at`, `updated_at`) VALUES
(1, 19, NULL, '1713776068_1. Standard Room .webp', 'Standard Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 50 sqm&nbsp;</p><p>&nbsp;</p>', NULL, NULL, '<ul><li>Daily buffet breakfast in Makase for 2 persons&nbsp;</li><li>Welcome drink at Neighbourhood Gallery and refreshing cold towel upon arrival&nbsp;</li><li>Complimentary 24-hours access to the Gym&nbsp;</li><li>Selections of resort&#39;s scheduled complimentary activities&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-05 06:54:11', '2025-04-01 17:02:58'),
(2, 19, NULL, '1713776468_2. Standard Garden View .webp', 'Standard Garden View', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 50 sqm&nbsp;</p>', NULL, NULL, '<ul><li>Daily buffet breakfast in Makase for 2 persons&nbsp;</li><li>Welcome drink at Neighbourhood Gallery and refreshing cold towel upon arrival&nbsp;</li><li>Complimentary 24-hours access to the Gym&nbsp;</li><li>Selections of resort&#39;s scheduled complimentary activities&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-05 06:57:43', '2025-04-01 17:02:58'),
(3, 19, NULL, '1713776669_3. Standard Courtyard Access .webp', 'Standard Courtyard Access', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 50 sqm</p>', NULL, NULL, '<ul><li>Daily buffet breakfast in Makase for 2 persons&nbsp;</li><li>Welcome drink at Neighbourhood Gallery and refreshing cold towel upon arrival&nbsp;</li><li>Complimentary 24-hours access to the Gym&nbsp;</li><li>Selections of resort&#39;s scheduled complimentary activities&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-05 07:04:49', '2025-04-01 17:02:58'),
(4, 19, NULL, '1713776799_4. Suite Garden .webp', 'Suite Garden View', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 69 sqm&nbsp;</p>', NULL, NULL, '<ul><li>Daily buffet breakfast in Makase for 2 persons&nbsp;</li><li>Welcome drink at Neighbourhood Gallery and refreshing cold towel upon arrival&nbsp;</li><li>Complimentary 24-hours access to the Gym&nbsp;</li><li>Selections of resort&#39;s scheduled complimentary activities&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-05 07:07:10', '2025-04-01 17:02:58'),
(5, 19, NULL, '1713777083_5. Wangsa One-Bedroom Pool Villa .webp', 'Wangsa 1BR Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 300 sqm&nbsp;</p>', NULL, NULL, '<ul><li>Daily buffet breakfast in Makase for 2 persons&nbsp;</li><li>Welcome drink at Neighbourhood Gallery and refreshing cold towel upon arrival&nbsp;</li><li>Complimentary 24-hours access to the Gym&nbsp;</li><li>Selections of resort&#39;s scheduled complimentary activities&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-05 07:30:36', '2025-04-01 17:02:58'),
(6, 5, NULL, '1715328842_Deluxe room.webp', 'Deluxe Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 48 sqm&nbsp;</p><p>Max Occupants:&nbsp;</p><ul><li>2 adult&nbsp;</li><li>2 child below 12 years old (1 child with extra bed &amp; 1 child sharing bed with parents)&nbsp;&nbsp;</li><li>1 infant with baby cot&nbsp;</li></ul>', NULL, NULL, '<ul><li>Daily Breakfast</li><li>Complimentary internet access at the resort&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-05 08:57:22', '2025-04-01 17:02:57'),
(9, 6, NULL, '1667796717_One Bedroom.webp', 'One Bedroom Pool Villa', 2, 1, 'Pool View', 'King Bed or Twin Beds', '280', 'Private pool,\r\nPrivate cabana,\r\nGourmet bar,\r\nOutdoor dining area,\r\n24-hour butler service,\r\n43” flat-screen TV,\r\nIndividual climate control,\r\nBlackout curtains,\r\nHair dryer,\r\nBranded bath amenities,\r\nPlush robes and slippers,\r\nCoffee maker,\r\nMinifridge,\r\nIron and ironing board on request,\r\nIn-room safe,\r\nDaily newspaper on request,\r\nRollaway bed on request,', '私人泳池，\r\n私人小屋，\r\n美食酒吧，\r\n戶外用餐區，\r\n24小時管家服務，\r\n43吋平面電視，\r\n獨立溫控，\r\n遮光窗簾，\r\n吹風機，\r\n品牌盥洗用品，\r\n豪華浴袍和拖鞋，\r\n咖啡機，\r\n迷你冰箱，\r\n熨斗和熨衣板（可應要求提供），\r\n客房內保險箱，\r\n每日報紙（可應要求提供），\r\n折疊床（可應要求提供），', '私人泳池，\r\n私人小屋，\r\n美食酒吧，\r\n户外用餐区，\r\n24小时管家服务，\r\n43英寸平板电视，\r\n独立温控，\r\n遮光窗帘，\r\n吹风机，\r\n品牌洗浴用品，\r\n豪华浴袍和拖鞋，\r\n咖啡机，\r\n迷你冰箱，\r\n熨斗和熨衣板（可应要求提供），\r\n客房内保险箱，\r\n每日报纸（可应要求提供），\r\n折叠床（可应要求提供）', NULL, NULL, NULL, '<ul><li>Daily a la carte breakfast</li><li>Host (butler) service</li><li>Wi-Fi Internet access throughout the resort</li><li>Morning yoga session from 07.30 - 08.30 am</li><li>Use of 24-hour Gym</li><li>24-hour Library</li><li>Alila Living bath amenities</li><li>Complimentary drop off and pick up service to and from Savaya</li></ul>', NULL, NULL, 'Active', '2022-11-05 09:51:57', '2025-10-07 00:10:22'),
(11, 6, NULL, '1667800629_three Bedroom Hillside villa.webp', 'Three Bedroom Hillside Villa', 6, 3, 'Ocean View', 'King Bed', '3000', NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily a la carte breakfast</li><li>Host (butler) service</li><li>Wi-Fi Internet access throughout the resort</li><li>Morning yoga session from 07.30 - 08.30 am</li><li>Use of 24-hour Gym</li><li>24-hour Library</li><li>Alila Living bath amenities</li><li>Complimentary drop off and pick up service to and from Savaya</li></ul>', NULL, NULL, 'Active', '2022-11-05 10:57:09', '2026-01-08 19:46:16'),
