(223, 52, NULL, '1730771036_Deluxe-King-Room-new.webp', 'Deluxe Room with Balcony', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily buffet breakfast at Sungai Restaurant for 2 people&nbsp;</li><li>4 bottled mineral water per room per day&nbsp;</li><li>Complimentary Wi-Fi in the room and all hotels areas: lobby, restaurant, pools, bar, lounge etc&nbsp;</li><li>Access to all hotel facilities: GYM and Fitness centre and two swimming pools&nbsp;</li><li>Daily Shuttle to Ubud center-drop and pick-up (based on hotel schedule)&nbsp;</li><li>Daily in house activities: Yoga by the river, aqua aerobic, Sthala gowes, mebanten-offering procession, explore Ubud, Balinese dance lesson, canang sari decoration and learning Balinese Language (based on hotel schedule)</li></ul>', NULL, NULL, 'Active', '2022-11-26 09:30:37', '2024-11-04 18:43:56'),
(226, 53, NULL, '1737016007_WhatsApp Image 2025-01-16 at 15.34.57.jpeg', '1BR Private Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 147(sqm)</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Welcome drink&nbsp;</li><li>In villa tea and coffee making facilities&nbsp;</li><li>Deluxe bathroom amenities&nbsp;</li><li>Daily replenish mineral water&nbsp;</li><li>Complimentary internet access throughout the resort&nbsp;</li><li>Honeymoon benefit : free flower arrangement on arrival&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-11-26 09:59:12', '2025-01-16 00:31:39'),
(227, 53, NULL, '1737016127_WhatsApp Image 2025-01-16 at 15.38.26.jpeg', '1BR Honeymoon Private Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 165(sqm)</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Welcome drink&nbsp;</li><li>In villa tea and coffee making facilities&nbsp;</li><li>Deluxe bathroom amenities&nbsp;</li><li>Daily replenish mineral water&nbsp;</li><li>Complimentary internet access throughout the resort&nbsp;</li><li>Honeymoon benefit : free flower arrangement on arrival&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-11-26 10:00:47', '2025-01-16 00:31:30'),
(228, 53, NULL, '1737016212_WhatsApp Image 2025-01-16 at 15.39.46.jpeg', '2BR Private Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 170(sqm)</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Welcome drink&nbsp;</li><li>In villa tea and coffee making facilities&nbsp;</li><li>Deluxe bathroom amenities&nbsp;</li><li>Daily replenish mineral water&nbsp;</li><li>Complimentary internet access throughout the resort&nbsp;</li><li>Honeymoon benefit : free flower arrangement on arrival&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-11-26 10:01:37', '2025-01-16 00:31:51'),
(233, 55, NULL, '1669619663_Terrace Tent.webp', 'Terrace Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult/1 child/1 infant or 3 adult&nbsp;</p><p>Offering a rice terrace or forest outlook and a private saltwater pool.&nbsp;</p>', NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-26 12:14:24', '2025-04-01 17:03:00'),
(234, 55, NULL, '1669619698_Rainforest Tent.webp', 'Rainforest Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult/1 child/1 infant or 3 adult&nbsp;</p><p>Offering a rainforest setting and view with a private saltwater pool.&nbsp;</p>', NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul><p>&nbsp;</p>', NULL, NULL, 'Draft', '2022-11-26 12:14:58', '2025-04-01 17:03:00'),
(235, 55, NULL, '1669620046_River Tent.webp', 'River Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult or 3 adult&nbsp;</p><p>Offering a Wos river experience and view with a private saltwater pool</p><p>NB: No infants and children below the age of 10 yo</p>', NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-26 12:20:46', '2025-04-01 17:03:00'),
(236, 55, NULL, '1669620185_Keliki Valley.webp', 'Keliki Valley Tent', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 173 sqm&nbsp;</p><p>Bedding Capacity: 2 adult or 3 adult&nbsp;</p><p>Offering unobstructed elevated Keliki Valley views and a private saltwater pool.&nbsp;</p><p>NB: No infants and children below the age of 10 yo</p>', NULL, NULL, '<ul><li>Breakfast for two daily served at Mads Lange&nbsp;</li><li>24-hour service of a Capella Culturist&nbsp;</li><li>Welcome duffel bag containing camp essentials upon arrival&nbsp;</li><li>Return airport transfers with our Camp Navigators for stays of 3 nights or more&nbsp;</li><li>Return transfers to Ubud centre daily as per the camp&rsquo;s schedule&nbsp;</li><li>Exclusive access to the Officer&rsquo;s Tent for morning coffee, afternoon tea, evening cocktails and canap&eacute;s daily&nbsp;</li><li>In-tent daily seasonal fruit and infused spring water&nbsp;</li><li>Complimentary soft drinks, juices and local alcoholic beverages from your in-tent refreshment trunk, replenished daily&nbsp;</li><li>Illy espresso machine and tea stations &nbsp;</li><li>24-hour exclusive access to The Armory, our tented gymnasium and The Cistern, the camp&rsquo;s 20 metre outdoor rainforest pool&nbsp;</li><li>Low and high impact activities with our Camp Rangers, offered as part of the camp&rsquo;s weekly activity schedule&nbsp;</li><li>Use of mountain bikes&nbsp;</li><li>Exclusive range of organic bathroom amenities and a soap menu&nbsp;</li><li>Four pieces of laundry per person, per day, exclusive of dry cleaning&nbsp;</li><li>Daily camp turndown ritual&nbsp;</li><li>High speed Wi-Fi throughout the camp &nbsp;</li><li>Complimentary holiday photo shoot in the camp up to 30 minutes including 1 complimentary e-portrait. Reservation required 24 hours in advance.&nbsp;</li></ul>', NULL, NULL, 'Draft', '2022-11-26 12:23:06', '2025-04-01 17:03:00'),
