(263, 61, NULL, '1705030110_Reserve Suite.webp', 'Reserve Suite', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Includes complimentary 24 hours daily breakfast for 2 people, 4 people for 2 Bedroom Villa and 6 people for 3 Bedroom Villa.&nbsp;</li><li>Includes complimentary non-alcoholic minibar (applicable for villa booking)&nbsp;</li><li>Includes complimentary pressing service, up to 5 pieces per room per day, non-accumulative (applicable for villa booking)&nbsp;</li><li>Includes complimentary resort photoshoot up to 30 minutes with complimentary one e-portrait&nbsp;</li><li>Includes complimentary hourly refreshment at the Pool Bar&nbsp;</li><li>Includes complimentary pass around canapes at AMBAR daily from 17.30hrs - 18.15hrs.&nbsp;</li><li>Includes daily complimentary activities as per resort schedule&nbsp;</li><li>Includes an exclusive invitation to join wellness program &#39;Disconnect to Reconnect&#39;&nbsp;</li><li>Includes complimentary Wi-Fi access&nbsp;</li><li>Includes complimentary 3 types of welcome amenities and daily in-room coffee and tea&nbsp;</li><li>Includes 24-hour personalized Buttler service (Patih) for all room categories&nbsp;</li><li>Includes unlimited use of the wellness facilities (steam room, sauna and vitality pool)</li></ul>', NULL, NULL, 'Active', '2022-11-27 09:22:22', '2024-12-29 22:20:58'),
