(413, 10, NULL, '1732006608_Deluxe_king_room_Ayodya_bali.webp', 'Ayodya Resort - Classic Deluxe', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Room size: 48 sqm&nbsp;', NULL, NULL, '<ul><li>Welcome drink &amp; cold towel provided upon arrival.&nbsp;</li><li>Complimentary 24-hour access to the fitness center.&nbsp;</li><li>Complimentary access to all resort activities, kid’s activities at kid’s club and Balinese cultural activities at Bale Banjar.&nbsp;</li><li>Complimentary internet access available throughout the resort.&nbsp;</li><li>Inter-connecting room are available. Please request for connecting room in advance, subject to availability.</li></ul>', NULL, NULL, 'Active', '2022-11-30 09:18:05', '2025-03-25 18:18:17'),
(415, 10, NULL, '1717036639_Grande King Bedroom.webp', 'Ayodya Resort - Classic Grande', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Room size: 56 sqm&nbsp;', NULL, NULL, '<ul><li>Welcome drink &amp; cold towel provided upon arrival.&nbsp;</li><li>Complimentary 24-hour access to the fitness center.&nbsp;</li><li>Complimentary access to all resort activities, kid’s activities at kid’s club and Balinese cultural activities at Bale Banjar.&nbsp;</li><li>Complimentary internet access available throughout the resort.&nbsp;</li><li>Inter-connecting room are available. Please request for connecting room in advance, subject to availability.</li></ul>', NULL, NULL, 'Active', '2022-11-30 09:21:19', '2025-03-25 18:19:04'),
(417, 10, NULL, '1717036979_Ayodya Palace Garden View Bedroom.webp', 'The Ayodya Palace - Ayodya Palace', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Room size: 56 sqm', NULL, NULL, '<ul><li>Ayodya Palace Lounge access from 07.00hrs till 00.00hrs&nbsp;</li><li>Choice of Buffet and A’ la carte breakfast served in Ayodya Palace Lounge, with Sparkling Wine from 7.00hrs - 11.00hrs&nbsp;</li><li>Afternoon tea served in Ayodya Palace Lounge from 15.00hrs - 16.30hrs&nbsp;</li><li>Evening cocktails and canapés from 18.00hrs - 19.30hrs&nbsp;</li><li>Complimentary laundry and pressing up to 4 (four) pieces per room per day&nbsp;</li><li>Access to Ayodya Palace Pool &amp; Loungers&nbsp;</li><li>Complimentary fruit, snacks, soft beverages, tea and coffee throughout the day at Ayodya Palace Lounge &amp; Pool&nbsp;</li><li>Selection of alcoholic and non-alcoholic beverages replenished daily in-room Mini Bar&nbsp;</li><li>Selection of tropical fruits replenished daily in the room&nbsp;</li><li>Personalized check-in / check-out at Palace Reception&nbsp;</li><li>Complimentary access to 24-hour Fitness Centre&nbsp;</li><li>Complimentary access to Camp Ananda Kids Club for children under 12 years old&nbsp;</li><li>Access to resort facilities and activities&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-11-30 09:47:07', '2025-03-25 18:21:15'),
