(448, 94, NULL, '1670379212_Deluxe Room.webp', 'Deluxe Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<i>Extra bed is not recommended due to space constraint however if guest insist it will be set up in front of the wardrobe area with additional charge</i>', NULL, NULL, '<ul><li>Complimentary welcome drink</li><li>Daily breakfast</li><li>One-time&nbsp;afternoon tea per stay</li><li>One-time welcome fruit upon arrival</li><li>Daily set up mineral water&nbsp;</li><li>Complimentary daily replenish Non-Alcohol Mini Bar&nbsp;</li></ul><b>Complimentary resort guest activties following regular hotel schedule such as:</b>&nbsp;<br><ul><li>Making herbal drink and body scrub available every day at Dala Spa&nbsp;</li><li>Yoga Class available every Wednesday and Saturday start from 16:00pm - 17:00pm&nbsp;</li></ul><b>Note:&nbsp;</b><br><ul><li>Please inform to our Front Office team one day in advance to join those above class.&nbsp;</li><li>Should the guest wish to arrange private session (out of regular hotel schedule) for yoga class, separate yoga class fee is available upon request.&nbsp;&nbsp;</li></ul><b>Added Value Benefit:&nbsp;</b><br><ul><li>Minimum 2 nights stay get 1 x 60 minutes Balinese Massage OR 3 course Set Menu Lunch for 2 persons&nbsp;</li><li>Minimum 4 nights stay get 1 x 60 minutes Balinese Massage AND 3 course Set Menu Lunch for 2 persons&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-12-05 07:13:32', '2025-05-14 18:37:33'),
(449, 94, NULL, '1670379245_Alaya Room.webp', 'Alaya Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<i>Extra bed is not recommended due to space constraint however if guest insist it will be set up in front of the wardrobe area with additional charge</i>', NULL, NULL, '<ul><li>Complimentary welcome drink</li><li>Daily breakfast</li><li>One-time&nbsp;afternoon tea per stay</li><li>One-time welcome fruit upon arrival</li><li>Daily set up mineral water&nbsp;</li><li>Complimentary daily replenish Non-Alcohol Mini Bar&nbsp;</li></ul><b>Complimentary resort guest activties following regular hotel schedule such as:&nbsp;</b><br><ul><li>Making herbal drink and body scrub available every day at Dala Spa&nbsp;</li><li>Yoga Class available every Wednesday and Saturday start from 16:00pm - 17:00pm&nbsp;</li></ul><b>Note:&nbsp;</b><br><ul><li>Please inform to our&nbsp;Front Office team one day in advance to join those above class.&nbsp;</li><li>Should the guest wish to arrange private session (out of regular hotel schedule) for yoga class, separate yoga class fee is available upon request.&nbsp;&nbsp;</li></ul><b>Added Value Benefit:&nbsp;</b><br><ul><li>Minimum 2 nights stay get 1 x 60 minutes Balinese Massage OR 3 course Set Menu Lunch for 2 persons&nbsp;</li><li>Minimum 4 nights stay get 1 x 60 minutes Balinese Massage AND 3 course Set Menu Lunch for 2 persons&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-12-05 07:14:05', '2025-05-14 18:41:00'),
(450, 94, NULL, '1670379359_Alaya Suite.webp', 'Alaya Suite', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<i>Extra bed is not recommended due to space constraint however if guest insist it will be set up in front of the wardrobe area with additional charge</i>', NULL, NULL, '<ul><li>Complimentary welcome drink</li><li>Daily breakfast</li><li>One-time&nbsp;afternoon tea per stay</li><li>One-time welcome fruit upon arrival</li><li>Daily set up mineral water&nbsp;</li><li>Complimentary daily replenish Non-Alcohol Mini Bar&nbsp;</li><li>Special for Alaya Suite Room get additional benefit of 1 x 30 minutes head and shoulder massage OR option of foot massage valid for 2 persons plus one time pick up or drop service to airport&nbsp;</li></ul><b>Complimentary resort guest activties following regular hotel schedule such as:&nbsp;</b><br><ul><li>Making herbal drink and body scrub available every day at Dala Spa&nbsp;</li><li>Yoga Class available every Wednesday and Saturday start from 16:00pm - 17:00pm&nbsp;</li></ul><b>Note:&nbsp;</b><br><ul><li>Please inform to our&nbsp;Front Office team one day in advance to join those above class.&nbsp;</li><li>Should the guest wish to arrange private session (out of regular hotel schedule) for yoga class, separate yoga class fee is available upon request.&nbsp;&nbsp;</li></ul><b>Added Value Benefit:&nbsp;</b><br><ul><li>Minimum 2 nights stay get 1 x 60 minutes Balinese Massage OR 3 course Set Menu Lunch for 2 persons&nbsp;</li><li>Minimum 4 nights stay get 1 x 60 minutes Balinese Massage AND 3 course Set Menu Lunch for 2 persons&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-12-05 07:15:59', '2025-05-14 18:41:36'),
(451, 95, NULL, '1737353517_WhatsApp Image 2025-01-20 at 14.11.38.jpeg', '1BR Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 32 sqm&nbsp;</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Welcome drink&nbsp;</li><li>In villa tea and coffee making facilities&nbsp;</li><li>Deluxe bathroom amenities&nbsp;</li><li>Daily replenish mineral water&nbsp;</li><li>Complimentary internet access throughout the resort&nbsp;</li><li>Honeymoon benefit : free flower arrangement on arrival&nbsp;&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-12-14 14:01:38', '2025-01-19 22:15:39'),
(452, 95, NULL, '1737353406_WhatsApp Image 2025-01-20 at 14.09.00.jpeg', '2BR Private Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 64 sqm&nbsp;&nbsp;</p>', NULL, NULL, '<ul><li>Daily breakfast</li><li>Welcome drink&nbsp;</li><li>In villa tea and coffee making facilities&nbsp;</li><li>Deluxe bathroom amenities&nbsp;</li><li>Daily replenish mineral water&nbsp;</li><li>Complimentary internet access throughout the resort&nbsp;</li><li>Honeymoon benefit : free flower arrangement on arrival&nbsp;&nbsp;</li></ul>', NULL, NULL, 'Active', '2022-12-14 14:02:13', '2025-01-19 22:15:45'),
(462, 18, NULL, '1697441589_Premier Garden Villa with Private Pool.webp', 'Premier Garder Villa with Private Pool', 2, 1, 'Garden View', 'King/Twin', '210', NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Welcome drink upon arrival&nbsp;</li><li>Daily breakfast for 2 adults&nbsp;</li><li>24 hour E-Butler Service&nbsp;</li><li>Evening turn-down service with canape bites&nbsp;</li><li>Capsule coffee making facilities and premium selected teas&nbsp;</li><li>Direct access to beach&nbsp;</li></ul><p>Bellow additional inclusion are not valid for Peak Season (20 Dec 2024 - 05 Jan 2025)&nbsp;</p><ul><li>2 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons&nbsp;</li><li>3 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons &amp; One time 60 minutes Balinese Massage at Talise Spa for 2 persons&nbsp;</li><li>4 Nights Package: One time three courses Set Menu Dinner at Segaran Restaurant for 2 persons &amp; One time 60 minutes Balinese Massage at Talise Spa for 2 persons &amp; One time Afternoon Tea at maja Lounge for 2 persons</li></ul>', NULL, NULL, 'Draft', '2023-03-28 11:26:57', '2026-02-01 17:23:35'),
(472, 98, NULL, '1769757257_1.webp', 'Spearmint-One Bedroom Villa', 2, 1, 'Pool View', 'King/Twin', '180', '<ol><li>Welcome drink on arrival</li><li>Daily breakfast at Sattvic Restaurant&nbsp;</li><li>Daily mineral water of two&nbsp;</li><li>Free WIFI Internet Access across the Villa </li><li>Free access to resort gym facilities and main pool </li><li>Free shuttle to Jimbaran beach based on schedule (drop off &amp; pick up)</li></ol>', '<li data-start=\"143\" data-end=\"156\"><p data-start=\"145\" data-end=\"156\">抵達時提供迎賓飲品</p>\r\n</li><li data-start=\"157\" data-end=\"179\">\r\n<p data-start=\"159\" data-end=\"179\">於 Sattvic 餐廳享用每日早餐</p>\r\n</li><li data-start=\"180\" data-end=\"193\">\r\n<p data-start=\"182\" data-end=\"193\">每日提供兩瓶礦泉水</p>\r\n</li><li data-start=\"194\" data-end=\"216\">\r\n<p data-start=\"196\" data-end=\"216\">別墅全區域提供免費 Wi-Fi 網路</p>\r\n</li><li data-start=\"217\" data-end=\"237\">\r\n<p data-start=\"219\" data-end=\"237\">免費使用度假村健身房設施及主泳池</p>\r\n</li><p>\r\n\r\n\r\n\r\n\r\n</p><li data-start=\"238\" data-end=\"268\">\r\n<p data-start=\"240\" data-end=\"268\">依時刻表提供往返金巴蘭海灘的免費接駁服務（接送服務）</p></li>', '<li data-start=\"308\" data-end=\"321\"><p data-start=\"310\" data-end=\"321\">抵达时提供欢迎饮品</p>\r\n</li><li data-start=\"322\" data-end=\"344\">\r\n<p data-start=\"324\" data-end=\"344\">于 Sattvic 餐厅享用每日早餐</p>\r\n</li><li data-start=\"345\" data-end=\"358\">\r\n<p data-start=\"347\" data-end=\"358\">每日提供两瓶矿泉水</p>\r\n</li><li data-start=\"359\" data-end=\"381\">\r\n<p data-start=\"361\" data-end=\"381\">别墅全区域提供免费 Wi-Fi 网络</p>\r\n</li><li data-start=\"382\" data-end=\"402\">\r\n<p data-start=\"384\" data-end=\"402\">免费使用度假村健身房设施及主泳池</p>\r\n</li><p>\r\n\r\n\r\n\r\n\r\n</p><li data-start=\"403\" data-end=\"432\">\r\n<p data-start=\"405\" data-end=\"432\">根据时间表提供往返金巴兰海滩的免费接驳服务（接送）</p></li>', NULL, NULL, NULL, '<ul><li>Daily breakfast&nbsp;</li><li>Welcome drink upon arrival&nbsp;</li><li>Wi-Fi in the room and throughout resort area&nbsp;</li></ul>', NULL, NULL