(480, 100, NULL, '1685351600_Luxury-Room-Lagoon-View-1-scaled.webp', 'Luxury Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Modern and comfortable living with 48㎡ / 516 SQFT, spacious amenities, LCD TV, private balcony, luxurious bathroom with separate bath and rain shower, special toiletries and up to 10MBps of free internet access.', NULL, NULL, 'Daily Breakfast', NULL, NULL, 'Active', '2023-05-29 01:13:20', '2025-04-14 18:25:53'),
