(482, 100, NULL, '1685351877_IMG_4717-scaled.webp', 'Luxury Room Plunge Pool', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Indulge in 48 SQM / 517 SQFT of modern living comfort with Private Plunge Pool, LCD TV. Luxurious bathroom comprises separate tub and rain shower with distinctive bathroom amenities, and complimentary Internet up to 10 MBps.', NULL, NULL, 'Daily Breakfast', NULL, NULL, 'Active', '2023-05-29 01:17:57', '2025-04-14 18:39:00'),
(483, 100, NULL, '1685352013_IMG_4718-scaled.webp', 'Luxury Room Pool Access', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '48 SQM / 516 SQFT, Club Millésime access, Modern living comfort with direct access to the resort’s immense lagoon pool, LCD TV, Luxurious bathroom comprises separate tub &amp; rain shower with distinctive bathroom amenities, Complimentary internet up to 10MBps.', NULL, NULL, '<ul><li>Daily Breakfast</li></ul><b>ADDITIONAL BENEFITS FOR CLUB MILLESIME GUESTS:</b><ul><li>Private check in and check out in the Club Millesime.</li><li>Breakfast, afternoon snacks, French high tea and evening cocktail in Club Millesime</li></ul>Club Millesime Operating Hours:Breakfast 06:30 – 11:00All Day Refreshments 10:00 – 22:00High Tea 15:00 – 17:00Cocktail Hours &amp; Tapas 17:30 – 19:30<ul><li>Centralized service to our Club Millesime Concierges (on-call).</li><li>Personalized butler service including unpacking/packing of luggage &nbsp;</li><li>A priority late departure arrangement (per-request) is entitled for Le Club Accor hotels, Gold member until 2 pm and Platinum member until 4 pm, depends on room availability.</li></ul>Note: Above benefit is subject to change without a prior notice. &nbsp;', NULL, NULL, 'Active', '2023-05-29 01:20:13', '2025-04-14 18:46:22'),
(484, 100, NULL, '1685352179_IMG_4723-scaled.webp', 'Prestige Suite', 2, 2, NULL, NULL, NULL, NULL, NULL, NULL, 'Enjoy 120m² of luxury living in our beachfront resort with Club Millésime access, Private balcony, Living and dining area, Luxurious bathroom with separate rain shower and luxury bathing amenities, Butler service, Complimentary Internet up to 10MBps.', NULL, NULL, '<ul><li>Daily Breakfast</li></ul><b>ADDITIONAL BENEFITS FOR CLUB MILLESIME GUESTS:</b><br><ul><li>Private check in and check out in the Club Millesime.</li><li>Breakfast, afternoon snacks, French high tea and evening cocktail in Club Millesime</li></ul>Club Millesime Operating Hours:Breakfast 06:30 – 11:00All Day Refreshments 10:00 – 22:00High Tea 15:00 – 17:00Cocktail Hours &amp; Tapas 17:30 – 19:30<ul><li>Centralized service to our Club Millesime Concierges (on-call).</li><li>Personalized butler service including unpacking/packing of luggage &nbsp;</li><li>A priority late departure arrangement (per-request) is entitled for Le Club Accor hotels, Gold member until 2 pm and Platinum member until 4 pm, depends on room availability.</li></ul>Note: Above benefit is subject to change without a prior notice. &nbsp;', NULL, NULL, 'Active', '2023-05-29 01:22:59', '2025-04-14 18:46:57'),
(485, 100, NULL, '1685352312_One-Bedroom-Villa-1-scaled.webp', 'Pool Villa 1 Bedroom', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Lavish 88 m² (947 sq. ft.) villa with private terrace and plunge pool, living room, marble bathroom with separate tub and rain shower, luxury bathing amenities, butler service, complimentary internet up to 10MBps, access to Club Millésime lounge and club benefits.', NULL, NULL, '<ul><li>Daily Breakfast</li></ul><b>ADDITIONAL BENEFITS FOR CLUB MILLESIME GUESTS:</b><ul><li>Private check in and check out in the Club Millesime.</li><li>Breakfast, afternoon snacks, French high tea and evening cocktail in Club Millesime</li></ul>Club Millesime Operating Hours:Breakfast 06:30 – 11:00All Day Refreshments 10:00 – 22:00High Tea 15:00 – 17:00Cocktail Hours &amp; Tapas 17:30 – 19:30<ul><li>Centralized service to our Club Millesime Concierges (on-call).</li><li>Personalized butler service including unpacking/packing of luggage &nbsp;</li><li>A priority late departure arrangement (per-request) is entitled for Le Club Accor hotels, Gold member until 2 pm and Platinum member until 4 pm, depends on room availability.</li></ul>Note: Above benefit is subject to change without a prior notice. &nbsp;', NULL, NULL, 'Active', '2023-05-29 01:25:12', '2025-04-14 18:47:24'),
(490, 102, NULL, '1715918402_1. Paddy View .webp', 'Paddy View', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'These rooms are tucked away at the edge of the park, and feature a private balcony that offers a breathtaking view of Bali’s emerald rice fields.', NULL, NULL, '<ul><li>Fruit Platter</li><li>Cold Towel and Welcome Drink on arrival</li><li>Park Entrance to Mason Elephant Park</li><li>Museum and Gallery, and Elephant  Introduction Movie at the Park Theatre daily</li><li>Daily Breakfast at Mammoths Head Bar &amp; Lounge</li><li>One time Elephant Safari Ride</li><li>Use of Fitness Room and Park relaxation pavilions and gazebos</li><li>Hands on Morning or Afternoon Elephant Bathing</li><li>Internet access in room.&nbsp;</li></ul>', NULL, NULL, 'Active', '2023-05-30 23:05:35', '2025-05-05 18:33:37'),
(491, 102, NULL, '1715918775_2. Garden View .webp', 'Garden View', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Our standard cozy, elephant-inspired rooms, surrounded by our lush botanical garden setting. These rooms include our ‘elephant chauffeur’ from your doorstep service.', NULL, NULL, '<ul><li>Fruit Platter</li><li>Cold Towel and Welcome Drink on arrival</li><li>Park Entrance to Mason Elephant Park</li><li>Museum and Gallery, and Elephant Introduction Movie at the Park Theatre daily</li><li>Daily Breakfast at Mammoths Head Bar &amp; Lounge</li><li>Elephant Chauffeur to Dinner (excluding Paddy View rooms and Lake Side rooms)&nbsp;</li><li>One time Elephant Safari Ride</li><li>Use of Fitness Room and Park relaxation pavilions and gazebos</li><li>Hands on Morning or Afternoon Elephant Bathing</li><li>Internet access in room.&nbsp;</li></ul>', NULL, NULL, 'Active', '2023-05-30 23:06:43', '2025-05-05 18:33:17'),
(492, 102, NULL, '1715919178_3. Lake Side.webp', 'Lake Side', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Comfy elevated wooden bungalow where you can rise to the sights and sounds of elephants bathing from your own doorstep.', NULL, NULL, '<ul><li>Fruit Platter</li><li>Cold Towel and Welcome Drink on arrival</li><li>Park Entrance to Mason Elephant Park</li><li>Museum and Gallery, and Elephant Introduction Movie at the Park Theatre daily</li><li>Daily Breakfast at Mammoths Head Bar &amp; Lounge</li><li>One time Elephant Safari Ride</li><li>Use of Fitness Room and Park relaxation pavilions and gazebos</li><li>Hands on Morning or Afternoon Elephant Bathing</li><li>Internet access in room.&nbsp;</li></ul>', NULL, NULL, 'Active', '2023-05-30 23:11:44', '2025-05-05 18:34:10'),
(493, 102, NULL, '1715919328_4. Park View .webp', 'Park View', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'Deluxe elephant-inspired rooms with private verandas overlooking the majority of the park and elephant chauffeur included. Watch our herd from your veranda as they slumber and go about their day.', NULL, NULL, '<ul><li>Fruit Platter</li><li>Cold Towel and Welcome Drink on arrival</li><li>Park Entrance to Mason Elephant Park</li><li>Museum and Gallery, and Elephant Introduction Movie at the Park Theatre daily</li><li>Daily Breakfast at Mammoths Head Bar &amp; Lounge</li><li>Elephant Chauffeur to Dinner (excluding Paddy View rooms and Lake Side rooms)&nbsp;</li><li>One time Elephant Safari Ride</li><li>Use of Fitness Room and Park relaxation pavilions and gazebos</li><li>Hands on Morning or Afternoon Elephant Bathing</li><li>Internet access in room.&nbsp;</li></ul><span><b>Value Added Benefits:</b><br></span><ul><li>One time Afternoon High Tea per stay at Mammoth Head Bar, Terrace and Lounge for booking at Park View Room or Executive Taro Suite.</li></ul><ul><li>One Elephant Painting (without frame) per room booking with minimum stay of three (3) nights for booking at Park View Room or Executive Suite.</li></ul>', NULL, NULL, 'Active', '2023-05-30 23:11:52', '2025-05-05 18:37:16'),
(494, 102, NULL, '1715919377_5. Taro Suite .webp', 'Taro Suite', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, 'The executive elephant experience. With an on-call private butler service, elephant chauffeur, wrap around veranda, relaxation lounge, private bar and your very own Jacuzzi. The Taro Suite is safari-style luxury in its own class.', NULL, NULL, '<ul><li>Fruit Platter</li><li>Cold Towel and Welcome Drink on arrival</li><li>Park Entrance to Mason Elephant Park</li><li>Museum and Gallery, and Elephant Introduction Movie at the Park Theatre daily</li><li>Daily Breakfast at Mammoths Head Bar &amp; Lounge</li><li>Elephant Chauffeur to Dinner (excluding Paddy View rooms and Lake Side rooms)&nbsp;</li><li>One time Elephant Safari Ride</li><li>Use of Fitness Room and Park relaxation pavilions and gazebos</li><li>Hands on Morning or Afternoon Elephant Bathing</li><li>Internet access in room.&nbsp;</li></ul><b>Value Added Benefits:<br></b><ul><li>One time Afternoon High Tea per stay at Mammoth Head Bar, Terrace and Lounge for booking at Park View Room or Executive Taro Suite.</li></ul><ul><li>One Elephant Painting (without frame) per room booking with minimum stay of three (3) nights for booking at Park View Room or Executive Suite.</li></ul>', NULL, NULL, 'Active', '2023-05-30 23:14:06', '2025-05-05 18:37:48'),
