(616, 86, NULL, '1753323113_8. The Reserve Room Garden View.avif', 'The Reserve Room Garden View', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Room Size: 40 m2</li><li>Maximum of Room Occupancy: 3 adults&nbsp;&nbsp;</li></ul>', NULL, NULL, '<div><b>THE RESERVE (16+ Years Age and above)&nbsp;</b></div><div><ul><li>Exclusive access to THE RESERVE Area&nbsp;</li><li>Exclusive area for arrival and departure experience&nbsp;</li><li>Daily complimentary cocktails and canapes for adults only (alcoholic drinks for above 18 years old) *&nbsp;</li><li><div><div>Daily complimentary Afternoon Tea&nbsp;</div></div></li><li><div>Unlimited access to THE RESERVE beach cabana&nbsp;</div></li><li><div>Unlimited access to private pool area for THE RESERVE adult only&nbsp;</div></li><li><div>Exclusive Breakfast area for THE RESERVE guest for adults only *&nbsp;</div></li><li><div>Concierge service&nbsp;</div></li><li><div>One-time complimentary pressing of two items per guest per stay&nbsp;</div></li><li><div>In-room espresso machine.&nbsp;</div></li><li><div>24-hour luggage porter&nbsp;</div></li><li><div>Complimentary Internet and Wi-Fi access throughout the resort&nbsp;</div></li><li><div>Welcome drink served in the RESERVE lounge upon check in&nbsp;</div></li><li><div>In-room welcome amenities upon arrival&nbsp;</div></li><li><div>In-room Premium bath amenities&nbsp;</div></li><li><div>Daily turndown service&nbsp;</div></li><li><div>Preferential reservation in the a la carte restaurants by our concierge&nbsp;</div></li><li>Extend check-out time until 2:00 pm (subject to availability)&nbsp;</li><li>Complimentary still and sparkling water at beach and swimming pool areas during the day&nbsp;</li></ul><i>* Please note that some areas at the hotel are dedicated to adults only (above 16 years old)&nbsp;</i><br><i>* The benefits are subject to change without prior notice&nbsp;</i></div>', NULL, NULL, 'Draft', '2024-01-09 01:11:46', '2025-07-23 23:01:19'),
