(686, 5, NULL, '1715566051_2BR Suite.webp', '2BR Suite', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 135 sqm&nbsp;</p><p>Max Occupants:&nbsp;</p><ul><li>4 adult&nbsp;</li><li>3 child below 12 years old (2 children with extra bed &amp; 1 child sharing bed with parents)&nbsp;</li><li>1 infant with baby cot&nbsp;</li></ul>', NULL, NULL, '<ul><li>Packing &amp; un-Packing Service&nbsp;</li><li>Welcome amenities fruits &amp; chocolate upon arrival&nbsp;</li><li>Additional benefit where the guests will enjoy the following:&nbsp;</li></ul><ol><li>Daily buffet / ala carte breakfast at HOMAYA from 07.00 - 10.30&nbsp;</li><li>Afternoon Tea with sweet, cookies, savory at BAR LOUNGE from 15.00 - 16.30&nbsp;</li><li>Evening free flow cocktails and canapes at BAR LOUNGE from 17.00 - 18.30. Include 2 type of drink per person. Maximum 2 persons. Drink selection are soft drink, beer, house wine and alcoholic or non-alcoholic cocktail&nbsp;</li></ol>', NULL, NULL, 'Draft', '2024-05-12 19:07:31', '2025-04-01 17:02:57'),
(687, 5, NULL, '1715566551_One-Bedroom-Villa-Bedroom.webp', '1BR Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 157 sqm&nbsp;</p><p>Max Occupants:&nbsp;</p><ul><li>3 adult (With existing bed + 1 extra bed)&nbsp;</li><li>1 infant with Baby cot&nbsp;</li></ul><p>Note: Children below 12 years old <strong>are not recommended</strong> to stay at <strong>1BR Pool Villa &amp; 2BR Pool Villa&nbsp;</strong></p>', NULL, NULL, '<ul><li>Packing &amp; un-Packing Service&nbsp;</li><li>Welcome amenities fruits &amp; chocolate upon arrival&nbsp;</li><li>Additional benefit where the guests will enjoy the following:&nbsp;</li></ul><ol><li>Daily buffet / ala carte breakfast at HOMAYA from 07.00 - 10.30&nbsp;</li><li>Afternoon Tea with sweet, cookies, savory at BAR LOUNGE from 15.00 - 16.30&nbsp;</li><li>Evening free flow cocktails and canapes at BAR LOUNGE from 17.00 - 18.30. Include 2 type of drink per person. Maximum 2 persons. Drink selection are soft drink, beer, house wine and alcoholic or non-alcoholic cocktail&nbsp;</li></ol>', NULL, NULL, 'Draft', '2024-05-12 19:15:52', '2025-04-01 17:02:57'),
