(689, 93, NULL, '1748589031_4..jpg', '3BR Luxury Pool Villa Paddy View', 6, 3, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Occupancy: 6 adults &amp; 1 child&nbsp;</li><li>Room Size: 400 sqm&nbsp;</li></ul>', NULL, NULL, '<ul><li>Welcome drinks upon arrival.&nbsp;</li><li>Daily Breakfast served at Akar Restaurant from 07.00 - 11.00.&nbsp;</li><li>Water Dispenser with gallon.&nbsp;</li><li>Complimentary Coffee and Tea-making facilities in the villa.&nbsp;</li><li>Morning Walk Relaxation through scenic rice fields, led by the concierge team (scheduled).&nbsp;</li><li>Sunrise Yoga Sessions are based on the schedule (reservation required).&nbsp;</li><li>Access to Gym Facilities and Kabana Jungle Pool Club.&nbsp;</li><li>Shuttle Service to and from Ubud Centre.&nbsp;</li><li>24-Hour Butler Service</li></ul>', NULL, NULL, 'Active', '2024-05-17 02:08:16', '2025-05-29 23:10:31'),
