(853, 64, NULL, '1749543772_5. river front pool villa.webp', 'River Front Pool Villa', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily American breakfast served at La View Restaurant&nbsp;</li><li>Welcome drink and cold towel upon arrival&nbsp;</li><li>Daily replenished mineral water&nbsp;</li><li>Free shuttle service to Ubud center (subject to resort\'s schedule)&nbsp;</li><li>Free Wi-Fi connection in all villas&nbsp;</li><li>Butler service and daily turn down services&nbsp;</li><li>Complimentary morning yoga session (subject to resort\'s schedule)&nbsp;</li><li>Min stays 3 nights get 1 x 60 minutes massage for 2 per stay&nbsp;</li></ul><b>Exclusive benefits for River Front Pool Villa:&nbsp;</b><br><ul><li>Daily American breakfast to be served at our restaurant or privacy of guest villa (07.00 am - 12.00 noon)&nbsp;</li><li>Complimentary mini bar stocked including beer&nbsp;</li><li>Complimentary daily laundry (maximum of 5 pieces)&nbsp;</li><li>Complimentary local phone call&nbsp;</li><li>Complimentary free flow coffee and tea, juices served with assorted traditional cake in the restaurant or privacy of guest villa (03.00 pm - 05.00 pm)&nbsp;</li><li>Complimentary one-time cocktail at the bar or restaurant (05.00 pm - 07.00 pm)&nbsp;</li><li>Personal coffee machine&nbsp;</li></ul>', NULL, NULL, 'Active', '2025-06-10 00:22:52', '2025-06-10 00:23:45'),
(854, 64, NULL, '1749544124_5. Family pool villa.webp', 'Family Pool Villa', 4, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Daily American breakfast served at La View Restaurant&nbsp;</li><li>Welcome drink and cold towel upon arrival&nbsp;</li><li>Daily replenished mineral water&nbsp;</li><li>Free shuttle service to Ubud center (subject to resort\'s schedule)&nbsp;</li><li>Free Wi-Fi connection in all villas&nbsp;</li><li>Butler service and daily turn down services&nbsp;</li><li>Complimentary morning yoga session (subject to resort\'s schedule)&nbsp;</li><li>Min stays 3 nights get 1 x 60 minutes massage for 2 per stay&nbsp;</li></ul>', NULL, NULL, 'Active', '2025-06-10 00:28:44', '2025-06-10 00:29:28'),
