(898, 93, NULL, '1754458853_5br royal pool villa paddy view.webp', '5BR Royal Pool Villa Paddy View', 10, 5, NULL, NULL, NULL, NULL, NULL, NULL, '<ul><li>Occupancy: 10 adults &amp; 1 child&nbsp;</li><li>Room Size: 600 sqm&nbsp;</li></ul>', NULL, NULL, '<ul><li>Welcome drinks upon arrival.&nbsp;</li><li>Daily Breakfast served at Akar Restaurant from 07.00 - 11.00.&nbsp;</li><li>Water Dispenser with gallon.&nbsp;</li><li>Complimentary Coffee and Tea-making facilities in the villa.&nbsp;</li><li>Morning Walk Relaxation through scenic rice fields, led by the concierge team (scheduled).&nbsp;</li><li>Sunrise Yoga Sessions are based on the schedule (reservation required).&nbsp;</li><li>Access to Gym Facilities and Kabana Jungle Pool Club.&nbsp;</li><li>Shuttle Service to and from Ubud Centre.&nbsp;</li><li>24-Hour Butler Service</li></ul>', NULL, NULL, 'Active', '2025-08-05 21:40:53', '2025-08-05 21:41:13'),
