(936, 54, 23, 'hotels/rooms/1669612788_Suite Room.webp', 'Suite Room', 2, 1, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Size: 50m2</p>', NULL, NULL, '<ul><li>Complimentary welcome drink</li><li>Daily breakfast</li><li>Daily afternoon tea</li><li>Daily seasonal fruit basket</li><li>Daily 2 bottles mineral water</li><li>Free Wifi – All Hotel’s area</li><li>Free Daily Guest activities based on schedule</li><li>Honeymoon benefits available based on request (flower decoration on the bed &amp; cake)&nbsp;</li></ul>', NULL, NULL, 'active', '2026-03-24 01:47:54', '2026-03-24 01:47:54'),
(937, 51, 23, 'hotels/rooms/1730780863_Premier Room.webp', 'Premier Room', 2, 1, NULL, 'Double/Single', '50', '<div>• Air Conditioner</div><div>• Coffee and Tea making facilities</div><div>• Mini Bar</div><div>• Laundry Service</div><div>• Safety Deposit Box</div><div>• Free WiFi</div><div>• Ceiling fan</div><div>• Shopping Bag</div><div>• CableTV (international &amp; local channels)</div><div>• IDD Telephone</div><div>• Slippers &amp; Kimonos</div><div>• Hair Dryer</div><div>• Iron (on request)</div><div>• Turndown Service</div>', NULL, NULL, '<p>The Premier Room provides a restful environment to unwind after a busy day spent exploring the sights of Ubud. It is a cozy base featuring clean-line furnishings, a smart en-suite bathroom, and a decorative wall that showcases Bali’s creative legacy. A private terrace or balcony blends seamlessly into the outdoors, providing extra space to sit and relax surrounded by a lush jungle view.</p>', NULL, NULL, '<ul><li>Complimentary welcome drink and cold towel upon arrival&nbsp;</li><li>Complimentary welcome fruit platter&nbsp;</li><li>Daily breakfast, afternoon tea, mini bar&nbsp;</li><li>Daily 2 bottles mineral water&nbsp;</li><li>Daily guest activities based on schedule&nbsp;</li><li>Wi-Fi - all hotel\'s area&nbsp;</li><li>Honeymoon benefits available based on request with flower decoration on the bed &amp; cake&nbsp;</li></ul>', NULL, NULL, 'active', '2026-03-24 18:59:04', '2026-03-24 18:59:04'),
(938, 51, 35, 'hotels/rooms/1730781107_2. Premier Room pool access.webp', 'Premier Room Pool Access', 2, 1, NULL, 'Double/Single', '50', '<div>• Air Conditioner</div><div>• Coffee and Tea making facilities</div><div>• Mini Bar</div><div>• Laundry Service</div><div>• Safety Deposit Box</div><div>• Ceiling fan</div><div>• Shopping bag</div><div>• Free WiFi</div><div><br></div><div>• CableTV (international &amp; local channels)</div><div>• IDD Telephone</div><div>• Slippers &amp; Kimonos</div><div>• Hair Dryer</div><div>• Iron (on request)</div><div>• Turndown Service</div>', NULL, NULL, '<p>The Premier Room Pool Access is an inviting sanctuary that features contemporary furnishings, a stylish en-suite bathroom, and a tastefully adorned space that pays homage to Bali’s artistic heritage. It offers a serene ambiance as the private terrace seamlessly opens up to direct access to the pool area, providing an exclusive space to unwind and rejuvenate.</p>', NULL, NULL, '<ul><li>Complimentary welcome drink and cold towel upon arrival&nbsp;</li><li>Complimentary welcome fruit platter&nbsp;</li><li>Daily breakfast, afternoon tea, mini bar&nbsp;</li><li>Daily 2 bottles mineral water&nbsp;</li><li>Daily guest activities based on schedule&nbsp;</li><li>Wi-Fi - all hotel\'s area&nbsp;</li><li>Honeymoon benefits available based on request with flower decoration on the bed &amp; cake&nbsp;</li></ul>', NULL, NULL, 'active', '2026-03-24 18:59:04', '2026-03-24 18:59:04');
INSERT INTO `hotel_rooms` (`id`, `hotels_id`, `room_view_id`, `cover`, `rooms`, `capacity_adult`, `capacity_child`, `view`, `beds`, `size`, `amenities`, `amenities_traditional`, `amenities_simplified`, `additional_info`, `additional_info_traditional`, `additional_info_simplified`, `include`, `include_traditional`, `include_simplified`, `status`, `created_at`, `updated_at`) VALUES
(939, 51, 23, 'hotels/rooms/1730785243_3. Adiwana Room.webp', 'Adiwana Room', 2, 1, NULL, 'Double/Single', '50', '<div>• Air Conditioner</div><div>• Coffee and Tea making facilities</div><div>• Mini Bar</div><div>• Laundry Service</div><div>• Safety Deposit Box</div><div>• Free WiFi</div><div>• Ceiling fan</div><div>• Shopping bag</div><div><br></div><div>• CableTV (international &amp; local channels)</div><div>• IDD Telephone</div><div>• Slippers &amp; Kimonos</div><div>• Hair Dryer</div><div>• Iron (on request)</div><div>• Turndown Service</div>', NULL, NULL, '<p>The Adiwana Room is the resort’s signature accommodation category that ensures total comfort and holiday peace of mind. It features a smart decor with an original work of local art extending along one entire wall and out onto the terrace. An elegant bathroom with a rain-shower cubicle and a floor standing bathtub promises spa-styled bathing indulgence</p>', NULL, NULL, '<ul><li>Complimentary welcome drink and cold towel upon arrival&nbsp;</li><li>Complimentary welcome fruit platter&nbsp;</li><li>Daily breakfast, afternoon tea, mini bar&nbsp;</li><li>Daily 2 bottles mineral water&nbsp;</li><li>Daily guest activities based on schedule&nbsp;</li><li>Wi-Fi - all hotel\'s area&nbsp;</li><li>Honeymoon benefits available based on request with flower decoration on the bed &amp; cake&nbsp;</li></ul>', NULL, NULL, 'active', '2026-03-24 18:59:04', '2026-03-24 18:59:04'),
(940, 51, 23, 'hotels/rooms/1730785662_4. Premier Suite Room.webp', 'Premier Suite Room', 2, 1, NULL, 'Double/Single', '70', '<div>• Air conditioner</div><div>• Coffee and tea making facilities</div><div>• Well-stocked minibar</div><div>• Laundry service</div><div>• Safety deposit box</div><div>• Coffee machine</div><div>• Ceiling fan</div><div>• Shopping bag</div><div>• Bose portable speaker</div><div><br></div><div>• Cable TV (international &amp; local channels)</div><div>• IDD telephone</div><div>• Slippers and kimonos</div><div>• Hair dryer</div><div>• Iron (on request)</div><div>• Turndown service</div><div>• Wi-Fi internet connection</div>', NULL, NULL, '<p>The Premier Suite is designed for an elevated experience, offering views that overlook the jungle in the lap of Ubud’s nature, providing an ideal setting for unwinding and relaxation. This category offers a larger living space attached to a contemporary bathroom setup.</p>', NULL, NULL, '<ul><li>Complimentary welcome drink and cold towel upon arrival&nbsp;</li><li>Complimentary welcome fruit platter&nbsp;</li><li>Daily breakfast, afternoon tea, mini bar&nbsp;</li><li>Daily 2 bottles mineral water&nbsp;</li><li>Daily guest activities based on schedule&nbsp;</li><li>Wi-Fi - all hotel\'s area&nbsp;</li><li>Honeymoon benefits available based on request with flower decoration on the bed &amp; cake&nbsp;</li></ul>', NULL, NULL, 'active', '2026-03-24 18:59:04', '2026-03-24 18:59:04'),
(941, 51, 23, 'hotels/rooms/1730785982_5. Adiwana Suite.webp', 'Adiwana Suite', 2, 1, NULL, 'Double/Single', '100', '<div>• Air Conditioner</div><div>• Coffee and Tea making facilities</div><div>• Free Daily Mini Bar</div><div>• Laundry Service</div><div>• Safety Deposit Box</div><div>• Coffee Machine</div><div>• Ceiling fan</div><div>• Shopping bag</div><div>• Bose Portable Speaker</div><div><br></div><div>• CableTV (international &amp; local channels)</div><div>• IDD Telephone</div><div>• Slippers &amp; Kimonos</div><div>• Hair Dryer</div><div>• Iron (on request)</div><div>• Turndown Service</div><div>• Kitchen Cutlery</div>', NULL, NULL, 'The Adiwana Suite redefines the notion of island-inspired elegance and has been created to anticipate every possible holiday need before it is even realized. This spacious category simply lends itself to relaxation with well-designed areas to sleep, unwind, and bathe in style. A soothing décor with bespoke furnishings and personal touches gives this suite an air of sophistication.', NULL, NULL, '<ul><li>Complimentary welcome drink and cold towel upon arrival&nbsp;</li><li>Complimentary welcome fruit platter&nbsp;</li><li>Daily breakfast, afternoon tea, mini bar&nbsp;</li><li>Daily 2 bottles mineral water&nbsp;</li><li>Daily guest activities based on schedule&nbsp;</li><li>Wi-Fi - all hotel\'s area&nbsp;</li><li>Honeymoon benefits available based on request with flower decoration on the bed &amp; cake&nbsp;</li></ul>', NULL, NULL, 'active', '2026-03-24 18:59:04', '2026-03-24 18:59:04'),
