INSERT INTO `inquiries` (`id`, `inquiry_number`, `customer_id`, `source`, `status`, `priority`, `assigned_to`, `deadline`, `notes`, `reminder_enabled`, `created_at`, `updated_at`, `created_by`, `updated_by`, `deleted_at`) VALUES
(4, 'INQ-DFS260326A', 7, 'wechat', 'processed', 'high', 7, '2026-03-30', '<p data-start=\"1016\" data-end=\"1106\">Halo, kami berencana trip ke <strong data-start=\"1045\" data-end=\"1086\">Bali</strong> dengan rombongan.</p>\r\n<p data-start=\"1108\" data-end=\"1331\">👥 Jumlah: 12 orang<br data-start=\"1127\" data-end=\"1130\">\r\n📅 Tanggal: sekitar September 2026 (flexible)<br data-start=\"1175\" data-end=\"1178\">\r\n📍 Destinasi yang diminati: <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Kintamani</span>, <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Mount Batur</span>, dan <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Ubud Monkey Forest</span></p>\r\n<p data-start=\"1333\" data-end=\"1396\">Mohon rekomendasi itinerary dan estimasi budget untuk 3–4 hari.</p>', 1, '2026-03-26 01:59:03', '2026-03-26 20:19:34', 7, 7, NULL),
(5, 'INQ-QWE260326B', 6, 'wechat', 'processed', 'high', 7, '2026-03-31', '<p data-start=\"138\" data-end=\"234\">Halo, saya ingin tanya paket tour di <strong data-start=\"175\" data-end=\"216\">Bali</strong> untuk keluarga.</p>\r\n<p data-start=\"236\" data-end=\"491\">📅 Tanggal: 15–17 Juli 2026<br data-start=\"263\" data-end=\"266\">\r\n👥 Jumlah: 4 orang (2 dewasa + 2 anak)<br data-start=\"304\" data-end=\"307\">\r\n🏨 Hotel: minimal 4 star<br data-start=\"331\" data-end=\"334\">\r\n📍 Destinasi yang ingin dikunjungi: <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Ubud</span>, <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Tegallalang Rice Terrace</span>, dan <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Tanah Lot Temple</span></p>\r\n<p data-start=\"493\" data-end=\"549\">Mohon info paket, harga, dan itinerary ya. Terima kasih.</p>', 1, '2026-03-26 02:01:35', '2026-04-06 00:15:53', 7, 7, NULL),
(376, 'INQ-TWM260410A', 383, 'other', 'processed', 'normal', 230, '2026-04-13', '<div>南部為主 (budget 781/pax)</div><div>➖➖➖➖➖➖➖➖➖➖➖</div><div>Day 1｜抵達 → 烏布（放鬆）</div><div>Day 2｜烏布皇宮&gt;烏布市集&gt;梯田</div><div>Day 3｜烏布 → 海神廟&gt;水明漾&gt;庫塔洋人街（或是海神廟&gt;Love Anchor</div><div>Day 4｜TEBING PANDAWA（藍色公路）&gt;Melasti Beach&gt;烏魯瓦圖廟&gt;金巴蘭日落</div><div>Day 5｜不包車</div><div>Day 6｜飯店 → 機場</div>', 1, '2026-04-10 07:19:41', '2026-04-10 07:39:24', 230, 230, NULL),
(377, 'INQ-TWD260414A', 384, 'wechat', 'processed', 'normal', 7, '2026-04-17', '<p data-start=\"592\" data-end=\"701\">Halo, saya sedang merencanakan liburan ke <strong data-start=\"640\" data-end=\"681\">Bali</strong> bersama pasangan.</p>\r\n<p data-start=\"703\" data-end=\"910\">📅 Rencana tanggal: 10–13 Agustus 2026<br data-start=\"741\" data-end=\"744\">\r\n👥 2 orang<br data-start=\"754\" data-end=\"757\">\r\n📍 Ingin mengunjungi: <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Nusa Penida</span>, <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Kelingking Beach</span>, dan sunset di <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Uluwatu Temple</span></p>\r\n<p data-start=\"912\" data-end=\"974\">Apakah tersedia paket tour atau private trip? Mohon detailnya.</p>', 1, '2026-04-14 05:51:58', '2026-04-14 05:52:26', 7, 7, NULL),
(378, 'INQ-TWM260416A', 383, 'line', 'processed', 'normal', 7, '2026-04-30', '<span data-sheets-root=\"1\" style=\"color: rgb(0, 0, 0); font-size: 10pt; font-family: Arial;\">Day 1｜抵達峇里島&gt; Jimbaran Bay 欣賞落日海鮮晚餐。<br>Day 2｜ Kanto Lampo Waterfall → Tukad Cepung 瀑布 → Tegallalang 梯田。<br>Day 3｜烏布 → 海神廟&gt;水明漾&gt;庫塔洋人街<br>Day 4｜不包車<br>Day 5｜飯店 → 機場</span>', 1, '2026-04-16 06:09:17', '2026-04-16 06:27:17', 5, 5, NULL);
