INSERT INTO `itineraries` (`id`, `inquiry_id`, `title`, `order_number`, `destination`, `destination_id`, `arrival_transport_id`, `departure_transport_id`, `duration_days`, `duration_nights`, `description`, `itinerary_include`, `itinerary_exclude`, `is_active`, `status`, `created_at`, `updated_at`, `created_by`, `updated_by`, `deleted_at`) VALUES
(35, 4, '3D2N Bali Adventure Package', NULL, 'Bali', 17, NULL, NULL, 3, 2, '<strong data-start=\"0\" data-end=\"31\" data-is-only-node=\"\">3D2N Bali Adventure Package</strong> is a 3-day, 2-night tour for thrill-seekers eager to explore Bali’s natural wonders and outdoor activities. Experience rafting, ATV rides, trekking, and visits to waterfalls and scenic landscapes. With comfortable accommodation, private transport, and a carefully planned itinerary, this package delivers an action-packed, unforgettable adventure across Bali.&nbsp;', 'Day 1: <ul><li data-section-id=\"1ub2eas\" data-start=\"127\" data-end=\"174\">Private air-conditioned vehicle with driver\r\n</li><li data-section-id=\"1l7v2f3\" data-start=\"175\" data-end=\"207\">\r\nFuel, parking, and toll fees\r\n</li><li data-section-id=\"1bw3vk9\" data-start=\"208\" data-end=\"257\">\r\nEnglish-speaking driver or professional guide\r\n</li><li data-section-id=\"1agmyp2\" data-start=\"258\" data-end=\"379\">\r\nEntrance tickets as per itinerary (e.g. <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Tegallalang Rice Terrace</span>, <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Tanah Lot Temple</span>)\r\n</li><li data-section-id=\"1lb1xzb\" data-start=\"380\" data-end=\"427\">\r\nComplimentary mineral water during the tour\r\n</li><li data-section-id=\"rrcx7j\" data-start=\"428\" data-end=\"482\">\r\nMeals as specified in the itinerary (lunch/dinner)\r\n</li><li data-section-id=\"oj0gg1\" data-start=\"483\" data-end=\"531\">\r\nHotel accommodation (for multi-day packages)\r\n</li><li data-section-id=\"zyhd8u\" data-start=\"532\" data-end=\"604\">\r\nAirport pick-up and drop-off (<span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Ngurah Rai International Airport</span>)\r\n</li><li data-section-id=\"2ubw75\" data-start=\"605\" data-end=\"640\">\r\nLocal taxes and service charges\r\n</li><li data-section-id=\"1u0yx59\" data-start=\"641\" data-end=\"679\">\r\nBasic travel insurance (if stated)</li></ul>\nDay 2: <ul style=\"--tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / 0.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ;\"><li data-section-id=\"1ub2eas\" data-start=\"127\" data-end=\"174\" style=\"--tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / 0.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: