(397, 377, '3D2N Bali Tour Package', NULL, 'Bali', 17, NULL, NULL, 3, 2, '<strong data-start=\"0\" data-end=\"26\" data-is-only-node=\"\">3D2N Bali Tour Package</strong> is a 3-day, 2-night holiday designed to explore the best of Bali in a short time. Discover iconic attractions, cultural sites, beautiful beaches, and scenic landscapes while enjoying a well-balanced itinerary. With comfortable accommodation, private transportation, and professional service, this package offers a convenient and memorable Bali experience.', '<ul><li data-section-id=\"mj8f8g\" data-start=\"157\" data-end=\"194\">Private transport (AC car + driver)\r\n</li><li data-section-id=\"uoc6zt\" data-start=\"195\" data-end=\"216\">\r\nFuel &amp; parking fees\r\n</li><li data-section-id=\"86y5kg\" data-start=\"217\" data-end=\"250\">\r\nEnglish-speaking driver / guide\r\n</li><li data-section-id=\"scw7nm\" data-start=\"251\" data-end=\"373\">\r\nEntrance tickets sesuai itinerary (contoh: <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Tegallalang Rice Terrace</span>, <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Tanah Lot Temple</span>)\r\n</li><li data-section-id=\"m56na2\" data-start=\"374\" data-end=\"407\">\r\nMineral water selama perjalanan\r\n</li><li data-section-id=\"1jiulm7\" data-start=\"408\" data-end=\"463\">\r\nMeals sesuai program (lunch / dinner jika disebutkan)\r\n</li><li data-section-id=\"1fhtlt5\" data-start=\"464\" data-end=\"509\">\r\nHotel accommodation (untuk paket multi-day)\r\n</li><li data-section-id=\"1tgkk4o\" data-start=\"510\" data-end=\"586\">\r\nAirport pick-up &amp; drop-off (contoh: <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Ngurah Rai International Airport</span>)\r\n</li><li data-section-id=\"1nhm9w3\" data-start=\"587\" data-end=\"612\">\r\nToll &amp; retribution fees\r\n</li><li data-section-id=\"1ugmb4n\" data-start=\"613\" data-end=\"657\">\r\nTour insurance (optional, jika disediakan)</li></ul>', '<ul data-start=\"699\" data-end=\"1131\"><li data-section-id=\"zekfbw\" data-start=\"699\" data-end=\"740\">International / domestic flight tickets\r\n</li>\r\n<li data-section-id=\"vi3crp\" data-start=\"741\" data-end=\"794\">\r\nPersonal expenses (shopping, minibar, laundry, dll)\r\n</li>\r\n<li data-section-id=\"yma0c\" data-start=\"795\" data-end=\"887\">\r\nOptional activities (watersport di <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\">Tanjung Benoa Beach</span>, swing, ATV, dll)\r\n</li>\r\n<li data-section-id=\"1wzwjnw\" data-start=\"888\" data-end=\"915\">\r\nTips untuk driver / guide\r\n</li>\r\n<li data-section-id=\"yu3pot\" data-start=\"916\" data-end=\"958\">\r\nTravel insurance (jika tidak disebutkan)\r\n</li>\r\n<li data-section-id=\"1e25z32\" data-start=\"959\" data-end=\"984\">\r\nMeals di luar itinerary\r\n</li>\r\n<li data-section-id=\"l1duos\" data-start=\"985\" data-end=\"1013\">\r\nVisa fee (jika diperlukan)\r\n</li>\r\n<li data-section-id=\"l4de3\" data-start=\"1014\" data-end=\"1053\">\r\nEarly check-in / late check-out hotel\r\n</li>\r\n<li data-section-id=\"aikupq\" data-start=\"1054\" data-end=\"1131\">\r\nAdditional surcharge (high season / peak season seperti Natal &amp; Tahun Baru)&nbsp;</li>\r\n</ul>', 1, 'processed', '2026-04-16 05:47:23', '2026-04-16 05:49:53', 1, 1, NULL),
