INSERT INTO `tourist_attractions` (`id`, `name`, `ideal_visit_minutes`, `contract_rate_per_pax`, `markup_type`, `markup`, `publish_rate_per_pax`, `location`, `city`, `province`, `country`, `timezone`, `address`, `destination_id`, `google_maps_url`, `latitude`, `longitude`, `description`, `gallery_images`, `is_active`, `created_at`, `updated_at`, `deleted_at`, `created_by`, `updated_by`) VALUES
(412, 'Pandawa Beach', 120, 50000, 'fixed', 50000, 100000, 'Kutuh, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Kutuh, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.8458077,115.1850695', -8.8458077, 115.1850695, '<p>Pandawa Beach is a hidden gem on Bali’s southern coast, known for its stunning white sand, crystal-clear waters, and dramatic limestone cliffs. Often called the “Secret Beach,” it offers a peaceful escape with breathtaking ocean views, perfect for relaxing, swimming, and capturing unforgettable moments.</p>', '[\"tourist-attractions\\/rbCSDXDrgQ7BUyLQtmp4uLz0Duz6LobgkuCUHXMI.jpg\"]', 1, '2026-03-25 21:46:46', '2026-04-09 06:56:39', NULL, 2, 7),
(413, 'Melasti Beach', 120, 50000, 'fixed', 50000, 100000, 'Ungasan, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Melasti, Ungasan, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.8483846,115.1628470', -8.8483846, 115.1628470, '<p>Melasti Beach is a breathtaking coastal destination famous for its dramatic cliffside roads, pristine white sand, and turquoise waters. Nestled beneath towering limestone cliffs, it offers a serene and scenic atmosphere, making it perfect for sunset views, relaxation, and stunning photography.</p>', '[\"tourist-attractions\\/n5VLCCfZZJnAMh3GVyfwOxAuS5SXClDpbhN1lAEw.jpg\"]', 1, '2026-03-25 21:48:44', '2026-04-09 06:54:20', NULL, 2, 7),
(414, 'Uluwatu Temple', 120, 100000, 'fixed', 50000, 150000, 'Uluwatu, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Labuan Sait- Pecatu, Uluwatu, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.8293856,115.0846389', -8.8293856, 115.0846389, '<p>Uluwatu Temple is an iconic sea temple perched on a dramatic cliff overlooking the Indian Ocean. Renowned for its breathtaking sunset views and spiritual atmosphere, it is one of Bali’s most sacred sites. Visitors can also enjoy the famous Kecak Dance performed at dusk, creating a truly unforgettable cultural experience.</p>', '[\"tourist-attractions\\/7dXLx7zFyByHCnSm0uK7uWL4qD68ucao16Z3aYx7.jpg\"]', 1, '2026-03-25 21:51:30', '2026-04-09 06:30:27', NULL, 2, 7),
(415, 'Nyang Nyang Beach', 120, 50000, 'fixed', 50000, 100000, 'Uluwatu, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Batu Lesung, Uluwatu, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.8397869,115.0943426', -8.8397869, 115.0943426, '<p>Nyang Nyang Beach is a secluded paradise known for its untouched natural beauty, soft white sand, and dramatic ocean views. Hidden beneath steep cliffs, this tranquil beach offers a peaceful escape away from the crowds, perfect for those seeking serenity, scenic walks, and breathtaking coastal landscapes.</p>', '[\"tourist-attractions\\/Zv08SU4379ero45mBRsWXNIqK9Tu0X3yX5O2ris4.jpg\"]', 1, '2026-03-25 21:53:22', '2026-04-09 06:55:42', NULL, 2, 7),
(416, 'Padang Padang Beach', 120, 50000, 'fixed', 50000, 100000, 'Uluwatu, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Labuan Sait- Pecatu, Uluwatu, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.8112575,115.1036329', -8.8112575, 115.1036329, '<p>Padang Padang Beach is a picturesque coastal gem known for its unique cave entrance, where visitors pass through a narrow rock passage to a stunning stretch of golden sand. Surrounded by towering cliffs and clear turquoise waters, it’s a popular spot for surfing, sunbathing, and enjoying a laid-back tropical atmosphere.</p>', '[\"tourist-attractions\\/u5C9dHkbUuFR54WKIgNBwZ98oj8ZQkH1LNoTV94i.jpg\"]', 1, '2026-03-25 21:59:43', '2026-04-09 06:56:12', NULL, 2, 7),
(417, 'Bungin Beach', 120, 100000, 'fixed', 50000, 150000, 'Pecatu, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Tanjung Simah, Pecatu, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.8071332,115.1114115', -8.8071332, 115.1114115, '<p>Bungin Beach offers a serene escape with its dramatic cliffside setting, soft golden sand, and clear blue waters. Popular among surfers and sunset lovers, it’s an ideal spot to unwind while enjoying breathtaking ocean views and a peaceful tropical atmosphere.</p>', '[\"tourist-attractions\\/O32nufzZAeOfoSHUwyZgsTDwSGgA1rQaEHQv9ZkY.jpg\"]', 1, '2026-03-25 22:03:51', '2026-04-09 06:42:32', NULL, 2, 7),
(418, 'Dreamland Beach', 120, 100000, 'fixed', 50000, 150000, 'Pecatu, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Sunset Path, Pecatu, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.7993934,115.1176029', -8.7993934, 115.1176029, '<p>Dreamland Beach is a beautiful seaside escape featuring soft white sand, rolling waves, and breathtaking cliffside scenery. A favorite for surfers and beach lovers, it’s the perfect place to relax, enjoy the ocean breeze, and catch stunning sunsets.</p>', '[\"tourist-attractions\\/2SxvbpVnJ7QERtpuwFp620cDdb64xI6Cn5Vx2Ap5.jpg\"]', 1, '2026-03-25 22:07:31', '2026-04-09 06:44:20', NULL, 2, 7),
(419, 'Balangan Beach', 120, 150000, 'fixed', 50000, 200000, 'Jimbaran, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT +8', 'Jalan Pantai Balangan, Jimbaran, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.7934241,115.1223655', -8.7934241, 115.1223655, '<p>Balangan Beach is a laid-back coastal haven known for its long stretch of golden sand, rolling waves, and scenic limestone cliffs. Popular among surfers and sunset seekers, it offers a relaxed atmosphere with stunning ocean views and a true tropical charm.</p>', '[\"tourist-attractions\\/c2j0W7I4nDIU1TKUUTlQAk6AKLWCYoMniOL4fwRS.jpg\"]', 1, '2026-03-25 22:09:29', '2026-04-09 04:20:45', NULL, 2, 2),
(420, 'Jimbaran Beach', 120, 50000, 'fixed', 50000, 100000, 'Jimbaran, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Bukit Permai, Jimbaran, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.7760882,115.1666120', -8.7760882, 115.1666120, '<p>Jimbaran Beach is a beautiful coastal destination famous for its calm waters, golden sands, and romantic seaside dining. Known for its fresh seafood restaurants set along the shore, it’s the perfect place to enjoy a relaxing beach day and a stunning sunset dinner by the ocean.</p>', '[\"tourist-attractions\\/h3z2JGaQmOXKG5SAQsUi44gYPUxxrYnMVMIzyiGT.jpg\"]', 1, '2026-03-25 22:17:04', '2026-04-09 06:47:53', NULL, 2, 7),
(421, 'Kedonganan Beach', 120, 0, 'fixed', 0, 0, 'Kuta, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Pantai Kedonganan, Kuta, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.7619645,115.1692939', -8.7619645, 115.1692939, '<p>Kedonganan Beach is a charming coastal spot known for its peaceful atmosphere, golden sands, and traditional fishing village vibes. Famous for its fresh seafood dining by the shore, it offers a more local and authentic alternative to nearby beaches, perfect for relaxing and enjoying beautiful sunsets.</p>', '[\"tourist-attractions\\/8uhwNHLdh4dmCbYEyElPpna1N8VdMRnTqmr0jxo2.jpg\"]', 1, '2026-03-25 22:22:13', '2026-04-09 06:49:44', NULL, 2, 7),
(422, 'Nusa Dua Beach', 120, 150000, 'fixed', 50000, 200000, 'Nusa Dua, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', '1, Nusa Dua, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.7954280,115.2325828', -8.7954280, 115.2325828, '<p>Nusa Dua Beach is a pristine and upscale coastal destination known for its calm, crystal-clear waters and soft white sand. Surrounded by luxury resorts, it offers a clean, tranquil environment ideal for swimming, relaxing, and enjoying a peaceful beachside escape.</p>', '[\"tourist-attractions\\/Ha8Ery0kW3hpaZr6AGBN1dMoO3TyFt9q1FwCV4NH.jpg\"]', 1, '2026-03-25 22:31:49', '2026-04-09 06:55:17', NULL, 2, 7),
(423, 'Garuda Wisnu Kencana (GWK)', 120, 350000, 'fixed', 100000, 450000, 'Ungasan, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Pura Pengulapan, Ungasan, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.8104175,115.1650237', -8.8104175, 115.1650237, '<p>Garuda Wisnu Kencana Cultural Park is a world-class cultural destination featuring the iconic towering statue of Lord Vishnu riding the mythical Garuda. Set within a vast park surrounded by limestone cliffs, it offers cultural performances, scenic views, and a unique glimpse into Balinese heritage and art.</p>', '[\"tourist-attractions\\/sN6IDQvgBoDk8CGim25LYtpUwLynLoqlbIcfwyG7.jpg\"]', 1, '2026-03-25 22:34:05', '2026-04-09 06:44:51', NULL, 2, 7),
(424, 'Kuta Beach Bali', 120, 100000, 'fixed', 50000, 150000, 'Kuta, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Benesari, Kuta, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.7181795,115.1687041', -8.7181795, 115.1687041, '<p>Kuta Beach is one of Bali’s most famous beaches, known for its long stretch of golden sand, lively atmosphere, and perfect waves for beginner surfers. It’s a vibrant destination ideal for sunset views, beach activities, and enjoying the island’s energetic coastal vibe.</p>', '[\"tourist-attractions\\/BA9PcP8Uy8hfvF7I51RLqq5UggKpzwiFuThxM5sx.jpg\"]', 1, '2026-03-25 22:37:17', '2026-04-09 06:51:39', NULL, 2, 7),
(425, 'Legian Beach', 120, 100000, 'fixed', 50000, 150000, 'Kuta, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Werkudara, Kuta, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.7033642,115.1645092', -8.7033642, 115.1645092, '<p>Legian Beach is a relaxed coastal destination known for its wide sandy shoreline, gentle waves, and laid-back atmosphere. Located between Kuta and Seminyak, it offers the perfect balance of vibrant beach life and peaceful surroundings, ideal for surfing, sunbathing, and enjoying beautiful sunsets.</p>', '[\"tourist-attractions\\/5520n83MdYHH5OzPVwsbV49KJL1NEiQ63UVtOQjx.jpg\"]', 1, '2026-03-25 22:40:08', '2026-04-09 06:52:06', NULL, 2, 7),
(426, 'Seminyak Beach', 120, 150000, 'fixed', 50000, 200000, 'Kuta, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT', 'Jalan Camplung Tanduk, Kuta, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.6909134,115.1569882', -8.6909134, 115.1569882, '<p>Seminyak Beach is a stylish coastal destination known for its wide sandy shores, vibrant beach clubs, and stunning sunsets. Offering a more upscale and relaxed vibe, it’s perfect for lounging, surfing, and enjoying Bali’s chic seaside atmosphere.</p>', '[\"tourist-attractions\\/me4eQfYyheShdC0o08AoE8xAtPrGBFOmFpMCfkQN.jpg\"]', 1, '2026-03-25 22:42:39', '2026-04-09 07:04:36', NULL, 2, 7),
(427, 'Petitenget Beach', 120, 100000, 'fixed', 50000, 150000, 'Canggu, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT +8', 'Canggu, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.6824606,115.1511623', -8.6824606, 115.1511623, '<p>Petitenget Beach is a serene coastal escape known for its wide sandy shoreline, rolling waves, and peaceful atmosphere. Located near trendy Seminyak, it offers a perfect blend of relaxation and scenic beauty, ideal for sunset strolls and enjoying Bali’s tranquil seaside charm.</p>', '[\"tourist-attractions\\/FfGmC3eiy2N0ywkPCG5pfSjtECp5RynUycIgayPf.jpg\"]', 1, '2026-03-25 22:45:44', '2026-04-09 06:58:47', NULL, 2, 7),
(428, 'Batu Bolong Beach', 120, 150000, 'fixed', 50000, 200000, 'Canggu, Bali', 'Badung', 'Bali', 'Indonesia', 'GMT +8', 'Jalan Munduk Kedungu, Canggu, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.6570587,115.1274313', -8.6570587, 115.1274313, '<p>Batu Bolong Beach is a vibrant beach in Canggu known for its laid-back surf culture, scenic coastline, and lively atmosphere. With consistent waves, beachfront cafes, and stunning sunset views, it’s a favorite spot for surfers, digital nomads, and travelers seeking a relaxed yet social seaside experience.</p>', '[\"tourist-attractions\\/nYVN4MzEWrpbU0mnqItWDBxg0ZK7RxLb6BNa0MCW.jpg\"]', 1, '2026-03-25 22:48:23', '2026-04-09 06:39:02', NULL, 2, 7),
(429, 'Nyanyi Beach', 120, 50000, 'fixed', 50000, 100000, 'Tabanan, Bali', 'Tabanan', 'Bali', 'Indonesia', 'GMT +8', 'Tabanan, Bali, Indonesia', 17, 'https://www.google.com/maps/place/Pantai+Nyanyi/@-8.6336409,115.0875351,15z/data=!3m1!4b1!4m6!3m5!1s0x2dd2382115f7f5f9:0x929870a0c1008d3a!8m2!3d-8.6336624!4d115.0978348!16s%2Fg%2F11bv30gntw?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.6336409, 115.0875351, '<p>Nyanyi Beach is a quiet and unspoiled coastal retreat known for its black sand shoreline, peaceful atmosphere, and scenic ocean views. Away from the crowds, it’s perfect for relaxing walks, enjoying nature, and experiencing Bali’s more tranquil side.</p>', '[\"tourist-attractions\\/BXmo8piKxJJO3Si6LcgIWPWJ4IiLlyNmMlLRxWnf.jpg\"]', 1, '2026-03-25 22:51:30', '2026-03-25 22:51:30', NULL, 2, 2),
(430, 'Tanah Lot Temple', 120, 150000, 'fixed', 50000, 200000, 'Tabanan, Bali', 'Tabanan', 'Bali', 'Indonesia', 'GMT +8', 'Jalan Enjung Pura, Tabanan, Bali, Indonesia', 17, 'https://www.google.com/maps/place/Tanah+Lot/@-8.6211932,115.0842492,17z/data=!3m1!4b1!4m6!3m5!1s0x2dd23783cb019389:0x256989653f3fd840!8m2!3d-8.6211724!4d115.0868637!16s%2Fg%2F11c5yp847l?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.6211932, 115.0842492, '<p>Tanah Lot Temple is one of Bali’s most iconic sea temples, set on a dramatic rock formation surrounded by the ocean. Famous for its breathtaking sunset views and cultural significance, it offers a magical blend of spirituality and natural beauty.</p>', '[\"tourist-attractions\\/738gubWgORykDX0fXycfemFgQg7adsOtrP1i1d36.jpg\"]', 1, '2026-03-25 22:54:43', '2026-03-25 22:54:43', NULL, 2, 2),
(431, 'Kedungu Beach', 120, 50000, 'fixed', 50000, 100000, 'Sudimara, Bali', 'Tabanan', 'Bali', 'Indonesia', 'GMT +8', 'Sudimara, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.6089971,115.0832705', -8.6089971, 115.0832705, '<p>Kedungu Beach is a peaceful coastal escape known for its dark volcanic sand, rolling waves, and uncrowded atmosphere. Popular among surfers and those seeking tranquility, it offers a raw, natural beauty with stunning sunset views and a laid-back vibe.</p>', '[\"tourist-attractions\\/iRcw0evUha3sbdSPXgR8gIuRP9dmAruYRcu3ixkr.jpg\"]', 1, '2026-03-25 22:57:24', '2026-04-09 06:50:22', NULL, 2, 7),
(432, 'Balian Beach', 120, 150000, 'fixed', 50000, 200000, 'Lalanglinggah, Bali', 'Tabanan', 'Bali', 'Indonesia', 'GMT +8', 'Jalan Raya Denpasar-Gilimanuk, Lalanglinggah, Bali, Indonesia', 17, 'https://maps.google.com/?q=-8.5026419,114.9642917', -8.5026419, 114.9642917, '<p>Balian Beach is a tranquil coastal retreat known for its black sand shoreline, consistent surf breaks, and lush natural surroundings. Popular among surfers and travelers seeking a quieter escape, it offers a relaxed atmosphere with beautiful ocean views and serene sunsets.</p>', '[\"tourist-attractions\\/eYyjsJVDnjw2YwovPxcI3sJB6skkx4XcZqLVrfbt.jpg\"]', 1, '2026-03-25 23:00:40', '2026-04-09 06:37:17', NULL, 2, 7),
(433, 'Menjangan Island', 120, 100000, 'fixed', 50000, 150000, 'Buleleng, Bali', 'Buleleng', 'Bali', 'Indonesia', 'GMT', 'Buleleng, Bali, Indonesia', 17, 'https://www.google.com/maps/place/Menjangan+Island/@-8.0983118,114.5047003,15z/data=!3m1!4b1!4m6!3m5!1s0x2dd141d1ab865ded:0x5e518b99fc683bc9!8m2!3d-8.0983333!4d114.515!16s%2Fm%2F064lmw4?entry=ttu&g_ep=EgoyMDI2MDMyMy4xIKXMDSoASAFQAw%3D%3D', -8.0983118, 114.5047003, '<p>Menjangan Island is a pristine tropical paradise located within West Bali National Park, renowned for its crystal-clear waters, vibrant coral reefs, and exceptional snorkeling and diving spots. Surrounded by untouched nature, it offers a peaceful escape for those seeking underwater beauty and serene island scenery.</p>', '[\"tourist-attractions\\/Yk494VwpuKdRbhSvIRCgYGgNr2hx6y9Dm9gVkTXY.jpg\"]', 1, '2026-03-25 23:02:55', '2026-03-25 23:02:55', NULL, 2, 2),
